/// Map a SQL type name to its SQLite affinity byte (§3.1 Type Affinity Rules).
///
/// Encoding: A..E maps to BLOB, TEXT, NUMERIC, INTEGER, REAL:
/// `'A'` = BLOB, `'B'` = TEXT, `'C'` = NUMERIC, `'D'` = INTEGER, `'E'` = REAL.
fn type_name_to_affinity(name: &str) -> u8 {
    let upper = name.to_uppercase();
    if upper.contains("INT") {
        b'D' // INTEGER affinity
    } else if upper.contains("CHAR") || upper.contains("TEXT") || upper.contains("CLOB") {
        b'B' // TEXT affinity
    } else if upper.contains("BLOB") || upper.is_empty() {
        b'A' // BLOB affinity
    } else if upper.contains("REAL") || upper.contains("FLOA") || upper.contains("DOUB") {
        b'E' // REAL affinity
    } else {
        b'C' // NUMERIC affinity
    }
}

/// A database row produced by a query.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Row {
    values: Vec<SqliteValue>,
}

impl Row {
    /// Returns all values in this row.
    pub fn values(&self) -> &[SqliteValue] {
        &self.values
    }

    /// Returns the value at `index`, if present.
    pub fn get(&self, index: usize) -> Option<&SqliteValue> {
        self.values.get(index)
    }
}

fn flat_combining_abort_total(snapshot: FlatCombiningMetrics) -> u64 {
    snapshot
        .fsqlite_htm_aborts_conflict
        .saturating_add(snapshot.fsqlite_htm_aborts_capacity)
        .saturating_add(snapshot.fsqlite_htm_aborts_explicit)
        .saturating_add(snapshot.fsqlite_htm_aborts_other)
}

fn flat_combining_success_estimate(snapshot: FlatCombiningMetrics) -> u64 {
    snapshot
        .fsqlite_htm_attempts
        .saturating_sub(flat_combining_abort_total(snapshot))
}

fn flat_combining_abort_rate_pct(snapshot: FlatCombiningMetrics) -> u64 {
    let attempts = snapshot.fsqlite_htm_attempts;
    if attempts == 0 {
        0
    } else {
        flat_combining_abort_total(snapshot)
            .saturating_mul(100)
            .checked_div(attempts)
            .unwrap_or(0)
    }
}

fn flat_combining_stats_rows() -> Vec<Row> {
    let snapshot = flat_combining_metrics();
    let metrics = [
        (
            "fsqlite_flat_combining_batches_total",
            snapshot.fsqlite_flat_combining_batches_total,
        ),
        (
            "fsqlite_flat_combining_ops_total",
            snapshot.fsqlite_flat_combining_ops_total,
        ),
        (
            "fsqlite_flat_combining_batch_size_sum",
            snapshot.fsqlite_flat_combining_batch_size_sum,
        ),
        (
            "fsqlite_flat_combining_batch_size_max",
            snapshot.fsqlite_flat_combining_batch_size_max,
        ),
        (
            "fsqlite_flat_combining_wait_ns_total",
            snapshot.fsqlite_flat_combining_wait_ns_total,
        ),
        (
            "fsqlite_flat_combining_wait_ns_max",
            snapshot.fsqlite_flat_combining_wait_ns_max,
        ),
        ("fsqlite_htm_attempts", snapshot.fsqlite_htm_attempts),
        (
            "fsqlite_htm_aborts_conflict",
            snapshot.fsqlite_htm_aborts_conflict,
        ),
        (
            "fsqlite_htm_aborts_capacity",
            snapshot.fsqlite_htm_aborts_capacity,
        ),
        (
            "fsqlite_htm_aborts_explicit",
            snapshot.fsqlite_htm_aborts_explicit,
        ),
        (
            "fsqlite_htm_aborts_other",
            snapshot.fsqlite_htm_aborts_other,
        ),
    ];

    metrics
        .into_iter()
        .map(|(name, value)| Row {
            values: vec![
                SqliteValue::Text(name.into()),
                SqliteValue::Integer(to_i64_clamped(value)),
            ],
        })
        .collect()
}

fn htm_metrics_row_values(snapshot: FlatCombiningMetrics) -> Vec<SqliteValue> {
    let aborts_total = flat_combining_abort_total(snapshot);
    vec![
        SqliteValue::Integer(to_i64_clamped(snapshot.fsqlite_htm_attempts)),
        SqliteValue::Integer(to_i64_clamped(snapshot.fsqlite_htm_aborts_conflict)),
        SqliteValue::Integer(to_i64_clamped(snapshot.fsqlite_htm_aborts_capacity)),
        SqliteValue::Integer(to_i64_clamped(snapshot.fsqlite_htm_aborts_explicit)),
        SqliteValue::Integer(to_i64_clamped(snapshot.fsqlite_htm_aborts_other)),
        SqliteValue::Integer(to_i64_clamped(aborts_total)),
        SqliteValue::Integer(to_i64_clamped(flat_combining_success_estimate(snapshot))),
        SqliteValue::Integer(to_i64_clamped(flat_combining_abort_rate_pct(snapshot))),
    ]
}

/// A prepared SQL statement.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum PreparedDmlKind {
    Insert,
    Update,
    Delete,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum PreparedUpdateDeleteFallbackReason {
    Returning,
    SqliteSequence,
    WithoutRowid,
    LiveVtab,
    Trigger,
    ForeignKey,
}

impl PreparedDmlKind {
    const fn statement_kind(self) -> &'static str {
        match self {
            Self::Insert => "insert",
            Self::Update => "update",
            Self::Delete => "delete",
        }
    }
}

fn record_prepared_update_delete_fallback(reason: PreparedUpdateDeleteFallbackReason) {
    if !hot_path_profile_enabled() {
        return;
    }
    match reason {
        PreparedUpdateDeleteFallbackReason::Returning => {
            FSQLITE_PREPARED_UPDATE_DELETE_FALLBACK_RETURNING.fetch_add(1, AtomicOrdering::Relaxed);
        }
        PreparedUpdateDeleteFallbackReason::SqliteSequence => {
            FSQLITE_PREPARED_UPDATE_DELETE_FALLBACK_SQLITE_SEQUENCE
                .fetch_add(1, AtomicOrdering::Relaxed);
        }
        PreparedUpdateDeleteFallbackReason::WithoutRowid => {
            FSQLITE_PREPARED_UPDATE_DELETE_FALLBACK_WITHOUT_ROWID
                .fetch_add(1, AtomicOrdering::Relaxed);
        }
        PreparedUpdateDeleteFallbackReason::LiveVtab => {
            FSQLITE_PREPARED_UPDATE_DELETE_FALLBACK_LIVE_VTAB.fetch_add(1, AtomicOrdering::Relaxed);
        }
        PreparedUpdateDeleteFallbackReason::Trigger => {
            FSQLITE_PREPARED_UPDATE_DELETE_FALLBACK_TRIGGER.fetch_add(1, AtomicOrdering::Relaxed);
        }
        PreparedUpdateDeleteFallbackReason::ForeignKey => {
            FSQLITE_PREPARED_UPDATE_DELETE_FALLBACK_FOREIGN_KEY
                .fetch_add(1, AtomicOrdering::Relaxed);
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct PreparedUpdateDeleteFastPath {
    kind: PreparedDmlKind,
    rollback_on_constraint_violation: bool,
    preserve_prior_changes_on_constraint_violation: bool,
    static_fallback_reason: Option<PreparedUpdateDeleteFallbackReason>,
    foreign_key_work: bool,
}

impl PreparedUpdateDeleteFastPath {
    fn supports_direct_dispatch_now(&self, conn: &Connection) -> bool {
        if let Some(reason) = self.static_fallback_reason {
            record_prepared_update_delete_fallback(reason);
            return false;
        }
        if self.foreign_key_work && conn.fk_cascade_propagation_enabled() {
            record_prepared_update_delete_fallback(PreparedUpdateDeleteFallbackReason::ForeignKey);
            return false;
        }
        true
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum PreparedInsertPostWriteAction {
    None,
    RefreshSqliteSequenceCache,
    RefreshAutoincrementSequence,
}

#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
struct TableExecutionRuntimeRequirements {
    autoincrement_root_page: Option<i32>,
    needs_column_defaults: bool,
}

impl TableExecutionRuntimeRequirements {
    const fn read_path() -> Self {
        Self {
            autoincrement_root_page: None,
            needs_column_defaults: true,
        }
    }

    const fn write_path(autoincrement_root_page: Option<i32>, needs_column_defaults: bool) -> Self {
        Self {
            autoincrement_root_page,
            needs_column_defaults,
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct PreparedPrecompiledDml {
    kind: PreparedDmlKind,
    table_name: String,
    post_write_action: PreparedInsertPostWriteAction,
    rollback_on_constraint_violation: bool,
    preserve_prior_changes_on_constraint_violation: bool,
    runtime_requirements: TableExecutionRuntimeRequirements,
}

#[derive(Debug, Clone)]
enum PreparedDmlDispatch {
    /// Fall back to the full statement pipeline. This can still reuse a cached
    /// compiled program when `db` is populated, but it keeps the AST around for
    /// trigger/FK/materialization paths that still need statement structure.
    Deferred(Arc<Statement>),
    /// Execute through a dedicated prepared-DML helper that reuses the cached
    /// program without keeping the full AST alive.
    Precompiled(PreparedPrecompiledDml),
}

#[derive(Clone)]
struct PreparedStatementTemplate {
    canonical_sql: String,
    program: Arc<VdbeProgram>,
    expression_postprocess: Option<ExpressionPostprocess>,
    distinct: bool,
    table_backed: bool,
    post_distinct_limit: Option<LimitClause>,
    schema_cookie: u32,
    schema_generation: u64,
    dml_dispatch: Option<PreparedDmlDispatch>,
    prepared_update_delete_fast_path: Option<PreparedUpdateDeleteFastPath>,
    deferred_query_statement: Option<Arc<Statement>>,
    deferred_query_column_count: Option<usize>,
    column_names: Vec<String>,
}

impl PreparedStatementTemplate {
    fn from_statement(stmt: &PreparedStatement<'_>) -> Self {
        Self {
            canonical_sql: stmt.sql.clone(),
            program: Arc::clone(&stmt.program),
            expression_postprocess: stmt.expression_postprocess.clone(),
            distinct: stmt.distinct,
            table_backed: stmt.db.is_some(),
            post_distinct_limit: stmt.post_distinct_limit.clone(),
            schema_cookie: stmt.schema_cookie,
            schema_generation: stmt.schema_generation,
            dml_dispatch: stmt.dml_dispatch.clone(),
            prepared_update_delete_fast_path: stmt.prepared_update_delete_fast_path.clone(),
            deferred_query_statement: stmt.deferred_query_statement.clone(),
            deferred_query_column_count: stmt.deferred_query_column_count,
            column_names: stmt.column_names.clone(),
        }
    }

    fn instantiate<'conn>(&self, conn: &'conn Connection) -> PreparedStatement<'conn> {
        PreparedStatement {
            sql: self.canonical_sql.clone(),
            program: Arc::clone(&self.program),
            func_registry: Some(Arc::clone(&*conn.func_registry.borrow())),
            expression_postprocess: self.expression_postprocess.clone(),
            distinct: self.distinct,
            db: self.table_backed.then(|| Rc::clone(&conn.db)),
            pager: self.table_backed.then(|| conn.pager.clone()),
            post_distinct_limit: self.post_distinct_limit.clone(),
            schema_cookie: self.schema_cookie,
            schema_generation: self.schema_generation,
            dml_dispatch: self.dml_dispatch.clone(),
            prepared_update_delete_fast_path: self.prepared_update_delete_fast_path.clone(),
            deferred_query_statement: self.deferred_query_statement.clone(),
            deferred_query_column_count: self.deferred_query_column_count,
            column_names: self.column_names.clone(),
            conn,
        }
    }
}

#[derive(Clone)]
struct PreparedCacheEntry {
    sql: String,
    template: PreparedStatementTemplate,
}

pub struct PreparedStatement<'conn> {
    sql: String,
    program: Arc<VdbeProgram>,
    func_registry: Option<Arc<FunctionRegistry>>,
    expression_postprocess: Option<ExpressionPostprocess>,
    distinct: bool,
    /// For table-backed SELECT, the statement must execute against the same
    /// MemDatabase as the Connection that prepared it.
    db: Option<Rc<RefCell<MemDatabase>>>,
    /// Phase 5 (bd-35my): pager backend for starting transactions during query.
    /// Needed because PreparedStatement::query() executes independently of the
    /// Connection's transaction state.
    pager: Option<PagerBackend>,
    /// For table-backed `SELECT DISTINCT ... LIMIT/OFFSET`, we compile an
    /// unbounded program and apply the LIMIT/OFFSET after de-duplication.
    ///
    /// This mirrors `Connection::execute_statement`'s distinct+limit handling
    /// to avoid returning too few rows when LIMIT is applied before DISTINCT.
    post_distinct_limit: Option<LimitClause>,
    /// Schema cookie captured at prepare time (bd-3mmj). Used by the
    /// engine's `ReadCookie` opcode and prepared-statement invalidation.
    schema_cookie: u32,
    /// Local schema-generation marker captured at prepare time so prepared
    /// statements invalidate on same-connection DDL before any memdb reload.
    schema_generation: u64,
    /// DML execution path metadata for prepared statements. Some statements
    /// still need the parsed AST at execution time, while others can run from
    /// the cached bytecode plus a small amount of dispatch metadata.
    dml_dispatch: Option<PreparedDmlDispatch>,
    /// Prepare-time fast-path metadata for UPDATE/DELETE statements that keep
    /// the AST as a generic fallback but can skip repeated eligibility scans.
    prepared_update_delete_fast_path: Option<PreparedUpdateDeleteFastPath>,
    /// For SELECT statements that cannot be safely precompiled because they
    /// depend on connection-level fallback routing or parameter-sensitive
    /// subquery rewriting, store the AST and re-dispatch at execution time.
    deferred_query_statement: Option<Arc<Statement>>,
    /// Cached column count for deferred SELECT statements whose placeholder
    /// program does not contain a `ResultRow` opcode.
    deferred_query_column_count: Option<usize>,
    /// Best-effort result column labels inferred at prepare time for SELECT
    /// statements so higher layers can expose stable metadata.
    column_names: Vec<String>,
    /// Reference to the parent Connection that prepared this statement.
    /// Used by `execute_with_params` to delegate DML execution through
    /// the Connection's full execution pipeline (triggers, constraints,
    /// autocommit).
    conn: &'conn Connection,
}

#[derive(Debug, Clone, Default)]
struct ExpressionPostprocess {
    order_by: Vec<OrderingTerm>,
    limit: Option<LimitClause>,
    output_aliases: HashMap<String, usize>,
    output_width: usize,
}

#[derive(Debug, Clone, Copy)]
struct ResolvedOrderTerm {
    column_index: usize,
    descending: bool,
    nulls_order: NullsOrder,
}

/// Compatibility mask for sqlite3_trace_v2-style callbacks.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct TraceMask(u32);

impl TraceMask {
    pub const STMT: Self = Self(0x01);
    pub const PROFILE: Self = Self(0x02);
    pub const ROW: Self = Self(0x04);
    pub const CLOSE: Self = Self(0x08);
    pub const ALL: Self = Self(Self::STMT.0 | Self::PROFILE.0 | Self::ROW.0 | Self::CLOSE.0);

    #[must_use]
    pub const fn contains(self, other: Self) -> bool {
        (self.0 & other.0) != 0
    }
}

impl std::ops::BitOr for TraceMask {
    type Output = Self;

    fn bitor(self, rhs: Self) -> Self::Output {
        Self(self.0 | rhs.0)
    }
}

/// sqlite3_trace_v2-style callback event payload.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum TraceEvent {
    /// Statement text about to execute.
    Statement { sql: String },
    /// Statement execution profile (nanoseconds).
    Profile { sql: String, elapsed_ns: u64 },
    /// Row delivered to the client.
    Row { values: Vec<SqliteValue> },
    /// Connection close lifecycle event.
    Close,
}

impl TraceEvent {
    #[must_use]
    fn callback_type(&self) -> &'static str {
        match self {
            Self::Statement { .. } => "stmt",
            Self::Profile { .. } => "profile",
            Self::Row { .. } => "row",
            Self::Close => "close",
        }
    }

    #[must_use]
    fn required_mask(&self) -> TraceMask {
        match self {
            Self::Statement { .. } => TraceMask::STMT,
            Self::Profile { .. } => TraceMask::PROFILE,
            Self::Row { .. } => TraceMask::ROW,
            Self::Close => TraceMask::CLOSE,
        }
    }
}

/// Callback signature for sqlite3_trace_v2 compatibility.
pub type TraceCallback = Arc<dyn Fn(TraceEvent) + Send + Sync + 'static>;

#[derive(Clone)]
struct TraceRegistration {
    mask: TraceMask,
    callback: TraceCallback,
}

fn emit_compat_trace_event(trace: Option<&TraceRegistration>, event: TraceEvent) {
    let Some(trace) = trace else {
        return;
    };
    if !trace.mask.contains(event.required_mask()) {
        return;
    }

    let callback_type = event.callback_type();
    record_compat_trace_callback();
    if tracing::enabled!(target: "fsqlite.compat_trace", tracing::Level::DEBUG) {
        let span = tracing::span!(
            target: "fsqlite.compat_trace",
            tracing::Level::DEBUG,
            "compat_trace",
            callback_type
        );
        record_trace_span_created();
        let _guard = span.enter();
        (trace.callback)(event);
        tracing::debug!(callback_type, "sqlite3_trace_v2 callback emitted");
    } else {
        (trace.callback)(event);
    }
}

impl std::fmt::Debug for PreparedStatement<'_> {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("PreparedStatement")
            .field("sql", &self.sql)
            .field("program", &self.program)
            .finish_non_exhaustive()
    }
}

impl PreparedStatement<'_> {
    fn requires_schema_validation(&self) -> bool {
        self.db.is_some() || self.dml_dispatch.is_some() || self.deferred_query_statement.is_some()
    }

    fn requires_external_schema_refresh(&self) -> bool {
        self.requires_schema_validation()
            && !self.conn.pager.is_memory()
            && self.conn.active_txn.borrow().is_none()
    }

    fn can_use_lightweight_external_schema_refresh(&self) -> bool {
        self.db.is_some()
            && self.deferred_query_statement.is_none()
            && self.deferred_dml_statement().is_none()
    }

    fn dispatch_precompiled_program(&self) -> Option<&VdbeProgram> {
        if self.deferred_dml_statement().is_some() && self.db.is_some() {
            Some(self.program.as_ref())
        } else {
            None
        }
    }

    fn deferred_dml_statement(&self) -> Option<&Statement> {
        match self.dml_dispatch.as_ref() {
            Some(PreparedDmlDispatch::Deferred(statement)) => Some(statement.as_ref()),
            Some(PreparedDmlDispatch::Precompiled(_)) | None => None,
        }
    }

    fn precompiled_dml(&self) -> Option<&PreparedPrecompiledDml> {
        match self.dml_dispatch.as_ref() {
            Some(PreparedDmlDispatch::Precompiled(dispatch)) => Some(dispatch),
            Some(PreparedDmlDispatch::Deferred(_)) | None => None,
        }
    }

    fn prepared_update_delete_fast_path(&self) -> Option<&PreparedUpdateDeleteFastPath> {
        self.prepared_update_delete_fast_path.as_ref()
    }

    fn ensure_schema_unchanged(&self, cx: &Cx) -> Result<()> {
        let _ = self.ensure_schema_unchanged_with_prebound_publication(cx)?;
        Ok(())
    }

    fn ensure_schema_unchanged_with_prebound_publication(
        &self,
        cx: &Cx,
    ) -> Result<Option<BoundPagerPublication>> {
        let prebound_publication = if self.requires_external_schema_refresh() {
            self.conn.refresh_prepared_schema_state(
                cx,
                self.can_use_lightweight_external_schema_refresh(),
            )?
        } else {
            None
        };
        if self.requires_schema_validation()
            && (self.conn.schema_cookie() != self.schema_cookie
                || self.conn.schema_generation() != self.schema_generation)
        {
            let invalidate_reason = if self.conn.schema_cookie() != self.schema_cookie {
                "schema_cookie_changed"
            } else {
                "schema_generation_changed"
            };
            let failure_diag = format!(
                "prepared_schema_identity={} current_schema_identity={}",
                format_schema_identity(self.schema_cookie, self.schema_generation),
                self.conn.current_schema_identity()
            );
            self.conn.log_statement_reuse_event(
                "prepared_schema_validation",
                &self.sql,
                false,
                invalidate_reason,
                0,
                0,
                failure_diag.as_str(),
            );
            return Err(FrankenError::SchemaChanged);
        }
        Ok(prebound_publication)
    }

    /// Returns `true` if this prepared statement is a DML statement
    /// (INSERT/UPDATE/DELETE).
    pub fn is_dml(&self) -> bool {
        self.dml_dispatch.is_some()
    }

    fn execute_table_program_with_reuse(
        &self,
        op_cx: &Cx,
        params: Option<&[SqliteValue]>,
        track_last_insert_rowid: bool,
    ) -> Result<(Vec<Row>, usize, Option<i64>)> {
        self.execute_table_program_with_reuse_mode(op_cx, params, track_last_insert_rowid, true)
    }

    fn execute_table_program_dml_with_reuse(
        &self,
        op_cx: &Cx,
        params: Option<&[SqliteValue]>,
        track_last_insert_rowid: bool,
    ) -> Result<(usize, Option<i64>)> {
        self.execute_table_program_with_reuse_mode(op_cx, params, track_last_insert_rowid, false)
            .map(|(_, changes, last_insert_rowid)| (changes, last_insert_rowid))
    }

    fn execute_table_program_with_reuse_mode(
        &self,
        op_cx: &Cx,
        params: Option<&[SqliteValue]>,
        track_last_insert_rowid: bool,
        collect_rows: bool,
    ) -> Result<(Vec<Row>, usize, Option<i64>)> {
        let Some(db) = self.db.as_ref() else {
            return Err(FrankenError::Internal(
                "prepared table program missing database handle".to_owned(),
            ));
        };
        let Some(func_registry) = self.func_registry.as_ref() else {
            return Err(FrankenError::Internal(
                "prepared table program missing function registry".to_owned(),
            ));
        };
        let page_size = PageSize::new(self.conn.pragma_state.borrow().page_size).unwrap();

        let execution_span = tracing::enabled!(target: "fsqlite.execution", tracing::Level::DEBUG)
            .then(|| {
                let span = tracing::span!(
                    target: "fsqlite.execution",
                    tracing::Level::DEBUG,
                    "execution",
                    mode = "table"
                );
                record_trace_span_created();
                span
            });
        let _execution_guard = execution_span.as_ref().map(tracing::Span::enter);

        let reject_mem = *self.conn.reject_mem_fallback.borrow();
        let runtime_requirements = self
            .precompiled_dml()
            .map_or(TableExecutionRuntimeRequirements::read_path(), |dispatch| {
                dispatch.runtime_requirements
            });
        let runtime_inputs = self
            .conn
            .table_execution_runtime_inputs(runtime_requirements);
        let cookie = *self.conn.schema_cookie.borrow();
        let had_active_txn = self.conn.active_txn.borrow().is_some();

        let (result, txn_back) = if had_active_txn {
            let txn = self.conn.active_txn.borrow_mut().take();
            let concurrent_ctx = if *self.conn.concurrent_txn.borrow() {
                let session_id = (*self.conn.concurrent_session_id.borrow()).ok_or_else(|| {
                    FrankenError::Internal(
                        "concurrent transaction missing session during prepared VDBE setup"
                            .to_owned(),
                    )
                })?;
                let handle = lock_unpoisoned(&self.conn.concurrent_registry)
                    .handle(session_id)
                    .ok_or_else(|| {
                        FrankenError::Internal(
                            "concurrent transaction missing handle during prepared VDBE setup"
                                .to_owned(),
                        )
                    })?;
                Some(ConcurrentExecContext {
                    session_id,
                    handle,
                    lock_table: Arc::clone(&self.conn.concurrent_lock_table),
                    commit_index: Arc::clone(&self.conn.concurrent_commit_index),
                    #[allow(clippy::cast_sign_loss)]
                    busy_timeout_ms: self.conn.pragma_state.borrow().busy_timeout_ms.max(0) as u64,
                })
            } else {
                None
            };

            let cached = self.conn.cached_vdbe_engine.borrow_mut().take();
            let ((result, txn_back), engine_back) = execute_table_program_with_db(
                self.program.as_ref(),
                params,
                func_registry,
                &self.conn.collation_registry,
                op_cx,
                db,
                txn,
                cookie,
                concurrent_ctx,
                runtime_inputs.autoincrement_seq_by_root_page,
                runtime_inputs.rowid_alias_col_by_root_page,
                runtime_inputs.table_column_count_by_root_page,
                runtime_inputs.column_defaults_by_root_page,
                runtime_inputs.index_desc_flags_by_root_page,
                reject_mem,
                Some(Arc::clone(&self.conn.version_store)),
                page_size,
                collect_rows,
                true,
                cached,
            );
            *self.conn.cached_vdbe_engine.borrow_mut() = engine_back;
            (result, txn_back)
        } else {
            let txn = self
                .pager
                .as_ref()
                .map(|p| {
                    self.conn
                        .begin_pager_txn_with_busy_timeout(p, op_cx, TransactionMode::ReadOnly)
                })
                .transpose()?;
            let cached = self.conn.cached_vdbe_engine.borrow_mut().take();
            let ((result, txn_back), engine_back) = execute_table_program_with_db(
                self.program.as_ref(),
                params,
                func_registry,
                &self.conn.collation_registry,
                op_cx,
                db,
                txn,
                cookie,
                None,
                runtime_inputs.autoincrement_seq_by_root_page,
                runtime_inputs.rowid_alias_col_by_root_page,
                runtime_inputs.table_column_count_by_root_page,
                runtime_inputs.column_defaults_by_root_page,
                runtime_inputs.index_desc_flags_by_root_page,
                reject_mem,
                Some(Arc::clone(&self.conn.version_store)),
                page_size,
                collect_rows,
                true,
                cached,
            );
            *self.conn.cached_vdbe_engine.borrow_mut() = engine_back;
            (result, txn_back)
        };

        if had_active_txn {
            *self.conn.active_txn.borrow_mut() = txn_back;
        } else if let Some(mut txn) = txn_back {
            txn.commit(op_cx)?;
        }

        match result {
            Ok((rows, changes, last_insert_rowid)) => {
                self.conn.clear_table_program_error_state();
                if track_last_insert_rowid && let Some(last_insert_rowid) = last_insert_rowid {
                    self.conn
                        .set_last_insert_rowid_without_sync(last_insert_rowid);
                }
                Ok((
                    rows,
                    changes,
                    if track_last_insert_rowid {
                        last_insert_rowid
                    } else {
                        None
                    },
                ))
            }
            Err(exec_error) => {
                self.conn.record_table_program_error_state(
                    exec_error.changes,
                    if track_last_insert_rowid {
                        exec_error.last_insert_rowid
                    } else {
                        None
                    },
                );
                Err(exec_error.error)
            }
        }
    }

    fn execute_table_query(&self, op_cx: &Cx, params: Option<&[SqliteValue]>) -> Result<Vec<Row>> {
        self.execute_table_program_with_reuse(op_cx, params, false)
            .map(|(rows, ..)| rows)
    }

    /// Execute as a query and return all result rows.
    pub fn query(&self) -> Result<Vec<Row>> {
        let _record_profile_scope = enter_record_profile_scope(RecordProfileScope::CoreConnection);
        if self.dml_dispatch.is_some() {
            return Err(FrankenError::Internal(
                "DML prepared statements must be executed through \
                 Connection::execute_prepared() or Connection::execute_prepared_with_params()"
                    .to_owned(),
            ));
        }
        self.conn.background_status()?;
        self.conn.sync_change_tracking_context();
        let op_cx = self.conn.op_cx_after_background_status();
        self.ensure_schema_unchanged(&op_cx)?;
        if let Some(statement) = &self.deferred_query_statement {
            return self
                .conn
                .execute_statement_after_background_status(statement.as_ref(), None);
        }
        let mut rows = if self.db.is_some() {
            self.execute_table_query(&op_cx, None)?
        } else {
            execute_program_with_postprocess(
                self.program.as_ref(),
                None,
                self.func_registry.as_ref(),
                Some(&self.conn.collation_registry),
                &op_cx,
                self.expression_postprocess.as_ref(),
                PageSize::new(self.conn.pragma_state.borrow().page_size).unwrap(),
            )?
        };
        if self.distinct {
            dedup_rows(&mut rows);
        }
        if let Some(limit_clause) = self.post_distinct_limit.as_ref() {
            apply_limit_clause(&mut rows, limit_clause);
        }
        Ok(rows)
    }

    /// Execute as a query with bound SQL parameters (`?1`, `?2`, ...).
    pub fn query_with_params(&self, params: &[SqliteValue]) -> Result<Vec<Row>> {
        let _record_profile_scope = enter_record_profile_scope(RecordProfileScope::CoreConnection);
        if self.dml_dispatch.is_some() {
            return Err(FrankenError::Internal(
                "DML prepared statements must be executed through \
                 Connection::execute_prepared() or Connection::execute_prepared_with_params()"
                    .to_owned(),
            ));
        }
        self.conn.background_status()?;
        self.conn.sync_change_tracking_context();
        let op_cx = self.conn.op_cx_after_background_status();
        self.ensure_schema_unchanged(&op_cx)?;
        if let Some(statement) = &self.deferred_query_statement {
            return self
                .conn
                .execute_statement_after_background_status(statement.as_ref(), Some(params));
        }
        let mut rows = if self.db.is_some() {
            self.execute_table_query(&op_cx, Some(params))?
        } else {
            execute_program_with_postprocess(
                self.program.as_ref(),
                Some(params),
                self.func_registry.as_ref(),
                Some(&self.conn.collation_registry),
                &op_cx,
                self.expression_postprocess.as_ref(),
                PageSize::new(self.conn.pragma_state.borrow().page_size).unwrap(),
            )?
        };
        if self.distinct {
            dedup_rows(&mut rows);
        }
        if let Some(limit_clause) = self.post_distinct_limit.as_ref() {
            apply_limit_clause(&mut rows, limit_clause);
        }
        Ok(rows)
    }

    /// Execute as a query and return exactly one row.
    pub fn query_row(&self) -> Result<Row> {
        exactly_one_row_or_error(self.query()?)
    }

    /// Execute as a query with parameters and return exactly one row.
    pub fn query_row_with_params(&self, params: &[SqliteValue]) -> Result<Row> {
        exactly_one_row_or_error(self.query_with_params(params)?)
    }

    /// Return the number of columns this statement will produce per row.
    #[must_use]
    pub fn column_count(&self) -> usize {
        if let Some(column_count) = self.deferred_query_column_count {
            return column_count;
        }
        self.program
            .ops()
            .iter()
            .find(|op| op.opcode == Opcode::ResultRow)
            .and_then(|op| usize::try_from(op.p2).ok())
            .unwrap_or(0)
    }

    /// Return best-effort result column labels inferred at prepare time.
    #[must_use]
    pub fn column_names(&self) -> &[String] {
        &self.column_names
    }

    /// Execute and return affected/output row count.
    ///
    /// For DML statements (INSERT/UPDATE/DELETE), this delegates to the
    /// parent Connection's execution pipeline, which handles triggers,
    /// constraints, and autocommit.  For SELECT statements, this returns
    /// the number of result rows.
    pub fn execute(&self) -> Result<usize> {
        if self.dml_dispatch.is_some() {
            return self.conn.execute_prepared(self);
        }
        Ok(self.query()?.len())
    }

    /// Execute with bound SQL parameters and return affected/output row count.
    ///
    /// For DML statements (INSERT/UPDATE/DELETE), this delegates to the
    /// parent Connection's execution pipeline, which handles triggers,
    /// constraints, and autocommit.  For SELECT statements, this returns
    /// the number of result rows.
    pub fn execute_with_params(&self, params: &[SqliteValue]) -> Result<usize> {
        if self.dml_dispatch.is_some() {
            return self.conn.execute_prepared_with_params(self, params);
        }
        Ok(self.query_with_params(params)?.len())
    }

    /// Return an EXPLAIN-style disassembly for the compiled program.
    pub fn explain(&self) -> String {
        if self.deferred_query_statement.is_some() {
            return "-- prepared SELECT is dispatched dynamically; no precompiled bytecode"
                .to_owned();
        }
        self.program.disassemble()
    }
}

/// A stored view definition: name + SELECT query.
#[derive(Debug, Clone)]
struct ViewDef {
    name: String,
    #[allow(dead_code)]
    columns: Vec<String>,
    query: SelectStatement,
}

/// Connection-local differential stream events emitted to subscribers.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum DifferentialEvent {
    /// Initial bootstrap payload captured at a committed MVCC snapshot.
    Snapshot {
        subscriber_id: u64,
        view_name: String,
        snapshot_seq: u64,
        next_commit_seq: u64,
        rows: Vec<Row>,
    },
    /// Placeholder stream mode until table-level differential routing lands.
    Invalidation {
        subscriber_id: u64,
        view_name: String,
        commit_seq: u64,
    },
}

/// Public status snapshot for one active differential subscriber.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct DifferentialSubscriberStatus {
    pub subscriber_id: u64,
    pub view_name: String,
    pub snapshot_seq: u64,
    pub next_commit_seq: u64,
    pub bootstrap_row_count: usize,
}

#[derive(Clone)]
struct DifferentialSubscriber {
    id: u64,
    view_name: String,
    #[allow(dead_code)]
    view_query: SelectStatement,
    snapshot_seq: CommitSeq,
    stream_begin_seq: CommitSeq,
    bootstrap_row_count: usize,
    sender: mpsc::Sender<DifferentialEvent>,
}

#[derive(Default)]
struct DifferentialRegistry {
    next_subscriber_id: AtomicU64,
    subscribers: Mutex<HashMap<u64, DifferentialSubscriber>>,
    snapshot_bootstraps_total: AtomicU64,
    fallback_invalidations_total: AtomicU64,
}

/// A stored trigger definition captured from `CREATE TRIGGER`.
#[derive(Debug, Clone)]
struct TriggerDef {
    name: String,
    table_name: String,
    timing: fsqlite_ast::TriggerTiming,
    event: fsqlite_ast::TriggerEvent,
    #[allow(dead_code)] // SQLite-only: always true; retained for display/roundtrip fidelity.
    for_each_row: bool,
    when_clause: Option<Expr>,
    body: Vec<Statement>,
    temporary: bool,
    create_sql: String,
}

impl TriggerDef {
    fn from_create_statement(
        stmt: &fsqlite_ast::CreateTriggerStatement,
        create_sql: String,
    ) -> Self {
        Self {
            name: stmt.name.name.clone(),
            table_name: stmt.table.clone(),
            timing: stmt.timing,
            event: stmt.event.clone(),
            for_each_row: stmt.for_each_row,
            when_clause: stmt.when.clone(),
            body: stmt.body.clone(),
            temporary: stmt.temporary,
            create_sql,
        }
    }
}

#[derive(Debug, Clone)]
struct TriggerFrame {
    table_name: String,
    column_names: Vec<String>,
    rowid_alias_col_idx: Option<usize>,
    old_row: Option<Vec<SqliteValue>>,
    new_row: Option<Vec<SqliteValue>>,
}

impl TriggerFrame {
    fn column_index(&self, column_name: &str) -> Option<usize> {
        self.column_names
            .iter()
            .position(|name| name.eq_ignore_ascii_case(column_name))
    }

    fn references_pseudo_column(&self, table_prefix: Option<&str>, column_name: &str) -> bool {
        let hidden_rowid = self.hidden_rowid_column_index(column_name);
        if self.column_index(column_name).is_none() && hidden_rowid.is_none() {
            return false;
        }
        match table_prefix {
            Some(prefix) => {
                prefix.eq_ignore_ascii_case("old")
                    || prefix.eq_ignore_ascii_case("new")
                    || prefix.eq_ignore_ascii_case(&self.table_name)
            }
            // Bare column references (no table prefix) resolve to NEW/OLD
            // in trigger SELECT bodies (e.g. SELECT RAISE(...) WHERE val > 10).
            // DML trigger bodies (UPDATE/DELETE/INSERT) use the dedicated
            // `bind_trigger_prefixed_only_in_expr` which skips bare names so
            // they resolve against the DML's target table instead.
            None => true,
        }
    }

    fn lookup_value(&self, table_prefix: Option<&str>, column_name: &str) -> Option<SqliteValue> {
        let column_index = self
            .column_index(column_name)
            .or_else(|| self.hidden_rowid_column_index(column_name))?;
        match table_prefix {
            Some(prefix) if prefix.eq_ignore_ascii_case("old") => {
                Self::lookup_from_row(self.old_row.as_deref(), column_index)
            }
            Some(prefix) if prefix.eq_ignore_ascii_case("new") => {
                Self::lookup_from_row(self.new_row.as_deref(), column_index)
            }
            Some(prefix) if prefix.eq_ignore_ascii_case(&self.table_name) => self
                .new_row
                .as_ref()
                .and_then(|row| row.get(column_index).cloned())
                .or_else(|| Self::lookup_from_row(self.old_row.as_deref(), column_index)),
            Some(_) => None,
            None => self
                .new_row
                .as_ref()
                .and_then(|row| row.get(column_index).cloned())
                .or_else(|| Self::lookup_from_row(self.old_row.as_deref(), column_index)),
        }
    }

    fn lookup_from_row(row: Option<&[SqliteValue]>, column_index: usize) -> Option<SqliteValue> {
        row.and_then(|values| values.get(column_index).cloned())
    }

    fn hidden_rowid_column_index(&self, column_name: &str) -> Option<usize> {
        self.column_index(column_name)
            .is_none()
            .then_some(self.rowid_alias_col_idx)
            .flatten()
            .filter(|_| is_rowid_alias(column_name))
    }
}

struct TriggerFrameGuard<'a> {
    stack: &'a RefCell<Vec<TriggerFrame>>,
}

impl Drop for TriggerFrameGuard<'_> {
    fn drop(&mut self) {
        let _ = self.stack.borrow_mut().pop();
    }
}

struct StatementSavepointDepthGuard<'a> {
    depth: &'a Cell<usize>,
}

impl Drop for StatementSavepointDepthGuard<'_> {
    fn drop(&mut self) {
        self.depth.set(self.depth.get().saturating_sub(1));
    }
}

/// Check if a trigger event matches a DML event.
///
/// For INSERT/DELETE, this is an exact match.
/// For UPDATE, the trigger event must either be `Update([])` (any column) or
/// `Update([cols])` where at least one of the specified columns is being updated.
fn trigger_event_matches(
    trigger_event: &fsqlite_ast::TriggerEvent,
    dml_event: &fsqlite_ast::TriggerEvent,
) -> bool {
    use fsqlite_ast::TriggerEvent;
    match (trigger_event, dml_event) {
        (TriggerEvent::Insert, TriggerEvent::Insert)
        | (TriggerEvent::Delete, TriggerEvent::Delete) => true,
        (TriggerEvent::Update(trigger_cols), TriggerEvent::Update(dml_cols)) => {
            // If trigger specifies no columns (UPDATE OF <nothing>), match any UPDATE.
            if trigger_cols.is_empty() {
                return true;
            }
            // If DML specifies no columns, treat as "all columns" - match any trigger.
            if dml_cols.is_empty() {
                return true;
            }
            // Otherwise, check if any trigger column is in the DML column list.
            trigger_cols
                .iter()
                .any(|tc| dml_cols.iter().any(|dc| tc.eq_ignore_ascii_case(dc)))
        }
        _ => false,
    }
}

/// Evaluate a trigger WHEN clause against the current OLD/NEW frame.
///
/// Unsupported expression shapes still default to firing so trigger behavior
/// remains conservative until the evaluator covers the full trigger surface.
fn trigger_when_matches(when_clause: Option<&Expr>, frame: Option<&TriggerFrame>) -> Result<bool> {
    let Some(expr) = when_clause else {
        return Ok(true);
    };
    let mut bound_expr = expr.clone();
    if let Some(active_frame) = frame {
        bind_trigger_columns_in_expr(&mut bound_expr, active_frame);
    }
    let row: [SqliteValue; 0] = [];
    let col_map: [(String, String, bool); 0] = [];
    match eval_join_expr(&bound_expr, &row, &col_map) {
        Ok(value) => Ok(is_sqlite_truthy(&value)),
        Err(FrankenError::NotImplemented(_)) => Ok(true),
        Err(error) => Err(error),
    }
}

/// For `UPDATE OF col1, col2` triggers, ensure at least one listed column
/// actually changed between OLD and NEW snapshots.
#[derive(Debug, Clone)]
struct TriggerRaiseDirective {
    action: fsqlite_ast::RaiseAction,
    message: Option<String>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum TriggerStatementOutcome {
    Continue,
    SkipDml,
}

/// Describes the action to take when a FK-referenced parent row is deleted.
#[allow(dead_code)]
enum FkDeleteAction {
    /// No child rows reference this parent — deletion is allowed.
    Allow,
    /// Child rows exist and ON DELETE CASCADE is specified.
    Cascade {
        child_table: String,
        child_columns: Vec<String>,
        parent_values: Vec<SqliteValue>,
    },
    /// Child rows exist and ON DELETE SET NULL is specified.
    SetNull {
        child_table: String,
        child_columns: Vec<String>,
        parent_values: Vec<SqliteValue>,
    },
}

/// Describes the action to take when a FK-referenced parent row is updated.
#[allow(dead_code)]
enum FkUpdateAction {
    Allow,
    Cascade {
        child_table: String,
        child_columns: Vec<String>,
        old_parent_values: Vec<SqliteValue>,
        new_parent_values: Vec<SqliteValue>,
    },
    SetNull {
        child_table: String,
        child_columns: Vec<String>,
        old_parent_values: Vec<SqliteValue>,
    },
}

fn trigger_statement_raise_directive(
    statement: &Statement,
) -> Result<Option<TriggerRaiseDirective>> {
    let Statement::Select(select) = statement else {
        return Ok(None);
    };
    if select.with.is_some() || !select.order_by.is_empty() || select.limit.is_some() {
        return Ok(None);
    }
    if !select.body.compounds.is_empty() {
        return Ok(None);
    }

    let SelectCore::Select {
        columns,
        from,
        where_clause,
        group_by,
        having,
        windows,
        ..
    } = &select.body.select
    else {
        return Ok(None);
    };
    if from.is_some() || !group_by.is_empty() || having.is_some() || !windows.is_empty() {
        return Ok(None);
    }
    if columns.len() != 1 {
        return Ok(None);
    }

    let ResultColumn::Expr {
        expr: Expr::Raise {
            action, message, ..
        },
        ..
    } = &columns[0]
    else {
        return Ok(None);
    };

    if let Some(predicate) = where_clause {
        let row: [SqliteValue; 0] = [];
        let col_map: [(String, String, bool); 0] = [];
        let predicate_val = eval_join_expr(predicate, &row, &col_map)?;
        if !is_sqlite_truthy(&predicate_val) {
            return Ok(None);
        }
    }

    Ok(Some(TriggerRaiseDirective {
        action: *action,
        message: message.clone(),
    }))
}

/// Returns true if the statement is a `SELECT RAISE(...)` (with or without a
/// WHERE clause).  Used by `execute_bound_trigger_statement` to skip
/// RAISE-containing SELECTs whose WHERE clause evaluated to false.
fn statement_is_raise_select(statement: &Statement) -> bool {
    let Statement::Select(select) = statement else {
        return false;
    };
    let SelectCore::Select { columns, .. } = &select.body.select else {
        return false;
    };
    columns.len() == 1
        && matches!(
            &columns[0],
            ResultColumn::Expr {
                expr: Expr::Raise { .. },
                ..
            }
        )
}

