    // ── Parse cache helpers (br-legjy.7.3) ─────────────────────────────

    /// Compute a 64-bit hash of an SQL string for parse cache lookup.
    fn sql_hash(sql: &str) -> u64 {
        use std::hash::BuildHasher;
        foldhash::fast::FixedState::default().hash_one(sql)
    }

    /// Return a cached parsed single statement, or parse fresh and cache it.
    /// The cache is invalidated whenever the schema cookie changes (DDL).
    fn cached_parse_single(&self, sql: &str) -> Result<std::sync::Arc<Statement>> {
        let profile_enabled = hot_path_profile_enabled();
        if profile_enabled {
            FSQLITE_PARSE_SINGLE_CALLS.fetch_add(1, AtomicOrdering::Relaxed);
        }
        let key = Self::sql_hash(sql);
        self.refresh_parse_cache_if_needed(sql);
        if let Some(cached) = self.lookup_parse_cache(key, sql) {
            if profile_enabled {
                FSQLITE_PARSE_CACHE_HITS.fetch_add(1, AtomicOrdering::Relaxed);
            }
            self.log_statement_reuse_event("parse", sql, true, "none", 0, 0, "none");
            return Ok(std::sync::Arc::clone(&cached.statement));
        }
        if profile_enabled {
            FSQLITE_PARSE_CACHE_MISSES.fetch_add(1, AtomicOrdering::Relaxed);
            FSQLITE_PARSED_SQL_BYTES.fetch_add(
                u64::try_from(sql.len()).unwrap_or(u64::MAX),
                AtomicOrdering::Relaxed,
            );
        }
        let start = profile_enabled.then(Instant::now);
        let stmt = match parse_single_statement(sql) {
            Ok(stmt) => stmt,
            Err(error) => {
                let failure_diag = error.to_string();
                self.log_statement_reuse_event(
                    "parse",
                    sql,
                    false,
                    "parse_error",
                    0,
                    0,
                    failure_diag.as_str(),
                );
                return Err(error);
            }
        };
        if let Some(start) = start {
            FSQLITE_PARSE_TIME_NS.fetch_add(
                u64::try_from(start.elapsed().as_nanos()).unwrap_or(u64::MAX),
                AtomicOrdering::Relaxed,
            );
        }
        self.log_statement_reuse_event("parse", sql, false, "none", 0, 0, "none");
        Ok(std::sync::Arc::clone(
            &self.insert_parse_cache(key, sql, stmt).statement,
        ))
    }

    /// Return cached parsed multi-statement list, or parse fresh.
    /// Multi-statement SQL is less common and cache hit rate is lower,
    /// so we only cache single-statement SQL in this path.
    fn cached_parse_multi(&self, sql: &str) -> Result<Vec<std::sync::Arc<Statement>>> {
        let profile_enabled = hot_path_profile_enabled();
        if profile_enabled {
            FSQLITE_PARSE_MULTI_CALLS.fetch_add(1, AtomicOrdering::Relaxed);
        }
        // Hot path optimization for repeated single-statement execute() calls.
        // Use the same collision-safe SQL equality check as cached_parse_single.
        let key = Self::sql_hash(sql);
        self.refresh_parse_cache_if_needed(sql);
        if let Some(cached) = self.lookup_parse_cache(key, sql) {
            if profile_enabled {
                FSQLITE_PARSE_CACHE_HITS.fetch_add(1, AtomicOrdering::Relaxed);
            }
            self.log_statement_reuse_event("parse", sql, true, "none", 0, 0, "none");
            return Ok(vec![std::sync::Arc::clone(&cached.statement)]);
        }

        // For single-statement SQL, use the cache.
        if profile_enabled {
            FSQLITE_PARSE_CACHE_MISSES.fetch_add(1, AtomicOrdering::Relaxed);
            FSQLITE_PARSED_SQL_BYTES.fetch_add(
                u64::try_from(sql.len()).unwrap_or(u64::MAX),
                AtomicOrdering::Relaxed,
            );
        }
        let start = profile_enabled.then(Instant::now);
        let stmts = match parse_statements(sql) {
            Ok(stmts) => stmts,
            Err(error) => {
                let failure_diag = error.to_string();
                self.log_statement_reuse_event(
                    "parse",
                    sql,
                    false,
                    "parse_error",
                    0,
                    0,
                    failure_diag.as_str(),
                );
                return Err(error);
            }
        };
        if let Some(start) = start {
            FSQLITE_PARSE_TIME_NS.fetch_add(
                u64::try_from(start.elapsed().as_nanos()).unwrap_or(u64::MAX),
                AtomicOrdering::Relaxed,
            );
        }
        if stmts.len() == 1 {
            self.insert_parse_cache(key, sql, stmts[0].clone());
        }
        self.log_statement_reuse_event("parse", sql, false, "none", 0, 0, "none");
        Ok(stmts.into_iter().map(std::sync::Arc::new).collect())
    }

    fn refresh_parse_cache_if_needed(&self, sql: &str) {
        let current_cookie = *self.schema_cookie.borrow();
        let cached_cookie = *self.parse_cache_cookie.borrow();
        if cached_cookie != current_cookie {
            self.parse_cache.borrow_mut().clear();
            self.compiled_cache.borrow_mut().clear();
            self.prepared_cache.borrow_mut().clear();
            self.table_execution_metadata_cache.borrow_mut().take();
            *self.parse_cache_cookie.borrow_mut() = current_cookie;
            self.log_statement_reuse_event(
                "schema_invalidation",
                sql,
                false,
                "schema_cookie_changed",
                0,
                0,
                "none",
            );
        }
    }

    fn lookup_parse_cache(&self, key: u64, sql: &str) -> Option<Arc<ParseCacheEntry>> {
        let mut cache = self.parse_cache.borrow_mut();
        let entry = cache.get(&key)?;
        if entry.sql == sql {
            Some(Arc::clone(entry))
        } else {
            None
        }
    }

    fn insert_parse_cache(
        &self,
        key: u64,
        sql: &str,
        statement: Statement,
    ) -> Arc<ParseCacheEntry> {
        let mut cache = self.parse_cache.borrow_mut();
        let entry = Arc::new(ParseCacheEntry {
            sql: sql.to_owned(),
            statement: Arc::new(statement),
        });
        cache.put(key, Arc::clone(&entry));
        entry
    }

    fn lookup_prepared_cache(&self, key: u64, sql: &str) -> Option<Arc<PreparedCacheEntry>> {
        let mut cache = self.prepared_cache.borrow_mut();
        let entry = cache.get(&key)?;
        if entry.sql == sql {
            Some(Arc::clone(entry))
        } else {
            None
        }
    }

    fn insert_prepared_cache(
        &self,
        key: u64,
        sql: &str,
        stmt: &PreparedStatement<'_>,
    ) -> Arc<PreparedCacheEntry> {
        let mut cache = self.prepared_cache.borrow_mut();
        let entry = Arc::new(PreparedCacheEntry {
            sql: sql.to_owned(),
            template: PreparedStatementTemplate::from_statement(stmt),
        });
        cache.put(key, Arc::clone(&entry));
        entry
    }

    // ── bd-1dp9.6.7.2.2: Schema-scoped compiled cache ─────────────────

    /// Look up a cached compiled VdbeProgram by SQL hash.
    fn lookup_compiled_cache(&self, key: u64, sql: &str) -> Option<Arc<CompiledCacheEntry>> {
        let mut cache = self.compiled_cache.borrow_mut();
        let entry = cache.get(&key)?;
        if entry.sql == sql {
            Some(Arc::clone(entry))
        } else {
            None
        }
    }

    /// Remove a cached compiled program by SQL text, if present.
    #[allow(dead_code)]
    fn invalidate_compiled_cache(&self, sql: &str) {
        let key = Self::sql_hash(sql);
        let mut cache = self.compiled_cache.borrow_mut();
        let compiled_removed = cache.peek(&key).is_some_and(|e| e.sql == sql);
        if compiled_removed {
            cache.pop(&key);
        }
        drop(cache);

        let mut prepared_cache = self.prepared_cache.borrow_mut();
        let prepared_removed = prepared_cache.peek(&key).is_some_and(|e| e.sql == sql);
        if prepared_removed {
            prepared_cache.pop(&key);
        }
        if compiled_removed || prepared_removed {
            self.log_statement_reuse_event(
                "compiled",
                sql,
                false,
                "explicit_invalidate",
                0,
                0,
                "none",
            );
        }
    }

    /// Store a compiled VdbeProgram in the schema-scoped cache.
    fn insert_compiled_cache(
        &self,
        key: u64,
        sql: &str,
        program: VdbeProgram,
    ) -> Arc<CompiledCacheEntry> {
        let mut cache = self.compiled_cache.borrow_mut();
        let entry = Arc::new(CompiledCacheEntry {
            sql: sql.to_owned(),
            program: Arc::new(program),
        });
        cache.put(key, Arc::clone(&entry));
        entry
    }

    /// Compile a statement, using the compiled cache when possible.
    /// The `sql_key` is the hash of the canonical SQL text; `sql` is the
    /// canonical SQL text for collision safety.
    fn compile_with_cache(
        &self,
        sql_key: u64,
        sql: &str,
        compile_fn: impl FnOnce(&Self) -> Result<VdbeProgram>,
    ) -> Result<Arc<VdbeProgram>> {
        let profile_enabled = hot_path_profile_enabled();
        if let Some(cached) = self.lookup_compiled_cache(sql_key, sql) {
            if profile_enabled {
                FSQLITE_COMPILED_CACHE_HITS.fetch_add(1, AtomicOrdering::Relaxed);
            }
            self.log_statement_reuse_event("compiled", sql, true, "none", 0, 0, "none");
            return Ok(Arc::clone(&cached.program));
        }
        if profile_enabled {
            FSQLITE_COMPILED_CACHE_MISSES.fetch_add(1, AtomicOrdering::Relaxed);
        }
        let start = Instant::now();
        let program = match compile_fn(self) {
            Ok(program) => program,
            Err(error) => {
                let compile_ns = u64::try_from(start.elapsed().as_nanos()).unwrap_or(u64::MAX);
                let failure_diag = error.to_string();
                self.log_statement_reuse_event(
                    "compiled",
                    sql,
                    false,
                    "compile_error",
                    compile_ns,
                    0,
                    failure_diag.as_str(),
                );
                return Err(error);
            }
        };
        let compile_ns = u64::try_from(start.elapsed().as_nanos()).unwrap_or(u64::MAX);
        if profile_enabled {
            FSQLITE_COMPILE_TIME_NS.fetch_add(compile_ns, AtomicOrdering::Relaxed);
        }
        self.log_statement_reuse_event("compiled", sql, false, "none", compile_ns, 0, "none");
        let entry = self.insert_compiled_cache(sql_key, sql, program);
        Ok(Arc::clone(&entry.program))
    }

    // ── Internal helpers ──────────────────────────────────────────────────

    fn next_internal_savepoint_name(&self, purpose: &str) -> String {
        let mut suffix = 0_u64;
        loop {
            let candidate = format!("__fsqlite_stmt_{purpose}_{}_{}", next_trace_id(), suffix);
            let conflicts = self
                .savepoints
                .borrow()
                .iter()
                .any(|savepoint| savepoint.name.eq_ignore_ascii_case(&candidate));
            if !conflicts {
                return candidate;
            }
            suffix = suffix.saturating_add(1);
        }
    }

    fn maybe_rollback_transaction_for_conflict_action(
        &self,
        rollback_on_constraint_violation: bool,
        was_auto: bool,
        error: &FrankenError,
    ) -> Result<()> {
        if !rollback_on_constraint_violation
            || was_auto
            || !error_triggers_conflict_action_rollback(error)
        {
            return Ok(());
        }
        if !*self.in_transaction.borrow() && self.active_txn.borrow().is_none() {
            return Ok(());
        }
        let rollback_stmt = fsqlite_ast::RollbackStatement { to_savepoint: None };
        self.execute_rollback(&rollback_stmt)
    }

    fn with_internal_statement_savepoint<T>(
        &self,
        purpose: &str,
        body: impl FnOnce() -> Result<T>,
    ) -> Result<T> {
        let cx = self.op_cx()?;
        self.with_internal_statement_savepoint_and_cx(&cx, purpose, body)
    }

    fn with_internal_statement_savepoint_and_cx<T>(
        &self,
        cx: &Cx,
        purpose: &str,
        body: impl FnOnce() -> Result<T>,
    ) -> Result<T> {
        let savepoint_name = self.next_internal_savepoint_name(purpose);
        let snapshot = self.snapshot();
        self.internal_statement_savepoint_depth.set(
            self.internal_statement_savepoint_depth
                .get()
                .saturating_add(1),
        );
        let _depth_guard = StatementSavepointDepthGuard {
            depth: &self.internal_statement_savepoint_depth,
        };

        if let Some(txn) = self.active_txn.borrow_mut().as_mut() {
            txn.savepoint(cx, &savepoint_name)?;
        }

        let concurrent_snapshot = if *self.concurrent_txn.borrow() {
            let concurrent_result = (|| -> Result<Option<ConcurrentSavepoint>> {
                let session_id = self.concurrent_session_id.borrow().ok_or_else(|| {
                    FrankenError::Internal(
                        "concurrent transaction active but no session ID".to_owned(),
                    )
                })?;
                let registry = lock_unpoisoned(&self.concurrent_registry);
                let handle = registry.get(session_id).ok_or_else(|| {
                    FrankenError::Internal("concurrent session handle not found".to_owned())
                })?;
                let snapshot = concurrent_savepoint(&handle, &savepoint_name).map_err(|e| {
                    FrankenError::Internal(format!("concurrent savepoint failed: {e}"))
                })?;
                Ok(Some(snapshot))
            })();
            match concurrent_result {
                Ok(snapshot) => snapshot,
                Err(error) => {
                    let cleanup_errors =
                        self.cleanup_failed_savepoint_setup(cx, &savepoint_name, None);
                    if !cleanup_errors.is_empty() {
                        return Err(FrankenError::Internal(format!(
                            "statement savepoint setup failed after {purpose}: {error}; cleanup failed: {}",
                            cleanup_errors.join("; ")
                        )));
                    }
                    return Err(error);
                }
            }
        } else {
            None
        };
        let live_vtab_level = self.current_live_vtab_savepoint_level()?;
        if let Err(error) = self.live_vtab_savepoint_all(cx, live_vtab_level) {
            let cleanup_errors = self.cleanup_failed_savepoint_setup(
                cx,
                &savepoint_name,
                concurrent_snapshot.as_ref(),
            );
            if !cleanup_errors.is_empty() {
                return Err(FrankenError::Internal(format!(
                    "statement savepoint setup failed after {purpose}: {error}; cleanup failed: {}",
                    cleanup_errors.join("; ")
                )));
            }
            return Err(error);
        }

        match body() {
            Ok(value) => {
                if let Some(txn) = self.active_txn.borrow_mut().as_mut() {
                    txn.release_savepoint(cx, &savepoint_name)?;
                }
                self.live_vtab_release_all(cx, live_vtab_level)?;
                Ok(value)
            }
            Err(statement_error) => {
                // Full ROLLBACK can clear the transaction underneath us
                // (for example via trigger RAISE(ROLLBACK)). In that case,
                // the outer rollback has already restored connection state.
                if self.active_txn.borrow().is_none() {
                    return Err(statement_error);
                }

                let mut cleanup_errors = Vec::new();
                let mut pager_rollback_succeeded = false;
                let mut concurrent_rollback_succeeded = true;
                if let Some(concurrent_snap) = concurrent_snapshot.as_ref() {
                    if let Some(session_id) = *self.concurrent_session_id.borrow() {
                        let registry = lock_unpoisoned(&self.concurrent_registry);
                        if let Some(mut handle) = registry.get_mut(session_id) {
                            if let Err(err) = concurrent_rollback_to_savepoint(
                                &mut handle,
                                &self.concurrent_lock_table,
                                session_id,
                                concurrent_snap,
                            ) {
                                concurrent_rollback_succeeded = false;
                                cleanup_errors.push(format!(
                                    "concurrent rollback_to_savepoint('{savepoint_name}') failed: {err}"
                                ));
                            }
                        } else {
                            concurrent_rollback_succeeded = false;
                            cleanup_errors.push(format!(
                                "concurrent session {session_id} missing during rollback"
                            ));
                        }
                    } else {
                        concurrent_rollback_succeeded = false;
                        cleanup_errors.push(
                            "concurrent transaction active but no session ID during rollback"
                                .to_owned(),
                        );
                    }
                }

                if concurrent_rollback_succeeded
                    && let Some(txn) = self.active_txn.borrow_mut().as_mut()
                {
                    match txn.rollback_to_savepoint(cx, &savepoint_name) {
                        Ok(()) => {
                            pager_rollback_succeeded = true;
                            if let Err(err) = txn.release_savepoint(cx, &savepoint_name) {
                                cleanup_errors.push(format!(
                                    "pager release_savepoint('{savepoint_name}') failed: {err}"
                                ));
                            }
                        }
                        Err(err) => cleanup_errors.push(format!(
                            "pager rollback_to_savepoint('{savepoint_name}') failed: {err}"
                        )),
                    }
                }

                if concurrent_rollback_succeeded && pager_rollback_succeeded {
                    match self.live_vtab_rollback_to_all(cx, live_vtab_level) {
                        Ok(()) => {
                            if let Err(err) = self.live_vtab_release_all(cx, live_vtab_level) {
                                cleanup_errors.push(format!(
                                    "virtual-table release({live_vtab_level}) failed: {err}"
                                ));
                            }
                        }
                        Err(err) => {
                            cleanup_errors.push(format!(
                                "virtual-table rollback_to({live_vtab_level}) failed: {err}"
                            ));
                        }
                    }
                }

                if pager_rollback_succeeded {
                    self.txn_metrics_note_rollback();
                    self.restore_snapshot(cx, &snapshot)?;
                }

                if !cleanup_errors.is_empty() {
                    return Err(FrankenError::Internal(format!(
                        "statement savepoint rollback failed after {purpose}: {statement_error}; cleanup failed: {}",
                        cleanup_errors.join("; ")
                    )));
                }

                Err(statement_error)
            }
        }
    }

    /// Execute a parsed statement, handling both DDL (CREATE TABLE) and
    /// DML (SELECT/INSERT/UPDATE/DELETE).
    #[allow(clippy::too_many_lines)]
    fn execute_statement(
        &self,
        statement: &Statement,
        params: Option<&[SqliteValue]>,
    ) -> Result<Vec<Row>> {
        if hot_path_profile_enabled() {
            FSQLITE_STATEMENT_DISPATCH_BACKGROUND_GATES.fetch_add(1, AtomicOrdering::Relaxed);
        }
        self.background_status()?;
        self.execute_statement_after_background_status(statement, params)
    }

    fn execute_statement_after_background_status(
        &self,
        statement: &Statement,
        params: Option<&[SqliteValue]>,
    ) -> Result<Vec<Row>> {
        self.execute_statement_impl_after_background_status(statement, params, None)
    }

    #[allow(clippy::too_many_lines)]
    fn execute_statement_impl_after_background_status(
        &self,
        statement: &Statement,
        params: Option<&[SqliteValue]>,
        precompiled: Option<&VdbeProgram>,
    ) -> Result<Vec<Row>> {
        let _record_profile_scope = enter_record_profile_scope(RecordProfileScope::CoreConnection);
        self.clear_table_program_error_state();
        self.sync_change_tracking_context();
        let statement_kind = match &statement {
            Statement::Select(_) => "select",
            Statement::Insert(_) => "insert",
            Statement::Update(_) => "update",
            Statement::Delete(_) => "delete",
            Statement::CreateTable(_) => "create_table",
            Statement::CreateVirtualTable(_) => "create_virtual_table",
            Statement::Drop(_) => "drop",
            Statement::AlterTable(_) => "alter_table",
            Statement::CreateIndex(_) => "create_index",
            Statement::Pragma(_) => "pragma",
            Statement::Begin(_) => "begin",
            Statement::Commit => "commit",
            Statement::Rollback(_) => "rollback",
            Statement::Savepoint(_) => "savepoint",
            Statement::Release(_) => "release",
            Statement::CreateView(_) => "create_view",
            Statement::CreateTrigger(_) => "create_trigger",
            Statement::Explain { .. } => "explain",
            _ => "other",
        };
        let statement_trace_enabled =
            tracing::enabled!(target: "fsqlite.statement", tracing::Level::DEBUG);
        let parse_trace_enabled = tracing::enabled!(target: "fsqlite.parse", tracing::Level::TRACE);
        let trace_id = (statement_trace_enabled || parse_trace_enabled)
            .then(next_trace_id)
            .unwrap_or(0);
        let decision_id = statement_trace_enabled.then(next_decision_id).unwrap_or(0);
        let trace_registration = self.trace_registration.borrow().clone();
        let compat_trace_stmt_enabled = trace_registration
            .as_ref()
            .is_some_and(|trace| trace.mask.contains(TraceMask::STMT));
        let compat_trace_profile_enabled = trace_registration
            .as_ref()
            .is_some_and(|trace| trace.mask.contains(TraceMask::PROFILE));
        let compat_trace_row_enabled = trace_registration
            .as_ref()
            .is_some_and(|trace| trace.mask.contains(TraceMask::ROW));
        let statement_sql = (compat_trace_stmt_enabled || compat_trace_profile_enabled)
            .then(|| statement.to_string());
        let statement_reuse_enabled =
            tracing::enabled!(target: "fsqlite.statement_reuse", tracing::Level::INFO);
        let statement_reuse_sql = statement_reuse_enabled.then(|| {
            statement_sql
                .clone()
                .unwrap_or_else(|| statement.to_string())
        });
        let statement_span = statement_trace_enabled.then(|| {
            let span = tracing::span!(
                target: "fsqlite.statement",
                tracing::Level::DEBUG,
                "statement",
                trace_id,
                decision_id,
                statement_kind
            );
            record_trace_span_created();
            span
        });
        let _statement_guard = statement_span.as_ref().map(tracing::Span::enter);
        if compat_trace_stmt_enabled {
            emit_compat_trace_event(
                trace_registration.as_ref(),
                TraceEvent::Statement {
                    sql: statement_sql.clone().unwrap_or_default(),
                },
            );
        }
        let execution_started = (statement_reuse_enabled || compat_trace_profile_enabled)
            .then(fsqlite_types::sync_primitives::Instant::now);
        let statement = {
            let parse_span = parse_trace_enabled.then(|| {
                let span = tracing::span!(
                    target: "fsqlite.parse",
                    tracing::Level::TRACE,
                    "parse",
                    trace_id,
                    statement_kind,
                    phase = "rewrite_subquery"
                );
                record_trace_span_created();
                span
            });
            let _parse_guard = parse_span.as_ref().map(tracing::Span::enter);
            self.rewrite_subquery_statement(statement, params)?
        };
        // 5B.5 + 5B.2 (bd-1yi8): autocommit wrapping — ensure a pager
        // transaction is active for data/DDL operations outside an
        // explicit BEGIN.  Writes use Immediate mode; reads use Deferred.
        // Transaction-control statements manage their own transactions.
        let is_write = matches!(
            statement.as_ref(),
            Statement::Insert(_)
                | Statement::Update(_)
                | Statement::Delete(_)
                | Statement::CreateTable(_)
                | Statement::CreateVirtualTable(_)
                | Statement::CreateView(_)
                | Statement::CreateTrigger(_)
                | Statement::Drop(_)
                | Statement::AlterTable(_)
                | Statement::CreateIndex(_)
                | Statement::Analyze(_)
                | Statement::Reindex(_)
        );
        let is_txn_control = matches!(
            statement.as_ref(),
            Statement::Begin(_)
                | Statement::Commit
                | Statement::Rollback(_)
                | Statement::Savepoint(_)
                | Statement::Release(_)
                // VACUUM INTO needs the pager quiescent, so it cannot run
                // inside the implicit autocommit read transaction used for
                // ordinary statement dispatch.
                | Statement::Vacuum(_)
                // PRAGMA handlers that need pager access (for example
                // `PRAGMA wal_checkpoint`) manage their own pager operations.
                | Statement::Pragma(_)
        );
        let capture_time_travel_snapshot = !matches!(
            statement.as_ref(),
            Statement::Insert(_) | Statement::Update(_) | Statement::Delete(_)
        );
        let op_cx = self.op_cx_after_background_status();
        let was_auto = if is_txn_control {
            false // transaction-control manages its own transactions
        } else if is_write {
            self.ensure_autocommit_txn_with_cx(&op_cx)?
        } else {
            self.ensure_autocommit_txn_mode_with_cx(TransactionMode::ReadOnly, &op_cx, None)?
        };
        let previous_total_changes = *self.total_changes.borrow();
        let previous_last_insert_rowid = self.current_last_insert_rowid();
        if !is_txn_control {
            if is_write {
                self.txn_metrics_note_write();
            } else if matches!(statement.as_ref(), Statement::Select(_)) {
                self.txn_metrics_note_read();
            }
        }
        let use_statement_savepoint = !was_auto
            && self.active_txn.borrow().is_some()
            && self.internal_statement_savepoint_depth.get() == 0
            && !statement_preserves_prior_changes_on_constraint(statement.as_ref())
            && matches!(
                statement.as_ref(),
                Statement::Insert(_)
                    | Statement::Update(_)
                    | Statement::Delete(_)
                    | Statement::CreateIndex(_)
                    | Statement::Reindex(_)
            );
        let rollback_on_constraint_violation =
            statement_rolls_back_transaction_on_constraint(statement.as_ref());
        let result = if use_statement_savepoint {
            self.with_internal_statement_savepoint_and_cx(&op_cx, statement_kind, || {
                self.execute_statement_dispatch_impl(
                    &op_cx,
                    statement.as_ref(),
                    params,
                    precompiled,
                )
            })
        } else {
            self.execute_statement_dispatch_impl(&op_cx, statement.as_ref(), params, precompiled)
        };
        let result = match result {
            Ok(rows) => Ok(rows),
            Err(error) => {
                if matches!(
                    statement.as_ref(),
                    Statement::Insert(_) | Statement::Update(_) | Statement::Delete(_)
                ) {
                    self.restore_failed_statement_tracking(
                        statement_preserves_prior_changes_on_constraint(statement.as_ref()),
                        &error,
                        previous_total_changes,
                        previous_last_insert_rowid,
                    );
                }
                match self.maybe_rollback_transaction_for_conflict_action(
                    rollback_on_constraint_violation,
                    was_auto,
                    &error,
                ) {
                    Ok(()) => Err(error),
                    Err(rollback_error) => Err(rollback_error),
                }
            }
        };
        let commit_autocommit_on_error = was_auto
            && statement_preserves_prior_changes_on_constraint(statement.as_ref())
            && matches!(
                result.as_ref(),
                Err(error) if error_is_constraint_violation(error)
            );
        let ok = result.is_ok() || commit_autocommit_on_error;
        self.resolve_autocommit_txn_with_capture_and_cx(
            was_auto,
            ok,
            capture_time_travel_snapshot,
            &op_cx,
        )?;
        if statement_reuse_enabled || compat_trace_profile_enabled {
            let elapsed_ns = execution_started
                .map(|started| u64::try_from(started.elapsed().as_nanos()).unwrap_or(u64::MAX))
                .unwrap_or(0);
            if let Some(statement_reuse_sql) = statement_reuse_sql.as_deref() {
                let failure_diag = match result.as_ref() {
                    Ok(_) => Cow::Borrowed("none"),
                    Err(error) => Cow::Owned(error.to_string()),
                };
                self.log_statement_reuse_event(
                    "execution",
                    statement_reuse_sql,
                    precompiled.is_some(),
                    if ok { "none" } else { "execution_error" },
                    0,
                    elapsed_ns,
                    failure_diag.as_ref(),
                );
            }
            if compat_trace_profile_enabled {
                emit_compat_trace_event(
                    trace_registration.as_ref(),
                    TraceEvent::Profile {
                        sql: statement_sql.unwrap_or_default(),
                        elapsed_ns,
                    },
                );
            }
        }
        if compat_trace_row_enabled && let Ok(rows) = result.as_ref() {
            for row in rows {
                emit_compat_trace_event(
                    trace_registration.as_ref(),
                    TraceEvent::Row {
                        values: row.values().to_vec(),
                    },
                );
            }
        }
        result
    }

    /// Inner dispatch for `execute_statement` — separated so that
    /// autocommit wrapping can bracket the entire execution.
    #[allow(clippy::too_many_lines)]
    #[allow(dead_code)]
    fn execute_statement_dispatch(
        &self,
        statement: &Statement,
        params: Option<&[SqliteValue]>,
    ) -> Result<Vec<Row>> {
        let op_cx = self.op_cx()?;
        self.execute_statement_dispatch_impl(&op_cx, statement, params, None)
    }

    #[allow(clippy::too_many_lines)]
    fn execute_statement_dispatch_impl(
        &self,
        cx: &Cx,
        statement: &Statement,
        params: Option<&[SqliteValue]>,
        precompiled: Option<&VdbeProgram>,
    ) -> Result<Vec<Row>> {
        if let Some(rows) = self.maybe_execute_attached_target_statement(statement, params)? {
            return Ok(rows);
        }
        self.reject_unsupported_attached_target_schema(statement)?;
        match statement {
            Statement::CreateTable(create) => {
                self.execute_create_table(create)?;
                // 5D.4: Persistence now handled by pager WAL, not compat_persist.
                Ok(Vec::new())
            }
            Statement::CreateVirtualTable(create_virtual) => {
                self.execute_create_virtual_table(create_virtual)?;
                // 5D.4: Persistence now handled by pager WAL, not compat_persist.
                Ok(Vec::new())
            }
            Statement::Select(select) => {
                // Time-travel: intercept FOR SYSTEM_TIME AS OF queries and
                // execute against a historical MemDatabase snapshot (#23).
                if let Some(target) = extract_temporal_clause(select) {
                    return self.execute_time_travel_select(select, params, &target);
                }
                // CTE (WITH clause): materialize as temporary tables.
                if select.with.is_some() {
                    self.log_mem_execution_fallback("select", "with_clause_materialization")?;
                    return self.execute_with_ctes(select, params);
                }
                // View expansion: materialize referenced views as temp tables.
                if self.has_view_references(select) {
                    self.log_mem_execution_fallback("select", "view_materialization")?;
                    return self.execute_with_materialized_views(select, params);
                }
                if let Some(rows) = self.maybe_execute_attached_select(select, params)? {
                    return Ok(rows);
                }
                // 5G.4 (bd-3ly4): sqlite_master/sqlite_schema virtual table support.
                if self.has_sqlite_schema_references(select) {
                    self.log_mem_execution_fallback(
                        "select",
                        "sqlite_schema_virtual_materialization",
                    )?;
                    return self.execute_with_materialized_sqlite_schema(select, params);
                }
                let distinct = is_distinct_select(select);
                let ordered_aggregate = has_ordered_aggregate(select);
                // Compound SELECT (UNION/UNION ALL/INTERSECT/EXCEPT).
                if !select.body.compounds.is_empty() {
                    return self.execute_compound_select(select, params);
                }
                // FROM-less aggregate SELECT (e.g. SELECT COUNT(*), SUM(NULL)).
                // Must be checked before the expression-only path because the
                // expression-only VDBE codegen cannot handle aggregate functions.
                if is_expression_only_select(select) && has_implicit_aggregation(select) {
                    return self.execute_fromless_aggregate(select);
                }
                // Expression-only SELECT with scalar subqueries in result
                // columns: the VDBE codegen cannot resolve table references
                // inside subqueries (e.g. CTE temp tables).  Evaluate via the
                // connection-level path that can call execute_statement.
                if is_expression_only_select(select) && expression_only_has_subquery(select) {
                    return self.execute_expression_only_with_subqueries(select, params);
                }
                // Check if this is an expression-only SELECT (no FROM clause).
                if is_expression_only_select(select) {
                    // Fallback codegen: eagerly rewrite IN subqueries.
                    let rewritten = self.rewrite_in_subqueries_select(select, params)?;
                    let plan_span = tracing::span!(
                        target: "fsqlite.plan",
                        tracing::Level::TRACE,
                        "plan",
                        stage = "compile_expression_select"
                    );
                    record_trace_span_created();
                    let _plan_guard = plan_span.enter();
                    let program = compile_expression_select(rewritten.as_ref())?;
                    let registry = self.func_registry.borrow().clone();
                    let op_cx = self.op_cx()?;
                    let mut rows = execute_program_with_postprocess(
                        &program,
                        params,
                        Some(&registry),
                        Some(&self.collation_registry),
                        &op_cx,
                        Some(&build_expression_postprocess(rewritten.as_ref())),
                        PageSize::new(self.pragma_state.borrow().page_size).unwrap(),
                    )?;
                    if distinct {
                        dedup_rows(&mut rows);
                    }
                    Ok(rows)
                } else if (has_group_by(select)
                    || has_implicit_aggregation(select)
                    || ordered_aggregate)
                    && (has_joins(select) || has_fallback_from_source(select))
                {
                    // GROUP BY (or implicit aggregation) + JOIN/non-table source:
                    // materialize the join as a temp table, then GROUP BY on that.
                    self.log_mem_execution_fallback("select", "group_by_join_fallback")?;
                    let rewritten = self.rewrite_in_subqueries_select(select, params)?;
                    let mut bound =
                        bind_placeholders_in_select_for_fallback(rewritten.as_ref(), params)?;
                    let limit_clause = bound.limit.take();
                    let mut rows = self.execute_group_by_join_select(cx, &bound, None)?;
                    if distinct {
                        dedup_rows(&mut rows);
                    }
                    if let Some(limit) = limit_clause {
                        apply_limit_clause(&mut rows, &limit);
                    }
                    Ok(rows)
                } else if (has_group_by(select) || ordered_aggregate)
                    && has_window_functions(select)
                {
                    // GROUP BY + window functions: two-phase execution.
                    // Phase 1: GROUP BY with non-window columns to get grouped rows.
                    // Phase 2: apply window functions to the grouped result.
                    self.log_mem_execution_fallback("select", "group_by_window_fallback")?;
                    let rewritten = self.rewrite_in_subqueries_select(select, params)?;
                    let mut bound =
                        bind_placeholders_in_select_for_fallback(rewritten.as_ref(), params)?;
                    let limit_clause = bound.limit.take();
                    let mut rows = self.execute_group_by_window_select(&bound, None)?;
                    if distinct {
                        dedup_rows(&mut rows);
                    }
                    if let Some(limit) = limit_clause {
                        apply_limit_clause(&mut rows, &limit);
                    }
                    Ok(rows)
                } else if has_group_by(select) || ordered_aggregate {
                    // Fallback path: eagerly rewrite IN subqueries.
                    self.log_mem_execution_fallback("select", "group_by_fallback")?;
                    let rewritten = self.rewrite_in_subqueries_select(select, params)?;
                    let mut bound =
                        bind_placeholders_in_select_for_fallback(rewritten.as_ref(), params)?;
                    let limit_clause = bound.limit.take();
                    let mut rows = self.execute_group_by_select(&bound, None)?;
                    if distinct {
                        dedup_rows(&mut rows);
                    }
                    if let Some(limit) = limit_clause {
                        apply_limit_clause(&mut rows, &limit);
                    }
                    Ok(rows)
                } else if has_window_functions(select) {
                    // Window function fallback: materialize rows, sort by
                    // window spec, compute window functions at connection level.
                    self.log_mem_execution_fallback("select", "window_function_fallback")?;
                    let rewritten = self.rewrite_in_subqueries_select(select, params)?;
                    let mut bound =
                        bind_placeholders_in_select_for_fallback(rewritten.as_ref(), params)?;
                    let limit_clause = bound.limit.take();
                    let mut rows = self.execute_window_select(&bound, None)?;
                    if distinct {
                        dedup_rows(&mut rows);
                    }
                    if let Some(limit) = limit_clause {
                        apply_limit_clause(&mut rows, &limit);
                    }
                    Ok(rows)
                } else if self.has_primary_live_vtab_source(select) {
                    // Live virtual-table instances are not yet emitted through
                    // the table-only VDBE codegen path. Route single-source
                    // scans through the connection fallback, which can drive
                    // the registered vtab instance directly.
                    self.log_mem_execution_fallback("select", "live_vtab_select_fallback")?;
                    let rewritten = self.rewrite_in_subqueries_select(select, params)?;
                    let mut bound =
                        bind_placeholders_in_select_for_fallback(rewritten.as_ref(), params)?;
                    let limit_clause = bound.limit.take();
                    let mut rows = self.execute_join_select(&bound, None)?;
                    if distinct {
                        dedup_rows(&mut rows);
                    }
                    if let Some(limit) = limit_clause {
                        apply_limit_clause(&mut rows, &limit);
                    }
                    Ok(rows)
                } else if select_contains_match_operator(select) {
                    // The VDBE path does not yet support MATCH/REGEXP in this
                    // connection path. Route through fallback evaluation.
                    self.log_mem_execution_fallback("select", "match_operator_fallback")?;
                    let rewritten = self.rewrite_in_subqueries_select(select, params)?;
                    let mut bound =
                        bind_placeholders_in_select_for_fallback(rewritten.as_ref(), params)?;
                    let limit_clause = bound.limit.take();
                    let mut rows = self.execute_join_select(&bound, None)?;
                    if distinct {
                        dedup_rows(&mut rows);
                    }
                    if let Some(limit) = limit_clause {
                        apply_limit_clause(&mut rows, &limit);
                    }
                    Ok(rows)
                } else if has_joins(select) || has_subquery_source(select) {
                    // NOTE: VDBE codegen for JOINs exists (codegen_join_select)
                    // but is not yet wired into the dispatch path because it
                    // produces incorrect results for many JOIN shapes (NATURAL,
                    // CROSS, multi-table, complex ON conditions). Once the
                    // codegen is validated against the conformance oracle, enable
                    // the fast path by uncommenting the routing below.
                    //
                    // TODO(perf): Enable VDBE JOIN routing when codegen_join_select
                    // passes all conformance tests:
                    // if has_joins(select) && !has_subquery_source(select) {
                    //     ... try compile_table_select → execute_table_program ...
                    // }

                    // Fallback path: eagerly rewrite IN subqueries.
                    // Also handles derived tables even without explicit JOINs.
                    let rewritten = self.rewrite_in_subqueries_select(select, params)?;
                    let native_join_dispatch =
                        self.can_execute_join_select_on_real_backend(rewritten.as_ref());
                    if !native_join_dispatch {
                        self.log_mem_execution_fallback("select", "join_or_subquery_fallback")?;
                    }
                    let mut bound =
                        bind_placeholders_in_select_for_fallback(rewritten.as_ref(), params)?;
                    let limit_clause = bound.limit.take();
                    let started = std::time::Instant::now();
                    let mut rows = self.execute_join_select(&bound, None)?;
                    if native_join_dispatch {
                        let elapsed_ns =
                            u64::try_from(started.elapsed().as_nanos()).unwrap_or(u64::MAX);
                        self.log_native_join_dispatch(&bound, rows.len(), elapsed_ns);
                    }
                    if distinct {
                        dedup_rows(&mut rows);
                    }
                    if let Some(limit) = limit_clause {
                        apply_limit_clause(&mut rows, &limit);
                    }
                    Ok(rows)
                } else if has_table_function_source(select) {
                    self.log_mem_execution_fallback("select", "join_or_subquery_fallback")?;
                    let rewritten = self.rewrite_in_subqueries_select(select, params)?;
                    let mut bound =
                        bind_placeholders_in_select_for_fallback(rewritten.as_ref(), params)?;
                    let limit_clause = bound.limit.take();
                    let mut rows = self.execute_join_select(&bound, None)?;
                    if distinct {
                        dedup_rows(&mut rows);
                    }
                    if let Some(limit) = limit_clause {
                        apply_limit_clause(&mut rows, &limit);
                    }
                    Ok(rows)
                } else if select_has_correlated_join_subquery(select) {
                    // Correlated scalar subqueries with JOINs in their FROM
                    // clause cannot be handled by the VDBE emit_scalar_subquery
                    // (which only opens one table cursor). Route through the
                    // connection-level fallback which can inline-evaluate them.
                    self.log_mem_execution_fallback("select", "correlated_join_subquery_fallback")?;
                    let rewritten = self.rewrite_in_subqueries_select(select, params)?;
                    let mut bound =
                        bind_placeholders_in_select_for_fallback(rewritten.as_ref(), params)?;
                    let limit_clause = bound.limit.take();
                    let mut rows = self.execute_join_select(&bound, None)?;
                    if distinct {
                        dedup_rows(&mut rows);
                    }
                    if let Some(limit) = limit_clause {
                        apply_limit_clause(&mut rows, &limit);
                    }
                    Ok(rows)
                } else {
                    let limit_clause = select.limit.clone();
                    let arc_prog;
                    let program: &VdbeProgram = if let Some(p) = precompiled {
                        p
                    } else {
                        // Eagerly rewrite IN-subqueries that the VDBE codegen
                        // cannot handle (e.g. those with GROUP BY / HAVING).
                        let rewritten = self.rewrite_in_subqueries_select(select, params)?;
                        let compiled_select = if distinct && limit_clause.is_some() {
                            let mut unbounded = rewritten.as_ref().clone();
                            unbounded.limit = None;
                            Cow::Owned(unbounded)
                        } else {
                            rewritten
                        };
                        let plan_span = tracing::span!(
                            target: "fsqlite.plan",
                            tracing::Level::TRACE,
                            "plan",
                            stage = "compile_table_select"
                        );
                        record_trace_span_created();
                        let _plan_guard = plan_span.enter();
                        // Cache the actual compiled SELECT shape, not the original
                        // SQL text, because eager subquery rewriting can inline
                        // parameter-sensitive literal lists before codegen.
                        // Use SelectStatement::to_string() directly to avoid
                        // cloning the entire AST into a Statement wrapper.
                        let sql_text = compiled_select.to_string();
                        let sql_key = Self::sql_hash(&sql_text);
                        arc_prog = self.compile_with_cache(sql_key, &sql_text, |conn| {
                            conn.compile_table_select(compiled_select.as_ref())
                        })?;
                        &arc_prog
                    };

                    let (mut rows, _, _) = self.execute_table_program_with_cx(
                        program,
                        params,
                        false,
                        TableExecutionRuntimeRequirements::read_path(),
                        cx,
                    )?;
                    if distinct {
                        dedup_rows(&mut rows);
                        if let Some(limit_clause) = limit_clause.as_ref() {
                            apply_limit_clause(&mut rows, limit_clause);
                        }
                    }
                    Ok(rows)
                }
            }
            Statement::Insert(insert) => {
                // FTS5 maintenance command compatibility:
                //   INSERT INTO <table>(<table>) VALUES('optimize')
                // is treated as a no-op in this compatibility path.
                if is_fts5_optimize_noop_insert(insert) {
                    self.reset_statement_change_count();
                    return Ok(Vec::new());
                }

                let table_name = &insert.table.name;
                self.reject_without_rowid_dml(table_name, "INSERT")?;
                let insert_event = fsqlite_ast::TriggerEvent::Insert;
                let is_live_vtab = self.has_live_vtab_instance(table_name);
                let has_before_insert = self.has_matching_triggers(
                    table_name,
                    fsqlite_ast::TriggerTiming::Before,
                    &insert_event,
                );
                let has_after_insert = self.has_matching_triggers(
                    table_name,
                    fsqlite_ast::TriggerTiming::After,
                    &insert_event,
                );
                if is_live_vtab {
                    if !insert.returning.is_empty() {
                        return Err(FrankenError::NotImplemented(
                            "RETURNING is not supported for live virtual-table INSERT".to_owned(),
                        ));
                    }
                    if insert.or_conflict.is_some() || !insert.upsert.is_empty() {
                        return Err(FrankenError::NotImplemented(
                            "UPSERT and conflict clauses are not supported for live virtual-table INSERT"
                                .to_owned(),
                        ));
                    }
                }
                if !is_live_vtab
                    && let fsqlite_ast::InsertSource::Select(select_stmt) = &insert.source
                {
                    // Detect simple VALUES clause (no compounds).
                    // We must use the VDBE path for simple VALUES to avoid infinite recursion
                    // in the fallback (which implements inserts by generating simple VALUES inserts).
                    let is_simple_values = matches!(select_stmt.body.select, SelectCore::Values(_))
                        && select_stmt.body.compounds.is_empty();

                    // Complex INSERT ... SELECT statements are replayed as
                    // per-row INSERT ... VALUES operations. Those inner
                    // statements already handle trigger firing and change
                    // tracking, so route around the outer trigger path here.
                    let needs_row_by_row_replay = insert.returning.is_empty()
                        && (has_before_insert || has_after_insert || self.fk_enforcement_enabled());
                    if insert.returning.is_empty() && (!is_simple_values || needs_row_by_row_replay)
                    {
                        self.log_mem_execution_fallback(
                            "insert_select",
                            "insert_select_row_by_row_fallback",
                        )?;
                        let _ = self.execute_insert_select_fallback(insert, select_stmt, params)?;
                        return Ok(Vec::new());
                    }
                }
                if !is_live_vtab
                    && insert.returning.is_empty()
                    && (has_before_insert || has_after_insert || self.fk_enforcement_enabled())
                    && let fsqlite_ast::InsertSource::Values(rows) = &insert.source
                    && rows.len() > 1
                {
                    self.log_mem_execution_fallback(
                        "insert_values",
                        "insert_values_row_by_row_trigger_or_fk_fallback",
                    )?;
                    let source_rows = self.materialize_insert_values_source_rows(rows, params)?;
                    let _ = self.execute_insert_select_materialized_rows(insert, &source_rows)?;
                    return Ok(Vec::new());
                }
                let mut live_insert_rows = if is_live_vtab {
                    Some(self.collect_live_vtab_insert_rows(insert, params)?)
                } else {
                    None
                };
                let mut trigger_new_rows = if has_before_insert || has_after_insert {
                    if let Some(rows) = live_insert_rows.as_ref() {
                        rows.iter().map(|row| row.values.clone()).collect()
                    } else {
                        self.collect_insert_trigger_rows(insert, params)?
                    }
                } else {
                    Vec::new()
                };

                // Phase 5G.2 (bd-iqam): Fire BEFORE INSERT triggers.
                let skip_dml = if has_before_insert {
                    let mut skip = false;
                    for new_values in &trigger_new_rows {
                        if self.fire_before_triggers(
                            table_name,
                            &insert_event,
                            None,
                            Some(new_values),
                        )? {
                            skip = true;
                            break;
                        }
                    }
                    skip
                } else {
                    false
                };
                if skip_dml {
                    // RAISE(IGNORE) was called - skip the INSERT.
                    self.reset_statement_change_count();
                    return Ok(Vec::new());
                }

                if is_live_vtab {
                    let mut live_insert_rows = live_insert_rows.take().unwrap_or_else(Vec::new);
                    let patch_first_column_with_rowid = {
                        let key = table_name.to_ascii_uppercase();
                        self.vtab_instances
                            .borrow()
                            .get(&key)
                            .is_some_and(|instance| instance.as_any().is::<RtreeVirtualTable>())
                    };
                    let inserted_rowids =
                        self.execute_live_vtab_insert_rows(table_name, &live_insert_rows)?;

                    if has_after_insert {
                        if patch_first_column_with_rowid {
                            for (row, rowid) in
                                live_insert_rows.iter_mut().zip(inserted_rowids.iter())
                            {
                                if row.values.first().is_some_and(|value| value.is_null()) {
                                    row.values[0] = SqliteValue::Integer(*rowid);
                                }
                            }
                        }
                        for row in &live_insert_rows {
                            self.fire_after_triggers(
                                table_name,
                                &insert_event,
                                None,
                                Some(&row.values),
                            )?;
                        }
                    }

                    self.record_statement_changes(live_insert_rows.len());
                    return Ok(Vec::new());
                }

                // Phase 5B.2 (bd-1yi8): INSERT OR REPLACE / INSERT OR IGNORE
                // now routes through VDBE which has UPSERT semantics in the
                // Insert opcode (table_move_to + delete + insert). The
                // previous execute_insert_or_conflict fallback checked
                // MemDatabase directly, which doesn't work after write-through
                // stopped syncing inserts to MemDatabase.
                //
                // TODO: Once execute_insert_or_conflict is updated to read
                // from the pager, we can re-enable it for performance.
                // For now, fall through to VDBE execution.

                let arc_prog;
                let program: &VdbeProgram = if let Some(p) = precompiled {
                    p
                } else {
                    let plan_span = tracing::span!(
                        target: "fsqlite.plan",
                        tracing::Level::TRACE,
                        "plan",
                        stage = "compile_table_insert"
                    );
                    record_trace_span_created();
                    let _plan_guard = plan_span.enter();
                    let sql_text = statement.to_string();
                    let sql_key = Self::sql_hash(&sql_text);
                    arc_prog = self.compile_with_cache(sql_key, &sql_text, |conn| {
                        conn.compile_table_insert(insert)
                    })?;
                    &arc_prog
                };
                let runtime_requirements = self.insert_runtime_requirements(insert)?;
                let (rows, affected, last_insert_rowid) = self.execute_table_program_with_cx(
                    program,
                    params,
                    true,
                    runtime_requirements,
                    cx,
                )?;

                // bd-thqgm: FK constraint checking on INSERT.
                if self.fk_enforcement_enabled() {
                    self.enforce_fk_on_insert(insert, table_name, params)?;
                }

                // Patch trigger NEW rows: fill in auto-assigned INTEGER
                // PRIMARY KEY rowids that were NULL at pre-computation time.
                if has_after_insert && !trigger_new_rows.is_empty() {
                    if affected == 0 {
                        trigger_new_rows.clear();
                    } else {
                        let tbl_key = table_name.to_ascii_lowercase();
                        if let Some(&ipk_idx) = self.rowid_alias_columns.borrow().get(&tbl_key) {
                            let last_rowid = self.current_last_insert_rowid();
                            let count = trigger_new_rows.len();
                            for (i, new_row) in trigger_new_rows.iter_mut().enumerate() {
                                if ipk_idx < new_row.len() && new_row[ipk_idx] == SqliteValue::Null
                                {
                                    #[allow(clippy::cast_possible_wrap)]
                                    let rowid = last_rowid - (count as i64 - 1) + i as i64;
                                    new_row[ipk_idx] = SqliteValue::Integer(rowid);
                                }
                            }
                        }
                    }
                }

                // Phase 5G.3: Fire AFTER INSERT triggers.
                if has_after_insert {
                    for new_values in &trigger_new_rows {
                        self.fire_after_triggers(
                            table_name,
                            &insert_event,
                            None,
                            Some(new_values),
                        )?;
                    }
                }

                if table_name.eq_ignore_ascii_case("sqlite_sequence") {
                    self.refresh_sqlite_sequence_cache()?;
                } else {
                    self.refresh_autoincrement_sequence_after_insert(
                        table_name,
                        affected,
                        last_insert_rowid,
                    )?;
                }

                // 5D.4: Persistence now handled by pager WAL, not compat_persist.
                self.record_statement_changes(affected);
                if insert.returning.is_empty() {
                    Ok(Vec::new())
                } else {
                    Ok(rows)
                }
            }
            Statement::Update(update) => {
                // CTE (WITH clause): materialize CTEs as temporary tables,
                // then execute the UPDATE with the WITH clause stripped.
                if update.with.is_some() {
                    self.log_mem_execution_fallback("update", "with_clause_materialization")?;
                    return self.execute_update_with_ctes(update, params);
                }
                let (effective_update, _limited_row_count_hint) =
                    self.materialize_update_limit_scope(update, params)?;
                let table_name = &effective_update.table.name.name;
                self.reject_without_rowid_dml(table_name, "UPDATE")?;
                // Collect columns being updated for UPDATE OF trigger matching.
                let update_cols: Vec<String> = effective_update
                    .assignments
                    .iter()
                    .flat_map(|a| match &a.target {
                        fsqlite_ast::AssignmentTarget::Column(c) => vec![c.clone()],
                        fsqlite_ast::AssignmentTarget::ColumnList(cols) => cols.clone(),
                    })
                    .collect();
                let update_event = fsqlite_ast::TriggerEvent::Update(update_cols);
                let has_before_update = self.has_matching_triggers(
                    table_name,
                    fsqlite_ast::TriggerTiming::Before,
                    &update_event,
                );
                let has_after_update = self.has_matching_triggers(
                    table_name,
                    fsqlite_ast::TriggerTiming::After,
                    &update_event,
                );
                let trigger_rows = if has_before_update || has_after_update {
                    self.collect_update_trigger_rows(&effective_update, params)?
                } else {
                    Vec::new()
                };

                // Phase 5G.2 (bd-iqam): Fire BEFORE UPDATE triggers.
                let skip_dml = if has_before_update {
                    let mut skip = false;
                    for (old_values, new_values) in &trigger_rows {
                        if self.fire_before_triggers(
                            table_name,
                            &update_event,
                            Some(old_values),
                            Some(new_values),
                        )? {
                            skip = true;
                            break;
                        }
                    }
                    skip
                } else {
                    false
                };
                if skip_dml {
                    self.reset_statement_change_count();
                    return Ok(Vec::new());
                }

                // FK enforcement on UPDATE:
                // 1. Parent-side: check old values aren't orphaning children
                //    (uses cascade-propagation gate so multi-level cascades work)
                // 2. Child-side: check new FK values have valid parents
                //    (uses strict gate — not needed during cascade operations)
                if self.fk_cascade_propagation_enabled() {
                    let rows_to_check = if !trigger_rows.is_empty() {
                        trigger_rows
                            .iter()
                            .map(|(old, new)| (old.clone(), new.clone()))
                            .collect::<Vec<_>>()
                    } else {
                        self.collect_update_trigger_rows(&effective_update, params)?
                    };
                    for (old_values, new_values) in &rows_to_check {
                        // Parent-side: if this table is referenced by children,
                        // check that changing FK-referenced values doesn't orphan them.
                        // Use ON UPDATE actions (not ON DELETE) for UPDATE statements.
                        let fk_actions =
                            self.check_fk_on_update(table_name, old_values, new_values)?;
                        for action in &fk_actions {
                            self.execute_fk_update_action(action)?;
                        }
                        // Child-side: validate new FK values against parent tables.
                        // Only check when NOT inside a cascade action, because
                        // the cascade itself is modifying parent data.
                        if self.fk_enforcement_enabled() {
                            self.check_fk_parent_exists(table_name, new_values)?;
                        }
                    }
                }

                let arc_prog;
                let program: &VdbeProgram = if let Some(p) = precompiled {
                    p
                } else {
                    let plan_span = tracing::span!(
                        target: "fsqlite.plan",
                        tracing::Level::TRACE,
                        "plan",
                        stage = "compile_table_update"
                    );
                    record_trace_span_created();
                    let _plan_guard = plan_span.enter();
                    let sql_text = effective_update.to_string();
                    let sql_key = Self::sql_hash(&sql_text);
                    arc_prog = self.compile_with_cache(sql_key, &sql_text, |conn| {
                        conn.compile_table_update(&effective_update)
                    })?;
                    &arc_prog
                };
                let (rows, affected, _) = self.execute_table_program_with_cx(
                    program,
                    params,
                    false,
                    TableExecutionRuntimeRequirements::read_path(),
                    cx,
                )?;

                // Phase 5G.3: Fire AFTER UPDATE triggers.
                if has_after_update {
                    for (old_values, new_values) in &trigger_rows {
                        self.fire_after_triggers(
                            table_name,
                            &update_event,
                            Some(old_values),
                            Some(new_values),
                        )?;
                    }
                }

                // 5D.4: Persistence now handled by pager WAL, not compat_persist.
                self.record_statement_changes(affected);
                if effective_update.returning.is_empty() {
                    Ok(Vec::new())
                } else {
                    Ok(rows)
                }
            }
            Statement::Delete(delete) => {
                // CTE (WITH clause): materialize CTEs as temporary tables,
                // then execute the DELETE with the WITH clause stripped.
                if delete.with.is_some() {
                    self.log_mem_execution_fallback("delete", "with_clause_materialization")?;
                    return self.execute_delete_with_ctes(delete, params);
                }
                let (effective_delete, _limited_row_count_hint) =
                    self.materialize_delete_limit_scope(delete, params)?;
                let table_name = &effective_delete.table.name.name;
                self.reject_without_rowid_dml(table_name, "DELETE")?;
                let delete_event = fsqlite_ast::TriggerEvent::Delete;
                let has_before_delete = self.has_matching_triggers(
                    table_name,
                    fsqlite_ast::TriggerTiming::Before,
                    &delete_event,
                );
                let has_after_delete = self.has_matching_triggers(
                    table_name,
                    fsqlite_ast::TriggerTiming::After,
                    &delete_event,
                );
                let trigger_old_rows = if has_before_delete || has_after_delete {
                    self.collect_delete_trigger_rows(&effective_delete, params)?
                } else {
                    Vec::new()
                };

                // Phase 5G.2 (bd-iqam): Fire BEFORE DELETE triggers.
                let skip_dml = if has_before_delete {
                    let mut skip = false;
                    for old_values in &trigger_old_rows {
                        if self.fire_before_triggers(
                            table_name,
                            &delete_event,
                            Some(old_values),
                            None,
                        )? {
                            skip = true;
                            break;
                        }
                    }
                    skip
                } else {
                    false
                };
                if skip_dml {
                    self.reset_statement_change_count();
                    return Ok(Vec::new());
                }

                // FK enforcement on DELETE: check/cascade for each row.
                // Use `fk_cascade_propagation_enabled` (not `fk_enforcement_enabled`)
                // so that multi-level cascades propagate through intermediate
                // tables (e.g., grandparent -> parent -> child).
                if self.fk_cascade_propagation_enabled() {
                    let rows_to_check = if !trigger_old_rows.is_empty() {
                        trigger_old_rows.clone()
                    } else {
                        self.collect_delete_trigger_rows(&effective_delete, params)?
                    };
                    for row_values in &rows_to_check {
                        let fk_actions = self.check_fk_on_delete(table_name, row_values)?;
                        for action in &fk_actions {
                            self.execute_fk_delete_action(action)?;
                        }
                    }
                }

                let arc_prog;
                let program: &VdbeProgram = if let Some(p) = precompiled {
                    p
                } else {
                    let plan_span = tracing::span!(
                        target: "fsqlite.plan",
                        tracing::Level::TRACE,
                        "plan",
                        stage = "compile_table_delete"
                    );
                    record_trace_span_created();
                    let _plan_guard = plan_span.enter();
                    let sql_text = effective_delete.to_string();
                    let sql_key = Self::sql_hash(&sql_text);
                    arc_prog = self.compile_with_cache(sql_key, &sql_text, |conn| {
                        conn.compile_table_delete(&effective_delete)
                    })?;
                    &arc_prog
                };
                let (rows, affected, _) = self.execute_table_program_with_cx(
                    program,
                    params,
                    false,
                    TableExecutionRuntimeRequirements::read_path(),
                    cx,
                )?;

                // Phase 5G.3: Fire AFTER DELETE triggers.
                if has_after_delete {
                    for old_values in &trigger_old_rows {
                        self.fire_after_triggers(
                            table_name,
                            &delete_event,
                            Some(old_values),
                            None,
                        )?;
                    }
                }

                // 5D.4: Persistence now handled by pager WAL, not compat_persist.
                self.record_statement_changes(affected);
                if effective_delete.returning.is_empty() {
                    Ok(Vec::new())
                } else {
                    Ok(rows)
                }
            }
            Statement::Begin(begin) => {
                self.execute_begin(*begin)?;
                Ok(Vec::new())
            }
            Statement::Commit => {
                self.execute_commit_with_cx(cx)?;
                Ok(Vec::new())
            }
            Statement::Rollback(rb) => {
                self.execute_rollback_with_cx(cx, rb)?;
                // 5D.4: Persistence now handled by pager WAL, not compat_persist.
                Ok(Vec::new())
            }
            Statement::Savepoint(name) => {
                self.execute_savepoint_with_cx(cx, name)?;
                Ok(Vec::new())
            }
            Statement::Release(name) => {
                self.execute_release_with_cx(cx, name)?;
                Ok(Vec::new())
            }
            Statement::Pragma(pragma) => self.execute_pragma(pragma),
            Statement::Drop(drop_stmt) => {
                self.execute_drop(drop_stmt)?;
                // 5D.4: Persistence now handled by pager WAL, not compat_persist.
                Ok(Vec::new())
            }
            Statement::AlterTable(alter) => {
                self.execute_alter_table(alter)?;
                // 5D.4: Persistence now handled by pager WAL, not compat_persist.
                Ok(Vec::new())
            }
            Statement::CreateIndex(create_idx) => {
                self.execute_create_index(create_idx)?;
                // 5D.4: Persistence now handled by pager WAL, not compat_persist.
                Ok(Vec::new())
            }
            Statement::CreateView(create_view) => {
                self.execute_create_view(create_view)?;
                Ok(Vec::new())
            }
            Statement::CreateTrigger(create_trigger) => {
                self.execute_create_trigger(create_trigger)?;
                Ok(Vec::new())
            }
            Statement::Vacuum(vacuum_stmt) => {
                self.execute_vacuum(vacuum_stmt, params)?;
                Ok(Vec::new())
            }
            Statement::Analyze(target) => {
                self.execute_analyze(target.as_ref())?;
                Ok(Vec::new())
            }
            Statement::Reindex(target) => {
                self.execute_reindex(target.as_ref())?;
                Ok(Vec::new())
            }
            Statement::Explain { query_plan, stmt } => {
                self.execute_explain(stmt, *query_plan, params)
            }
            Statement::Attach(attach) => {
                let path_rows = self.execute_statement(
                    &Statement::Select(SelectStatement {
                        with: None,
                        body: SelectBody {
                            select: SelectCore::Select {
                                distinct: Distinctness::All,
                                columns: vec![ResultColumn::Expr {
                                    expr: attach.expr.clone(),
                                    alias: None,
                                }],
                                from: None,
                                where_clause: None,
                                group_by: Vec::new(),
                                having: None,
                                windows: Vec::new(),
                            },
                            compounds: Vec::new(),
                        },
                        order_by: Vec::new(),
                        limit: None,
                    }),
                    params,
                )?;
                let path = path_rows
                    .first()
                    .and_then(|r| r.values().first())
                    .map(|v| match v {
                        SqliteValue::Text(s) => s.to_string(),
                        other => format!("{other}"),
                    })
                    .unwrap_or_default();
                let attached_connection = Box::new(Self::open(path.clone())?);
                self.attached_schemas
                    .borrow_mut()
                    .attach(attach.schema.clone(), path)?;
                self.attached_connections
                    .borrow_mut()
                    .insert(attached_schema_key(&attach.schema), attached_connection);
                Ok(Vec::new())
            }
            Statement::Detach(schema_name) => {
                self.attached_schemas.borrow_mut().detach(schema_name)?;
                self.attached_connections
                    .borrow_mut()
                    .remove(&attached_schema_key(schema_name));
                Ok(Vec::new())
            }
            #[allow(unreachable_patterns)]
            _ => Err(FrankenError::NotImplemented(
                "unsupported statement type".to_owned(),
            )),
        }
    }

    /// Pre-process statement-level subquery expressions before compilation.
    ///
    /// EXISTS and scalar subqueries are eagerly evaluated everywhere.
    /// Simple `IN (SELECT ...)` are left intact for VDBE probe, but IN
    /// subqueries with GROUP BY/HAVING/windows/compounds/WITH are eagerly
    /// evaluated since VDBE codegen emits NULL for those.  Fallback paths (GROUP BY,
    /// JOIN, expression-only SELECT) apply the IN rewrite separately.
    fn rewrite_subquery_statement<'a>(
        &self,
        statement: &'a Statement,
        params: Option<&[SqliteValue]>,
    ) -> Result<Cow<'a, Statement>> {
        // Fast path: if the statement has no EXISTS/scalar-subquery expressions
        // in rewrite-covered locations, skip the clone/traversal rewrite pass.
        let has_flattenable_derived_table = matches!(
            statement,
            Statement::Select(select) if flatten_simple_from_subquery_select(select).is_some()
        );
        if !statement_contains_rewritable_subquery(statement) && !has_flattenable_derived_table {
            return Ok(Cow::Borrowed(statement));
        }
        match statement {
            Statement::Select(select) if select.with.is_some() => {
                // When the SELECT has a WITH clause, the CTE tables have not
                // been materialized yet.  Subqueries may reference CTE names,
                // so skip eager rewriting here — it will happen after CTE
                // materialization inside execute_with_ctes.
                Ok(Cow::Borrowed(statement))
            }
            Statement::Select(select)
                if is_expression_only_select(select) && expression_only_has_subquery(select) =>
            {
                // Expression-only SELECTs with scalar subqueries in result
                // columns are handled by execute_expression_only_with_subqueries
                // in dispatch.  Skip the eager rewrite here — evaluating each
                // subquery via execute_statement would create nested autocommit
                // transactions that can trigger reload_memdb_from_pager,
                // destroying CTE temp tables between subquery evaluations.
                Ok(Cow::Borrowed(statement))
            }
            Statement::Select(select) => {
                let rewritten = self.rewrite_subqueries(select, params)?;
                Ok(Cow::Owned(Statement::Select(rewritten)))
            }
            Statement::Update(update) if update.with.is_some() => Ok(Cow::Borrowed(statement)),
            Statement::Update(update) => {
                let mut update = update.clone();
                // Rewrite EXISTS / scalar subqueries, plus IN subqueries that
                // VDBE can't probe (GROUP BY, HAVING, windows, compounds, WITH).
                for assignment in &mut update.assignments {
                    rewrite_in_expr(&mut assignment.value, self, false, params)?;
                }
                if let Some(where_expr) = update.where_clause.as_mut() {
                    rewrite_in_expr(where_expr, self, false, params)?;
                }
                Ok(Cow::Owned(Statement::Update(update)))
            }
            Statement::Delete(delete) if delete.with.is_some() => Ok(Cow::Borrowed(statement)),
            Statement::Delete(delete) => {
                let mut delete = delete.clone();
                // Rewrite EXISTS / scalar subqueries, plus IN subqueries that
                // VDBE can't probe (GROUP BY, HAVING, windows, compounds, WITH).
                if let Some(where_expr) = delete.where_clause.as_mut() {
                    rewrite_in_expr(where_expr, self, false, params)?;
                }
                Ok(Cow::Owned(Statement::Delete(delete)))
            }
            other => Ok(Cow::Borrowed(other)),
        }
    }

    #[allow(clippy::too_many_lines, clippy::significant_drop_tightening)]
    fn execute_insert_select_fallback(
        &self,
        insert: &fsqlite_ast::InsertStatement,
        select_stmt: &fsqlite_ast::SelectStatement,
        params: Option<&[SqliteValue]>,
    ) -> Result<usize> {
        let source_rows =
            self.materialize_insert_select_source_rows(insert, select_stmt, params)?;
        self.execute_insert_select_materialized_rows(insert, &source_rows)
    }

    fn execute_materialized_insert_select_statement(
        &self,
        insert: &fsqlite_ast::InsertStatement,
        source_rows: &[Row],
    ) -> Result<usize> {
        let was_auto = self.ensure_autocommit_txn()?;
        let preserve_prior_changes_on_constraint_violation =
            insert.or_conflict == Some(fsqlite_ast::ConflictAction::Fail);
        let use_statement_savepoint = !was_auto
            && self.active_txn.borrow().is_some()
            && self.internal_statement_savepoint_depth.get() == 0
            && !preserve_prior_changes_on_constraint_violation;
        let result = if use_statement_savepoint {
            self.with_internal_statement_savepoint("insert_select", || {
                self.execute_insert_select_materialized_rows(insert, source_rows)
            })
        } else {
            self.execute_insert_select_materialized_rows(insert, source_rows)
        };
        let commit_autocommit_on_error = was_auto
            && preserve_prior_changes_on_constraint_violation
            && matches!(
                result.as_ref(),
                Err(error) if error_is_constraint_violation(error)
            );
        let ok = result.is_ok() || commit_autocommit_on_error;
        self.resolve_autocommit_txn_with_capture(was_auto, ok, false)?;
        result
    }

    fn materialize_insert_select_source_rows(
        &self,
        insert: &fsqlite_ast::InsertStatement,
        select_stmt: &fsqlite_ast::SelectStatement,
        params: Option<&[SqliteValue]>,
    ) -> Result<Vec<Row>> {
        // If the INSERT has a WITH clause (CTEs), transfer it to the SELECT
        // so execute_statement will materialize the CTEs before evaluation.
        let effective_select = if let Some(ref with) = insert.with {
            let mut sel = select_stmt.clone();
            sel.with = Some(with.clone());
            sel
        } else {
            select_stmt.clone()
        };
        self.execute_statement(&Statement::Select(effective_select), params)
    }

    fn materialize_insert_values_source_rows(
        &self,
        rows: &[Vec<Expr>],
        params: Option<&[SqliteValue]>,
    ) -> Result<Vec<Row>> {
        rows.iter()
            .map(|row_exprs| {
                Ok(Row {
                    values: self.evaluate_insert_source_row(row_exprs, params)?,
                })
            })
            .collect()
    }

    fn execute_insert_select_materialized_rows(
        &self,
        insert: &fsqlite_ast::InsertStatement,
        source_rows: &[Row],
    ) -> Result<usize> {
        if !insert.upsert.is_empty() || !insert.returning.is_empty() {
            return Err(FrankenError::NotImplemented(
                "INSERT ... SELECT fallback does not support UPSERT/RETURNING".to_owned(),
            ));
        }
        let layout = self.resolve_insert_target_layout(insert)?;
        if layout.table_columns.is_empty() {
            return Err(FrankenError::Internal(format!(
                "table '{}' has no insertable columns",
                insert.table.name
            )));
        }
        if source_rows.is_empty() {
            return Ok(0);
        }

        let source_column_count = layout.targets.len();
        for (row_idx, row) in source_rows.iter().enumerate() {
            if row.values().len() != source_column_count {
                return Err(FrankenError::Internal(format!(
                    "INSERT ... SELECT column count mismatch: source row {row_idx} has {} values, SELECT produced {source_column_count}",
                    row.values().len()
                )));
            }
        }

        let qualified_table = quote_qualified_name(&insert.table);
        let placeholders = (1..=layout.table_columns.len()).map(|idx| format!("?{idx}"));
        let conflict_clause = match &insert.or_conflict {
            Some(fsqlite_ast::ConflictAction::Replace) => "OR REPLACE ",
            Some(fsqlite_ast::ConflictAction::Ignore) => "OR IGNORE ",
            Some(fsqlite_ast::ConflictAction::Abort) => "OR ABORT ",
            Some(fsqlite_ast::ConflictAction::Fail) => "OR FAIL ",
            Some(fsqlite_ast::ConflictAction::Rollback) => "OR ROLLBACK ",
            None => "",
        };
        let insert_sql = if insert.columns.is_empty() {
            let placeholders = placeholders.collect::<Vec<_>>().join(", ");
            format!("INSERT {conflict_clause}INTO {qualified_table} VALUES ({placeholders});")
        } else {
            let quoted_targets = insert
                .columns
                .iter()
                .map(|column| quote_identifier(column))
                .collect::<Vec<_>>()
                .join(", ");
            let placeholders = (1..=layout.targets.len())
                .map(|idx| format!("?{idx}"))
                .collect::<Vec<_>>()
                .join(", ");
            format!(
                "INSERT {conflict_clause}INTO {qualified_table} ({quoted_targets}) VALUES ({placeholders});"
            )
        };

        let preserve_prior_changes_on_constraint_violation =
            insert.or_conflict == Some(fsqlite_ast::ConflictAction::Fail);
        let previous_total_changes = *self.total_changes.borrow();
        let previous_last_insert_rowid = self.current_last_insert_rowid();
        let execute_rows = || -> Result<usize> {
            let mut statement_changes = 0usize;
            for row in source_rows {
                match self.execute_with_params(&insert_sql, row.values()) {
                    Ok(affected) => {
                        statement_changes = statement_changes.saturating_add(affected);
                    }
                    Err(error) => {
                        if self.internal_statement_savepoint_depth.get() > 0 {
                            self.restore_change_tracking_state(
                                0,
                                previous_total_changes,
                                previous_last_insert_rowid,
                            );
                        } else {
                            self.set_statement_change_count(statement_changes);
                            self.record_table_program_error_state(
                                statement_changes,
                                (statement_changes > 0).then(|| self.current_last_insert_rowid()),
                            );
                        }
                        return Err(error);
                    }
                }
            }
            self.set_statement_change_count(statement_changes);
            Ok(statement_changes)
        };

        if !preserve_prior_changes_on_constraint_violation
            && self.active_txn.borrow().is_some()
            && self.internal_statement_savepoint_depth.get() == 0
        {
            self.with_internal_statement_savepoint("insert_select", execute_rows)
        } else {
            execute_rows()
        }
    }

    fn validate_insert_target_columns(
        table_schema: &TableSchema,
        table_name: &str,
        insert_columns: &[String],
    ) -> Result<()> {
        if insert_columns.is_empty() {
            return Ok(());
        }

        for column in insert_columns {
            if table_schema.column_index(column).is_none() && !is_hidden_rowid_alias_name(column) {
                return Err(FrankenError::Internal(format!(
                    "column '{column}' not found in table '{table_name}'"
                )));
            }
        }

        Ok(())
    }

    /// Handle INSERT OR REPLACE / INSERT OR IGNORE for VALUES source by
    /// evaluating each row, resolving the INTEGER PRIMARY KEY rowid, and
    /// applying conflict resolution directly on the in-memory database.
    #[allow(dead_code)]
    #[allow(clippy::too_many_lines)]
    fn execute_insert_or_conflict(
        &self,
        insert: &fsqlite_ast::InsertStatement,
        rows: &[Vec<Expr>],
        params: Option<&[SqliteValue]>,
    ) -> Result<usize> {
        use fsqlite_ast::ConflictAction;

        let conflict = insert
            .or_conflict
            .as_ref()
            .ok_or_else(|| FrankenError::Internal("expected or_conflict".to_owned()))?;

        let table_name = &insert.table.name;
        let schema = self.schema.borrow();
        let table_schema = schema
            .iter()
            .find(|t| t.name.eq_ignore_ascii_case(table_name))
            .ok_or_else(|| FrankenError::Internal(format!("no such table: {table_name}")))?
            .clone();
        Self::validate_insert_target_columns(&table_schema, table_name, &insert.columns)?;
        let root_page = table_schema.root_page;
        let num_cols = table_schema.columns.len();

        // Determine which VALUES position maps to the INTEGER PRIMARY KEY
        // column so we can extract the user-supplied rowid.
        let ipk_col_idx = self
            .rowid_alias_columns
            .borrow()
            .get(&table_name.to_ascii_lowercase())
            .copied();
        // Map from VALUES position to table target.
        let target_map: Vec<InsertTarget> = if insert.columns.is_empty() {
            (0..num_cols).map(InsertTarget::Column).collect()
        } else {
            insert
                .columns
                .iter()
                .map(|col| {
                    if let Some(index) = table_schema.column_index(col) {
                        Ok(InsertTarget::Column(index))
                    } else if is_hidden_rowid_alias_name(col) {
                        Ok(InsertTarget::HiddenRowid)
                    } else {
                        Err(FrankenError::Internal(format!(
                            "column '{col}' not found in table '{table_name}'"
                        )))
                    }
                })
                .collect::<Result<Vec<_>>>()?
        };
        // Which VALUES position (if any) maps to the rowid family target.
        let ipk_values_pos = target_map.iter().rposition(|target| match target {
            InsertTarget::HiddenRowid => true,
            InsertTarget::Column(index) => Some(*index) == ipk_col_idx,
        });

        drop(schema);

        let mut affected = 0usize;

        for row_exprs in rows {
            // Evaluate the row expressions by wrapping them in a SELECT.
            let expr_strs: Vec<String> = row_exprs.iter().map(|e| format!("{e}")).collect();
            let select_sql = format!("SELECT {}", expr_strs.join(", "));
            let eval_rows = if let Some(p) = params {
                self.query_with_params(&select_sql, p)?
            } else {
                self.query(&select_sql)?
            };
            let values: Vec<SqliteValue> = eval_rows
                .first()
                .map(|r| r.values().to_vec())
                .unwrap_or_default();

            // Extract the user-supplied rowid from the IPK column (if any).
            let explicit_rowid = ipk_values_pos
                .and_then(|pos| values.get(pos))
                .and_then(Self::coerce_explicit_rowid_value);

            // Build the full column value vector in table order. For ordinary
            // columns, duplicate targets keep the first assignment like SQLite.
            let mut col_values = vec![SqliteValue::Null; num_cols];
            let mut filled_columns = vec![false; num_cols];
            for (val_pos, target) in target_map.iter().enumerate() {
                let Some(v) = values.get(val_pos) else {
                    continue;
                };
                let InsertTarget::Column(tgt) = target else {
                    continue;
                };
                if Some(*tgt) == ipk_col_idx || filled_columns[*tgt] {
                    continue;
                }
                col_values[*tgt] = v.clone();
                filled_columns[*tgt] = true;
            }
            if let (Some(ipk_idx), Some(rowid)) = (ipk_col_idx, explicit_rowid) {
                col_values[ipk_idx] = SqliteValue::Integer(rowid);
            }

            // Verify we don't silently ignore STORED generated columns in the fallback path.
            for col_info in &table_schema.columns {
                if col_info.generated_stored == Some(true) {
                    return Err(FrankenError::NotImplemented(
                        "STORED generated columns are not yet supported in the INSERT OR REPLACE fallback path".to_owned()
                    ));
                }
            }

            let mut db = self.db.borrow_mut();

            // Check UNIQUE constraints on columns.
            let mut unique_violation_col: Option<String> = None;
            let mut conflicting_rowids: Vec<i64> = Vec::new();
            if let Some(table) = db.get_table(root_page) {
                // 1. Column-level UNIQUE constraints.
                for (i, col_info) in table_schema.columns.iter().enumerate() {
                    if col_info.unique && !col_info.is_ipk {
                        let new_val = &col_values[i];
                        if !new_val.is_null() {
                            for mem_row in table.iter_rows() {
                                if Some(mem_row.0) == explicit_rowid {
                                    continue; // Replacing this rowid.
                                }
                                if let Some(existing_val) = mem_row.1.get(i) {
                                    if existing_val == new_val {
                                        if *conflict == ConflictAction::Replace {
                                            conflicting_rowids.push(mem_row.0);
                                        } else {
                                            unique_violation_col = Some(col_info.name.clone());
                                        }
                                        break;
                                    }
                                }
                            }
                        }
                    }
                    if unique_violation_col.is_some() {
                        break;
                    }
                }

                // 2. Index-level UNIQUE constraints (CREATE UNIQUE INDEX).
                if unique_violation_col.is_none() {
                    for idx in &table_schema.indexes {
                        if !idx.is_unique {
                            continue;
                        }
                        // Resolve index column names to positions in the table.
                        let idx_positions: Vec<usize> = idx
                            .columns
                            .iter()
                            .filter_map(|c| table_schema.column_index(c))
                            .collect();
                        if idx_positions.len() != idx.columns.len() {
                            continue; // Column resolution failed, skip.
                        }
                        // If any indexed value is NULL, skip (NULL is unique).
                        if idx_positions.iter().any(|&pos| col_values[pos].is_null()) {
                            continue;
                        }
                        let new_key: Vec<&SqliteValue> =
                            idx_positions.iter().map(|&pos| &col_values[pos]).collect();

                        for mem_row in table.iter_rows() {
                            if Some(mem_row.0) == explicit_rowid {
                                continue;
                            }
                            let existing_key: Vec<Option<&SqliteValue>> = idx_positions
                                .iter()
                                .map(|&pos| mem_row.1.get(pos))
                                .collect();
                            if existing_key.iter().all(|v| v.is_some())
                                && existing_key
                                    .iter()
                                    .zip(new_key.iter())
                                    .all(|(e, n)| e.unwrap() == *n)
                            {
                                if *conflict == ConflictAction::Replace {
                                    conflicting_rowids.push(mem_row.0);
                                } else {
                                    unique_violation_col = Some(idx.key_label());
                                }
                                break;
                            }
                        }
                        if unique_violation_col.is_some() {
                            break;
                        }
                    }
                }
            }

            if let Some(col_name) = unique_violation_col {
                if *conflict == ConflictAction::Ignore {
                    continue;
                }
                return Err(FrankenError::UniqueViolation {
                    columns: format!("{}.{}", table_name, col_name),
                });
            }

            // For REPLACE: delete rows that conflict on non-IPK UNIQUE columns.
            if *conflict == ConflictAction::Replace && !conflicting_rowids.is_empty() {
                let table = db.get_table_mut(root_page).ok_or_else(|| {
                    FrankenError::Internal(format!("table not found at root page {root_page}"))
                })?;
                for rid in &conflicting_rowids {
                    table.delete_by_rowid(*rid);
                }
            }

            if let Some(rowid) = explicit_rowid {
                let exists = db
                    .get_table(root_page)
                    .and_then(|t| t.find_by_rowid(rowid))
                    .is_some();

                match conflict {
                    ConflictAction::Replace => {
                        // insert_row delegates to insert() which has upsert
                        // semantics: replaces if rowid already exists.
                        let table = db.get_table_mut(root_page).ok_or_else(|| {
                            FrankenError::Internal(format!(
                                "table not found at root page {root_page}"
                            ))
                        })?;
                        if let Some(ipk_idx) = ipk_col_idx {
                            col_values[ipk_idx] = SqliteValue::Integer(rowid);
                        }
                        table.insert_row(rowid, col_values);
                        self.record_last_insert_rowid(rowid);
                        affected += 1;
                    }
                    ConflictAction::Ignore => {
                        if !exists {
                            let table = db.get_table_mut(root_page).ok_or_else(|| {
                                FrankenError::Internal(format!(
                                    "table not found at root page {root_page}"
                                ))
                            })?;
                            if let Some(ipk_idx) = ipk_col_idx {
                                col_values[ipk_idx] = SqliteValue::Integer(rowid);
                            }
                            table.insert_row(rowid, col_values);
                            self.record_last_insert_rowid(rowid);
                            affected += 1;
                        }
                        // else: silently skip this row
                    }
                    ConflictAction::Abort | ConflictAction::Fail | ConflictAction::Rollback => {
                        if exists {
                            return Err(FrankenError::UniqueViolation {
                                columns: format!("{table_name}.rowid"),
                            });
                        }
                        let table = db.get_table_mut(root_page).ok_or_else(|| {
                            FrankenError::Internal(format!(
                                "table not found at root page {root_page}"
                            ))
                        })?;
                        if let Some(ipk_idx) = ipk_col_idx {
                            col_values[ipk_idx] = SqliteValue::Integer(rowid);
                        }
                        table.insert_row(rowid, col_values);
                        self.record_last_insert_rowid(rowid);
                        affected += 1;
                    }
                }
            } else {
                // No explicit rowid; auto-allocate.  Conflict on auto-generated
                // rowid is practically impossible.
                let table = db.get_table_mut(root_page).ok_or_else(|| {
                    FrankenError::Internal(format!("table not found at root page {root_page}"))
                })?;
                let new_rowid = table.alloc_rowid();
                if let Some(ipk_idx) = ipk_col_idx {
                    col_values[ipk_idx] = SqliteValue::Integer(new_rowid);
                }
                table.insert_row(new_rowid, col_values);
                self.record_last_insert_rowid(new_rowid);
                affected += 1;
            }
        }

        Ok(affected)
    }

    fn resolve_insert_target_layout(
        &self,
        insert: &fsqlite_ast::InsertStatement,
    ) -> Result<InsertTargetLayout> {
        let schema = self.schema.borrow();
        let table = schema
            .iter()
            .find(|tbl| tbl.name.eq_ignore_ascii_case(&insert.table.name))
            .ok_or_else(|| {
                FrankenError::Internal(format!("table not found: {}", insert.table.name))
            })?;
        Self::validate_insert_target_columns(table, &insert.table.name, &insert.columns)?;

        let table_columns: Vec<String> = table.columns.iter().map(|col| col.name.clone()).collect();
        let rowid_alias_col_idx = table.columns.iter().position(|column| column.is_ipk);

        if insert.columns.is_empty() {
            let targets = (0..table_columns.len()).map(InsertTarget::Column).collect();
            return Ok(InsertTargetLayout {
                explicit_rowid_source: rowid_alias_col_idx,
                rowid_alias_col_idx,
                table_columns,
                targets,
            });
        }

        let mut targets = Vec::with_capacity(insert.columns.len());
        for col in &insert.columns {
            if let Some(idx) = table.column_index(col) {
                targets.push(InsertTarget::Column(idx));
            } else if is_hidden_rowid_alias_name(col) {
                targets.push(InsertTarget::HiddenRowid);
            } else {
                return Err(FrankenError::Internal(format!(
                    "column '{col}' not found in table '{}'",
                    insert.table.name
                )));
            }
        }
        let explicit_rowid_source = targets.iter().rposition(|target| match target {
            InsertTarget::HiddenRowid => true,
            InsertTarget::Column(idx) => Some(*idx) == rowid_alias_col_idx,
        });
        Ok(InsertTargetLayout {
            table_columns,
            targets,
            rowid_alias_col_idx,
            explicit_rowid_source,
        })
    }

    /// Compile and wrap a statement into a `PreparedStatement`.
    fn compile_and_wrap(&self, sql: &str, statement: &Statement) -> Result<PreparedStatement<'_>> {
        let registry = Some(Arc::clone(&*self.func_registry.borrow()));
        let prepared_column_names = self.prepared_statement_column_names(statement);
        match statement {
            Statement::Select(_) if self.prepared_select_requires_dispatch(statement) => {
                let placeholder_program =
                    Arc::new(ProgramBuilder::new().finish().map_err(|e| {
                        FrankenError::Internal(format!("failed to build placeholder program: {e}"))
                    })?);
                Ok(PreparedStatement {
                    sql: sql.to_owned(),
                    program: placeholder_program,
                    func_registry: registry,
                    expression_postprocess: None,
                    distinct: false,
                    db: None,
                    pager: None,
                    post_distinct_limit: None,
                    schema_cookie: self.schema_cookie(),
                    schema_generation: self.schema_generation(),
                    dml_dispatch: None,
                    prepared_update_delete_fast_path: None,
                    deferred_query_statement: Some(Arc::new(statement.clone())),
                    deferred_query_column_count: Some(
                        self.prepared_statement_column_count(statement),
                    ),
                    column_names: prepared_column_names,
                    conn: self,
                })
            }
            Statement::Select(select) if is_expression_only_select(select) => {
                let program = Arc::new(compile_expression_select(select)?);
                let expression_postprocess = Some(build_expression_postprocess(select));
                Ok(PreparedStatement {
                    sql: sql.to_owned(),
                    program,
                    func_registry: registry,
                    expression_postprocess,
                    distinct: is_distinct_select(select),
                    db: None,
                    pager: None,
                    post_distinct_limit: None,
                    schema_cookie: self.schema_cookie(),
                    schema_generation: self.schema_generation(),
                    dml_dispatch: None,
                    prepared_update_delete_fast_path: None,
                    deferred_query_statement: None,
                    deferred_query_column_count: None,
                    column_names: prepared_column_names,
                    conn: self,
                })
            }
            Statement::Select(select) => {
                let distinct = is_distinct_select(select);
                let limit_clause = select.limit.clone();
                let program = if distinct && limit_clause.is_some() {
                    let mut unbounded = select.clone();
                    unbounded.limit = None;
                    let compiled_sql = unbounded.to_string();
                    let compiled_sql_key = Self::sql_hash(&compiled_sql);
                    self.compile_with_cache(compiled_sql_key, &compiled_sql, |conn| {
                        conn.compile_table_select(&unbounded)
                    })?
                } else {
                    let sql_key = Self::sql_hash(sql);
                    self.compile_with_cache(sql_key, sql, |conn| conn.compile_table_select(select))?
                };
                Ok(PreparedStatement {
                    sql: sql.to_owned(),
                    program,
                    func_registry: registry,
                    expression_postprocess: None,
                    distinct,
                    db: Some(Rc::clone(&self.db)),
                    pager: Some(self.pager.clone()),
                    post_distinct_limit: if distinct { limit_clause } else { None },
                    schema_cookie: self.schema_cookie(),
                    schema_generation: self.schema_generation(),
                    dml_dispatch: None,
                    prepared_update_delete_fast_path: None,
                    deferred_query_statement: None,
                    deferred_query_column_count: None,
                    column_names: prepared_column_names,
                    conn: self,
                })
            }
            Statement::Insert(insert) => {
                // bd-1dp9.6.7.2.1: Pre-compile simple VALUES-based INSERTs
                // into a real VdbeProgram so execute_prepared can reuse the
                // cached program without re-running codegen each call.
                // INSERT...SELECT with complex subqueries still gets a
                // placeholder and falls back to full execute_statement.
                let requires_deferred_dispatch =
                    self.prepared_insert_requires_deferred_dispatch(insert)?;
                let is_simple_values = matches!(
                    &insert.source,
                    fsqlite_ast::InsertSource::Values(_) | fsqlite_ast::InsertSource::DefaultValues
                ) || matches!(
                    &insert.source,
                    fsqlite_ast::InsertSource::Select(sel)
                    if matches!(sel.body.select, SelectCore::Values(_))
                       && sel.body.compounds.is_empty()
                );

                if is_simple_values && !requires_deferred_dispatch {
                    let sql_key = Self::sql_hash(sql);
                    let program = self.compile_with_cache(sql_key, sql, |conn| {
                        conn.compile_table_insert(insert)
                    })?;
                    Ok(PreparedStatement {
                        sql: sql.to_owned(),
                        program,
                        func_registry: registry,
                        expression_postprocess: None,
                        distinct: false,
                        db: Some(Rc::clone(&self.db)),
                        pager: Some(self.pager.clone()),
                        post_distinct_limit: None,
                        schema_cookie: self.schema_cookie(),
                        schema_generation: self.schema_generation(),
                        dml_dispatch: Some(
                            if self.prepared_insert_supports_direct_dispatch(insert) {
                                PreparedDmlDispatch::Precompiled(PreparedPrecompiledDml {
                                    kind: PreparedDmlKind::Insert,
                                    table_name: insert.table.name.clone(),
                                    post_write_action: self
                                        .prepared_insert_post_write_action(&insert.table.name),
                                    rollback_on_constraint_violation: insert.or_conflict
                                        == Some(fsqlite_ast::ConflictAction::Rollback),
                                    preserve_prior_changes_on_constraint_violation: insert
                                        .or_conflict
                                        == Some(fsqlite_ast::ConflictAction::Fail),
                                    runtime_requirements: self
                                        .insert_runtime_requirements(insert)?,
                                })
                            } else {
                                PreparedDmlDispatch::Deferred(Arc::new(statement.clone()))
                            },
                        ),
                        prepared_update_delete_fast_path: None,
                        deferred_query_statement: None,
                        deferred_query_column_count: None,
                        column_names: prepared_column_names.clone(),
                        conn: self,
                    })
                } else {
                    // Attached-target or complex INSERT statements must stay on
                    // the deferred path so execution can route through the
                    // statement dispatcher instead of main-schema bytecode.
                    let placeholder_program =
                        Arc::new(ProgramBuilder::new().finish().map_err(|e| {
                            FrankenError::Internal(format!(
                                "failed to build placeholder program: {e}"
                            ))
                        })?);
                    Ok(PreparedStatement {
                        sql: sql.to_owned(),
                        program: placeholder_program,
                        func_registry: registry,
                        expression_postprocess: None,
                        distinct: false,
                        db: None,
                        pager: None,
                        post_distinct_limit: None,
                        schema_cookie: self.schema_cookie(),
                        schema_generation: self.schema_generation(),
                        dml_dispatch: Some(PreparedDmlDispatch::Deferred(Arc::new(
                            statement.clone(),
                        ))),
                        prepared_update_delete_fast_path: None,
                        deferred_query_statement: None,
                        deferred_query_column_count: None,
                        column_names: prepared_column_names.clone(),
                        conn: self,
                    })
                }
            }
            Statement::Update(update) => {
                if Self::prepared_update_supports_precompiled_program(update)
                    && !self.prepared_update_requires_deferred_dispatch(update)?
                {
                    let fast_path = self.prepared_update_fast_path_metadata(update);
                    let sql_key = Self::sql_hash(sql);
                    let program = self.compile_with_cache(sql_key, sql, |conn| {
                        conn.compile_table_update(update)
                    })?;
                    Ok(PreparedStatement {
                        sql: sql.to_owned(),
                        program,
                        func_registry: registry,
                        expression_postprocess: None,
                        distinct: false,
                        db: Some(Rc::clone(&self.db)),
                        pager: Some(self.pager.clone()),
                        post_distinct_limit: None,
                        schema_cookie: self.schema_cookie(),
                        schema_generation: self.schema_generation(),
                        dml_dispatch: Some(PreparedDmlDispatch::Deferred(Arc::new(
                            statement.clone(),
                        ))),
                        prepared_update_delete_fast_path: Some(fast_path),
                        deferred_query_statement: None,
                        deferred_query_column_count: None,
                        column_names: prepared_column_names,
                        conn: self,
                    })
                } else {
                    let placeholder_program =
                        Arc::new(ProgramBuilder::new().finish().map_err(|e| {
                            FrankenError::Internal(format!(
                                "failed to build placeholder program: {e}"
                            ))
                        })?);
                    Ok(PreparedStatement {
                        sql: sql.to_owned(),
                        program: placeholder_program,
                        func_registry: registry,
                        expression_postprocess: None,
                        distinct: false,
                        db: None,
                        pager: None,
                        post_distinct_limit: None,
                        schema_cookie: self.schema_cookie(),
                        schema_generation: self.schema_generation(),
                        dml_dispatch: Some(PreparedDmlDispatch::Deferred(Arc::new(
                            statement.clone(),
                        ))),
                        prepared_update_delete_fast_path: None,
                        deferred_query_statement: None,
                        deferred_query_column_count: None,
                        column_names: prepared_column_names,
                        conn: self,
                    })
                }
            }
            Statement::Delete(delete) => {
                if Self::prepared_delete_supports_precompiled_program(delete)
                    && !self.prepared_delete_requires_deferred_dispatch(delete)?
                {
                    let fast_path = self.prepared_delete_fast_path_metadata(delete);
                    let sql_key = Self::sql_hash(sql);
                    let program = self.compile_with_cache(sql_key, sql, |conn| {
                        conn.compile_table_delete(delete)
                    })?;
                    Ok(PreparedStatement {
                        sql: sql.to_owned(),
                        program,
                        func_registry: registry,
                        expression_postprocess: None,
                        distinct: false,
                        db: Some(Rc::clone(&self.db)),
                        pager: Some(self.pager.clone()),
                        post_distinct_limit: None,
                        schema_cookie: self.schema_cookie(),
                        schema_generation: self.schema_generation(),
                        dml_dispatch: Some(PreparedDmlDispatch::Deferred(Arc::new(
                            statement.clone(),
                        ))),
                        prepared_update_delete_fast_path: Some(fast_path),
                        deferred_query_statement: None,
                        deferred_query_column_count: None,
                        column_names: prepared_column_names,
                        conn: self,
                    })
                } else {
                    let placeholder_program =
                        Arc::new(ProgramBuilder::new().finish().map_err(|e| {
                            FrankenError::Internal(format!(
                                "failed to build placeholder program: {e}"
                            ))
                        })?);
                    Ok(PreparedStatement {
                        sql: sql.to_owned(),
                        program: placeholder_program,
                        func_registry: registry,
                        expression_postprocess: None,
                        distinct: false,
                        db: None,
                        pager: None,
                        post_distinct_limit: None,
                        schema_cookie: self.schema_cookie(),
                        schema_generation: self.schema_generation(),
                        dml_dispatch: Some(PreparedDmlDispatch::Deferred(Arc::new(
                            statement.clone(),
                        ))),
                        prepared_update_delete_fast_path: None,
                        deferred_query_statement: None,
                        deferred_query_column_count: None,
                        column_names: prepared_column_names,
                        conn: self,
                    })
                }
            }
            _ => Err(FrankenError::NotImplemented(
                "prepare() supports SELECT, INSERT, UPDATE, and DELETE statements only".to_owned(),
            )),
        }
    }

    fn prepared_insert_supports_direct_dispatch(
        &self,
        insert: &fsqlite_ast::InsertStatement,
    ) -> bool {
        if is_fts5_optimize_noop_insert(insert) {
            return false;
        }
        if !insert.returning.is_empty() {
            return false;
        }

        let table_name = insert.table.name.as_str();
        let insert_event = fsqlite_ast::TriggerEvent::Insert;
        if self.has_matching_triggers(
            table_name,
            fsqlite_ast::TriggerTiming::Before,
            &insert_event,
        ) || self.has_matching_triggers(
            table_name,
            fsqlite_ast::TriggerTiming::After,
            &insert_event,
        ) {
            return false;
        }

        self.schema
            .borrow()
            .iter()
            .find(|table| table.name.eq_ignore_ascii_case(table_name))
            .is_some_and(|table| table.foreign_keys.is_empty())
    }

    fn prepared_insert_requires_deferred_dispatch(
        &self,
        insert: &fsqlite_ast::InsertStatement,
    ) -> Result<bool> {
        Ok(self.attached_target_schema(&insert.table)?.is_some())
    }

    fn prepared_update_requires_deferred_dispatch(
        &self,
        update: &fsqlite_ast::UpdateStatement,
    ) -> Result<bool> {
        let registry = self.attached_schemas.borrow();
        Ok(determine_attached_update_schema(update, &registry)?.is_some())
    }

    fn prepared_delete_requires_deferred_dispatch(
        &self,
        delete: &fsqlite_ast::DeleteStatement,
    ) -> Result<bool> {
        let registry = self.attached_schemas.borrow();
        Ok(determine_attached_delete_schema(delete, &registry)?.is_some())
    }

    fn prepared_update_supports_precompiled_program(update: &fsqlite_ast::UpdateStatement) -> bool {
        update.with.is_none()
            && update.order_by.is_empty()
            && update.limit.is_none()
            && !update
                .assignments
                .iter()
                .any(|assignment| expr_contains_rewritable_subquery(&assignment.value))
            && !update
                .where_clause
                .as_ref()
                .is_some_and(expr_contains_rewritable_subquery)
    }

    fn prepared_delete_supports_precompiled_program(delete: &fsqlite_ast::DeleteStatement) -> bool {
        delete.with.is_none()
            && delete.order_by.is_empty()
            && delete.limit.is_none()
            && !delete
                .where_clause
                .as_ref()
                .is_some_and(expr_contains_rewritable_subquery)
    }

    fn prepared_update_delete_static_fallback_reason(
        &self,
        table_name: &str,
        returning_present: bool,
        trigger_event: &fsqlite_ast::TriggerEvent,
    ) -> Option<PreparedUpdateDeleteFallbackReason> {
        if returning_present {
            return Some(PreparedUpdateDeleteFallbackReason::Returning);
        }
        if table_name.eq_ignore_ascii_case("sqlite_sequence") {
            return Some(PreparedUpdateDeleteFallbackReason::SqliteSequence);
        }
        if self.table_declares_without_rowid(table_name) {
            return Some(PreparedUpdateDeleteFallbackReason::WithoutRowid);
        }
        if self.has_live_vtab_instance(table_name) {
            return Some(PreparedUpdateDeleteFallbackReason::LiveVtab);
        }
        if self.has_matching_triggers(
            table_name,
            fsqlite_ast::TriggerTiming::Before,
            trigger_event,
        ) || self.has_matching_triggers(
            table_name,
            fsqlite_ast::TriggerTiming::After,
            trigger_event,
        ) {
            return Some(PreparedUpdateDeleteFallbackReason::Trigger);
        }
        None
    }

    fn prepared_update_fast_path_metadata(
        &self,
        update: &fsqlite_ast::UpdateStatement,
    ) -> PreparedUpdateDeleteFastPath {
        let table_name = update.table.name.name.as_str();
        let update_cols: Vec<String> = update
            .assignments
            .iter()
            .flat_map(|assignment| match &assignment.target {
                fsqlite_ast::AssignmentTarget::Column(column) => vec![column.clone()],
                fsqlite_ast::AssignmentTarget::ColumnList(columns) => columns.clone(),
            })
            .collect();
        let update_event = fsqlite_ast::TriggerEvent::Update(update_cols);
        PreparedUpdateDeleteFastPath {
            kind: PreparedDmlKind::Update,
            rollback_on_constraint_violation: update.or_conflict
                == Some(fsqlite_ast::ConflictAction::Rollback),
            preserve_prior_changes_on_constraint_violation: update.or_conflict
                == Some(fsqlite_ast::ConflictAction::Fail),
            static_fallback_reason: self.prepared_update_delete_static_fallback_reason(
                table_name,
                !update.returning.is_empty(),
                &update_event,
            ),
            foreign_key_work: self.table_has_foreign_key_work(table_name),
        }
    }

    fn prepared_delete_fast_path_metadata(
        &self,
        delete: &fsqlite_ast::DeleteStatement,
    ) -> PreparedUpdateDeleteFastPath {
        let table_name = delete.table.name.name.as_str();
        let delete_event = fsqlite_ast::TriggerEvent::Delete;
        PreparedUpdateDeleteFastPath {
            kind: PreparedDmlKind::Delete,
            rollback_on_constraint_violation: false,
            preserve_prior_changes_on_constraint_violation: false,
            static_fallback_reason: self.prepared_update_delete_static_fallback_reason(
                table_name,
                !delete.returning.is_empty(),
                &delete_event,
            ),
            foreign_key_work: self.table_is_foreign_key_parent(table_name),
        }
    }

    fn table_is_foreign_key_parent(&self, table_name: &str) -> bool {
        self.schema.borrow().iter().any(|table| {
            table
                .foreign_keys
                .iter()
                .any(|fk| fk.parent_table.eq_ignore_ascii_case(table_name))
        })
    }

    fn table_has_foreign_key_work(&self, table_name: &str) -> bool {
        let schema = self.schema.borrow();
        let has_outbound_foreign_keys = schema.iter().any(|table| {
            table.name.eq_ignore_ascii_case(table_name) && !table.foreign_keys.is_empty()
        });
        has_outbound_foreign_keys
            || schema.iter().any(|table| {
                table
                    .foreign_keys
                    .iter()
                    .any(|fk| fk.parent_table.eq_ignore_ascii_case(table_name))
            })
    }

    fn insert_runtime_requirements(
        &self,
        insert: &fsqlite_ast::InsertStatement,
    ) -> Result<TableExecutionRuntimeRequirements> {
        let target_root_page = {
            let schema = self.schema.borrow();
            schema
                .iter()
                .find(|table| table.name.eq_ignore_ascii_case(&insert.table.name))
                .map(|table| table.root_page)
                .ok_or_else(|| {
                    FrankenError::Internal(format!("no such table: {}", insert.table.name))
                })?
        };
        let autoincrement_root_page = self
            .autoincrement_tables
            .borrow()
            .contains(&insert.table.name.to_ascii_lowercase())
            .then_some(target_root_page);
        // Simple VALUES/DEFAULT VALUES inserts already have omitted-column
        // defaults compiled directly into bytecode, so they do not need the
        // connection-level legacy short-record default map.
        let needs_column_defaults = match &insert.source {
            fsqlite_ast::InsertSource::Values(_) | fsqlite_ast::InsertSource::DefaultValues => {
                false
            }
            fsqlite_ast::InsertSource::Select(select_stmt) => {
                !matches!(select_stmt.body.select, SelectCore::Values(_))
                    || !select_stmt.body.compounds.is_empty()
            }
        };
        Ok(TableExecutionRuntimeRequirements::write_path(
            autoincrement_root_page,
            needs_column_defaults,
        ))
    }

    fn prepared_insert_post_write_action(&self, table_name: &str) -> PreparedInsertPostWriteAction {
        if table_name.eq_ignore_ascii_case("sqlite_sequence") {
            PreparedInsertPostWriteAction::RefreshSqliteSequenceCache
        } else if self.is_autoincrement_table(table_name) {
            PreparedInsertPostWriteAction::RefreshAutoincrementSequence
        } else {
            PreparedInsertPostWriteAction::None
        }
    }

    fn prepared_select_requires_dispatch(&self, statement: &Statement) -> bool {
        let Statement::Select(select) = statement else {
            return false;
        };

        let expression_only = is_expression_only_select(select);
        let has_ordered_aggregate = has_ordered_aggregate(select);
        let has_grouping =
            has_group_by(select) || has_implicit_aggregation(select) || has_ordered_aggregate;
        let has_join_like_source = has_joins(select) || has_fallback_from_source(select);

        statement_contains_rewritable_subquery(statement)
            || select.with.is_some()
            || self.has_view_references(select)
            || self.has_sqlite_schema_references(select)
            || select_references_non_main_schema(select)
            || !select.body.compounds.is_empty()
            || (expression_only && has_implicit_aggregation(select))
            || (expression_only && expression_only_has_subquery(select))
            || (has_grouping && has_join_like_source)
            || has_group_by(select)
            || has_ordered_aggregate
            || has_window_functions(select)
            || select_contains_match_operator(select)
            // All JOINs go through deferred dispatch (interpreted path) until
            // codegen_join_select is validated against the conformance oracle.
            || has_join_like_source
            || select_has_correlated_join_subquery(select)
    }

    fn prepared_statement_column_count(&self, statement: &Statement) -> usize {
        let Statement::Select(select) = statement else {
            return 0;
        };
        self.select_result_column_count(select, &[], &mut Vec::new())
    }

    fn prepared_statement_column_names(&self, statement: &Statement) -> Vec<String> {
        let Statement::Select(select) = statement else {
            return Vec::new();
        };
        let inferred = infer_select_column_names(select);
        if inferred.is_empty() {
            return inferred;
        }
        let schema = self.schema.borrow();
        resolve_cte_column_names_with_schema(&inferred, select, &schema)
    }

    fn select_result_column_count(
        &self,
        select: &SelectStatement,
        outer_ctes: &[fsqlite_ast::Cte],
        active_ctes: &mut Vec<String>,
    ) -> usize {
        let mut visible_ctes = outer_ctes.to_vec();
        if let Some(with) = &select.with {
            visible_ctes.extend(with.ctes.clone());
        }

        match &select.body.select {
            SelectCore::Values(rows) => rows.first().map_or(0, Vec::len),
            SelectCore::Select { columns, from, .. } => columns
                .iter()
                .map(|column| match column {
                    ResultColumn::Expr { .. } => 1,
                    ResultColumn::Star => from.as_ref().map_or(1, |from_clause| {
                        self.from_clause_result_column_count(
                            from_clause,
                            &visible_ctes,
                            active_ctes,
                        )
                    }),
                    ResultColumn::TableStar(name) => from.as_ref().map_or(1, |from_clause| {
                        self.named_source_result_column_count(
                            from_clause,
                            name,
                            &visible_ctes,
                            active_ctes,
                        )
                    }),
                })
                .sum(),
        }
    }

    #[allow(clippy::wrong_self_convention)]
    fn from_clause_result_column_count(
        &self,
        from: &FromClause,
        visible_ctes: &[fsqlite_ast::Cte],
        active_ctes: &mut Vec<String>,
    ) -> usize {
        let mut total =
            self.table_or_subquery_result_column_count(&from.source, visible_ctes, active_ctes);
        for join in &from.joins {
            total +=
                self.table_or_subquery_result_column_count(&join.table, visible_ctes, active_ctes);
        }
        total
    }

    fn named_source_result_column_count(
        &self,
        from: &FromClause,
        source_name: &str,
        visible_ctes: &[fsqlite_ast::Cte],
        active_ctes: &mut Vec<String>,
    ) -> usize {
        std::iter::once(&from.source)
            .chain(from.joins.iter().map(|join| &join.table))
            .find(|source| source_matches_name(source, source_name))
            .map_or(1, |source| {
                self.table_or_subquery_result_column_count(source, visible_ctes, active_ctes)
            })
    }

    fn table_or_subquery_result_column_count(
        &self,
        source: &TableOrSubquery,
        visible_ctes: &[fsqlite_ast::Cte],
        active_ctes: &mut Vec<String>,
    ) -> usize {
        match source {
            TableOrSubquery::Table { name, .. } => {
                self.named_relation_result_column_count(&name.name, visible_ctes, active_ctes)
            }
            TableOrSubquery::Subquery { query, .. } => self
                .select_result_column_count(query, visible_ctes, active_ctes)
                .max(infer_select_column_names(query).len())
                .max(1),
            TableOrSubquery::TableFunction { name, .. } => {
                table_function_column_names(name).map_or(1, |cols| cols.len())
            }
            TableOrSubquery::ParenJoin(from) => {
                self.from_clause_result_column_count(from, visible_ctes, active_ctes)
            }
        }
    }

    fn named_relation_result_column_count(
        &self,
        relation_name: &str,
        visible_ctes: &[fsqlite_ast::Cte],
        active_ctes: &mut Vec<String>,
    ) -> usize {
        if let Some(table) = self
            .schema
            .borrow()
            .iter()
            .find(|table| table.name.eq_ignore_ascii_case(relation_name))
        {
            return table.columns.len();
        }

        if let Some(cte) = visible_ctes
            .iter()
            .rev()
            .find(|cte| cte.name.eq_ignore_ascii_case(relation_name))
        {
            return self.cte_result_column_count(cte, visible_ctes, active_ctes);
        }

        if let Some(view) = self
            .views
            .borrow()
            .iter()
            .find(|view| view.name.eq_ignore_ascii_case(relation_name))
        {
            return self
                .select_result_column_count(&view.query, visible_ctes, active_ctes)
                .max(1);
        }

        1
    }

    fn cte_result_column_count(
        &self,
        cte: &fsqlite_ast::Cte,
        visible_ctes: &[fsqlite_ast::Cte],
        active_ctes: &mut Vec<String>,
    ) -> usize {
        if !cte.columns.is_empty() {
            return cte.columns.len();
        }
        if active_ctes
            .iter()
            .any(|active_name| active_name.eq_ignore_ascii_case(&cte.name))
        {
            return infer_select_column_names(&cte.query).len().max(1);
        }

        active_ctes.push(cte.name.clone());
        let column_count = self
            .select_result_column_count(&cte.query, visible_ctes, active_ctes)
            .max(1);
        active_ctes.pop();
        column_count
    }

    /// Count the number of rows in `table_name` matching an optional WHERE
    /// clause.  Used by UPDATE/DELETE to compute the affected-row count
    /// without modifying the VDBE engine.
    fn select_matching_rows(
        &self,
        table_ref: &fsqlite_ast::QualifiedTableRef,
        where_clause: Option<&Expr>,
        order_by: &[fsqlite_ast::OrderingTerm],
        limit: Option<&fsqlite_ast::LimitClause>,
        params: Option<&[SqliteValue]>,
    ) -> Result<Vec<Row>> {
        let select = Self::build_single_table_select(
            table_ref,
            vec![ResultColumn::Star],
            where_clause,
            order_by,
            limit,
        );
        self.execute_statement(&Statement::Select(select), params)
    }

    /// Count rows matching UPDATE/DELETE scope using the existing SELECT
    /// helper so affected-row accounting is decoupled from VDBE opcode shape.
    #[allow(dead_code)]
    fn count_matching_rows(
        &self,
        table_ref: &fsqlite_ast::QualifiedTableRef,
        where_clause: Option<&Expr>,
        order_by: &[fsqlite_ast::OrderingTerm],
        limit: Option<&fsqlite_ast::LimitClause>,
        params: Option<&[SqliteValue]>,
    ) -> Result<usize> {
        self.select_matching_rows(table_ref, where_clause, order_by, limit, params)
            .map(|rows| rows.len())
    }

    /// Materialize the target row-set for `UPDATE ... ORDER BY/LIMIT` into a
    /// deterministic key-filter expression so VDBE execution mutates only the
    /// selected rows.
    fn materialize_update_limit_scope(
        &self,
        update: &fsqlite_ast::UpdateStatement,
        params: Option<&[SqliteValue]>,
    ) -> Result<(fsqlite_ast::UpdateStatement, Option<usize>)> {
        if update.order_by.is_empty() && update.limit.is_none() {
            return Ok((update.clone(), None));
        }
        if update.from.is_some() {
            return Err(FrankenError::NotImplemented(
                "UPDATE ... FROM with ORDER BY/LIMIT is not yet supported".to_owned(),
            ));
        }

        let (key_column, _is_hidden_rowid) = self.resolve_dml_limit_key(&update.table.name.name)?;
        let selected_keys = self.select_matching_limit_keys(
            &update.table,
            update.where_clause.as_ref(),
            &update.order_by,
            update.limit.as_ref(),
            params,
            &key_column,
        )?;

        let mut effective = update.clone();
        effective.where_clause = Some(Self::build_limit_scope_filter_expr(
            &effective.table,
            &key_column,
            &selected_keys,
        ));
        effective.order_by.clear();
        effective.limit = None;
        Ok((effective, Some(selected_keys.len())))
    }

    /// Materialize the target row-set for `DELETE ... ORDER BY/LIMIT` into a
    /// deterministic key-filter expression so VDBE execution deletes only the
    /// selected rows.
    fn materialize_delete_limit_scope(
        &self,
        delete: &fsqlite_ast::DeleteStatement,
        params: Option<&[SqliteValue]>,
    ) -> Result<(fsqlite_ast::DeleteStatement, Option<usize>)> {
        if delete.order_by.is_empty() && delete.limit.is_none() {
            return Ok((delete.clone(), None));
        }

        let (key_column, _is_hidden_rowid) = self.resolve_dml_limit_key(&delete.table.name.name)?;
        let selected_keys = self.select_matching_limit_keys(
            &delete.table,
            delete.where_clause.as_ref(),
            &delete.order_by,
            delete.limit.as_ref(),
            params,
            &key_column,
        )?;

        let mut effective = delete.clone();
        effective.where_clause = Some(Self::build_limit_scope_filter_expr(
            &effective.table,
            &key_column,
            &selected_keys,
        ));
        effective.order_by.clear();
        effective.limit = None;
        Ok((effective, Some(selected_keys.len())))
    }

    /// Resolve a stable key column for DML LIMIT scoping.
    ///
    /// Prefers hidden rowid aliases when available; otherwise falls back to the
    /// INTEGER PRIMARY KEY column when all rowid aliases are shadowed.
    fn resolve_dml_limit_key(&self, table_name: &str) -> Result<(String, bool)> {
        let schema = self.schema.borrow();
        let table = schema
            .iter()
            .find(|tbl| tbl.name.eq_ignore_ascii_case(table_name))
            .ok_or_else(|| FrankenError::NoSuchTable {
                name: table_name.to_owned(),
            })?;

        let shadowed: HashSet<String> = table
            .columns
            .iter()
            .map(|column| column.name.to_ascii_lowercase())
            .collect();

        for candidate in ["rowid", "_rowid_", "oid"] {
            if !shadowed.contains(candidate) {
                return Ok((candidate.to_owned(), true));
            }
        }

        if let Some(ipk_column) = table.columns.iter().find(|column| column.is_ipk) {
            return Ok((ipk_column.name.clone(), false));
        }

        Err(FrankenError::NotImplemented(format!(
            "ORDER BY/LIMIT for UPDATE/DELETE requires rowid or INTEGER PRIMARY KEY on table `{table_name}`"
        )))
    }

    /// Select key values for UPDATE/DELETE LIMIT scoping using the statement's
    /// original WHERE/ORDER BY/LIMIT clauses.
    #[allow(clippy::too_many_arguments)]
    fn select_matching_limit_keys(
        &self,
        table_ref: &fsqlite_ast::QualifiedTableRef,
        where_clause: Option<&Expr>,
        order_by: &[fsqlite_ast::OrderingTerm],
        limit: Option<&fsqlite_ast::LimitClause>,
        params: Option<&[SqliteValue]>,
        key_column: &str,
    ) -> Result<Vec<i64>> {
        let select = Self::build_single_table_select(
            table_ref,
            vec![ResultColumn::Expr {
                expr: Self::build_limit_scope_projection_expr(table_ref, key_column),
                alias: None,
            }],
            where_clause,
            order_by,
            limit,
        );
        let rows = self.execute_statement(&Statement::Select(select), params)?;

        rows.iter()
            .map(|row| {
                let key_value = row.values().first().ok_or_else(|| {
                    FrankenError::Internal(
                        "DML LIMIT key materialization returned an empty row".to_owned(),
                    )
                })?;
                Self::decode_limit_scope_key(key_value, key_column)
            })
            .collect()
    }

    fn build_single_table_select(
        table_ref: &fsqlite_ast::QualifiedTableRef,
        columns: Vec<ResultColumn>,
        where_clause: Option<&Expr>,
        order_by: &[OrderingTerm],
        limit: Option<&LimitClause>,
    ) -> SelectStatement {
        SelectStatement {
            with: None,
            body: SelectBody {
                select: SelectCore::Select {
                    distinct: Distinctness::All,
                    columns,
                    from: Some(FromClause {
                        source: TableOrSubquery::Table {
                            name: table_ref.name.clone(),
                            alias: table_ref.alias.clone(),
                            index_hint: table_ref.index_hint.clone(),
                            time_travel: table_ref.time_travel.clone(),
                        },
                        joins: Vec::new(),
                    }),
                    where_clause: where_clause.cloned().map(Box::new),
                    group_by: Vec::new(),
                    having: None,
                    windows: Vec::new(),
                },
                compounds: Vec::new(),
            },
            order_by: order_by.to_vec(),
            limit: limit.cloned(),
        }
    }

    fn build_limit_scope_projection_expr(
        table_ref: &fsqlite_ast::QualifiedTableRef,
        key_column: &str,
    ) -> Expr {
        Expr::Column(
            ColumnRef {
                table: table_ref.alias.clone(),
                column: key_column.to_owned(),
            },
            Span::ZERO,
        )
    }

    fn build_limit_scope_filter_expr(
        table_ref: &fsqlite_ast::QualifiedTableRef,
        key_column: &str,
        selected_keys: &[i64],
    ) -> Expr {
        if selected_keys.is_empty() {
            return Expr::Literal(Literal::Integer(0), Span::ZERO);
        }

        let key_ref = Expr::Column(
            ColumnRef {
                table: table_ref.alias.clone(),
                column: key_column.to_owned(),
            },
            Span::ZERO,
        );
        let list = selected_keys
            .iter()
            .map(|value| Expr::Literal(Literal::Integer(*value), Span::ZERO))
            .collect();

        Expr::In {
            expr: Box::new(key_ref),
            set: InSet::List(list),
            not: false,
            span: Span::ZERO,
        }
    }

    fn decode_limit_scope_key(value: &SqliteValue, key_column: &str) -> Result<i64> {
        match value {
            SqliteValue::Integer(n) => Ok(*n),
            SqliteValue::Float(f) => {
                if f.is_finite()
                    && f.fract() == 0.0
                    && *f >= i64::MIN as f64
                    && *f <= i64::MAX as f64
                {
                    Ok(*f as i64)
                } else {
                    Err(FrankenError::Internal(format!(
                        "non-integral key value `{f}` materialized for `{key_column}`"
                    )))
                }
            }
            SqliteValue::Text(text) => text.parse::<i64>().map_err(|err| {
                FrankenError::Internal(format!(
                    "failed to parse key `{text}` for `{key_column}` as INTEGER: {err}"
                ))
            }),
            other => Err(FrankenError::Internal(format!(
                "unsupported key type `{other:?}` materialized for `{key_column}`"
            ))),
        }
    }

    fn collect_insert_trigger_rows(
        &self,
        insert: &fsqlite_ast::InsertStatement,
        params: Option<&[SqliteValue]>,
    ) -> Result<Vec<Vec<SqliteValue>>> {
        let layout = self.resolve_insert_target_layout(insert)?;
        let default_sqls = self.collect_insert_default_sqls(&insert.table.name)?;
        let table_column_count = layout.table_columns.len();
        if default_sqls.len() != table_column_count {
            return Err(FrankenError::Internal(format!(
                "INSERT trigger snapshot: default row width {} does not match table width {table_column_count}",
                default_sqls.len()
            )));
        }
        match &insert.source {
            fsqlite_ast::InsertSource::Values(rows) => rows
                .iter()
                .enumerate()
                .map(|(row_idx, row_exprs)| {
                    let source_values = self.evaluate_insert_source_row(row_exprs, params)?;
                    let default_row = self.evaluate_default_row_from_sqls(&default_sqls)?;
                    self.map_insert_source_row_to_table_row(
                        &default_row,
                        &layout.targets,
                        layout.rowid_alias_col_idx,
                        layout.explicit_rowid_source,
                        &source_values,
                        &format!("INSERT VALUES row {}", row_idx + 1),
                    )
                })
                .collect(),
            fsqlite_ast::InsertSource::Select(select) => {
                let source_rows =
                    self.execute_statement(&Statement::Select(*select.clone()), params)?;
                source_rows
                    .iter()
                    .enumerate()
                    .map(|(row_idx, row)| {
                        let default_row = self.evaluate_default_row_from_sqls(&default_sqls)?;
                        self.map_insert_source_row_to_table_row(
                            &default_row,
                            &layout.targets,
                            layout.rowid_alias_col_idx,
                            layout.explicit_rowid_source,
                            row.values(),
                            &format!("INSERT SELECT row {}", row_idx + 1),
                        )
                    })
                    .collect()
            }
            fsqlite_ast::InsertSource::DefaultValues => {
                Ok(vec![self.evaluate_default_row_from_sqls(&default_sqls)?])
            }
        }
    }

    fn evaluate_insert_source_row(
        &self,
        row_exprs: &[Expr],
        params: Option<&[SqliteValue]>,
    ) -> Result<Vec<SqliteValue>> {
        let projection = row_exprs
            .iter()
            .map(ToString::to_string)
            .collect::<Vec<_>>()
            .join(", ");
        let sql = format!("SELECT {projection}");
        let rows = if let Some(params) = params {
            self.query_with_params(&sql, params)?
        } else {
            self.query(&sql)?
        };
        Ok(rows
            .first()
            .map(|row| row.values().to_vec())
            .unwrap_or_default())
    }

    fn collect_live_vtab_insert_rows(
        &self,
        insert: &fsqlite_ast::InsertStatement,
        params: Option<&[SqliteValue]>,
    ) -> Result<Vec<LiveVtabInsertRow>> {
        let schema = self.schema.borrow();
        let table = schema
            .iter()
            .find(|tbl| tbl.name.eq_ignore_ascii_case(&insert.table.name))
            .ok_or_else(|| {
                FrankenError::Internal(format!("table not found: {}", insert.table.name))
            })?
            .clone();
        drop(schema);

        let table_columns: Vec<String> = table.columns.iter().map(|col| col.name.clone()).collect();
        let default_sqls = self.collect_insert_default_sqls(&insert.table.name)?;
        if default_sqls.len() != table_columns.len() {
            return Err(FrankenError::Internal(format!(
                "live virtual-table INSERT default row width {} does not match table width {}",
                default_sqls.len(),
                table_columns.len()
            )));
        }

        let source_targets = if insert.columns.is_empty() {
            (0..table_columns.len()).map(Some).collect::<Vec<_>>()
        } else {
            let mut targets = Vec::with_capacity(insert.columns.len());
            for column in &insert.columns {
                if let Some(idx) = table.column_index(column) {
                    targets.push(Some(idx));
                    continue;
                }
                if is_rowid_alias(column) {
                    targets.push(None);
                    continue;
                }
                return Err(FrankenError::Internal(format!(
                    "column '{column}' not found in table '{}'",
                    insert.table.name
                )));
            }
            targets
        };

        let build_row =
            |source_values: &[SqliteValue], context: &str| -> Result<LiveVtabInsertRow> {
                if source_values.len() != source_targets.len() {
                    return Err(FrankenError::Internal(format!(
                        "{context}: column count mismatch (source has {}, target expects {})",
                        source_values.len(),
                        source_targets.len()
                    )));
                }

                let mut row = self.evaluate_default_row_from_sqls(&default_sqls)?;
                let mut explicit_rowid = None;
                let mut filled_columns = vec![false; row.len()];
                for (source_idx, target_idx) in source_targets.iter().copied().enumerate() {
                    if let Some(target_idx) = target_idx {
                        if filled_columns[target_idx] {
                            continue;
                        }
                        row[target_idx] = source_values[source_idx].clone();
                        filled_columns[target_idx] = true;
                    } else {
                        explicit_rowid = Some(source_values[source_idx].clone());
                    }
                }

                Ok(LiveVtabInsertRow {
                    explicit_rowid,
                    values: row,
                })
            };

        match &insert.source {
            fsqlite_ast::InsertSource::Values(rows) => rows
                .iter()
                .enumerate()
                .map(|(row_idx, row_exprs)| {
                    let source_values = self.evaluate_insert_source_row(row_exprs, params)?;
                    build_row(
                        &source_values,
                        &format!("live virtual-table INSERT VALUES row {}", row_idx + 1),
                    )
                })
                .collect(),
            fsqlite_ast::InsertSource::Select(select) => {
                let source_rows =
                    self.execute_statement(&Statement::Select(*select.clone()), params)?;
                source_rows
                    .iter()
                    .enumerate()
                    .map(|(row_idx, row)| {
                        build_row(
                            row.values(),
                            &format!("live virtual-table INSERT SELECT row {}", row_idx + 1),
                        )
                    })
                    .collect()
            }
            fsqlite_ast::InsertSource::DefaultValues => Ok(vec![build_row(
                &[],
                "live virtual-table INSERT DEFAULT VALUES",
            )?]),
        }
    }

    fn execute_live_vtab_insert_rows(
        &self,
        table_name: &str,
        rows: &[LiveVtabInsertRow],
    ) -> Result<Vec<i64>> {
        let cx = self.op_cx()?;
        let key = table_name.to_ascii_uppercase();
        let mut instances = self.vtab_instances.borrow_mut();
        let instance = instances.get_mut(&key).ok_or_else(|| {
            FrankenError::Internal(format!("virtual table not found: {table_name}"))
        })?;
        self.begin_live_vtab_transaction_if_needed(table_name, instance.as_mut(), &cx)?;

        let mut inserted_rowids = Vec::with_capacity(rows.len());
        for row in rows {
            let mut args = Vec::with_capacity(row.values.len() + 2);
            args.push(SqliteValue::Null);
            let new_rowid = if instance.as_any().is::<RtreeVirtualTable>() {
                row.explicit_rowid
                    .clone()
                    .or_else(|| row.values.first().cloned())
                    .unwrap_or(SqliteValue::Null)
            } else {
                row.explicit_rowid.clone().unwrap_or(SqliteValue::Null)
            };
            args.push(new_rowid);
            args.extend(row.values.iter().cloned());
            let rowid = instance.update(&cx, &args)?.ok_or_else(|| {
                FrankenError::Internal(format!(
                    "virtual table {table_name} did not return a rowid for INSERT",
                ))
            })?;
            inserted_rowids.push(rowid);
            self.record_last_insert_rowid(rowid);
        }

        Ok(inserted_rowids)
    }

    #[allow(clippy::unused_self)]
    fn map_insert_source_row_to_table_row(
        &self,
        default_row: &[SqliteValue],
        source_targets: &[InsertTarget],
        rowid_alias_col_idx: Option<usize>,
        explicit_rowid_source: Option<usize>,
        source_values: &[SqliteValue],
        context: &str,
    ) -> Result<Vec<SqliteValue>> {
        if source_values.len() != source_targets.len() {
            return Err(FrankenError::Internal(format!(
                "{context}: column count mismatch (source has {}, target expects {})",
                source_values.len(),
                source_targets.len()
            )));
        }

        let mut row = default_row.to_vec();
        let explicit_rowid = explicit_rowid_source
            .and_then(|source_idx| source_values.get(source_idx))
            .and_then(Self::coerce_explicit_rowid_value);
        let mut filled_targets = vec![false; row.len()];
        for (source_idx, target) in source_targets.iter().copied().enumerate() {
            let InsertTarget::Column(target_idx) = target else {
                continue;
            };
            if Some(target_idx) == rowid_alias_col_idx || filled_targets[target_idx] {
                continue;
            }
            row[target_idx] = source_values[source_idx].clone();
            filled_targets[target_idx] = true;
        }
        if let (Some(ipk_idx), Some(rowid)) = (rowid_alias_col_idx, explicit_rowid) {
            row[ipk_idx] = SqliteValue::Integer(rowid);
        }
        Ok(row)
    }

    fn collect_insert_default_sqls(&self, table_name: &str) -> Result<Vec<Option<String>>> {
        let default_sqls: Vec<Option<String>> = {
            let schema = self.schema.borrow();
            let table = schema
                .iter()
                .find(|tbl| tbl.name.eq_ignore_ascii_case(table_name))
                .ok_or_else(|| FrankenError::Internal(format!("table not found: {table_name}")))?;
            table
                .columns
                .iter()
                .map(|column| column.default_value.clone())
                .collect()
        };

        Ok(default_sqls)
    }

    fn coerce_explicit_rowid_value(value: &SqliteValue) -> Option<i64> {
        if matches!(value, SqliteValue::Null) {
            None
        } else {
            Some(value.to_integer())
        }
    }

    fn evaluate_default_row_from_sqls(
        &self,
        default_sqls: &[Option<String>],
    ) -> Result<Vec<SqliteValue>> {
        default_sqls
            .iter()
            .map(|default_sql| self.evaluate_column_default_value(default_sql.as_deref()))
            .collect()
    }

    fn evaluate_column_default_value(&self, default_sql: Option<&str>) -> Result<SqliteValue> {
        let Some(default_sql) = default_sql else {
            return Ok(SqliteValue::Null);
        };
        let trimmed = default_sql.trim();
        if trimmed.is_empty() {
            return Ok(SqliteValue::Null);
        }

        let sql = format!("SELECT {trimmed}");
        let statement = parse_single_statement(&sql)?;
        let rows = self.execute_statement(&statement, None).map_err(|error| {
            FrankenError::Internal(format!(
                "failed to evaluate DEFAULT expression `{trimmed}`: {error}"
            ))
        })?;

        Ok(rows
            .first()
            .and_then(|row| row.values().first())
            .cloned()
            .unwrap_or(SqliteValue::Null))
    }

    fn collect_update_trigger_rows(
        &self,
        update: &fsqlite_ast::UpdateStatement,
        params: Option<&[SqliteValue]>,
    ) -> Result<Vec<(Vec<SqliteValue>, Vec<SqliteValue>)>> {
        let matched_rows = self.select_matching_rows(
            &update.table,
            update.where_clause.as_ref(),
            &[],
            None,
            params,
        )?;
        if matched_rows.is_empty() {
            return Ok(Vec::new());
        }

        let table_name = &update.table.name.name;
        let schema = self.schema.borrow();
        let table = schema
            .iter()
            .find(|t| t.name.eq_ignore_ascii_case(table_name))
            .ok_or_else(|| FrankenError::NoSuchTable {
                name: table_name.clone(),
            })?;
        let column_names: Vec<String> = table.columns.iter().map(|col| col.name.clone()).collect();
        let table_label = update
            .table
            .alias
            .as_deref()
            .unwrap_or(table_name)
            .to_owned();
        drop(schema);

        let col_map = column_names
            .iter()
            .cloned()
            .map(|name| (table_label.clone(), name, false))
            .collect::<Vec<_>>();

        // Bind placeholders in assignment values so eval_join_expr can
        // evaluate them.  Without this, numbered placeholders (`?1`, `?2`, ...)
        // would reach the catch-all arm and fail with "unsupported expression
        // type: Placeholder".  This is particularly triggered when
        // PRAGMA foreign_keys=ON causes collect_update_trigger_rows to be
        // called for FK constraint checking.
        let bound_assignments = if let Some(p) = params {
            let mut cloned = update.assignments.clone();
            let mut bind_state = BindParamState::default();
            for a in &mut cloned {
                bind_placeholders_in_expr(&mut a.value, &mut bind_state, p)?;
            }
            cloned
        } else {
            update.assignments.clone()
        };

        let mut trigger_rows = Vec::with_capacity(matched_rows.len());
        for row in matched_rows {
            let old_values = row.values().to_vec();
            let mut new_values = old_values.clone();

            for assignment in &bound_assignments {
                match &assignment.target {
                    fsqlite_ast::AssignmentTarget::Column(column_name) => {
                        let target_index =
                            find_column_index_case_insensitive(&column_names, column_name)
                                .ok_or_else(|| {
                                    FrankenError::Internal(format!(
                                        "UPDATE trigger snapshot: unknown column `{column_name}`"
                                    ))
                                })?;
                        new_values[target_index] =
                            eval_join_expr(&assignment.value, &old_values, &col_map)?;
                    }
                    fsqlite_ast::AssignmentTarget::ColumnList(columns) => {
                        if columns.len() == 1 {
                            let target_index =
                                find_column_index_case_insensitive(&column_names, &columns[0])
                                    .ok_or_else(|| {
                                        FrankenError::Internal(format!(
                                            "UPDATE trigger snapshot: unknown column `{}`",
                                            columns[0]
                                        ))
                                    })?;
                            let value_expr = match &assignment.value {
                                Expr::RowValue(values, _) if values.len() == 1 => &values[0],
                                other => other,
                            };
                            new_values[target_index] =
                                eval_join_expr(value_expr, &old_values, &col_map)?;
                            continue;
                        }

                        match &assignment.value {
                            Expr::RowValue(values, _) if values.len() == columns.len() => {
                                for (column_name, value_expr) in columns.iter().zip(values) {
                                    let target_index = find_column_index_case_insensitive(
                                        &column_names,
                                        column_name,
                                    )
                                    .ok_or_else(|| {
                                        FrankenError::Internal(format!(
                                            "UPDATE trigger snapshot: unknown column `{column_name}`"
                                        ))
                                    })?;
                                    new_values[target_index] =
                                        eval_join_expr(value_expr, &old_values, &col_map)?;
                                }
                            }
                            _ => {
                                return Err(FrankenError::Internal(
                                    "UPDATE trigger snapshot: column-list assignment requires row-value expression of matching arity".to_owned(),
                                ));
                            }
                        }
                    }
                }
            }

            trigger_rows.push((old_values, new_values));
        }
        Ok(trigger_rows)
    }

    fn collect_delete_trigger_rows(
        &self,
        delete: &fsqlite_ast::DeleteStatement,
        params: Option<&[SqliteValue]>,
    ) -> Result<Vec<Vec<SqliteValue>>> {
        let matched_rows = self.select_matching_rows(
            &delete.table,
            delete.where_clause.as_ref(),
            &[],
            None,
            params,
        )?;
        Ok(matched_rows
            .into_iter()
            .map(|row| row.values().to_vec())
            .collect())
    }

    fn txn_metrics_mark_started(&self) {
        let mut metrics = self.txn_lifecycle_metrics.borrow_mut();
        if metrics.active_started_at.is_none() {
            metrics.active_started_at = Some(Instant::now());
            metrics.active_first_read_at = None;
            metrics.active_first_write_at = None;
            metrics.active_read_ops = 0;
            metrics.active_write_ops = 0;
            metrics.active_savepoint_depth = 0;
            metrics.active_rollbacks = 0;
        }
    }

    fn txn_metrics_note_read(&self) {
        let mut metrics = self.txn_lifecycle_metrics.borrow_mut();
        if metrics.active_started_at.is_some() {
            metrics.active_read_ops = metrics.active_read_ops.saturating_add(1);
            if metrics.active_first_read_at.is_none() {
                metrics.active_first_read_at = Some(Instant::now());
            }
        }
    }

    fn txn_metrics_note_write(&self) {
        let mut metrics = self.txn_lifecycle_metrics.borrow_mut();
        if metrics.active_started_at.is_some() {
            metrics.active_write_ops = metrics.active_write_ops.saturating_add(1);
            if metrics.active_first_write_at.is_none() {
                metrics.active_first_write_at = Some(Instant::now());
            }
        }
    }

    fn txn_metrics_set_savepoint_depth(&self, depth: usize) {
        let mut metrics = self.txn_lifecycle_metrics.borrow_mut();
        if metrics.active_started_at.is_some() {
            metrics.active_savepoint_depth = u64::try_from(depth).unwrap_or(u64::MAX);
        }
    }

    fn txn_metrics_note_rollback(&self) {
        let mut metrics = self.txn_lifecycle_metrics.borrow_mut();
        metrics.rollback_count_total = metrics.rollback_count_total.saturating_add(1);
        if metrics.active_started_at.is_some() {
            metrics.active_rollbacks = metrics.active_rollbacks.saturating_add(1);
        }
    }

    fn txn_metrics_mark_finished(&self) {
        let mut metrics = self.txn_lifecycle_metrics.borrow_mut();
        let Some(started_at) = metrics.active_started_at.take() else {
            return;
        };

        let elapsed_ms_u128 = started_at.elapsed().as_millis();
        let elapsed_ms = u64::try_from(elapsed_ms_u128).unwrap_or(u64::MAX);
        metrics.completed_count = metrics.completed_count.saturating_add(1);
        metrics.completed_duration_ms_total = metrics
            .completed_duration_ms_total
            .saturating_add(elapsed_ms_u128);
        metrics.max_snapshot_age_ms = metrics.max_snapshot_age_ms.max(elapsed_ms);
        if elapsed_ms >= metrics.long_txn_threshold_ms {
            metrics.long_running_count = metrics.long_running_count.saturating_add(1);
        }
        metrics.active_first_read_at = None;
        metrics.active_first_write_at = None;
        metrics.active_read_ops = 0;
        metrics.active_write_ops = 0;
        metrics.active_savepoint_depth = 0;
        metrics.active_rollbacks = 0;
    }

    fn txn_metrics_rows(&self) -> Vec<Row> {
        let to_i64 = |value: u64| i64::try_from(value).unwrap_or(i64::MAX);
        let metrics = self.txn_lifecycle_metrics.borrow();
        let active_count = u64::from(metrics.active_started_at.is_some());
        let avg_duration_ms_u128 = if metrics.completed_count == 0 {
            0
        } else {
            metrics.completed_duration_ms_total / u128::from(metrics.completed_count)
        };
        let avg_duration_ms = u64::try_from(avg_duration_ms_u128).unwrap_or(u64::MAX);
        let snapshot_age_ms = metrics.current_snapshot_age_ms();
        let max_snapshot_age_ms = metrics.max_snapshot_age_ms.max(snapshot_age_ms);
        let first_read_ms = metrics.current_first_read_ms();
        let first_write_ms = metrics.current_first_write_ms();
        let active_long_running = u64::from(
            metrics.active_started_at.is_some() && snapshot_age_ms >= metrics.long_txn_threshold_ms,
        );
        let long_running_count = metrics
            .long_running_count
            .saturating_add(active_long_running);
        let entries = [
            ("active_count", active_count),
            ("avg_duration_ms", avg_duration_ms),
            ("long_running_count", long_running_count),
            ("max_snapshot_age_ms", max_snapshot_age_ms),
            ("first_read_ms", first_read_ms),
            ("first_write_ms", first_write_ms),
            ("read_ops", metrics.active_read_ops),
            ("write_ops", metrics.active_write_ops),
            ("savepoint_depth", metrics.active_savepoint_depth),
            ("rollback_count_active", metrics.active_rollbacks),
            ("rollback_count_total", metrics.rollback_count_total),
            ("long_txn_threshold_ms", metrics.long_txn_threshold_ms),
            (
                "advisor_large_read_ops_threshold",
                metrics.advisor_large_read_ops_threshold,
            ),
            (
                "advisor_savepoint_depth_threshold",
                metrics.advisor_savepoint_depth_threshold,
            ),
            (
                "advisor_rollback_ratio_percent",
                metrics.advisor_rollback_ratio_percent,
            ),
            ("completed_count", metrics.completed_count),
        ];
        entries
            .into_iter()
            .map(|(name, value)| Row {
                values: vec![
                    SqliteValue::Text(name.into()),
                    SqliteValue::Integer(to_i64(value)),
                ],
            })
            .collect()
    }

    fn txn_live_rows(&self) -> Vec<Row> {
        let to_i64 = |value: u64| i64::try_from(value).unwrap_or(i64::MAX);
        let (active_duration_ms, active_read_ops, active_write_ops) = {
            let metrics = self.txn_lifecycle_metrics.borrow();
            (
                metrics.current_snapshot_age_ms(),
                metrics.active_read_ops,
                metrics.active_write_ops,
            )
        };

        let session_id = *self.concurrent_session_id.borrow();
        if let Some(session_id) = session_id {
            let registry = lock_unpoisoned(&self.concurrent_registry);
            if let Some(handle) = registry.get(session_id) {
                let pages_read = u64::try_from(handle.read_set().len()).unwrap_or(u64::MAX);
                let pages_written =
                    u64::try_from(handle.write_set_pages().len()).unwrap_or(u64::MAX);
                return vec![Row {
                    values: vec![
                        SqliteValue::Integer(i64::try_from(session_id).unwrap_or(i64::MAX)),
                        SqliteValue::Integer(to_i64(active_duration_ms)),
                        SqliteValue::Integer(to_i64(pages_read)),
                        SqliteValue::Integer(to_i64(pages_written)),
                        SqliteValue::Integer(to_i64(active_duration_ms)),
                    ],
                }];
            }
        }

        if self.active_txn.borrow().is_some() {
            return vec![Row {
                values: vec![
                    SqliteValue::Integer(0),
                    SqliteValue::Integer(to_i64(active_duration_ms)),
                    SqliteValue::Integer(to_i64(active_read_ops)),
                    SqliteValue::Integer(to_i64(active_write_ops)),
                    SqliteValue::Integer(to_i64(active_duration_ms)),
                ],
            }];
        }

        Vec::new()
    }

    fn txn_metrics_set_long_threshold_ms(&self, threshold_ms: u64) -> u64 {
        let mut metrics = self.txn_lifecycle_metrics.borrow_mut();
        metrics.long_txn_threshold_ms = threshold_ms.max(1);
        metrics.long_txn_threshold_ms
    }

    fn txn_metrics_long_threshold_ms(&self) -> u64 {
        self.txn_lifecycle_metrics.borrow().long_txn_threshold_ms
    }

    fn txn_metrics_set_large_read_ops_threshold(&self, threshold: u64) -> u64 {
        let mut metrics = self.txn_lifecycle_metrics.borrow_mut();
        metrics.advisor_large_read_ops_threshold = threshold.max(1);
        metrics.advisor_large_read_ops_threshold
    }

    fn txn_metrics_large_read_ops_threshold(&self) -> u64 {
        self.txn_lifecycle_metrics
            .borrow()
            .advisor_large_read_ops_threshold
    }

    fn txn_metrics_set_savepoint_depth_threshold(&self, threshold: u64) -> u64 {
        let mut metrics = self.txn_lifecycle_metrics.borrow_mut();
        metrics.advisor_savepoint_depth_threshold = threshold.max(1);
        metrics.advisor_savepoint_depth_threshold
    }

    fn txn_metrics_savepoint_depth_threshold(&self) -> u64 {
        self.txn_lifecycle_metrics
            .borrow()
            .advisor_savepoint_depth_threshold
    }

    fn txn_metrics_set_rollback_ratio_percent(&self, threshold: u64) -> u64 {
        let mut metrics = self.txn_lifecycle_metrics.borrow_mut();
        metrics.advisor_rollback_ratio_percent = threshold.clamp(1, 100);
        metrics.advisor_rollback_ratio_percent
    }

    fn txn_metrics_rollback_ratio_percent(&self) -> u64 {
        self.txn_lifecycle_metrics
            .borrow()
            .advisor_rollback_ratio_percent
    }

    fn txn_advisor_rows(&self) -> Vec<Row> {
        let to_i64 = |value: u64| i64::try_from(value).unwrap_or(i64::MAX);
        let metrics = self.txn_lifecycle_metrics.borrow();
        let mut rows = Vec::new();

        let mut push_row =
            |code: &str, severity: &str, message: String, actual: u64, threshold: u64| {
                rows.push(Row {
                    values: vec![
                        SqliteValue::Text(code.into()),
                        SqliteValue::Text(severity.into()),
                        SqliteValue::Text(message.into()),
                        SqliteValue::Integer(to_i64(actual)),
                        SqliteValue::Integer(to_i64(threshold)),
                    ],
                });
            };

        let snapshot_age_ms = metrics.current_snapshot_age_ms();
        if metrics.active_started_at.is_some() && snapshot_age_ms >= metrics.long_txn_threshold_ms {
            push_row(
                "long_txn",
                "warn",
                format!(
                    "transaction has been active for {snapshot_age_ms}ms; consider reducing scope or committing sooner"
                ),
                snapshot_age_ms,
                metrics.long_txn_threshold_ms,
            );
        }

        if metrics.active_started_at.is_some()
            && metrics.active_read_ops >= metrics.advisor_large_read_ops_threshold
        {
            push_row(
                "large_read_set",
                "warn",
                format!(
                    "transaction has read {} pages/ops; consider narrower read scope",
                    metrics.active_read_ops
                ),
                metrics.active_read_ops,
                metrics.advisor_large_read_ops_threshold,
            );
        }

        if metrics.active_started_at.is_some()
            && metrics.active_savepoint_depth >= metrics.advisor_savepoint_depth_threshold
        {
            push_row(
                "deep_savepoint_stack",
                "info",
                format!(
                    "savepoint depth is {}; consider flattening nested savepoints",
                    metrics.active_savepoint_depth
                ),
                metrics.active_savepoint_depth,
                metrics.advisor_savepoint_depth_threshold,
            );
        }

        if metrics.completed_count >= 4 {
            let rollback_ratio_percent = {
                let numerator = u128::from(metrics.rollback_count_total).saturating_mul(100);
                let denominator = u128::from(metrics.completed_count);
                u64::try_from(numerator / denominator).unwrap_or(u64::MAX)
            };
            if rollback_ratio_percent >= metrics.advisor_rollback_ratio_percent {
                push_row(
                    "rollback_pressure",
                    "warn",
                    format!(
                        "rollback ratio is {}%; consider reducing contention/conflicts",
                        rollback_ratio_percent
                    ),
                    rollback_ratio_percent,
                    metrics.advisor_rollback_ratio_percent,
                );
            }
        }

        rows
    }

    fn txn_timeline_json_rows(&self) -> Vec<Row> {
        let metrics = self.txn_lifecycle_metrics.borrow();
        let active = metrics.active_started_at.is_some();
        let snapshot_age_ms = metrics.current_snapshot_age_ms();
        let first_read_ms = metrics.current_first_read_ms();
        let first_write_ms = metrics.current_first_write_ms();
        let snapshot_age_us = snapshot_age_ms.saturating_mul(1_000);
        let first_read_us = first_read_ms.saturating_mul(1_000);
        let first_write_us = first_write_ms.saturating_mul(1_000);

        let mut trace_events = vec![json!({
            "name": "txn_lifecycle",
            "cat": "transaction",
            "ph": "B",
            "ts": 0_u64,
            "pid": 1_u64,
            "tid": 1_u64,
            "args": {
                "active": active
            }
        })];

        if first_read_ms > 0 {
            trace_events.push(json!({
                "name": "first_read",
                "cat": "transaction",
                "ph": "i",
                "s": "t",
                "ts": first_read_us,
                "pid": 1_u64,
                "tid": 1_u64,
                "args": {
                    "read_ops": metrics.active_read_ops
                }
            }));
        }

        if first_write_ms > 0 {
            trace_events.push(json!({
                "name": "first_write",
                "cat": "transaction",
                "ph": "i",
                "s": "t",
                "ts": first_write_us,
                "pid": 1_u64,
                "tid": 1_u64,
                "args": {
                    "write_ops": metrics.active_write_ops
                }
            }));
        }

        trace_events.push(json!({
            "name": "txn_counters",
            "cat": "transaction",
            "ph": "C",
            "ts": snapshot_age_us,
            "pid": 1_u64,
            "tid": 1_u64,
            "args": {
                "snapshot_age_ms": snapshot_age_ms,
                "read_ops": metrics.active_read_ops,
                "write_ops": metrics.active_write_ops,
                "savepoint_depth": metrics.active_savepoint_depth,
                "active_rollbacks": metrics.active_rollbacks
            }
        }));

        if !active {
            trace_events.push(json!({
                "name": "txn_lifecycle",
                "cat": "transaction",
                "ph": "E",
                "ts": snapshot_age_us,
                "pid": 1_u64,
                "tid": 1_u64,
                "args": {
                    "completed_count": metrics.completed_count,
                    "rollback_count_total": metrics.rollback_count_total
                }
            }));
        }

        let snapshot = json!({
            "active": active,
            "snapshot_age_ms": snapshot_age_ms,
            "first_read_ms": first_read_ms,
            "first_write_ms": first_write_ms,
            "read_ops": metrics.active_read_ops,
            "write_ops": metrics.active_write_ops,
            "savepoint_depth": metrics.active_savepoint_depth,
            "active_rollbacks": metrics.active_rollbacks,
            "completed_count": metrics.completed_count,
            "rollback_count_total": metrics.rollback_count_total,
            "advisor": {
                "long_txn_threshold_ms": metrics.long_txn_threshold_ms,
                "large_read_ops_threshold": metrics.advisor_large_read_ops_threshold,
                "savepoint_depth_threshold": metrics.advisor_savepoint_depth_threshold,
                "rollback_ratio_percent_threshold": metrics.advisor_rollback_ratio_percent
            },
            // Chrome trace-compatible timeline while preserving existing top-level fields.
            "traceEvents": trace_events
        })
        .to_string();

        vec![Row {
            values: vec![SqliteValue::Text(snapshot.into())],
        }]
    }

    fn checkpoint_schedule_override_mode(&self) -> Option<CheckpointMode> {
        self.checkpoint_advisor_state
            .borrow()
            .schedule_override_mode
    }

    fn active_concurrent_txn_count(&self) -> u64 {
        u64::try_from(lock_unpoisoned(&self.concurrent_registry).active_count()).unwrap_or(u64::MAX)
    }

    fn wal_checkpoint_blocked_by_active_concurrent_txns(&self) -> bool {
        self.active_concurrent_txn_count() > 0
    }

    fn checkpoint_schedule_set_override_mode(
        &self,
        mode: Option<CheckpointMode>,
    ) -> Option<CheckpointMode> {
        let mut state = self.checkpoint_advisor_state.borrow_mut();
        state.schedule_override_mode = mode;
        state.schedule_override_mode
    }

    fn checkpoint_set_urgent_wal_frames_threshold(&self, threshold: u64) -> u64 {
        let mut state = self.checkpoint_advisor_state.borrow_mut();
        state.urgent_wal_frames_threshold = threshold.max(1);
        state.urgent_wal_frames_threshold
    }

    fn checkpoint_urgent_wal_frames_threshold(&self) -> u64 {
        self.checkpoint_advisor_state
            .borrow()
            .urgent_wal_frames_threshold
    }

    fn checkpoint_set_low_activity_txn_threshold(&self, threshold: u64) -> u64 {
        let mut state = self.checkpoint_advisor_state.borrow_mut();
        state.low_activity_txn_threshold = threshold;
        state.low_activity_txn_threshold
    }

    fn checkpoint_low_activity_txn_threshold(&self) -> u64 {
        self.checkpoint_advisor_state
            .borrow()
            .low_activity_txn_threshold
    }

    fn checkpoint_set_write_pressure_frames_per_sec(&self, threshold: u64) -> u64 {
        let mut state = self.checkpoint_advisor_state.borrow_mut();
        state.write_pressure_frames_per_sec = threshold.max(1);
        state.write_pressure_frames_per_sec
    }

    fn checkpoint_write_pressure_frames_per_sec(&self) -> u64 {
        self.checkpoint_advisor_state
            .borrow()
            .write_pressure_frames_per_sec
    }

    fn checkpoint_runtime_snapshot(&self) -> CheckpointRuntimeSnapshot {
        let wal_metrics = fsqlite_wal::GLOBAL_WAL_METRICS.snapshot();
        let local_active_txn_count = u64::from(
            self.txn_lifecycle_metrics
                .borrow()
                .active_started_at
                .is_some(),
        );
        let active_txn_count = self
            .active_concurrent_txn_count()
            .max(local_active_txn_count);
        let wal_autocheckpoint_pages = {
            let raw = self.pragma_state.borrow().wal_autocheckpoint.max(0);
            u64::try_from(raw).unwrap_or(u64::MAX)
        };
        #[allow(clippy::cast_possible_truncation)]
        let wal_frames_estimate = self.pager.wal_frame_count() as u64;

        let now = Instant::now();
        let mut state = self.checkpoint_advisor_state.borrow_mut();
        let write_rate_frames_per_sec = if let Some(previous_sample_at) = state.last_wal_sample_at {
            let elapsed_us = now
                .saturating_duration_since(previous_sample_at)
                .as_micros();
            let elapsed_us_u64 = u64::try_from(elapsed_us).unwrap_or(u64::MAX);
            let delta_frames = wal_metrics
                .frames_written_total
                .saturating_sub(state.last_wal_sample_frames_written_total);
            if elapsed_us_u64 == 0 {
                delta_frames
            } else {
                delta_frames
                    .saturating_mul(1_000_000)
                    .checked_div(elapsed_us_u64)
                    .unwrap_or(0)
            }
        } else {
            0
        };
        state.last_wal_sample_frames_written_total = wal_metrics.frames_written_total;
        state.last_wal_sample_at = Some(now);

        let adaptive_autocheckpoint_target_pages = if wal_autocheckpoint_pages == 0 {
            0
        } else if write_rate_frames_per_sec >= state.write_pressure_frames_per_sec {
            wal_autocheckpoint_pages.saturating_add((wal_autocheckpoint_pages / 2).max(1))
        } else if active_txn_count <= state.low_activity_txn_threshold {
            wal_autocheckpoint_pages
                .saturating_mul(3)
                .checked_div(4)
                .unwrap_or(1)
                .max(1)
        } else {
            wal_autocheckpoint_pages
        };

        let last_checkpoint_throughput_frames_per_sec = if state.last_checkpoint_duration_us == 0 {
            0
        } else {
            state
                .last_checkpoint_frames_backfilled
                .saturating_mul(1_000_000)
                .checked_div(state.last_checkpoint_duration_us)
                .unwrap_or(0)
        };

        let last_checkpoint_age_ms = state.last_checkpoint_at.map_or(0, |at| {
            let elapsed_ms = now.saturating_duration_since(at).as_millis();
            u64::try_from(elapsed_ms).unwrap_or(u64::MAX)
        });

        CheckpointRuntimeSnapshot {
            active_txn_count,
            wal_autocheckpoint_pages,
            adaptive_autocheckpoint_target_pages,
            wal_frames_estimate,
            frames_written_total: wal_metrics.frames_written_total,
            bytes_written_total: wal_metrics.bytes_written_total,
            write_rate_frames_per_sec,
            checkpoint_count: wal_metrics.checkpoint_count,
            local_checkpoint_count: state.local_checkpoint_count,
            checkpoint_frames_backfilled_total: wal_metrics.checkpoint_frames_backfilled_total,
            checkpoint_avg_duration_us: wal_metrics.avg_checkpoint_duration_us(),
            last_checkpoint_mode: state.last_checkpoint_mode,
            last_checkpoint_total_frames: state.last_checkpoint_total_frames,
            last_checkpoint_frames_backfilled: state.last_checkpoint_frames_backfilled,
            last_checkpoint_duration_us: state.last_checkpoint_duration_us,
            last_checkpoint_throughput_frames_per_sec,
            last_checkpoint_age_ms,
            urgent_wal_frames_threshold: state.urgent_wal_frames_threshold,
            low_activity_txn_threshold: state.low_activity_txn_threshold,
            write_pressure_frames_per_sec: state.write_pressure_frames_per_sec,
        }
    }

