/// Quote a SQL identifier only when necessary (contains special chars,
/// starts with a digit, or is empty).  Matches C SQLite's behavior of
/// storing unquoted identifiers in `sqlite_master.sql`.
pub(crate) fn maybe_quote_ident(name: &str) -> String {
    let needs_quoting = name.is_empty()
        || name.as_bytes()[0].is_ascii_digit()
        || !name.bytes().all(|b| b.is_ascii_alphanumeric() || b == b'_');
    if needs_quoting {
        let escaped = name.replace('"', "\"\"");
        format!("\"{escaped}\"")
    } else {
        name.to_owned()
    }
}

fn render_create_table_sql(table: &TableSchema, is_autoincrement: bool) -> String {
    let is_single_column_primary_key = |column_name: &str| {
        table
            .primary_key_constraints
            .iter()
            .any(|pk| pk.len() == 1 && pk[0].eq_ignore_ascii_case(column_name))
    };
    let primary_key_matches_index = |index: &IndexSchema| {
        table.primary_key_constraints.iter().any(|pk| {
            pk.len() == index.columns.len()
                && pk
                    .iter()
                    .zip(&index.columns)
                    .all(|(lhs, rhs)| lhs.eq_ignore_ascii_case(rhs))
        })
    };
    let mut defs: Vec<String> = table
        .columns
        .iter()
        .map(|col| {
            let mut part = maybe_quote_ident(&col.name);
            if let Some(type_decl) = col.type_name.as_deref() {
                part.push(' ');
                part.push_str(type_decl);
            }
            if col.is_ipk {
                part.push_str(" PRIMARY KEY");
                if is_autoincrement {
                    part.push_str(" AUTOINCREMENT");
                }
            }
            if col.notnull && !col.is_ipk {
                part.push_str(" NOT NULL");
            }
            if col.unique && !col.is_ipk && !is_single_column_primary_key(&col.name) {
                part.push_str(" UNIQUE");
            }
            if let Some(ref default) = col.default_value {
                part.push_str(" DEFAULT ");
                part.push_str(default);
            }
            if let Some(ref collation) = col.collation {
                part.push_str(" COLLATE ");
                part.push_str(collation);
            }
            if let Some(ref gen_expr) = col.generated_expr {
                part.push_str(" GENERATED ALWAYS AS (");
                part.push_str(gen_expr);
                part.push(')');
                if col.generated_stored == Some(true) {
                    part.push_str(" STORED");
                } else {
                    part.push_str(" VIRTUAL");
                }
            }
            part
        })
        .collect();

    // Append table-level UNIQUE constraints for multi-column implicit indexes
    // so the rendered SQL round-trips correctly through sqlite_master.
    for index in &table.indexes {
        if !index.is_unique || index.columns.is_empty() {
            continue;
        }
        if primary_key_matches_index(index) {
            continue;
        }
        // Single-column UNIQUE constraints are already rendered inline above.
        if index.columns.len() == 1
            && table.columns.iter().any(|column| {
                column.unique
                    && !column.is_ipk
                    && column.name.eq_ignore_ascii_case(&index.columns[0])
            })
        {
            continue;
        }
        let cols = index
            .columns
            .iter()
            .map(|name| maybe_quote_ident(name))
            .collect::<Vec<_>>()
            .join(", ");
        defs.push(format!("UNIQUE ({cols})"));
    }
    for pk in &table.primary_key_constraints {
        if pk.len() == 1
            && table
                .columns
                .iter()
                .any(|column| column.is_ipk && column.name.eq_ignore_ascii_case(&pk[0]))
        {
            continue;
        }
        let cols = pk
            .iter()
            .map(|name| maybe_quote_ident(name))
            .collect::<Vec<_>>()
            .join(", ");
        defs.push(format!("PRIMARY KEY ({cols})"));
    }

    let column_defs = defs.join(", ");
    // Append table-level FOREIGN KEY constraints so they survive
    // round-tripping through sqlite_master.
    let mut fk_clauses = String::new();
    for fk in &table.foreign_keys {
        use std::fmt::Write;
        let child_cols: Vec<&str> = fk
            .child_columns
            .iter()
            .filter_map(|&idx| table.columns.get(idx).map(|c| c.name.as_str()))
            .collect();
        if child_cols.is_empty() {
            continue;
        }
        write!(
            fk_clauses,
            ", FOREIGN KEY({}) REFERENCES {}",
            child_cols
                .iter()
                .map(|c| maybe_quote_ident(c))
                .collect::<Vec<_>>()
                .join(", "),
            maybe_quote_ident(&fk.parent_table),
        )
        .ok();
        if !fk.parent_columns.is_empty() {
            write!(
                fk_clauses,
                "({})",
                fk.parent_columns
                    .iter()
                    .map(|c| maybe_quote_ident(c))
                    .collect::<Vec<_>>()
                    .join(", ")
            )
            .ok();
        }
        if fk.on_delete != FkActionType::NoAction {
            write!(fk_clauses, " ON DELETE {}", fk_action_sql(fk.on_delete)).ok();
        }
        if fk.on_update != FkActionType::NoAction {
            write!(fk_clauses, " ON UPDATE {}", fk_action_sql(fk.on_update)).ok();
        }
    }
    // Append table-level CHECK constraints.
    let mut check_clauses = String::new();
    for check_expr in &table.check_constraints {
        use std::fmt::Write;
        write!(check_clauses, ", CHECK({check_expr})").ok();
    }
    let mut table_options = Vec::new();
    if table.without_rowid {
        table_options.push("WITHOUT ROWID");
    }
    if table.strict {
        table_options.push("STRICT");
    }
    let table_options_suffix = if table_options.is_empty() {
        String::new()
    } else {
        format!(" {}", table_options.join(", "))
    };
    format!(
        "CREATE TABLE {}({column_defs}{fk_clauses}{check_clauses}){table_options_suffix}",
        maybe_quote_ident(&table.name)
    )
}

fn fk_action_sql(action: FkActionType) -> &'static str {
    match action {
        FkActionType::NoAction => "NO ACTION",
        FkActionType::Restrict => "RESTRICT",
        FkActionType::SetNull => "SET NULL",
        FkActionType::SetDefault => "SET DEFAULT",
        FkActionType::Cascade => "CASCADE",
    }
}

fn render_create_index_sql(index: &IndexSchema, table_name: &str) -> String {
    let unique = if index.is_unique { "UNIQUE " } else { "" };
    let cols = if index.key_expressions.is_empty() {
        index
            .columns
            .iter()
            .map(|column| quote_identifier(column))
            .collect::<Vec<_>>()
            .join(", ")
    } else {
        index.key_expressions.join(", ")
    };
    let where_clause = index
        .where_clause
        .as_ref()
        .map(|predicate| format!(" WHERE {predicate}"))
        .unwrap_or_default();
    format!(
        "CREATE {unique}INDEX {} ON {}({}){where_clause}",
        quote_identifier(&index.name),
        quote_identifier(table_name),
        cols
    )
}

/// Check whether a `SelectCore` references a named table/CTE in any FROM source.
fn select_core_references_table(core: &SelectCore, table_name: &str) -> bool {
    match core {
        SelectCore::Select {
            from: Some(from), ..
        } => from_clause_references_table(from, table_name),
        SelectCore::Select { from: None, .. } | SelectCore::Values(_) => false,
    }
}

fn from_clause_references_table(from: &fsqlite_ast::FromClause, table_name: &str) -> bool {
    table_or_subquery_references_table(&from.source, table_name)
        || from
            .joins
            .iter()
            .any(|join| table_or_subquery_references_table(&join.table, table_name))
}

fn table_or_subquery_references_table(table: &TableOrSubquery, table_name: &str) -> bool {
    match table {
        TableOrSubquery::Table { name, .. } => name.name.eq_ignore_ascii_case(table_name),
        TableOrSubquery::Subquery { query, .. } => select_references_table(query, table_name),
        TableOrSubquery::ParenJoin(from) => from_clause_references_table(from, table_name),
        TableOrSubquery::TableFunction { .. } => false,
    }
}

fn select_references_table(select: &SelectStatement, table_name: &str) -> bool {
    select_core_references_table(&select.body.select, table_name)
        || select
            .body
            .compounds
            .iter()
            .any(|(_, core)| select_core_references_table(core, table_name))
}

/// Recursively resolve column names for a subquery that uses `SELECT *`.
/// Walks through nested subqueries and schema tables to find the actual
/// column names that will appear in the result set.
fn resolve_subquery_star_columns(select: &SelectStatement, schema: &[TableSchema]) -> Vec<String> {
    let basic = infer_select_column_names(select);
    if !basic.iter().any(|n| n == "*" || n.ends_with(".*")) {
        return basic;
    }
    // Has unresolved stars — try to expand from FROM sources.
    let core = &select.body.select;
    if let SelectCore::Select {
        from: Some(from), ..
    } = core
    {
        let mut result = Vec::new();
        for name in &basic {
            if name == "*" {
                // Expand from all FROM sources.
                match &from.source {
                    TableOrSubquery::Table { name: tbl_name, .. } => {
                        if let Some(tbl) = schema
                            .iter()
                            .find(|t| t.name.eq_ignore_ascii_case(&tbl_name.name))
                        {
                            for col in &tbl.columns {
                                result.push(col.name.clone());
                            }
                        }
                    }
                    TableOrSubquery::Subquery { query, .. } => {
                        let sub_cols = resolve_subquery_star_columns(query, schema);
                        result.extend(sub_cols);
                    }
                    TableOrSubquery::TableFunction { name, .. } => {
                        if let Some(cols) = table_function_column_names(name) {
                            result.extend(cols.iter().map(|col| (*col).to_owned()));
                        }
                    }
                    _ => {}
                }
            } else {
                result.push(name.clone());
            }
        }
        if !result.is_empty() && !result.iter().any(|n| n == "*") {
            return result;
        }
    }
    basic
}

/// Infer column names from a SELECT statement's result columns.
fn infer_select_column_names(select: &SelectStatement) -> Vec<String> {
    let core = &select.body.select;
    match core {
        SelectCore::Select { columns, .. } => columns
            .iter()
            .enumerate()
            .map(|(i, col)| match col {
                ResultColumn::Expr {
                    alias: Some(alias), ..
                } => alias.clone(),
                ResultColumn::Expr { expr, .. } => match expr {
                    Expr::Column(col_ref, _) => col_ref.column.clone(),
                    _ => format!("_c{i}"),
                },
                ResultColumn::Star => "*".to_owned(),
                ResultColumn::TableStar(name) => format!("{name}.*"),
            })
            .collect(),
        SelectCore::Values(rows) => {
            // SQLite names VALUES columns as "column1", "column2", etc.
            let width = rows.first().map_or(0, Vec::len);
            (0..width).map(|i| format!("column{}", i + 1)).collect()
        }
    }
}

/// Resolve CTE/view column names by expanding `*` and `table.*` using the schema.
fn resolve_cte_column_names_with_schema(
    inferred: &[String],
    select: &SelectStatement,
    schema: &[TableSchema],
) -> Vec<String> {
    if !inferred.iter().any(|n| n == "*" || n.ends_with(".*")) {
        return inferred.to_vec();
    }
    let core = &select.body.select;
    let from_tables = extract_from_table_names(core);
    let mut result = Vec::new();
    for name in inferred {
        if name == "*" {
            let mut expanded = false;
            for tbl_name in &from_tables {
                if let Some(tbl_schema) = schema
                    .iter()
                    .find(|t| t.name.eq_ignore_ascii_case(tbl_name))
                {
                    for col in &tbl_schema.columns {
                        result.push(col.name.clone());
                    }
                    expanded = true;
                }
            }
            if !expanded {
                result.push(name.clone());
            }
        } else if let Some(prefix) = name.strip_suffix(".*") {
            if let Some(tbl_schema) = schema.iter().find(|t| t.name.eq_ignore_ascii_case(prefix)) {
                for col in &tbl_schema.columns {
                    result.push(col.name.clone());
                }
            } else {
                result.push(name.clone());
            }
        } else {
            result.push(name.clone());
        }
    }
    result
}

fn extract_from_table_names(core: &SelectCore) -> Vec<String> {
    if let SelectCore::Select {
        from: Some(from), ..
    } = core
    {
        let mut names = Vec::new();
        collect_table_names_from_source(&from.source, &mut names);
        for join in &from.joins {
            collect_table_names_from_source(&join.table, &mut names);
        }
        names
    } else {
        Vec::new()
    }
}

fn collect_table_names_from_source(source: &TableOrSubquery, out: &mut Vec<String>) {
    match source {
        TableOrSubquery::Table { name, .. } => {
            out.push(name.name.clone());
        }
        TableOrSubquery::ParenJoin(from) => {
            collect_table_names_from_source(&from.source, out);
            for join in &from.joins {
                collect_table_names_from_source(&join.table, out);
            }
        }
        TableOrSubquery::Subquery { .. } | TableOrSubquery::TableFunction { .. } => {}
    }
}

fn source_matches_name(source: &TableOrSubquery, target: &str) -> bool {
    match source {
        TableOrSubquery::Table { name, alias, .. } => {
            alias
                .as_ref()
                .is_some_and(|alias| alias.eq_ignore_ascii_case(target))
                || name.name.eq_ignore_ascii_case(target)
        }
        TableOrSubquery::Subquery { alias, .. } | TableOrSubquery::TableFunction { alias, .. } => {
            alias
                .as_ref()
                .is_some_and(|alias| alias.eq_ignore_ascii_case(target))
        }
        TableOrSubquery::ParenJoin(_) => false,
    }
}

// ---------------------------------------------------------------------------
// Subquery rewriting helpers (IN, EXISTS, scalar subqueries)
// ---------------------------------------------------------------------------

/// Walk a `SelectCore` and rewrite subquery expressions found in its
/// result columns, WHERE clause, or HAVING clause.
///
/// When `rewrite_in` is true, also eagerly evaluate `IN (SELECT ...)`
/// into literal lists (needed for interpreted fallback paths).
fn rewrite_in_select_core(
    core: &mut SelectCore,
    conn: &Connection,
    rewrite_in: bool,
    params: Option<&[SqliteValue]>,
) -> Result<()> {
    if let SelectCore::Select {
        columns,
        where_clause,
        having,
        ..
    } = core
    {
        for col in columns.iter_mut() {
            if let ResultColumn::Expr { expr, .. } = col {
                rewrite_in_expr(expr, conn, rewrite_in, params)?;
            }
        }
        if let Some(wh) = where_clause.as_mut() {
            rewrite_in_expr(wh, conn, rewrite_in, params)?;
        }
        if let Some(hv) = having.as_mut() {
            rewrite_in_expr(hv, conn, rewrite_in, params)?;
        }
    }
    Ok(())
}

fn flatten_simple_from_subquery_select(select: &SelectStatement) -> Option<SelectStatement> {
    if select.with.is_some() || !select.body.compounds.is_empty() {
        return None;
    }

    let SelectCore::Select {
        columns: outer_columns,
        from: Some(outer_from),
        where_clause: outer_where,
        group_by,
        having,
        windows,
        ..
    } = &select.body.select
    else {
        return None;
    };

    if !outer_from.joins.is_empty()
        || !group_by.is_empty()
        || having.is_some()
        || !windows.is_empty()
    {
        return None;
    }

    let TableOrSubquery::Subquery {
        query: inner_query,
        alias: outer_alias,
    } = &outer_from.source
    else {
        return None;
    };

    if inner_query.with.is_some()
        || !inner_query.body.compounds.is_empty()
        || !inner_query.order_by.is_empty()
        || inner_query.limit.is_some()
    {
        return None;
    }

    let SelectCore::Select {
        distinct,
        columns: inner_columns,
        from: Some(inner_from),
        where_clause: inner_where,
        group_by: inner_group_by,
        having: inner_having,
        windows: inner_windows,
    } = &inner_query.body.select
    else {
        return None;
    };

    if *distinct != Distinctness::All
        || !inner_from.joins.is_empty()
        || !matches!(inner_from.source, TableOrSubquery::Table { .. })
        || !inner_group_by.is_empty()
        || inner_having.is_some()
        || !inner_windows.is_empty()
    {
        return None;
    }

    let projection_map = build_flatten_projection_map(inner_columns)?;
    let flattened_columns = flatten_outer_result_columns(
        outer_columns,
        inner_columns,
        outer_alias.as_deref(),
        &projection_map,
    )?;
    let flattened_where = flatten_expr_option(
        outer_where.as_deref(),
        outer_alias.as_deref(),
        &projection_map,
    )?;
    let flattened_order_by =
        flatten_order_by_terms(&select.order_by, outer_alias.as_deref(), &projection_map)?;

    let mut flattened = select.clone();
    if let SelectCore::Select {
        columns,
        from,
        where_clause,
        ..
    } = &mut flattened.body.select
    {
        *columns = flattened_columns;
        *from = Some(inner_from.clone());
        *where_clause = combine_where_clauses(inner_where.clone(), flattened_where);
    }
    flattened.order_by = flattened_order_by;
    Some(flattened)
}

#[derive(Debug, Clone, Default)]
struct FlattenProjectionMap {
    passthrough_columns: bool,
    columns: HashMap<String, Expr>,
}

fn build_flatten_projection_map(columns: &[ResultColumn]) -> Option<FlattenProjectionMap> {
    let mut projection = FlattenProjectionMap::default();

    for column in columns {
        match column {
            ResultColumn::Star | ResultColumn::TableStar(_) => {
                projection.passthrough_columns = true;
            }
            ResultColumn::Expr {
                expr: Expr::Column(column_ref, span),
                alias,
            } => {
                let exposed_name = alias
                    .clone()
                    .unwrap_or_else(|| column_ref.column.clone())
                    .to_ascii_lowercase();
                if projection.columns.contains_key(&exposed_name) {
                    return None;
                }
                projection
                    .columns
                    .insert(exposed_name, Expr::Column(column_ref.clone(), *span));
            }
            ResultColumn::Expr { .. } => return None,
        }
    }

    Some(projection)
}

fn flatten_outer_result_columns(
    outer_columns: &[ResultColumn],
    inner_columns: &[ResultColumn],
    outer_alias: Option<&str>,
    projection_map: &FlattenProjectionMap,
) -> Option<Vec<ResultColumn>> {
    let mut flattened = Vec::new();

    for column in outer_columns {
        match column {
            ResultColumn::Star => flattened.extend(inner_columns.iter().cloned()),
            ResultColumn::TableStar(qualifier) => {
                if !outer_alias.is_some_and(|alias| qualifier.eq_ignore_ascii_case(alias)) {
                    return None;
                }
                flattened.extend(inner_columns.iter().cloned());
            }
            ResultColumn::Expr {
                expr: Expr::Column(column_ref, _),
                alias,
            } => {
                let rewritten_expr =
                    flatten_expr(column, outer_alias, projection_map).and_then(|rewritten| {
                        match rewritten {
                            ResultColumn::Expr { expr, .. } => Some(expr),
                            ResultColumn::Star | ResultColumn::TableStar(_) => None,
                        }
                    })?;
                flattened.push(ResultColumn::Expr {
                    expr: rewritten_expr,
                    alias: alias.clone().or_else(|| Some(column_ref.column.clone())),
                });
            }
            ResultColumn::Expr { .. } => return None,
        }
    }

    Some(flattened)
}

#[allow(clippy::option_option)]
fn flatten_expr_option(
    expr: Option<&Expr>,
    outer_alias: Option<&str>,
    projection_map: &FlattenProjectionMap,
) -> Option<Option<Box<Expr>>> {
    match expr {
        Some(inner) => flatten_expr_tree(inner, outer_alias, projection_map)
            .map(Box::new)
            .map(Some),
        None => Some(None),
    }
}

fn flatten_order_by_terms(
    order_by: &[OrderingTerm],
    outer_alias: Option<&str>,
    projection_map: &FlattenProjectionMap,
) -> Option<Vec<OrderingTerm>> {
    order_by
        .iter()
        .map(|term| {
            Some(OrderingTerm {
                expr: flatten_expr_tree(&term.expr, outer_alias, projection_map)?,
                direction: term.direction,
                nulls: term.nulls,
            })
        })
        .collect()
}

fn flatten_expr(
    column: &ResultColumn,
    outer_alias: Option<&str>,
    projection_map: &FlattenProjectionMap,
) -> Option<ResultColumn> {
    let ResultColumn::Expr { expr, alias } = column else {
        return None;
    };
    Some(ResultColumn::Expr {
        expr: flatten_expr_tree(expr, outer_alias, projection_map)?,
        alias: alias.clone(),
    })
}

fn flatten_expr_tree(
    expr: &Expr,
    outer_alias: Option<&str>,
    projection_map: &FlattenProjectionMap,
) -> Option<Expr> {
    match expr {
        Expr::Literal(_, _)
        | Expr::Subquery(_, _)
        | Expr::Placeholder(_, _)
        | Expr::Raise { .. } => Some(expr.clone()),
        Expr::Column(column_ref, span) => {
            flatten_column_ref(column_ref, *span, outer_alias, projection_map)
        }
        Expr::BinaryOp {
            left,
            op,
            right,
            span,
        } => Some(Expr::BinaryOp {
            left: Box::new(flatten_expr_tree(left, outer_alias, projection_map)?),
            op: *op,
            right: Box::new(flatten_expr_tree(right, outer_alias, projection_map)?),
            span: *span,
        }),
        Expr::UnaryOp {
            op,
            expr: inner,
            span,
        } => Some(Expr::UnaryOp {
            op: *op,
            expr: Box::new(flatten_expr_tree(inner, outer_alias, projection_map)?),
            span: *span,
        }),
        Expr::Between {
            expr: inner,
            low,
            high,
            not,
            span,
        } => Some(Expr::Between {
            expr: Box::new(flatten_expr_tree(inner, outer_alias, projection_map)?),
            low: Box::new(flatten_expr_tree(low, outer_alias, projection_map)?),
            high: Box::new(flatten_expr_tree(high, outer_alias, projection_map)?),
            not: *not,
            span: *span,
        }),
        Expr::In {
            expr: inner,
            set,
            not,
            span,
        } => {
            let rewritten_set = match set {
                InSet::List(items) => InSet::List(
                    items
                        .iter()
                        .map(|item| flatten_expr_tree(item, outer_alias, projection_map))
                        .collect::<Option<Vec<_>>>()?,
                ),
                _ => set.clone(),
            };
            Some(Expr::In {
                expr: Box::new(flatten_expr_tree(inner, outer_alias, projection_map)?),
                set: rewritten_set,
                not: *not,
                span: *span,
            })
        }
        Expr::Like {
            expr: inner,
            pattern,
            escape,
            op,
            not,
            span,
        } => Some(Expr::Like {
            expr: Box::new(flatten_expr_tree(inner, outer_alias, projection_map)?),
            pattern: Box::new(flatten_expr_tree(pattern, outer_alias, projection_map)?),
            escape: flatten_expr_option(escape.as_deref(), outer_alias, projection_map)?,
            op: *op,
            not: *not,
            span: *span,
        }),
        Expr::Case {
            operand,
            whens,
            else_expr,
            span,
        } => Some(Expr::Case {
            operand: flatten_expr_option(operand.as_deref(), outer_alias, projection_map)?,
            whens: whens
                .iter()
                .map(|(when_expr, then_expr)| {
                    Some((
                        flatten_expr_tree(when_expr, outer_alias, projection_map)?,
                        flatten_expr_tree(then_expr, outer_alias, projection_map)?,
                    ))
                })
                .collect::<Option<Vec<_>>>()?,
            else_expr: flatten_expr_option(else_expr.as_deref(), outer_alias, projection_map)?,
            span: *span,
        }),
        Expr::Cast {
            expr: inner,
            type_name,
            span,
        } => Some(Expr::Cast {
            expr: Box::new(flatten_expr_tree(inner, outer_alias, projection_map)?),
            type_name: type_name.clone(),
            span: *span,
        }),
        Expr::Exists {
            subquery,
            not,
            span,
        } => Some(Expr::Exists {
            subquery: subquery.clone(),
            not: *not,
            span: *span,
        }),
        Expr::FunctionCall {
            name,
            args,
            distinct,
            order_by,
            filter,
            over,
            span,
        } => {
            let rewritten_args = match args {
                FunctionArgs::Star => FunctionArgs::Star,
                FunctionArgs::List(exprs) => FunctionArgs::List(
                    exprs
                        .iter()
                        .map(|inner| flatten_expr_tree(inner, outer_alias, projection_map))
                        .collect::<Option<Vec<_>>>()?,
                ),
            };
            Some(Expr::FunctionCall {
                name: name.clone(),
                args: rewritten_args,
                distinct: *distinct,
                order_by: flatten_order_by_terms(order_by, outer_alias, projection_map)?,
                filter: flatten_expr_option(filter.as_deref(), outer_alias, projection_map)?,
                over: over.clone(),
                span: *span,
            })
        }
        Expr::Collate {
            expr: inner,
            collation,
            span,
        } => Some(Expr::Collate {
            expr: Box::new(flatten_expr_tree(inner, outer_alias, projection_map)?),
            collation: collation.clone(),
            span: *span,
        }),
        Expr::IsNull {
            expr: inner,
            not,
            span,
        } => Some(Expr::IsNull {
            expr: Box::new(flatten_expr_tree(inner, outer_alias, projection_map)?),
            not: *not,
            span: *span,
        }),
        Expr::JsonAccess {
            expr: inner,
            path,
            arrow,
            span,
        } => Some(Expr::JsonAccess {
            expr: Box::new(flatten_expr_tree(inner, outer_alias, projection_map)?),
            path: Box::new(flatten_expr_tree(path, outer_alias, projection_map)?),
            arrow: *arrow,
            span: *span,
        }),
        Expr::RowValue(values, span) => Some(Expr::RowValue(
            values
                .iter()
                .map(|value| flatten_expr_tree(value, outer_alias, projection_map))
                .collect::<Option<Vec<_>>>()?,
            *span,
        )),
    }
}

fn flatten_column_ref(
    column_ref: &ColumnRef,
    span: Span,
    outer_alias: Option<&str>,
    projection_map: &FlattenProjectionMap,
) -> Option<Expr> {
    let exposed_name = column_ref.column.to_ascii_lowercase();
    let explicitly_qualified = column_ref
        .table
        .as_ref()
        .is_some_and(|table| outer_alias.is_some_and(|alias| table.eq_ignore_ascii_case(alias)));

    if explicitly_qualified || column_ref.table.is_none() {
        if let Some(mapped) = projection_map.columns.get(&exposed_name) {
            return Some(mapped.clone());
        }
        if projection_map.passthrough_columns {
            return Some(Expr::Column(
                ColumnRef::bare(column_ref.column.clone()),
                span,
            ));
        }
        if explicitly_qualified {
            return None;
        }
    }

    Some(Expr::Column(column_ref.clone(), span))
}

fn combine_where_clauses(
    inner_where: Option<Box<Expr>>,
    outer_where: Option<Box<Expr>>,
) -> Option<Box<Expr>> {
    match (inner_where, outer_where) {
        (Some(inner), Some(outer)) => {
            let span = inner.span().merge(outer.span());
            Some(Box::new(Expr::BinaryOp {
                left: inner,
                op: BinaryOp::And,
                right: outer,
                span,
            }))
        }
        (Some(inner), None) => Some(inner),
        (None, Some(outer)) => Some(outer),
        (None, None) => None,
    }
}

/// Returns true when statement-level subquery rewrite can mutate this statement.
///
/// This intentionally tracks only expression positions visited by
/// `rewrite_subquery_statement` / `rewrite_in_select_core` with
/// `rewrite_in_subqueries = false`.
fn statement_contains_rewritable_subquery(statement: &Statement) -> bool {
    match statement {
        Statement::Select(select) => select_contains_rewritable_subquery(select),
        Statement::Update(update) => {
            update
                .assignments
                .iter()
                .any(|assignment| expr_contains_rewritable_subquery(&assignment.value))
                || update
                    .where_clause
                    .as_ref()
                    .is_some_and(expr_contains_rewritable_subquery)
        }
        Statement::Delete(delete) => delete
            .where_clause
            .as_ref()
            .is_some_and(expr_contains_rewritable_subquery),
        _ => false,
    }
}

/// Returns true when SELECT rewrite-covered expression sites contain
/// EXISTS/scalar-subquery forms that `rewrite_in_expr(..., false, ...)` mutates.
fn select_contains_rewritable_subquery(select: &SelectStatement) -> bool {
    select_core_contains_rewritable_subquery(&select.body.select)
        || select
            .body
            .compounds
            .iter()
            .any(|(_, core)| select_core_contains_rewritable_subquery(core))
}

fn select_core_contains_rewritable_subquery(core: &SelectCore) -> bool {
    match core {
        SelectCore::Select {
            columns,
            where_clause,
            having,
            ..
        } => {
            columns.iter().any(|column| match column {
                ResultColumn::Expr { expr, .. } => expr_contains_rewritable_subquery(expr),
                ResultColumn::Star | ResultColumn::TableStar(_) => false,
            }) || where_clause
                .as_ref()
                .is_some_and(|expr| expr_contains_rewritable_subquery(expr))
                || having
                    .as_ref()
                    .is_some_and(|expr| expr_contains_rewritable_subquery(expr))
        }
        SelectCore::Values(_) => false,
    }
}

/// Check if an IN subquery uses features that VDBE codegen cannot handle
/// in IN-probe expressions (GROUP BY, HAVING, windows, compounds, WITH).
/// These need eager evaluation or VDBE will emit NULL.
fn in_subquery_needs_eager_eval(sub: &SelectStatement) -> bool {
    // VDBE rejects compounds and WITH in resolve_in_probe_source
    if sub.with.is_some() || !sub.body.compounds.is_empty() {
        return true;
    }
    // VDBE rejects GROUP BY / HAVING / windows in both probe paths
    matches!(
        &sub.body.select,
        SelectCore::Select {
            group_by, having, windows, ..
        } if !group_by.is_empty()
            || having.is_some()
            || !windows.is_empty()
    )
}

/// Check whether the subquery's FROM clause references an unmaterialized view.
/// VDBE codegen cannot resolve views in IN-probe paths (it only looks in the
/// materialized table schema), so such subqueries must be eagerly evaluated at
/// the connection level where views can be materialized.
fn in_subquery_references_view(sub: &SelectStatement, conn: &Connection) -> bool {
    let views = conn.views.borrow();
    if views.is_empty() {
        return false;
    }
    let schema = conn.schema.borrow();
    let is_view = |name: &str| -> bool {
        views.iter().any(|v| v.name.eq_ignore_ascii_case(name))
            && !schema.iter().any(|t| t.name.eq_ignore_ascii_case(name))
    };
    if let SelectCore::Select {
        from: Some(ref from),
        ..
    } = sub.body.select
    {
        if let TableOrSubquery::Table { ref name, .. } = from.source {
            if is_view(&name.name) {
                return true;
            }
        }
        for join in &from.joins {
            if let TableOrSubquery::Table { ref name, .. } = join.table {
                if is_view(&name.name) {
                    return true;
                }
            }
        }
    }
    false
}

/// Recursively detect expression forms that the non-IN rewrite pass mutates.
fn expr_contains_rewritable_subquery(expr: &Expr) -> bool {
    match expr {
        Expr::Exists { .. } | Expr::Subquery(_, _) => true,
        Expr::BinaryOp { left, right, .. } => {
            expr_contains_rewritable_subquery(left) || expr_contains_rewritable_subquery(right)
        }
        Expr::UnaryOp { expr, .. } | Expr::IsNull { expr, .. } | Expr::Cast { expr, .. } => {
            expr_contains_rewritable_subquery(expr)
        }
        Expr::Between {
            expr, low, high, ..
        } => {
            expr_contains_rewritable_subquery(expr)
                || expr_contains_rewritable_subquery(low)
                || expr_contains_rewritable_subquery(high)
        }
        Expr::In { expr, set, .. } => {
            // Multi-column IN (RowValue operand) needs rewriting into
            // OR-chains because VDBE codegen cannot handle tuple comparison.
            matches!(expr.as_ref(), Expr::RowValue(..))
                || expr_contains_rewritable_subquery(expr)
                || match set {
                    InSet::List(exprs) => exprs.iter().any(expr_contains_rewritable_subquery),
                    // Always mark IN subqueries as rewritable so the rewrite
                    // pass can inspect them.  The actual eager-eval decision
                    // is made inside `rewrite_in_expr` which checks for GROUP
                    // BY / HAVING / windows / views / etc.  Without this,
                    // IN subqueries referencing views are never reached by
                    // the rewrite pass and VDBE codegen silently emits NULL.
                    InSet::Subquery(_) => true,
                    InSet::Table(_) => false,
                }
        }
        Expr::Case {
            operand,
            whens,
            else_expr,
            ..
        } => {
            operand
                .as_ref()
                .is_some_and(|expr| expr_contains_rewritable_subquery(expr))
                || whens.iter().any(|(when_expr, then_expr)| {
                    expr_contains_rewritable_subquery(when_expr)
                        || expr_contains_rewritable_subquery(then_expr)
                })
                || else_expr
                    .as_ref()
                    .is_some_and(|expr| expr_contains_rewritable_subquery(expr))
        }
        Expr::FunctionCall {
            args: FunctionArgs::List(exprs),
            ..
        } => exprs.iter().any(expr_contains_rewritable_subquery),
        Expr::Like { expr, pattern, .. } => {
            expr_contains_rewritable_subquery(expr) || expr_contains_rewritable_subquery(pattern)
        }
        Expr::Literal(_, _)
        | Expr::Column(_, _)
        | Expr::FunctionCall {
            args: FunctionArgs::Star,
            ..
        }
        | Expr::Placeholder(_, _)
        | Expr::Raise { .. }
        | Expr::Collate { .. }
        | Expr::JsonAccess { .. }
        | Expr::RowValue(_, _) => false,
    }
}

struct SharedRuntimeState {
    key: SharedMvccKey,
    regions: RegionTree,
    db_root_region: Region,
    write_coordinator_region: Region,
    write_coordinator_service_starting: bool,
    write_coordinator_service_running: bool,
    #[cfg_attr(target_arch = "wasm32", allow(dead_code))]
    write_coordinator_service_generation: u64,
    #[cfg_attr(target_arch = "wasm32", allow(dead_code))]
    write_coordinator_service_launch_count: u64,
    write_coordinator_shutdown: Option<WriteCoordinatorShutdownTx>,
    open_connections: usize,
    poisoned: Option<String>,
}

#[cfg(not(target_arch = "wasm32"))]
struct WriteCoordinatorServiceStart {
    generation: u64,
    path_key: String,
}

#[cfg(not(target_arch = "wasm32"))]
enum WriteCoordinatorServiceReservation {
    Running,
    Starting,
    Reserved(WriteCoordinatorServiceStart),
}

#[derive(Debug, Clone, PartialEq, Eq, Hash)]
struct SharedMvccKey {
    path_key: String,
    runtime_id: u64,
}

impl SharedMvccKey {
    fn new(path_key: String, runtime: &RuntimeContext) -> Self {
        Self {
            path_key,
            runtime_id: runtime.runtime_id(),
        }
    }
}

struct SharedMvccState {
    registry: Arc<Mutex<ConcurrentRegistry>>,
    conflict_observer: Arc<MetricsObserver>,
    lock_table: Arc<InProcessPageLockTable>,
    commit_index: Arc<CommitIndex>,
    next_commit_seq: Arc<AtomicU64>,
    _runtime: Arc<RuntimeContext>,
    runtime_state: Mutex<SharedRuntimeState>,
    /// Fast-path poison check: single atomic load instead of mutex lock.
    /// Set to `true` when a background worker reports a fatal error.
    /// `background_status()` checks this first and only acquires the
    /// mutex when the flag is set (to read the error details).
    is_poisoned: AtomicBool,
}

impl SharedMvccState {
    fn new(key: SharedMvccKey, runtime: Arc<RuntimeContext>) -> Result<Self> {
        let mut regions = RegionTree::new();
        let db_root_cx = runtime
            .root_cx
            .create_child()
            .with_trace_context(next_trace_id(), 0, 0);
        let db_root_region = regions.create_root(RegionKind::DbRoot, db_root_cx)?;
        let write_coordinator_cx = regions
            .cx(db_root_region)
            .ok_or_else(|| FrankenError::internal("database root region missing Cx"))?
            .create_child()
            .with_trace_context(next_trace_id(), 0, 0);
        let write_coordinator_region = regions.create_child(
            db_root_region,
            RegionKind::WriteCoordinator,
            write_coordinator_cx,
        )?;

        tracing::info!(
            target: "fsqlite::runtime",
            event = "region_created",
            db_path = %key.path_key,
            region_id = db_root_region.get(),
            region_kind = "db_root"
        );
        tracing::info!(
            target: "fsqlite::runtime",
            event = "region_created",
            db_path = %key.path_key,
            region_id = write_coordinator_region.get(),
            region_kind = "write_coordinator"
        );

        let conflict_observer = Arc::new(MetricsObserver::new(1024));
        Ok(Self {
            registry: Arc::new(Mutex::new(ConcurrentRegistry::new())),
            conflict_observer: Arc::clone(&conflict_observer),
            lock_table: Arc::new(InProcessPageLockTable::with_observer(
                conflict_observer as Arc<dyn fsqlite_observability::ConflictObserver>,
            )),
            commit_index: Arc::new(CommitIndex::new()),
            next_commit_seq: Arc::new(AtomicU64::new(1)),
            _runtime: runtime,
            runtime_state: Mutex::new(SharedRuntimeState {
                key,
                regions,
                db_root_region,
                write_coordinator_region,
                write_coordinator_service_starting: false,
                write_coordinator_service_running: false,
                write_coordinator_service_generation: 0,
                write_coordinator_service_launch_count: 0,
                write_coordinator_shutdown: None,
                open_connections: 0,
                poisoned: None,
            }),
            is_poisoned: AtomicBool::new(false),
        })
    }

    fn background_status(&self) -> Result<()> {
        if hot_path_profile_enabled() {
            FSQLITE_BACKGROUND_STATUS_CHECKS.fetch_add(1, AtomicOrdering::Relaxed);
        }
        // Fast path: single atomic load avoids mutex lock on every statement.
        // is_poisoned is only set when a background worker reports a fatal
        // error — on the normal hot path this is a single cache-line read.
        if !self.is_poisoned.load(AtomicOrdering::Relaxed) {
            return Ok(());
        }
        let state = lock_unpoisoned(&self.runtime_state);
        match &state.poisoned {
            Some(details) => Err(FrankenError::BackgroundWorkerFailed(details.clone())),
            None => Ok(()),
        }
    }

    fn register_connection(&self) -> Result<(Region, Cx)> {
        let mut state = lock_unpoisoned(&self.runtime_state);
        if let Some(details) = &state.poisoned {
            return Err(FrankenError::BackgroundWorkerFailed(details.clone()));
        }

        let db_root_cx = state
            .regions
            .cx(state.db_root_region)
            .ok_or_else(|| FrankenError::internal("database root region missing Cx"))?;
        let db_root_region = state.db_root_region;
        let connection_cx = db_root_cx
            .create_child()
            .with_trace_context(next_trace_id(), 0, 0);
        let connection_region = state.regions.create_child(
            db_root_region,
            RegionKind::PerConnection,
            connection_cx.clone(),
        )?;
        state.open_connections = state.open_connections.saturating_add(1);

        tracing::info!(
            target: "fsqlite::runtime",
            event = "region_created",
            db_path = %state.key.path_key,
            region_id = connection_region.get(),
            region_kind = "per_connection"
        );

        Ok((connection_region, connection_cx))
    }

    #[cfg(not(target_arch = "wasm32"))]
    fn reserve_write_coordinator_service_start(
        &self,
    ) -> Result<WriteCoordinatorServiceReservation> {
        let mut state = lock_unpoisoned(&self.runtime_state);
        if let Some(details) = &state.poisoned {
            return Err(FrankenError::BackgroundWorkerFailed(details.clone()));
        }

        if state.write_coordinator_service_running
            && state.regions.active_tasks(state.write_coordinator_region) == 0
        {
            state.write_coordinator_service_running = false;
            state.write_coordinator_shutdown = None;
        }

        if state.write_coordinator_service_running {
            return Ok(WriteCoordinatorServiceReservation::Running);
        }

        if state.write_coordinator_service_starting {
            return Ok(WriteCoordinatorServiceReservation::Starting);
        }

        state.write_coordinator_service_starting = true;
        state.write_coordinator_service_generation =
            state.write_coordinator_service_generation.saturating_add(1);
        Ok(WriteCoordinatorServiceReservation::Reserved(
            WriteCoordinatorServiceStart {
                generation: state.write_coordinator_service_generation,
                path_key: state.key.path_key.clone(),
            },
        ))
    }

    #[cfg(not(target_arch = "wasm32"))]
    fn revert_write_coordinator_service_start(&self, reservation: &WriteCoordinatorServiceStart) {
        let mut state = lock_unpoisoned(&self.runtime_state);
        if !state.write_coordinator_service_starting
            || state.write_coordinator_service_generation != reservation.generation
        {
            return;
        }

        state.write_coordinator_service_starting = false;
        state.write_coordinator_service_running = false;
        state.write_coordinator_shutdown = None;
    }

    #[cfg(not(target_arch = "wasm32"))]
    fn record_write_coordinator_service_launch(
        &self,
        reservation: &WriteCoordinatorServiceStart,
        shutdown: WriteCoordinatorShutdownTx,
    ) {
        let mut state = lock_unpoisoned(&self.runtime_state);
        if !state.write_coordinator_service_starting
            || state.write_coordinator_service_generation != reservation.generation
        {
            return;
        }

        state.write_coordinator_service_starting = false;
        state.write_coordinator_service_running = true;
        state.write_coordinator_service_launch_count = state
            .write_coordinator_service_launch_count
            .saturating_add(1);
        state.write_coordinator_shutdown = Some(shutdown);
    }

    #[cfg(not(target_arch = "wasm32"))]
    fn ensure_write_coordinator_service_started(&self) -> Result<()> {
        let wait_deadline = Instant::now()
            + if cfg!(test) {
                Duration::from_millis(100)
            } else {
                Duration::from_secs(1)
            };

        let reservation = loop {
            match self.reserve_write_coordinator_service_start()? {
                WriteCoordinatorServiceReservation::Running => return Ok(()),
                WriteCoordinatorServiceReservation::Reserved(start) => break start,
                WriteCoordinatorServiceReservation::Starting => {
                    if Instant::now() >= wait_deadline {
                        return Err(FrankenError::internal(
                            "write coordinator service start timed out while another launcher remained in Starting state",
                        ));
                    }
                    std::hint::spin_loop();
                    #[cfg(not(target_arch = "wasm32"))]
                    std::thread::yield_now();
                    #[cfg(not(target_arch = "wasm32"))]
                    std::thread::sleep(Duration::from_millis(1));
                }
            }
        };

        let (shutdown_tx, mut shutdown_rx) = asupersync::channel::oneshot::channel::<()>();
        let task_path_key = reservation.path_key.clone();
        let launched = match self.try_spawn_write_coordinator_task(move |task_cx| async move {
            let Some(native_task_cx) = task_cx.attached_native_cx() else {
                tracing::error!(
                    target: "fsqlite::runtime",
                    bead_id = WRITE_COORDINATOR_SERVICE_BEAD_ID,
                    event = "write_coordinator_service_missing_native_cx",
                    db_path = %task_path_key
                );
                return;
            };

            tracing::info!(
                target: "fsqlite::runtime",
                bead_id = WRITE_COORDINATOR_SERVICE_BEAD_ID,
                event = "write_coordinator_service_started",
                db_path = %task_path_key
            );

            match shutdown_rx.recv(&native_task_cx).await {
                Ok(())
                | Err(
                    asupersync::channel::oneshot::RecvError::Closed
                    | asupersync::channel::oneshot::RecvError::Cancelled,
                ) => {}
                Err(asupersync::channel::oneshot::RecvError::PolledAfterCompletion) => {
                    tracing::warn!(
                        target: "fsqlite::runtime",
                        bead_id = WRITE_COORDINATOR_SERVICE_BEAD_ID,
                        event = "write_coordinator_service_invalid_recv_state",
                        db_path = %task_path_key
                    );
                }
            }

            let _ = task_cx.checkpoint_with("write coordinator service shutdown");
            tracing::info!(
                target: "fsqlite::runtime",
                bead_id = WRITE_COORDINATOR_SERVICE_BEAD_ID,
                event = "write_coordinator_service_stopped",
                db_path = %task_path_key
            );
        }) {
            Ok(launched) => launched,
            Err(err) => {
                self.revert_write_coordinator_service_start(&reservation);
                return Err(err);
            }
        };

        if launched {
            self.record_write_coordinator_service_launch(&reservation, shutdown_tx);
        } else {
            self.revert_write_coordinator_service_start(&reservation);
            tracing::debug!(
                target: "fsqlite::runtime",
                bead_id = WRITE_COORDINATOR_SERVICE_BEAD_ID,
                event = "write_coordinator_service_deferred",
                db_path = %reservation.path_key
            );
        }

        Ok(())
    }

    #[cfg(target_arch = "wasm32")]
    fn ensure_write_coordinator_service_started(&self) -> Result<()> {
        Ok(())
    }

    #[cfg_attr(not(test), allow(dead_code))]
    fn register_write_coordinator_task(&self) -> Result<(TaskHandle, Cx)> {
        let state = lock_unpoisoned(&self.runtime_state);
        if let Some(details) = &state.poisoned {
            return Err(FrankenError::BackgroundWorkerFailed(details.clone()));
        }

        let region = state.write_coordinator_region;
        let task = state.regions.register_task(region)?;
        let cx = state
            .regions
            .cx(region)
            .ok_or_else(|| FrankenError::internal("write coordinator region missing Cx"))?
            .create_child();
        Ok((task, cx))
    }

    fn try_spawn_write_coordinator_task<F, Fut>(&self, task: F) -> Result<bool>
    where
        F: FnOnce(Cx) -> Fut + Send + 'static,
        Fut: Future<Output = ()> + Send + 'static,
    {
        #[cfg(any(target_arch = "wasm32", not(feature = "native")))]
        {
            let _ = task;
            return Ok(false);
        }

        #[cfg(all(not(target_arch = "wasm32"), feature = "native"))]
        {
            let Some(runtime_handle) = self._runtime.native_runtime_handle() else {
                return Ok(false);
            };
            let (region_task, task_cx) = self.register_write_coordinator_task()?;
            runtime_handle
                .try_spawn(async move {
                    let _region_task = region_task;
                    if let Some(native_task_cx) = asupersync::Cx::current() {
                        task_cx.set_native_cx(native_task_cx);
                    }
                    if task_cx.checkpoint().is_err() {
                        return;
                    }
                    task(task_cx).await;
                })
                .map_err(|err| {
                    FrankenError::internal(format!(
                        "failed to spawn write coordinator task on active asupersync runtime: {err}"
                    ))
                })?;
            Ok(true)
        }
    }

    #[cfg_attr(not(test), allow(dead_code))]
    fn spawn_write_coordinator_task<F, Fut>(&self, task: F) -> Result<()>
    where
        F: FnOnce(Cx) -> Fut + Send + 'static,
        Fut: Future<Output = ()> + Send + 'static,
    {
        if self.try_spawn_write_coordinator_task(task)? {
            return Ok(());
        }

        Err(FrankenError::internal(
            "write coordinator tasks require an active asupersync runtime",
        ))
    }

    fn release_connection(&self, connection_region: Region, best_effort: bool) -> Result<()> {
        let mut state = lock_unpoisoned(&self.runtime_state);

        let connection_close_started = Instant::now();
        tracing::info!(
            target: "fsqlite::runtime",
            event = "region_closing",
            db_path = %state.key.path_key,
            region_id = connection_region.get(),
            active_tasks = state.regions.active_tasks(connection_region)
        );
        if let Err(err) = state.regions.close_and_drain(connection_region) {
            tracing::warn!(
                target: "fsqlite::runtime",
                event = "region_close_failed",
                db_path = %state.key.path_key,
                region_id = connection_region.get(),
                error = %err
            );
            if !best_effort {
                return Err(err);
            }
        }
        state.open_connections = state.open_connections.saturating_sub(1);
        tracing::info!(
            target: "fsqlite::runtime",
            event = "region_closed",
            db_path = %state.key.path_key,
            region_id = connection_region.get(),
            elapsed_ms = u64::try_from(connection_close_started.elapsed().as_millis())
                .unwrap_or(u64::MAX)
        );

        if state.open_connections == 0 {
            state.write_coordinator_service_starting = false;
            state.write_coordinator_service_running = false;
            let _ = state.write_coordinator_shutdown.take();
            let db_root_region = state.db_root_region;
            let root_close_started = Instant::now();
            tracing::info!(
                target: "fsqlite::runtime",
                event = "region_closing",
                db_path = %state.key.path_key,
                region_id = db_root_region.get(),
                active_tasks = state.regions.active_tasks(db_root_region)
            );
            if let Err(err) = state.regions.close_and_drain(db_root_region) {
                tracing::warn!(
                    target: "fsqlite::runtime",
                    event = "region_close_failed",
                    db_path = %state.key.path_key,
                    region_id = db_root_region.get(),
                    error = %err
                );
                if !best_effort {
                    return Err(err);
                }
            }
            tracing::info!(
                target: "fsqlite::runtime",
                event = "region_closed",
                db_path = %state.key.path_key,
                region_id = db_root_region.get(),
                elapsed_ms = u64::try_from(root_close_started.elapsed().as_millis())
                    .unwrap_or(u64::MAX)
            );

            if state.key.path_key != ":memory:" {
                if let Some(state_map) = SHARED_MVCC_STATE_BY_PATH.get() {
                    lock_unpoisoned(state_map).remove(&state.key);
                }
            }
        }

        Ok(())
    }

    #[cfg_attr(not(test), allow(dead_code))]
    fn poison(&self, details: impl Into<String>) {
        let details = details.into();
        let mut state = lock_unpoisoned(&self.runtime_state);
        if state.poisoned.is_some() {
            return;
        }

        state.poisoned = Some(details.clone());
        self.is_poisoned.store(true, AtomicOrdering::Release);
        if let Some(db_root_cx) = state.regions.cx(state.db_root_region) {
            db_root_cx.cancel_with_reason(CancelReason::Abort);
        }
        tracing::error!(
            target: "fsqlite::runtime",
            event = "poisoned",
            db_path = %state.key.path_key,
            cause = %details
        );
    }
}

static SHARED_MVCC_STATE_BY_PATH: OnceLock<Mutex<HashMap<SharedMvccKey, Weak<SharedMvccState>>>> =
    OnceLock::new();

fn lock_unpoisoned<T>(mutex: &Mutex<T>) -> std::sync::MutexGuard<'_, T> {
    mutex
        .lock()
        .unwrap_or_else(std::sync::PoisonError::into_inner)
}

fn mvcc_state_path_key(path: &str) -> String {
    if path == ":memory:" {
        return path.to_owned();
    }
    std::fs::canonicalize(path)
        .unwrap_or_else(|_| PathBuf::from(path))
        .to_string_lossy()
        .into_owned()
}

fn mvcc_state_key(path: &str, runtime: &RuntimeContext) -> SharedMvccKey {
    SharedMvccKey::new(mvcc_state_path_key(path), runtime)
}

fn shared_mvcc_state_for_path(
    path: &str,
    runtime: Arc<RuntimeContext>,
) -> Result<Arc<SharedMvccState>> {
    if path == ":memory:" {
        return Ok(Arc::new(SharedMvccState::new(
            SharedMvccKey::new(path.to_owned(), &runtime),
            runtime,
        )?));
    }

    let key = mvcc_state_key(path, &runtime);
    let state_map = SHARED_MVCC_STATE_BY_PATH.get_or_init(|| Mutex::new(HashMap::new()));
    let mut map = lock_unpoisoned(state_map);

    if let Some(existing) = map.get(&key).and_then(Weak::upgrade) {
        return Ok(existing);
    }

    let state = Arc::new(SharedMvccState::new(key.clone(), runtime)?);
    map.insert(key, Arc::downgrade(&state));
    Ok(state)
}

/// Recursively walk an expression tree and eagerly evaluate subquery
/// expressions: `EXISTS (SELECT ...)` and scalar `(SELECT ...)`.
/// Check whether a SELECT subquery is correlated — i.e., its WHERE clause
/// references column names qualified with a table that is NOT the subquery's
/// own FROM table.  Correlated subqueries must be evaluated per-row rather
/// than eagerly before the scan.
fn is_correlated_subquery(subquery: &SelectStatement) -> bool {
    let inner_table = match &subquery.body.select {
        SelectCore::Select { from, .. } => from.as_ref().and_then(|f| match &f.source {
            fsqlite_ast::TableOrSubquery::Table { name, alias, .. } => {
                // When the subquery uses an alias (`FROM t AS a`), column refs
                // inside the subquery use the alias, not the real table name.
                Some(alias.as_ref().unwrap_or(&name.name).clone())
            }
            _ => None,
        }),
        _ => None,
    };
    let where_clause = match &subquery.body.select {
        SelectCore::Select { where_clause, .. } => where_clause.as_deref(),
        _ => None,
    };
    if let Some(wh) = where_clause {
        return expr_has_external_column_ref(wh, inner_table.as_deref());
    }
    false
}

/// Return true if `expr` contains any qualified column reference whose table
/// qualifier does NOT match `inner_table` (case-insensitive).
fn expr_has_external_column_ref(expr: &Expr, inner_table: Option<&str>) -> bool {
    match expr {
        Expr::Column(col_ref, _) => {
            if let Some(qualifier) = &col_ref.table {
                if let Some(inner) = inner_table {
                    return !qualifier.eq_ignore_ascii_case(inner);
                }
                // No inner table → any qualified ref is external.
                return true;
            }
            false
        }
        Expr::BinaryOp { left, right, .. } => {
            expr_has_external_column_ref(left, inner_table)
                || expr_has_external_column_ref(right, inner_table)
        }
        Expr::UnaryOp { expr: inner, .. }
        | Expr::IsNull { expr: inner, .. }
        | Expr::Cast { expr: inner, .. }
        | Expr::Collate { expr: inner, .. } => expr_has_external_column_ref(inner, inner_table),
        Expr::Between {
            expr: inner,
            low,
            high,
            ..
        } => {
            expr_has_external_column_ref(inner, inner_table)
                || expr_has_external_column_ref(low, inner_table)
                || expr_has_external_column_ref(high, inner_table)
        }
        Expr::In {
            expr: inner, set, ..
        } => {
            expr_has_external_column_ref(inner, inner_table)
                || matches!(set, InSet::List(items) if items.iter().any(|e| expr_has_external_column_ref(e, inner_table)))
        }
        Expr::FunctionCall { args, .. } => {
            matches!(args, FunctionArgs::List(items) if items.iter().any(|e| expr_has_external_column_ref(e, inner_table)))
        }
        Expr::Case {
            operand,
            whens,
            else_expr,
            ..
        } => {
            operand
                .as_ref()
                .is_some_and(|o| expr_has_external_column_ref(o, inner_table))
                || whens.iter().any(|(c, t)| {
                    expr_has_external_column_ref(c, inner_table)
                        || expr_has_external_column_ref(t, inner_table)
                })
                || else_expr
                    .as_ref()
                    .is_some_and(|e| expr_has_external_column_ref(e, inner_table))
        }
        Expr::Like {
            expr: inner,
            pattern,
            escape,
            ..
        } => {
            expr_has_external_column_ref(inner, inner_table)
                || expr_has_external_column_ref(pattern, inner_table)
                || escape
                    .as_ref()
                    .is_some_and(|e| expr_has_external_column_ref(e, inner_table))
        }
        Expr::Exists { subquery, .. } | Expr::Subquery(subquery, _) => {
            let nested_where = match &subquery.body.select {
                SelectCore::Select { where_clause, .. } => where_clause.as_deref(),
                _ => None,
            };
            nested_where.is_some_and(|wh| expr_has_external_column_ref(wh, inner_table))
        }
        _ => false,
    }
}

/// Collect all table names and aliases from a subquery's FROM clause
/// (including JOINed tables).
fn collect_subquery_inner_tables(sub: &SelectStatement) -> Vec<String> {
    let mut tables = Vec::new();
    if let SelectCore::Select {
        from: Some(from), ..
    } = &sub.body.select
    {
        if let TableOrSubquery::Table { name, alias, .. } = &from.source {
            // When a table has an alias, SQL requires using the alias for
            // column references inside the subquery.  Only the alias should
            // be treated as "inner" so that references using the original
            // table name (which may match an outer table) are correctly
            // recognised as outer refs and substituted.
            if let Some(a) = alias {
                tables.push(a.clone());
            } else {
                tables.push(name.name.clone());
            }
        }
        for join in &from.joins {
            if let TableOrSubquery::Table { name, alias, .. } = &join.table {
                if let Some(a) = alias {
                    tables.push(a.clone());
                } else {
                    tables.push(name.name.clone());
                }
            }
        }
    }
    tables
}

/// Check if an expression tree contains any `Expr::Subquery`.
fn expr_has_any_subquery(expr: &Expr) -> bool {
    match expr {
        Expr::Subquery(_, _) | Expr::Exists { .. } => true,
        Expr::FunctionCall { args, .. } => match args {
            FunctionArgs::List(exprs) => exprs.iter().any(expr_has_any_subquery),
            FunctionArgs::Star => false,
        },
        Expr::BinaryOp { left, right, .. } => {
            expr_has_any_subquery(left) || expr_has_any_subquery(right)
        }
        Expr::UnaryOp { expr: inner, .. }
        | Expr::IsNull { expr: inner, .. }
        | Expr::Cast { expr: inner, .. }
        | Expr::Collate { expr: inner, .. } => expr_has_any_subquery(inner),
        Expr::Case {
            operand,
            whens,
            else_expr,
            ..
        } => {
            operand.as_ref().is_some_and(|e| expr_has_any_subquery(e))
                || whens
                    .iter()
                    .any(|(w, t)| expr_has_any_subquery(w) || expr_has_any_subquery(t))
                || else_expr.as_ref().is_some_and(|e| expr_has_any_subquery(e))
        }
        _ => false,
    }
}

/// Check if an expression contains a correlated scalar subquery whose
/// FROM clause has JOINs (multi-table subquery). These cannot be handled
/// by the VDBE `emit_scalar_subquery` which only opens one table cursor.
fn expr_has_correlated_join_subquery(expr: &Expr) -> bool {
    match expr {
        Expr::Subquery(sub, _) => {
            if let SelectCore::Select {
                from: Some(from), ..
            } = &sub.body.select
            {
                if !from.joins.is_empty() {
                    return true;
                }
            }
            false
        }
        Expr::FunctionCall { args, .. } => match args {
            FunctionArgs::List(exprs) => exprs.iter().any(expr_has_correlated_join_subquery),
            FunctionArgs::Star => false,
        },
        Expr::BinaryOp { left, right, .. } => {
            expr_has_correlated_join_subquery(left) || expr_has_correlated_join_subquery(right)
        }
        Expr::UnaryOp { expr: inner, .. }
        | Expr::IsNull { expr: inner, .. }
        | Expr::Cast { expr: inner, .. }
        | Expr::Collate { expr: inner, .. } => expr_has_correlated_join_subquery(inner),
        Expr::Case {
            operand,
            whens,
            else_expr,
            ..
        } => {
            operand
                .as_ref()
                .is_some_and(|e| expr_has_correlated_join_subquery(e))
                || whens.iter().any(|(w, t)| {
                    expr_has_correlated_join_subquery(w) || expr_has_correlated_join_subquery(t)
                })
                || else_expr
                    .as_ref()
                    .is_some_and(|e| expr_has_correlated_join_subquery(e))
        }
        _ => false,
    }
}

/// Check if a SELECT statement contains any correlated scalar subquery
/// with JOINs in any of its result columns, WHERE clause, or ORDER BY.
fn select_has_correlated_join_subquery(select: &SelectStatement) -> bool {
    let SelectCore::Select {
        columns,
        where_clause,
        ..
    } = &select.body.select
    else {
        return false;
    };
    for col in columns {
        if let ResultColumn::Expr { expr, .. } = col {
            if expr_has_correlated_join_subquery(expr) {
                return true;
            }
        }
    }
    if let Some(wh) = where_clause {
        if expr_has_correlated_join_subquery(wh) {
            return true;
        }
    }
    for term in &select.order_by {
        if expr_has_correlated_join_subquery(&term.expr) {
            return true;
        }
    }
    false
}

/// Substitute external column references in an expression with literal
/// values from the outer row. Column references whose table qualifier
/// matches one of the `inner_tables` are left unchanged.
fn substitute_outer_refs_in_expr(
    expr: &Expr,
    row: &[SqliteValue],
    outer_col_map: &[(String, String, bool)],
    inner_tables: &[String],
) -> Expr {
    match expr {
        Expr::Column(col_ref, _span) => {
            if let Some(qualifier) = &col_ref.table {
                let is_inner = inner_tables
                    .iter()
                    .any(|t| t.eq_ignore_ascii_case(qualifier));
                if !is_inner {
                    if let Ok(idx) =
                        find_col_in_map(outer_col_map, Some(qualifier), &col_ref.column, None)
                    {
                        let val = row.get(idx).cloned().unwrap_or(SqliteValue::Null);
                        return value_to_literal_expr(val);
                    }
                }
            }
            expr.clone()
        }
        Expr::BinaryOp {
            left,
            op,
            right,
            span,
        } => Expr::BinaryOp {
            left: Box::new(substitute_outer_refs_in_expr(
                left,
                row,
                outer_col_map,
                inner_tables,
            )),
            op: *op,
            right: Box::new(substitute_outer_refs_in_expr(
                right,
                row,
                outer_col_map,
                inner_tables,
            )),
            span: *span,
        },
        Expr::FunctionCall {
            name,
            args,
            distinct,
            order_by,
            filter,
            over,
            span,
        } => {
            let new_args = match args {
                FunctionArgs::List(exprs) => FunctionArgs::List(
                    exprs
                        .iter()
                        .map(|e| substitute_outer_refs_in_expr(e, row, outer_col_map, inner_tables))
                        .collect(),
                ),
                FunctionArgs::Star => FunctionArgs::Star,
            };
            Expr::FunctionCall {
                name: name.clone(),
                args: new_args,
                distinct: *distinct,
                order_by: order_by.clone(),
                filter: filter.as_ref().map(|f| {
                    Box::new(substitute_outer_refs_in_expr(
                        f,
                        row,
                        outer_col_map,
                        inner_tables,
                    ))
                }),
                over: over.clone(),
                span: *span,
            }
        }
        Expr::UnaryOp {
            op,
            expr: inner,
            span,
        } => Expr::UnaryOp {
            op: *op,
            expr: Box::new(substitute_outer_refs_in_expr(
                inner,
                row,
                outer_col_map,
                inner_tables,
            )),
            span: *span,
        },
        Expr::IsNull {
            expr: inner,
            not,
            span,
        } => Expr::IsNull {
            expr: Box::new(substitute_outer_refs_in_expr(
                inner,
                row,
                outer_col_map,
                inner_tables,
            )),
            not: *not,
            span: *span,
        },
        Expr::Like {
            expr: operand,
            pattern,
            escape,
            op: like_op,
            not,
            span,
        } => Expr::Like {
            expr: Box::new(substitute_outer_refs_in_expr(
                operand,
                row,
                outer_col_map,
                inner_tables,
            )),
            pattern: Box::new(substitute_outer_refs_in_expr(
                pattern,
                row,
                outer_col_map,
                inner_tables,
            )),
            escape: escape.as_ref().map(|e| {
                Box::new(substitute_outer_refs_in_expr(
                    e,
                    row,
                    outer_col_map,
                    inner_tables,
                ))
            }),
            op: *like_op,
            not: *not,
            span: *span,
        },
        Expr::Between {
            expr: operand,
            low,
            high,
            not,
            span,
        } => Expr::Between {
            expr: Box::new(substitute_outer_refs_in_expr(
                operand,
                row,
                outer_col_map,
                inner_tables,
            )),
            low: Box::new(substitute_outer_refs_in_expr(
                low,
                row,
                outer_col_map,
                inner_tables,
            )),
            high: Box::new(substitute_outer_refs_in_expr(
                high,
                row,
                outer_col_map,
                inner_tables,
            )),
            not: *not,
            span: *span,
        },
        Expr::In {
            expr: operand,
            set,
            not,
            span,
        } => {
            let new_set = match set {
                fsqlite_ast::InSet::List(items) => fsqlite_ast::InSet::List(
                    items
                        .iter()
                        .map(|e| substitute_outer_refs_in_expr(e, row, outer_col_map, inner_tables))
                        .collect(),
                ),
                other => other.clone(),
            };
            Expr::In {
                expr: Box::new(substitute_outer_refs_in_expr(
                    operand,
                    row,
                    outer_col_map,
                    inner_tables,
                )),
                set: new_set,
                not: *not,
                span: *span,
            }
        }
        Expr::Case {
            operand,
            whens,
            else_expr,
            span,
        } => Expr::Case {
            operand: operand.as_ref().map(|e| {
                Box::new(substitute_outer_refs_in_expr(
                    e,
                    row,
                    outer_col_map,
                    inner_tables,
                ))
            }),
            whens: whens
                .iter()
                .map(|(w, t)| {
                    (
                        substitute_outer_refs_in_expr(w, row, outer_col_map, inner_tables),
                        substitute_outer_refs_in_expr(t, row, outer_col_map, inner_tables),
                    )
                })
                .collect(),
            else_expr: else_expr.as_ref().map(|e| {
                Box::new(substitute_outer_refs_in_expr(
                    e,
                    row,
                    outer_col_map,
                    inner_tables,
                ))
            }),
            span: *span,
        },
        Expr::Cast {
            expr: inner,
            type_name,
            span,
        } => Expr::Cast {
            expr: Box::new(substitute_outer_refs_in_expr(
                inner,
                row,
                outer_col_map,
                inner_tables,
            )),
            type_name: type_name.clone(),
            span: *span,
        },
        Expr::Collate {
            expr: inner,
            collation,
            span,
        } => Expr::Collate {
            expr: Box::new(substitute_outer_refs_in_expr(
                inner,
                row,
                outer_col_map,
                inner_tables,
            )),
            collation: collation.clone(),
            span: *span,
        },
        _ => expr.clone(),
    }
}

/// Substitute external column references in a subquery's WHERE clause
/// and JOIN ON conditions with literal values from the outer row.
fn substitute_outer_refs_in_select(
    select: &mut SelectStatement,
    row: &[SqliteValue],
    outer_col_map: &[(String, String, bool)],
    inner_tables: &[String],
) {
    if let SelectCore::Select {
        where_clause, from, ..
    } = &mut select.body.select
    {
        if let Some(wh) = where_clause {
            **wh = substitute_outer_refs_in_expr(wh, row, outer_col_map, inner_tables);
        }
        // Also substitute in JOIN ON conditions.
        if let Some(from) = from {
            for join in &mut from.joins {
                if let Some(JoinConstraint::On(ref mut on_expr)) = join.constraint {
                    *on_expr =
                        substitute_outer_refs_in_expr(on_expr, row, outer_col_map, inner_tables);
                }
            }
        }
    }
}

///
/// When `rewrite_in_subqueries` is true, eagerly evaluate ALL
/// `IN (SELECT ...)` into literal lists.  When false, only eagerly
/// evaluate IN subqueries that VDBE codegen cannot handle (those with
/// GROUP BY, HAVING, windows, compounds, or WITH clauses) — simple
/// ones are left intact for VDBE runtime probe scans.
#[allow(clippy::too_many_lines)]
fn rewrite_in_expr(
    expr: &mut Expr,
    conn: &Connection,
    rewrite_in_subqueries: bool,
    params: Option<&[SqliteValue]>,
) -> Result<()> {
    match expr {
        Expr::In {
            set, expr: inner, ..
        } => {
            rewrite_in_expr(inner, conn, rewrite_in_subqueries, params)?;
            if let InSet::Subquery(sub) = set {
                // Correlated IN subqueries reference outer table columns and
                // must be evaluated per-row; skip eager rewrite.
                if !is_correlated_subquery(sub) {
                    // Eagerly evaluate the subquery when requested, OR when the
                    // subquery uses GROUP BY / HAVING / windows / compounds / WITH
                    // which VDBE codegen cannot handle in IN-probe expressions
                    // (it would emit NULL).  Also eagerly evaluate when the
                    // subquery references a VIEW — VDBE codegen's
                    // resolve_in_probe_source / try_emit_complex_in_subquery
                    // cannot resolve view names (they only look in the
                    // materialized table schema) and would silently emit NULL.
                    let needs_eager = rewrite_in_subqueries
                        || in_subquery_needs_eager_eval(sub)
                        || in_subquery_references_view(sub, conn);
                    if needs_eager {
                        let rows =
                            conn.execute_statement(&Statement::Select(*sub.clone()), params)?;
                        let literals: Vec<Expr> = rows
                            .into_iter()
                            .filter_map(|row| row.values.into_iter().next())
                            .map(value_to_literal_expr)
                            .collect();
                        *set = InSet::List(literals);
                    }
                }
            }
            if let InSet::List(exprs) = set {
                for e in exprs.iter_mut() {
                    rewrite_in_expr(e, conn, rewrite_in_subqueries, params)?;
                }
            }
            // Rewrite multi-column IN: (a, b) IN ((1, 10), (3, 30))
            // → ((a = 1 AND b = 10) OR (a = 3 AND b = 30))
            // This expansion lets the VDBE codegen and connection-level
            // evaluator handle multi-column IN without dedicated RowValue
            // comparison logic.
            if let Expr::RowValue(rv_exprs, _) = inner.as_ref() {
                if let InSet::List(list_items) = set {
                    let span = fsqlite_ast::Span::new(0, 0);
                    let mut or_arms: Vec<Expr> = Vec::with_capacity(list_items.len());
                    for item in list_items.iter() {
                        let rhs_exprs = match item {
                            Expr::RowValue(rv, _) => rv.as_slice(),
                            _ => std::slice::from_ref(item),
                        };
                        if rhs_exprs.len() != rv_exprs.len() {
                            continue;
                        }
                        let and_terms: Vec<Expr> = rv_exprs
                            .iter()
                            .zip(rhs_exprs.iter())
                            .map(|(l, r)| Expr::BinaryOp {
                                left: Box::new(l.clone()),
                                op: fsqlite_ast::BinaryOp::Eq,
                                right: Box::new(r.clone()),
                                span,
                            })
                            .collect();
                        let conj = and_terms.into_iter().reduce(|acc, e| Expr::BinaryOp {
                            left: Box::new(acc),
                            op: fsqlite_ast::BinaryOp::And,
                            right: Box::new(e),
                            span,
                        });
                        if let Some(c) = conj {
                            or_arms.push(c);
                        }
                    }
                    if let Some(combined) = or_arms.into_iter().reduce(|acc, e| Expr::BinaryOp {
                        left: Box::new(acc),
                        op: fsqlite_ast::BinaryOp::Or,
                        right: Box::new(e),
                        span,
                    }) {
                        if let Expr::In { not, .. } = expr {
                            *expr = if *not {
                                Expr::UnaryOp {
                                    op: fsqlite_ast::UnaryOp::Not,
                                    expr: Box::new(combined),
                                    span,
                                }
                            } else {
                                combined
                            };
                        }
                    }
                }
            }
        }
        Expr::Exists {
            subquery,
            not,
            span,
        } => {
            // Correlated EXISTS subqueries reference outer table columns and
            // must be evaluated per-row; skip the eager rewrite so they survive
            // into the row-level filter evaluation (eval_join_expr).
            if is_correlated_subquery(subquery) {
                return Ok(());
            }
            let rows = conn.execute_statement(&Statement::Select(*subquery.clone()), params)?;
            let exists = !rows.is_empty();
            let result = if *not { !exists } else { exists };
            *expr = Expr::Literal(Literal::Integer(i64::from(result)), *span);
        }
        Expr::Subquery(sub, span) => {
            // Correlated scalar subqueries reference outer table columns and
            // must be evaluated per-row; skip the eager rewrite so they survive
            // into the VDBE codegen which handles them via emit_scalar_subquery.
            if is_correlated_subquery(sub) {
                return Ok(());
            }
            let rows = conn.execute_statement(&Statement::Select(*sub.clone()), params)?;
            let val = rows
                .into_iter()
                .next()
                .and_then(|row| row.values.into_iter().next())
                .unwrap_or(SqliteValue::Null);
            *expr = Expr::Literal(
                match val {
                    SqliteValue::Integer(i) => Literal::Integer(i),
                    SqliteValue::Float(f) => Literal::Float(f),
                    SqliteValue::Text(s) => Literal::String(s.to_string()),
                    SqliteValue::Blob(b) => Literal::Blob(b.to_vec()),
                    SqliteValue::Null => Literal::Null,
                },
                *span,
            );
        }
        Expr::BinaryOp { left, right, .. } => {
            rewrite_in_expr(left, conn, rewrite_in_subqueries, params)?;
            rewrite_in_expr(right, conn, rewrite_in_subqueries, params)?;
        }
        Expr::UnaryOp { expr: inner, .. }
        | Expr::IsNull { expr: inner, .. }
        | Expr::Cast { expr: inner, .. } => {
            rewrite_in_expr(inner, conn, rewrite_in_subqueries, params)?;
        }
        Expr::Between {
            expr: inner,
            low,
            high,
            ..
        } => {
            rewrite_in_expr(inner, conn, rewrite_in_subqueries, params)?;
            rewrite_in_expr(low, conn, rewrite_in_subqueries, params)?;
            rewrite_in_expr(high, conn, rewrite_in_subqueries, params)?;
        }
        Expr::Case {
            operand,
            whens,
            else_expr,
            ..
        } => {
            if let Some(op) = operand.as_mut() {
                rewrite_in_expr(op, conn, rewrite_in_subqueries, params)?;
            }
            for (cond, then) in whens.iter_mut() {
                rewrite_in_expr(cond, conn, rewrite_in_subqueries, params)?;
                rewrite_in_expr(then, conn, rewrite_in_subqueries, params)?;
            }
            if let Some(el) = else_expr.as_mut() {
                rewrite_in_expr(el, conn, rewrite_in_subqueries, params)?;
            }
        }
        Expr::FunctionCall {
            args: FunctionArgs::List(exprs),
            ..
        } => {
            for e in exprs.iter_mut() {
                rewrite_in_expr(e, conn, rewrite_in_subqueries, params)?;
            }
        }
        Expr::Like {
            expr: inner,
            pattern,
            ..
        } => {
            rewrite_in_expr(inner, conn, rewrite_in_subqueries, params)?;
            rewrite_in_expr(pattern, conn, rewrite_in_subqueries, params)?;
        }
        // Leaf nodes that contain no sub-expressions.
        _ => {}
    }
    Ok(())
}

/// Convert a `SqliteValue` into a synthetic `Expr::Literal`.
fn value_to_literal_expr(val: SqliteValue) -> Expr {
    use fsqlite_ast::Span;
    match val {
        SqliteValue::Integer(i) => Expr::Literal(Literal::Integer(i), Span::ZERO),
        SqliteValue::Float(f) => Expr::Literal(Literal::Float(f), Span::ZERO),
        SqliteValue::Text(s) => Expr::Literal(Literal::String(s.to_string()), Span::ZERO),
        SqliteValue::Blob(b) => Expr::Literal(Literal::Blob(b.to_vec()), Span::ZERO),
        SqliteValue::Null => Expr::Literal(Literal::Null, Span::ZERO),
    }
}

/// Known aggregate function names (must match codegen.rs).
const AGG_NAMES: &[&str] = &[
    "avg",
    "count",
    "group_concat",
    "string_agg",
    "max",
    "min",
    "sum",
    "total",
];

/// Check whether a function name is a known aggregate.
fn is_agg_fn(name: &str) -> bool {
    let lower = name.to_ascii_lowercase();
    AGG_NAMES.iter().any(|&n| n == lower)
}

/// Returns true if this is a scalar max/min call (2+ arguments), not aggregate.
fn is_scalar_max_min(name: &str, args: &FunctionArgs) -> bool {
    let lower = name.to_ascii_lowercase();
    (lower == "max" || lower == "min") && matches!(args, FunctionArgs::List(a) if a.len() >= 2)
}

/// Check whether an expression tree contains any aggregate function calls.
fn expr_contains_agg(expr: &Expr) -> bool {
    match expr {
        Expr::FunctionCall { name, args, .. } => {
            if is_agg_fn(name) && !is_scalar_max_min(name, args) {
                return true;
            }
            match args {
                FunctionArgs::List(exprs) => exprs.iter().any(expr_contains_agg),
                FunctionArgs::Star => false,
            }
        }
        Expr::BinaryOp { left, right, .. } => expr_contains_agg(left) || expr_contains_agg(right),
        Expr::UnaryOp { expr: inner, .. }
        | Expr::IsNull { expr: inner, .. }
        | Expr::Cast { expr: inner, .. }
        | Expr::Collate { expr: inner, .. } => expr_contains_agg(inner),
        Expr::Between {
            expr: inner,
            low,
            high,
            ..
        } => expr_contains_agg(inner) || expr_contains_agg(low) || expr_contains_agg(high),
        Expr::Case {
            operand,
            whens,
            else_expr,
            ..
        } => {
            operand.as_ref().is_some_and(|e| expr_contains_agg(e))
                || whens
                    .iter()
                    .any(|(w, t)| expr_contains_agg(w) || expr_contains_agg(t))
                || else_expr.as_ref().is_some_and(|e| expr_contains_agg(e))
        }
        _ => false,
    }
}

/// Evaluate an expression that may contain aggregate function calls against
/// a group of rows. Aggregate sub-expressions are computed over the full
/// group; the remaining scalar parts are evaluated against the first row.
fn eval_group_agg_join_expr(
    expr: &Expr,
    group_rows: &[&Vec<SqliteValue>],
    col_map: &[(String, String, bool)],
) -> Result<SqliteValue> {
    match expr {
        Expr::FunctionCall {
            name,
            args,
            distinct,
            filter,
            ..
        } if is_agg_fn(name) && !is_scalar_max_min(name, args) => {
            let func = name.to_ascii_lowercase();
            // Apply FILTER clause: only include rows where the filter
            // expression evaluates to true.
            let filtered_rows: Vec<&&Vec<SqliteValue>> = if let Some(filter_expr) = filter {
                group_rows
                    .iter()
                    .filter(|r| {
                        eval_join_expr(filter_expr, r, col_map)
                            .map(|v| is_sqlite_truthy(&v))
                            .unwrap_or(false)
                    })
                    .collect()
            } else {
                group_rows.iter().collect()
            };
            let effective_rows: &[&&Vec<SqliteValue>] = &filtered_rows;
            match args {
                FunctionArgs::Star => {
                    if func == "count" {
                        #[allow(clippy::cast_possible_wrap)]
                        return Ok(SqliteValue::Integer(effective_rows.len() as i64));
                    }
                    Ok(SqliteValue::Null)
                }
                FunctionArgs::List(exprs) if exprs.is_empty() => {
                    if func == "count" {
                        #[allow(clippy::cast_possible_wrap)]
                        return Ok(SqliteValue::Integer(effective_rows.len() as i64));
                    }
                    Ok(SqliteValue::Null)
                }
                FunctionArgs::List(exprs) => {
                    let mut owned_values: Vec<SqliteValue> = effective_rows
                        .iter()
                        .filter_map(|r| eval_join_expr(&exprs[0], r, col_map).ok())
                        .filter(|v| !v.is_null())
                        .collect();
                    if *distinct {
                        let mut refs: Vec<&SqliteValue> = owned_values.iter().collect();
                        dedup_values(&mut refs);
                        owned_values = refs.into_iter().cloned().collect();
                    }
                    let separator = if func == "group_concat" || func == "string_agg" {
                        exprs
                            .get(1)
                            .and_then(|e| {
                                if let Expr::Literal(Literal::String(s), _) = e {
                                    Some(s.as_str())
                                } else {
                                    None
                                }
                            })
                            .or(Some(","))
                    } else {
                        None
                    };
                    let agg_refs: Vec<&SqliteValue> = owned_values.iter().collect();
                    Ok(compute_aggregate_ext(&func, &agg_refs, separator))
                }
            }
        }
        Expr::FunctionCall { name, args, .. } => {
            // Scalar function — evaluate args which may themselves contain aggs.
            if is_fts5_aux_function_name(name) {
                let row = group_rows.first().map_or(&[][..], |row| row.as_slice());
                if let Some(result) = try_eval_fts5_aux_function(name, args, row, col_map) {
                    return result;
                }
                return Err(FrankenError::function_error(format!(
                    "unable to use function {name} in the requested context",
                )));
            }
            let arg_vals: Vec<SqliteValue> = match args {
                FunctionArgs::List(exprs) => exprs
                    .iter()
                    .map(|e| eval_group_agg_join_expr(e, group_rows, col_map))
                    .collect::<Result<Vec<_>>>()?,
                FunctionArgs::Star => vec![],
            };
            Ok(eval_scalar_fn(name, &arg_vals))
        }
        Expr::BinaryOp {
            left, op, right, ..
        } => {
            let lv = eval_group_agg_join_expr(left, group_rows, col_map)?;
            let rv = eval_group_agg_join_expr(right, group_rows, col_map)?;
            Ok(eval_join_binary_op(&lv, *op, &rv))
        }
        Expr::Case {
            operand,
            whens,
            else_expr,
            ..
        } => {
            let base = operand
                .as_ref()
                .map(|e| eval_group_agg_join_expr(e, group_rows, col_map))
                .transpose()?;
            for (when_expr, then_expr) in whens {
                let when_val = eval_group_agg_join_expr(when_expr, group_rows, col_map)?;
                let matches = if let Some(ref b) = base {
                    !b.is_null()
                        && !when_val.is_null()
                        && cmp_values(b, &when_val) == std::cmp::Ordering::Equal
                } else {
                    is_sqlite_truthy(&when_val)
                };
                if matches {
                    return eval_group_agg_join_expr(then_expr, group_rows, col_map);
                }
            }
            if let Some(else_e) = else_expr {
                eval_group_agg_join_expr(else_e, group_rows, col_map)
            } else {
                Ok(SqliteValue::Null)
            }
        }
        Expr::IsNull { expr, not, .. } => {
            let val = eval_group_agg_join_expr(expr, group_rows, col_map)?;
            let result = if *not { !val.is_null() } else { val.is_null() };
            Ok(if result {
                SqliteValue::Integer(1)
            } else {
                SqliteValue::Integer(0)
            })
        }
        Expr::UnaryOp { op, expr, .. } => {
            let val = eval_group_agg_join_expr(expr, group_rows, col_map)?;
            match op {
                UnaryOp::Negate => match &val {
                    SqliteValue::Integer(n) => Ok(SqliteValue::Integer(n.wrapping_neg())),
                    SqliteValue::Float(f) => Ok(SqliteValue::Float(-f)),
                    _ => Ok(SqliteValue::Null),
                },
                UnaryOp::Plus => Ok(val),
                UnaryOp::Not => Ok(SqliteValue::Integer(i64::from(!is_sqlite_truthy(&val)))),
                UnaryOp::BitNot => match &val {
                    SqliteValue::Integer(n) => Ok(SqliteValue::Integer(!n)),
                    _ => Ok(SqliteValue::Null),
                },
            }
        }
        Expr::In {
            expr,
            set: InSet::List(list),
            not,
            ..
        } => {
            let val = eval_group_agg_join_expr(expr, group_rows, col_map)?;
            if val.is_null() {
                return Ok(SqliteValue::Null);
            }
            let list_vals: Vec<SqliteValue> = list
                .iter()
                .map(|e| eval_group_agg_join_expr(e, group_rows, col_map))
                .collect::<Result<Vec<_>>>()?;
            let found = list_vals.iter().any(|lv: &SqliteValue| {
                !lv.is_null() && cmp_values(&val, lv) == std::cmp::Ordering::Equal
            });
            let result = if *not { !found } else { found };
            Ok(SqliteValue::Integer(i64::from(result)))
        }
        Expr::Between {
            expr,
            low,
            high,
            not,
            ..
        } => {
            let val = eval_group_agg_join_expr(expr, group_rows, col_map)?;
            let lo = eval_group_agg_join_expr(low, group_rows, col_map)?;
            let hi = eval_group_agg_join_expr(high, group_rows, col_map)?;
            if val.is_null() || lo.is_null() || hi.is_null() {
                return Ok(SqliteValue::Null);
            }
            let in_range = cmp_values(&val, &lo) != std::cmp::Ordering::Less
                && cmp_values(&val, &hi) != std::cmp::Ordering::Greater;
            let result = if *not { !in_range } else { in_range };
            Ok(SqliteValue::Integer(i64::from(result)))
        }
        Expr::Cast {
            expr: inner,
            type_name,
            ..
        } => {
            let val = eval_group_agg_join_expr(inner, group_rows, col_map)?;
            if val.is_null() {
                return Ok(SqliteValue::Null);
            }
            Ok(apply_cast(val, &type_name.name))
        }
        Expr::Collate { expr: inner, .. } => eval_group_agg_join_expr(inner, group_rows, col_map),
        // No aggregate sub-expressions: delegate to per-row eval on first row.
        // When group_rows is empty (implicit aggregation on an empty table),
        // still try evaluating with an empty row — this correctly handles
        // literals, constants, and expressions that don't reference columns
        // (e.g. the `1` in `SELECT COUNT(*) + 1 FROM empty_table`).
        other => {
            let empty = Vec::new();
            let row: &Vec<SqliteValue> = group_rows.first().copied().unwrap_or(&empty);
            eval_join_expr(other, row, col_map).or(Ok(SqliteValue::Null))
        }
    }
}

/// Describes one result column in a GROUP BY query.
enum GroupByColumn {
    /// A non-aggregate expression that appears in GROUP BY; evaluated per-group.
    Plain(Box<Expr>),
    /// An aggregate function; stores (func_name_lower, arg_col_index_or_None_for_star).
    Agg {
        name: String,
        arg_col: Option<usize>,
        arg_expr: Option<Box<Expr>>,
        distinct: bool,
        separator: Option<String>,
        separator_expr: Option<Box<Expr>>,
        /// FILTER clause expression, e.g. `COUNT(*) FILTER (WHERE x > 5)`.
        filter: Option<Box<Expr>>,
        /// Collation sequence for the aggregate argument column (e.g. "NOCASE").
        /// Used for DISTINCT dedup and MIN/MAX comparison.
        collation: Option<String>,
        /// In-aggregate ORDER BY (SQLite 3.44+), e.g. `GROUP_CONCAT(x ORDER BY y)`.
        order_by: Vec<fsqlite_ast::OrderingTerm>,
    },
}

/// Compare two expressions for structural equality, ignoring source spans.
fn exprs_match(a: &Expr, b: &Expr) -> bool {
    match (a, b) {
        (Expr::Column(ca, _), Expr::Column(cb, _)) => {
            ca.column.eq_ignore_ascii_case(&cb.column)
                && ca.table.as_deref().map(str::to_ascii_lowercase)
                    == cb.table.as_deref().map(str::to_ascii_lowercase)
        }
        (Expr::Literal(la, _), Expr::Literal(lb, _)) => la == lb,
        (
            Expr::BinaryOp {
                left: la,
                op: oa,
                right: ra,
                ..
            },
            Expr::BinaryOp {
                left: lb,
                op: ob,
                right: rb,
                ..
            },
        ) => oa == ob && exprs_match(la, lb) && exprs_match(ra, rb),
        (
            Expr::UnaryOp {
                op: oa, expr: ea, ..
            },
            Expr::UnaryOp {
                op: ob, expr: eb, ..
            },
        ) => oa == ob && exprs_match(ea, eb),
        (
            Expr::FunctionCall {
                name: na,
                args: aa,
                distinct: da,
                ..
            },
            Expr::FunctionCall {
                name: nb,
                args: ab,
                distinct: db,
                ..
            },
        ) => {
            na.eq_ignore_ascii_case(nb)
                && da == db
                && match (aa, ab) {
                    (FunctionArgs::Star, FunctionArgs::Star) => true,
                    (FunctionArgs::List(la), FunctionArgs::List(lb)) => {
                        la.len() == lb.len()
                            && la.iter().zip(lb.iter()).all(|(x, y)| exprs_match(x, y))
                    }
                    _ => false,
                }
        }
        (
            Expr::IsNull {
                expr: ea, not: na, ..
            },
            Expr::IsNull {
                expr: eb, not: nb, ..
            },
        ) => na == nb && exprs_match(ea, eb),
        (
            Expr::Cast {
                expr: ea,
                type_name: ta,
                ..
            },
            Expr::Cast {
                expr: eb,
                type_name: tb,
                ..
            },
        ) => ta.name.eq_ignore_ascii_case(&tb.name) && exprs_match(ea, eb),
        // Fallback: use the AST-level PartialEq for variants not handled
        // above (Subquery, Exists, In, Between, Case, etc.).
        _ => a == b,
    }
}

/// Resolve a column name from an expression (simple Expr::Column case).
fn expr_col_name(expr: &Expr) -> Option<&str> {
    match expr {
        Expr::Column(col_ref, _) => Some(col_ref.column.as_str()),
        _ => None,
    }
}

#[derive(Debug, Clone)]
#[allow(dead_code)]
struct NormalizedIndexedColumnTerm {
    column_name: String,
    collation: Option<String>,
    direction: Option<SortDirection>,
}

#[derive(Debug, Clone)]
struct ReconstructedIndexDefinition {
    columns: Vec<String>,
    key_expressions: Vec<String>,
    key_sort_directions: Vec<SortDirection>,
    where_clause: Option<String>,
    is_unique: bool,
}

impl ReconstructedIndexDefinition {
    #[must_use]
    fn key_term_count(&self) -> usize {
        if self.key_expressions.is_empty() {
            self.columns.len()
        } else {
            self.key_expressions.len()
        }
    }
}

fn parse_index_definition_from_create_sql(
    create_sql: &str,
) -> Option<ReconstructedIndexDefinition> {
    match parse_single_statement(create_sql).ok()? {
        Statement::CreateIndex(stmt) => index_definition_from_create_index_statement(&stmt),
        _ => None,
    }
}

fn infer_implicit_index_definition_from_master_entries(
    master_entries: &[Vec<SqliteValue>],
    table_name: &str,
    index_name: &str,
) -> Option<ReconstructedIndexDefinition> {
    let ordinal = parse_autoindex_ordinal(index_name, table_name)?;
    let table_create_sql = master_entries.iter().find_map(|entry| {
        if entry.len() < 5 {
            return None;
        }
        let entry_type = match &entry[0] {
            SqliteValue::Text(s) => s,
            _ => return None,
        };
        if !entry_type.eq_ignore_ascii_case("table") {
            return None;
        }
        let entry_table_name = match &entry[1] {
            SqliteValue::Text(s) => s,
            _ => return None,
        };
        if !entry_table_name.eq_ignore_ascii_case(table_name) {
            return None;
        }
        match &entry[4] {
            SqliteValue::Text(sql) => Some(sql),
            _ => None,
        }
    })?;
    let definitions = implicit_index_definitions_from_create_table_sql(table_create_sql)?;
    let definition_index = ordinal.checked_sub(1)?;
    definitions.get(definition_index).cloned()
}

fn parse_autoindex_ordinal(index_name: &str, table_name: &str) -> Option<usize> {
    let index_name_lower = index_name.to_ascii_lowercase();
    let prefix = format!("sqlite_autoindex_{}_", table_name.to_ascii_lowercase());
    let suffix = index_name_lower.strip_prefix(&prefix)?;
    if suffix.is_empty() || !suffix.chars().all(|ch| ch.is_ascii_digit()) {
        return None;
    }
    let ordinal = suffix.parse::<usize>().ok()?;
    if ordinal == 0 { None } else { Some(ordinal) }
}

fn implicit_index_definitions_from_create_table_sql(
    create_table_sql: &str,
) -> Option<Vec<ReconstructedIndexDefinition>> {
    let statement = parse_single_statement(create_table_sql).ok()?;
    let Statement::CreateTable(create_stmt) = statement else {
        return None;
    };
    let CreateTableBody::Columns {
        columns: column_defs,
        constraints,
    } = create_stmt.body
    else {
        return Some(Vec::new());
    };

    let mut definitions = Vec::new();
    for column in &column_defs {
        let has_unique_constraint = column.constraints.iter().any(|constraint| {
            matches!(
                constraint.kind,
                ColumnConstraintKind::Unique { .. } | ColumnConstraintKind::PrimaryKey { .. }
            )
        });
        let is_ipk = column.type_name.as_ref().is_some_and(|type_name| {
            type_name.name.eq_ignore_ascii_case("INTEGER")
                && column.constraints.iter().any(|constraint| {
                    matches!(
                        constraint.kind,
                        ColumnConstraintKind::PrimaryKey {
                            direction: None | Some(SortDirection::Asc),
                            ..
                        }
                    )
                })
        });
        if has_unique_constraint && !is_ipk {
            definitions.push(ReconstructedIndexDefinition {
                columns: vec![column.name.clone()],
                key_expressions: vec![column.name.clone()],
                key_sort_directions: vec![SortDirection::Asc],
                where_clause: None,
                is_unique: true,
            });
        }
    }

    for constraint in constraints {
        if let TableConstraintKind::Unique {
            columns: idx_cols, ..
        }
        | TableConstraintKind::PrimaryKey {
            columns: idx_cols, ..
        } = constraint.kind
        {
            let key_expressions = idx_cols
                .iter()
                .map(|indexed| indexed.expr.to_string())
                .collect::<Vec<_>>();
            if !key_expressions.is_empty() {
                definitions.push(ReconstructedIndexDefinition {
                    columns: extract_simple_index_columns(&idx_cols),
                    key_expressions,
                    key_sort_directions: idx_cols
                        .iter()
                        .map(|indexed| indexed.direction.unwrap_or(SortDirection::Asc))
                        .collect(),
                    where_clause: None,
                    is_unique: true,
                });
            }
        }
    }

    Some(definitions)
}

fn index_definition_from_create_index_statement(
    stmt: &fsqlite_ast::CreateIndexStatement,
) -> Option<ReconstructedIndexDefinition> {
    let key_expressions = stmt
        .columns
        .iter()
        .map(|indexed| indexed.expr.to_string())
        .collect::<Vec<_>>();
    if key_expressions.is_empty() {
        return None;
    }
    Some(ReconstructedIndexDefinition {
        columns: extract_simple_index_columns(&stmt.columns),
        key_expressions,
        key_sort_directions: stmt
            .columns
            .iter()
            .map(|indexed| indexed.direction.unwrap_or(SortDirection::Asc))
            .collect(),
        where_clause: stmt.where_clause.as_ref().map(ToString::to_string),
        is_unique: stmt.unique,
    })
}

fn extract_simple_index_columns(indexed_terms: &[fsqlite_ast::IndexedColumn]) -> Vec<String> {
    indexed_terms
        .iter()
        .map(normalize_indexed_column_term)
        .collect::<Option<Vec<_>>>()
        .map(|terms| {
            terms
                .into_iter()
                .map(|term| term.column_name)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default()
}

fn collect_primary_key_constraints(
    columns: &[fsqlite_ast::ColumnDef],
    constraints: &[fsqlite_ast::TableConstraint],
) -> Vec<Vec<String>> {
    let mut primary_keys = columns
        .iter()
        .filter(|column| {
            column.constraints.iter().any(|constraint| {
                matches!(constraint.kind, ColumnConstraintKind::PrimaryKey { .. })
            })
        })
        .map(|column| vec![column.name.clone()])
        .collect::<Vec<_>>();

    primary_keys.extend(constraints.iter().filter_map(|constraint| {
        let TableConstraintKind::PrimaryKey {
            columns: indexed_columns,
            ..
        } = &constraint.kind
        else {
            return None;
        };
        let columns = indexed_columns
            .iter()
            .map(normalize_indexed_column_term)
            .collect::<Option<Vec<_>>>()?
            .into_iter()
            .map(|term| term.column_name)
            .collect::<Vec<_>>();
        (!columns.is_empty()).then_some(columns)
    }));

    primary_keys
}

/// Normalize an indexed-column AST node into execution/persistence metadata.
///
/// `CREATE INDEX` currently supports only column references as indexed terms,
/// but accepts SQL forms where `COLLATE` is represented either as a postfix
/// expression (`name COLLATE NOCASE`) or as parser-level indexed-column
/// metadata.
fn normalize_indexed_column_term(
    indexed: &fsqlite_ast::IndexedColumn,
) -> Option<NormalizedIndexedColumnTerm> {
    fn extract(expr: &Expr) -> Option<(&str, Option<&str>)> {
        match expr {
            Expr::Column(col_ref, _) => Some((col_ref.column.as_str(), None)),
            Expr::Collate {
                expr, collation, ..
            } => {
                let (column_name, _) = extract(expr)?;
                Some((column_name, Some(collation.as_str())))
            }
            _ => None,
        }
    }

    let (column_name, expr_collation) = extract(&indexed.expr)?;
    let collation = indexed
        .collation
        .clone()
        .or_else(|| expr_collation.map(str::to_owned));

    Some(NormalizedIndexedColumnTerm {
        column_name: column_name.to_owned(),
        collation,
        direction: indexed.direction,
    })
}

/// Build arguments for a window function `step()` call.
///
/// For functions with explicit args (lag, lead, etc.), evaluates those args.
/// For pure-numbering functions (row_number, rank, dense_rank) with no
/// explicit args, passes the ORDER BY values so they can detect peer groups.
/// Resolve a `FrameBound` to a numeric row offset for ROWS frames.
/// Returns `None` for `UnboundedPreceding`/`UnboundedFollowing`/`CurrentRow`.
fn resolve_frame_bound_offset(bound: &FrameBound) -> Option<usize> {
    match bound {
        FrameBound::Preceding(expr) | FrameBound::Following(expr) => match expr.as_ref() {
            Expr::Literal(Literal::Integer(n), _) => {
                Some(usize::try_from(*n).unwrap_or(usize::MAX))
            }
            #[allow(clippy::cast_possible_truncation, clippy::cast_sign_loss)]
            Expr::Literal(Literal::Float(f), _) => Some(*f as usize),
            _ => Some(0),
        },
        FrameBound::CurrentRow => Some(0),
        FrameBound::UnboundedPreceding | FrameBound::UnboundedFollowing => None,
    }
}

/// Compute the ROWS frame start/end indices for a given row position in a partition.
/// Returns `(frame_start, frame_end_exclusive)` clamped to `[0, partition_size)`.
#[allow(clippy::cast_possible_truncation)]
fn rows_frame_bounds(pos: usize, partition_size: usize, frame: &FrameSpec) -> (usize, usize) {
    let start = match &frame.start {
        FrameBound::UnboundedPreceding => 0,
        FrameBound::CurrentRow => pos,
        FrameBound::Preceding(expr) => {
            let n = resolve_frame_bound_offset(&FrameBound::Preceding(expr.clone())).unwrap_or(0);
            pos.saturating_sub(n)
        }
        FrameBound::Following(expr) => {
            let n = resolve_frame_bound_offset(&FrameBound::Following(expr.clone())).unwrap_or(0);
            (pos + n).min(partition_size)
        }
        FrameBound::UnboundedFollowing => partition_size,
    };
    let end_inclusive = match frame.end.as_ref().unwrap_or(&FrameBound::CurrentRow) {
        FrameBound::UnboundedFollowing => partition_size.saturating_sub(1),
        FrameBound::CurrentRow => pos,
        FrameBound::Following(expr) => {
            let n = resolve_frame_bound_offset(&FrameBound::Following(expr.clone())).unwrap_or(0);
            (pos + n).min(partition_size.saturating_sub(1))
        }
        FrameBound::Preceding(expr) => {
            let n = resolve_frame_bound_offset(&FrameBound::Preceding(expr.clone())).unwrap_or(0);
            pos.saturating_sub(n)
        }
        FrameBound::UnboundedPreceding => 0,
    };
    (start, end_inclusive + 1)
}

/// Check if a frame spec uses ROWS with explicit numeric bounds (not all unbounded).
fn is_rows_sliding_frame(frame: Option<&FrameSpec>) -> bool {
    let Some(f) = frame else { return false };
    if !matches!(f.frame_type, FrameType::Rows) {
        return false;
    }
    let start_explicit = matches!(
        f.start,
        FrameBound::Preceding(_) | FrameBound::Following(_) | FrameBound::CurrentRow
    );
    let end_explicit = f.end.as_ref().is_some_and(|e| {
        matches!(
            e,
            FrameBound::Preceding(_) | FrameBound::Following(_) | FrameBound::CurrentRow
        )
    });
    // At least one bound is not UNBOUNDED.
    start_explicit || end_explicit
}

/// Build peer groups from a sorted partition: groups of row indices where
/// all rows in a group have equal ORDER BY key values.
fn build_peer_groups(
    partition_indices: &[usize],
    order_by: &[(Expr, bool)],
    row_values: &[Vec<SqliteValue>],
    col_map: &[(String, String, bool)],
) -> Vec<Vec<usize>> {
    if partition_indices.is_empty() {
        return Vec::new();
    }
    let mut groups: Vec<Vec<usize>> = vec![vec![partition_indices[0]]];
    for &ri in &partition_indices[1..] {
        let prev_ri = *groups.last().unwrap().last().unwrap();
        let same = order_by.iter().all(|(oexpr, _)| {
            let va =
                eval_join_expr(oexpr, &row_values[prev_ri], col_map).unwrap_or(SqliteValue::Null);
            let vb = eval_join_expr(oexpr, &row_values[ri], col_map).unwrap_or(SqliteValue::Null);
            cmp_sqlite_values(&va, &vb) == std::cmp::Ordering::Equal
        });
        if same {
            groups.last_mut().unwrap().push(ri);
        } else {
            groups.push(vec![ri]);
        }
    }
    groups
}

fn peer_rows_for_current_row(peer_groups: &[Vec<usize>], current_ri: usize) -> Vec<usize> {
    peer_groups
        .iter()
        .find(|group| group.contains(&current_ri))
        .cloned()
        .unwrap_or_else(|| vec![current_ri])
}

fn window_frame_rows_for_current(
    pos: usize,
    partition_indices: &[usize],
    order_by: &[(Expr, bool)],
    row_values: &[Vec<SqliteValue>],
    col_map: &[(String, String, bool)],
    frame: &FrameSpec,
    peer_groups: &[Vec<usize>],
) -> Vec<usize> {
    match frame.frame_type {
        FrameType::Rows => {
            let (frame_start, frame_end) = rows_frame_bounds(pos, partition_indices.len(), frame);
            partition_indices[frame_start..frame_end].to_vec()
        }
        FrameType::Groups => {
            let current_ri = partition_indices[pos];
            let group_pos = peer_groups
                .iter()
                .position(|group| group.contains(&current_ri))
                .unwrap_or(0);
            let (group_start, group_end) = groups_frame_bounds(group_pos, peer_groups.len(), frame);
            peer_groups[group_start..group_end]
                .iter()
                .flatten()
                .copied()
                .collect()
        }
        FrameType::Range => {
            if order_by.is_empty() {
                partition_indices.to_vec()
            } else {
                let (frame_start, frame_end) = range_value_frame_bounds(
                    pos,
                    partition_indices,
                    order_by,
                    row_values,
                    col_map,
                    frame,
                );
                partition_indices[frame_start..frame_end].to_vec()
            }
        }
    }
}

fn apply_frame_exclusion(
    frame_rows: Vec<usize>,
    current_ri: usize,
    peer_rows: &[usize],
    exclude: Option<FrameExclude>,
) -> Vec<usize> {
    match exclude.unwrap_or(FrameExclude::NoOthers) {
        FrameExclude::NoOthers => frame_rows,
        FrameExclude::CurrentRow => frame_rows
            .into_iter()
            .filter(|&ri| ri != current_ri)
            .collect(),
        FrameExclude::Group => {
            let peer_set: HashSet<usize> = peer_rows.iter().copied().collect();
            frame_rows
                .into_iter()
                .filter(|ri| !peer_set.contains(ri))
                .collect()
        }
        FrameExclude::Ties => {
            let peer_set: HashSet<usize> = peer_rows.iter().copied().collect();
            frame_rows
                .into_iter()
                .filter(|&ri| ri == current_ri || !peer_set.contains(&ri))
                .collect()
        }
    }
}

/// Compute GROUPS frame bounds (start group index, end group index exclusive).
fn groups_frame_bounds(group_pos: usize, num_groups: usize, frame: &FrameSpec) -> (usize, usize) {
    let start = match &frame.start {
        FrameBound::UnboundedPreceding => 0,
        FrameBound::CurrentRow => group_pos,
        FrameBound::Preceding(expr) => {
            let n = resolve_frame_bound_offset(&FrameBound::Preceding(expr.clone())).unwrap_or(0);
            group_pos.saturating_sub(n)
        }
        FrameBound::Following(expr) => {
            let n = resolve_frame_bound_offset(&FrameBound::Following(expr.clone())).unwrap_or(0);
            (group_pos + n).min(num_groups)
        }
        FrameBound::UnboundedFollowing => num_groups,
    };
    let end_inclusive = match frame.end.as_ref().unwrap_or(&FrameBound::CurrentRow) {
        FrameBound::UnboundedFollowing => num_groups.saturating_sub(1),
        FrameBound::CurrentRow => group_pos,
        FrameBound::Following(expr) => {
            let n = resolve_frame_bound_offset(&FrameBound::Following(expr.clone())).unwrap_or(0);
            (group_pos + n).min(num_groups.saturating_sub(1))
        }
        FrameBound::Preceding(expr) => {
            let n = resolve_frame_bound_offset(&FrameBound::Preceding(expr.clone())).unwrap_or(0);
            group_pos.saturating_sub(n)
        }
        FrameBound::UnboundedPreceding => 0,
    };
    (start, end_inclusive + 1)
}

/// Compute RANGE frame bounds based on ORDER BY values.
/// Returns `(start_row_idx, end_row_idx_exclusive)` within the partition.
fn range_value_frame_bounds(
    pos: usize,
    partition_indices: &[usize],
    order_by: &[(Expr, bool)],
    row_values: &[Vec<SqliteValue>],
    col_map: &[(String, String, bool)],
    frame: &FrameSpec,
) -> (usize, usize) {
    // Extract current row's ORDER BY value as f64 for arithmetic comparison.
    let current_ri = partition_indices[pos];
    let current_val = order_by
        .first()
        .and_then(|(oexpr, _)| eval_join_expr(oexpr, &row_values[current_ri], col_map).ok())
        .and_then(|v| match v {
            SqliteValue::Integer(n) => Some(n as f64),
            SqliteValue::Float(f) => Some(f),
            _ => None,
        })
        .unwrap_or(0.0);

    let bound_offset_f64 = |bound: &FrameBound| -> f64 {
        match bound {
            FrameBound::Preceding(expr) | FrameBound::Following(expr) => match expr.as_ref() {
                Expr::Literal(Literal::Integer(n), _) => *n as f64,
                Expr::Literal(Literal::Float(f), _) => *f,
                _ => 0.0,
            },
            _ => 0.0,
        }
    };

    let low = match &frame.start {
        FrameBound::UnboundedPreceding => f64::NEG_INFINITY,
        FrameBound::CurrentRow => current_val,
        FrameBound::Preceding(e) => {
            current_val - bound_offset_f64(&FrameBound::Preceding(e.clone()))
        }
        FrameBound::Following(e) => {
            current_val + bound_offset_f64(&FrameBound::Following(e.clone()))
        }
        FrameBound::UnboundedFollowing => f64::INFINITY,
    };
    let high = match frame.end.as_ref().unwrap_or(&FrameBound::CurrentRow) {
        FrameBound::UnboundedFollowing => f64::INFINITY,
        FrameBound::CurrentRow => current_val,
        FrameBound::Preceding(e) => {
            current_val - bound_offset_f64(&FrameBound::Preceding(e.clone()))
        }
        FrameBound::Following(e) => {
            current_val + bound_offset_f64(&FrameBound::Following(e.clone()))
        }
        FrameBound::UnboundedPreceding => f64::NEG_INFINITY,
    };

    let psize = partition_indices.len();
    let mut start = 0;
    let mut end = psize;
    for (i, &ri) in partition_indices.iter().enumerate() {
        let v = order_by
            .first()
            .and_then(|(oexpr, _)| eval_join_expr(oexpr, &row_values[ri], col_map).ok())
            .and_then(|v| match v {
                SqliteValue::Integer(n) => Some(n as f64),
                SqliteValue::Float(f) => Some(f),
                _ => None,
            })
            .unwrap_or(0.0);
        if v < low {
            start = i + 1;
        }
        if v > high && end == psize {
            end = i;
        }
    }
    (start, end)
}

fn build_window_args(
    func_args: &[Expr],
    order_by: &[(Expr, bool)],
    row: &[SqliteValue],
    col_map: &[(String, String, bool)],
) -> Result<Vec<SqliteValue>> {
    if func_args.is_empty() {
        order_by
            .iter()
            .map(|(expr, _)| eval_join_expr(expr, row, col_map))
            .collect()
    } else {
        func_args
            .iter()
            .map(|expr| eval_join_expr(expr, row, col_map))
            .collect()
    }
}

/// Build a `SELECT *` scan from a GROUP BY SELECT (strips aggregates and GROUP BY).
fn build_raw_scan_select(select: &SelectStatement) -> SelectStatement {
    let new_core = match &select.body.select {
        SelectCore::Select {
            from, where_clause, ..
        } => SelectCore::Select {
            distinct: Distinctness::All,
            columns: vec![ResultColumn::Star],
            from: from.clone(),
            where_clause: where_clause.clone(),
            group_by: vec![],
            having: None,
            windows: vec![],
        },
        other @ SelectCore::Values(_) => other.clone(),
    };
    SelectStatement {
        with: select.with.clone(),
        body: SelectBody {
            select: new_core,
            compounds: vec![],
        },
        order_by: vec![],
        limit: None,
    }
}

/// Test whether a `SqliteValue` is truthy (non-zero, non-NULL).
/// C SQLite truthiness for OP_If/OP_IfNot (CASE WHEN, WHERE, HAVING):
/// uses `sqlite3VdbeRealValue() != 0.0`, so 0.1 and 0.5 are truthy.
fn is_sqlite_truthy(v: &SqliteValue) -> bool {
    match v {
        SqliteValue::Null => false,
        SqliteValue::Integer(n) => *n != 0,
        SqliteValue::Float(f) => *f != 0.0,
        SqliteValue::Text(_) | SqliteValue::Blob(_) => {
            let i = v.to_integer();
            if i != 0 {
                return true;
            }
            v.to_float() != 0.0
        }
    }
}

/// Evaluate a HAVING predicate against a group's computed result values.
///
/// `group_rows` and `col_map` allow computing aggregates that are not in the
/// SELECT list (e.g. `HAVING COUNT(*) > 1` when COUNT(*) is not a result column).
fn evaluate_having_predicate(
    expr: &Expr,
    values: &[SqliteValue],
    descriptors: &[GroupByColumn],
    columns: &[ResultColumn],
    group_rows: &[Vec<SqliteValue>],
    col_map: &[(String, String, bool)],
) -> bool {
    is_sqlite_truthy(&evaluate_having_value(
        expr,
        values,
        descriptors,
        columns,
        group_rows,
        col_map,
    ))
}

/// Evaluate a HAVING expression to a `SqliteValue`.
///
/// First tries to resolve from the already-computed result values (matching against
/// Check if `op` IS/IS NOT with `rhs` TRUE/FALSE should use `IsTrue`.
/// Returns `(p3, p4)` for the `IsTrue` opcode.
fn is_true_false_params_core(op: BinaryOp, rhs: &Expr) -> Option<(i32, P4)> {
    let is_not = matches!(op, BinaryOp::IsNot);
    match rhs {
        Expr::Literal(Literal::True, _) => {
            if is_not {
                Some((0, P4::Int(1)))
            } else {
                Some((0, P4::None))
            }
        }
        Expr::Literal(Literal::False, _) => {
            if is_not {
                Some((1, P4::None))
            } else {
                Some((1, P4::Int(1)))
            }
        }
        _ => None,
    }
}

/// descriptors/columns). Falls back to computing aggregates directly from
/// group_rows for HAVING expressions that reference aggregates not in SELECT.
#[allow(clippy::too_many_lines)]
fn evaluate_having_value(
    expr: &Expr,
    values: &[SqliteValue],
    descriptors: &[GroupByColumn],
    columns: &[ResultColumn],
    group_rows: &[Vec<SqliteValue>],
    col_map: &[(String, String, bool)],
) -> SqliteValue {
    match expr {
        // Aggregate function -- first try matching a result column, then compute directly.
        Expr::FunctionCall {
            name,
            args,
            distinct: having_distinct,
            ..
        } if is_agg_fn(name) && !is_scalar_max_min(name, args) => {
            let lower = name.to_ascii_lowercase();
            // Try to find a matching aggregate in the result descriptors.
            for (i, desc) in descriptors.iter().enumerate() {
                if let GroupByColumn::Agg {
                    name: agg_name,
                    arg_col,
                    distinct: desc_distinct,
                    ..
                } = desc
                {
                    if *agg_name != lower {
                        continue;
                    }
                    // DISTINCT flag must match.
                    if *having_distinct != *desc_distinct {
                        continue;
                    }
                    let args_match = match args {
                        FunctionArgs::Star => arg_col.is_none(),
                        FunctionArgs::List(exprs) if exprs.is_empty() => arg_col.is_none(),
                        FunctionArgs::List(exprs) => {
                            if let Some(ResultColumn::Expr {
                                expr:
                                    Expr::FunctionCall {
                                        args: FunctionArgs::List(result_args),
                                        ..
                                    },
                                ..
                            }) = columns.get(i)
                            {
                                // Compare first argument structurally
                                // (not just bare name) so that COUNT(r.id)
                                // doesn't match COUNT(p.id).
                                result_args
                                    .first()
                                    .is_some_and(|e| exprs_match(&exprs[0], e))
                            } else {
                                false
                            }
                        }
                    };
                    if args_match {
                        return values.get(i).cloned().unwrap_or(SqliteValue::Null);
                    }
                }
            }
            // Aggregate not found in SELECT — compute directly from group_rows.
            compute_having_aggregate(&lower, args, group_rows, col_map)
        }

        // Column reference — find matching plain column in result set or raw data.
        Expr::Column(col_ref, _) => {
            let col_name = &col_ref.column;
            // First check result column aliases.
            for (i, rc) in columns.iter().enumerate() {
                if let ResultColumn::Expr {
                    alias: Some(alias), ..
                } = rc
                {
                    if alias.eq_ignore_ascii_case(col_name) {
                        return values.get(i).cloned().unwrap_or(SqliteValue::Null);
                    }
                }
            }
            // Then check result column names.
            for (i, rc) in columns.iter().enumerate() {
                if let ResultColumn::Expr { expr, .. } = rc {
                    if let Some(name) = expr_col_name(expr) {
                        if name.eq_ignore_ascii_case(col_name) {
                            return values.get(i).cloned().unwrap_or(SqliteValue::Null);
                        }
                    }
                }
            }
            // Fall back to resolving from raw group data via col_map.
            let table_prefix = col_ref.table.as_deref();
            if let Ok(idx) = find_col_in_map(col_map, table_prefix, col_name, None) {
                return group_rows
                    .first()
                    .and_then(|r| r.get(idx))
                    .cloned()
                    .unwrap_or(SqliteValue::Null);
            }
            SqliteValue::Null
        }

        // Literal values.
        Expr::Literal(lit, _) => match lit {
            fsqlite_ast::Literal::Integer(n) => SqliteValue::Integer(*n),
            fsqlite_ast::Literal::Float(f) => SqliteValue::Float(*f),
            fsqlite_ast::Literal::String(s) => SqliteValue::Text(s.clone().into()),
            fsqlite_ast::Literal::True => SqliteValue::Integer(1),
            fsqlite_ast::Literal::False => SqliteValue::Integer(0),
            _ => SqliteValue::Null,
        },

        // Binary operations.
        Expr::BinaryOp {
            left, op, right, ..
        } => {
            let lv = evaluate_having_value(left, values, descriptors, columns, group_rows, col_map);
            let rv =
                evaluate_having_value(right, values, descriptors, columns, group_rows, col_map);
            let is_null_op = matches!(lv, SqliteValue::Null) || matches!(rv, SqliteValue::Null);
            match op {
                fsqlite_ast::BinaryOp::Gt => {
                    if is_null_op {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Integer(i64::from(
                            cmp_values(&lv, &rv) == std::cmp::Ordering::Greater,
                        ))
                    }
                }
                fsqlite_ast::BinaryOp::Lt => {
                    if is_null_op {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Integer(i64::from(
                            cmp_values(&lv, &rv) == std::cmp::Ordering::Less,
                        ))
                    }
                }
                fsqlite_ast::BinaryOp::Ge => {
                    if is_null_op {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Integer(i64::from(
                            cmp_values(&lv, &rv) != std::cmp::Ordering::Less,
                        ))
                    }
                }
                fsqlite_ast::BinaryOp::Le => {
                    if is_null_op {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Integer(i64::from(
                            cmp_values(&lv, &rv) != std::cmp::Ordering::Greater,
                        ))
                    }
                }
                fsqlite_ast::BinaryOp::Eq => {
                    if is_null_op {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Integer(i64::from(
                            cmp_values(&lv, &rv) == std::cmp::Ordering::Equal,
                        ))
                    }
                }
                fsqlite_ast::BinaryOp::Ne => {
                    if is_null_op {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Integer(i64::from(
                            cmp_values(&lv, &rv) != std::cmp::Ordering::Equal,
                        ))
                    }
                }
                fsqlite_ast::BinaryOp::And => {
                    // OP_And uses sqlite3VdbeIntValue (integer truncation).
                    let l_null = matches!(lv, SqliteValue::Null);
                    let r_null = matches!(rv, SqliteValue::Null);
                    let l_truthy = is_sqlite_truthy(&lv);
                    let r_truthy = is_sqlite_truthy(&rv);
                    if (!l_truthy && !l_null) || (!r_truthy && !r_null) {
                        SqliteValue::Integer(0)
                    } else if l_null || r_null {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Integer(1)
                    }
                }
                fsqlite_ast::BinaryOp::Or => {
                    // OP_Or uses sqlite3VdbeIntValue (integer truncation).
                    let l_null = matches!(lv, SqliteValue::Null);
                    let r_null = matches!(rv, SqliteValue::Null);
                    let l_truthy = is_sqlite_truthy(&lv);
                    let r_truthy = is_sqlite_truthy(&rv);
                    if l_truthy || r_truthy {
                        SqliteValue::Integer(1)
                    } else if l_null || r_null {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Integer(0)
                    }
                }
                fsqlite_ast::BinaryOp::Add => lv.sql_add(&rv),
                fsqlite_ast::BinaryOp::Subtract => lv.sql_sub(&rv),
                fsqlite_ast::BinaryOp::Multiply => lv.sql_mul(&rv),
                fsqlite_ast::BinaryOp::Divide => numeric_div(&lv, &rv),
                fsqlite_ast::BinaryOp::Modulo => numeric_mod(&lv, &rv),
                fsqlite_ast::BinaryOp::Concat => {
                    if is_null_op {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Text(format!("{}{}", lv.to_text(), rv.to_text()).into())
                    }
                }
                fsqlite_ast::BinaryOp::BitAnd => {
                    if is_null_op {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Integer(lv.to_integer() & rv.to_integer())
                    }
                }
                fsqlite_ast::BinaryOp::BitOr => {
                    if is_null_op {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Integer(lv.to_integer() | rv.to_integer())
                    }
                }
                fsqlite_ast::BinaryOp::ShiftLeft => {
                    if is_null_op {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Integer(lv.to_integer().wrapping_shl(rv.to_integer() as u32))
                    }
                }
                fsqlite_ast::BinaryOp::ShiftRight => {
                    if is_null_op {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Integer(lv.to_integer().wrapping_shr(rv.to_integer() as u32))
                    }
                }
                _ => SqliteValue::Null,
            }
        }

        // Unary operations.
        Expr::UnaryOp {
            op, expr: inner, ..
        } => {
            let v = evaluate_having_value(inner, values, descriptors, columns, group_rows, col_map);
            match op {
                fsqlite_ast::UnaryOp::Negate => match v {
                    SqliteValue::Integer(n) => n
                        .checked_neg()
                        .map_or_else(|| SqliteValue::Float(-(n as f64)), SqliteValue::Integer),
                    SqliteValue::Float(f) => SqliteValue::Float(-f),
                    _ => SqliteValue::Null,
                },
                fsqlite_ast::UnaryOp::Not => {
                    // OP_Not uses sqlite3VdbeIntValue (integer truncation).
                    if matches!(v, SqliteValue::Null) {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Integer(i64::from(!is_sqlite_truthy(&v)))
                    }
                }
                fsqlite_ast::UnaryOp::BitNot => {
                    if matches!(v, SqliteValue::Null) {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Integer(!v.to_integer())
                    }
                }
                fsqlite_ast::UnaryOp::Plus => v,
            }
        }

        // IS NULL / IS NOT NULL.
        Expr::IsNull {
            expr: inner, not, ..
        } => {
            let v = evaluate_having_value(inner, values, descriptors, columns, group_rows, col_map);
            let is_null = matches!(v, SqliteValue::Null);
            SqliteValue::Integer(i64::from(if *not { !is_null } else { is_null }))
        }

        // BETWEEN with three-valued NULL logic.
        Expr::Between {
            expr: inner,
            low,
            high,
            not,
            ..
        } => {
            let eval =
                |e| evaluate_having_value(e, values, descriptors, columns, group_rows, col_map);
            let val = eval(inner);
            let low_val = eval(low);
            let high_val = eval(high);
            let ge_low = if val.is_null() || low_val.is_null() {
                None
            } else {
                Some(cmp_values(&val, &low_val) != std::cmp::Ordering::Less)
            };
            let le_high = if val.is_null() || high_val.is_null() {
                None
            } else {
                Some(cmp_values(&val, &high_val) != std::cmp::Ordering::Greater)
            };
            match (ge_low, le_high) {
                (Some(false), _) | (_, Some(false)) => SqliteValue::Integer(i64::from(*not)),
                (Some(true), Some(true)) => SqliteValue::Integer(i64::from(!*not)),
                _ => SqliteValue::Null,
            }
        }

        // IN with three-valued NULL logic.
        Expr::In {
            expr: inner,
            set,
            not,
            ..
        } => {
            let val =
                evaluate_having_value(inner, values, descriptors, columns, group_rows, col_map);
            if val.is_null() {
                return SqliteValue::Null;
            }
            match set {
                InSet::List(exprs) => {
                    let mut found = false;
                    let mut saw_null = false;
                    for e in exprs {
                        let set_val = evaluate_having_value(
                            e,
                            values,
                            descriptors,
                            columns,
                            group_rows,
                            col_map,
                        );
                        if set_val.is_null() {
                            saw_null = true;
                            continue;
                        }
                        if cmp_values(&val, &set_val) == std::cmp::Ordering::Equal {
                            found = true;
                            break;
                        }
                    }
                    if found {
                        SqliteValue::Integer(i64::from(!*not))
                    } else if saw_null {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Integer(i64::from(*not))
                    }
                }
                _ => SqliteValue::Null,
            }
        }

        // CASE expression.
        Expr::Case {
            operand,
            whens,
            else_expr,
            ..
        } => {
            let eval =
                |e| evaluate_having_value(e, values, descriptors, columns, group_rows, col_map);
            let base = operand.as_deref().map(eval);
            for (when_expr, then_expr) in whens {
                let when_val = eval(when_expr);
                let matches = if let Some(ref b) = base {
                    // Simple CASE: NULL base never matches (NULL = x is NULL).
                    !b.is_null()
                        && !when_val.is_null()
                        && cmp_values(b, &when_val) == std::cmp::Ordering::Equal
                } else {
                    // Searched CASE: evaluate condition truthiness.
                    is_sqlite_truthy(&when_val)
                };
                if matches {
                    return eval(then_expr);
                }
            }
            else_expr.as_deref().map_or(SqliteValue::Null, eval)
        }

        // CAST expression.
        Expr::Cast {
            expr: inner,
            type_name,
            ..
        } => {
            let v = evaluate_having_value(inner, values, descriptors, columns, group_rows, col_map);
            if v.is_null() {
                return SqliteValue::Null;
            }
            let upper = type_name.name.to_ascii_uppercase();
            if upper.contains("INT") {
                SqliteValue::Integer(v.to_integer())
            } else if upper.contains("TEXT") || upper.contains("CHAR") || upper.contains("CLOB") {
                SqliteValue::Text(v.to_text().into())
            } else if upper.contains("BLOB") || upper.is_empty() {
                match v {
                    SqliteValue::Blob(_) => v,
                    _ => SqliteValue::Blob(v.to_text().into_bytes().into()),
                }
            } else if upper.contains("REAL") || upper.contains("FLOA") || upper.contains("DOUB") {
                SqliteValue::Float(v.to_float())
            } else {
                // NUMERIC affinity: try integer, then float, else text.
                let txt = v.to_text();
                if let Ok(i) = txt.parse::<i64>() {
                    SqliteValue::Integer(i)
                } else if let Ok(f) = txt.parse::<f64>() {
                    // Reject non-finite (NaN/Inf) — sqlite3AtoF doesn't recognize them.
                    if f.is_finite() {
                        SqliteValue::Float(f)
                    } else {
                        SqliteValue::Text(txt.into())
                    }
                } else {
                    SqliteValue::Text(txt.into())
                }
            }
        }

        Expr::Like {
            expr: inner,
            pattern,
            op,
            not,
            escape,
            ..
        } => {
            let val =
                evaluate_having_value(inner, values, descriptors, columns, group_rows, col_map);
            let pat =
                evaluate_having_value(pattern, values, descriptors, columns, group_rows, col_map);
            if val.is_null() || pat.is_null() {
                return SqliteValue::Null;
            }
            let s = val.to_text();
            let p = pat.to_text();
            let esc_char = escape.as_deref().and_then(|e| {
                let v = evaluate_having_value(e, values, descriptors, columns, group_rows, col_map);
                v.to_text().chars().next()
            });
            let matched = match op {
                LikeOp::Like => simple_like_match(&p, &s, esc_char),
                LikeOp::Glob => simple_glob_match(&p, &s),
                LikeOp::Match => {
                    let match_row = group_rows.first().map_or(&[][..], Vec::as_slice);
                    match_query_with_table_columns(inner, &p, &s, match_row, col_map)
                }
                // REGEXP requires a user-defined function; this fallback
                // eval path cannot call it, so return NULL (parity: SQLite
                // errors if no regexp() function is registered).
                LikeOp::Regexp => return SqliteValue::Null,
            };
            SqliteValue::Integer(i64::from(if *not { !matched } else { matched }))
        }

        // Non-aggregate scalar function call — evaluate arguments and delegate.
        Expr::FunctionCall { name, args, .. } => {
            let arg_values: Vec<SqliteValue> = match args {
                FunctionArgs::Star => vec![],
                FunctionArgs::List(exprs) => exprs
                    .iter()
                    .map(|e| {
                        evaluate_having_value(e, values, descriptors, columns, group_rows, col_map)
                    })
                    .collect(),
            };
            eval_scalar_fn(name, &arg_values)
        }

        // COLLATE just wraps an expression — evaluate the inner expression.
        Expr::Collate { expr: inner, .. } => {
            evaluate_having_value(inner, values, descriptors, columns, group_rows, col_map)
        }

        _ => SqliteValue::Null,
    }
}

/// Evaluate a non-aggregate expression (CASE, arithmetic, etc.) against a raw
/// group row using the column map.  Returns Null on errors or unresolvable refs.
fn eval_having_expr(
    expr: &Expr,
    row: &[SqliteValue],
    col_map: &[(String, String, bool)],
) -> SqliteValue {
    eval_join_expr(expr, row, col_map).unwrap_or(SqliteValue::Null)
}

/// Compute an aggregate directly from group rows (for HAVING aggregates not in SELECT).
#[allow(clippy::cast_possible_wrap)]
fn compute_having_aggregate(
    func: &str,
    args: &FunctionArgs,
    group_rows: &[Vec<SqliteValue>],
    col_map: &[(String, String, bool)],
) -> SqliteValue {
    // Determine whether the argument is a simple column ref or a complex
    // expression that needs per-row evaluation.
    enum ArgSource {
        Star,
        ColIdx(usize),
        Expr(Expr),
    }

    let arg_source = match args {
        FunctionArgs::Star => ArgSource::Star,
        FunctionArgs::List(exprs) if exprs.is_empty() => ArgSource::Star,
        FunctionArgs::List(exprs) if exprs.len() == 1 => {
            if let Some(col_name) = expr_col_name(&exprs[0]) {
                let table_prefix = match &exprs[0] {
                    Expr::Column(cr, _) => cr.table.as_deref(),
                    _ => None,
                };
                if let Ok(idx) = find_col_in_map(col_map, table_prefix, col_name, None) {
                    ArgSource::ColIdx(idx)
                } else {
                    return SqliteValue::Null;
                }
            } else {
                // Complex expression (CASE, arithmetic, etc.) — evaluate per row.
                ArgSource::Expr(exprs[0].clone())
            }
        }
        FunctionArgs::List(_) => return SqliteValue::Null,
    };

    match arg_source {
        ArgSource::Star => {
            if func == "count" {
                SqliteValue::Integer(group_rows.len() as i64)
            } else {
                SqliteValue::Null
            }
        }
        ArgSource::ColIdx(idx) => {
            if func == "count" {
                let cnt = group_rows
                    .iter()
                    .filter(|r| r.get(idx).is_some_and(|v| !matches!(v, SqliteValue::Null)))
                    .count();
                return SqliteValue::Integer(cnt as i64);
            }
            let agg_values: Vec<&SqliteValue> = group_rows
                .iter()
                .filter_map(|r| r.get(idx))
                .filter(|v| !matches!(v, SqliteValue::Null))
                .collect();
            compute_aggregate(func, &agg_values)
        }
        ArgSource::Expr(ref expr) => {
            // Evaluate the expression for each row in the group.
            let evaluated: Vec<SqliteValue> = group_rows
                .iter()
                .map(|row| eval_having_expr(expr, row, col_map))
                .collect();
            let non_null: Vec<&SqliteValue> = evaluated
                .iter()
                .filter(|v| !matches!(v, SqliteValue::Null))
                .collect();
            if func == "count" {
                return SqliteValue::Integer(non_null.len() as i64);
            }
            compute_aggregate(func, &non_null)
        }
    }
}

/// SQL division with NULL propagation, division-by-zero → NULL, and overflow
/// promotion to REAL (matching VDBE `sql_div` semantics).
#[allow(clippy::cast_precision_loss)]
fn numeric_div(a: &SqliteValue, b: &SqliteValue) -> SqliteValue {
    if a.is_null() || b.is_null() {
        return SqliteValue::Null;
    }
    if let (SqliteValue::Integer(ai), SqliteValue::Integer(bi)) = (a, b) {
        if *bi == 0 {
            SqliteValue::Null
        } else {
            match ai.checked_div(*bi) {
                Some(result) => SqliteValue::Integer(result),
                // i64::MIN / -1 overflows; C SQLite promotes to float
                // via `goto fp_math` (vdbe.c:1916).
                #[allow(clippy::cast_precision_loss)]
                None => {
                    let result = *ai as f64 / *bi as f64;
                    if result.is_nan() {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Float(result)
                    }
                }
            }
        }
    } else {
        let bf = b.to_float();
        if bf == 0.0 {
            SqliteValue::Null
        } else {
            let result = a.to_float() / bf;
            if result.is_nan() {
                SqliteValue::Null
            } else {
                SqliteValue::Float(result)
            }
        }
    }
}

/// SQL remainder with NULL propagation and division-by-zero → NULL.
///
/// C SQLite: both-integer → Integer result; otherwise fp_math (fmod) → Float result.
#[allow(clippy::cast_precision_loss)]
fn numeric_mod(a: &SqliteValue, b: &SqliteValue) -> SqliteValue {
    if a.is_null() || b.is_null() {
        return SqliteValue::Null;
    }
    let both_int = matches!((a, b), (SqliteValue::Integer(_), SqliteValue::Integer(_)));
    if both_int {
        let ai = a.to_integer();
        let bi = b.to_integer();
        if bi == 0 {
            SqliteValue::Null
        } else {
            SqliteValue::Integer(ai.checked_rem(bi).unwrap_or(0))
        }
    } else {
        // C SQLite uses fmod() for non-integer operands.
        let af = a.to_float();
        let bf = b.to_float();
        if bf == 0.0 {
            SqliteValue::Null
        } else {
            let result = af % bf;
            if result.is_nan() {
                SqliteValue::Null
            } else {
                SqliteValue::Float(result)
            }
        }
    }
}

/// Compare two `SqliteValue`s for ordering.
///
/// SQLite type ordering: NULL < INTEGER/REAL < TEXT < BLOB.
/// Within the same type class, values compare naturally.
/// Integer-float comparisons use precision-preserving algorithm.
fn cmp_values(a: &SqliteValue, b: &SqliteValue) -> std::cmp::Ordering {
    use std::cmp::Ordering;

    /// Return a numeric rank for the SQLite type affinity ordering.
    fn type_rank(v: &SqliteValue) -> u8 {
        match v {
            SqliteValue::Null => 0,
            SqliteValue::Integer(_) | SqliteValue::Float(_) => 1,
            SqliteValue::Text(_) => 2,
            SqliteValue::Blob(_) => 3,
        }
    }

    /// Precision-preserving integer-float comparison (avoids lossy `as f64`).
    fn int_float_cmp(i: i64, r: f64) -> Ordering {
        fsqlite_types::value::int_float_cmp(i, r)
    }

    /// Try to coerce a text string to a numeric `SqliteValue`.
    /// Returns `Some(Integer|Float)` if the *entire* string (after trimming
    /// whitespace) is a valid number, matching SQLite's affinity coercion
    /// rule for TEXT-vs-numeric comparisons.
    fn try_text_to_numeric(s: &str) -> Option<SqliteValue> {
        let trimmed = s.trim();
        if trimmed.is_empty() {
            return None;
        }
        let bytes = trimmed.as_bytes();
        let end = {
            let mut i = 0usize;
            if bytes[i] == b'+' || bytes[i] == b'-' {
                i += 1;
            }
            let digit_start = i;
            while i < bytes.len() && bytes[i].is_ascii_digit() {
                i += 1;
            }
            if i < bytes.len() && bytes[i] == b'.' {
                i += 1;
                while i < bytes.len() && bytes[i].is_ascii_digit() {
                    i += 1;
                }
            }
            if i == digit_start {
                return None;
            }
            if i < bytes.len() && (bytes[i] == b'e' || bytes[i] == b'E') {
                let exp_start = i;
                i += 1;
                if i < bytes.len() && (bytes[i] == b'+' || bytes[i] == b'-') {
                    i += 1;
                }
                if i < bytes.len() && bytes[i].is_ascii_digit() {
                    while i < bytes.len() && bytes[i].is_ascii_digit() {
                        i += 1;
                    }
                } else {
                    i = exp_start;
                }
            }
            i
        };
        // Entire string (after trim) must be consumed for coercion.
        if end != trimmed.len() {
            return None;
        }
        let has_decimal = trimmed.bytes().any(|b| matches!(b, b'.' | b'e' | b'E'));
        if !has_decimal {
            if let Ok(v) = trimmed.parse::<i64>() {
                return Some(SqliteValue::Integer(v));
            }
        }
        if let Ok(v) = trimmed.parse::<f64>() {
            // If it's an exact integer value, store as Integer.
            #[allow(clippy::cast_possible_truncation, clippy::cast_precision_loss)]
            if v.is_finite()
                && (-9_223_372_036_854_775_808.0..9_223_372_036_854_775_808.0).contains(&v)
            {
                let truncated = v as i64;
                #[allow(clippy::float_cmp)]
                if truncated as f64 == v && !has_decimal {
                    return Some(SqliteValue::Integer(truncated));
                }
            }
            return Some(SqliteValue::Float(v));
        }
        None
    }

    let rank_a = type_rank(a);
    let rank_b = type_rank(b);
    if rank_a != rank_b {
        // Apply affinity coercion: TEXT vs numeric → try to coerce TEXT to number.
        // This matches SQLite's column-affinity comparison rule (Section 4.2).
        match (a, b) {
            (SqliteValue::Text(s), SqliteValue::Integer(_) | SqliteValue::Float(_)) => {
                if let Some(coerced) = try_text_to_numeric(s) {
                    return cmp_values(&coerced, b);
                }
            }
            (SqliteValue::Integer(_) | SqliteValue::Float(_), SqliteValue::Text(s)) => {
                if let Some(coerced) = try_text_to_numeric(s) {
                    return cmp_values(a, &coerced);
                }
            }
            _ => {}
        }
        return rank_a.cmp(&rank_b);
    }

    match (a, b) {
        (SqliteValue::Null, SqliteValue::Null) => Ordering::Equal,
        (SqliteValue::Integer(ai), SqliteValue::Integer(bi)) => ai.cmp(bi),
        (SqliteValue::Float(af), SqliteValue::Float(bf)) => {
            af.partial_cmp(bf).unwrap_or(Ordering::Equal)
        }
        (SqliteValue::Integer(ai), SqliteValue::Float(bf)) => int_float_cmp(*ai, *bf),
        (SqliteValue::Float(af), SqliteValue::Integer(bi)) => int_float_cmp(*bi, *af).reverse(),
        (SqliteValue::Text(at), SqliteValue::Text(bt)) => at.cmp(bt),
        (SqliteValue::Blob(ab), SqliteValue::Blob(bb)) => ab.cmp(bb),
        _ => unreachable!("same rank guarantees same type class"),
    }
}

/// Compare two values using pure storage-class ordering **without** TEXT→numeric
/// coercion. In SQLite, TEXT→numeric coercion only applies when a column with
/// INTEGER/REAL/NUMERIC affinity is involved (Section 4.2). When both operands
/// come from untyped (BLOB/NONE affinity) columns, values of different storage
/// classes are ordered by class rank: NULL < numeric < TEXT < BLOB.
#[allow(dead_code)]
fn cmp_values_no_affinity(a: &SqliteValue, b: &SqliteValue) -> std::cmp::Ordering {
    use std::cmp::Ordering;

    fn type_rank(v: &SqliteValue) -> u8 {
        match v {
            SqliteValue::Null => 0,
            SqliteValue::Integer(_) | SqliteValue::Float(_) => 1,
            SqliteValue::Text(_) => 2,
            SqliteValue::Blob(_) => 3,
        }
    }

    fn int_float_cmp(i: i64, r: f64) -> Ordering {
        fsqlite_types::value::int_float_cmp(i, r)
    }

    let rank_a = type_rank(a);
    let rank_b = type_rank(b);
    if rank_a != rank_b {
        return rank_a.cmp(&rank_b);
    }

    match (a, b) {
        (SqliteValue::Null, SqliteValue::Null) => Ordering::Equal,
        (SqliteValue::Integer(ai), SqliteValue::Integer(bi)) => ai.cmp(bi),
        (SqliteValue::Float(af), SqliteValue::Float(bf)) => {
            af.partial_cmp(bf).unwrap_or(Ordering::Equal)
        }
        (SqliteValue::Integer(ai), SqliteValue::Float(bf)) => int_float_cmp(*ai, *bf),
        (SqliteValue::Float(af), SqliteValue::Integer(bi)) => int_float_cmp(*bi, *af).reverse(),
        (SqliteValue::Text(at), SqliteValue::Text(bt)) => at.cmp(bt),
        (SqliteValue::Blob(ab), SqliteValue::Blob(bb)) => ab.cmp(bb),
        _ => unreachable!("same rank guarantees same type class"),
    }
}

/// Determine whether a comparison between two expressions should apply
/// TEXT→numeric affinity coercion (SQLite Section 4.2 rules).
/// Returns true if at least one expression references a column with
/// INTEGER, REAL, or NUMERIC type affinity.
#[allow(dead_code)]
fn should_coerce_for_comparison(
    left: &Expr,
    right: &Expr,
    col_map: &[(String, String, bool)],
    schemas: &[TableSchema],
) -> bool {
    fn expr_has_numeric_affinity(
        expr: &Expr,
        col_map: &[(String, String, bool)],
        schemas: &[TableSchema],
    ) -> bool {
        if let Expr::Column(col_ref, _) = expr {
            let col_name = &col_ref.column;
            let table_prefix = col_ref.table.as_deref();
            // Look up the table name from col_map.
            if let Some((table_name, _, _)) = col_map.iter().find(|(tbl, col, _)| {
                col.eq_ignore_ascii_case(col_name)
                    && table_prefix.is_none_or(|p| tbl.eq_ignore_ascii_case(p))
            }) {
                // Find the table schema.
                if let Some(schema) = schemas
                    .iter()
                    .find(|s| s.name.eq_ignore_ascii_case(table_name))
                {
                    if let Some(col_def) = schema
                        .columns
                        .iter()
                        .find(|c| c.name.eq_ignore_ascii_case(col_name))
                    {
                        // Check if the column's declared type implies numeric affinity.
                        let ty = col_def.type_name.as_deref().unwrap_or("").to_uppercase();
                        // SQLite affinity rules: INT → INTEGER, REAL/FLOA/DOUB → REAL,
                        // TEXT/CHAR/CLOB → TEXT, BLOB or empty → NONE.
                        // NUMERIC affinity for anything else.
                        if ty.is_empty() || ty.contains("BLOB") {
                            return false; // NONE affinity
                        }
                        if ty.contains("INT")
                            || ty.contains("REAL")
                            || ty.contains("FLOA")
                            || ty.contains("DOUB")
                            || ty.contains("NUMERIC")
                            || ty.contains("NUM")
                        {
                            return true;
                        }
                        if ty.contains("TEXT") || ty.contains("CHAR") || ty.contains("CLOB") {
                            return false; // TEXT affinity
                        }
                        // Default: NUMERIC affinity
                        return true;
                    }
                }
            }
        }
        false
    }
    expr_has_numeric_affinity(left, col_map, schemas)
        || expr_has_numeric_affinity(right, col_map, schemas)
}

/// Return the empty-set default for an aggregate function.
///
/// SQLite: `COUNT` → 0, `TOTAL` → 0.0, everything else → NULL.
fn empty_aggregate_default(name: &str) -> SqliteValue {
    match name {
        "count" => SqliteValue::Integer(0),
        "total" => SqliteValue::Float(0.0),
        _ => SqliteValue::Null,
    }
}

/// Kahan-Babuska-Neumaier compensated summation step (matches C SQLite func.c:1871).
#[inline]
fn kbn_step(sum: &mut f64, err: &mut f64, value: f64) {
    let s = *sum;
    let t = s + value;
    if s.abs() > value.abs() {
        *err += (s - t) + value;
    } else {
        *err += (value - t) + s;
    }
    *sum = t;
}

/// Compute the aggregate value for a group of values.
#[allow(clippy::cast_possible_wrap)]
fn compute_aggregate(name: &str, values: &[&SqliteValue]) -> SqliteValue {
    match name {
        "count" => SqliteValue::Integer(values.len() as i64),
        "sum" | "total" => {
            // SQLite: total() always returns 0.0 for empty input;
            // sum() returns NULL when all values are NULL (empty after pre-filter).
            if values.is_empty() {
                return if name == "total" {
                    SqliteValue::Float(0.0)
                } else {
                    SqliteValue::Null
                };
            }
            let mut sum = 0.0_f64;
            let mut err = 0.0_f64;
            let mut has_int = false;
            let mut all_int = true;
            let mut int_sum = 0_i64;
            let mut int_overflowed = false;
            for v in values {
                match v {
                    SqliteValue::Integer(n) => {
                        has_int = true;
                        if !int_overflowed {
                            match int_sum.checked_add(*n) {
                                Some(s) => int_sum = s,
                                None => int_overflowed = true,
                            }
                        }
                        kbn_step(&mut sum, &mut err, *n as f64);
                    }
                    SqliteValue::Float(f) => {
                        all_int = false;
                        kbn_step(&mut sum, &mut err, *f);
                    }
                    SqliteValue::Null => {}
                    other => {
                        // Text/Blob: coerce to float (C SQLite's sqlite3_value_double).
                        all_int = false;
                        kbn_step(&mut sum, &mut err, other.to_float());
                    }
                }
            }
            if name == "total" {
                SqliteValue::Float(sum + err)
            } else if has_int && all_int && !int_overflowed {
                SqliteValue::Integer(int_sum)
            } else {
                // Integer overflow or mixed types: return float.
                SqliteValue::Float(sum + err)
            }
        }
        "avg" => {
            if values.is_empty() {
                return SqliteValue::Null;
            }
            let mut sum = 0.0_f64;
            let mut err = 0.0_f64;
            let mut count = 0_u64;
            for v in values {
                match v {
                    SqliteValue::Null => {}
                    SqliteValue::Integer(n) => {
                        kbn_step(&mut sum, &mut err, *n as f64);
                        count += 1;
                    }
                    SqliteValue::Float(f) => {
                        kbn_step(&mut sum, &mut err, *f);
                        count += 1;
                    }
                    other => {
                        // Text/Blob: coerce to float (C SQLite's sqlite3_value_double).
                        kbn_step(&mut sum, &mut err, other.to_float());
                        count += 1;
                    }
                }
            }
            if count == 0 {
                SqliteValue::Null
            } else {
                SqliteValue::Float((sum + err) / count as f64)
            }
        }
        "min" => values
            .iter()
            .filter(|v| !matches!(v, SqliteValue::Null))
            .min_by(|a, b| cmp_sqlite_values(a, b))
            .map_or(SqliteValue::Null, |v| (*v).clone()),
        "max" => values
            .iter()
            .filter(|v| !matches!(v, SqliteValue::Null))
            .max_by(|a, b| cmp_sqlite_values(a, b))
            .map_or(SqliteValue::Null, |v| (*v).clone()),
        "group_concat" | "string_agg" => {
            let parts: Vec<String> = values
                .iter()
                .filter(|v| !matches!(v, SqliteValue::Null))
                .map(|v| v.to_text())
                .collect();
            // SQLite: GROUP_CONCAT returns NULL when all values are NULL.
            if parts.is_empty() {
                SqliteValue::Null
            } else {
                SqliteValue::Text(parts.join(",").into())
            }
        }
        _ => SqliteValue::Null,
    }
}

/// Extended aggregate computation with optional DISTINCT dedup already applied
/// and an explicit separator for `GROUP_CONCAT`.
#[allow(clippy::cast_possible_wrap)]
fn compute_aggregate_ext(
    name: &str,
    values: &[&SqliteValue],
    separator: Option<&str>,
) -> SqliteValue {
    if (name == "group_concat" || name == "string_agg") && separator.is_some() {
        let sep = separator.unwrap_or(",");
        let parts: Vec<String> = values
            .iter()
            .filter(|v| !matches!(v, SqliteValue::Null))
            .map(|v| v.to_text())
            .collect();
        if parts.is_empty() {
            SqliteValue::Null
        } else {
            SqliteValue::Text(parts.join(sep).into())
        }
    } else {
        compute_aggregate(name, values)
    }
}

/// Remove duplicate values in-place, preserving first-occurrence order.
fn dedup_values(values: &mut Vec<&SqliteValue>) {
    let mut seen = Vec::new();
    values.retain(|v| {
        if seen.contains(v) {
            false
        } else {
            seen.push(*v);
            true
        }
    });
}

/// Collation-aware duplicate removal. When a collation is specified (e.g.
/// `NOCASE`), text values are compared through the collation registry so
/// that `'Alice'` and `'alice'` are treated as equal.
fn dedup_values_collated(
    values: &mut Vec<&SqliteValue>,
    collation: Option<&str>,
    collation_registry: &Mutex<CollationRegistry>,
) {
    if collation.is_none() {
        dedup_values(values);
        return;
    }
    let snap = collation_registry
        .lock()
        .map(|r| r.clone())
        .unwrap_or_default();
    let mut seen: Vec<&SqliteValue> = Vec::new();
    values.retain(|v| {
        let already = seen.iter().any(|s| {
            cmp_sqlite_values_collated_snapshot(v, s, collation, &snap) == std::cmp::Ordering::Equal
        });
        if already {
            false
        } else {
            seen.push(*v);
            true
        }
    });
}

/// Determine the effective collation for an aggregate argument expression
/// by checking explicit COLLATE first, then looking up the column's
/// declared collation in the schema.  Returns `None` for the default
/// BINARY collation to allow the fast binary-comparison path.
fn agg_arg_collation(expr: &Expr, schemas: &[TableSchema]) -> Option<String> {
    // Explicit COLLATE takes priority.
    if let Expr::Collate { collation, .. } = expr {
        if collation.eq_ignore_ascii_case("BINARY") {
            return None;
        }
        return Some(collation.clone());
    }
    // Column reference: look up in the schema.
    if let Expr::Column(cr, _) = expr {
        for ts in schemas {
            let matches = cr
                .table
                .as_ref()
                .is_none_or(|t| t.eq_ignore_ascii_case(&ts.name));
            if matches {
                if let Some(ci) = ts
                    .columns
                    .iter()
                    .find(|c| c.name.eq_ignore_ascii_case(&cr.column))
                {
                    if let Some(ref coll) = ci.collation {
                        if !coll.eq_ignore_ascii_case("BINARY") {
                            return Some(coll.clone());
                        }
                    }
                }
            }
        }
    }
    None
}

/// Extended aggregate computation with optional collation for MIN/MAX.
#[allow(clippy::cast_possible_wrap)]
fn compute_aggregate_ext_collated(
    name: &str,
    values: &[&SqliteValue],
    separator: Option<&str>,
    collation: Option<&str>,
    collation_registry: &Mutex<CollationRegistry>,
) -> SqliteValue {
    // For MIN/MAX with a non-default collation, use collation-aware comparison.
    if collation.is_some() && (name == "min" || name == "max") {
        let snap = collation_registry
            .lock()
            .map(|r| r.clone())
            .unwrap_or_default();
        let filtered = values.iter().filter(|v| !matches!(v, SqliteValue::Null));
        let result = if name == "min" {
            filtered.min_by(|a, b| cmp_sqlite_values_collated_snapshot(a, b, collation, &snap))
        } else {
            filtered.max_by(|a, b| cmp_sqlite_values_collated_snapshot(a, b, collation, &snap))
        };
        return result.map_or(SqliteValue::Null, |v| (*v).clone());
    }
    compute_aggregate_ext(name, values, separator)
}

/// Compare two `SqliteValue`s for ordering.
///
/// SQLite type ordering: NULL < INTEGER/REAL < TEXT < BLOB.
/// Within the same type class, values compare naturally.
fn cmp_sqlite_values(a: &SqliteValue, b: &SqliteValue) -> std::cmp::Ordering {
    use std::cmp::Ordering;

    /// Return a numeric rank for the SQLite type affinity ordering.
    fn type_rank(v: &SqliteValue) -> u8 {
        match v {
            SqliteValue::Null => 0,
            SqliteValue::Integer(_) | SqliteValue::Float(_) => 1,
            SqliteValue::Text(_) => 2,
            SqliteValue::Blob(_) => 3,
        }
    }

    let rank_a = type_rank(a);
    let rank_b = type_rank(b);
    if rank_a != rank_b {
        return rank_a.cmp(&rank_b);
    }

    /// Precision-preserving integer-float comparison.
    fn int_float_cmp(i: i64, r: f64) -> Ordering {
        fsqlite_types::value::int_float_cmp(i, r)
    }

    // Same type class — compare within class.
    match (a, b) {
        (SqliteValue::Null, SqliteValue::Null) => Ordering::Equal,
        (SqliteValue::Integer(a), SqliteValue::Integer(b)) => a.cmp(b),
        (SqliteValue::Float(a), SqliteValue::Float(b)) => {
            a.partial_cmp(b).unwrap_or(Ordering::Equal)
        }
        (SqliteValue::Integer(a), SqliteValue::Float(b)) => int_float_cmp(*a, *b),
        (SqliteValue::Float(a), SqliteValue::Integer(b)) => int_float_cmp(*b, *a).reverse(),
        (SqliteValue::Text(a), SqliteValue::Text(b)) => a.cmp(b),
        (SqliteValue::Blob(a), SqliteValue::Blob(b)) => a.cmp(b),
        _ => unreachable!("unreachable given rank check above"),
    }
}

/// Compare text bytes using a pre-snapshotted collation registry.
/// Avoids mutex acquisition on every comparison in O(N log N) sort loops.
#[cfg_attr(not(test), allow(dead_code))]
fn compare_text_bytes_collated(
    left: &[u8],
    right: &[u8],
    collation: &str,
    collation_registry: &Mutex<CollationRegistry>,
) -> std::cmp::Ordering {
    let compare_with = |registry: &CollationRegistry| {
        registry
            .find(collation)
            .map(|collation| collation.compare(left, right))
    };

    compare_with(&lock_unpoisoned(collation_registry)).unwrap_or_else(|| left.cmp(right))
}

/// Compare text bytes using a pre-snapshotted collation registry.
/// Avoids mutex acquisition on every comparison in O(N log N) sort loops.
fn compare_text_bytes_collated_snapshot(
    left: &[u8],
    right: &[u8],
    collation: &str,
    registry: &CollationRegistry,
) -> std::cmp::Ordering {
    registry
        .find(collation)
        .map(|coll_fn| coll_fn.compare(left, right))
        .unwrap_or_else(|| left.cmp(right))
}

/// Lock-free variant using a pre-snapshotted registry.
#[allow(dead_code)]
fn cmp_sqlite_values_collated(
    a: &SqliteValue,
    b: &SqliteValue,
    collation: Option<&str>,
    collation_registry: &Mutex<CollationRegistry>,
) -> std::cmp::Ordering {
    if let (Some(coll), SqliteValue::Text(at), SqliteValue::Text(bt)) = (collation, a, b) {
        return compare_text_bytes_collated(at.as_bytes(), bt.as_bytes(), coll, collation_registry);
    }
    cmp_sqlite_values(a, b)
}

/// Lock-free variant using a pre-snapshotted registry.
fn cmp_sqlite_values_collated_snapshot(
    a: &SqliteValue,
    b: &SqliteValue,
    collation: Option<&str>,
    registry: &CollationRegistry,
) -> std::cmp::Ordering {
    if let (Some(coll), SqliteValue::Text(at), SqliteValue::Text(bt)) = (collation, a, b) {
        return compare_text_bytes_collated_snapshot(at.as_bytes(), bt.as_bytes(), coll, registry);
    }
    cmp_sqlite_values(a, b)
}

/// Compare two GROUP BY key vectors with per-element collation.
fn group_keys_equal_collated(
    a: &[SqliteValue],
    b: &[SqliteValue],
    collations: &[Option<String>],
    coll_snap: &CollationRegistry,
) -> bool {
    if a.len() != b.len() {
        return false;
    }
    a.iter().zip(b.iter()).enumerate().all(|(i, (av, bv))| {
        let coll = collations.get(i).and_then(|c| c.as_deref());
        cmp_sqlite_values_collated_snapshot(av, bv, coll, coll_snap) == std::cmp::Ordering::Equal
    })
}

/// Determine the effective collation for a GROUP BY expression.
/// Explicit COLLATE in the expression takes priority, otherwise
/// inherit the column's declared collation from the table schema.
fn expr_effective_collation_for_table(expr: &Expr, schema: &TableSchema) -> Option<String> {
    if let Expr::Collate { collation, .. } = expr {
        return Some(collation.clone());
    }
    if let Expr::Column(cr, _) = expr {
        return schema
            .columns
            .iter()
            .find(|c| c.name.eq_ignore_ascii_case(&cr.column))
            .and_then(|c| c.collation.clone());
    }
    None
}

/// Try to resolve an ORDER BY expression to a column index in `columns`.
/// Returns `None` if the expression doesn't match any column.
fn resolve_order_term_idx(expr: &Expr, columns: &[ResultColumn]) -> Option<usize> {
    if let Expr::Literal(Literal::Integer(n), _) = expr {
        let pos = usize::try_from(*n).unwrap_or(0);
        if pos >= 1 && pos <= columns.len() {
            return Some(pos - 1);
        }
    }
    if let Some(col_name) = expr_col_name(expr) {
        let found = columns.iter().position(|c| match c {
            ResultColumn::Expr {
                expr: Expr::Column(r, _),
                ..
            } => r.column.eq_ignore_ascii_case(col_name),
            ResultColumn::Expr {
                alias: Some(alias), ..
            } => alias.eq_ignore_ascii_case(col_name),
            _ => false,
        });
        if found.is_some() {
            return found;
        }
    }
    columns.iter().position(|c| match c {
        ResultColumn::Expr { expr: e, .. } => exprs_match(expr, e),
        _ => false,
    })
}

/// Sort result rows by ORDER BY terms (for GROUP BY post-processing).
/// `col_collations` maps result column index to collation name
/// (e.g. "NOCASE") for collation-aware sorting.
fn sort_rows_by_order_terms(
    rows: &mut [Row],
    order_by: &[OrderingTerm],
    columns: &[ResultColumn],
    col_collations: &[Option<String>],
    collation_registry: &Mutex<CollationRegistry>,
) -> Result<()> {
    let resolved: Vec<(usize, bool, NullsOrder, Option<String>)> = order_by
        .iter()
        .map(|term| {
            // Try integer position reference first (ORDER BY 1, 2).
            let idx = if let Expr::Literal(Literal::Integer(n), _) = &term.expr {
                let pos = usize::try_from(*n).unwrap_or(0);
                if pos >= 1 && pos <= columns.len() {
                    Some(pos - 1)
                } else {
                    None
                }
            } else if let Some(col_name) = expr_col_name(&term.expr) {
                // Extract optional table qualifier from ORDER BY column ref.
                let order_table = if let Expr::Column(cr, _) = &term.expr {
                    cr.table.as_deref()
                } else {
                    None
                };
                columns.iter().position(|c| match c {
                    ResultColumn::Expr {
                        expr: Expr::Column(r, _),
                        ..
                    } => {
                        if !r.column.eq_ignore_ascii_case(col_name) {
                            return false;
                        }
                        // If the ORDER BY has a table qualifier, the result
                        // column must have a matching qualifier.
                        if let Some(tbl) = order_table {
                            r.table
                                .as_ref()
                                .is_some_and(|rt| rt.eq_ignore_ascii_case(tbl))
                        } else {
                            true
                        }
                    }
                    ResultColumn::Expr {
                        alias: Some(alias), ..
                    } => alias.eq_ignore_ascii_case(col_name),
                    _ => false,
                })
            } else {
                // Expression ORDER BY: match structurally against result columns.
                columns.iter().position(|c| match c {
                    ResultColumn::Expr { expr, .. } => exprs_match(&term.expr, expr),
                    _ => false,
                })
            };
            let idx = idx.ok_or_else(|| {
                FrankenError::Internal("ORDER BY expression not found in SELECT list".to_owned())
            })?;
            let desc = matches!(term.direction, Some(SortDirection::Desc));
            let nulls = term
                .nulls
                .unwrap_or_else(|| default_nulls_order(term.direction));
            let coll = match &term.expr {
                Expr::Collate { collation, .. } => Some(collation.clone()),
                _ => col_collations.get(idx).cloned().flatten(),
            };
            Ok((idx, desc, nulls, coll))
        })
        .collect::<Result<Vec<_>>>()?;

    // Snapshot collation registry once before the sort to avoid locking the
    // mutex on every comparison (§14.9 seqlock-inspired optimization).
    // Under O(N log N) sorting, this eliminates N×log(N) mutex acquisitions.
    let coll_snapshot = lock_unpoisoned(collation_registry).clone();

    rows.sort_by(|a, b| {
        for (idx, desc, nulls, coll) in &resolved {
            let av = &a.values()[*idx];
            let bv = &b.values()[*idx];
            let a_null = av.is_null();
            let b_null = bv.is_null();
            if a_null || b_null {
                if a_null && b_null {
                    continue;
                }
                let ord = match (a_null, *nulls) {
                    (true, NullsOrder::First) | (false, NullsOrder::Last) => {
                        std::cmp::Ordering::Less
                    }
                    (true, NullsOrder::Last) | (false, NullsOrder::First) => {
                        std::cmp::Ordering::Greater
                    }
                };
                return ord;
            }
            let ord = cmp_sqlite_values_collated_snapshot(av, bv, coll.as_deref(), &coll_snapshot);
            let ord = if *desc { ord.reverse() } else { ord };
            if ord != std::cmp::Ordering::Equal {
                return ord;
            }
        }
        std::cmp::Ordering::Equal
    });

    Ok(())
}

/// Convert an AST `ForeignKeyClause` to a codegen `FkDef`.
fn fk_clause_to_def(child_indices: &[usize], clause: &fsqlite_ast::ForeignKeyClause) -> FkDef {
    let mut on_delete = FkActionType::NoAction;
    let mut on_update = FkActionType::NoAction;
    for action in &clause.actions {
        let action_type = match action.action {
            fsqlite_ast::ForeignKeyActionType::SetNull => FkActionType::SetNull,
            fsqlite_ast::ForeignKeyActionType::SetDefault => FkActionType::SetDefault,
            fsqlite_ast::ForeignKeyActionType::Cascade => FkActionType::Cascade,
            fsqlite_ast::ForeignKeyActionType::Restrict => FkActionType::Restrict,
            fsqlite_ast::ForeignKeyActionType::NoAction => FkActionType::NoAction,
        };
        match action.trigger {
            fsqlite_ast::ForeignKeyTrigger::OnDelete => on_delete = action_type,
            fsqlite_ast::ForeignKeyTrigger::OnUpdate => on_update = action_type,
        }
    }
    FkDef {
        child_columns: child_indices.to_vec(),
        parent_table: clause.table.clone(),
        parent_columns: clause.columns.clone(),
        on_delete,
        on_update,
    }
}

/// Map an AST type name to a codegen affinity character.
fn type_name_to_affinity_char(name: &str) -> char {
    let upper = name.to_uppercase();
    if upper.contains("INT") {
        'D' // INTEGER affinity
    } else if upper.contains("CHAR") || upper.contains("TEXT") || upper.contains("CLOB") {
        'B' // TEXT affinity
    } else if upper.contains("BLOB") || upper.is_empty() {
        'A' // BLOB (none) affinity
    } else if upper.contains("REAL") || upper.contains("FLOA") || upper.contains("DOUB") {
        'E' // REAL affinity
    } else {
        'C' // NUMERIC affinity
    }
}

/// Format a `DefaultValue` AST node as SQL text for PRAGMA table_info output.
fn format_default_value(dv: &DefaultValue) -> String {
    match dv {
        DefaultValue::Expr(expr) => expr.to_string(),
        DefaultValue::ParenExpr(expr) => format!("({})", expr),
    }
}

fn validate_default_value_is_constant(column_name: &str, dv: &DefaultValue) -> Result<()> {
    let expr = match dv {
        DefaultValue::Expr(expr) | DefaultValue::ParenExpr(expr) => expr,
    };
    if default_expr_is_self_contained(expr) {
        Ok(())
    } else {
        Err(FrankenError::Internal(format!(
            "default value of column [{column_name}] is not constant"
        )))
    }
}

fn default_expr_is_self_contained(expr: &Expr) -> bool {
    match expr {
        Expr::Literal(_, _) => true,
        Expr::Column(_, _)
        | Expr::Exists { .. }
        | Expr::Subquery(_, _)
        | Expr::Raise { .. }
        | Expr::RowValue(_, _)
        | Expr::Placeholder(_, _) => false,
        Expr::BinaryOp { left, right, .. } => {
            default_expr_is_self_contained(left) && default_expr_is_self_contained(right)
        }
        Expr::UnaryOp { expr: inner, .. }
        | Expr::Cast { expr: inner, .. }
        | Expr::Collate { expr: inner, .. }
        | Expr::IsNull { expr: inner, .. } => default_expr_is_self_contained(inner),
        Expr::Between {
            expr: inner,
            low,
            high,
            ..
        } => {
            default_expr_is_self_contained(inner)
                && default_expr_is_self_contained(low)
                && default_expr_is_self_contained(high)
        }
        Expr::In {
            expr: inner, set, ..
        } => {
            default_expr_is_self_contained(inner)
                && match set {
                    InSet::List(exprs) => exprs.iter().all(default_expr_is_self_contained),
                    InSet::Subquery(_) | InSet::Table(_) => false,
                }
        }
        Expr::Like {
            expr: inner,
            pattern,
            escape,
            ..
        } => {
            default_expr_is_self_contained(inner)
                && default_expr_is_self_contained(pattern)
                && escape.as_deref().is_none_or(default_expr_is_self_contained)
        }
        Expr::Case {
            operand,
            whens,
            else_expr,
            ..
        } => {
            operand
                .as_deref()
                .is_none_or(default_expr_is_self_contained)
                && whens.iter().all(|(when_expr, then_expr)| {
                    default_expr_is_self_contained(when_expr)
                        && default_expr_is_self_contained(then_expr)
                })
                && else_expr
                    .as_deref()
                    .is_none_or(default_expr_is_self_contained)
        }
        Expr::FunctionCall {
            args,
            distinct,
            order_by,
            filter,
            over,
            ..
        } => {
            !distinct
                && order_by.is_empty()
                && filter.is_none()
                && over.is_none()
                && match args {
                    FunctionArgs::Star => false,
                    FunctionArgs::List(exprs) => exprs.iter().all(default_expr_is_self_contained),
                }
        }
        Expr::JsonAccess {
            expr: inner, path, ..
        } => default_expr_is_self_contained(inner) && default_expr_is_self_contained(path),
    }
}

/// Convert a `CodegenError` to a `FrankenError`.
/// Shared empty Arc for column defaults — avoids per-statement heap allocation
/// when no tables have column defaults (the common case for read-only queries).
fn empty_column_defaults_arc() -> Arc<HbHashMap<i32, Vec<Option<SqliteValue>>>> {
    use std::sync::OnceLock;
    static EMPTY: OnceLock<Arc<HbHashMap<i32, Vec<Option<SqliteValue>>>>> = OnceLock::new();
    Arc::clone(EMPTY.get_or_init(|| Arc::new(HbHashMap::new())))
}

fn codegen_error_to_franken(e: CodegenError) -> FrankenError {
    match e {
        CodegenError::TableNotFound(name) => {
            FrankenError::Internal(format!("no such table: {name}",))
        }
        CodegenError::ColumnNotFound { table, column } => {
            FrankenError::Internal(format!("no such column: {column} in table {table}",))
        }
        CodegenError::Unsupported(msg) => FrankenError::NotImplemented(msg),
    }
}

/// Short label for a statement type, used in EXPLAIN error messages.
fn stmt_kind_label(stmt: &Statement) -> &'static str {
    match stmt {
        Statement::Select(_) => "SELECT",
        Statement::Insert(_) => "INSERT",
        Statement::Update(_) => "UPDATE",
        Statement::Delete(_) => "DELETE",
        Statement::CreateTable(_) => "CREATE TABLE",
        Statement::CreateVirtualTable(_) => "CREATE VIRTUAL TABLE",
        Statement::Drop(_) => "DROP",
        Statement::AlterTable(_) => "ALTER TABLE",
        Statement::CreateIndex(_) => "CREATE INDEX",
        Statement::CreateView(_) => "CREATE VIEW",
        Statement::CreateTrigger(_) => "CREATE TRIGGER",
        Statement::Pragma(_) => "PRAGMA",
        Statement::Begin(_) => "BEGIN",
        Statement::Commit => "COMMIT",
        Statement::Rollback(_) => "ROLLBACK",
        Statement::Savepoint(_) => "SAVEPOINT",
        Statement::Release(_) => "RELEASE",
        Statement::Vacuum(_) => "VACUUM",
        Statement::Analyze(_) => "ANALYZE",
        Statement::Reindex(_) => "REINDEX",
        Statement::Explain { .. } => "EXPLAIN",
        _ => "unknown",
    }
}

/// Extract the first table name from a `SelectCore` for EXPLAIN QUERY PLAN.
fn first_table_name_from_core(core: &SelectCore) -> Option<String> {
    match core {
        SelectCore::Select { from, .. } => {
            let from_clause = from.as_ref()?;
            match &from_clause.source {
                TableOrSubquery::Table { name, .. } => Some(name.name.clone()),
                _ => None,
            }
        }
        SelectCore::Values(_) => None,
    }
}

fn planner_needed_columns(
    columns: &[ResultColumn],
    table_name: &str,
    table_alias: Option<&str>,
) -> Option<Vec<String>> {
    let mut needed = Vec::with_capacity(columns.len());
    for column in columns {
        let ResultColumn::Expr { expr, .. } = column else {
            return None;
        };
        let Expr::Column(column_ref, _) = expr else {
            return None;
        };
        if let Some(qualifier) = column_ref.table.as_deref()
            && !qualifier.eq_ignore_ascii_case(table_name)
            && !table_alias.is_some_and(|alias| qualifier.eq_ignore_ascii_case(alias))
        {
            return None;
        }
        needed.push(column_ref.column.clone());
    }
    Some(needed)
}

fn planner_where_column_matches(
    column: &fsqlite_planner::WhereColumn,
    table_name: &str,
    table_alias: Option<&str>,
    expected_column: &str,
) -> bool {
    column.column.eq_ignore_ascii_case(expected_column)
        && column.table.as_deref().is_none_or(|qualifier| {
            qualifier.eq_ignore_ascii_case(table_name)
                || table_alias.is_some_and(|alias| qualifier.eq_ignore_ascii_case(alias))
        })
}

fn planner_directive_index_column(
    table: &TableSchema,
    table_alias: Option<&str>,
    where_terms: &[fsqlite_planner::WhereTerm<'_>],
    index_name: &str,
) -> Option<String> {
    let index = table
        .indexes
        .iter()
        .find(|candidate| candidate.name.eq_ignore_ascii_case(index_name))?;
    let leading_column = index.columns.first()?.clone();
    where_terms.iter().find_map(|term| {
        term.column.as_ref().and_then(|column| {
            planner_where_column_matches(column, &table.name, table_alias, &leading_column)
                .then_some(leading_column.clone())
        })
    })
}

fn planner_directive_covering_access_kind(
    table: &TableSchema,
    table_alias: Option<&str>,
    where_terms: &[fsqlite_planner::WhereTerm<'_>],
    index_name: &str,
) -> Option<(PlannerSelectAccessKind, String)> {
    let index_column = planner_directive_index_column(table, table_alias, where_terms, index_name)?;
    let mut saw_equality = false;
    let mut saw_range = false;
    for term in where_terms {
        let Some(column) = term.column.as_ref() else {
            continue;
        };
        if !planner_where_column_matches(column, &table.name, table_alias, &index_column) {
            continue;
        }
        match &term.kind {
            WhereTermKind::Equality => saw_equality = true,
            WhereTermKind::Range | WhereTermKind::Between => saw_range = true,
            _ => {}
        }
    }
    if saw_equality {
        Some((PlannerSelectAccessKind::IndexEquality, index_column))
    } else if saw_range {
        Some((PlannerSelectAccessKind::IndexRange, index_column))
    } else {
        None
    }
}

fn explain_query_plan_detail_from_directive(directive: &SelectPlannerDirective) -> String {
    match directive.access_kind {
        PlannerSelectAccessKind::FullTableScan => format!("SCAN {}", directive.table_name),
        PlannerSelectAccessKind::RowidLookup => {
            format!(
                "SEARCH {} USING INTEGER PRIMARY KEY (rowid=?)",
                directive.table_name
            )
        }
        PlannerSelectAccessKind::IndexEquality => format!(
            "SEARCH {} USING {}INDEX {} ({}=?)",
            directive.table_name,
            if directive.covering { "COVERING " } else { "" },
            directive.index_name.as_deref().unwrap_or("(unknown)"),
            directive.index_column.as_deref().unwrap_or("(expr)"),
        ),
        PlannerSelectAccessKind::IndexRange => format!(
            "SEARCH {} USING {}INDEX {} ({} range)",
            directive.table_name,
            if directive.covering { "COVERING " } else { "" },
            directive.index_name.as_deref().unwrap_or("(unknown)"),
            directive.index_column.as_deref().unwrap_or("(expr)"),
        ),
    }
}

/// Hex-encode a byte slice (lowercase).
fn hex_encode(bytes: &[u8]) -> String {
    use std::fmt::Write;
    let mut s = String::with_capacity(bytes.len() * 2);
    for b in bytes {
        let _ = write!(s, "{b:02x}");
    }
    s
}

fn execute_program(
    program: &VdbeProgram,
    params: Option<&[SqliteValue]>,
    func_registry: Option<&Arc<FunctionRegistry>>,
    collation_registry: Option<&Arc<Mutex<CollationRegistry>>>,
    execution_cx: &Cx,
    page_size: PageSize,
) -> Result<Vec<Row>> {
    let mut engine =
        VdbeEngine::new_with_execution_cx(program.register_count(), execution_cx, page_size);
    if let Some(params) = params {
        validate_bound_parameters(program, params)?;
        engine.set_bindings_slice(params);
    }
    if let Some(registry) = func_registry {
        engine.set_function_registry(Arc::clone(registry));
    }
    if let Some(registry) = collation_registry {
        engine.set_collation_registry(Arc::clone(registry));
    }

    match engine.execute(program)? {
        ExecOutcome::Done => Ok(engine
            .take_results()
            .into_iter()
            .map(|values| Row {
                values: values.into_vec(),
            })
            .collect()),
        ExecOutcome::Error { code, message } => Err(FrankenError::Internal(format!(
            "VDBE halted with code {code}: {message}",
        ))),
    }
}

fn execute_program_with_postprocess(
    program: &VdbeProgram,
    params: Option<&[SqliteValue]>,
    func_registry: Option<&Arc<FunctionRegistry>>,
    collation_registry: Option<&Arc<Mutex<CollationRegistry>>>,
    execution_cx: &Cx,
    expression_postprocess: Option<&ExpressionPostprocess>,
    page_size: PageSize,
) -> Result<Vec<Row>> {
    let mut rows = execute_program(
        program,
        params,
        func_registry,
        collation_registry,
        execution_cx,
        page_size,
    )?;
    if let Some(postprocess) = expression_postprocess {
        apply_expression_postprocess(&mut rows, postprocess)?;
    }
    Ok(rows)
}

/// MVCC concurrent context for page-level locking (bd-kivg / 5E.2).
/// Passed to `execute_table_program_with_db` when in concurrent mode.
struct ConcurrentExecContext {
    session_id: u64,
    handle: SharedConcurrentHandle,
    lock_table: Arc<InProcessPageLockTable>,
    commit_index: Arc<CommitIndex>,
    busy_timeout_ms: u64,
}

#[derive(Debug, Clone, Copy)]
struct TableProgramErrorState {
    changes: usize,
    last_insert_rowid: Option<i64>,
}

#[derive(Debug)]
struct TableProgramExecError {
    error: FrankenError,
    changes: usize,
    last_insert_rowid: Option<i64>,
}

type TableProgramExecResult =
    std::result::Result<(Vec<Row>, usize, Option<i64>), TableProgramExecError>;
type TableProgramExecOutcome = (TableProgramExecResult, Option<Box<dyn TransactionHandle>>);

#[allow(clippy::too_many_arguments)]
fn execute_table_program_with_db(
    program: &VdbeProgram,
    params: Option<&[SqliteValue]>,
    func_registry: &Arc<FunctionRegistry>,
    collation_registry: &Arc<Mutex<CollationRegistry>>,
    execution_cx: &Cx,
    db: &Rc<RefCell<MemDatabase>>,
    txn: Option<Box<dyn TransactionHandle>>,
    schema_cookie: u32,
    concurrent_ctx: Option<ConcurrentExecContext>,
    autoincrement_seq_by_root_page: HbHashMap<i32, i64>,
    rowid_alias_col_by_root_page: Arc<HbHashMap<i32, usize>>,
    table_column_count_by_root_page: Arc<HbHashMap<i32, usize>>,
    column_defaults_by_root_page: Arc<HbHashMap<i32, Vec<Option<SqliteValue>>>>,
    index_desc_flags_by_root_page: Arc<HbHashMap<i32, Vec<bool>>>,
    reject_mem_fallback: bool,
    version_store: Option<Arc<VersionStore>>,
    page_size: PageSize,
    collect_rows: bool,
    prepared_engine_reuse_profile: bool,
    cached_engine: Option<VdbeEngine>,
) -> (TableProgramExecOutcome, Option<VdbeEngine>) {
    let execution_span = tracing::enabled!(target: "fsqlite.execution", tracing::Level::DEBUG)
        .then(|| {
            let span = tracing::span!(
                target: "fsqlite.execution",
                tracing::Level::DEBUG,
                "execution",
                mode = "vdbe"
            );
            record_trace_span_created();
            span
        });
    let _execution_guard = execution_span.as_ref().map(tracing::Span::enter);
    // Reuse a cached engine if available (avoids 21+ collection allocations).
    // If no cached engine exists, create a fresh one.
    let reusing_engine = cached_engine.is_some();
    if prepared_engine_reuse_profile && hot_path_profile_enabled() {
        if reusing_engine {
            FSQLITE_PREPARED_TABLE_ENGINE_REUSES.fetch_add(1, AtomicOrdering::Relaxed);
        } else {
            FSQLITE_PREPARED_TABLE_ENGINE_FRESH_ALLOCS.fetch_add(1, AtomicOrdering::Relaxed);
        }
    }
    let mut engine = if let Some(mut cached) = cached_engine {
        cached.reset_for_reuse(program.register_count(), execution_cx, page_size);
        cached
    } else {
        VdbeEngine::new_with_execution_cx(program.register_count(), execution_cx, page_size)
    };
    if let Some(params) = params {
        if let Err(e) = validate_bound_parameters(program, params) {
            return (
                (
                    Err(TableProgramExecError {
                        error: e,
                        changes: 0,
                        last_insert_rowid: None,
                    }),
                    txn,
                ),
                Some(engine),
            );
        }
        engine.set_bindings_slice(params);
    }

    engine.set_function_registry(Arc::clone(func_registry));
    engine.set_collation_registry(Arc::clone(collation_registry));
    engine.set_schema_cookie(schema_cookie);
    engine.set_autoincrement_sequence_by_root_page(autoincrement_seq_by_root_page);
    engine.set_shared_rowid_alias_column_by_root_page(rowid_alias_col_by_root_page);
    engine.set_shared_table_column_count_by_root_page(table_column_count_by_root_page);
    engine.set_shared_column_defaults_by_root_page(column_defaults_by_root_page);
    engine.set_shared_index_desc_flags_by_root_page(index_desc_flags_by_root_page);
    engine.set_collect_result_rows(collect_rows);
    // bd-2ttd8.1: enable parity-cert mode to reject MemPageStore fallback.
    engine.set_reject_mem_fallback(reject_mem_fallback);
    // Time-travel support: pass the MVCC version store so SetSnapshot can
    // create TimeTravelPageIo cursors for historical page resolution.
    if let Some(vs) = version_store {
        engine.set_version_store(vs);
    }

    // Phase 5 (bd-2a3y): if a transaction handle is available, lend it to
    // the engine so storage cursors route through the real pager/WAL stack.
    // bd-kivg / 5E.2: if concurrent context is provided, use set_transaction_concurrent
    // to enable MVCC page-level locking.
    if let Some(txn) = txn {
        if let Some(ctx) = concurrent_ctx {
            engine.set_transaction_concurrent(
                txn,
                ctx.session_id,
                ctx.handle,
                ctx.lock_table,
                ctx.commit_index,
                ctx.busy_timeout_ms,
            );
        } else {
            engine.set_transaction(txn);
        }
    } else {
        engine.enable_storage_read_cursors(true);
    }

    // Lend the MemDatabase to the engine for the duration of execution.
    let db_value = db.replace(MemDatabase::new());
    engine.set_database(db_value);

    // Always take the DB and txn back, even if execution returns Err.
    let trace_export_enabled =
        tracing::enabled!(target: "fsqlite.trace_export", tracing::Level::DEBUG);
    let export_started = trace_export_enabled.then(fsqlite_types::sync_primitives::Instant::now);
    let exec_res = engine.execute(program);
    if let Some(export_started) = export_started {
        let export_latency_us =
            u64::try_from(export_started.elapsed().as_micros()).unwrap_or(u64::MAX);
        record_trace_export(1, export_latency_us);
    }
    if exec_res.is_err() || matches!(exec_res, Ok(ExecOutcome::Error { .. })) {
        record_trace_export_error();
    }
    let engine_rowid = engine.last_insert_rowid();

    if let Some(db_value) = engine.take_database() {
        *db.borrow_mut() = db_value;
    }
    let txn_back = match engine.take_transaction() {
        Ok(txn) => txn,
        Err(e) => {
            return (
                (
                    Err(TableProgramExecError {
                        error: e,
                        changes: engine.changes(),
                        last_insert_rowid: engine_rowid,
                    }),
                    None,
                ),
                Some(engine),
            );
        }
    };

    let changes = engine.changes();
    let result = match exec_res {
        Ok(ExecOutcome::Done) => {
            if !collect_rows && hot_path_profile_enabled() {
                FSQLITE_PREPARED_TABLE_DML_AFFECTED_ONLY_RUNS.fetch_add(1, AtomicOrdering::Relaxed);
            }
            let rows = if collect_rows {
                engine
                    .take_results()
                    .into_iter()
                    .map(|values| Row {
                        values: values.into_vec(),
                    })
                    .collect()
            } else {
                Vec::new()
            };
            Ok((rows, changes, engine_rowid))
        }
        Ok(ExecOutcome::Error { code, message }) => Err(TableProgramExecError {
            error: FrankenError::Internal(format!("VDBE halted with code {code}: {message}",)),
            changes,
            last_insert_rowid: engine_rowid,
        }),
        Err(e) => Err(TableProgramExecError {
            error: e,
            changes,
            last_insert_rowid: engine_rowid,
        }),
    };
    ((result, txn_back), Some(engine))
}

fn build_expression_postprocess(select: &SelectStatement) -> ExpressionPostprocess {
    let mut output_aliases = HashMap::new();
    let output_width = match &select.body.select {
        SelectCore::Select { columns, .. } => {
            for (index, column) in columns.iter().enumerate() {
                if let ResultColumn::Expr {
                    alias: Some(alias), ..
                } = column
                {
                    output_aliases
                        .entry(alias.to_ascii_lowercase())
                        .or_insert(index);
                }
            }
            columns.len()
        }
        SelectCore::Values(rows) => rows.first().map_or(0, Vec::len),
    };

    ExpressionPostprocess {
        order_by: select.order_by.clone(),
        limit: select.limit.clone(),
        output_aliases,
        output_width,
    }
}

fn apply_expression_postprocess(
    rows: &mut Vec<Row>,
    postprocess: &ExpressionPostprocess,
) -> Result<()> {
    if !postprocess.order_by.is_empty() {
        let resolved_order_terms = resolve_order_terms(
            &postprocess.order_by,
            postprocess.output_width,
            &postprocess.output_aliases,
        )?;
        rows.sort_by(|left, right| {
            for term in &resolved_order_terms {
                let Some(left_value) = left.values.get(term.column_index) else {
                    continue;
                };
                let Some(right_value) = right.values.get(term.column_index) else {
                    continue;
                };
                let ordering = compare_order_values(left_value, right_value, *term);
                if ordering != std::cmp::Ordering::Equal {
                    return ordering;
                }
            }
            std::cmp::Ordering::Equal
        });
    }

    if let Some(limit_clause) = postprocess.limit.as_ref() {
        let offset = limit_clause
            .offset
            .as_ref()
            .map_or(Ok(0_i64), parse_limit_offset_expr)?;
        if offset > 0 {
            let offset = usize::try_from(offset).unwrap_or(usize::MAX);
            if offset >= rows.len() {
                rows.clear();
                return Ok(());
            }
            rows.drain(0..offset);
        }

        let limit = parse_limit_offset_expr(&limit_clause.limit)?;
        if limit >= 0 {
            let limit = usize::try_from(limit).unwrap_or(usize::MAX);
            rows.truncate(limit);
        }
    }

    Ok(())
}

fn resolve_order_terms(
    order_by: &[OrderingTerm],
    output_width: usize,
    output_aliases: &HashMap<String, usize>,
) -> Result<Vec<ResolvedOrderTerm>> {
    order_by
        .iter()
        .map(|term| {
            let column_index = match &term.expr {
                Expr::Column(column_ref, _) if column_ref.table.is_none() => output_aliases
                    .get(&column_ref.column.to_ascii_lowercase())
                    .copied()
                    .ok_or_else(|| {
                        FrankenError::NotImplemented(
                            "expression-only ORDER BY currently supports output-column positions or aliases only".to_owned(),
                        )
                    })?,
                _ => order_term_positional_index(&term.expr)?,
            };
            if column_index >= output_width {
                return Err(FrankenError::OutOfRange {
                    what: "ORDER BY column index".to_owned(),
                    value: (column_index + 1).to_string(),
                });
            }
            Ok(ResolvedOrderTerm {
                column_index,
                descending: term.direction == Some(SortDirection::Desc),
                nulls_order: term
                    .nulls
                    .unwrap_or_else(|| default_nulls_order(term.direction)),
            })
        })
        .collect()
}

fn order_term_positional_index(expr: &Expr) -> Result<usize> {
    let one_based = parse_limit_offset_expr(expr)?;
    if one_based <= 0 {
        return Err(FrankenError::OutOfRange {
            what: "ORDER BY column index".to_owned(),
            value: one_based.to_string(),
        });
    }
    let zero_based = one_based - 1;
    usize::try_from(zero_based).map_err(|_| FrankenError::OutOfRange {
        what: "ORDER BY column index".to_owned(),
        value: one_based.to_string(),
    })
}

fn parse_limit_offset_expr(expr: &Expr) -> Result<i64> {
    match expr {
        Expr::Literal(Literal::Integer(value), _) => Ok(*value),
        Expr::UnaryOp {
            op: UnaryOp::Plus,
            expr: inner,
            ..
        } => parse_limit_offset_expr(inner),
        Expr::UnaryOp {
            op: UnaryOp::Negate,
            expr: inner,
            ..
        } => parse_limit_offset_expr(inner)?
            .checked_neg()
            .ok_or_else(|| FrankenError::OutOfRange {
                what: "LIMIT/OFFSET expression".to_owned(),
                value: "integer overflow".to_owned(),
            }),
        _ => Err(FrankenError::NotImplemented(
            "expression-only LIMIT/OFFSET currently supports integer literals only".to_owned(),
        )),
    }
}

fn default_nulls_order(direction: Option<SortDirection>) -> NullsOrder {
    if direction == Some(SortDirection::Desc) {
        NullsOrder::Last
    } else {
        NullsOrder::First
    }
}

fn compare_order_values(
    left: &SqliteValue,
    right: &SqliteValue,
    term: ResolvedOrderTerm,
) -> std::cmp::Ordering {
    let left_is_null = left.is_null();
    let right_is_null = right.is_null();
    if left_is_null || right_is_null {
        if left_is_null && right_is_null {
            return std::cmp::Ordering::Equal;
        }
        return match (left_is_null, term.nulls_order) {
            (true, NullsOrder::First) | (false, NullsOrder::Last) => std::cmp::Ordering::Less,
            (true, NullsOrder::Last) | (false, NullsOrder::First) => std::cmp::Ordering::Greater,
        };
    }

    let mut ordering = left.partial_cmp(right).unwrap_or(std::cmp::Ordering::Equal);
    if term.descending {
        ordering = ordering.reverse();
    }
    ordering
}

fn exactly_one_row_or_error(rows: Vec<Row>) -> Result<Row> {
    let mut iter = rows.into_iter();
    let row = iter.next().ok_or(FrankenError::QueryReturnedNoRows)?;
    if iter.next().is_some() {
        return Err(FrankenError::QueryReturnedMultipleRows);
    }
    Ok(row)
}

fn validate_bound_parameters(program: &VdbeProgram, params: &[SqliteValue]) -> Result<()> {
    let max_required =
        program
            .max_bind_parameter_index()
            .map_err(|raw_index| FrankenError::OutOfRange {
                what: "bind parameter index".to_owned(),
                value: raw_index.to_string(),
            })?;

    if max_required > usize::try_from(MAX_VARIABLE_NUMBER).expect("u32 variable limit fits usize") {
        return Err(FrankenError::OutOfRange {
            what: "bind parameter index".to_owned(),
            value: max_required.to_string(),
        });
    }

    if max_required > params.len() {
        return Err(FrankenError::OutOfRange {
            what: "bind parameter index".to_owned(),
            value: max_required.to_string(),
        });
    }
    Ok(())
}

fn parse_single_statement(sql: &str) -> Result<Statement> {
    let statements = parse_statements(sql)?;
    let mut iter = statements.into_iter();
    let statement = iter.next().ok_or_else(|| FrankenError::ParseError {
        offset: 0,
        detail: "no SQL statement provided".to_owned(),
    })?;

    if iter.next().is_some() {
        return Err(FrankenError::NotImplemented(
            "multiple statements are not supported in this API path".to_owned(),
        ));
    }

    Ok(statement)
}

fn parse_statements(sql: &str) -> Result<Vec<Statement>> {
    let mut parser = Parser::from_sql(sql);
    let (statements, errors) = parser.parse_all();

    if let Some(parse_error) = errors.first() {
        return Err(FrankenError::ParseError {
            #[allow(clippy::cast_sign_loss)]
            offset: parse_error.span.start as usize,
            detail: parse_error.message.clone(),
        });
    }

    if statements.is_empty() {
        return Err(FrankenError::ParseError {
            offset: 0,
            detail: "no SQL statement provided".to_owned(),
        });
    }

    Ok(statements)
}

fn batch_is_noop(sql: &str) -> Result<bool> {
    let bytes = sql.as_bytes();
    let mut i = 0;

    while i < bytes.len() {
        match bytes[i] {
            b';' | b' ' | b'\t' | b'\r' | b'\n' => {
                i += 1;
            }
            b'-' if i + 1 < bytes.len() && bytes[i + 1] == b'-' => {
                i += 2;
                while i < bytes.len() && bytes[i] != b'\n' {
                    i += 1;
                }
            }
            b'/' if i + 1 < bytes.len() && bytes[i + 1] == b'*' => {
                let comment_start = i;
                i += 2;
                let mut terminated = false;
                while i + 1 < bytes.len() {
                    if bytes[i] == b'*' && bytes[i + 1] == b'/' {
                        i += 2;
                        terminated = true;
                        break;
                    }
                    i += 1;
                }
                if !terminated {
                    return Err(FrankenError::ParseError {
                        offset: comment_start,
                        detail: "unterminated block comment".to_owned(),
                    });
                }
            }
            _ => return Ok(false),
        }
    }

    Ok(true)
}

#[cfg(test)]
mod batch_execution_tests {
    use super::*;

    #[test]
    fn execute_batch_treats_empty_and_comment_only_sql_as_noop() {
        let conn = Connection::open(":memory:").unwrap();
        conn.execute_batch("").unwrap();
        conn.execute_batch("   ;  ;  ").unwrap();
        conn.execute_batch("  -- nothing here\n/* still empty */ ; ")
            .unwrap();
    }

    #[test]
    fn execute_batch_rejects_unterminated_block_comment() {
        let conn = Connection::open(":memory:").unwrap();
        let error = conn
            .execute_batch("/* unterminated")
            .expect_err("unterminated block comments should not be treated as empty batches");
        assert!(matches!(error, FrankenError::ParseError { offset: 0, .. }));
    }
}

fn quote_identifier(identifier: &str) -> String {
    let escaped = identifier.replace('"', "\"\"");
    format!("\"{escaped}\"")
}

fn quote_qualified_name(name: &fsqlite_ast::QualifiedName) -> String {
    match &name.schema {
        Some(schema) => format!(
            "{}.{}",
            quote_identifier(schema),
            quote_identifier(&name.name)
        ),
        None => quote_identifier(&name.name),
    }
}

fn to_i64_clamped(value: u64) -> i64 {
    i64::try_from(value).unwrap_or(i64::MAX)
}

fn join_page_numbers(pages: &[PageNumber]) -> String {
    pages
        .iter()
        .map(|page| page.get().to_string())
        .collect::<Vec<_>>()
        .join(",")
}

fn join_txn_tokens(tokens: &[TxnToken]) -> String {
    tokens
        .iter()
        .map(|token| format!("{}:{}", token.id.get(), token.epoch.get()))
        .collect::<Vec<_>>()
        .join(",")
}

fn read_set_top_k_string(summary: &SsiReadSetSummary) -> String {
    summary
        .top_k_pages
        .iter()
        .map(|page| page.get().to_string())
        .collect::<Vec<_>>()
        .join(",")
}

fn ssi_decision_cards_to_rows(cards: &[SsiDecisionCard]) -> Vec<Row> {
    cards
        .iter()
        .map(|card| Row {
            values: vec![
                SqliteValue::Integer(to_i64_clamped(card.txn.id.get())),
                SqliteValue::Integer(i64::from(card.txn.epoch.get())),
                SqliteValue::Integer(to_i64_clamped(card.snapshot_seq.get())),
                SqliteValue::Integer(to_i64_clamped(card.commit_seq.map_or(0, CommitSeq::get))),
                SqliteValue::Text(card.decision_type.as_str().to_owned().into()),
                SqliteValue::Text(join_txn_tokens(&card.conflicting_txns).into()),
                SqliteValue::Text(join_page_numbers(&card.conflict_pages).into()),
                SqliteValue::Integer(
                    i64::try_from(card.read_set_summary.page_count).unwrap_or(i64::MAX),
                ),
                SqliteValue::Text(read_set_top_k_string(&card.read_set_summary).into()),
                SqliteValue::Integer(to_i64_clamped(card.read_set_summary.bloom_fingerprint)),
                SqliteValue::Text(join_page_numbers(&card.write_set).into()),
                SqliteValue::Text(card.rationale.clone().into()),
                SqliteValue::Integer(to_i64_clamped(card.timestamp_unix_ns)),
                SqliteValue::Integer(to_i64_clamped(card.decision_epoch)),
                SqliteValue::Text(card.chain_hash_hex().into()),
            ],
        })
        .collect()
}

#[cfg(not(target_arch = "wasm32"))]
fn hex_encode_blake3(bytes: [u8; 32]) -> String {
    use std::fmt::Write as _;

    let mut encoded = String::with_capacity(64);
    for byte in bytes {
        let _ = write!(&mut encoded, "{byte:02x}");
    }
    encoded
}

#[cfg(not(target_arch = "wasm32"))]
fn raptorq_repair_evidence_cards_to_rows(cards: &[WalFecRepairEvidenceCard]) -> Vec<Row> {
    cards
        .iter()
        .map(|card| Row {
            values: vec![
                SqliteValue::Integer(i64::from(card.frame_id)),
                card.wal_file_offset_bytes
                    .map_or(SqliteValue::Null, |offset| {
                        SqliteValue::Integer(to_i64_clamped(offset))
                    }),
                SqliteValue::Integer(to_i64_clamped(card.monotonic_timestamp_ns)),
                SqliteValue::Integer(to_i64_clamped(card.wall_clock_unix_ns)),
                SqliteValue::Text(card.corruption_signature_hex().into()),
                card.bit_error_pattern
                    .as_ref()
                    .map_or(SqliteValue::Null, |pattern| {
                        SqliteValue::Text(pattern.clone().into())
                    }),
                SqliteValue::Text(card.repair_source.as_str().to_owned().into()),
                SqliteValue::Integer(i64::from(card.symbols_used)),
                SqliteValue::Integer(i64::from(card.validated_source_symbols)),
                SqliteValue::Integer(i64::from(card.validated_repair_symbols)),
                SqliteValue::Integer(i64::from(card.required_symbols)),
                SqliteValue::Integer(i64::from(card.available_symbols)),
                SqliteValue::Text(hex_encode_blake3(card.witness.corrupted_hash_blake3).into()),
                SqliteValue::Text(hex_encode_blake3(card.witness.repaired_hash_blake3).into()),
                SqliteValue::Text(hex_encode_blake3(card.witness.expected_hash_blake3).into()),
                SqliteValue::Integer(to_i64_clamped(card.repair_latency_ns)),
                SqliteValue::Integer(i64::from(card.confidence_per_mille)),
                SqliteValue::Text(card.severity_bucket.as_str().to_owned().into()),
                SqliteValue::Integer(to_i64_clamped(card.ledger_epoch)),
                SqliteValue::Text(card.chain_hash_hex().into()),
            ],
        })
        .collect()
}

#[derive(Debug, Clone)]
struct LineageJoinSpec {
    left_table: String,
    right_table: String,
    left_column: String,
    right_column: String,
    left_contributor_column: String,
    right_contributor_column: String,
}

fn parse_lineage_identifier(raw: &str, label: &str) -> Result<String> {
    let trimmed = raw.trim();
    if trimmed.is_empty() {
        return Err(FrankenError::Internal(format!(
            "PRAGMA lineage {label} must be non-empty"
        )));
    }
    if !trimmed
        .chars()
        .all(|ch| ch.is_ascii_alphanumeric() || ch == '_')
    {
        return Err(FrankenError::Internal(format!(
            "PRAGMA lineage {label} must use [A-Za-z0-9_], got `{trimmed}`"
        )));
    }
    Ok(trimmed.to_owned())
}

fn parse_lineage_query_spec(spec: &str) -> Result<LineageJoinSpec> {
    let parts = spec.split(',').map(str::trim).collect::<Vec<_>>();
    if !(parts.len() == 4 || parts.len() == 6) {
        return Err(FrankenError::Internal(
            "PRAGMA lineage must be `left_table,right_table,left_col,right_col[,left_id_col,right_id_col]`"
                .to_owned(),
        ));
    }
    let (left_contributor_column, right_contributor_column) = if parts.len() == 6 {
        (
            parse_lineage_identifier(parts[4], "left contributor column")?,
            parse_lineage_identifier(parts[5], "right contributor column")?,
        )
    } else {
        ("rowid".to_owned(), "rowid".to_owned())
    };
    Ok(LineageJoinSpec {
        left_table: parse_lineage_identifier(parts[0], "left table")?,
        right_table: parse_lineage_identifier(parts[1], "right table")?,
        left_column: parse_lineage_identifier(parts[2], "left join column")?,
        right_column: parse_lineage_identifier(parts[3], "right join column")?,
        left_contributor_column,
        right_contributor_column,
    })
}

fn parse_lineage_query(value: &fsqlite_ast::PragmaValue) -> Result<LineageJoinSpec> {
    let expr = match value {
        fsqlite_ast::PragmaValue::Assign(e) | fsqlite_ast::PragmaValue::Call(e) => e,
    };
    match expr {
        Expr::Literal(Literal::String(spec), _) => parse_lineage_query_spec(spec),
        Expr::Column(col_ref, _) if col_ref.table.is_none() => {
            parse_lineage_query_spec(&col_ref.column)
        }
        _ => Err(FrankenError::Internal(
            "PRAGMA lineage value must be a string like `left,right,left_col,right_col[,left_id_col,right_id_col]`".to_owned(),
        )),
    }
}

fn execute_simple_join_lineage_query(
    conn: &Connection,
    spec: &LineageJoinSpec,
) -> Result<Vec<Row>> {
    let sql = format!(
        "SELECT l.{left_id_col}, r.{right_id_col}, l.{left_col}, r.{right_col} \
         FROM {left_tbl} AS l \
         JOIN {right_tbl} AS r \
         ON l.{left_col} = r.{right_col} \
         ORDER BY 1, 2;",
        left_id_col = spec.left_contributor_column,
        right_id_col = spec.right_contributor_column,
        left_col = spec.left_column,
        right_col = spec.right_column,
        left_tbl = spec.left_table,
        right_tbl = spec.right_table
    );
    conn.query(&sql)
}

fn parse_u64_component(raw: &str, label: &str) -> Result<u64> {
    raw.trim().parse::<u64>().map_err(|_| {
        FrankenError::Internal(format!(
            "PRAGMA ssi_decisions {label} must be an unsigned integer, got `{raw}`"
        ))
    })
}

fn parse_ssi_decision_query_spec(spec: &str) -> Result<SsiDecisionQuery> {
    let trimmed = spec.trim();
    if trimmed.is_empty() {
        return Ok(SsiDecisionQuery::default());
    }

    if trimmed.chars().all(|ch| ch.is_ascii_digit()) {
        return Ok(SsiDecisionQuery {
            txn_id: Some(parse_u64_component(trimmed, "txn")?),
            ..SsiDecisionQuery::default()
        });
    }

    let mut query = SsiDecisionQuery::default();
    for term in trimmed.split(',') {
        let term = term.trim();
        if term.is_empty() {
            continue;
        }

        if let Some(raw) = term.strip_prefix("txn:") {
            query.txn_id = Some(parse_u64_component(raw, "txn")?);
            continue;
        }
        if let Some(raw) = term.strip_prefix("type:") {
            let decision_type = SsiDecisionType::from_str(raw).map_err(|_| {
                FrankenError::Internal(format!(
                    "PRAGMA ssi_decisions type must be one of COMMIT_ALLOWED/ABORT_WRITE_SKEW/ABORT_PHANTOM/ABORT_CYCLE, got `{raw}`"
                ))
            })?;
            query.decision_type = Some(decision_type);
            continue;
        }
        if let Some(raw) = term.strip_prefix("time:") {
            let (start_raw, end_raw) = raw.split_once('-').ok_or_else(|| {
                FrankenError::Internal(
                    "PRAGMA ssi_decisions time filter must be `time:<start>-<end>`".to_owned(),
                )
            })?;
            query.timestamp_start_ns = if start_raw.trim().is_empty() {
                None
            } else {
                Some(parse_u64_component(start_raw, "time start")?)
            };
            query.timestamp_end_ns = if end_raw.trim().is_empty() {
                None
            } else {
                Some(parse_u64_component(end_raw, "time end")?)
            };
            continue;
        }

        if query.decision_type.is_none() {
            if let Ok(decision_type) = SsiDecisionType::from_str(term) {
                query.decision_type = Some(decision_type);
                continue;
            }
        }

        return Err(FrankenError::Internal(format!(
            "PRAGMA ssi_decisions filter term `{term}` is invalid; use txn:<id>, type:<decision>, or time:<start>-<end>"
        )));
    }

    Ok(query)
}

fn parse_ssi_decision_query(value: &fsqlite_ast::PragmaValue) -> Result<SsiDecisionQuery> {
    let expr = match value {
        fsqlite_ast::PragmaValue::Assign(e) | fsqlite_ast::PragmaValue::Call(e) => e,
    };
    match expr {
        Expr::Literal(Literal::Integer(n), _) => {
            if *n < 0 {
                return Err(FrankenError::Internal(
                    "PRAGMA ssi_decisions txn id must be >= 0".to_owned(),
                ));
            }
            Ok(SsiDecisionQuery {
                txn_id: Some(u64::try_from(*n).unwrap_or(u64::MAX)),
                ..SsiDecisionQuery::default()
            })
        }
        Expr::Literal(Literal::String(s), _) => parse_ssi_decision_query_spec(s),
        Expr::Column(col_ref, _) if col_ref.table.is_none() => {
            parse_ssi_decision_query_spec(&col_ref.column)
        }
        _ => Err(FrankenError::Internal(
            "PRAGMA ssi_decisions value must be an integer txn id or string filter".to_owned(),
        )),
    }
}

#[cfg(not(target_arch = "wasm32"))]
fn parse_raptorq_u64_component(raw: &str, label: &str) -> Result<u64> {
    raw.trim().parse::<u64>().map_err(|_| {
        FrankenError::Internal(format!(
            "PRAGMA raptorq_repair_evidence {label} must be an unsigned integer, got `{raw}`"
        ))
    })
}

#[cfg(not(target_arch = "wasm32"))]
fn parse_raptorq_repair_evidence_query_spec(spec: &str) -> Result<WalFecRepairEvidenceQuery> {
    let trimmed = spec.trim();
    if trimmed.is_empty() {
        return Ok(WalFecRepairEvidenceQuery::default());
    }

    if trimmed.chars().all(|ch| ch.is_ascii_digit()) {
        let frame_id = parse_raptorq_u64_component(trimmed, "frame")?;
        return Ok(WalFecRepairEvidenceQuery {
            frame_id: Some(u32::try_from(frame_id).unwrap_or(u32::MAX)),
            ..WalFecRepairEvidenceQuery::default()
        });
    }

    let mut query = WalFecRepairEvidenceQuery::default();
    for term in trimmed.split(',') {
        let term = term.trim();
        if term.is_empty() {
            continue;
        }

        if let Some(raw) = term
            .strip_prefix("frame:")
            .or_else(|| term.strip_prefix("page:"))
        {
            let frame_id = parse_raptorq_u64_component(raw, "frame")?;
            query.frame_id = Some(u32::try_from(frame_id).unwrap_or(u32::MAX));
            continue;
        }

        if let Some(raw) = term.strip_prefix("severity:") {
            let bucket = WalFecRepairSeverityBucket::from_str(raw).map_err(|_| {
                FrankenError::Internal(format!(
                    "PRAGMA raptorq_repair_evidence severity must be one of 1|2-5|6-10|11+, got `{raw}`"
                ))
            })?;
            query.severity_bucket = Some(bucket);
            continue;
        }

        if let Some(raw) = term.strip_prefix("time:") {
            let (start_raw, end_raw) = raw.split_once('-').ok_or_else(|| {
                FrankenError::Internal(
                    "PRAGMA raptorq_repair_evidence time filter must be `time:<start>-<end>`"
                        .to_owned(),
                )
            })?;
            query.wall_clock_start_ns = if start_raw.trim().is_empty() {
                None
            } else {
                Some(parse_raptorq_u64_component(start_raw, "time start")?)
            };
            query.wall_clock_end_ns = if end_raw.trim().is_empty() {
                None
            } else {
                Some(parse_raptorq_u64_component(end_raw, "time end")?)
            };
            continue;
        }

        if let Some(raw) = term.strip_prefix("limit:") {
            let limit = parse_raptorq_u64_component(raw, "limit")?;
            query.limit = Some(usize::try_from(limit).unwrap_or(usize::MAX));
            continue;
        }

        if query.severity_bucket.is_none() {
            if let Ok(bucket) = WalFecRepairSeverityBucket::from_str(term) {
                query.severity_bucket = Some(bucket);
                continue;
            }
        }

        return Err(FrankenError::Internal(format!(
            "PRAGMA raptorq_repair_evidence filter term `{term}` is invalid; use frame:<id>, severity:<bucket>, time:<start>-<end>, or limit:<n>"
        )));
    }

    Ok(query)
}

#[cfg(not(target_arch = "wasm32"))]
fn parse_raptorq_repair_evidence_query(
    value: &fsqlite_ast::PragmaValue,
) -> Result<WalFecRepairEvidenceQuery> {
    let expr = match value {
        fsqlite_ast::PragmaValue::Assign(e) | fsqlite_ast::PragmaValue::Call(e) => e,
    };
    match expr {
        Expr::Literal(Literal::Integer(n), _) => {
            if *n < 0 {
                return Err(FrankenError::Internal(
                    "PRAGMA raptorq_repair_evidence frame id must be >= 0".to_owned(),
                ));
            }
            Ok(WalFecRepairEvidenceQuery {
                frame_id: Some(u32::try_from(*n).unwrap_or(u32::MAX)),
                ..WalFecRepairEvidenceQuery::default()
            })
        }
        Expr::Literal(Literal::String(s), _) => parse_raptorq_repair_evidence_query_spec(s),
        Expr::Column(col_ref, _) if col_ref.table.is_none() => {
            parse_raptorq_repair_evidence_query_spec(&col_ref.column)
        }
        _ => Err(FrankenError::Internal(
            "PRAGMA raptorq_repair_evidence value must be an integer frame id or string filter"
                .to_owned(),
        )),
    }
}

/// Parse a PRAGMA value as a boolean.
///
/// Accepts `on`, `off`, `true`, `false`, `1`, `0`, `yes`, `no`
/// (case-insensitive).
fn parse_pragma_bool(value: &fsqlite_ast::PragmaValue) -> Result<bool> {
    let expr = match value {
        fsqlite_ast::PragmaValue::Assign(e) | fsqlite_ast::PragmaValue::Call(e) => e,
    };
    let text = match expr {
        Expr::Literal(Literal::Integer(n), _) => {
            return match *n {
                0 => Ok(false),
                1 => Ok(true),
                _ => Err(FrankenError::Internal(format!(
                    "PRAGMA boolean value must be 0 or 1, got {n}"
                ))),
            };
        }
        Expr::Literal(Literal::True, _) => return Ok(true),
        Expr::Literal(Literal::False, _) => return Ok(false),
        Expr::Literal(Literal::String(s), _) => s.clone(),
        Expr::Column(col_ref, _) if col_ref.table.is_none() => col_ref.column.clone(),
        _ => {
            return Err(FrankenError::Internal(
                "PRAGMA boolean value must be ON/OFF/TRUE/FALSE/1/0".to_owned(),
            ));
        }
    };
    match text.to_ascii_lowercase().as_str() {
        "on" | "true" | "yes" | "1" => Ok(true),
        "off" | "false" | "no" | "0" => Ok(false),
        _ => Err(FrankenError::Internal(format!(
            "PRAGMA boolean value must be ON/OFF/TRUE/FALSE/1/0, got `{text}`"
        ))),
    }
}

/// Parse a PRAGMA value as a non-negative integer (`usize`).
fn parse_pragma_nonnegative_usize(value: &fsqlite_ast::PragmaValue, what: &str) -> Result<usize> {
    let expr = match value {
        fsqlite_ast::PragmaValue::Assign(e) | fsqlite_ast::PragmaValue::Call(e) => e,
    };
    let raw = match expr {
        Expr::Literal(Literal::Integer(n), _) => *n,
        Expr::UnaryOp {
            op: UnaryOp::Negate,
            expr,
            ..
        } => match expr.as_ref() {
            Expr::Literal(Literal::Integer(n), _) => n.saturating_neg(),
            _ => {
                return Err(FrankenError::Internal(format!(
                    "PRAGMA {what} must be a non-negative integer"
                )));
            }
        },
        Expr::Column(col_ref, _) if col_ref.table.is_none() => {
            col_ref.column.parse::<i64>().map_err(|_| {
                FrankenError::Internal(format!(
                    "PRAGMA {what} must be a non-negative integer, got `{}`",
                    col_ref.column
                ))
            })?
        }
        _ => {
            return Err(FrankenError::Internal(format!(
                "PRAGMA {what} must be a non-negative integer"
            )));
        }
    };

    if raw < 0 {
        return Err(FrankenError::Internal(format!(
            "PRAGMA {what} must be >= 0, got {raw}"
        )));
    }

    usize::try_from(raw).map_err(|_| {
        FrankenError::Internal(format!(
            "PRAGMA {what} value is too large for this platform: {raw}"
        ))
    })
}

/// Parse a PRAGMA value as a checkpoint mode.
///
/// Accepts `PASSIVE`, `FULL`, `RESTART`, `TRUNCATE` (case-insensitive).
fn parse_checkpoint_mode(value: &fsqlite_ast::PragmaValue) -> Result<CheckpointMode> {
    let expr = match value {
        fsqlite_ast::PragmaValue::Assign(e) | fsqlite_ast::PragmaValue::Call(e) => e,
    };
    let text = match expr {
        Expr::Literal(Literal::String(s), _) => s.clone(),
        Expr::Column(col_ref, _) if col_ref.table.is_none() => col_ref.column.clone(),
        _ => {
            return Err(FrankenError::Internal(
                "PRAGMA wal_checkpoint mode must be PASSIVE/FULL/RESTART/TRUNCATE".to_owned(),
            ));
        }
    };
    match text.to_uppercase().as_str() {
        "PASSIVE" => Ok(CheckpointMode::Passive),
        "FULL" => Ok(CheckpointMode::Full),
        "RESTART" => Ok(CheckpointMode::Restart),
        "TRUNCATE" => Ok(CheckpointMode::Truncate),
        _ => Err(FrankenError::Internal(format!(
            "PRAGMA wal_checkpoint mode must be PASSIVE/FULL/RESTART/TRUNCATE, got `{text}`"
        ))),
    }
}

const fn checkpoint_mode_code(mode: CheckpointMode) -> i64 {
    match mode {
        CheckpointMode::Passive => 0,
        CheckpointMode::Full => 1,
        CheckpointMode::Restart => 2,
        CheckpointMode::Truncate => 3,
    }
}

const fn checkpoint_mode_label(mode: CheckpointMode) -> &'static str {
    match mode {
        CheckpointMode::Passive => "PASSIVE",
        CheckpointMode::Full => "FULL",
        CheckpointMode::Restart => "RESTART",
        CheckpointMode::Truncate => "TRUNCATE",
    }
}

const fn checkpoint_schedule_override_label(mode: Option<CheckpointMode>) -> &'static str {
    match mode {
        Some(mode) => checkpoint_mode_label(mode),
        None => "AUTO",
    }
}

fn parse_checkpoint_schedule_override_mode(
    value: &fsqlite_ast::PragmaValue,
) -> Result<Option<CheckpointMode>> {
    let expr = match value {
        fsqlite_ast::PragmaValue::Assign(e) | fsqlite_ast::PragmaValue::Call(e) => e,
    };
    let text = match expr {
        Expr::Literal(Literal::String(s), _) => s.clone(),
        Expr::Column(col_ref, _) if col_ref.table.is_none() => col_ref.column.clone(),
        _ => {
            return Err(FrankenError::Internal(
                "PRAGMA fsqlite_checkpoint_schedule must be AUTO/PASSIVE/FULL/RESTART/TRUNCATE"
                    .to_owned(),
            ));
        }
    };

    match text.to_uppercase().as_str() {
        "AUTO" | "DEFAULT" => Ok(None),
        "PASSIVE" => Ok(Some(CheckpointMode::Passive)),
        "FULL" => Ok(Some(CheckpointMode::Full)),
        "RESTART" => Ok(Some(CheckpointMode::Restart)),
        "TRUNCATE" => Ok(Some(CheckpointMode::Truncate)),
        _ => Err(FrankenError::Internal(format!(
            "PRAGMA fsqlite_checkpoint_schedule must be AUTO/PASSIVE/FULL/RESTART/TRUNCATE, got `{text}`"
        ))),
    }
}

fn parse_database_header(page1_bytes: &[u8]) -> Option<DatabaseHeader> {
    if page1_bytes.iter().all(|&b| b == 0) || page1_bytes.len() < DATABASE_HEADER_SIZE {
        return None;
    }
    let mut header_bytes = [0_u8; DATABASE_HEADER_SIZE];
    header_bytes.copy_from_slice(&page1_bytes[..DATABASE_HEADER_SIZE]);
    DatabaseHeader::from_bytes(&header_bytes).ok()
}

fn parse_database_header_checked(page1_bytes: &[u8]) -> Result<DatabaseHeader> {
    if page1_bytes.iter().all(|&b| b == 0) || page1_bytes.len() < DATABASE_HEADER_SIZE {
        return Err(FrankenError::DatabaseCorrupt {
            detail: "database header missing or truncated".to_owned(),
        });
    }
    let mut header_bytes = [0_u8; DATABASE_HEADER_SIZE];
    header_bytes.copy_from_slice(&page1_bytes[..DATABASE_HEADER_SIZE]);
    DatabaseHeader::from_bytes(&header_bytes).map_err(|err| FrankenError::DatabaseCorrupt {
        detail: format!("database header invalid: {err}"),
    })
}

fn sqlite_master_signature(row: &[SqliteValue]) -> Result<(String, String, String, i64)> {
    if row.len() < 4 {
        return Err(FrankenError::DatabaseCorrupt {
            detail: format!(
                "sqlite_master row has {} columns; expected at least 4",
                row.len()
            ),
        });
    }
    let entry_type = match &row[0] {
        SqliteValue::Text(text) => text.to_ascii_lowercase(),
        other => {
            return Err(FrankenError::DatabaseCorrupt {
                detail: format!("sqlite_master type column has unexpected value {other:?}"),
            });
        }
    };
    let name = match &row[1] {
        SqliteValue::Text(text) => text.clone(),
        other => {
            return Err(FrankenError::DatabaseCorrupt {
                detail: format!("sqlite_master name column has unexpected value {other:?}"),
            });
        }
    };
    let tbl_name = match &row[2] {
        SqliteValue::Text(text) => text.clone(),
        other => {
            return Err(FrankenError::DatabaseCorrupt {
                detail: format!("sqlite_master tbl_name column has unexpected value {other:?}"),
            });
        }
    };
    let root_page = match &row[3] {
        SqliteValue::Integer(value) => *value,
        other => {
            return Err(FrankenError::DatabaseCorrupt {
                detail: format!("sqlite_master rootpage column has unexpected value {other:?}"),
            });
        }
    };
    Ok((
        entry_type,
        name.to_string(),
        tbl_name.to_string(),
        root_page,
    ))
}

fn format_master_signature(signature: &(String, String, String, i64)) -> String {
    format!(
        "(type={}, name={}, tbl_name={}, rootpage={})",
        signature.0, signature.1, signature.2, signature.3
    )
}

fn sqlite_master_sql_text(row: &[SqliteValue]) -> Result<Option<&str>> {
    match row.get(4) {
        Some(SqliteValue::Text(sql)) => Ok(Some(sql.as_ref())),
        Some(SqliteValue::Null) | None => Ok(None),
        Some(other) => Err(FrankenError::DatabaseCorrupt {
            detail: format!("sqlite_master sql column has unexpected value {other:?}"),
        }),
    }
}

fn is_implicit_autoindex_name(name: &str) -> bool {
    name.to_ascii_lowercase().starts_with("sqlite_autoindex_")
}

fn is_virtual_table_sql(sql: &str) -> bool {
    sql.trim_start()
        .to_ascii_uppercase()
        .starts_with("CREATE VIRTUAL TABLE")
}

fn is_without_rowid_table_sql(sql: &str) -> bool {
    crate::compat_persist::is_without_rowid_table_sql(sql)
}

fn should_ignore_expected_master_row_for_integrity(row: &[SqliteValue]) -> Result<bool> {
    let (entry_type, name, _, _) = sqlite_master_signature(row)?;
    Ok(entry_type == "index" && is_implicit_autoindex_name(&name))
}

fn should_ignore_actual_master_row_for_integrity(row: &[SqliteValue]) -> Result<bool> {
    let (entry_type, name, _, root_page) = sqlite_master_signature(row)?;
    if entry_type == "index" && is_implicit_autoindex_name(&name) {
        return Ok(true);
    }
    // Detect virtual tables by either of two patterns (same logic as the
    // schema-reload paths fixed in a1cee5a8 and 72e43013):
    //   1. rootpage=0 — stock SQLite convention (FTS5, rtree, etc.)
    //   2. CREATE SQL starts with CREATE VIRTUAL TABLE — FrankenSQLite-native
    //      virtual tables with a positive rootpage number.
    // Using AND was the same bug: a positive-rootpage virtual table would
    // fail condition 1, appear in actual_signatures but not in
    // expected_signatures (since the schema loader already skips it), and
    // trigger a false "unexpected entry" integrity error.
    if entry_type == "table"
        && (root_page == 0 || sqlite_master_sql_text(row)?.is_some_and(is_virtual_table_sql))
    {
        return Ok(true);
    }
    Ok(false)
}

fn page_number_from_schema_root(
    root_page: i32,
    object_name: &str,
    object_kind: &str,
) -> Result<PageNumber> {
    let raw = u32::try_from(root_page).unwrap_or(0);
    PageNumber::new(raw).ok_or_else(|| FrankenError::DatabaseCorrupt {
        detail: format!("{object_kind} `{object_name}` has invalid root page number {root_page}"),
    })
}

#[allow(clippy::too_many_lines)]
fn compile_expression_select(select: &SelectStatement) -> Result<VdbeProgram> {
    if !select.body.compounds.is_empty() {
        return Err(FrankenError::NotImplemented(
            "compound SELECT is not supported in this connection path".to_owned(),
        ));
    }

    let mut builder = ProgramBuilder::new();
    let mut bind_state = BindParamState::default();
    let init_target = builder.emit_label();
    builder.emit_jump_to_label(Opcode::Init, 0, 0, init_target, P4::None, 0);

    match &select.body.select {
        SelectCore::Select {
            columns,
            from,
            where_clause,
            group_by,
            having,
            windows,
            ..
        } => {
            // DISTINCT is handled post-execution via dedup_rows() in the
            // caller, so we can safely ignore the `distinct` field here.
            if from.is_some() {
                return Err(FrankenError::NotImplemented(
                    "SELECT ... FROM is not supported in this connection path".to_owned(),
                ));
            }
            if !group_by.is_empty() {
                return Err(FrankenError::NotImplemented(
                    "GROUP BY is not supported in this connection path".to_owned(),
                ));
            }
            if having.is_some() {
                return Err(FrankenError::NotImplemented(
                    "HAVING is not supported in this connection path".to_owned(),
                ));
            }
            if !windows.is_empty() {
                return Err(FrankenError::NotImplemented(
                    "WINDOW is not supported in this connection path".to_owned(),
                ));
            }
            if columns.is_empty() {
                return Err(FrankenError::ParseError {
                    offset: 0,
                    detail: "SELECT must include at least one result column".to_owned(),
                });
            }

            let is_count_star_only = if columns.len() == 1 {
                match &columns[0] {
                    ResultColumn::Expr {
                        expr:
                            Expr::FunctionCall {
                                name,
                                args,
                                distinct,
                                filter,
                                over,
                                ..
                            },
                        ..
                    } if name.eq_ignore_ascii_case("count")
                        && (matches!(args, FunctionArgs::Star)
                            || matches!(args, FunctionArgs::List(v) if v.is_empty())) =>
                    {
                        if *distinct || filter.is_some() || over.is_some() {
                            return Err(FrankenError::NotImplemented(
                                "function modifiers (DISTINCT/FILTER/OVER) are not supported"
                                    .to_owned(),
                            ));
                        }
                        true
                    }
                    _ => false,
                }
            } else {
                false
            };

            if is_count_star_only {
                let out_first_reg = builder.alloc_regs(1);
                if let Some(predicate) = where_clause.as_ref() {
                    let predicate_reg = builder.alloc_temp();
                    emit_expr(&mut builder, predicate, predicate_reg, &mut bind_state)?;
                    let false_label = builder.emit_label();
                    let done_label = builder.emit_label();
                    builder.emit_jump_to_label(
                        Opcode::IfNot,
                        predicate_reg,
                        1,
                        false_label,
                        P4::None,
                        0,
                    );
                    builder.free_temp(predicate_reg);
                    builder.emit_op(Opcode::Integer, 1, out_first_reg, 0, P4::None, 0);
                    builder.emit_jump_to_label(Opcode::Goto, 0, 0, done_label, P4::None, 0);
                    builder.resolve_label(false_label);
                    builder.emit_op(Opcode::Integer, 0, out_first_reg, 0, P4::None, 0);
                    builder.resolve_label(done_label);
                } else {
                    builder.emit_op(Opcode::Integer, 1, out_first_reg, 0, P4::None, 0);
                }
                builder.emit_op(Opcode::ResultRow, out_first_reg, 1, 0, P4::None, 0);
            } else {
                let out_count =
                    i32::try_from(columns.len()).map_err(|_| FrankenError::TooManyColumns {
                        count: columns.len(),
                        max: i32::MAX as usize,
                    })?;
                let out_first_reg = builder.alloc_regs(out_count);
                let skip_row_label = if let Some(predicate) = where_clause.as_ref() {
                    let predicate_reg = builder.alloc_temp();
                    emit_expr(&mut builder, predicate, predicate_reg, &mut bind_state)?;
                    let skip_label = builder.emit_label();
                    builder.emit_jump_to_label(
                        Opcode::IfNot,
                        predicate_reg,
                        1,
                        skip_label,
                        P4::None,
                        0,
                    );
                    builder.free_temp(predicate_reg);
                    Some(skip_label)
                } else {
                    None
                };

                for (idx, column) in columns.iter().enumerate() {
                    let expr = match column {
                        ResultColumn::Expr { expr, .. } => expr,
                        ResultColumn::Star | ResultColumn::TableStar(_) => {
                            return Err(FrankenError::NotImplemented(
                                "star expansion requires name resolution and FROM sources"
                                    .to_owned(),
                            ));
                        }
                    };

                    let idx_i32 = i32::try_from(idx).map_err(|_| FrankenError::OutOfRange {
                        what: "result column index".to_owned(),
                        value: idx.to_string(),
                    })?;
                    let output_reg = out_first_reg + idx_i32;
                    emit_expr(&mut builder, expr, output_reg, &mut bind_state)?;
                }

                builder.emit_op(Opcode::ResultRow, out_first_reg, out_count, 0, P4::None, 0);
                if let Some(skip_label) = skip_row_label {
                    builder.resolve_label(skip_label);
                }
            }
        }
        SelectCore::Values(rows) => {
            if rows.is_empty() {
                return Err(FrankenError::ParseError {
                    offset: 0,
                    detail: "VALUES must include at least one row".to_owned(),
                });
            }
            let first_row_len = rows[0].len();
            if first_row_len == 0 {
                return Err(FrankenError::ParseError {
                    offset: 0,
                    detail: "VALUES row must include at least one expression".to_owned(),
                });
            }
            for row in rows {
                if row.len() != first_row_len {
                    return Err(FrankenError::ParseError {
                        offset: 0,
                        detail: "VALUES rows must have matching column counts".to_owned(),
                    });
                }
            }

            let out_count =
                i32::try_from(first_row_len).map_err(|_| FrankenError::TooManyColumns {
                    count: first_row_len,
                    max: i32::MAX as usize,
                })?;
            let out_first_reg = builder.alloc_regs(out_count);

            for row in rows {
                for (idx, expr) in row.iter().enumerate() {
                    let idx_i32 = i32::try_from(idx).map_err(|_| FrankenError::OutOfRange {
                        what: "VALUES column index".to_owned(),
                        value: idx.to_string(),
                    })?;
                    emit_expr(&mut builder, expr, out_first_reg + idx_i32, &mut bind_state)?;
                }
                builder.emit_op(Opcode::ResultRow, out_first_reg, out_count, 0, P4::None, 0);
            }
        }
    }

    builder.emit_op(Opcode::Halt, 0, 0, 0, P4::None, 0);
    builder.resolve_label(init_target);
    builder.finish()
}

#[allow(clippy::too_many_lines)]
fn emit_expr(
    builder: &mut ProgramBuilder,
    expr: &Expr,
    target_reg: i32,
    bind_state: &mut BindParamState,
) -> Result<()> {
    match expr {
        Expr::Literal(literal, _) => {
            emit_literal(builder, literal, target_reg);
            Ok(())
        }
        Expr::BinaryOp {
            left, op, right, ..
        } => emit_binary_expr(builder, left, *op, right, target_reg, bind_state),
        Expr::UnaryOp { op, expr, .. } => {
            emit_unary_expr(builder, *op, expr, target_reg, bind_state)
        }
        Expr::FunctionCall {
            name,
            args,
            distinct,
            filter,
            over,
            ..
        } => emit_function_call(
            builder,
            name,
            args,
            *distinct,
            filter.is_some(),
            over.is_some(),
            target_reg,
            bind_state,
        ),
        Expr::Placeholder(placeholder, _) => {
            let param_index = placeholder_to_index(placeholder, bind_state)?;
            builder.emit_op(Opcode::Variable, param_index, target_reg, 0, P4::None, 0);
            Ok(())
        }
        Expr::Case {
            operand,
            whens,
            else_expr,
            ..
        } => emit_case_expr(
            builder,
            operand.as_deref(),
            whens,
            else_expr.as_deref(),
            target_reg,
            bind_state,
        ),
        Expr::Cast {
            expr: inner,
            type_name,
            ..
        } => {
            emit_expr(builder, inner, target_reg, bind_state)?;
            let affinity = type_name_to_affinity(&type_name.name);
            builder.emit_op(
                Opcode::Cast,
                target_reg,
                i32::from(affinity),
                0,
                P4::None,
                0,
            );
            Ok(())
        }
        Expr::IsNull {
            expr: inner, not, ..
        } => {
            emit_expr(builder, inner, target_reg, bind_state)?;
            let lbl_null = builder.emit_label();
            let lbl_done = builder.emit_label();
            builder.emit_jump_to_label(Opcode::IsNull, target_reg, 0, lbl_null, P4::None, 0);
            let val_not_null = i32::from(*not);
            let val_null = i32::from(!*not);
            builder.emit_op(Opcode::Integer, val_not_null, target_reg, 0, P4::None, 0);
            builder.emit_jump_to_label(Opcode::Goto, 0, 0, lbl_done, P4::None, 0);
            builder.resolve_label(lbl_null);
            builder.emit_op(Opcode::Integer, val_null, target_reg, 0, P4::None, 0);
            builder.resolve_label(lbl_done);
            Ok(())
        }
        // ── BETWEEN: expr [NOT] BETWEEN low AND high ──────────────────
        Expr::Between {
            expr: inner,
            low,
            high,
            not,
            ..
        } => emit_between_expr(builder, inner, low, high, *not, target_reg, bind_state),

        // ── IN: expr [NOT] IN (list) ──────────────────────────────────
        Expr::In {
            expr: inner,
            set,
            not,
            ..
        } => emit_in_expr(builder, inner, set, *not, target_reg, bind_state),

        // ── LIKE/GLOB/MATCH/REGEXP ────────────────────────────────────
        Expr::Like {
            expr: inner,
            pattern,
            escape,
            op,
            not,
            ..
        } => emit_like_expr(
            builder,
            inner,
            pattern,
            escape.as_deref(),
            *op,
            *not,
            target_reg,
            bind_state,
        ),

        // ── COLLATE: transparent wrapper – evaluate inner expression ─
        Expr::Collate { expr: inner, .. } => emit_expr(builder, inner, target_reg, bind_state),

        _ => Err(FrankenError::NotImplemented(format!(
            "expression form is not supported in this connection path: {expr:?}",
        ))),
    }
}

/// Extract the collation name from a COLLATE expression wrapper, if any.
fn extract_collation(expr: &Expr) -> Option<&str> {
    if let Expr::Collate { collation, .. } = expr {
        Some(collation.as_str())
    } else {
        None
    }
}

fn emit_binary_expr(
    builder: &mut ProgramBuilder,
    left: &Expr,
    op: BinaryOp,
    right: &Expr,
    target_reg: i32,
    bind_state: &mut BindParamState,
) -> Result<()> {
    let left_reg = builder.alloc_temp();
    let right_reg = builder.alloc_temp();
    emit_expr(builder, left, left_reg, bind_state)?;
    emit_expr(builder, right, right_reg, bind_state)?;

    let opcode = match op {
        BinaryOp::Add => Opcode::Add,
        BinaryOp::Subtract => Opcode::Subtract,
        BinaryOp::Multiply => Opcode::Multiply,
        BinaryOp::Divide => Opcode::Divide,
        BinaryOp::Modulo => Opcode::Remainder,
        BinaryOp::Concat => Opcode::Concat,
        BinaryOp::BitAnd => Opcode::BitAnd,
        BinaryOp::BitOr => Opcode::BitOr,
        BinaryOp::ShiftLeft => Opcode::ShiftLeft,
        BinaryOp::ShiftRight => Opcode::ShiftRight,
        BinaryOp::And => Opcode::And,
        BinaryOp::Or => Opcode::Or,
        // Comparison operators produce 0/1 via conditional jumps.
        BinaryOp::Eq | BinaryOp::Ne | BinaryOp::Lt | BinaryOp::Le | BinaryOp::Gt | BinaryOp::Ge => {
            let cmp_opcode = match op {
                BinaryOp::Eq => Opcode::Eq,
                BinaryOp::Ne => Opcode::Ne,
                BinaryOp::Lt => Opcode::Lt,
                BinaryOp::Le => Opcode::Le,
                BinaryOp::Gt => Opcode::Gt,
                BinaryOp::Ge => Opcode::Ge,
                _ => unreachable!(),
            };
            // Extract explicit COLLATE from either operand for the comparison.
            let coll_p4 = extract_collation(left)
                .or_else(|| extract_collation(right))
                .map_or(P4::None, |c| P4::Collation(c.to_owned()));
            // SQL three-valued logic: if either operand is NULL, result is NULL.
            let null_label = builder.emit_label();
            let true_label = builder.emit_label();
            let done_label = builder.emit_label();
            builder.emit_jump_to_label(Opcode::IsNull, left_reg, 0, null_label, P4::None, 0);
            builder.emit_jump_to_label(Opcode::IsNull, right_reg, 0, null_label, P4::None, 0);
            builder.emit_jump_to_label(cmp_opcode, right_reg, left_reg, true_label, coll_p4, 0);
            builder.emit_op(Opcode::Integer, 0, target_reg, 0, P4::None, 0);
            builder.emit_jump_to_label(Opcode::Goto, 0, 0, done_label, P4::None, 0);
            builder.resolve_label(true_label);
            builder.emit_op(Opcode::Integer, 1, target_reg, 0, P4::None, 0);
            builder.emit_jump_to_label(Opcode::Goto, 0, 0, done_label, P4::None, 0);
            builder.resolve_label(null_label);
            builder.emit_op(Opcode::Null, 0, target_reg, 0, P4::None, 0);
            builder.resolve_label(done_label);
            builder.free_temp(right_reg);
            builder.free_temp(left_reg);
            return Ok(());
        }
        BinaryOp::Is | BinaryOp::IsNot => {
            // IS TRUE / IS FALSE / IS NOT TRUE / IS NOT FALSE → IsTrue opcode.
            if let Some((p3, p4)) = is_true_false_params_core(op, right) {
                builder.emit_op(Opcode::IsTrue, left_reg, target_reg, p3, p4, 0);
                builder.free_temp(right_reg);
                builder.free_temp(left_reg);
                return Ok(());
            }
            let (cmp_opcode, nulleq_flag) = match op {
                BinaryOp::Is => (Opcode::Eq, 0x80_u16),
                BinaryOp::IsNot => (Opcode::Ne, 0x80_u16),
                _ => unreachable!(),
            };
            let true_label = builder.emit_label();
            let done_label = builder.emit_label();
            builder.emit_jump_to_label(
                cmp_opcode,
                right_reg,
                left_reg,
                true_label,
                P4::None,
                nulleq_flag,
            );
            builder.emit_op(Opcode::Integer, 0, target_reg, 0, P4::None, 0);
            builder.emit_jump_to_label(Opcode::Goto, 0, 0, done_label, P4::None, 0);
            builder.resolve_label(true_label);
            builder.emit_op(Opcode::Integer, 1, target_reg, 0, P4::None, 0);
            builder.resolve_label(done_label);
            builder.free_temp(right_reg);
            builder.free_temp(left_reg);
            return Ok(());
        }
    };

    // Engine semantics for these opcodes consume p2 (left) and p1 (right).
    builder.emit_op(opcode, right_reg, left_reg, target_reg, P4::None, 0);
    builder.free_temp(right_reg);
    builder.free_temp(left_reg);
    Ok(())
}

fn emit_unary_expr(
    builder: &mut ProgramBuilder,
    op: UnaryOp,
    expr: &Expr,
    target_reg: i32,
    bind_state: &mut BindParamState,
) -> Result<()> {
    match op {
        UnaryOp::Plus => emit_expr(builder, expr, target_reg, bind_state),
        UnaryOp::BitNot => {
            let source_reg = builder.alloc_temp();
            emit_expr(builder, expr, source_reg, bind_state)?;
            builder.emit_op(Opcode::BitNot, source_reg, target_reg, 0, P4::None, 0);
            builder.free_temp(source_reg);
            Ok(())
        }
        UnaryOp::Not => {
            let source_reg = builder.alloc_temp();
            emit_expr(builder, expr, source_reg, bind_state)?;
            builder.emit_op(Opcode::Not, source_reg, target_reg, 0, P4::None, 0);
            builder.free_temp(source_reg);
            Ok(())
        }
        UnaryOp::Negate => {
            let source_reg = builder.alloc_temp();
            let neg_one_reg = builder.alloc_temp();
            emit_expr(builder, expr, source_reg, bind_state)?;
            builder.emit_op(Opcode::Integer, -1, neg_one_reg, 0, P4::None, 0);
            // target = source * (-1)  (preserves IEEE 754 negative zero)
            builder.emit_op(
                Opcode::Multiply,
                neg_one_reg,
                source_reg,
                target_reg,
                P4::None,
                0,
            );
            builder.free_temp(neg_one_reg);
            builder.free_temp(source_reg);
            Ok(())
        }
    }
}

/// Emit a scalar function call as a `PureFunc` opcode.
///
/// Layout: arguments are evaluated into consecutive registers starting at
/// `first_arg_reg`. The opcode carries `P4::FuncName(name)`, with `p2` =
/// first arg register, `p3` = output register, and `p5` = arg count. The
/// VDBE engine looks up the function by name in its `FunctionRegistry`.
#[allow(clippy::fn_params_excessive_bools, clippy::too_many_arguments)]
fn emit_function_call(
    builder: &mut ProgramBuilder,
    name: &str,
    args: &FunctionArgs,
    distinct: bool,
    has_filter: bool,
    has_over: bool,
    target_reg: i32,
    bind_state: &mut BindParamState,
) -> Result<()> {
    if distinct || has_filter || has_over {
        return Err(FrankenError::NotImplemented(
            "function modifiers (DISTINCT/FILTER/OVER) are not supported".to_owned(),
        ));
    }

    let arguments = match args {
        FunctionArgs::List(arguments) => arguments,
        FunctionArgs::Star => {
            return Err(FrankenError::NotImplemented(
                "function(*) is not supported in expression-only SELECT".to_owned(),
            ));
        }
    };

    let arg_count = arguments.len();
    let arg_count_u16 = u16::try_from(arg_count).map_err(|_| FrankenError::TooManyArguments {
        name: name.to_owned(),
    })?;

    #[allow(clippy::cast_possible_wrap, clippy::cast_possible_truncation)]
    let first_arg_reg = builder.alloc_regs(arg_count as i32);

    // Evaluate each argument into consecutive registers.
    for (i, arg_expr) in arguments.iter().enumerate() {
        #[allow(clippy::cast_possible_wrap, clippy::cast_possible_truncation)]
        let reg = first_arg_reg + i as i32;
        emit_expr(builder, arg_expr, reg, bind_state)?;
    }

    // Emit PureFunc: p1 = 0 (flags), p2 = first_arg_reg, p3 = output_reg,
    // p4 = FuncName, p5 = arg_count.
    builder.emit_op(
        Opcode::PureFunc,
        0,
        first_arg_reg,
        target_reg,
        P4::FuncName(name.to_owned()),
        arg_count_u16,
    );
    Ok(())
}

fn emit_literal(builder: &mut ProgramBuilder, literal: &Literal, target_reg: i32) {
    match literal {
        Literal::Integer(value) => {
            if let Ok(as_i32) = i32::try_from(*value) {
                builder.emit_op(Opcode::Integer, as_i32, target_reg, 0, P4::None, 0);
            } else {
                builder.emit_op(Opcode::Int64, 0, target_reg, 0, P4::Int64(*value), 0);
            }
        }
        Literal::Float(value) => {
            builder.emit_op(Opcode::Real, 0, target_reg, 0, P4::Real(*value), 0);
        }
        Literal::String(value) => {
            builder.emit_op(Opcode::String8, 0, target_reg, 0, P4::Str(value.clone()), 0);
        }
        Literal::Null => {
            builder.emit_op(Opcode::Null, 0, target_reg, 0, P4::None, 0);
        }
        Literal::CurrentTime | Literal::CurrentDate | Literal::CurrentTimestamp => {
            builder.emit_op(
                Opcode::String8,
                0,
                target_reg,
                0,
                P4::Str(current_utc_literal_text(literal)),
                0,
            );
        }
        Literal::True => {
            builder.emit_op(Opcode::Integer, 1, target_reg, 0, P4::None, 0);
        }
        Literal::False => {
            builder.emit_op(Opcode::Integer, 0, target_reg, 0, P4::None, 0);
        }
        Literal::Blob(value) => {
            builder.emit_op(Opcode::Blob, 0, target_reg, 0, P4::Blob(value.clone()), 0);
        }
    }
}

fn current_utc_literal_text(literal: &Literal) -> String {
    use std::time::SystemTime;

    let secs = SystemTime::now()
        .duration_since(SystemTime::UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs();
    let days = secs / 86_400;
    let day_secs = secs % 86_400;
    let hour = day_secs / 3_600;
    let minute = (day_secs % 3_600) / 60;
    let second = day_secs % 60;
    let (year, month, day) = epoch_days_to_ymd(days);

    match literal {
        Literal::CurrentTimestamp => {
            format!("{year:04}-{month:02}-{day:02} {hour:02}:{minute:02}:{second:02}")
        }
        Literal::CurrentDate => format!("{year:04}-{month:02}-{day:02}"),
        Literal::CurrentTime => format!("{hour:02}:{minute:02}:{second:02}"),
        _ => unreachable!("non-current-time literal passed to current_utc_literal_text"),
    }
}

fn epoch_days_to_ymd(days: u64) -> (u64, u64, u64) {
    let z = days + 719_468;
    let era = z / 146_097;
    let doe = z - era * 146_097;
    let yoe = (doe - doe / 1_460 + doe / 36_524 - doe / 146_096) / 365;
    let mut year = yoe + era * 400;
    let doy = doe - (365 * yoe + yoe / 4 - yoe / 100);
    let mp = (5 * doy + 2) / 153;
    let day = doy - (153 * mp + 2) / 5 + 1;
    let month = if mp < 10 { mp + 3 } else { mp - 9 };
    if month <= 2 {
        year += 1;
    }
    (year, month, day)
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct BindParamState {
    next_index: i32,
    named_indices: HashMap<NamedPlaceholderKey, i32>,
}

#[derive(Debug, Clone, PartialEq, Eq, Hash)]
struct NamedPlaceholderKey {
    prefix: char,
    name: String,
}

impl Default for BindParamState {
    fn default() -> Self {
        Self {
            next_index: 1,
            named_indices: HashMap::new(),
        }
    }
}

impl BindParamState {
    fn claim_anonymous(&mut self) -> Result<i32> {
        let index = self.next_index;
        if index <= 0
            || u32::try_from(index)
                .ok()
                .is_none_or(|n| n > MAX_VARIABLE_NUMBER)
        {
            return Err(FrankenError::OutOfRange {
                what: "placeholder index".to_owned(),
                value: index.to_string(),
            });
        }
        self.next_index =
            self.next_index
                .checked_add(1)
                .ok_or_else(|| FrankenError::OutOfRange {
                    what: "placeholder index".to_owned(),
                    value: index.to_string(),
                })?;
        Ok(index)
    }

    fn register_numbered(&mut self, index: i32) -> Result<i32> {
        if index <= 0
            || u32::try_from(index)
                .ok()
                .is_none_or(|n| n > MAX_VARIABLE_NUMBER)
        {
            return Err(FrankenError::OutOfRange {
                what: "placeholder index".to_owned(),
                value: index.to_string(),
            });
        }
        let next = index
            .checked_add(1)
            .ok_or_else(|| FrankenError::OutOfRange {
                what: "placeholder index".to_owned(),
                value: index.to_string(),
            })?;
        self.next_index = self.next_index.max(next);
        Ok(index)
    }

    fn register_named(&mut self, prefix: char, name: &str) -> Result<i32> {
        let key = NamedPlaceholderKey {
            prefix,
            name: name.to_owned(),
        };
        if let Some(index) = self.named_indices.get(&key) {
            return Ok(*index);
        }

        let index = self.claim_anonymous()?;
        self.named_indices.insert(key, index);
        Ok(index)
    }
}

fn placeholder_to_index(
    placeholder: &PlaceholderType,
    bind_state: &mut BindParamState,
) -> Result<i32> {
    match placeholder {
        PlaceholderType::Anonymous => bind_state.claim_anonymous(),
        PlaceholderType::Numbered(index) => {
            let index = i32::try_from(*index).map_err(|_| FrankenError::OutOfRange {
                what: "placeholder index".to_owned(),
                value: index.to_string(),
            })?;
            bind_state.register_numbered(index)
        }
        PlaceholderType::ColonNamed(name) => bind_state.register_named(':', name),
        PlaceholderType::AtNamed(name) => bind_state.register_named('@', name),
        PlaceholderType::DollarNamed(name) => bind_state.register_named('$', name),
    }
}

fn canonicalize_select_placeholders(select: &SelectStatement) -> Result<SelectStatement> {
    let mut normalized = select.clone();
    let mut bind_state = BindParamState::default();
    canonicalize_select_placeholders_in_statement(&mut normalized, &mut bind_state)?;
    Ok(normalized)
}

fn canonicalize_select_placeholders_in_statement(
    select: &mut SelectStatement,
    bind_state: &mut BindParamState,
) -> Result<()> {
    if let Some(with_clause) = &mut select.with {
        for cte in &mut with_clause.ctes {
            canonicalize_select_placeholders_in_statement(&mut cte.query, bind_state)?;
        }
    }

    canonicalize_select_placeholders_in_core(&mut select.body.select, bind_state)?;
    for (_, core) in &mut select.body.compounds {
        canonicalize_select_placeholders_in_core(core, bind_state)?;
    }

    for ordering in &mut select.order_by {
        canonicalize_expr_placeholders(&mut ordering.expr, bind_state)?;
    }
    if let Some(limit_clause) = &mut select.limit {
        canonicalize_expr_placeholders(&mut limit_clause.limit, bind_state)?;
        if let Some(offset) = &mut limit_clause.offset {
            canonicalize_expr_placeholders(offset, bind_state)?;
        }
    }

    Ok(())
}

fn canonicalize_select_placeholders_in_core(
    core: &mut SelectCore,
    bind_state: &mut BindParamState,
) -> Result<()> {
    match core {
        SelectCore::Select {
            columns,
            from,
            where_clause,
            group_by,
            having,
            windows,
            ..
        } => {
            for column in columns {
                if let ResultColumn::Expr { expr, .. } = column {
                    canonicalize_expr_placeholders(expr, bind_state)?;
                }
            }
            if let Some(from_clause) = from {
                canonicalize_placeholders_in_from_clause(from_clause, bind_state)?;
            }
            if let Some(predicate) = where_clause {
                canonicalize_expr_placeholders(predicate, bind_state)?;
            }
            for expr in group_by {
                canonicalize_expr_placeholders(expr, bind_state)?;
            }
            if let Some(predicate) = having {
                canonicalize_expr_placeholders(predicate, bind_state)?;
            }
            for window in windows {
                canonicalize_placeholders_in_window_spec(&mut window.spec, bind_state)?;
            }
        }
        SelectCore::Values(rows) => {
            for row in rows {
                for expr in row {
                    canonicalize_expr_placeholders(expr, bind_state)?;
                }
            }
        }
    }
    Ok(())
}

fn canonicalize_placeholders_in_from_clause(
    from: &mut fsqlite_ast::FromClause,
    bind_state: &mut BindParamState,
) -> Result<()> {
    canonicalize_placeholders_in_table_or_subquery(&mut from.source, bind_state)?;
    for join in &mut from.joins {
        canonicalize_placeholders_in_table_or_subquery(&mut join.table, bind_state)?;
        if let Some(JoinConstraint::On(expr)) = &mut join.constraint {
            canonicalize_expr_placeholders(expr, bind_state)?;
        }
    }
    Ok(())
}

fn canonicalize_placeholders_in_table_or_subquery(
    source: &mut TableOrSubquery,
    bind_state: &mut BindParamState,
) -> Result<()> {
    match source {
        TableOrSubquery::Table { .. } => {}
        TableOrSubquery::Subquery { query, .. } => {
            canonicalize_select_placeholders_in_statement(query, bind_state)?;
        }
        TableOrSubquery::TableFunction { args, .. } => {
            for arg in args {
                canonicalize_expr_placeholders(arg, bind_state)?;
            }
        }
        TableOrSubquery::ParenJoin(from_clause) => {
            canonicalize_placeholders_in_from_clause(from_clause, bind_state)?;
        }
    }
    Ok(())
}

fn canonicalize_placeholders_in_window_spec(
    spec: &mut fsqlite_ast::WindowSpec,
    bind_state: &mut BindParamState,
) -> Result<()> {
    for expr in &mut spec.partition_by {
        canonicalize_expr_placeholders(expr, bind_state)?;
    }
    for ordering in &mut spec.order_by {
        canonicalize_expr_placeholders(&mut ordering.expr, bind_state)?;
    }
    if let Some(frame) = &mut spec.frame {
        canonicalize_placeholders_in_frame_bound(&mut frame.start, bind_state)?;
        if let Some(end) = &mut frame.end {
            canonicalize_placeholders_in_frame_bound(end, bind_state)?;
        }
    }
    Ok(())
}

fn canonicalize_placeholders_in_frame_bound(
    bound: &mut fsqlite_ast::FrameBound,
    bind_state: &mut BindParamState,
) -> Result<()> {
    match bound {
        fsqlite_ast::FrameBound::Preceding(expr) | fsqlite_ast::FrameBound::Following(expr) => {
            canonicalize_expr_placeholders(expr, bind_state)?;
        }
        fsqlite_ast::FrameBound::UnboundedPreceding
        | fsqlite_ast::FrameBound::CurrentRow
        | fsqlite_ast::FrameBound::UnboundedFollowing => {}
    }
    Ok(())
}

fn canonicalize_expr_placeholders(expr: &mut Expr, bind_state: &mut BindParamState) -> Result<()> {
    match expr {
        Expr::BinaryOp { left, right, .. } => {
            canonicalize_expr_placeholders(left, bind_state)?;
            canonicalize_expr_placeholders(right, bind_state)?;
        }
        Expr::UnaryOp { expr: inner, .. }
        | Expr::IsNull { expr: inner, .. }
        | Expr::Cast { expr: inner, .. }
        | Expr::Collate { expr: inner, .. } => {
            canonicalize_expr_placeholders(inner, bind_state)?;
        }
        Expr::Between {
            expr: inner,
            low,
            high,
            ..
        } => {
            canonicalize_expr_placeholders(inner, bind_state)?;
            canonicalize_expr_placeholders(low, bind_state)?;
            canonicalize_expr_placeholders(high, bind_state)?;
        }
        Expr::In {
            expr: inner, set, ..
        } => {
            canonicalize_expr_placeholders(inner, bind_state)?;
            match set {
                fsqlite_ast::InSet::List(values) => {
                    for value in values {
                        canonicalize_expr_placeholders(value, bind_state)?;
                    }
                }
                fsqlite_ast::InSet::Subquery(query) => {
                    canonicalize_select_placeholders_in_statement(query, bind_state)?;
                }
                fsqlite_ast::InSet::Table(_) => {}
            }
        }
        Expr::Like {
            expr: inner,
            pattern,
            escape,
            ..
        } => {
            canonicalize_expr_placeholders(inner, bind_state)?;
            canonicalize_expr_placeholders(pattern, bind_state)?;
            if let Some(escape_expr) = escape {
                canonicalize_expr_placeholders(escape_expr, bind_state)?;
            }
        }
        Expr::Case {
            operand,
            whens,
            else_expr,
            ..
        } => {
            if let Some(base) = operand {
                canonicalize_expr_placeholders(base, bind_state)?;
            }
            for (when_expr, then_expr) in whens {
                canonicalize_expr_placeholders(when_expr, bind_state)?;
                canonicalize_expr_placeholders(then_expr, bind_state)?;
            }
            if let Some(else_branch) = else_expr {
                canonicalize_expr_placeholders(else_branch, bind_state)?;
            }
        }
        Expr::Subquery(subquery, _) | Expr::Exists { subquery, .. } => {
            canonicalize_select_placeholders_in_statement(subquery, bind_state)?;
        }
        Expr::FunctionCall {
            args, filter, over, ..
        } => {
            if let FunctionArgs::List(list) = args {
                for arg in list {
                    canonicalize_expr_placeholders(arg, bind_state)?;
                }
            }
            if let Some(filter_expr) = filter {
                canonicalize_expr_placeholders(filter_expr, bind_state)?;
            }
            if let Some(window_spec) = over {
                canonicalize_placeholders_in_window_spec(window_spec, bind_state)?;
            }
        }
        Expr::JsonAccess {
            expr: inner, path, ..
        } => {
            canonicalize_expr_placeholders(inner, bind_state)?;
            canonicalize_expr_placeholders(path, bind_state)?;
        }
        Expr::RowValue(values, _) => {
            for value in values {
                canonicalize_expr_placeholders(value, bind_state)?;
            }
        }
        Expr::Placeholder(placeholder, span) => {
            let index = placeholder_to_index(placeholder, bind_state)?;
            let numbered = u32::try_from(index).map_err(|_| FrankenError::OutOfRange {
                what: "placeholder index".to_owned(),
                value: index.to_string(),
            })?;
            *expr = Expr::Placeholder(PlaceholderType::Numbered(numbered), *span);
        }
        Expr::Literal(_, _) | Expr::Column(_, _) | Expr::Raise { .. } => {}
    }
    Ok(())
}

/// Bind SELECT placeholders to literal values for fallback evaluators.
///
/// Fallback JOIN/GROUP BY paths interpret expressions directly instead of
/// executing VDBE `Variable` opcodes, so bind parameters must be substituted
/// into the AST beforehand.
fn bind_placeholders_in_select_for_fallback(
    select: &SelectStatement,
    params: Option<&[SqliteValue]>,
) -> Result<SelectStatement> {
    let Some(params) = params else {
        return Ok(select.clone());
    };
    let mut bound = select.clone();
    let mut bind_state = BindParamState::default();
    bind_placeholders_in_select_statement(&mut bound, &mut bind_state, params)?;
    Ok(bound)
}

fn bind_placeholders_in_select_statement(
    select: &mut SelectStatement,
    bind_state: &mut BindParamState,
    params: &[SqliteValue],
) -> Result<()> {
    if let Some(with_clause) = &mut select.with {
        for cte in &mut with_clause.ctes {
            bind_placeholders_in_select_statement(&mut cte.query, bind_state, params)?;
        }
    }

    bind_placeholders_in_select_core(&mut select.body.select, bind_state, params)?;
    for (_, core) in &mut select.body.compounds {
        bind_placeholders_in_select_core(core, bind_state, params)?;
    }

    for ordering in &mut select.order_by {
        bind_placeholders_in_expr(&mut ordering.expr, bind_state, params)?;
    }
    if let Some(limit_clause) = &mut select.limit {
        bind_placeholders_in_expr(&mut limit_clause.limit, bind_state, params)?;
        if let Some(offset) = &mut limit_clause.offset {
            bind_placeholders_in_expr(offset, bind_state, params)?;
        }
    }

    Ok(())
}

fn bind_placeholders_in_select_core(
    core: &mut SelectCore,
    bind_state: &mut BindParamState,
    params: &[SqliteValue],
) -> Result<()> {
    match core {
        SelectCore::Select {
            columns,
            from,
            where_clause,
            group_by,
            having,
            windows,
            ..
        } => {
            for column in columns {
                if let ResultColumn::Expr { expr, .. } = column {
                    bind_placeholders_in_expr(expr, bind_state, params)?;
                }
            }
            if let Some(from_clause) = from {
                bind_placeholders_in_from_clause(from_clause, bind_state, params)?;
            }
            if let Some(predicate) = where_clause {
                bind_placeholders_in_expr(predicate, bind_state, params)?;
            }
            for expr in group_by {
                bind_placeholders_in_expr(expr, bind_state, params)?;
            }
            if let Some(predicate) = having {
                bind_placeholders_in_expr(predicate, bind_state, params)?;
            }
            for window in windows {
                bind_placeholders_in_window_spec(&mut window.spec, bind_state, params)?;
            }
        }
        SelectCore::Values(rows) => {
            for row in rows {
                for expr in row {
                    bind_placeholders_in_expr(expr, bind_state, params)?;
                }
            }
        }
    }
    Ok(())
}

fn bind_placeholders_in_from_clause(
    from: &mut fsqlite_ast::FromClause,
    bind_state: &mut BindParamState,
    params: &[SqliteValue],
) -> Result<()> {
    bind_placeholders_in_table_or_subquery(&mut from.source, bind_state, params)?;
    for join in &mut from.joins {
        bind_placeholders_in_table_or_subquery(&mut join.table, bind_state, params)?;
        if let Some(JoinConstraint::On(expr)) = &mut join.constraint {
            bind_placeholders_in_expr(expr, bind_state, params)?;
        }
    }
    Ok(())
}

fn bind_placeholders_in_table_or_subquery(
    source: &mut TableOrSubquery,
    bind_state: &mut BindParamState,
    params: &[SqliteValue],
) -> Result<()> {
    match source {
        TableOrSubquery::Table { .. } => {}
        TableOrSubquery::Subquery { query, .. } => {
            bind_placeholders_in_select_statement(query, bind_state, params)?;
        }
        TableOrSubquery::TableFunction { args, .. } => {
            for arg in args {
                bind_placeholders_in_expr(arg, bind_state, params)?;
            }
        }
        TableOrSubquery::ParenJoin(from_clause) => {
            bind_placeholders_in_from_clause(from_clause, bind_state, params)?;
        }
    }
    Ok(())
}

fn bind_placeholders_in_window_spec(
    spec: &mut fsqlite_ast::WindowSpec,
    bind_state: &mut BindParamState,
    params: &[SqliteValue],
) -> Result<()> {
    for expr in &mut spec.partition_by {
        bind_placeholders_in_expr(expr, bind_state, params)?;
    }
    for ordering in &mut spec.order_by {
        bind_placeholders_in_expr(&mut ordering.expr, bind_state, params)?;
    }
    if let Some(frame) = &mut spec.frame {
        bind_placeholders_in_frame_bound(&mut frame.start, bind_state, params)?;
        if let Some(end) = &mut frame.end {
            bind_placeholders_in_frame_bound(end, bind_state, params)?;
        }
    }
    Ok(())
}

fn bind_placeholders_in_frame_bound(
    bound: &mut fsqlite_ast::FrameBound,
    bind_state: &mut BindParamState,
    params: &[SqliteValue],
) -> Result<()> {
    match bound {
        fsqlite_ast::FrameBound::Preceding(expr) | fsqlite_ast::FrameBound::Following(expr) => {
            bind_placeholders_in_expr(expr, bind_state, params)?;
        }
        fsqlite_ast::FrameBound::UnboundedPreceding
        | fsqlite_ast::FrameBound::CurrentRow
        | fsqlite_ast::FrameBound::UnboundedFollowing => {}
    }
    Ok(())
}

fn bind_placeholder_to_literal(
    placeholder: &PlaceholderType,
    bind_state: &mut BindParamState,
    params: &[SqliteValue],
) -> Result<Literal> {
    let param_index = placeholder_to_index(placeholder, bind_state)?;
    let one_based = usize::try_from(param_index).map_err(|_| FrankenError::OutOfRange {
        what: "bind parameter index".to_owned(),
        value: param_index.to_string(),
    })?;
    if one_based == 0 || one_based > params.len() {
        return Err(FrankenError::OutOfRange {
            what: "bind parameter index".to_owned(),
            value: param_index.to_string(),
        });
    }
    Ok(sqlite_value_to_literal(&params[one_based - 1]))
}

fn sqlite_value_to_literal(value: &SqliteValue) -> Literal {
    match value {
        SqliteValue::Null => Literal::Null,
        SqliteValue::Integer(v) => Literal::Integer(*v),
        SqliteValue::Float(v) => Literal::Float(*v),
        SqliteValue::Text(v) => Literal::String(v.to_string()),
        SqliteValue::Blob(v) => Literal::Blob(v.to_vec()),
    }
}

#[allow(clippy::too_many_lines)]
fn bind_trigger_columns_in_statement(statement: &mut Statement, frame: &TriggerFrame) {
    match statement {
        Statement::Select(select) => {
            bind_trigger_columns_in_select_statement(select, frame);
        }
        Statement::Insert(insert) => {
            if let Some(with_clause) = &mut insert.with {
                for cte in &mut with_clause.ctes {
                    bind_trigger_columns_in_select_statement(&mut cte.query, frame);
                }
            }
            match &mut insert.source {
                fsqlite_ast::InsertSource::Values(rows) => {
                    for row in rows {
                        for expr in row {
                            bind_trigger_columns_in_expr(expr, frame);
                        }
                    }
                }
                fsqlite_ast::InsertSource::Select(select) => {
                    bind_trigger_columns_in_select_statement(select, frame);
                }
                fsqlite_ast::InsertSource::DefaultValues => {}
            }
            for upsert in &mut insert.upsert {
                if let Some(target) = &mut upsert.target {
                    if let Some(where_clause) = &mut target.where_clause {
                        bind_trigger_columns_in_expr(where_clause, frame);
                    }
                }
                if let fsqlite_ast::UpsertAction::Update {
                    assignments,
                    where_clause,
                } = &mut upsert.action
                {
                    for assignment in assignments {
                        bind_trigger_columns_in_expr(&mut assignment.value, frame);
                    }
                    if let Some(predicate) = where_clause {
                        bind_trigger_columns_in_expr(predicate, frame);
                    }
                }
            }
            for column in &mut insert.returning {
                if let ResultColumn::Expr { expr, .. } = column {
                    bind_trigger_columns_in_expr(expr, frame);
                }
            }
        }
        Statement::Update(update) => {
            if let Some(with_clause) = &mut update.with {
                for cte in &mut with_clause.ctes {
                    bind_trigger_columns_in_select_statement(&mut cte.query, frame);
                }
            }
            // In DML trigger bodies, bare column references in SET values
            // and WHERE clauses refer to the DML's target table columns,
            // not to the trigger's NEW/OLD pseudo-columns.  Use the
            // prefix-only variant so only explicit NEW.x / OLD.x refs
            // are replaced with trigger values.
            for assignment in &mut update.assignments {
                bind_trigger_prefixed_only_in_expr(&mut assignment.value, frame);
            }
            if let Some(from_clause) = &mut update.from {
                bind_trigger_columns_in_from_clause(from_clause, frame);
            }
            if let Some(where_clause) = &mut update.where_clause {
                bind_trigger_prefixed_only_in_expr(where_clause, frame);
            }
            for column in &mut update.returning {
                if let ResultColumn::Expr { expr, .. } = column {
                    bind_trigger_columns_in_expr(expr, frame);
                }
            }
            for ordering in &mut update.order_by {
                bind_trigger_prefixed_only_in_expr(&mut ordering.expr, frame);
            }
            if let Some(limit_clause) = &mut update.limit {
                bind_trigger_prefixed_only_in_expr(&mut limit_clause.limit, frame);
                if let Some(offset) = &mut limit_clause.offset {
                    bind_trigger_prefixed_only_in_expr(offset, frame);
                }
            }
        }
        Statement::Delete(delete) => {
            if let Some(with_clause) = &mut delete.with {
                for cte in &mut with_clause.ctes {
                    bind_trigger_columns_in_select_statement(&mut cte.query, frame);
                }
            }
            if let Some(where_clause) = &mut delete.where_clause {
                bind_trigger_prefixed_only_in_expr(where_clause, frame);
            }
            for column in &mut delete.returning {
                if let ResultColumn::Expr { expr, .. } = column {
                    bind_trigger_columns_in_expr(expr, frame);
                }
            }
            for ordering in &mut delete.order_by {
                bind_trigger_prefixed_only_in_expr(&mut ordering.expr, frame);
            }
            if let Some(limit_clause) = &mut delete.limit {
                bind_trigger_prefixed_only_in_expr(&mut limit_clause.limit, frame);
                if let Some(offset) = &mut limit_clause.offset {
                    bind_trigger_prefixed_only_in_expr(offset, frame);
                }
            }
        }
        Statement::CreateTrigger(create_trigger) => {
            if let Some(when_clause) = &mut create_trigger.when {
                bind_trigger_columns_in_expr(when_clause, frame);
            }
            for body_stmt in &mut create_trigger.body {
                bind_trigger_columns_in_statement(body_stmt, frame);
            }
        }
        _ => {}
    }
}

fn bind_trigger_columns_in_select_statement(select: &mut SelectStatement, frame: &TriggerFrame) {
    if let Some(with_clause) = &mut select.with {
        for cte in &mut with_clause.ctes {
            bind_trigger_columns_in_select_statement(&mut cte.query, frame);
        }
    }

    bind_trigger_columns_in_select_core(&mut select.body.select, frame);
    for (_, core) in &mut select.body.compounds {
        bind_trigger_columns_in_select_core(core, frame);
    }

    for ordering in &mut select.order_by {
        bind_trigger_columns_in_expr(&mut ordering.expr, frame);
    }
    if let Some(limit_clause) = &mut select.limit {
        bind_trigger_columns_in_expr(&mut limit_clause.limit, frame);
        if let Some(offset) = &mut limit_clause.offset {
            bind_trigger_columns_in_expr(offset, frame);
        }
    }
}

fn bind_trigger_columns_in_select_core(core: &mut SelectCore, frame: &TriggerFrame) {
    match core {
        SelectCore::Select {
            columns,
            from,
            where_clause,
            group_by,
            having,
            windows,
            ..
        } => {
            for column in columns {
                if let ResultColumn::Expr { expr, .. } = column {
                    bind_trigger_columns_in_expr(expr, frame);
                }
            }
            if let Some(from_clause) = from {
                bind_trigger_columns_in_from_clause(from_clause, frame);
            }
            if let Some(predicate) = where_clause {
                bind_trigger_columns_in_expr(predicate, frame);
            }
            for expr in group_by {
                bind_trigger_columns_in_expr(expr, frame);
            }
            if let Some(predicate) = having {
                bind_trigger_columns_in_expr(predicate, frame);
            }
            for window in windows {
                bind_trigger_columns_in_window_spec(&mut window.spec, frame);
            }
        }
        SelectCore::Values(rows) => {
            for row in rows {
                for expr in row {
                    bind_trigger_columns_in_expr(expr, frame);
                }
            }
        }
    }
}

fn bind_trigger_columns_in_from_clause(from: &mut fsqlite_ast::FromClause, frame: &TriggerFrame) {
    bind_trigger_columns_in_table_or_subquery(&mut from.source, frame);
    for join in &mut from.joins {
        bind_trigger_columns_in_table_or_subquery(&mut join.table, frame);
        if let Some(JoinConstraint::On(expr)) = &mut join.constraint {
            bind_trigger_columns_in_expr(expr, frame);
        }
    }
}

fn bind_trigger_columns_in_table_or_subquery(source: &mut TableOrSubquery, frame: &TriggerFrame) {
    match source {
        TableOrSubquery::Table { .. } => {}
        TableOrSubquery::Subquery { query, .. } => {
            bind_trigger_columns_in_select_statement(query, frame);
        }
        TableOrSubquery::TableFunction { args, .. } => {
            for arg in args {
                bind_trigger_columns_in_expr(arg, frame);
            }
        }
        TableOrSubquery::ParenJoin(from_clause) => {
            bind_trigger_columns_in_from_clause(from_clause, frame);
        }
    }
}

fn bind_trigger_columns_in_window_spec(spec: &mut fsqlite_ast::WindowSpec, frame: &TriggerFrame) {
    for expr in &mut spec.partition_by {
        bind_trigger_columns_in_expr(expr, frame);
    }
    for ordering in &mut spec.order_by {
        bind_trigger_columns_in_expr(&mut ordering.expr, frame);
    }
    if let Some(window_frame) = &mut spec.frame {
        bind_trigger_columns_in_frame_bound(&mut window_frame.start, frame);
        if let Some(end) = &mut window_frame.end {
            bind_trigger_columns_in_frame_bound(end, frame);
        }
    }
}

fn bind_trigger_columns_in_frame_bound(bound: &mut fsqlite_ast::FrameBound, frame: &TriggerFrame) {
    match bound {
        fsqlite_ast::FrameBound::Preceding(expr) | fsqlite_ast::FrameBound::Following(expr) => {
            bind_trigger_columns_in_expr(expr, frame);
        }
        fsqlite_ast::FrameBound::UnboundedPreceding
        | fsqlite_ast::FrameBound::CurrentRow
        | fsqlite_ast::FrameBound::UnboundedFollowing => {}
    }
}

#[allow(clippy::too_many_lines)]
fn bind_trigger_columns_in_expr(expr: &mut Expr, frame: &TriggerFrame) {
    bind_trigger_columns_in_expr_inner(expr, frame, false);
}

/// Like [`bind_trigger_columns_in_expr`], but only replaces column references
/// that have an explicit `OLD.` or `NEW.` prefix.  Bare column references
/// (no qualifier) and table-qualified references (`t.id`) are left untouched
/// so they resolve against the DML's target table at execution time.
///
/// Used for UPDATE/DELETE WHERE and SET clauses inside trigger bodies, where
/// `id` in `WHERE id = NEW.id` must refer to the scan row's column — not be
/// replaced with the trigger pseudo-column value (which would turn the
/// predicate into `WHERE 1 = 1`).
fn bind_trigger_prefixed_only_in_expr(expr: &mut Expr, frame: &TriggerFrame) {
    bind_trigger_columns_in_expr_inner(expr, frame, true);
}

#[allow(clippy::too_many_lines)]
fn bind_trigger_columns_in_expr_inner(expr: &mut Expr, frame: &TriggerFrame, prefix_only: bool) {
    match expr {
        Expr::Literal(_, _) | Expr::Raise { .. } | Expr::Placeholder(_, _) => {}
        Expr::Column(col_ref, _) => {
            let table_prefix = col_ref.table.as_deref();
            if prefix_only {
                // In prefix_only mode (DML WHERE/SET inside trigger bodies),
                // only replace column references with an explicit OLD or NEW
                // qualifier.  Bare names (`id`) and table-qualified names
                // (`t.id`) must resolve against the DML's target table at
                // execution time — they are NOT trigger pseudo-columns.
                let is_old_or_new = table_prefix.is_some_and(|p| {
                    p.eq_ignore_ascii_case("old") || p.eq_ignore_ascii_case("new")
                });
                if !is_old_or_new {
                    return;
                }
            }
            let column_name = col_ref.column.clone();
            if frame.references_pseudo_column(table_prefix, &column_name) {
                if let Some(value) = frame.lookup_value(table_prefix, &column_name) {
                    *expr = value_to_literal_expr(value);
                }
            }
        }
        Expr::BinaryOp { left, right, .. } => {
            bind_trigger_columns_in_expr_inner(left, frame, prefix_only);
            bind_trigger_columns_in_expr_inner(right, frame, prefix_only);
        }
        Expr::UnaryOp { expr: inner, .. }
        | Expr::Cast { expr: inner, .. }
        | Expr::Collate { expr: inner, .. }
        | Expr::IsNull { expr: inner, .. } => {
            bind_trigger_columns_in_expr_inner(inner, frame, prefix_only);
        }
        Expr::Between {
            expr: inner,
            low,
            high,
            ..
        } => {
            bind_trigger_columns_in_expr_inner(inner, frame, prefix_only);
            bind_trigger_columns_in_expr_inner(low, frame, prefix_only);
            bind_trigger_columns_in_expr_inner(high, frame, prefix_only);
        }
        Expr::In {
            expr: inner, set, ..
        } => {
            bind_trigger_columns_in_expr_inner(inner, frame, prefix_only);
            match set {
                InSet::List(values) => {
                    for value in values {
                        bind_trigger_columns_in_expr_inner(value, frame, prefix_only);
                    }
                }
                InSet::Subquery(query) => {
                    bind_trigger_columns_in_select_statement(query, frame);
                }
                InSet::Table(_) => {}
            }
        }
        Expr::Like {
            expr: inner,
            pattern,
            escape,
            ..
        } => {
            bind_trigger_columns_in_expr_inner(inner, frame, prefix_only);
            bind_trigger_columns_in_expr_inner(pattern, frame, prefix_only);
            if let Some(escape_expr) = escape {
                bind_trigger_columns_in_expr_inner(escape_expr, frame, prefix_only);
            }
        }
        Expr::Case {
            operand,
            whens,
            else_expr,
            ..
        } => {
            if let Some(base) = operand {
                bind_trigger_columns_in_expr_inner(base, frame, prefix_only);
            }
            for (when_expr, then_expr) in whens {
                bind_trigger_columns_in_expr_inner(when_expr, frame, prefix_only);
                bind_trigger_columns_in_expr_inner(then_expr, frame, prefix_only);
            }
            if let Some(else_branch) = else_expr {
                bind_trigger_columns_in_expr_inner(else_branch, frame, prefix_only);
            }
        }
        Expr::Exists { subquery, .. } | Expr::Subquery(subquery, _) => {
            bind_trigger_columns_in_select_statement(subquery, frame);
        }
        Expr::FunctionCall {
            args, filter, over, ..
        } => {
            if let FunctionArgs::List(arguments) = args {
                for arg in arguments {
                    bind_trigger_columns_in_expr_inner(arg, frame, prefix_only);
                }
            }
            if let Some(filter_expr) = filter {
                bind_trigger_columns_in_expr_inner(filter_expr, frame, prefix_only);
            }
            if let Some(window_spec) = over {
                bind_trigger_columns_in_window_spec(window_spec, frame);
            }
        }
        Expr::JsonAccess {
            expr: inner, path, ..
        } => {
            bind_trigger_columns_in_expr_inner(inner, frame, prefix_only);
            bind_trigger_columns_in_expr_inner(path, frame, prefix_only);
        }
        Expr::RowValue(values, _) => {
            for value in values {
                bind_trigger_columns_in_expr_inner(value, frame, prefix_only);
            }
        }
    }
}

#[allow(clippy::too_many_lines)]
fn bind_placeholders_in_expr(
    expr: &mut Expr,
    bind_state: &mut BindParamState,
    params: &[SqliteValue],
) -> Result<()> {
    match expr {
        Expr::Literal(_, _) | Expr::Column(_, _) | Expr::Raise { .. } => {}
        Expr::BinaryOp { left, right, .. } => {
            bind_placeholders_in_expr(left, bind_state, params)?;
            bind_placeholders_in_expr(right, bind_state, params)?;
        }
        Expr::UnaryOp { expr: inner, .. }
        | Expr::Cast { expr: inner, .. }
        | Expr::Collate { expr: inner, .. }
        | Expr::IsNull { expr: inner, .. } => {
            bind_placeholders_in_expr(inner, bind_state, params)?;
        }
        Expr::Between {
            expr: inner,
            low,
            high,
            ..
        } => {
            bind_placeholders_in_expr(inner, bind_state, params)?;
            bind_placeholders_in_expr(low, bind_state, params)?;
            bind_placeholders_in_expr(high, bind_state, params)?;
        }
        Expr::In {
            expr: inner, set, ..
        } => {
            bind_placeholders_in_expr(inner, bind_state, params)?;
            match set {
                InSet::List(values) => {
                    for value in values {
                        bind_placeholders_in_expr(value, bind_state, params)?;
                    }
                }
                InSet::Subquery(query) => {
                    bind_placeholders_in_select_statement(query, bind_state, params)?;
                }
                InSet::Table(_) => {}
            }
        }
        Expr::Like {
            expr: inner,
            pattern,
            escape,
            ..
        } => {
            bind_placeholders_in_expr(inner, bind_state, params)?;
            bind_placeholders_in_expr(pattern, bind_state, params)?;
            if let Some(escape_expr) = escape {
                bind_placeholders_in_expr(escape_expr, bind_state, params)?;
            }
        }
        Expr::Case {
            operand,
            whens,
            else_expr,
            ..
        } => {
            if let Some(base) = operand {
                bind_placeholders_in_expr(base, bind_state, params)?;
            }
            for (when_expr, then_expr) in whens {
                bind_placeholders_in_expr(when_expr, bind_state, params)?;
                bind_placeholders_in_expr(then_expr, bind_state, params)?;
            }
            if let Some(else_branch) = else_expr {
                bind_placeholders_in_expr(else_branch, bind_state, params)?;
            }
        }
        Expr::Exists { subquery, .. } | Expr::Subquery(subquery, _) => {
            bind_placeholders_in_select_statement(subquery, bind_state, params)?;
        }
        Expr::FunctionCall {
            args, filter, over, ..
        } => {
            if let FunctionArgs::List(arguments) = args {
                for arg in arguments {
                    bind_placeholders_in_expr(arg, bind_state, params)?;
                }
            }
            if let Some(filter_expr) = filter {
                bind_placeholders_in_expr(filter_expr, bind_state, params)?;
            }
            if let Some(window_spec) = over {
                bind_placeholders_in_window_spec(window_spec, bind_state, params)?;
            }
        }
        Expr::JsonAccess {
            expr: inner, path, ..
        } => {
            bind_placeholders_in_expr(inner, bind_state, params)?;
            bind_placeholders_in_expr(path, bind_state, params)?;
        }
        Expr::RowValue(values, _) => {
            for value in values {
                bind_placeholders_in_expr(value, bind_state, params)?;
            }
        }
        Expr::Placeholder(placeholder, span) => {
            let literal = bind_placeholder_to_literal(placeholder, bind_state, params)?;
            *expr = Expr::Literal(literal, *span);
        }
    }
    Ok(())
}

fn emit_case_expr(
    builder: &mut ProgramBuilder,
    operand: Option<&Expr>,
    whens: &[(Expr, Expr)],
    else_expr: Option<&Expr>,
    target_reg: i32,
    bind_state: &mut BindParamState,
) -> Result<()> {
    let done_label = builder.emit_label();
    let r_operand = if let Some(op_expr) = operand {
        let r = builder.alloc_temp();
        emit_expr(builder, op_expr, r, bind_state)?;
        Some(r)
    } else {
        None
    };

    for (when_expr, then_expr) in whens {
        let next_when = builder.emit_label();

        if let Some(r_op) = r_operand {
            let r_when = builder.alloc_temp();
            emit_expr(builder, when_expr, r_when, bind_state)?;
            // NULL in either operand or WHEN value means no match
            // (NULL = x is UNKNOWN in SQL, which is falsy for CASE).
            builder.emit_jump_to_label(Opcode::IsNull, r_op, 0, next_when, P4::None, 0);
            builder.emit_jump_to_label(Opcode::IsNull, r_when, 0, next_when, P4::None, 0);
            builder.emit_jump_to_label(Opcode::Ne, r_when, r_op, next_when, P4::None, 0);
            builder.free_temp(r_when);
        } else {
            emit_expr(builder, when_expr, target_reg, bind_state)?;
            builder.emit_jump_to_label(Opcode::IfNot, target_reg, 1, next_when, P4::None, 0);
        }

        emit_expr(builder, then_expr, target_reg, bind_state)?;
        builder.emit_jump_to_label(Opcode::Goto, 0, 0, done_label, P4::None, 0);
        builder.resolve_label(next_when);
    }

    if let Some(el) = else_expr {
        emit_expr(builder, el, target_reg, bind_state)?;
    } else {
        builder.emit_op(Opcode::Null, 0, target_reg, 0, P4::None, 0);
    }

    builder.resolve_label(done_label);

    if let Some(r_op) = r_operand {
        builder.free_temp(r_op);
    }

    Ok(())
}

/// Compile `expr [NOT] BETWEEN low AND high` into comparison opcodes.
///
/// Equivalent to `(expr >= low) AND (expr <= high)`, optionally negated.
fn emit_between_expr(
    builder: &mut ProgramBuilder,
    expr: &Expr,
    low: &Expr,
    high: &Expr,
    not: bool,
    target_reg: i32,
    bind_state: &mut BindParamState,
) -> Result<()> {
    let expr_reg = builder.alloc_temp();
    let low_reg = builder.alloc_temp();
    let high_reg = builder.alloc_temp();

    emit_expr(builder, expr, expr_reg, bind_state)?;
    emit_expr(builder, low, low_reg, bind_state)?;
    emit_expr(builder, high, high_reg, bind_state)?;

    // Three-valued NULL logic for BETWEEN.  BETWEEN is equivalent to
    // (expr >= low) AND (expr <= high) with three-valued AND:
    //   FALSE AND x     = FALSE
    //   NULL  AND TRUE  = NULL
    //   NULL  AND NULL  = NULL
    //   TRUE  AND TRUE  = TRUE
    let lbl_false = builder.emit_label();
    let lbl_null = builder.emit_label();
    let lbl_true = builder.emit_label();
    let lbl_done = builder.emit_label();
    let lbl_low_null = builder.emit_label();

    // If operand is NULL, short-circuit to NULL result.
    builder.emit_jump_to_label(Opcode::IsNull, expr_reg, 0, lbl_null, P4::None, 0);

    // Check: expr >= low.  Ge jumps when true with non-NULL operands.
    let lbl_ge_ok = builder.emit_label();
    builder.emit_jump_to_label(Opcode::Ge, low_reg, expr_reg, lbl_ge_ok, P4::None, 0);
    // Ge didn't fire: either (a) low is NULL, or (b) expr < low → FALSE.
    builder.emit_jump_to_label(Opcode::IsNull, low_reg, 0, lbl_low_null, P4::None, 0);
    builder.emit_jump_to_label(Opcode::Goto, 0, 0, lbl_false, P4::None, 0);

    // expr >= low confirmed (low is not NULL since Ge fired).
    builder.resolve_label(lbl_ge_ok);
    // Check: expr <= high.
    builder.emit_jump_to_label(Opcode::Le, high_reg, expr_reg, lbl_true, P4::None, 0);
    // Le didn't fire: either high is NULL → TRUE AND NULL = NULL,
    // or expr > high → FALSE.
    builder.emit_jump_to_label(Opcode::IsNull, high_reg, 0, lbl_null, P4::None, 0);
    builder.emit_jump_to_label(Opcode::Goto, 0, 0, lbl_false, P4::None, 0);

    // Low was NULL — the >= result is NULL.  Must still evaluate <=
    // because NULL AND FALSE = FALSE (short-circuit on FALSE).
    builder.resolve_label(lbl_low_null);
    let lbl_low_null_le_ok = builder.emit_label();
    builder.emit_jump_to_label(
        Opcode::Le,
        high_reg,
        expr_reg,
        lbl_low_null_le_ok,
        P4::None,
        0,
    );
    // Le didn't fire: high is NULL → NULL AND NULL = NULL,
    // or expr > high → NULL AND FALSE = FALSE.
    builder.emit_jump_to_label(Opcode::IsNull, high_reg, 0, lbl_null, P4::None, 0);
    builder.emit_jump_to_label(Opcode::Goto, 0, 0, lbl_false, P4::None, 0);
    // expr <= high confirmed but low was NULL → NULL AND TRUE = NULL.
    builder.resolve_label(lbl_low_null_le_ok);
    builder.emit_jump_to_label(Opcode::Goto, 0, 0, lbl_null, P4::None, 0);

    // Both conditions satisfied with non-NULL bounds.
    builder.resolve_label(lbl_true);
    builder.emit_op(Opcode::Integer, i32::from(!not), target_reg, 0, P4::None, 0);
    builder.emit_jump_to_label(Opcode::Goto, 0, 0, lbl_done, P4::None, 0);

    // At least one condition is definitely FALSE.
    builder.resolve_label(lbl_false);
    builder.emit_op(Opcode::Integer, i32::from(not), target_reg, 0, P4::None, 0);
    builder.emit_jump_to_label(Opcode::Goto, 0, 0, lbl_done, P4::None, 0);

    // NULL involvement without definite FALSE → result is NULL.
    builder.resolve_label(lbl_null);
    builder.emit_op(Opcode::Null, 0, target_reg, 0, P4::None, 0);

    builder.resolve_label(lbl_done);

    builder.free_temp(high_reg);
    builder.free_temp(low_reg);
    builder.free_temp(expr_reg);
    Ok(())
}

/// Compile `expr [NOT] IN (e1, e2, ...)` into a chain of equality checks.
///
/// Only `InSet::List` is supported; subqueries and table references return
/// `NotImplemented`.
fn emit_in_expr(
    builder: &mut ProgramBuilder,
    expr: &Expr,
    set: &InSet,
    not: bool,
    target_reg: i32,
    bind_state: &mut BindParamState,
) -> Result<()> {
    let list = match set {
        InSet::List(list) => list,
        InSet::Subquery(_) => {
            return Err(FrankenError::NotImplemented(
                "IN (SELECT ...) subquery is not yet supported".to_owned(),
            ));
        }
        InSet::Table(_) => {
            return Err(FrankenError::NotImplemented(
                "IN table_name is not yet supported".to_owned(),
            ));
        }
    };

    if list.is_empty() {
        // Empty list: `expr IN ()` is always false, `NOT IN ()` always true.
        let val = i32::from(not);
        builder.emit_op(Opcode::Integer, val, target_reg, 0, P4::None, 0);
        return Ok(());
    }

    let expr_reg = builder.alloc_temp();
    emit_expr(builder, expr, expr_reg, bind_state)?;

    let lbl_null = builder.emit_label();
    let lbl_found = builder.emit_label();
    let lbl_done = builder.emit_label();

    // Three-valued NULL semantics for IN:
    //   NULL IN (...)            → NULL
    //   v IN (a, NULL, b) miss   → NULL  (NULL in list)
    //   v IN (a, b, c) miss      → FALSE (no NULLs)
    //   v IN (...) hit           → TRUE
    builder.emit_jump_to_label(Opcode::IsNull, expr_reg, 0, lbl_null, P4::None, 0);

    // r_saw_null: set to 1 at runtime if any list element is NULL.
    let r_saw_null = builder.alloc_temp();
    builder.emit_op(Opcode::Integer, 0, r_saw_null, 0, P4::None, 0);

    // Check each list element against expr.
    let elem_reg = builder.alloc_temp();
    for elem in list {
        emit_expr(builder, elem, elem_reg, bind_state)?;
        builder.emit_jump_to_label(Opcode::Eq, elem_reg, expr_reg, lbl_found, P4::None, 0);
        // Eq with NULL never jumps.  If this value was NULL, flag it.
        let next_val = builder.emit_label();
        let set_flag = builder.emit_label();
        builder.emit_jump_to_label(Opcode::IsNull, elem_reg, 0, set_flag, P4::None, 0);
        builder.emit_jump_to_label(Opcode::Goto, 0, 0, next_val, P4::None, 0);
        builder.resolve_label(set_flag);
        builder.emit_op(Opcode::Integer, 1, r_saw_null, 0, P4::None, 0);
        builder.resolve_label(next_val);
    }
    builder.free_temp(elem_reg);

    // No match.  If any element was NULL → result is NULL.
    builder.emit_jump_to_label(Opcode::If, r_saw_null, 0, lbl_null, P4::None, 0);
    builder.free_temp(r_saw_null);
    builder.emit_op(Opcode::Integer, i32::from(not), target_reg, 0, P4::None, 0);
    builder.emit_jump_to_label(Opcode::Goto, 0, 0, lbl_done, P4::None, 0);

    // NULL result.
    builder.resolve_label(lbl_null);
    builder.emit_op(Opcode::Null, 0, target_reg, 0, P4::None, 0);
    builder.emit_jump_to_label(Opcode::Goto, 0, 0, lbl_done, P4::None, 0);

    // Match found.
    builder.resolve_label(lbl_found);
    builder.emit_op(Opcode::Integer, i32::from(!not), target_reg, 0, P4::None, 0);

    builder.resolve_label(lbl_done);
    builder.free_temp(expr_reg);
    Ok(())
}

/// Compile `expr [NOT] LIKE/GLOB pattern [ESCAPE escape]` as a PureFunc call.
///
/// Emits a call to the `like` (or `glob`) scalar function with 2-3 arguments:
/// `like(pattern, expr)` or `like(pattern, expr, escape)`. The result is
/// negated if `not` is true.
#[allow(clippy::too_many_arguments)]
fn emit_like_expr(
    builder: &mut ProgramBuilder,
    expr: &Expr,
    pattern: &Expr,
    escape: Option<&Expr>,
    op: LikeOp,
    not: bool,
    target_reg: i32,
    bind_state: &mut BindParamState,
) -> Result<()> {
    let func_name = match op {
        LikeOp::Like => "like",
        LikeOp::Glob => "glob",
        LikeOp::Match => "match",
        LikeOp::Regexp => "regexp",
    };

    let has_escape = escape.is_some();
    let arg_count: i32 = if has_escape { 3 } else { 2 };
    let first_arg_reg = builder.alloc_regs(arg_count);

    // SQLite like() takes (pattern, string [, escape]).
    emit_expr(builder, pattern, first_arg_reg, bind_state)?;
    emit_expr(builder, expr, first_arg_reg + 1, bind_state)?;
    if let Some(esc) = escape {
        emit_expr(builder, esc, first_arg_reg + 2, bind_state)?;
    }

    #[allow(clippy::cast_possible_truncation, clippy::cast_sign_loss)]
    let arg_count_u16 = arg_count as u16;

    builder.emit_op(
        Opcode::PureFunc,
        0,
        first_arg_reg,
        target_reg,
        P4::FuncName(func_name.to_owned()),
        arg_count_u16,
    );

    // Negate the result if NOT LIKE / NOT GLOB.
    if not {
        builder.emit_op(Opcode::Not, target_reg, target_reg, 0, P4::None, 0);
    }

    Ok(())
}

// ──────────────────────────────────────────────────────────────────────────
//  JOIN helpers
// ──────────────────────────────────────────────────────────────────────────

/// Metadata for a table participating in a JOIN.
struct JoinTableSource {
    table_name: String,
    alias: Option<String>,
    col_names: Vec<String>,
    hidden_rowid_projection: Option<String>,
}

impl JoinTableSource {
    fn scan_width(&self) -> usize {
        self.col_names.len() + usize::from(self.hidden_rowid_projection.is_some())
    }
}

fn join_table_supports_hidden_rowid(
    table_name: &str,
    original_ddl_sql: &HashMap<String, String>,
) -> bool {
    original_ddl_sql
        .get(&table_name.to_ascii_lowercase())
        .is_none_or(|sql| !is_without_rowid_table_sql(sql))
}

fn join_hidden_rowid_projection(columns: &[String], supports_hidden_rowid: bool) -> Option<String> {
    if !supports_hidden_rowid {
        return None;
    }
    let shadowed: HashSet<String> = columns
        .iter()
        .map(|column| column.to_ascii_lowercase())
        .collect();
    ["rowid", "_rowid_", "oid"]
        .into_iter()
        .find(|candidate| !shadowed.contains(*candidate))
        .map(str::to_owned)
}

fn build_join_scan_sql(source: &JoinTableSource) -> String {
    let mut projections = source
        .col_names
        .iter()
        .map(|column| quote_identifier(column))
        .collect::<Vec<_>>();
    if let Some(hidden_rowid_projection) = &source.hidden_rowid_projection {
        projections.push(hidden_rowid_projection.clone());
    }
    format!(
        "SELECT {} FROM {}",
        projections.join(", "),
        quote_identifier(&source.table_name)
    )
}

#[derive(Debug, Clone)]
struct LiveVtabConstraintCandidate {
    expr: Expr,
    constraint: IndexConstraint,
    value: SqliteValue,
}

#[derive(Debug, Clone)]
struct LiveVtabScanPlan {
    idx_num: i32,
    idx_str: Option<String>,
    args: Vec<SqliteValue>,
    residual_where: Option<Expr>,
}

#[derive(Debug, Clone)]
struct Fts5AuxTableContext {
    index: InvertedIndex,
    query_terms: Vec<String>,
    row_table_label: String,
}

#[derive(Debug, Clone, Default)]
struct Fts5AuxContext {
    tables: HashMap<String, Fts5AuxTableContext>,
}

impl Fts5AuxContext {
    fn insert(&mut self, table_label: String, context: Fts5AuxTableContext) {
        self.tables
            .insert(table_label.to_ascii_uppercase(), context);
    }

    fn table(&self, table_label: &str) -> Option<&Fts5AuxTableContext> {
        self.tables.get(&table_label.to_ascii_uppercase())
    }

    fn is_empty(&self) -> bool {
        self.tables.is_empty()
    }
}

thread_local! {
    static CURRENT_FTS5_AUX_CONTEXT: RefCell<Vec<Fts5AuxContext>> = const { RefCell::new(Vec::new()) };
}

struct Fts5AuxContextGuard;

impl Fts5AuxContextGuard {
    fn push(context: Fts5AuxContext) -> Self {
        CURRENT_FTS5_AUX_CONTEXT.with(|stack| stack.borrow_mut().push(context));
        Self
    }
}

impl Drop for Fts5AuxContextGuard {
    fn drop(&mut self) {
        CURRENT_FTS5_AUX_CONTEXT.with(|stack| {
            let _ = stack.borrow_mut().pop();
        });
    }
}

fn with_current_fts5_aux_context<T>(f: impl FnOnce(Option<&Fts5AuxContext>) -> T) -> T {
    CURRENT_FTS5_AUX_CONTEXT.with(|stack| {
        let stack = stack.borrow();
        f(stack.last())
    })
}

#[derive(Debug, Clone)]
struct LiveVtabInsertRow {
    explicit_rowid: Option<SqliteValue>,
    values: Vec<SqliteValue>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum InsertTarget {
    Column(usize),
    HiddenRowid,
}

#[derive(Debug, Clone)]
struct InsertTargetLayout {
    table_columns: Vec<String>,
    targets: Vec<InsertTarget>,
    rowid_alias_col_idx: Option<usize>,
    explicit_rowid_source: Option<usize>,
}

/// Hashable wrapper for SqliteValue join keys with SQLite type-affinity
/// coercion.  TEXT values that represent valid numbers are normalized to
/// their numeric form so that `Integer(10)` and `Text("10")` hash and
/// compare equally — matching SQLite's comparison semantics in JOIN ON.
#[derive(Clone)]
struct HashableJoinKey(smallvec::SmallVec<[SqliteValue; 2]>);

/// Normalize a `SqliteValue` for hash-join comparison: coerce TEXT that
/// is a valid number to its numeric form (matching `cmp_values` behavior).
fn normalize_join_key_value(val: &SqliteValue) -> std::borrow::Cow<'_, SqliteValue> {
    if let SqliteValue::Text(s) = val {
        let trimmed = s.trim();
        if !trimmed.is_empty() {
            // Try integer first (no decimal point / exponent).
            let has_decimal = trimmed.bytes().any(|b| matches!(b, b'.' | b'e' | b'E'));
            if !has_decimal {
                if let Ok(v) = trimmed.parse::<i64>() {
                    return std::borrow::Cow::Owned(SqliteValue::Integer(v));
                }
            }
            if let Ok(v) = trimmed.parse::<f64>() {
                if v.is_finite() {
                    #[allow(clippy::cast_possible_truncation, clippy::cast_precision_loss)]
                    if !has_decimal {
                        let truncated = v as i64;
                        #[allow(clippy::float_cmp)]
                        if truncated as f64 == v {
                            return std::borrow::Cow::Owned(SqliteValue::Integer(truncated));
                        }
                    }
                    return std::borrow::Cow::Owned(SqliteValue::Float(v));
                }
            }
        }
    }
    std::borrow::Cow::Borrowed(val)
}

/// Hash a single normalized value (shared by Hash impl).
#[allow(clippy::branches_sharing_code)]
fn hash_normalized_value<H: std::hash::Hasher>(val: &SqliteValue, state: &mut H) {
    // Use a fixed discriminant scheme: numeric=1, text=2, blob=3, null=0.
    match val {
        SqliteValue::Null => 0u8.hash(state),
        SqliteValue::Integer(i) => {
            1u8.hash(state);
            i.hash(state);
        }
        SqliteValue::Float(f) => {
            let normalized = if *f == 0.0 { 0.0_f64 } else { *f };
            // If the float is an exact integer, hash as integer for
            // consistency with Integer values.
            #[allow(clippy::cast_possible_truncation, clippy::cast_precision_loss)]
            if normalized.is_finite()
                && normalized.fract() == 0.0
                && (-9_223_372_036_854_775_808.0..9_223_372_036_854_775_808.0).contains(&normalized)
            {
                1u8.hash(state);
                (normalized as i64).hash(state);
            } else {
                1u8.hash(state);
                normalized.to_bits().hash(state);
            }
        }
        SqliteValue::Text(s) => {
            2u8.hash(state);
            s.hash(state);
        }
        SqliteValue::Blob(b) => {
            3u8.hash(state);
            b.hash(state);
        }
    }
}

impl PartialEq for HashableJoinKey {
    fn eq(&self, other: &Self) -> bool {
        if self.0.len() != other.0.len() {
            return false;
        }
        self.0.iter().zip(other.0.iter()).all(|(a, b)| {
            cmp_values(&normalize_join_key_value(a), &normalize_join_key_value(b))
                == std::cmp::Ordering::Equal
        })
    }
}

impl Eq for HashableJoinKey {}

impl std::hash::Hash for HashableJoinKey {
    fn hash<H: std::hash::Hasher>(&self, state: &mut H) {
        self.0.len().hash(state);
        for val in &self.0 {
            let normalized = normalize_join_key_value(val);
            hash_normalized_value(&normalized, state);
        }
    }
}

/// Try to extract equi-join column index pairs from an ON expression.
/// Returns `Some(pairs)` when the expr is `a.col = b.col` (or AND chain
/// of such equalities), where one side references a left column and the
/// other a right column.
fn try_extract_equi_join_indices(
    expr: &Expr,
    col_map: &[(String, String, bool)],
    left_width: usize,
) -> Option<Vec<(usize, usize)>> {
    let mut terms = Vec::new();
    flatten_and_terms(expr, &mut terms);
    if terms.is_empty() {
        return None;
    }
    let mut pairs = Vec::with_capacity(terms.len());
    for term in &terms {
        let Expr::BinaryOp {
            left,
            op: BinaryOp::Eq,
            right,
            ..
        } = term
        else {
            return None;
        };
        let resolve_col = |e: &Expr| -> Option<usize> {
            if let Expr::Column(col_ref, _) = e {
                if let Some(table) = &col_ref.table {
                    col_map.iter().position(|(t, c, _)| {
                        t.eq_ignore_ascii_case(table) && c.eq_ignore_ascii_case(&col_ref.column)
                    })
                } else {
                    col_map
                        .iter()
                        .position(|(_, c, _)| c.eq_ignore_ascii_case(&col_ref.column))
                }
            } else {
                None
            }
        };
        let l_idx = resolve_col(left)?;
        let r_idx = resolve_col(right)?;
        if l_idx < left_width && r_idx >= left_width {
            pairs.push((l_idx, r_idx - left_width));
        } else if r_idx < left_width && l_idx >= left_width {
            pairs.push((r_idx, l_idx - left_width));
        } else {
            return None;
        }
    }
    Some(pairs)
}

/// Hash-join: build a multi-map on the right table, probe for each left row.
/// O(n+m) instead of O(n*m).
#[allow(clippy::too_many_arguments)]
fn execute_hash_join(
    left: &[Vec<SqliteValue>],
    right: &[Vec<SqliteValue>],
    right_width: usize,
    left_width: usize,
    kind: JoinKind,
    equi_pairs: &[(usize, usize)],
    track_right: bool,
) -> Vec<Vec<SqliteValue>> {
    let combined_width = left_width + right_width;
    let mut right_index: HashMap<HashableJoinKey, Vec<usize>> = HashMap::with_capacity(right.len());
    for (ri, right_row) in right.iter().enumerate() {
        let key: smallvec::SmallVec<[SqliteValue; 2]> = equi_pairs
            .iter()
            .map(|&(_, r_idx)| right_row.get(r_idx).cloned().unwrap_or(SqliteValue::Null))
            .collect();
        if key.iter().any(|v| matches!(v, SqliteValue::Null)) {
            continue;
        }
        right_index
            .entry(HashableJoinKey(key))
            .or_default()
            .push(ri);
    }
    let mut right_matched = if track_right {
        vec![false; right.len()]
    } else {
        Vec::new()
    };
    let mut result = Vec::with_capacity(left.len());
    for left_row in left {
        let probe_key: smallvec::SmallVec<[SqliteValue; 2]> = equi_pairs
            .iter()
            .map(|&(l_idx, _)| left_row.get(l_idx).cloned().unwrap_or(SqliteValue::Null))
            .collect();
        let mut matched = false;
        if !probe_key.iter().any(|v| matches!(v, SqliteValue::Null)) {
            if let Some(matching_indices) = right_index.get(&HashableJoinKey(probe_key)) {
                for &ri in matching_indices {
                    let right_row = &right[ri];
                    let mut combined = Vec::with_capacity(combined_width);
                    combined.extend_from_slice(left_row);
                    combined.extend_from_slice(&right_row[..right_width]);
                    result.push(combined);
                    matched = true;
                    if track_right {
                        right_matched[ri] = true;
                    }
                }
            }
        }
        if !matched && matches!(kind, JoinKind::Left | JoinKind::Full) {
            let mut combined = Vec::with_capacity(combined_width);
            combined.extend_from_slice(left_row);
            combined.extend(std::iter::repeat_n(SqliteValue::Null, right_width));
            result.push(combined);
        }
    }
    if track_right {
        for (ri, right_row) in right.iter().enumerate() {
            if !right_matched[ri] {
                let mut combined = Vec::with_capacity(combined_width);
                combined.extend(std::iter::repeat_n(SqliteValue::Null, left_width));
                combined.extend_from_slice(&right_row[..right_width]);
                result.push(combined);
            }
        }
    }
    result
}

/// Perform a single join step: combine left-side rows with right-side rows.
/// Uses hash-join O(n+m) for equi-joins, falls back to nested-loop O(n*m).
#[allow(clippy::too_many_arguments, clippy::too_many_lines)]
fn execute_single_join(
    left: &[Vec<SqliteValue>],
    right: &[Vec<SqliteValue>],
    right_width: usize,
    left_width: usize,
    kind: JoinKind,
    constraint: Option<&JoinConstraint>,
    col_map: &[(String, String, bool)],
) -> Result<Vec<Vec<SqliteValue>>> {
    let combined_width = left_width + right_width;

    // ── Hash-join fast path for equi-joins (O(n+m) vs O(n*m)) ──
    if let Some(JoinConstraint::On(expr)) = constraint {
        if let Some(equi_pairs) = try_extract_equi_join_indices(expr, col_map, left_width) {
            let track_right = matches!(kind, JoinKind::Right | JoinKind::Full);
            return Ok(execute_hash_join(
                left,
                right,
                right_width,
                left_width,
                kind,
                &equi_pairs,
                track_right,
            ));
        }
    }
    if let Some(JoinConstraint::Using(cols)) = constraint {
        let mut equi_pairs = Vec::with_capacity(cols.len());
        let mut all_found = true;
        for col_name in cols {
            let l_idx = col_map[..left_width]
                .iter()
                .position(|(_, name, _)| name.eq_ignore_ascii_case(col_name));
            let r_idx = col_map[left_width..]
                .iter()
                .position(|(_, name, _)| name.eq_ignore_ascii_case(col_name));
            if let (Some(l), Some(r)) = (l_idx, r_idx) {
                equi_pairs.push((l, r));
            } else {
                all_found = false;
                break;
            }
        }
        if all_found && !equi_pairs.is_empty() {
            let track_right = matches!(kind, JoinKind::Right | JoinKind::Full);
            return Ok(execute_hash_join(
                left,
                right,
                right_width,
                left_width,
                kind,
                &equi_pairs,
                track_right,
            ));
        }
    }

    // ── Fallback: nested-loop join ──
    let mut result = Vec::new();
    let track_right = matches!(kind, JoinKind::Right | JoinKind::Full);
    let mut right_matched = if track_right {
        vec![false; right.len()]
    } else {
        Vec::new()
    };

    let mut scratch = Vec::with_capacity(combined_width);

    let using_indices = if let Some(JoinConstraint::Using(cols)) = constraint {
        let mut indices = Vec::with_capacity(cols.len());
        let mut complete = true;
        for col_name in cols {
            let Some(l_idx) = col_map[..left_width]
                .iter()
                .position(|(_, name, _)| name.eq_ignore_ascii_case(col_name))
            else {
                complete = false;
                break;
            };
            let Some(r_idx) = col_map[left_width..]
                .iter()
                .position(|(_, name, _)| name.eq_ignore_ascii_case(col_name))
            else {
                complete = false;
                break;
            };
            indices.push((l_idx, left_width + r_idx));
        }
        complete.then_some(indices)
    } else {
        None
    };

    for left_row in left {
        let mut matched = false;

        for (ri, right_row) in right.iter().enumerate() {
            scratch.clear();
            scratch.extend_from_slice(left_row);
            scratch.extend_from_slice(&right_row[..right_width]);

            // Evaluate join constraint.
            let passes = match constraint {
                None => true,
                Some(JoinConstraint::On(expr)) => eval_join_predicate(expr, &scratch, col_map)?,
                Some(JoinConstraint::Using(cols)) => using_indices.as_deref().map_or_else(
                    || eval_using_constraint(cols, &scratch, col_map, left_width),
                    |indices| eval_using_constraint_indices(indices, &scratch),
                ),
            };

            if passes {
                matched = true;
                if track_right {
                    right_matched[ri] = true;
                }
                result.push(scratch.clone());
            }
        }

        // LEFT/FULL JOIN: if no right row matched, emit left + NULLs.
        if !matched && matches!(kind, JoinKind::Left | JoinKind::Full) {
            let mut combined = Vec::with_capacity(combined_width);
            combined.extend_from_slice(left_row);
            combined.extend(std::iter::repeat_n(SqliteValue::Null, right_width));
            result.push(combined);
        }

        // CROSS JOIN without constraint: handled by `passes = true` above.
    }

    // RIGHT/FULL JOIN: for each unmatched right row, emit NULLs + right.
    if track_right {
        for (ri, right_row) in right.iter().enumerate() {
            if !right_matched[ri] {
                let mut combined = Vec::with_capacity(combined_width);
                combined.extend(std::iter::repeat_n(SqliteValue::Null, left_width));
                combined.extend_from_slice(&right_row[..right_width]);
                result.push(combined);
            }
        }
    }

    Ok(result)
}

fn flatten_and_terms<'a>(expr: &'a Expr, terms: &mut Vec<&'a Expr>) {
    if let Expr::BinaryOp {
        left,
        op: BinaryOp::And,
        right,
        ..
    } = expr
    {
        flatten_and_terms(left, terms);
        flatten_and_terms(right, terms);
    } else {
        terms.push(expr);
    }
}

fn rebuild_and_terms(mut terms: Vec<Expr>) -> Option<Expr> {
    let first = terms.pop()?;
    Some(
        terms
            .into_iter()
            .rev()
            .fold(first, |right, left| Expr::BinaryOp {
                left: Box::new(left),
                op: BinaryOp::And,
                right: Box::new(right),
                span: Span::ZERO,
            }),
    )
}

fn direct_vtab_constraint_op(op: BinaryOp) -> Option<ConstraintOp> {
    match op {
        BinaryOp::Eq => Some(ConstraintOp::Eq),
        BinaryOp::Lt => Some(ConstraintOp::Lt),
        BinaryOp::Le => Some(ConstraintOp::Le),
        BinaryOp::Gt => Some(ConstraintOp::Gt),
        BinaryOp::Ge => Some(ConstraintOp::Ge),
        _ => None,
    }
}

fn statement_rolls_back_transaction_on_constraint(statement: &Statement) -> bool {
    matches!(
        statement,
        Statement::Insert(insert)
            if insert.or_conflict == Some(fsqlite_ast::ConflictAction::Rollback)
    ) || matches!(
        statement,
        Statement::Update(update)
            if update.or_conflict == Some(fsqlite_ast::ConflictAction::Rollback)
    )
}

fn statement_preserves_prior_changes_on_constraint(statement: &Statement) -> bool {
    matches!(
        statement,
        Statement::Insert(insert)
            if insert.or_conflict == Some(fsqlite_ast::ConflictAction::Fail)
    ) || matches!(
        statement,
        Statement::Update(update)
            if update.or_conflict == Some(fsqlite_ast::ConflictAction::Fail)
    )
}

fn error_is_constraint_violation(error: &FrankenError) -> bool {
    if error.error_code() == ErrorCode::Constraint {
        return true;
    }
    matches!(
        error,
        FrankenError::Internal(message)
            if message.starts_with(&format!(
                "VDBE halted with code {}:",
                ErrorCode::Constraint as i32
            ))
    )
}

fn error_triggers_conflict_action_rollback(error: &FrankenError) -> bool {
    error_is_constraint_violation(error)
}

fn reverse_vtab_constraint_op(op: BinaryOp) -> Option<ConstraintOp> {
    match op {
        BinaryOp::Eq => Some(ConstraintOp::Eq),
        BinaryOp::Lt => Some(ConstraintOp::Gt),
        BinaryOp::Le => Some(ConstraintOp::Ge),
        BinaryOp::Gt => Some(ConstraintOp::Lt),
        BinaryOp::Ge => Some(ConstraintOp::Le),
        _ => None,
    }
}

fn eval_live_vtab_constant_expr(expr: &Expr) -> Option<SqliteValue> {
    match expr {
        Expr::Literal(lit, _) => Some(literal_to_join_value(lit)),
        Expr::UnaryOp {
            op: UnaryOp::Negate,
            expr: inner,
            ..
        } => match eval_live_vtab_constant_expr(inner)? {
            SqliteValue::Integer(value) => Some(SqliteValue::Integer(value.saturating_neg())),
            SqliteValue::Float(value) => Some(SqliteValue::Float(-value)),
            _ => None,
        },
        Expr::UnaryOp {
            op: UnaryOp::Plus,
            expr: inner,
            ..
        }
        | Expr::Collate { expr: inner, .. } => eval_live_vtab_constant_expr(inner),
        _ => None,
    }
}

fn is_vtab_table_match_operand(expr: &Expr, table_name: &str) -> bool {
    matches!(
        expr,
        Expr::Column(col_ref, _)
            if col_ref.table.is_none() && col_ref.column.eq_ignore_ascii_case(table_name)
    )
}

fn column_ref_to_vtab_constraint_column(
    col_ref: &ColumnRef,
    col_map: &[(String, String, bool)],
) -> Option<i32> {
    let idx = find_col_in_map(col_map, col_ref.table.as_deref(), &col_ref.column, None).ok()?;
    let (_, _, hidden) = col_map.get(idx)?;
    if *hidden {
        Some(-1)
    } else {
        i32::try_from(idx).ok()
    }
}

fn extract_live_vtab_constraint_candidate(
    expr: &Expr,
    col_map: &[(String, String, bool)],
    table_name: &str,
) -> Option<LiveVtabConstraintCandidate> {
    match expr {
        Expr::BinaryOp {
            left, op, right, ..
        } => {
            if let Expr::Column(col_ref, _) = left.as_ref()
                && let Some(value) = eval_live_vtab_constant_expr(right)
                && let Some(column) = column_ref_to_vtab_constraint_column(col_ref, col_map)
                && let Some(constraint_op) = direct_vtab_constraint_op(*op)
            {
                return Some(LiveVtabConstraintCandidate {
                    expr: expr.clone(),
                    constraint: IndexConstraint {
                        column,
                        op: constraint_op,
                        usable: true,
                    },
                    value,
                });
            }
            if let Expr::Column(col_ref, _) = right.as_ref()
                && let Some(value) = eval_live_vtab_constant_expr(left)
                && let Some(column) = column_ref_to_vtab_constraint_column(col_ref, col_map)
                && let Some(constraint_op) = reverse_vtab_constraint_op(*op)
            {
                return Some(LiveVtabConstraintCandidate {
                    expr: expr.clone(),
                    constraint: IndexConstraint {
                        column,
                        op: constraint_op,
                        usable: true,
                    },
                    value,
                });
            }
            None
        }
        Expr::Like {
            expr: inner,
            pattern,
            op: LikeOp::Match,
            not: false,
            ..
        } => {
            let value = eval_live_vtab_constant_expr(pattern)?;
            let column = if is_vtab_table_match_operand(inner, table_name) {
                0
            } else if let Expr::Column(col_ref, _) = inner.as_ref() {
                column_ref_to_vtab_constraint_column(col_ref, col_map)?
            } else {
                return None;
            };
            Some(LiveVtabConstraintCandidate {
                expr: expr.clone(),
                constraint: IndexConstraint {
                    column,
                    op: ConstraintOp::Match,
                    usable: true,
                },
                value,
            })
        }
        _ => None,
    }
}

fn is_fts5_table_label_match(expr: &Expr, table_name: &str) -> bool {
    matches!(
        expr,
        Expr::Column(col_ref, _)
            if col_ref.table.is_none() && col_ref.column.eq_ignore_ascii_case(table_name)
    )
}

fn collect_fts5_match_queries_for_source(
    where_clause: Option<&Expr>,
    table_name: &str,
) -> Vec<String> {
    let Some(where_clause) = where_clause else {
        return Vec::new();
    };

    let mut terms = Vec::new();
    flatten_and_terms(where_clause, &mut terms);

    let mut queries = Vec::new();
    for term in terms {
        if let Expr::Like {
            expr,
            pattern,
            op: LikeOp::Match,
            not: false,
            ..
        } = term
            && is_fts5_table_label_match(expr, table_name)
            && let Some(query) = eval_live_vtab_constant_expr(pattern)
            && !query.is_null()
        {
            queries.push(query.to_text());
        }
    }

    queries
}

fn maybe_filter_primary_join_rows(
    row_data: Vec<Vec<SqliteValue>>,
    table_index: usize,
    primary_where_pushdown: Option<&Expr>,
    primary_col_map: &[(String, String, bool)],
    fts5_aux_context: Option<&Fts5AuxContext>,
) -> Result<Vec<Vec<SqliteValue>>> {
    if table_index != 0 {
        return Ok(row_data);
    }
    let Some(expr) = primary_where_pushdown else {
        return Ok(row_data);
    };

    let mut filtered = Vec::with_capacity(row_data.len());
    let _fts5_aux_guard =
        fts5_aux_context.map(|context| Fts5AuxContextGuard::push(context.clone()));
    for row in row_data {
        if eval_join_predicate(expr, &row, primary_col_map)? {
            filtered.push(row);
        }
    }
    Ok(filtered)
}

fn expr_references_only_col_map(expr: &Expr, col_map: &[(String, String, bool)]) -> bool {
    match expr {
        Expr::Literal(_, _) | Expr::Placeholder(_, _) | Expr::Raise { .. } => true,
        Expr::Column(col_ref, _) => {
            find_col_in_map(col_map, col_ref.table.as_deref(), &col_ref.column, None).is_ok()
        }
        Expr::BinaryOp { left, right, .. } => {
            expr_references_only_col_map(left, col_map)
                && expr_references_only_col_map(right, col_map)
        }
        Expr::UnaryOp { expr: inner, .. }
        | Expr::Cast { expr: inner, .. }
        | Expr::Collate { expr: inner, .. }
        | Expr::IsNull { expr: inner, .. } => expr_references_only_col_map(inner, col_map),
        Expr::Between {
            expr: inner,
            low,
            high,
            ..
        } => {
            expr_references_only_col_map(inner, col_map)
                && expr_references_only_col_map(low, col_map)
                && expr_references_only_col_map(high, col_map)
        }
        Expr::In {
            expr: inner, set, ..
        } => {
            expr_references_only_col_map(inner, col_map)
                && match set {
                    InSet::List(values) => values
                        .iter()
                        .all(|value| expr_references_only_col_map(value, col_map)),
                    InSet::Subquery(_) | InSet::Table(_) => false,
                }
        }
        Expr::Like {
            expr: inner,
            pattern,
            escape,
            ..
        } => {
            expr_references_only_col_map(inner, col_map)
                && expr_references_only_col_map(pattern, col_map)
                && escape
                    .as_ref()
                    .is_none_or(|expr| expr_references_only_col_map(expr, col_map))
        }
        Expr::Case {
            operand,
            whens,
            else_expr,
            ..
        } => {
            operand
                .as_ref()
                .is_none_or(|expr| expr_references_only_col_map(expr, col_map))
                && whens.iter().all(|(when_expr, then_expr)| {
                    expr_references_only_col_map(when_expr, col_map)
                        && expr_references_only_col_map(then_expr, col_map)
                })
                && else_expr
                    .as_ref()
                    .is_none_or(|expr| expr_references_only_col_map(expr, col_map))
        }
        Expr::FunctionCall {
            args, filter, over, ..
        } => {
            over.is_none()
                && filter
                    .as_ref()
                    .is_none_or(|expr| expr_references_only_col_map(expr, col_map))
                && match args {
                    FunctionArgs::List(arguments) => arguments
                        .iter()
                        .all(|argument| expr_references_only_col_map(argument, col_map)),
                    FunctionArgs::Star => true,
                }
        }
        Expr::JsonAccess {
            expr: inner, path, ..
        } => {
            expr_references_only_col_map(inner, col_map)
                && expr_references_only_col_map(path, col_map)
        }
        Expr::RowValue(values, _) => values
            .iter()
            .all(|value| expr_references_only_col_map(value, col_map)),
        Expr::Exists { .. } | Expr::Subquery(..) => false,
    }
}

/// Evaluate a USING constraint: check that named columns match in both sides.
fn eval_using_constraint(
    cols: &[String],
    combined_row: &[SqliteValue],
    col_map: &[(String, String, bool)],
    left_width: usize,
) -> bool {
    for col_name in cols {
        // Find the column in the left side.
        let left_val = col_map[..left_width]
            .iter()
            .enumerate()
            .find(|(_, (_, name, _))| name.eq_ignore_ascii_case(col_name))
            .and_then(|(i, _)| combined_row.get(i));
        // Find the column in the right side.
        let right_val = col_map[left_width..]
            .iter()
            .enumerate()
            .find(|(_, (_, name, _))| name.eq_ignore_ascii_case(col_name))
            .and_then(|(i, _)| combined_row.get(left_width + i));

        match (left_val, right_val) {
            (Some(l), Some(r)) => {
                // SQL join semantics: USING expands to equality checks,
                // and `NULL = NULL` is not true.
                if matches!(l, SqliteValue::Null) || matches!(r, SqliteValue::Null) {
                    return false;
                }
                if cmp_sqlite_values(l, r) != std::cmp::Ordering::Equal {
                    return false;
                }
            }
            _ => return false,
        }
    }
    true
}

fn eval_using_constraint_indices(indices: &[(usize, usize)], combined_row: &[SqliteValue]) -> bool {
    for &(left_idx, right_idx) in indices {
        let left_val = combined_row.get(left_idx);
        let right_val = combined_row.get(right_idx);
        match (left_val, right_val) {
            (Some(l), Some(r)) => {
                if matches!(l, SqliteValue::Null) || matches!(r, SqliteValue::Null) {
                    return false;
                }
                if cmp_sqlite_values(l, r) != std::cmp::Ordering::Equal {
                    return false;
                }
            }
            _ => return false,
        }
    }
    true
}

/// Evaluate a boolean predicate expression against a combined join row.
fn eval_join_predicate(
    expr: &Expr,
    row: &[SqliteValue],
    col_map: &[(String, String, bool)],
) -> Result<bool> {
    let val = eval_join_expr(expr, row, col_map)?;
    Ok(is_sqlite_truthy(&val))
}

fn fts5_table_label_from_args(args: &FunctionArgs) -> Option<&str> {
    let FunctionArgs::List(arguments) = args else {
        return None;
    };
    let Some(Expr::Column(col_ref, _)) = arguments.first() else {
        return None;
    };
    if col_ref.table.is_some() {
        return None;
    }
    Some(col_ref.column.as_str())
}

fn current_fts5_rowid(
    table_label: &str,
    row: &[SqliteValue],
    col_map: &[(String, String, bool)],
) -> Option<i64> {
    let idx = col_map.iter().position(|(table, column, hidden)| {
        *hidden && table.eq_ignore_ascii_case(table_label) && column.eq_ignore_ascii_case("rowid")
    })?;
    row.get(idx).map(SqliteValue::to_integer)
}

fn current_fts5_visible_columns<'a>(
    table_label: &str,
    row: &'a [SqliteValue],
    col_map: &[(String, String, bool)],
) -> Vec<&'a SqliteValue> {
    col_map
        .iter()
        .enumerate()
        .filter(|(_, (table, _, hidden))| table.eq_ignore_ascii_case(table_label) && !*hidden)
        .filter_map(|(idx, _)| row.get(idx))
        .collect()
}

fn resolve_fts5_row_table_label(
    table_label: &str,
    _col_map: &[(String, String, bool)],
) -> Option<String> {
    with_current_fts5_aux_context(|ctx_opt| {
        ctx_opt.and_then(|ctx| {
            ctx.table(table_label)
                .map(|table_ctx| table_ctx.row_table_label.clone())
        })
    })
}

fn auto_fts5_column_index(query_terms: &[String], columns: &[&SqliteValue]) -> Option<usize> {
    if columns.is_empty() {
        return None;
    }

    let mut best_index = 0usize;
    let mut best_hits = 0usize;
    for (idx, value) in columns.iter().enumerate() {
        let lower = sqlite_value_to_text(value).to_ascii_lowercase();
        let hits = query_terms
            .iter()
            .map(|term| lower.matches(term.as_str()).count())
            .sum();
        if hits > best_hits {
            best_hits = hits;
            best_index = idx;
        }
    }
    Some(best_index)
}

fn sqlite_value_as_f64(value: &SqliteValue) -> Option<f64> {
    match value {
        SqliteValue::Integer(i) => Some(*i as f64),
        SqliteValue::Float(f) => Some(*f),
        SqliteValue::Text(text) => text.parse::<f64>().ok(),
        SqliteValue::Blob(_) | SqliteValue::Null => None,
    }
}

fn eval_fts5_aux_function(
    name: &str,
    args: &FunctionArgs,
    row: &[SqliteValue],
    col_map: &[(String, String, bool)],
) -> Result<SqliteValue> {
    let table_label = fts5_table_label_from_args(args).ok_or_else(|| {
        FrankenError::function_error(format!(
            "unable to use function {name} in the requested context"
        ))
    })?;
    let FunctionArgs::List(arguments) = args else {
        return Err(FrankenError::function_error(format!(
            "unable to use function {name} in the requested context",
        )));
    };

    with_current_fts5_aux_context(|ctx_opt| {
        let ctx = ctx_opt.ok_or_else(|| {
            FrankenError::function_error(format!(
                "unable to use function {name} in the requested context",
            ))
        })?;
        let table_ctx = ctx.table(table_label).ok_or_else(|| {
            FrankenError::function_error(format!(
                "unable to use function {name} in the requested context",
            ))
        })?;
        let rowid =
            current_fts5_rowid(&table_ctx.row_table_label, row, col_map).ok_or_else(|| {
                FrankenError::function_error(format!(
                    "unable to use function {name} in the requested context"
                ))
            })?;
        let visible_columns =
            current_fts5_visible_columns(&table_ctx.row_table_label, row, col_map);

        match name {
            "bm25" => {
                let mut weights = Vec::new();
                for expr in &arguments[1..] {
                    let value = eval_join_expr(expr, row, col_map)?;
                    if value.is_null() {
                        return Ok(SqliteValue::Null);
                    }
                    let Some(weight) = sqlite_value_as_f64(&value) else {
                        return Err(FrankenError::function_error(
                            "bm25 column weight must be numeric",
                        ));
                    };
                    weights.push(weight);
                }
                Ok(SqliteValue::Float(bm25_score(
                    &table_ctx.index,
                    rowid,
                    &table_ctx.query_terms,
                    &weights,
                )))
            }
            "highlight" => {
                if arguments.len() != 4 {
                    return Err(FrankenError::function_error(
                        "wrong number of arguments to function highlight()",
                    ));
                }
                let col_value = eval_join_expr(&arguments[1], row, col_map)?;
                let open_value = eval_join_expr(&arguments[2], row, col_map)?;
                let close_value = eval_join_expr(&arguments[3], row, col_map)?;
                if col_value.is_null() || open_value.is_null() || close_value.is_null() {
                    return Ok(SqliteValue::Null);
                }
                let column_index = col_value.to_integer();
                if column_index < 0 {
                    return Err(FrankenError::function_error(
                        "highlight column index must be non-negative",
                    ));
                }
                let column_index = usize::try_from(column_index).map_err(|_| {
                    FrankenError::function_error("highlight column index out of range")
                })?;
                let text = visible_columns.get(column_index).ok_or_else(|| {
                    FrankenError::function_error("highlight column index out of range")
                })?;
                if text.is_null() {
                    return Ok(SqliteValue::Null);
                }
                Ok(SqliteValue::Text(
                    fts5_highlight(
                        &sqlite_value_to_text(text),
                        &table_ctx.query_terms,
                        &open_value.to_text(),
                        &close_value.to_text(),
                    )
                    .into(),
                ))
            }
            "snippet" => {
                if arguments.len() != 6 {
                    return Err(FrankenError::function_error(
                        "wrong number of arguments to function snippet()",
                    ));
                }
                let col_value = eval_join_expr(&arguments[1], row, col_map)?;
                let open_value = eval_join_expr(&arguments[2], row, col_map)?;
                let close_value = eval_join_expr(&arguments[3], row, col_map)?;
                let ellipsis_value = eval_join_expr(&arguments[4], row, col_map)?;
                let max_tokens_value = eval_join_expr(&arguments[5], row, col_map)?;
                if col_value.is_null()
                    || open_value.is_null()
                    || close_value.is_null()
                    || ellipsis_value.is_null()
                    || max_tokens_value.is_null()
                {
                    return Ok(SqliteValue::Null);
                }
                let max_tokens = usize::try_from(max_tokens_value.to_integer()).map_err(|_| {
                    FrankenError::function_error("snippet token limit must be positive")
                })?;
                if !(1..=64).contains(&max_tokens) {
                    return Err(FrankenError::function_error(
                        "snippet token limit must be between 1 and 64",
                    ));
                }
                let column_index = if col_value.to_integer() < 0 {
                    auto_fts5_column_index(&table_ctx.query_terms, &visible_columns)
                } else {
                    usize::try_from(col_value.to_integer()).ok()
                }
                .ok_or_else(|| FrankenError::function_error("snippet column index out of range"))?;
                let text = visible_columns.get(column_index).ok_or_else(|| {
                    FrankenError::function_error("snippet column index out of range")
                })?;
                if text.is_null() {
                    return Ok(SqliteValue::Null);
                }
                Ok(SqliteValue::Text(
                    fts5_snippet(
                        &sqlite_value_to_text(text),
                        &table_ctx.query_terms,
                        &open_value.to_text(),
                        &close_value.to_text(),
                        &ellipsis_value.to_text(),
                        max_tokens,
                    )
                    .into(),
                ))
            }
            _ => Err(FrankenError::function_error(format!(
                "unable to use function {name} in the requested context",
            ))),
        }
    })
}

fn try_eval_fts5_aux_function(
    name: &str,
    args: &FunctionArgs,
    row: &[SqliteValue],
    col_map: &[(String, String, bool)],
) -> Option<Result<SqliteValue>> {
    let lower = name.to_ascii_lowercase();
    match lower.as_str() {
        "bm25" | "highlight" | "snippet" => {
            Some(eval_fts5_aux_function(lower.as_str(), args, row, col_map))
        }
        _ => None,
    }
}

fn is_fts5_aux_function_name(name: &str) -> bool {
    name.eq_ignore_ascii_case("bm25")
        || name.eq_ignore_ascii_case("highlight")
        || name.eq_ignore_ascii_case("snippet")
}

/// Evaluate an expression against a combined join row, producing a value.
#[allow(clippy::too_many_lines)]
fn eval_join_expr(
    expr: &Expr,
    row: &[SqliteValue],
    col_map: &[(String, String, bool)],
) -> Result<SqliteValue> {
    match expr {
        Expr::Column(col_ref, _) => {
            let col_name = &col_ref.column;
            let table_prefix = col_ref.table.as_deref();
            if let Ok(idx) = find_col_in_map(col_map, table_prefix, col_name, None) {
                return Ok(row.get(idx).cloned().unwrap_or(SqliteValue::Null));
            }

            // FTS-style shorthand: `<table_name> MATCH 'query'` uses the table
            // identifier as an implicit document-text operand.
            if table_prefix.is_none()
                && let Some(row_table_label) = resolve_fts5_row_table_label(col_name, col_map)
            {
                let text = collect_match_columns(&row_table_label, row, col_map)
                    .into_iter()
                    .map(|(_, value)| value)
                    .collect::<Vec<_>>()
                    .join(" ");
                return Ok(SqliteValue::Text(text.into()));
            }

            Err(FrankenError::Internal(format!(
                "column not found: {col_name}"
            )))
        }
        Expr::Literal(lit, _) => Ok(literal_to_join_value(lit)),
        Expr::BinaryOp {
            left, op, right, ..
        } => {
            // IS TRUE / IS FALSE / IS NOT TRUE / IS NOT FALSE
            if matches!(op, BinaryOp::Is | BinaryOp::IsNot) {
                if let Expr::Literal(lit, _) = right.as_ref() {
                    if matches!(lit, Literal::True | Literal::False) {
                        let lv = eval_join_expr(left, row, col_map)?;
                        let truthy = if lv.is_null() {
                            None
                        } else {
                            Some(is_sqlite_truthy(&lv))
                        };
                        let is_true_test = matches!(lit, Literal::True);
                        let is_not = matches!(op, BinaryOp::IsNot);
                        let result = match truthy {
                            Some(t) => {
                                // IS TRUE / IS NOT FALSE → keep truthiness
                                // IS FALSE / IS NOT TRUE → invert truthiness
                                let keep = is_true_test != is_not;
                                i64::from(if keep { t } else { !t })
                            }
                            None => i64::from(is_not),
                        };
                        return Ok(SqliteValue::Integer(result));
                    }
                }
            }
            let lv = eval_join_expr(left, row, col_map)?;
            let rv = eval_join_expr(right, row, col_map)?;
            Ok(eval_join_binary_op(&lv, *op, &rv))
        }
        Expr::UnaryOp {
            op, expr: inner, ..
        } => {
            let val = eval_join_expr(inner, row, col_map)?;
            Ok(match op {
                UnaryOp::Negate => match val {
                    SqliteValue::Integer(n) => n
                        .checked_neg()
                        .map_or_else(|| SqliteValue::Float(-(n as f64)), SqliteValue::Integer),
                    SqliteValue::Float(f) => SqliteValue::Float(-f),
                    _ => SqliteValue::Null,
                },
                // NOT NULL is NULL per three-valued logic.
                // OP_Not uses sqlite3VdbeIntValue (integer truncation).
                UnaryOp::Not => {
                    if val.is_null() {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Integer(i64::from(!is_sqlite_truthy(&val)))
                    }
                }
                // ~NULL is NULL.
                UnaryOp::BitNot => {
                    if val.is_null() {
                        SqliteValue::Null
                    } else {
                        SqliteValue::Integer(!val.to_integer())
                    }
                }
                _ => SqliteValue::Null,
            })
        }
        Expr::IsNull {
            expr: inner, not, ..
        } => {
            let val = eval_join_expr(inner, row, col_map)?;
            let is_null = matches!(val, SqliteValue::Null);
            Ok(SqliteValue::Integer(i64::from(if *not {
                !is_null
            } else {
                is_null
            })))
        }
        Expr::Between {
            expr: inner,
            low,
            high,
            not,
            ..
        } => {
            let val = eval_join_expr(inner, row, col_map)?;
            let low_val = eval_join_expr(low, row, col_map)?;
            let high_val = eval_join_expr(high, row, col_map)?;
            // Three-valued BETWEEN: (val >= low) AND (val <= high).
            let ge_low = if val.is_null() || low_val.is_null() {
                None // NULL comparison → unknown
            } else {
                Some(cmp_values(&val, &low_val) != std::cmp::Ordering::Less)
            };
            let le_high = if val.is_null() || high_val.is_null() {
                None
            } else {
                Some(cmp_values(&val, &high_val) != std::cmp::Ordering::Greater)
            };
            // Three-valued AND: FALSE wins over NULL.
            match (ge_low, le_high) {
                (Some(false), _) | (_, Some(false)) => Ok(SqliteValue::Integer(i64::from(*not))),
                (Some(true), Some(true)) => Ok(SqliteValue::Integer(i64::from(!*not))),
                _ => Ok(SqliteValue::Null),
            }
        }
        Expr::In {
            expr: inner,
            set,
            not,
            ..
        } => {
            // Multi-column IN: (a, b) IN ((1, 10), (3, 30))
            if let Expr::RowValue(rv_exprs, _) = inner.as_ref() {
                let InSet::List(list_exprs) = set else {
                    return Err(FrankenError::NotImplemented(
                        "multi-column IN with subquery not supported".to_owned(),
                    ));
                };
                let lhs: Vec<SqliteValue> = rv_exprs
                    .iter()
                    .map(|e| eval_join_expr(e, row, col_map))
                    .collect::<Result<Vec<_>>>()?;
                let mut saw_null = false;
                let mut found = false;
                for list_item in list_exprs {
                    let rhs_exprs = match list_item {
                        Expr::RowValue(rv, _) => rv.as_slice(),
                        _ => std::slice::from_ref(list_item),
                    };
                    if rhs_exprs.len() != lhs.len() {
                        continue;
                    }
                    let rhs: Vec<SqliteValue> = rhs_exprs
                        .iter()
                        .map(|e| eval_join_expr(e, row, col_map))
                        .collect::<Result<Vec<_>>>()?;
                    // Element-wise three-valued comparison:
                    // - If any pair is FALSE (not equal), this tuple is FALSE.
                    // - If no pair is FALSE but some are NULL, this tuple is NULL.
                    // - If all pairs are TRUE (equal), this tuple matches.
                    let mut tuple_has_null = false;
                    let mut tuple_all_equal = true;
                    for (l, r) in lhs.iter().zip(rhs.iter()) {
                        if l.is_null() || r.is_null() {
                            tuple_has_null = true;
                        } else if cmp_values(l, r) != std::cmp::Ordering::Equal {
                            tuple_all_equal = false;
                            break;
                        }
                    }
                    if tuple_all_equal && !tuple_has_null {
                        found = true;
                        break;
                    }
                    if tuple_all_equal && tuple_has_null {
                        saw_null = true;
                    }
                }
                return if found {
                    Ok(SqliteValue::Integer(i64::from(!*not)))
                } else if saw_null {
                    Ok(SqliteValue::Null)
                } else {
                    Ok(SqliteValue::Integer(i64::from(*not)))
                };
            }

            // Scalar IN: val IN (1, 2, 3)
            let val = eval_join_expr(inner, row, col_map)?;
            // Three-valued IN: NULL operand → NULL result.
            if val.is_null() {
                return Ok(SqliteValue::Null);
            }
            let mut saw_null = false;
            let found = match set {
                InSet::List(exprs) => {
                    let mut found = false;
                    for e in exprs {
                        let set_val = eval_join_expr(e, row, col_map)?;
                        if set_val.is_null() {
                            saw_null = true;
                            continue;
                        }
                        if cmp_values(&val, &set_val) == std::cmp::Ordering::Equal {
                            found = true;
                            break;
                        }
                    }
                    found
                }
                _ => {
                    return Err(FrankenError::NotImplemented(
                        "IN subquery in JOIN not supported".to_owned(),
                    ));
                }
            };
            if found {
                Ok(SqliteValue::Integer(i64::from(!*not)))
            } else if saw_null {
                Ok(SqliteValue::Null)
            } else {
                Ok(SqliteValue::Integer(i64::from(*not)))
            }
        }
        Expr::FunctionCall { name, args, .. } => {
            if let Some(result) = try_eval_fts5_aux_function(name, args, row, col_map) {
                return result;
            }
            if is_fts5_aux_function_name(name) {
                return Err(FrankenError::function_error(format!(
                    "unable to use function {name} in the requested context",
                )));
            }
            let arg_vals: Vec<SqliteValue> = match args {
                FunctionArgs::List(exprs) => exprs
                    .iter()
                    .map(|e| eval_join_expr(e, row, col_map))
                    .collect::<Result<Vec<_>>>()?,
                FunctionArgs::Star => vec![],
            };
            Ok(eval_scalar_fn(name, &arg_vals))
        }
        Expr::Like {
            expr: inner,
            pattern,
            op,
            not,
            escape,
            ..
        } => {
            let val = eval_join_expr(inner, row, col_map)?;
            let pat = eval_join_expr(pattern, row, col_map)?;
            if val.is_null() || pat.is_null() {
                return Ok(SqliteValue::Null);
            }
            let s = val.to_text();
            let p = pat.to_text();
            let esc_char = if let Some(esc_expr) = escape {
                let esc_val = eval_join_expr(esc_expr, row, col_map)?;
                esc_val.to_text().chars().next()
            } else {
                None
            };
            let matched = match op {
                LikeOp::Like => simple_like_match(&p, &s, esc_char),
                LikeOp::Glob => simple_glob_match(&p, &s),
                LikeOp::Match => match_query_with_table_columns(inner, &p, &s, row, col_map),
                LikeOp::Regexp => {
                    return Err(FrankenError::Internal(
                        "no such function: regexp".to_owned(),
                    ));
                }
            };
            Ok(SqliteValue::Integer(i64::from(if *not {
                !matched
            } else {
                matched
            })))
        }
        Expr::Case {
            operand,
            whens,
            else_expr,
            ..
        } => {
            let base = operand
                .as_ref()
                .map(|e| eval_join_expr(e, row, col_map))
                .transpose()?;
            for (when_expr, then_expr) in whens {
                let when_val = eval_join_expr(when_expr, row, col_map)?;
                let matches = if let Some(ref b) = base {
                    // Simple CASE: NULL base never matches (NULL = x is UNKNOWN).
                    !b.is_null()
                        && !when_val.is_null()
                        && cmp_values(b, &when_val) == std::cmp::Ordering::Equal
                } else {
                    is_sqlite_truthy(&when_val)
                };
                if matches {
                    return eval_join_expr(then_expr, row, col_map);
                }
            }
            if let Some(else_e) = else_expr {
                eval_join_expr(else_e, row, col_map)
            } else {
                Ok(SqliteValue::Null)
            }
        }
        Expr::Cast {
            expr: inner,
            type_name,
            ..
        } => {
            let val = eval_join_expr(inner, row, col_map)?;
            if val.is_null() {
                return Ok(SqliteValue::Null);
            }
            Ok(apply_cast(val, &type_name.name))
        }
        Expr::Collate { expr: inner, .. } => eval_join_expr(inner, row, col_map),
        other => Err(FrankenError::NotImplemented(format!(
            "eval_join_expr: unsupported expression type: {other:?}"
        ))),
    }
}

/// Find a column's index in the combined column map.
fn find_col_in_map(
    col_map: &[(String, String, bool)],
    table_prefix: Option<&str>,
    col_name: &str,
    using_skip_indices: Option<&HashSet<usize>>,
) -> Result<usize> {
    if let Some(prefix) = table_prefix {
        // Qualified: match table label + column name.
        if let Some(idx) = col_map.iter().position(|(tbl, col, _)| {
            tbl.eq_ignore_ascii_case(prefix) && col.eq_ignore_ascii_case(col_name)
        }) {
            return Ok(idx);
        }
        if is_rowid_alias(col_name)
            && let Some(idx) = col_map.iter().position(|(tbl, col, hidden)| {
                tbl.eq_ignore_ascii_case(prefix) && *hidden && col.eq_ignore_ascii_case("rowid")
            })
        {
            return Ok(idx);
        }
        Err(FrankenError::Internal(format!(
            "column not found: {prefix}.{col_name}"
        )))
    } else {
        // Unqualified: find all matches, ignoring skipped USING columns.
        let mut first = None;
        let mut ambiguous = false;
        for (i, (_, col, _)) in col_map.iter().enumerate() {
            if using_skip_indices.is_some_and(|s| s.contains(&i)) {
                continue;
            }
            if col.eq_ignore_ascii_case(col_name) {
                if first.is_none() {
                    first = Some(i);
                } else {
                    ambiguous = true;
                }
            }
        }
        if ambiguous {
            return Err(FrankenError::AmbiguousColumn {
                name: col_name.to_owned(),
            });
        }
        if let Some(idx) = first {
            return Ok(idx);
        }
        if is_rowid_alias(col_name) {
            let mut hidden_match = None;
            let mut hidden_ambiguous = false;
            for (i, (_, col, hidden)) in col_map.iter().enumerate() {
                if using_skip_indices.is_some_and(|s| s.contains(&i)) {
                    continue;
                }
                if *hidden && col.eq_ignore_ascii_case("rowid") {
                    if hidden_match.is_none() {
                        hidden_match = Some(i);
                    } else {
                        hidden_ambiguous = true;
                    }
                }
            }
            if hidden_ambiguous {
                return Err(FrankenError::AmbiguousColumn {
                    name: col_name.to_owned(),
                });
            }
            if let Some(idx) = hidden_match {
                return Ok(idx);
            }
        }
        Err(FrankenError::Internal(format!(
            "column not found: {col_name}"
        )))
    }
}

fn find_column_index_case_insensitive(column_names: &[String], target: &str) -> Option<usize> {
    column_names
        .iter()
        .position(|column_name| column_name.eq_ignore_ascii_case(target))
}

/// Check whether a column name is an implicit rowid alias (`rowid`, `_rowid_`, `oid`).
fn is_rowid_alias(name: &str) -> bool {
    let lower = name.to_ascii_lowercase();
    lower == "rowid" || lower == "_rowid_" || lower == "oid"
}

/// Rewrite rowid alias references in an expression tree so that `rowid`,
/// `_rowid_`, and `oid` column references become the real column name of the
/// `INTEGER PRIMARY KEY` column (the rowid alias).
/// Resolve GROUP BY expressions that reference SELECT-list aliases.
///
/// SQLite resolves a bare identifier in GROUP BY against the table columns
/// first, and only falls back to SELECT-list aliases when no column matches.
/// This function implements that fallback: for each GROUP BY expression that
/// is a bare column reference not found in `col_map`, it checks for a matching
/// alias in `columns` and replaces the expression with the aliased expression.
fn resolve_group_by_aliases(
    group_by_exprs: &mut [Expr],
    columns: &[ResultColumn],
    col_map: &[(String, String, bool)],
) {
    for expr in group_by_exprs.iter_mut() {
        // Numeric index: GROUP BY 1 → group by the first result column.
        if let Expr::Literal(Literal::Integer(n), _) = expr {
            let idx = usize::try_from(*n).unwrap_or(0);
            if idx >= 1 && idx <= columns.len() {
                if let ResultColumn::Expr { expr: col_expr, .. } = &columns[idx - 1] {
                    *expr = col_expr.clone();
                }
            }
            continue;
        }
        if let Expr::Column(col_ref, _) = expr {
            if col_ref.table.is_some() {
                continue; // Qualified reference — not an alias.
            }
            let name = &col_ref.column;
            // If the identifier resolves to a table column, leave it as-is.
            if find_col_in_map(col_map, None, name, None).is_ok() {
                continue;
            }
            // Look for a matching SELECT-list alias.
            for col in columns {
                if let ResultColumn::Expr {
                    alias: Some(alias),
                    expr: aliased_expr,
                } = col
                {
                    if alias.eq_ignore_ascii_case(name) {
                        *expr = aliased_expr.clone();
                        break;
                    }
                }
            }
        }
    }
}

fn rewrite_rowid_aliases_in_expr(expr: &mut Expr, real_col: &str) {
    match expr {
        Expr::Column(col_ref, _) if is_rowid_alias(&col_ref.column) => {
            real_col.clone_into(&mut col_ref.column);
        }
        Expr::BinaryOp { left, right, .. } => {
            rewrite_rowid_aliases_in_expr(left, real_col);
            rewrite_rowid_aliases_in_expr(right, real_col);
        }
        Expr::UnaryOp { expr: inner, .. }
        | Expr::IsNull { expr: inner, .. }
        | Expr::Cast { expr: inner, .. } => {
            rewrite_rowid_aliases_in_expr(inner, real_col);
        }
        Expr::Between {
            expr: inner,
            low,
            high,
            ..
        } => {
            rewrite_rowid_aliases_in_expr(inner, real_col);
            rewrite_rowid_aliases_in_expr(low, real_col);
            rewrite_rowid_aliases_in_expr(high, real_col);
        }
        Expr::In {
            expr: inner, set, ..
        } => {
            rewrite_rowid_aliases_in_expr(inner, real_col);
            if let InSet::List(exprs) = set {
                for e in exprs {
                    rewrite_rowid_aliases_in_expr(e, real_col);
                }
            }
        }
        Expr::FunctionCall {
            args: FunctionArgs::List(exprs),
            ..
        } => {
            for e in exprs {
                rewrite_rowid_aliases_in_expr(e, real_col);
            }
        }
        Expr::Case {
            operand,
            whens,
            else_expr,
            ..
        } => {
            if let Some(op) = operand {
                rewrite_rowid_aliases_in_expr(op, real_col);
            }
            for (when_e, then_e) in whens {
                rewrite_rowid_aliases_in_expr(when_e, real_col);
                rewrite_rowid_aliases_in_expr(then_e, real_col);
            }
            if let Some(el) = else_expr {
                rewrite_rowid_aliases_in_expr(el, real_col);
            }
        }
        _ => {}
    }
}

/// Convert an AST literal to a `SqliteValue` (for JOIN expression evaluation).
fn literal_to_join_value(lit: &Literal) -> SqliteValue {
    match lit {
        Literal::Integer(n) => SqliteValue::Integer(*n),
        Literal::Float(f) => SqliteValue::Float(*f),
        Literal::String(s) => SqliteValue::Text(s.clone().into()),
        Literal::True => SqliteValue::Integer(1),
        Literal::False => SqliteValue::Integer(0),
        _ => SqliteValue::Null,
    }
}

/// Evaluate a binary operator on two `SqliteValue`s (for JOIN expression evaluation).
fn eval_join_binary_op(left: &SqliteValue, op: BinaryOp, right: &SqliteValue) -> SqliteValue {
    match op {
        // SQL comparisons: NULL compared to anything is NULL (UNKNOWN).
        BinaryOp::Eq | BinaryOp::Ne | BinaryOp::Gt | BinaryOp::Lt | BinaryOp::Ge | BinaryOp::Le => {
            if left.is_null() || right.is_null() {
                return SqliteValue::Null;
            }
            let cmp = cmp_values(left, right);
            let result = match op {
                BinaryOp::Eq => cmp == std::cmp::Ordering::Equal,
                BinaryOp::Ne => cmp != std::cmp::Ordering::Equal,
                BinaryOp::Gt => cmp == std::cmp::Ordering::Greater,
                BinaryOp::Lt => cmp == std::cmp::Ordering::Less,
                BinaryOp::Ge => cmp != std::cmp::Ordering::Less,
                BinaryOp::Le => cmp != std::cmp::Ordering::Greater,
                _ => unreachable!("outer match filters to comparison ops only"),
            };
            SqliteValue::Integer(i64::from(result))
        }
        // Three-valued AND: FALSE AND NULL = FALSE, TRUE AND NULL = NULL.
        // OP_And uses sqlite3VdbeIntValue (integer truncation).
        BinaryOp::And => {
            let l_null = left.is_null();
            let r_null = right.is_null();
            let l_truthy = is_sqlite_truthy(left);
            let r_truthy = is_sqlite_truthy(right);
            if (!l_truthy && !l_null) || (!r_truthy && !r_null) {
                SqliteValue::Integer(0)
            } else if l_null || r_null {
                SqliteValue::Null
            } else {
                SqliteValue::Integer(1)
            }
        }
        // Three-valued OR: TRUE OR NULL = TRUE, FALSE OR NULL = NULL.
        // OP_Or uses sqlite3VdbeIntValue (integer truncation).
        BinaryOp::Or => {
            let l_null = left.is_null();
            let r_null = right.is_null();
            let l_truthy = is_sqlite_truthy(left);
            let r_truthy = is_sqlite_truthy(right);
            if l_truthy || r_truthy {
                SqliteValue::Integer(1)
            } else if l_null || r_null {
                SqliteValue::Null
            } else {
                SqliteValue::Integer(0)
            }
        }
        BinaryOp::Add => left.sql_add(right),
        BinaryOp::Subtract => left.sql_sub(right),
        BinaryOp::Multiply => left.sql_mul(right),
        BinaryOp::Divide => numeric_div(left, right),
        BinaryOp::Modulo => numeric_mod(left, right),
        BinaryOp::Concat => {
            if left.is_null() || right.is_null() {
                SqliteValue::Null
            } else {
                let l = sqlite_value_to_text(left);
                let r = sqlite_value_to_text(right);
                SqliteValue::Text(format!("{l}{r}").into())
            }
        }
        // IS / IS NOT: NULLEQ semantics (NULL IS NULL = TRUE).
        BinaryOp::Is => {
            let eq = match (left.is_null(), right.is_null()) {
                (true, true) => true,
                (true, false) | (false, true) => false,
                (false, false) => cmp_values(left, right) == std::cmp::Ordering::Equal,
            };
            SqliteValue::Integer(i64::from(eq))
        }
        BinaryOp::IsNot => {
            let eq = match (left.is_null(), right.is_null()) {
                (true, true) => true,
                (true, false) | (false, true) => false,
                (false, false) => cmp_values(left, right) == std::cmp::Ordering::Equal,
            };
            SqliteValue::Integer(i64::from(!eq))
        }
        BinaryOp::BitAnd => {
            if left.is_null() || right.is_null() {
                SqliteValue::Null
            } else {
                SqliteValue::Integer(left.to_integer() & right.to_integer())
            }
        }
        BinaryOp::BitOr => {
            if left.is_null() || right.is_null() {
                SqliteValue::Null
            } else {
                SqliteValue::Integer(left.to_integer() | right.to_integer())
            }
        }
        BinaryOp::ShiftLeft => {
            if left.is_null() || right.is_null() {
                SqliteValue::Null
            } else {
                SqliteValue::Integer(left.to_integer().wrapping_shl(right.to_integer() as u32))
            }
        }
        BinaryOp::ShiftRight => {
            if left.is_null() || right.is_null() {
                SqliteValue::Null
            } else {
                SqliteValue::Integer(left.to_integer().wrapping_shr(right.to_integer() as u32))
            }
        }
    }
}

/// Simple case-insensitive LIKE pattern match (`%` = any sequence, `_` = any char).
///
/// `escape_char`: when `Some(ch)`, the character `ch` escapes the next
/// pattern character (e.g., `LIKE '%!%%' ESCAPE '!'` treats `%` after `!`
/// as a literal percent). A dangling trailing escape never matches.
fn simple_like_match(pattern: &str, string: &str, escape_char: Option<char>) -> bool {
    let pat: Vec<char> = pattern.to_ascii_lowercase().chars().collect();
    let txt: Vec<char> = string.to_ascii_lowercase().chars().collect();
    let esc = escape_char.map(|c| c.to_ascii_lowercase());
    like_dp(&pat, &txt, 0, 0, esc)
}

fn like_dp(pat: &[char], txt: &[char], pi: usize, ti: usize, esc: Option<char>) -> bool {
    if pi == pat.len() {
        return ti == txt.len();
    }
    // Check for escape character: next pattern char is treated as literal.
    if Some(pat[pi]) == esc {
        if pi + 1 >= pat.len() {
            return false;
        }
        let literal = pat[pi + 1];
        return ti < txt.len() && txt[ti] == literal && like_dp(pat, txt, pi + 2, ti + 1, esc);
    }
    match pat[pi] {
        '%' => {
            // Match zero or more characters.
            let mut t = ti;
            loop {
                if like_dp(pat, txt, pi + 1, t, esc) {
                    return true;
                }
                if t >= txt.len() {
                    return false;
                }
                t += 1;
            }
        }
        '_' => {
            // Match exactly one character.
            ti < txt.len() && like_dp(pat, txt, pi + 1, ti + 1, esc)
        }
        c => ti < txt.len() && txt[ti] == c && like_dp(pat, txt, pi + 1, ti + 1, esc),
    }
}

/// Lightweight MATCH predicate for fallback paths.
///
/// Supports single-term search, quoted phrases, `AND`/`OR`, and `prefix*`.
fn simple_match_query(query: &str, document: &str) -> bool {
    fn eval_clause(clause: &str, text_lower: &str) -> bool {
        let trimmed = clause.trim();
        if trimmed.contains(" OR ") {
            return trimmed
                .split(" OR ")
                .any(|part| eval_clause(part, text_lower));
        }
        if trimmed.contains(" AND ") {
            return trimmed
                .split(" AND ")
                .all(|part| eval_clause(part, text_lower));
        }
        simple_match_term(trimmed, text_lower)
    }

    let text_lower = document.to_ascii_lowercase();
    eval_clause(query, &text_lower)
}

fn match_query_with_table_columns(
    operand_expr: &Expr,
    query: &str,
    document: &str,
    row: &[SqliteValue],
    col_map: &[(String, String, bool)],
) -> bool {
    if let Expr::Column(col_ref, _) = operand_expr
        && col_ref.table.is_none()
        && let Some(row_table_label) = resolve_fts5_row_table_label(&col_ref.column, col_map)
    {
        let columns = collect_match_columns(&row_table_label, row, col_map);
        return simple_match_query_with_columns(query, document, &columns);
    }

    simple_match_query(query, document)
}

fn collect_match_columns(
    table_name: &str,
    row: &[SqliteValue],
    col_map: &[(String, String, bool)],
) -> Vec<(String, String)> {
    col_map
        .iter()
        .enumerate()
        .filter(|(_, (table, _, hidden))| table.eq_ignore_ascii_case(table_name) && !hidden)
        .filter_map(|(idx, (_, column, _))| {
            let value = row.get(idx)?;
            if matches!(value, SqliteValue::Null) {
                return None;
            }
            Some((column.clone(), sqlite_value_to_text(value)))
        })
        .collect()
}

fn simple_match_query_with_columns(
    query: &str,
    document: &str,
    columns: &[(String, String)],
) -> bool {
    let Ok(tokens) = parse_fts5_query(query) else {
        return simple_match_query(query, document);
    };
    let Ok(expr) = build_expr(&tokens) else {
        return simple_match_query(query, document);
    };
    simple_match_fts5_expr(&expr, document, columns)
}

fn simple_match_fts5_expr(expr: &Fts5Expr, document: &str, columns: &[(String, String)]) -> bool {
    match expr {
        Fts5Expr::Term(term) => simple_match_term(term, &document.to_lowercase()),
        Fts5Expr::Prefix(prefix) => simple_match_prefix(prefix, &document.to_lowercase()),
        Fts5Expr::Phrase(words) => simple_match_phrase(words, &document.to_lowercase()),
        Fts5Expr::And(left, right) => {
            simple_match_fts5_expr(left, document, columns)
                && simple_match_fts5_expr(right, document, columns)
        }
        Fts5Expr::Or(left, right) => {
            simple_match_fts5_expr(left, document, columns)
                || simple_match_fts5_expr(right, document, columns)
        }
        Fts5Expr::Not(left, right) => {
            simple_match_fts5_expr(left, document, columns)
                && !simple_match_fts5_expr(right, document, columns)
        }
        Fts5Expr::Near(terms, _) => terms
            .iter()
            .all(|term| simple_match_term(term, &document.to_lowercase())),
        Fts5Expr::ColumnFilter(column_name, inner) => {
            let filtered_columns: Vec<(String, String)> = columns
                .iter()
                .filter(|(column, _)| column.eq_ignore_ascii_case(column_name))
                .cloned()
                .collect();
            if filtered_columns.is_empty() {
                return false;
            }
            let filtered_document = filtered_columns
                .iter()
                .map(|(_, text)| text.as_str())
                .collect::<Vec<_>>()
                .join(" ");
            simple_match_fts5_expr(inner, &filtered_document, &filtered_columns)
        }
        Fts5Expr::InitialToken(inner) => match inner.as_ref() {
            Fts5Expr::Term(term) => document
                .split_whitespace()
                .next()
                .is_some_and(|word| word.to_lowercase().contains(&term.to_lowercase())),
            Fts5Expr::Prefix(prefix) => document
                .split_whitespace()
                .next()
                .is_some_and(|word| word.to_lowercase().starts_with(&prefix.to_lowercase())),
            Fts5Expr::Phrase(words) => document
                .to_lowercase()
                .starts_with(&words.join(" ").to_lowercase()),
            _ => simple_match_fts5_expr(inner, document, columns),
        },
    }
}

fn simple_match_term(term: &str, text_lower: &str) -> bool {
    let mut normalized = term
        .trim()
        .trim_matches('"')
        .trim_matches('\'')
        .to_lowercase();
    if normalized.is_empty() {
        return false;
    }
    if normalized.ends_with('*') {
        normalized.pop();
        if normalized.is_empty() {
            return true;
        }
        return text_lower
            .split_whitespace()
            .any(|word| word.starts_with(&normalized));
    }
    text_lower.contains(&normalized)
}

fn simple_match_prefix(prefix: &str, text_lower: &str) -> bool {
    let normalized = prefix.trim().to_lowercase();
    if normalized.is_empty() {
        return false;
    }
    text_lower
        .split_whitespace()
        .any(|word| word.starts_with(&normalized))
}

fn simple_match_phrase(words: &[String], text_lower: &str) -> bool {
    if words.is_empty() {
        return false;
    }
    text_lower.contains(&words.join(" ").to_lowercase())
}

/// Simple GLOB pattern match (`*` = any sequence, `?` = any char, case-sensitive).
fn simple_glob_match(pattern: &str, string: &str) -> bool {
    let pat: Vec<char> = pattern.chars().collect();
    let txt: Vec<char> = string.chars().collect();
    glob_dp(&pat, &txt, 0, 0)
}

fn glob_dp(pat: &[char], txt: &[char], pi: usize, ti: usize) -> bool {
    if pi == pat.len() {
        return ti == txt.len();
    }
    match pat[pi] {
        '*' => {
            let mut t = ti;
            loop {
                if glob_dp(pat, txt, pi + 1, t) {
                    return true;
                }
                if t >= txt.len() {
                    return false;
                }
                t += 1;
            }
        }
        '?' => ti < txt.len() && glob_dp(pat, txt, pi + 1, ti + 1),
        c => ti < txt.len() && txt[ti] == c && glob_dp(pat, txt, pi + 1, ti + 1),
    }
}

/// Parse leading integer from a string, matching SQLite's prefix extraction.
fn parse_integer_prefix(s: &str) -> i64 {
    let f = parse_float_prefix(s);
    #[allow(clippy::manual_clamp)]
    if f >= i64::MAX as f64 {
        i64::MAX
    } else if f <= i64::MIN as f64 {
        i64::MIN
    } else {
        f as i64
    }
}

/// Parse the longest numeric prefix of `s` as a float, matching SQLite's
/// `sqlite3AtoF` behavior. Does NOT recognize "nan"/"inf"/"infinity".
fn parse_float_prefix(s: &str) -> f64 {
    let trimmed = s.trim();
    if trimmed.is_empty() {
        return 0.0;
    }
    let bytes = trimmed.as_bytes();
    let mut i = 0;
    // Optional sign
    if i < bytes.len() && (bytes[i] == b'+' || bytes[i] == b'-') {
        i += 1;
    }
    let start = i;
    // Integer digits
    while i < bytes.len() && bytes[i].is_ascii_digit() {
        i += 1;
    }
    // Decimal point + fractional digits
    if i < bytes.len() && bytes[i] == b'.' {
        i += 1;
        while i < bytes.len() && bytes[i].is_ascii_digit() {
            i += 1;
        }
    }
    // Must have consumed at least one digit
    if i == start {
        return 0.0;
    }
    // Exponent
    if i < bytes.len() && (bytes[i] == b'e' || bytes[i] == b'E') {
        let mut j = i + 1;
        if j < bytes.len() && (bytes[j] == b'+' || bytes[j] == b'-') {
            j += 1;
        }
        if j < bytes.len() && bytes[j].is_ascii_digit() {
            j += 1;
            while j < bytes.len() && bytes[j].is_ascii_digit() {
                j += 1;
            }
            i = j;
        }
    }
    trimmed[..i].parse::<f64>().unwrap_or(0.0)
}

/// Apply a CAST to a value based on the target type name.
#[allow(clippy::cast_possible_truncation)]
fn apply_cast(val: SqliteValue, type_name: &str) -> SqliteValue {
    if val.is_null() {
        return SqliteValue::Null;
    }
    // Use SQLite affinity rules (substring matching, priority order)
    // to determine target type: INT > TEXT/CHAR/CLOB > BLOB > REAL/FLOA/DOUB > NUMERIC
    let upper = type_name.to_ascii_uppercase();
    if upper.contains("INT") {
        match val {
            SqliteValue::Integer(_) => val,
            SqliteValue::Float(f) => SqliteValue::Integer(f as i64),
            SqliteValue::Text(ref s) => SqliteValue::Integer(parse_integer_prefix(s)),
            SqliteValue::Blob(ref b) => {
                let s = String::from_utf8_lossy(b);
                SqliteValue::Integer(parse_integer_prefix(&s))
            }
            SqliteValue::Null => SqliteValue::Null,
        }
    } else if upper.contains("TEXT") || upper.contains("CHAR") || upper.contains("CLOB") {
        SqliteValue::Text(val.to_text().into())
    } else if upper.contains("BLOB") || upper.is_empty() {
        match val {
            SqliteValue::Blob(_) => val,
            SqliteValue::Text(s) => SqliteValue::Blob(s.as_bytes().to_vec().into()),
            SqliteValue::Integer(_) | SqliteValue::Float(_) => {
                SqliteValue::Blob(val.to_text().into_bytes().into())
            }
            SqliteValue::Null => SqliteValue::Null,
        }
    } else if upper.contains("REAL") || upper.contains("FLOA") || upper.contains("DOUB") {
        match val {
            SqliteValue::Float(_) => val,
            SqliteValue::Integer(n) => SqliteValue::Float(n as f64),
            SqliteValue::Text(ref s) => {
                let f = parse_float_prefix(s);
                SqliteValue::Float(if f.is_finite() { f } else { 0.0 })
            }
            SqliteValue::Blob(ref b) => {
                let s = String::from_utf8_lossy(b);
                let f = parse_float_prefix(&s);
                SqliteValue::Float(if f.is_finite() { f } else { 0.0 })
            }
            SqliteValue::Null => SqliteValue::Null,
        }
    } else {
        // NUMERIC affinity: try integer first, then float
        match val {
            SqliteValue::Text(ref s) => {
                if let Ok(n) = s.trim().parse::<i64>() {
                    SqliteValue::Integer(n)
                } else if let Ok(f) = s.trim().parse::<f64>() {
                    if f.is_finite() {
                        SqliteValue::Float(f)
                    } else {
                        val
                    }
                } else {
                    val
                }
            }
            _ => val,
        }
    }
}

/// Convert a `SqliteValue` to its text representation.
fn sqlite_value_to_text(v: &SqliteValue) -> String {
    v.to_text()
}

/// Evaluate a scalar function call (for JOIN expression evaluation).
#[allow(
    clippy::too_many_lines,
    clippy::cast_possible_truncation,
    clippy::cast_sign_loss,
    clippy::cast_possible_wrap
)]
fn eval_scalar_fn(name: &str, args: &[SqliteValue]) -> SqliteValue {
    // Avoid allocation when name is already lowercase (common case from parser).
    let owned_lower;
    let lower: &str = if name.bytes().all(|b| !b.is_ascii_uppercase()) {
        name
    } else {
        owned_lower = name.to_ascii_lowercase();
        &owned_lower
    };

    // Standard SQL NULL propagation: if any argument is NULL, most scalar
    // functions return NULL.  Functions with special NULL handling are exempt.
    match lower {
        "coalesce" | "ifnull" | "nullif" | "typeof" | "quote" | "iif" => {}
        _ => {
            if args.iter().any(SqliteValue::is_null) {
                return SqliteValue::Null;
            }
        }
    }

    match lower {
        "length" | "len" => match args.first() {
            Some(SqliteValue::Text(s)) => {
                // C SQLite: length() returns character count, not byte count.
                #[allow(clippy::cast_possible_wrap)]
                SqliteValue::Integer(s.chars().count() as i64)
            }
            Some(SqliteValue::Blob(b)) =>
            {
                #[allow(clippy::cast_possible_wrap)]
                SqliteValue::Integer(b.len() as i64)
            }
            Some(SqliteValue::Integer(n)) =>
            {
                #[allow(clippy::cast_possible_wrap)]
                SqliteValue::Integer(n.to_string().len() as i64)
            }
            Some(v @ SqliteValue::Float(_)) =>
            {
                #[allow(clippy::cast_possible_wrap)]
                SqliteValue::Integer(v.to_text().len() as i64)
            }
            _ => SqliteValue::Null,
        },
        "upper" => {
            if let Some(SqliteValue::Text(s)) = args.first() {
                SqliteValue::Text(s.to_ascii_uppercase().into())
            } else {
                SqliteValue::Null
            }
        }
        "lower" => {
            if let Some(SqliteValue::Text(s)) = args.first() {
                SqliteValue::Text(s.to_ascii_lowercase().into())
            } else {
                SqliteValue::Null
            }
        }
        "abs" => match args.first() {
            Some(SqliteValue::Integer(n)) => {
                if *n == i64::MIN {
                    // i64::MIN cannot be negated; C SQLite returns integer overflow error.
                    // Promote to float to avoid panic.
                    #[allow(clippy::cast_precision_loss)]
                    SqliteValue::Float((*n as f64).abs())
                } else {
                    SqliteValue::Integer(n.abs())
                }
            }
            Some(SqliteValue::Float(f)) => {
                // Match C SQLite: abs uses `x < 0 ? -x : x`.
                // IEEE 754: -0.0 < 0.0 is false, so abs(-0.0) == -0.0.
                SqliteValue::Float(if *f < 0.0 { -f } else { *f })
            }
            _ => SqliteValue::Null,
        },
        "coalesce" => args
            .iter()
            .find(|v| !matches!(v, SqliteValue::Null))
            .cloned()
            .unwrap_or(SqliteValue::Null),
        "ifnull" => {
            if args.len() >= 2 {
                if matches!(&args[0], SqliteValue::Null) {
                    args[1].clone()
                } else {
                    args[0].clone()
                }
            } else {
                SqliteValue::Null
            }
        }
        "nullif" => {
            if args.len() >= 2 && cmp_values(&args[0], &args[1]) == std::cmp::Ordering::Equal {
                SqliteValue::Null
            } else {
                args.first().cloned().unwrap_or(SqliteValue::Null)
            }
        }
        "typeof" => {
            let type_name = match args.first() {
                Some(SqliteValue::Integer(_)) => "integer",
                Some(SqliteValue::Float(_)) => "real",
                Some(SqliteValue::Text(_)) => "text",
                Some(SqliteValue::Blob(_)) => "blob",
                _ => "null",
            };
            SqliteValue::Text(type_name.into())
        }
        "strftime" => {
            use fsqlite_func::ScalarFunction;
            if let Ok(v) = fsqlite_func::datetime::StrftimeFunc.invoke(args) {
                v
            } else {
                SqliteValue::Null
            }
        }
        "date" => {
            use fsqlite_func::ScalarFunction;
            if let Ok(v) = fsqlite_func::datetime::DateFunc.invoke(args) {
                v
            } else {
                SqliteValue::Null
            }
        }
        "time" => {
            use fsqlite_func::ScalarFunction;
            if let Ok(v) = fsqlite_func::datetime::TimeFunc.invoke(args) {
                v
            } else {
                SqliteValue::Null
            }
        }
        "datetime" => {
            use fsqlite_func::ScalarFunction;
            if let Ok(v) = fsqlite_func::datetime::DateTimeFunc.invoke(args) {
                v
            } else {
                SqliteValue::Null
            }
        }
        "julianday" => {
            use fsqlite_func::ScalarFunction;
            if let Ok(v) = fsqlite_func::datetime::JuliandayFunc.invoke(args) {
                v
            } else {
                SqliteValue::Null
            }
        }
        "unixepoch" => {
            use fsqlite_func::ScalarFunction;
            if let Ok(v) = fsqlite_func::datetime::UnixepochFunc.invoke(args) {
                v
            } else {
                SqliteValue::Null
            }
        }
        "timediff" => {
            use fsqlite_func::ScalarFunction;
            if let Ok(v) = fsqlite_func::datetime::TimediffFunc.invoke(args) {
                v
            } else {
                SqliteValue::Null
            }
        }
        "iif" => {
            if args.len() >= 3 {
                if is_sqlite_truthy(&args[0]) {
                    args[1].clone()
                } else {
                    args[2].clone()
                }
            } else {
                SqliteValue::Null
            }
        }
        "max" => args
            .iter()
            .filter(|v| !matches!(v, SqliteValue::Null))
            .max_by(|a, b| cmp_sqlite_values(a, b))
            .cloned()
            .unwrap_or(SqliteValue::Null),
        "min" => args
            .iter()
            .filter(|v| !matches!(v, SqliteValue::Null))
            .min_by(|a, b| cmp_sqlite_values(a, b))
            .cloned()
            .unwrap_or(SqliteValue::Null),
        "replace" => {
            if args.len() >= 3 {
                if args[0].is_null() || args[1].is_null() || args[2].is_null() {
                    return SqliteValue::Null;
                }
                let s = sqlite_value_to_text(&args[0]);
                let from = sqlite_value_to_text(&args[1]);
                let to = sqlite_value_to_text(&args[2]);
                if from.is_empty() {
                    SqliteValue::Text(s.into())
                } else {
                    SqliteValue::Text(s.replace(&from, &to).into())
                }
            } else {
                SqliteValue::Null
            }
        }
        "substr" | "substring" => {
            // Coerce any non-NULL value to text first (C SQLite does this).
            // E.g., SUBSTR(12345, 2, 3) should return '234'.
            let coerced_text = args.first().and_then(|v| {
                if v.is_null() {
                    None
                } else {
                    Some(sqlite_value_to_text(v))
                }
            });
            if let Some(s) = coerced_text.as_deref() {
                let chars: Vec<char> = s.chars().collect();
                let n = chars.len() as i64;
                let raw_start = args
                    .get(1)
                    .map_or(1, fsqlite_types::SqliteValue::to_integer);
                // SQLite: negative start counts from right.
                let p2 = match raw_start.cmp(&0) {
                    std::cmp::Ordering::Less => n + 1 + raw_start,
                    std::cmp::Ordering::Equal => 0, // range calculation handles this correctly
                    std::cmp::Ordering::Greater => raw_start,
                };
                if let Some(len_val) = args.get(2) {
                    let p3 = len_val.to_integer();
                    // C SQLite range: [p2, p2+p3) in 1-based positions.
                    // Characters before position 1 are ignored; negative length
                    // means characters before the start position.
                    let (y, z) = if p3 < 0 {
                        // Negative length: range is [p2+p3, p2)
                        (p2 + p3, p2)
                    } else {
                        (p2, p2 + p3)
                    };
                    // Clamp to valid 1-based range [1, n+1).
                    let start = (y.max(1) - 1) as usize;
                    let end = ((z - 1).max(0) as usize).min(chars.len());
                    let start = start.min(chars.len());
                    if start < end {
                        SqliteValue::Text(chars[start..end].iter().collect::<String>().into())
                    } else {
                        SqliteValue::Text(String::new().into())
                    }
                } else {
                    let idx = ((p2.max(1) - 1) as usize).min(chars.len());
                    SqliteValue::Text(chars[idx..].iter().collect::<String>().into())
                }
            } else {
                SqliteValue::Null
            }
        }
        "instr" => {
            if args.len() >= 2 {
                let haystack = sqlite_value_to_text(&args[0]);
                let needle = sqlite_value_to_text(&args[1]);
                // C SQLite: instr() returns 1-based character position, not byte offset.
                #[allow(clippy::cast_possible_wrap)]
                let pos = haystack.find(&needle).map_or(0i64, |byte_pos| {
                    (haystack[..byte_pos].chars().count() + 1) as i64
                });
                SqliteValue::Integer(pos)
            } else {
                SqliteValue::Null
            }
        }
        "trim" => {
            if let Some(v) = args.first() {
                let s = sqlite_value_to_text(v);
                if let Some(chars_arg) = args.get(1) {
                    let chars: Vec<char> = sqlite_value_to_text(chars_arg).chars().collect();
                    SqliteValue::Text(
                        s.trim_matches(|c: char| chars.contains(&c))
                            .to_owned()
                            .into(),
                    )
                } else {
                    // C SQLite default: trim spaces only (not all Unicode whitespace).
                    SqliteValue::Text(s.trim_matches(' ').to_owned().into())
                }
            } else {
                SqliteValue::Null
            }
        }
        "ltrim" => {
            if let Some(v) = args.first() {
                let s = sqlite_value_to_text(v);
                if let Some(chars_arg) = args.get(1) {
                    let chars: Vec<char> = sqlite_value_to_text(chars_arg).chars().collect();
                    SqliteValue::Text(
                        s.trim_start_matches(|c: char| chars.contains(&c))
                            .to_owned()
                            .into(),
                    )
                } else {
                    SqliteValue::Text(s.trim_start_matches(' ').to_owned().into())
                }
            } else {
                SqliteValue::Null
            }
        }
        "rtrim" => {
            if let Some(v) = args.first() {
                let s = sqlite_value_to_text(v);
                if let Some(chars_arg) = args.get(1) {
                    let chars: Vec<char> = sqlite_value_to_text(chars_arg).chars().collect();
                    SqliteValue::Text(
                        s.trim_end_matches(|c: char| chars.contains(&c))
                            .to_owned()
                            .into(),
                    )
                } else {
                    SqliteValue::Text(s.trim_end_matches(' ').to_owned().into())
                }
            } else {
                SqliteValue::Null
            }
        }
        "hex" => match args.first() {
            Some(SqliteValue::Blob(b)) => {
                use std::fmt::Write;
                let mut hex = String::with_capacity(b.len() * 2);
                for &byte in b.iter() {
                    let _ = write!(hex, "{byte:02X}");
                }
                SqliteValue::Text(hex.into())
            }
            Some(v) => {
                use std::fmt::Write;
                let s = sqlite_value_to_text(v);
                let mut hex = String::with_capacity(s.len() * 2);
                for b in s.bytes() {
                    let _ = write!(hex, "{b:02X}");
                }
                SqliteValue::Text(hex.into())
            }
            None => SqliteValue::Null,
        },
        "quote" => match args.first() {
            Some(SqliteValue::Null) => SqliteValue::Text("NULL".into()),
            Some(SqliteValue::Integer(n)) => SqliteValue::Text(n.to_string().into()),
            Some(v @ SqliteValue::Float(_)) => SqliteValue::Text(v.to_text().into()),
            Some(SqliteValue::Text(s)) => {
                SqliteValue::Text(format!("'{}'", s.replace('\'', "''")).into())
            }
            Some(SqliteValue::Blob(b)) => {
                use std::fmt::Write;
                let mut hex = String::with_capacity(b.len() * 2);
                for &byte in b.iter() {
                    let _ = write!(hex, "{byte:02X}");
                }
                SqliteValue::Text(format!("X'{hex}'").into())
            }
            None => SqliteValue::Null,
        },
        "unicode" => {
            if let Some(SqliteValue::Text(s)) = args.first() {
                s.chars().next().map_or(SqliteValue::Null, |c| {
                    SqliteValue::Integer(i64::from(c as u32))
                })
            } else {
                SqliteValue::Null
            }
        }
        "char" => {
            let s: String = args
                .iter()
                .filter_map(|v| {
                    if let SqliteValue::Integer(n) = v {
                        #[allow(clippy::cast_sign_loss)]
                        char::from_u32(*n as u32)
                    } else {
                        None
                    }
                })
                .collect();
            SqliteValue::Text(s.into())
        }
        "random" => {
            use std::sync::atomic::{AtomicU64, Ordering};
            static COUNTER: AtomicU64 = AtomicU64::new(0x517C_C1B7_2722_0A95);
            let mut s = COUNTER.fetch_add(1, Ordering::Relaxed);
            // xorshift64
            s ^= s << 13;
            s ^= s >> 7;
            s ^= s << 17;
            COUNTER.store(s, Ordering::Relaxed);
            #[allow(clippy::cast_possible_wrap)]
            SqliteValue::Integer(s as i64)
        }
        "zeroblob" => {
            let n = args.first().map_or(0, |v| v.to_integer().max(0)) as usize;
            SqliteValue::Blob(vec![0u8; n].into())
        }
        "round" => match args.first() {
            Some(SqliteValue::Float(f)) => {
                #[allow(clippy::cast_possible_truncation)]
                let n = args
                    .get(1)
                    .map_or(0, fsqlite_types::SqliteValue::to_integer)
                    .clamp(0, 30) as usize;
                // SQLite's custom printf uses "round half away from zero".
                // Rust's format! uses "round half to even". They differ
                // only on exact ties — detect those and adjust.
                let rounded = {
                    let prec = n + 15;
                    let full = format!("{f:.prec$}");
                    let dot = full.find('.').unwrap_or(full.len());
                    let rd_idx = dot + 1 + n;
                    if rd_idx >= full.len() {
                        format!("{f:.n$}").parse::<f64>().unwrap_or(*f)
                    } else {
                        let rd = full.as_bytes()[rd_idx] - b'0';
                        if rd != 5 || !full[rd_idx + 1..].bytes().all(|b| b == b'0') {
                            format!("{f:.n$}").parse::<f64>().unwrap_or(*f)
                        } else {
                            let mut trunc = full.as_bytes()[..rd_idx].to_vec();
                            if trunc.last() == Some(&b'.') {
                                trunc.pop();
                            }
                            let start = usize::from(trunc.first() == Some(&b'-'));
                            let mut carry = true;
                            for b in trunc[start..].iter_mut().rev() {
                                if *b == b'.' {
                                    continue;
                                }
                                if carry {
                                    if *b == b'9' {
                                        *b = b'0';
                                    } else {
                                        *b += 1;
                                        carry = false;
                                        break;
                                    }
                                }
                            }
                            if carry {
                                trunc.insert(start, b'1');
                            }
                            String::from_utf8(trunc)
                                .ok()
                                .and_then(|s| s.parse::<f64>().ok())
                                .unwrap_or(*f)
                        }
                    }
                };
                SqliteValue::Float(rounded)
            }
            Some(SqliteValue::Integer(n)) => SqliteValue::Float(*n as f64),
            _ => SqliteValue::Null,
        },
        "sign" => match args.first() {
            Some(SqliteValue::Integer(n)) => SqliteValue::Integer(n.signum()),
            Some(SqliteValue::Float(f)) => {
                if f.is_nan() {
                    SqliteValue::Null
                } else {
                    SqliteValue::Integer(if *f > 0.0 {
                        1
                    } else if *f < 0.0 {
                        -1
                    } else {
                        0
                    })
                }
            }
            _ => SqliteValue::Null,
        },
        "concat" => {
            let parts: Vec<String> = args
                .iter()
                .filter(|v| !matches!(v, SqliteValue::Null))
                .map(sqlite_value_to_text)
                .collect();
            SqliteValue::Text(parts.concat().into())
        }
        "concat_ws" => {
            if let Some(sep) = args.first() {
                if matches!(sep, SqliteValue::Null) {
                    return SqliteValue::Null;
                }
                let sep_str = sqlite_value_to_text(sep);
                let parts: Vec<String> = args[1..]
                    .iter()
                    .filter(|v| !matches!(v, SqliteValue::Null))
                    .map(sqlite_value_to_text)
                    .collect();
                SqliteValue::Text(parts.join(&sep_str).into())
            } else {
                SqliteValue::Null
            }
        }
        "sqlite_version" => SqliteValue::Text("3.52.0".into()),
        "last_insert_rowid" => SqliteValue::Integer(get_last_insert_rowid()),
        "changes" => SqliteValue::Integer(get_last_changes()),
        "total_changes" => SqliteValue::Integer(get_total_changes()),
        "likely" | "unlikely" => args.first().cloned().unwrap_or(SqliteValue::Null),
        _ => SqliteValue::Null,
    }
}

/// Evaluate a join expression with optional USING column skip support.
///
/// For column references, uses `find_col_in_map` with the `using_skip` set
/// so that right-table USING duplicates are excluded from unqualified lookup.
/// For all other expression types, delegates to `eval_join_expr`.
fn eval_join_expr_with_using(
    expr: &Expr,
    row: &[SqliteValue],
    col_map: &[(String, String, bool)],
    using_skip: Option<&HashSet<usize>>,
) -> Result<SqliteValue> {
    if let Some(skip) = using_skip {
        if let Expr::Column(col_ref, _) = expr {
            let col_name = &col_ref.column;
            let table_prefix = col_ref.table.as_deref();
            if let Ok(idx) = find_col_in_map(col_map, table_prefix, col_name, Some(skip)) {
                return Ok(row.get(idx).cloned().unwrap_or(SqliteValue::Null));
            }
        }
    }
    eval_join_expr(expr, row, col_map)
}

// ── Time-travel query helper functions (#23) ──────────────────────────────

/// Extract the first `TimeTravelTarget` from a SELECT statement's FROM clause.
///
/// Checks the primary source table and all JOIN tables. Returns `None` if no
/// `FOR SYSTEM_TIME AS OF` clause is present.
fn extract_temporal_clause(select: &SelectStatement) -> Option<TimeTravelTarget> {
    let from = match &select.body.select {
        SelectCore::Select { from, .. } => from.as_ref()?,
        SelectCore::Values(_) => return None,
    };
    // Check the primary source table.
    if let TableOrSubquery::Table {
        time_travel: Some(tt),
        ..
    } = &from.source
    {
        return Some(tt.target.clone());
    }
    // Check JOIN tables.
    for join in &from.joins {
        if let TableOrSubquery::Table {
            time_travel: Some(tt),
            ..
        } = &join.table
        {
            return Some(tt.target.clone());
        }
    }
    None
}

/// Remove all `TimeTravelClause` annotations from a SELECT statement.
///
/// This produces a clean SELECT that can be executed against a historical
/// MemDatabase snapshot without the VDBE seeing time-travel directives.
#[allow(clippy::collapsible_match)]
fn strip_temporal_clauses(select: &mut SelectStatement) {
    if let SelectCore::Select { ref mut from, .. } = select.body.select {
        if let Some(from) = from {
            if let TableOrSubquery::Table {
                ref mut time_travel,
                ..
            } = from.source
            {
                *time_travel = None;
            }
            for join in &mut from.joins {
                if let TableOrSubquery::Table {
                    ref mut time_travel,
                    ..
                } = join.table
                {
                    *time_travel = None;
                }
            }
        }
    }
}

/// Parse a timestamp string to nanoseconds since Unix epoch.
///
/// Accepts:
/// - Pure integer (Unix seconds): "1700000000"
/// - ISO-8601: "2024-01-15T10:30:00Z"
/// - SQLite datetime: "2024-01-15 10:30:00"
fn parse_timestamp_to_ns(ts: &str) -> Result<u64> {
    // Try as raw integer (Unix seconds).
    if let Ok(secs) = ts.parse::<u64>() {
        return Ok(secs.saturating_mul(1_000_000_000));
    }

    // Try ISO-8601 / SQLite datetime.
    let ts = ts.trim_end_matches('Z');
    let parts: Vec<&str> = ts.splitn(2, ['T', ' ']).collect();
    if parts.len() != 2 {
        return Err(FrankenError::Internal(format!(
            "time-travel: cannot parse timestamp '{ts}' — expected ISO-8601 or Unix seconds"
        )));
    }
    let date_parts: Vec<&str> = parts[0].split('-').collect();
    if date_parts.len() != 3 {
        return Err(FrankenError::Internal(format!(
            "time-travel: invalid date in timestamp '{ts}'"
        )));
    }
    let year: i64 = date_parts[0]
        .parse()
        .map_err(|_| FrankenError::Internal(format!("time-travel: invalid year in '{ts}'")))?;
    let month: i64 = date_parts[1]
        .parse()
        .map_err(|_| FrankenError::Internal(format!("time-travel: invalid month in '{ts}'")))?;
    let day: i64 = date_parts[2]
        .parse()
        .map_err(|_| FrankenError::Internal(format!("time-travel: invalid day in '{ts}'")))?;

    let time_parts: Vec<&str> = parts[1].split(':').collect();
    let (hour, min, sec) = match time_parts.len() {
        3 => {
            let h: u64 = time_parts[0].parse().unwrap_or(0);
            let m: u64 = time_parts[1].parse().unwrap_or(0);
            let s: u64 = time_parts[2].parse().unwrap_or(0);
            (h, m, s)
        }
        _ => (0, 0, 0),
    };

    // Howard Hinnant's civil date algorithm.
    let era_day = {
        let y = if month <= 2 { year - 1 } else { year };
        let m = if month <= 2 { month + 9 } else { month - 3 };
        let era = y.div_euclid(400);
        let yoe = y.rem_euclid(400);
        let doy = (153 * m + 2) / 5 + day - 1;
        let doe = yoe * 365 + yoe / 4 - yoe / 100 + doy;
        era * 146097 + doe
    };
    // Days from 0000-03-01 to Unix epoch (1970-01-01) = 719468.
    let unix_days = era_day - 719468;
    let total_secs = unix_days as u64 * 86400 + hour * 3600 + min * 60 + sec;
    Ok(total_secs.saturating_mul(1_000_000_000))
}

/// Format a `TimeTravelTarget` for error messages.
fn format_time_travel_target(target: &TimeTravelTarget) -> String {
    match target {
        TimeTravelTarget::CommitSequence(seq) => format!("COMMITSEQ {seq}"),
        TimeTravelTarget::Timestamp(ts) => format!("'{ts}'"),
    }
}

