    #[test]
    fn test_same_row_concurrent_beads_rewrite_reports_transient_not_pk_violation() {
        let dir = tempfile::tempdir().unwrap();
        let db_path = dir.path().join("same_row_beads_rewrite_text_pk.db");
        let db_str = db_path.to_string_lossy().to_string();

        {
            let conn = Connection::open(&db_str).unwrap();
            conn.execute("PRAGMA fsqlite.concurrent_mode=ON;").unwrap();
            conn.execute(
                "CREATE TABLE issues (
                    id TEXT PRIMARY KEY,
                    content_hash TEXT,
                    title TEXT NOT NULL,
                    status TEXT NOT NULL,
                    priority INTEGER NOT NULL,
                    created_at TEXT NOT NULL,
                    updated_at TEXT NOT NULL,
                    ephemeral INTEGER NOT NULL DEFAULT 0,
                    pinned INTEGER NOT NULL DEFAULT 0,
                    is_template INTEGER
                );",
            )
            .unwrap();
            conn.execute("CREATE INDEX idx_issues_content_hash ON issues(content_hash);")
                .unwrap();
            conn.execute(
                "INSERT INTO issues(
                    id, content_hash, title, status, priority, created_at, updated_at,
                    ephemeral, pinned, is_template
                 ) VALUES (
                    'bd-040',
                    'seed-040',
                    'issue 040',
                    'open',
                    0,
                    '2026-03-11T08:00:00Z',
                    '2026-03-11T08:00:00Z',
                    0,
                    0,
                    0
                 );",
            )
            .unwrap();
        }

        let conn1 = Connection::open(&db_str).unwrap();
        let conn2 = Connection::open(&db_str).unwrap();
        for conn in [&conn1, &conn2] {
            conn.execute("PRAGMA busy_timeout=5000;").unwrap();
            conn.execute("PRAGMA fsqlite.concurrent_mode=ON;").unwrap();
        }

        conn1.execute("BEGIN CONCURRENT;").unwrap();
        conn2.execute("BEGIN CONCURRENT;").unwrap();

        assert_eq!(
            conn1
                .execute(
                    "UPDATE issues
                     SET content_hash = 'winner-hash',
                         priority = 1,
                         created_at = '2026-03-12T01:00:00Z',
                         updated_at = '2026-03-12T01:00:00Z',
                         status = 'closed',
                         pinned = 1,
                         is_template = 0
                     WHERE id = 'bd-040';"
                )
                .unwrap(),
            1
        );

        let loser_err = match conn2.execute(
            "UPDATE issues
             SET content_hash = 'loser-hash',
                 priority = 2,
                 created_at = '2026-03-12T02:00:00Z',
                 updated_at = '2026-03-12T02:00:00Z',
                 status = 'tombstone',
                 pinned = 0,
                 is_template = NULL
             WHERE id = 'bd-040';",
        ) {
            Ok(changes) => {
                assert_eq!(
                    changes, 1,
                    "second writer should affect one row before stale conflict resolves"
                );
                conn1.execute("COMMIT;").unwrap();
                conn2.execute("COMMIT;").unwrap_err()
            }
            Err(err) => {
                conn1.execute("COMMIT;").unwrap();
                err
            }
        };

        assert!(
            loser_err.is_transient(),
            "same-row Beads rewrite should fail transiently, got {loser_err:?}"
        );

        conn2.execute("ROLLBACK;").unwrap();

        let visible = conn1
            .query_row(
                "SELECT content_hash, priority, created_at, status, pinned, is_template
                 FROM issues
                 WHERE id = 'bd-040';",
            )
            .unwrap();
        assert_eq!(
            visible.values(),
            &[
                SqliteValue::Text("winner-hash".into()),
                SqliteValue::Integer(1),
                SqliteValue::Text("2026-03-12T01:00:00Z".into()),
                SqliteValue::Text("closed".into()),
                SqliteValue::Integer(1),
                SqliteValue::Integer(0),
            ],
            "winner state must remain visible after loser rollback"
        );
    }

    #[test]
    fn test_retrying_same_row_beads_rewrite_rebinds_latest_content_hash() {
        let dir = tempfile::tempdir().unwrap();
        let db_path = dir.path().join("retry_same_row_beads_rewrite_text_pk.db");
        let db_str = db_path.to_string_lossy().to_string();

        {
            let conn = Connection::open(&db_str).unwrap();
            conn.execute("PRAGMA fsqlite.concurrent_mode=ON;").unwrap();
            conn.execute(
                "CREATE TABLE issues (
                    id TEXT PRIMARY KEY,
                    content_hash TEXT,
                    title TEXT NOT NULL,
                    status TEXT NOT NULL,
                    priority INTEGER NOT NULL,
                    created_at TEXT NOT NULL,
                    updated_at TEXT NOT NULL,
                    ephemeral INTEGER NOT NULL DEFAULT 0,
                    pinned INTEGER NOT NULL DEFAULT 0,
                    is_template INTEGER
                );",
            )
            .unwrap();
            conn.execute("CREATE INDEX idx_issues_content_hash ON issues(content_hash);")
                .unwrap();
            conn.execute(
                "INSERT INTO issues(
                    id, content_hash, title, status, priority, created_at, updated_at,
                    ephemeral, pinned, is_template
                 ) VALUES (
                    'bd-040',
                    'seed-040',
                    'issue 040',
                    'open',
                    0,
                    '2026-03-11T08:00:00Z',
                    '2026-03-11T08:00:00Z',
                    0,
                    0,
                    0
                 );",
            )
            .unwrap();
        }

        let conn1 = Connection::open(&db_str).unwrap();
        let conn2 = Connection::open(&db_str).unwrap();
        for conn in [&conn1, &conn2] {
            conn.execute("PRAGMA busy_timeout=5000;").unwrap();
            conn.execute("PRAGMA fsqlite.concurrent_mode=ON;").unwrap();
        }

        conn1.execute("BEGIN CONCURRENT;").unwrap();
        conn2.execute("BEGIN CONCURRENT;").unwrap();

        assert_eq!(
            conn1
                .execute(
                    "UPDATE issues
                     SET content_hash = 'winner-hash',
                         priority = 1,
                         created_at = '2026-03-12T01:00:00Z',
                         updated_at = '2026-03-12T01:00:00Z',
                         status = 'closed',
                         pinned = 1,
                         is_template = 0
                     WHERE id = 'bd-040';"
                )
                .unwrap(),
            1
        );

        let loser_err = match conn2.execute(
            "UPDATE issues
             SET content_hash = 'loser-hash',
                 priority = 2,
                 created_at = '2026-03-12T02:00:00Z',
                 updated_at = '2026-03-12T02:00:00Z',
                 status = 'tombstone',
                 pinned = 0,
                 is_template = NULL
             WHERE id = 'bd-040';",
        ) {
            Ok(changes) => {
                assert_eq!(changes, 1);
                conn1.execute("COMMIT;").unwrap();
                conn2.execute("COMMIT;").unwrap_err()
            }
            Err(err) => {
                conn1.execute("COMMIT;").unwrap();
                err
            }
        };
        assert!(
            loser_err.is_transient(),
            "losing writer should fail transiently, got {loser_err:?}"
        );

        conn2.execute("ROLLBACK;").unwrap();
        assert_eq!(
            conn2
                .query_row("SELECT content_hash FROM issues WHERE id = 'bd-040';")
                .unwrap()
                .get(0),
            Some(&SqliteValue::Text("winner-hash".into())),
            "loser must see winner content hash after rollback"
        );

        conn2.execute("BEGIN CONCURRENT;").unwrap();
        assert_eq!(
            conn2
                .execute(
                    "UPDATE issues
                     SET content_hash = 'retry-hash',
                         priority = 3,
                         created_at = '2026-03-12T03:00:00Z',
                         updated_at = '2026-03-12T03:00:00Z',
                         status = 'open',
                         pinned = 0,
                         is_template = 0
                     WHERE id = 'bd-040';"
                )
                .unwrap(),
            1
        );
        conn2.execute("COMMIT;").unwrap();

        let sqlite = rusqlite::Connection::open(&db_path).unwrap();
        let integrity_check: String = sqlite
            .query_row("PRAGMA integrity_check;", [], |row| row.get(0))
            .unwrap();
        assert_eq!(
            integrity_check, "ok",
            "retrying same-row rewrite must keep the content-hash index SQLite-compatible"
        );

        let retry_ids = sqlite
            .prepare(
                "SELECT id
                 FROM issues INDEXED BY idx_issues_content_hash
                 WHERE content_hash = 'retry-hash'
                 ORDER BY id",
            )
            .unwrap()
            .query_map([], |row| row.get::<_, String>(0))
            .unwrap()
            .collect::<rusqlite::Result<Vec<_>>>()
            .unwrap();
        assert_eq!(
            retry_ids,
            vec!["bd-040".to_owned()],
            "retry hash must be the only forced-index result"
        );

        let winner_count: i64 = sqlite
            .query_row(
                "SELECT COUNT(*) FROM issues WHERE content_hash = 'winner-hash'",
                [],
                |row| row.get(0),
            )
            .unwrap();
        assert_eq!(
            winner_count, 0,
            "winner hash must be fully removed after retry rewrite"
        );
    }

    #[test]
    fn test_concurrent_beads_issue_index_churn_stays_sqlite_compatible() {
        const WORKERS: usize = 4;
        const TXNS_PER_WORKER: usize = 90;
        const ISSUE_COUNT: usize = 48;

        let dir = tempfile::tempdir().unwrap();
        let db_path = dir.path().join("beads_issue_index_concurrent.db");
        let db_str = db_path.to_string_lossy().to_string();

        {
            let conn = Connection::open(&db_str).unwrap();
            conn.execute("PRAGMA busy_timeout=5000;").unwrap();
            conn.execute("PRAGMA fsqlite.concurrent_mode=ON;").unwrap();
            conn.execute(
                "CREATE TABLE issues (
                    id TEXT PRIMARY KEY,
                    content_hash TEXT,
                    title TEXT NOT NULL,
                    status TEXT NOT NULL,
                    priority INTEGER NOT NULL,
                    created_at TEXT NOT NULL,
                    updated_at TEXT NOT NULL,
                    ephemeral INTEGER NOT NULL DEFAULT 0,
                    pinned INTEGER NOT NULL DEFAULT 0,
                    is_template INTEGER
                );",
            )
            .unwrap();
            conn.execute("CREATE INDEX idx_issues_content_hash ON issues(content_hash);")
                .unwrap();
            conn.execute(
                "CREATE INDEX idx_issues_ready
                 ON issues(status, priority, created_at)
                 WHERE status = 'open'
                   AND ephemeral = 0
                   AND pinned = 0
                   AND is_template = 0;",
            )
            .unwrap();
            conn.execute(
                "CREATE INDEX idx_issues_list_active_order
                 ON issues(priority, created_at DESC)
                 WHERE status NOT IN ('closed', 'tombstone')
                   AND ((is_template = 0) OR is_template IS NULL);",
            )
            .unwrap();

            conn.execute("BEGIN;").unwrap();
            for issue_idx in 0..ISSUE_COUNT {
                let status = if issue_idx % 7 == 0 { "closed" } else { "open" };
                let is_template_sql = match issue_idx % 5 {
                    0 => "NULL",
                    1 => "1",
                    _ => "0",
                };
                conn.execute(&format!(
                    "INSERT INTO issues(
                        id, content_hash, title, status, priority, created_at, updated_at,
                        ephemeral, pinned, is_template
                     ) VALUES (
                        'bd-{issue_idx:03}',
                        'seed-{issue_idx:03}',
                        'issue {issue_idx:03}',
                        '{status}',
                        {},
                        '2026-03-11T{:02}:{:02}:00Z',
                        '2026-03-11T{:02}:{:02}:00Z',
                        0,
                        0,
                        {is_template_sql}
                     );",
                    issue_idx % 5,
                    issue_idx % 24,
                    issue_idx % 60,
                    issue_idx % 24,
                    issue_idx % 60,
                ))
                .unwrap();
            }
            conn.execute("COMMIT;").unwrap();
        }

        let start_barrier = std::sync::Arc::new(std::sync::Barrier::new(WORKERS));
        let mut handles = Vec::with_capacity(WORKERS);
        for worker_id in 0..WORKERS {
            let db = db_str.clone();
            let barrier = std::sync::Arc::clone(&start_barrier);
            handles.push(std::thread::spawn(move || -> u64 {
                let conn = Connection::open(&db).unwrap();
                conn.execute("PRAGMA busy_timeout=5000;").unwrap();
                conn.execute("PRAGMA fsqlite.concurrent_mode=ON;").unwrap();
                barrier.wait();

                let mut retries = 0_u64;
                for txn_idx in 0..TXNS_PER_WORKER {
                    let issue_idx = (worker_id * 17 + txn_idx * 7) % ISSUE_COUNT;
                    let status = match (worker_id + txn_idx) % 3 {
                        0 => "open",
                        1 => "closed",
                        _ => "tombstone",
                    };
                    let pinned = if (worker_id + txn_idx) % 5 == 0 { 1 } else { 0 };
                    let priority = i64::try_from((worker_id * 11 + txn_idx) % 5).unwrap();
                    let is_template_sql = match (worker_id + txn_idx) % 4 {
                        0 => "NULL",
                        1 => "1",
                        _ => "0",
                    };
                    let created_at = format!(
                        "2026-03-12T{:02}:{:02}:{:02}Z",
                        (worker_id * 5 + txn_idx) % 24,
                        (worker_id * 13 + txn_idx * 3) % 60,
                        (txn_idx * 7 + worker_id) % 60,
                    );
                    let updated_at = format!(
                        "2026-03-12T{:02}:{:02}:{:02}Z",
                        (worker_id * 7 + txn_idx) % 24,
                        (worker_id * 19 + txn_idx * 5) % 60,
                        (txn_idx * 11 + worker_id) % 60,
                    );
                    let content_hash =
                        format!("w{worker_id:02}-tx{txn_idx:03}-bd-{issue_idx:03}");

                    loop {
                        conn.execute("BEGIN CONCURRENT;").unwrap();
                        let update_sql = format!(
                            "UPDATE issues
                             SET content_hash = '{content_hash}',
                                 priority = {priority},
                                 created_at = '{created_at}',
                                 updated_at = '{updated_at}',
                                 status = '{status}',
                                 pinned = {pinned},
                                 is_template = {is_template_sql}
                             WHERE id = 'bd-{issue_idx:03}';"
                        );

                        match conn.execute(&update_sql) {
                            Ok(changes) => {
                                assert_eq!(changes, 1, "expected one Beads row update");
                            }
                            Err(err) if err.is_transient() => {
                                retries += 1;
                                let _ = conn.execute("ROLLBACK;");
                                continue;
                            }
                            Err(err) => {
                                panic!(
                                    "non-transient concurrent Beads update failure \
                                     (worker={worker_id} txn={txn_idx} issue=bd-{issue_idx:03}): {err}"
                                );
                            }
                        }

                        match conn.execute("COMMIT;") {
                            Ok(_) => break,
                            Err(err) if err.is_transient() => {
                                retries += 1;
                                let _ = conn.execute("ROLLBACK;");
                            }
                            Err(err) => {
                                panic!(
                                    "non-transient concurrent Beads commit failure \
                                     (worker={worker_id} txn={txn_idx} issue=bd-{issue_idx:03}): {err}"
                                );
                            }
                        }
                    }
                }

                retries
            }));
        }

        let mut total_retries = 0_u64;
        for handle in handles {
            total_retries += handle.join().expect("worker should not panic");
        }

        let sqlite = rusqlite::Connection::open(&db_path).unwrap();
        let integrity_check: String = sqlite
            .query_row("PRAGMA integrity_check;", [], |row| row.get(0))
            .unwrap();
        if integrity_check != "ok" {
            let page_count: i64 = sqlite
                .query_row("PRAGMA page_count;", [], |row| row.get(0))
                .unwrap();
            let freelist_count: i64 = sqlite
                .query_row("PRAGMA freelist_count;", [], |row| row.get(0))
                .unwrap();
            eprintln!(
                "beads churn debug: path={} page_count={} freelist_count={} integrity={integrity_check}",
                db_path.display(),
                page_count,
                freelist_count
            );

            let master_rows = sqlite
                .prepare(
                    "SELECT type, name, tbl_name, rootpage
                     FROM sqlite_master
                     ORDER BY rootpage, name",
                )
                .unwrap()
                .query_map([], |row| {
                    Ok((
                        row.get::<_, String>(0)?,
                        row.get::<_, String>(1)?,
                        row.get::<_, String>(2)?,
                        row.get::<_, i64>(3)?,
                    ))
                })
                .unwrap()
                .collect::<rusqlite::Result<Vec<_>>>()
                .unwrap();
            for (entry_type, name, table_name, rootpage) in master_rows {
                eprintln!(
                    "beads churn debug: sqlite_master type={entry_type} name={name} table={table_name} rootpage={rootpage}"
                );
            }

            match sqlite.prepare(
                "SELECT name, path, pageno, pagetype, ncell
                 FROM dbstat
                 ORDER BY pageno, name, path",
            ) {
                Ok(mut stmt) => {
                    let rows = stmt
                        .query_map([], |row| {
                            Ok((
                                row.get::<_, String>(0)?,
                                row.get::<_, String>(1)?,
                                row.get::<_, i64>(2)?,
                                row.get::<_, String>(3)?,
                                row.get::<_, i64>(4)?,
                            ))
                        })
                        .unwrap()
                        .collect::<rusqlite::Result<Vec<_>>>()
                        .unwrap();
                    for (name, path, pageno, pagetype, ncell) in rows {
                        eprintln!(
                            "beads churn debug: dbstat name={name} path={path} pageno={pageno} pagetype={pagetype} ncell={ncell}"
                        );
                    }
                }
                Err(err) => {
                    eprintln!("beads churn debug: dbstat unavailable: {err}");
                }
            }

            let fsqlite = Connection::open(&db_str).unwrap();
            let own_integrity_rows = fsqlite.query("PRAGMA integrity_check;").unwrap();
            for row in own_integrity_rows {
                if let Some(SqliteValue::Text(message)) = row.values.first() {
                    eprintln!("beads churn debug: fsqlite integrity_check={message}");
                }
            }
        }
        assert_eq!(
            integrity_check, "ok",
            "concurrent Beads-like index churn must preserve SQLite compatibility (retries={total_retries})"
        );

        let indexed_active = sqlite
            .prepare(
                "SELECT id
                 FROM issues INDEXED BY idx_issues_list_active_order
                 WHERE status NOT IN ('closed', 'tombstone')
                   AND ((is_template = 0) OR is_template IS NULL)
                   AND status = 'open'
                   AND is_template = 0
                 ORDER BY priority, created_at DESC",
            )
            .unwrap()
            .query_map([], |row| row.get::<_, String>(0))
            .unwrap()
            .collect::<rusqlite::Result<Vec<_>>>()
            .unwrap();
        let fullscan_active = sqlite
            .prepare(
                "SELECT id
                 FROM issues NOT INDEXED
                 WHERE status NOT IN ('closed', 'tombstone')
                   AND ((is_template = 0) OR is_template IS NULL)
                   AND status = 'open'
                   AND is_template = 0
                 ORDER BY priority, created_at DESC",
            )
            .unwrap()
            .query_map([], |row| row.get::<_, String>(0))
            .unwrap()
            .collect::<rusqlite::Result<Vec<_>>>()
            .unwrap();
        assert_eq!(
            indexed_active, fullscan_active,
            "forced descending partial-index scan must match full scan after concurrent churn"
        );

        let hash_rows = sqlite
            .prepare("SELECT id, content_hash FROM issues ORDER BY id")
            .unwrap()
            .query_map([], |row| {
                Ok((row.get::<_, String>(0)?, row.get::<_, String>(1)?))
            })
            .unwrap()
            .collect::<rusqlite::Result<Vec<_>>>()
            .unwrap();
        for (id, content_hash) in hash_rows {
            let indexed_ids = sqlite
                .prepare(
                    "SELECT id
                     FROM issues INDEXED BY idx_issues_content_hash
                     WHERE content_hash = ?1
                     ORDER BY id",
                )
                .unwrap()
                .query_map([content_hash.as_str()], |row| row.get::<_, String>(0))
                .unwrap()
                .collect::<rusqlite::Result<Vec<_>>>()
                .unwrap();
            let fullscan_ids = sqlite
                .prepare(
                    "SELECT id
                     FROM issues NOT INDEXED
                     WHERE content_hash = ?1
                     ORDER BY id",
                )
                .unwrap()
                .query_map([content_hash.as_str()], |row| row.get::<_, String>(0))
                .unwrap()
                .collect::<rusqlite::Result<Vec<_>>>()
                .unwrap();
            assert_eq!(
                indexed_ids, fullscan_ids,
                "forced content-hash index lookup must match full scan for {id}"
            );
            assert!(
                indexed_ids.contains(&id),
                "content-hash lookup must return its owning row for {id}"
            );
        }
    }

    #[test]
    fn test_agent_mail_message_recipient_churn_stays_sqlite_compatible() {
        const SEED_MESSAGES: usize = 192;
        const CHURN_TXNS: usize = 192;
        const AGENT_COUNT: usize = 24;
        const RECIPIENTS_PER_MESSAGE: usize = 5;

        let dir = tempfile::tempdir().unwrap();
        let db_path = dir.path().join("agent_mail_message_recipient_churn.db");
        let db_str = db_path.to_string_lossy().to_string();
        let body_pad = "payloadblock".repeat(12);

        let conn = Connection::open(&db_str).unwrap();
        conn.execute("PRAGMA busy_timeout=5000;").unwrap();
        conn.execute("PRAGMA fsqlite.concurrent_mode=ON;").unwrap();
        conn.execute(
            "CREATE TABLE projects (
                id INTEGER PRIMARY KEY,
                slug TEXT NOT NULL
            );",
        )
        .unwrap();
        conn.execute(
            "CREATE TABLE agents (
                id INTEGER PRIMARY KEY,
                project_id INTEGER NOT NULL,
                name TEXT NOT NULL,
                last_active_ts INTEGER NOT NULL DEFAULT 0
            );",
        )
        .unwrap();
        conn.execute(
            "CREATE TABLE messages (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                project_id INTEGER NOT NULL REFERENCES projects(id),
                sender_id INTEGER NOT NULL REFERENCES agents(id),
                thread_id TEXT,
                subject TEXT NOT NULL,
                body_md TEXT NOT NULL,
                importance TEXT NOT NULL DEFAULT 'normal',
                ack_required INTEGER NOT NULL DEFAULT 0,
                created_ts INTEGER NOT NULL,
                attachments TEXT NOT NULL DEFAULT '[]',
                recipients_json TEXT NOT NULL DEFAULT '{}'
            );",
        )
        .unwrap();
        conn.execute(
            "CREATE TABLE message_recipients (
                message_id INTEGER NOT NULL REFERENCES messages(id),
                agent_id INTEGER NOT NULL REFERENCES agents(id),
                kind TEXT NOT NULL DEFAULT 'to',
                read_ts INTEGER,
                ack_ts INTEGER,
                PRIMARY KEY(message_id, agent_id)
            );",
        )
        .unwrap();
        conn.execute(
            "CREATE TABLE inbox_stats (
                agent_id INTEGER PRIMARY KEY,
                total_count INTEGER NOT NULL,
                unread_count INTEGER NOT NULL,
                ack_pending_count INTEGER NOT NULL,
                last_message_ts INTEGER
            );",
        )
        .unwrap();

        conn.execute(
            "CREATE INDEX idx_messages_project_created ON messages(project_id, created_ts);",
        )
        .unwrap();
        conn.execute(
            "CREATE INDEX idx_messages_project_sender_created
             ON messages(project_id, sender_id, created_ts);",
        )
        .unwrap();
        conn.execute("CREATE INDEX idx_messages_thread_id ON messages(thread_id);")
            .unwrap();
        conn.execute("CREATE INDEX idx_messages_importance ON messages(importance);")
            .unwrap();
        conn.execute("CREATE INDEX idx_messages_created_ts ON messages(created_ts);")
            .unwrap();
        conn.execute("CREATE INDEX idx_msg_thread_created ON messages(thread_id, created_ts);")
            .unwrap();
        conn.execute(
            "CREATE INDEX idx_msg_project_importance_created
             ON messages(project_id, importance, created_ts);",
        )
        .unwrap();
        conn.execute("CREATE INDEX idx_message_recipients_agent ON message_recipients(agent_id);")
            .unwrap();
        conn.execute(
            "CREATE INDEX idx_message_recipients_agent_message
             ON message_recipients(agent_id, message_id);",
        )
        .unwrap();
        conn.execute("CREATE INDEX idx_mr_agent_ack ON message_recipients(agent_id, ack_ts);")
            .unwrap();
        conn.execute("CREATE INDEX idx_mr_ack_message ON message_recipients(ack_ts, message_id);")
            .unwrap();

        conn.execute(
            "CREATE TRIGGER trg_inbox_stats_insert
             AFTER INSERT ON message_recipients
             BEGIN
               INSERT OR IGNORE INTO inbox_stats
                 (agent_id, total_count, unread_count, ack_pending_count, last_message_ts)
               VALUES (
                 NEW.agent_id,
                 0,
                 0,
                 0,
                 (SELECT m.created_ts FROM messages m WHERE m.id = NEW.message_id)
               );
               UPDATE inbox_stats
               SET total_count = total_count + 1,
                   unread_count = unread_count + 1,
                   ack_pending_count = ack_pending_count +
                     COALESCE((SELECT m.ack_required FROM messages m WHERE m.id = NEW.message_id), 0),
                   last_message_ts = COALESCE(
                     (SELECT m.created_ts FROM messages m WHERE m.id = NEW.message_id),
                     last_message_ts
                   )
               WHERE agent_id = NEW.agent_id;
             END;",
        )
        .unwrap();

        conn.execute("BEGIN;").unwrap();
        conn.execute("INSERT INTO projects(id, slug) VALUES (1, 'project-1');")
            .unwrap();
        for agent_id in 1..=AGENT_COUNT {
            conn.execute(&format!(
                "INSERT INTO agents(id, project_id, name, last_active_ts)
                 VALUES ({agent_id}, 1, 'agent-{agent_id:02}', 1700000000);"
            ))
            .unwrap();
        }

        let mut live_message_ids = std::collections::VecDeque::new();
        let mut next_message_id = 1_i64;
        for seed_idx in 0..SEED_MESSAGES {
            let message_id = next_message_id;
            next_message_id += 1;
            live_message_ids.push_back(message_id);

            let sender_id = i64::try_from((seed_idx % AGENT_COUNT) + 1).unwrap();
            let thread_id = format!("thread-{:02}", seed_idx % 17);
            let subject = format!("seed subject {seed_idx:03}");
            let body_md = format!("seed body {seed_idx:03} {body_pad}");
            let importance = match seed_idx % 3 {
                0 => "normal",
                1 => "high",
                _ => "urgent",
            };
            let ack_required = if seed_idx % 2 == 0 { 1 } else { 0 };
            let created_ts = 1_700_000_000_i64 + i64::try_from(seed_idx).unwrap();

            conn.execute(&format!(
                "INSERT INTO messages(
                    id, project_id, sender_id, thread_id, subject, body_md,
                    importance, ack_required, created_ts, attachments, recipients_json
                 ) VALUES (
                    {message_id},
                    1,
                    {sender_id},
                    '{thread_id}',
                    '{subject}',
                    '{body_md}',
                    '{importance}',
                    {ack_required},
                    {created_ts},
                    '[]',
                    '{{}}'
                 );"
            ))
            .unwrap();

            for recipient_offset in 0..RECIPIENTS_PER_MESSAGE {
                let agent_id =
                    i64::try_from(((seed_idx + recipient_offset) % AGENT_COUNT) + 1).unwrap();
                let kind = if recipient_offset == 0 { "to" } else { "cc" };
                conn.execute(&format!(
                    "INSERT INTO message_recipients(message_id, agent_id, kind, read_ts, ack_ts)
                     VALUES ({message_id}, {agent_id}, '{kind}', NULL, NULL);"
                ))
                .unwrap();
            }
        }
        conn.execute("COMMIT;").unwrap();

        for txn_idx in 0..CHURN_TXNS {
            let delete_id = live_message_ids.pop_front().unwrap();
            let message_id = next_message_id;
            next_message_id += 1;
            live_message_ids.push_back(message_id);

            let sender_id = i64::try_from((txn_idx % AGENT_COUNT) + 1).unwrap();
            let thread_id = format!("thread-{:02}", txn_idx % 17);
            let subject = format!("churn subject {txn_idx:03}");
            let body_md = format!("churn body {txn_idx:03} {body_pad}");
            let importance = match (txn_idx + 1) % 3 {
                0 => "normal",
                1 => "high",
                _ => "urgent",
            };
            let ack_required = if txn_idx % 2 == 0 { 1 } else { 0 };
            let created_ts = 1_800_000_000_i64 + i64::try_from(txn_idx).unwrap();
            let read_agent = i64::try_from(((txn_idx * 3) % AGENT_COUNT) + 1).unwrap();
            let ack_agent = i64::try_from(((txn_idx * 3 + 1) % AGENT_COUNT) + 1).unwrap();

            conn.execute("BEGIN CONCURRENT;").unwrap();
            conn.execute(&format!(
                "DELETE FROM message_recipients WHERE message_id = {delete_id};"
            ))
            .unwrap();
            conn.execute(&format!(
                "DELETE FROM messages WHERE id = {delete_id} AND project_id = 1;"
            ))
            .unwrap();
            conn.execute("DELETE FROM inbox_stats;").unwrap();
            conn.execute(
                "INSERT INTO inbox_stats
                   (agent_id, total_count, unread_count, ack_pending_count, last_message_ts)
                 SELECT
                   r.agent_id,
                   COUNT(*) AS total_count,
                   SUM(CASE WHEN r.read_ts IS NULL THEN 1 ELSE 0 END) AS unread_count,
                   SUM(CASE WHEN m.ack_required = 1 AND r.ack_ts IS NULL THEN 1 ELSE 0 END)
                     AS ack_pending_count,
                   MAX(m.created_ts) AS last_message_ts
                 FROM message_recipients r
                 JOIN messages m ON m.id = r.message_id
                 GROUP BY r.agent_id;",
            )
            .unwrap();

            conn.execute(&format!(
                "INSERT INTO messages(
                    id, project_id, sender_id, thread_id, subject, body_md,
                    importance, ack_required, created_ts, attachments, recipients_json
                 ) VALUES (
                    {message_id},
                    1,
                    {sender_id},
                    '{thread_id}',
                    '{subject}',
                    '{body_md}',
                    '{importance}',
                    {ack_required},
                    {created_ts},
                    '[]',
                    '{{}}'
                 );"
            ))
            .unwrap();

            for recipient_offset in 0..RECIPIENTS_PER_MESSAGE {
                let agent_id =
                    i64::try_from(((txn_idx * 3 + recipient_offset) % AGENT_COUNT) + 1).unwrap();
                let kind = if recipient_offset == 0 { "to" } else { "cc" };
                conn.execute(&format!(
                    "INSERT INTO message_recipients(message_id, agent_id, kind, read_ts, ack_ts)
                     VALUES ({message_id}, {agent_id}, '{kind}', NULL, NULL);"
                ))
                .unwrap();
            }

            conn.execute(&format!(
                "UPDATE message_recipients
                 SET read_ts = {created_ts}
                 WHERE agent_id = {read_agent} AND message_id = {message_id};"
            ))
            .unwrap();
            conn.execute(&format!(
                "UPDATE message_recipients
                 SET read_ts = {created_ts}, ack_ts = {}
                 WHERE agent_id = {ack_agent} AND message_id = {message_id};",
                created_ts + 1
            ))
            .unwrap();
            conn.execute("COMMIT;").unwrap();
        }

        drop(conn);

        let sqlite = rusqlite::Connection::open(&db_path).unwrap();
        let integrity_check: String = sqlite
            .query_row("PRAGMA integrity_check;", [], |row| row.get(0))
            .unwrap();
        assert_eq!(
            integrity_check, "ok",
            "Agent Mail-style message/recipient churn must preserve SQLite compatibility"
        );

        for agent_id in 1..=i64::try_from(AGENT_COUNT).unwrap() {
            let indexed_count: i64 = sqlite
                .query_row(
                    "SELECT COUNT(*)
                     FROM message_recipients INDEXED BY idx_message_recipients_agent
                     WHERE agent_id = ?1",
                    [agent_id],
                    |row| row.get(0),
                )
                .unwrap();
            let fullscan_count: i64 = sqlite
                .query_row(
                    "SELECT COUNT(*)
                     FROM message_recipients NOT INDEXED
                     WHERE agent_id = ?1",
                    [agent_id],
                    |row| row.get(0),
                )
                .unwrap();
            assert_eq!(
                indexed_count, fullscan_count,
                "forced recipient-agent index lookup must match full scan for agent {agent_id}"
            );

            let indexed_message_ids = sqlite
                .prepare(
                    "SELECT message_id
                     FROM message_recipients INDEXED BY idx_message_recipients_agent_message
                     WHERE agent_id = ?1
                     ORDER BY message_id",
                )
                .unwrap()
                .query_map([agent_id], |row| row.get::<_, i64>(0))
                .unwrap()
                .collect::<rusqlite::Result<Vec<_>>>()
                .unwrap();
            let fullscan_message_ids = sqlite
                .prepare(
                    "SELECT message_id
                     FROM message_recipients NOT INDEXED
                     WHERE agent_id = ?1
                     ORDER BY message_id",
                )
                .unwrap()
                .query_map([agent_id], |row| row.get::<_, i64>(0))
                .unwrap()
                .collect::<rusqlite::Result<Vec<_>>>()
                .unwrap();
            assert_eq!(
                indexed_message_ids, fullscan_message_ids,
                "forced recipient agent+message index lookup must match full scan for agent {agent_id}"
            );

            let indexed_ack_pending: i64 = sqlite
                .query_row(
                    "SELECT COUNT(*)
                     FROM message_recipients INDEXED BY idx_mr_agent_ack
                     WHERE agent_id = ?1 AND ack_ts IS NULL",
                    [agent_id],
                    |row| row.get(0),
                )
                .unwrap();
            let fullscan_ack_pending: i64 = sqlite
                .query_row(
                    "SELECT COUNT(*)
                     FROM message_recipients NOT INDEXED
                     WHERE agent_id = ?1 AND ack_ts IS NULL",
                    [agent_id],
                    |row| row.get(0),
                )
                .unwrap();
            assert_eq!(
                indexed_ack_pending, fullscan_ack_pending,
                "forced recipient ack index lookup must match full scan for agent {agent_id}"
            );
        }
    }

