    #[test]
    fn test_live_vtab_autocommit_sync_failure_rolls_back_state() {
        let conn = Connection::open(":memory:").unwrap();
        conn.register_module(
            "txn_test",
            Box::new(module_factory_from::<TxnAwareTestVtab>()),
        );
        conn.execute("CREATE VIRTUAL TABLE vt USING txn_test(value);")
            .unwrap();
        with_txn_test_vtab(&conn, "vt", |vtab| vtab.fail_sync = true);

        let err = conn
            .execute("INSERT INTO vt(value) VALUES ('sync fail');")
            .expect_err("autocommit VTAB sync failure should abort the implicit transaction");
        assert!(
            err.to_string().contains("virtual table VT sync failed")
                || err.to_string().contains("virtual table vt sync failed"),
            "unexpected autocommit error: {err}",
        );
        assert!(
            !*conn.in_transaction.borrow(),
            "sync failure should abort the implicit transaction"
        );

        let rows = conn.query("SELECT rowid, value FROM vt;").unwrap();
        assert!(
            rows.is_empty(),
            "implicit transaction rollback must restore live VTAB state after sync failure"
        );

        let hook_log = with_txn_test_vtab(&conn, "vt", |vtab| vtab.hook_log.clone());
        assert!(
            hook_log.contains(&"sync".to_owned()),
            "expected sync hook before autocommit failure: {hook_log:?}"
        );
        assert!(
            hook_log.contains(&"rollback".to_owned()),
            "sync failure should roll back the live VTAB in autocommit: {hook_log:?}"
        );
        assert!(
            !hook_log.contains(&"commit".to_owned()),
            "failed autocommit must not finalize the live VTAB: {hook_log:?}"
        );
    }

    #[test]
    fn test_live_vtab_late_enlistment_uses_single_current_savepoint_catchup() {
        let conn = Connection::open(":memory:").unwrap();
        conn.register_module(
            "txn_test",
            Box::new(module_factory_from::<TxnAwareTestVtab>()),
        );
        conn.execute("CREATE VIRTUAL TABLE vt USING txn_test(value);")
            .unwrap();

        conn.execute("BEGIN;").unwrap();
        conn.execute("SAVEPOINT sp_outer;").unwrap();
        conn.execute("SAVEPOINT sp_inner;").unwrap();
        conn.execute("INSERT INTO vt(value) VALUES ('late');")
            .unwrap();
        conn.execute("ROLLBACK;").unwrap();

        let hook_log = with_txn_test_vtab(&conn, "vt", |vtab| vtab.hook_log.clone());
        let savepoints = hook_log
            .iter()
            .filter(|hook| hook.starts_with("savepoint:"))
            .cloned()
            .collect::<Vec<_>>();
        assert_eq!(
            savepoints,
            vec!["savepoint:2".to_owned()],
            "late VTAB enlistment should catch up only to the current savepoint level",
        );
    }

    #[test]
    fn test_live_vtab_sync_failure_aborts_explicit_commit() {
        let conn = Connection::open(":memory:").unwrap();
        conn.register_module(
            "txn_test",
            Box::new(module_factory_from::<TxnAwareTestVtab>()),
        );
        conn.execute("CREATE VIRTUAL TABLE vt USING txn_test(value);")
            .unwrap();

        conn.execute("BEGIN;").unwrap();
        conn.execute("INSERT INTO vt(value) VALUES ('sync fail');")
            .unwrap();
        with_txn_test_vtab(&conn, "vt", |vtab| vtab.fail_sync = true);

        let err = conn
            .execute("COMMIT;")
            .expect_err("sync failure should abort COMMIT");
        assert!(
            err.to_string().contains("virtual table VT sync failed")
                || err.to_string().contains("virtual table vt sync failed"),
            "unexpected COMMIT error: {err}",
        );
        assert!(
            !*conn.in_transaction.borrow(),
            "sync failure should abort the explicit transaction"
        );

        let rows = conn.query("SELECT rowid, value FROM vt;").unwrap();
        assert!(rows.is_empty(), "sync failure must restore live VTAB state");

        let hook_log = with_txn_test_vtab(&conn, "vt", |vtab| vtab.hook_log.clone());
        assert!(
            hook_log.contains(&"sync".to_owned()),
            "expected sync hook before COMMIT failure: {hook_log:?}"
        );
        assert!(
            hook_log.contains(&"rollback".to_owned()),
            "sync failure should roll back the live VTAB: {hook_log:?}"
        );
        assert!(
            !hook_log.contains(&"commit".to_owned()),
            "failed COMMIT must not finalize the live VTAB: {hook_log:?}"
        );
    }

    #[test]
    fn test_live_vtab_drop_rollback_restores_instance() {
        let conn = Connection::open(":memory:").unwrap();
        conn.register_module(
            "txn_test",
            Box::new(module_factory_from::<TxnAwareTestVtab>()),
        );
        conn.execute("CREATE VIRTUAL TABLE vt USING txn_test(value);")
            .unwrap();
        conn.execute("INSERT INTO vt(value) VALUES ('keep');")
            .unwrap();

        conn.execute("BEGIN;").unwrap();
        conn.execute("DROP TABLE vt;").unwrap();
        assert!(
            !conn.vtab_instances.borrow().contains_key("VT"),
            "DROP TABLE should hide the live VTAB immediately"
        );
        assert!(
            conn.dropped_vtab_instances.borrow().contains_key("VT"),
            "DROP TABLE inside a transaction should stage the live VTAB for commit/rollback"
        );
        conn.execute("ROLLBACK;").unwrap();

        assert!(
            conn.vtab_instances.borrow().contains_key("VT"),
            "ROLLBACK must restore the dropped live VTAB instance"
        );
        assert!(
            conn.dropped_vtab_instances.borrow().is_empty(),
            "ROLLBACK must clear staged dropped VTAB instances"
        );
        let rows = conn
            .query("SELECT rowid, value FROM vt ORDER BY rowid;")
            .unwrap();
        assert_eq!(
            rows.iter().map(row_values).collect::<Vec<_>>(),
            vec![vec![
                SqliteValue::Integer(1),
                SqliteValue::Text("keep".into()),
            ]],
            "ROLLBACK must restore the dropped VTAB contents"
        );
    }

    #[test]
    fn test_live_vtab_drop_savepoint_rollback_restores_instance() {
        let conn = Connection::open(":memory:").unwrap();
        conn.register_module(
            "txn_test",
            Box::new(module_factory_from::<TxnAwareTestVtab>()),
        );
        conn.execute("CREATE VIRTUAL TABLE vt USING txn_test(value);")
            .unwrap();
        conn.execute("INSERT INTO vt(value) VALUES ('keep');")
            .unwrap();

        conn.execute("BEGIN;").unwrap();
        conn.execute("SAVEPOINT sp_drop;").unwrap();
        conn.execute("DROP TABLE vt;").unwrap();
        assert!(
            !conn.vtab_instances.borrow().contains_key("VT"),
            "DROP TABLE inside savepoint should hide the live VTAB immediately"
        );
        assert!(
            conn.dropped_vtab_instances.borrow().contains_key("VT"),
            "DROP TABLE inside savepoint should stage the live VTAB for restore/finalize"
        );

        conn.execute("ROLLBACK TO sp_drop;").unwrap();
        conn.execute("RELEASE SAVEPOINT sp_drop;").unwrap();
        conn.execute("COMMIT;").unwrap();

        assert!(
            conn.vtab_instances.borrow().contains_key("VT"),
            "ROLLBACK TO SAVEPOINT must restore a dropped live VTAB instance"
        );
        assert!(
            conn.dropped_vtab_instances.borrow().is_empty(),
            "ROLLBACK TO SAVEPOINT must clear the staged dropped VTAB"
        );
        let rows = conn
            .query("SELECT rowid, value FROM vt ORDER BY rowid;")
            .unwrap();
        assert_eq!(
            rows.iter().map(row_values).collect::<Vec<_>>(),
            vec![vec![
                SqliteValue::Integer(1),
                SqliteValue::Text("keep".into()),
            ]],
            "ROLLBACK TO SAVEPOINT must restore the dropped VTAB contents"
        );
    }

