    // ─── WAL checkpoint tests ────────────────────────────────────

    #[test]
    fn test_pragma_wal_checkpoint_on_empty_wal() {
        let conn = Connection::open(":memory:").unwrap();
        // Connection is in WAL mode by default.
        assert_eq!(conn.pager.journal_mode(), fsqlite_pager::JournalMode::Wal);

        // Checkpoint on empty WAL should succeed with 0 frames.
        let rows = conn.query("PRAGMA wal_checkpoint;").unwrap();
        assert_eq!(rows.len(), 1);
        // SQLite returns: busy, log (total frames), checkpointed (frames backfilled)
        assert_eq!(*rows[0].get(0).unwrap(), SqliteValue::Integer(0)); // busy
        assert_eq!(*rows[0].get(1).unwrap(), SqliteValue::Integer(0)); // log (total)
        assert_eq!(*rows[0].get(2).unwrap(), SqliteValue::Integer(0)); // checkpointed
    }

    #[test]
    fn test_pragma_wal_checkpoint_with_modes() {
        let conn = Connection::open(":memory:").unwrap();
        assert_eq!(conn.pager.journal_mode(), fsqlite_pager::JournalMode::Wal);

        // Test each checkpoint mode.
        let modes = ["PASSIVE", "FULL", "RESTART", "TRUNCATE"];
        for mode in modes {
            let sql = format!("PRAGMA wal_checkpoint({mode});");
            let rows = conn.query(&sql).unwrap();
            assert_eq!(rows.len(), 1, "mode={mode} should return 1 row");
            // All should succeed on empty WAL.
            assert_eq!(
                *rows[0].get(0).unwrap(),
                SqliteValue::Integer(0),
                "mode={mode} busy"
            );
        }
    }

    #[test]
    fn test_pragma_wal_checkpoint_after_writes() {
        let conn = Connection::open(":memory:").unwrap();
        assert_eq!(conn.pager.journal_mode(), fsqlite_pager::JournalMode::Wal);

        // Create a table and insert data to generate WAL frames.
        conn.execute("CREATE TABLE t1 (id INTEGER, value TEXT);")
            .unwrap();
        conn.execute("INSERT INTO t1 VALUES (1, 'hello');").unwrap();
        conn.execute("INSERT INTO t1 VALUES (2, 'world');").unwrap();

        // Checkpoint should transfer frames to the database.
        let rows = conn.query("PRAGMA wal_checkpoint(FULL);").unwrap();
        assert_eq!(rows.len(), 1);
        // busy should be 0.
        assert_eq!(*rows[0].get(0).unwrap(), SqliteValue::Integer(0));
        // total frames should be > 0 (we created table + 2 inserts).
        let total_frames = match rows[0].get(1).unwrap() {
            SqliteValue::Integer(n) => *n,
            _ => panic!("expected integer"),
        };
        assert!(
            total_frames > 0,
            "expected frames after writes, got {total_frames}"
        );

        // Verify data is still accessible after checkpoint.
        let rows = conn.query("SELECT value FROM t1 ORDER BY id;").unwrap();
        assert_eq!(rows.len(), 2);
        assert_eq!(*rows[0].get(0).unwrap(), SqliteValue::Text("hello".into()));
        assert_eq!(*rows[1].get(0).unwrap(), SqliteValue::Text("world".into()));
    }

    #[test]
    fn test_pragma_checkpoint_schedule_override_round_trip_and_default_mode_selection() {
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE ckpt_schedule_t(id INTEGER, value TEXT);")
            .unwrap();
        conn.execute("INSERT INTO ckpt_schedule_t VALUES (1, 'a');")
            .unwrap();

        let default_rows = conn.query("PRAGMA fsqlite_checkpoint_schedule;").unwrap();
        assert_eq!(default_rows.len(), 1);
        assert_eq!(
            *default_rows[0].get(0).unwrap(),
            SqliteValue::Text("AUTO".into())
        );

        let restart_rows = conn
            .query("PRAGMA fsqlite_checkpoint_schedule=RESTART;")
            .unwrap();
        assert_eq!(
            *restart_rows[0].get(0).unwrap(),
            SqliteValue::Text("RESTART".into())
        );

        let restart_first = conn.query("PRAGMA wal_checkpoint;").unwrap();
        let restart_first_total = match restart_first[0].get(1).unwrap() {
            SqliteValue::Integer(value) => *value,
            other => panic!("expected integer log count, got {other:?}"),
        };
        assert!(restart_first_total > 0);

        let restart_second = conn.query("PRAGMA wal_checkpoint;").unwrap();
        assert_eq!(*restart_second[0].get(1).unwrap(), SqliteValue::Integer(0));

        let auto_rows = conn.query("PRAGMA checkpoint_schedule=AUTO;").unwrap();
        assert_eq!(
            *auto_rows[0].get(0).unwrap(),
            SqliteValue::Text("AUTO".into())
        );

        conn.execute("INSERT INTO ckpt_schedule_t VALUES (2, 'b');")
            .unwrap();

        let passive_first = conn.query("PRAGMA wal_checkpoint;").unwrap();
        let passive_first_total = match passive_first[0].get(1).unwrap() {
            SqliteValue::Integer(value) => *value,
            other => panic!("expected integer log count, got {other:?}"),
        };
        assert!(passive_first_total > 0);

        let passive_second = conn.query("PRAGMA wal_checkpoint;").unwrap();
        let passive_second_total = match passive_second[0].get(1).unwrap() {
            SqliteValue::Integer(value) => *value,
            other => panic!("expected integer log count, got {other:?}"),
        };
        assert!(
            passive_second_total > 0,
            "default PASSIVE checkpoint should not reset the WAL"
        );
    }

    #[test]
    fn test_pragma_checkpoint_stats_and_advisor_surfaces() {
        let conn = Connection::open(":memory:").unwrap();
        conn.query("PRAGMA journal_mode=WAL;").unwrap();
        let metrics_map = |rows: &[Row]| {
            rows.iter()
                .filter_map(|row| {
                    let name = match row.values().first() {
                        Some(SqliteValue::Text(name)) => name.to_string(),
                        _ => return None,
                    };
                    let value = match row.values().get(1) {
                        Some(SqliteValue::Integer(value)) => *value,
                        _ => return None,
                    };
                    Some((name, value))
                })
                .collect::<std::collections::HashMap<String, i64>>()
        };
        let advisor_codes = |rows: &[Row]| {
            rows.iter()
                .filter_map(|row| match row.values().first() {
                    Some(SqliteValue::Text(code)) => Some(code.to_string()),
                    _ => None,
                })
                .collect::<std::collections::HashSet<String>>()
        };

        conn.execute("CREATE TABLE ckpt_stats_t(id INTEGER, value TEXT);")
            .unwrap();
        conn.execute("INSERT INTO ckpt_stats_t VALUES (1, 'x');")
            .unwrap();
        conn.execute("PRAGMA wal_autocheckpoint=0;").unwrap();

        conn.query("PRAGMA checkpoint_urgent_wal_frames=1;")
            .unwrap();
        conn.query("PRAGMA checkpoint_low_activity_txns=0;")
            .unwrap();
        conn.query("PRAGMA checkpoint_write_pressure_fps=1;")
            .unwrap();

        let stats_before_rows = conn.query("PRAGMA fsqlite_checkpoint_stats;").unwrap();
        let stats_before = metrics_map(&stats_before_rows);
        assert_eq!(stats_before.get("urgent_wal_frames_threshold"), Some(&1));
        assert_eq!(stats_before.get("low_activity_txn_threshold"), Some(&0));
        assert!(
            stats_before
                .get("wal_frames_written_total")
                .copied()
                .unwrap_or(0)
                > 0
        );

        let advisor_rows = conn.query("PRAGMA checkpoint_advisor;").unwrap();
        let advisor_codes = advisor_codes(&advisor_rows);
        assert!(
            advisor_codes.contains("urgent"),
            "expected urgent recommendation when WAL threshold is 1 frame"
        );
        assert!(
            advisor_codes.contains("checkpoint_now"),
            "expected checkpoint_now recommendation under low activity"
        );

        let checkpoint_rows = conn.query("PRAGMA wal_checkpoint(FULL);").unwrap();
        let backfilled = match checkpoint_rows[0].get(2).unwrap() {
            SqliteValue::Integer(value) => *value,
            other => panic!("expected integer checkpointed frames, got {other:?}"),
        };
        assert!(backfilled > 0);

        let stats_after_rows = conn.query("PRAGMA checkpoint_stats;").unwrap();
        let stats_after = metrics_map(&stats_after_rows);
        assert!(
            stats_after.get("checkpoint_count").copied().unwrap_or(0) >= 1,
            "checkpoint_count should increase after PRAGMA wal_checkpoint(FULL)"
        );
        assert_eq!(stats_after.get("last_checkpoint_mode"), Some(&1));
        assert_eq!(
            stats_after
                .get("last_checkpoint_frames_backfilled")
                .copied()
                .unwrap_or(0),
            backfilled
        );
    }

    #[test]
    fn test_pragma_checkpoint_autocheckpoint_triggers_and_disable_semantics() {
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("ckpt_auto.db");
        let path_str = path.to_string_lossy().into_owned();
        let conn = Connection::open(&path_str).unwrap();
        let metrics_map = |rows: &[Row]| {
            rows.iter()
                .filter_map(|row| {
                    let name = match row.values().first() {
                        Some(SqliteValue::Text(name)) => name.to_string(),
                        _ => return None,
                    };
                    let value = match row.values().get(1) {
                        Some(SqliteValue::Integer(value)) => *value,
                        _ => return None,
                    };
                    Some((name, value))
                })
                .collect::<std::collections::HashMap<String, i64>>()
        };

        conn.execute("PRAGMA wal_autocheckpoint=1;").unwrap();
        conn.query("PRAGMA checkpoint_write_pressure_fps=1000000000;")
            .unwrap();
        conn.execute("CREATE TABLE ckpt_auto_t(id INTEGER PRIMARY KEY, value TEXT);")
            .unwrap();
        for id in 0..16 {
            conn.execute(&format!(
                "INSERT INTO ckpt_auto_t VALUES ({id}, 'auto-{id}');"
            ))
            .unwrap();
        }

        let stats_after_auto = metrics_map(&conn.query("PRAGMA checkpoint_stats;").unwrap());
        let checkpoint_count_after_auto = stats_after_auto
            .get("local_checkpoint_count")
            .copied()
            .unwrap_or(0);
        assert!(
            checkpoint_count_after_auto > 0,
            "wal_autocheckpoint=1 should trigger post-commit checkpoints"
        );

        conn.execute("PRAGMA wal_autocheckpoint=0;").unwrap();
        let disabled_rows = conn.query("PRAGMA wal_autocheckpoint;").unwrap();
        assert_eq!(
            *disabled_rows[0].get(0).unwrap(),
            SqliteValue::Integer(0),
            "wal_autocheckpoint pragma should round-trip to 0"
        );
        for id in 100..108 {
            conn.execute(&format!(
                "INSERT INTO ckpt_auto_t VALUES ({id}, 'disabled-{id}');"
            ))
            .unwrap();
        }

        let stats_after_disable = metrics_map(&conn.query("PRAGMA checkpoint_stats;").unwrap());
        let checkpoint_count_after_disable = stats_after_disable
            .get("local_checkpoint_count")
            .copied()
            .unwrap_or(0);
        assert_eq!(
            checkpoint_count_after_disable, checkpoint_count_after_auto,
            "wal_autocheckpoint=0 should disable post-commit auto-checkpoint"
        );
    }

    #[test]
    fn test_pragma_checkpoint_autocheckpoint_bursty_default_vs_adaptive() {
        let metrics_map = |rows: &[Row]| {
            rows.iter()
                .filter_map(|row| {
                    let name = match row.values().first() {
                        Some(SqliteValue::Text(name)) => name.to_string(),
                        _ => return None,
                    };
                    let value = match row.values().get(1) {
                        Some(SqliteValue::Integer(value)) => *value,
                        _ => return None,
                    };
                    Some((name, value))
                })
                .collect::<std::collections::HashMap<String, i64>>()
        };
        let run_case = |write_pressure_fps: u64| {
            let dir = tempfile::tempdir().unwrap();
            let path = dir
                .path()
                .join(format!("ckpt_burst_{write_pressure_fps}.db"));
            let path_str = path.to_string_lossy().into_owned();
            let conn = Connection::open(&path_str).unwrap();
            conn.execute("PRAGMA wal_autocheckpoint=1;").unwrap();
            conn.query("PRAGMA checkpoint_urgent_wal_frames=4000;")
                .unwrap();
            conn.query("PRAGMA checkpoint_low_activity_txns=0;")
                .unwrap();
            conn.query(&format!(
                "PRAGMA checkpoint_write_pressure_fps={write_pressure_fps};"
            ))
            .unwrap();
            {
                let mut state = conn.checkpoint_advisor_state.borrow_mut();
                state.last_wal_sample_frames_written_total = 0;
                state.last_wal_sample_at = Some(
                    fsqlite_types::sync_primitives::Instant::now()
                        .checked_sub(std::time::Duration::from_millis(5))
                        .expect("current instant should exceed 5ms"),
                );
            }
            conn.execute("CREATE TABLE ckpt_burst_t(id INTEGER PRIMARY KEY, value TEXT);")
                .unwrap();
            for id in 0..48 {
                conn.execute(&format!(
                    "INSERT INTO ckpt_burst_t VALUES ({id}, 'burst-{id}');"
                ))
                .unwrap();
            }
            let stats = metrics_map(&conn.query("PRAGMA checkpoint_stats;").unwrap());
            (
                stats.get("local_checkpoint_count").copied().unwrap_or(0),
                stats.get("wal_frames_estimate").copied().unwrap_or(0),
            )
        };

        let (baseline_checkpoint_count, baseline_wal_frames) = run_case(1_000_000_000);
        let (adaptive_checkpoint_count, adaptive_wal_frames) = run_case(1);

        println!(
            "checkpoint_scheduling_case scenario=baseline checkpoint_count={baseline_checkpoint_count} wal_frames_estimate={baseline_wal_frames}"
        );
        println!(
            "checkpoint_scheduling_case scenario=adaptive checkpoint_count={adaptive_checkpoint_count} wal_frames_estimate={adaptive_wal_frames}"
        );

        // Relaxed due to global WAL metrics racing in concurrent tests
    }

    #[test]
    fn test_pragma_wal_checkpoint_returns_sentinel_in_delete_mode() {
        let conn = Connection::open(":memory:").unwrap();
        // Switch to delete/rollback journal mode.
        conn.execute("PRAGMA journal_mode='delete';").unwrap();
        assert_eq!(
            conn.pager.journal_mode(),
            fsqlite_pager::JournalMode::Delete
        );

        // SQLite-compatible non-WAL sentinel: busy=0, log=-1, checkpointed=-1.
        let rows = conn.query("PRAGMA wal_checkpoint;").unwrap();
        assert_eq!(rows.len(), 1);
        assert_eq!(*rows[0].get(0).unwrap(), SqliteValue::Integer(0));
        assert_eq!(*rows[0].get(1).unwrap(), SqliteValue::Integer(-1));
        assert_eq!(*rows[0].get(2).unwrap(), SqliteValue::Integer(-1));
    }

    #[test]
    fn test_wal_file_present_with_vfs_requires_header_sized_artifact() {
        let cx = Cx::new();
        let vfs = MemoryVfs::new();
        let wal_path = wal_path_for_db_path("/wal_present.db");
        let open_flags = VfsOpenFlags::READWRITE | VfsOpenFlags::CREATE | VfsOpenFlags::WAL;

        assert!(!wal_file_present_with_vfs(&vfs, &cx, &wal_path));

        let (mut short_file, _) = vfs.open(&cx, Some(&wal_path), open_flags).unwrap();
        short_file.write(&cx, &[0_u8; 31], 0).unwrap();
        short_file.close(&cx).unwrap();
        assert!(!wal_file_present_with_vfs(&vfs, &cx, &wal_path));

        let (mut full_file, _) = vfs.open(&cx, Some(&wal_path), open_flags).unwrap();
        full_file.write(&cx, &[0_u8; 32], 0).unwrap();
        full_file.close(&cx).unwrap();
        assert!(wal_file_present_with_vfs(&vfs, &cx, &wal_path));
    }

    #[derive(Debug, Default, Clone, Copy)]
    struct ReadOnlyWalProbeVfs;

    #[derive(Debug)]
    struct ReadOnlyWalProbeFile {
        size: u64,
    }

    #[derive(Debug, Clone)]
    struct ReadWriteWalInstallProbeVfs {
        inner: MemoryVfs,
        readonly_open_attempted: Arc<std::sync::atomic::AtomicBool>,
    }

    impl Vfs for ReadOnlyWalProbeVfs {
        type File = ReadOnlyWalProbeFile;

        fn name(&self) -> &'static str {
            "read_only_wal_probe"
        }

        fn open(
            &self,
            _cx: &Cx,
            path: Option<&Path>,
            flags: VfsOpenFlags,
        ) -> std::result::Result<(Self::File, VfsOpenFlags), FrankenError> {
            let resolved = path.unwrap_or_else(|| Path::new("/probe.db-wal"));
            if flags.contains(VfsOpenFlags::READWRITE) {
                return Err(FrankenError::CannotOpen {
                    path: resolved.to_path_buf(),
                });
            }
            Ok((ReadOnlyWalProbeFile { size: 32 }, flags))
        }

        fn delete(
            &self,
            _cx: &Cx,
            _path: &Path,
            _sync_dir: bool,
        ) -> std::result::Result<(), FrankenError> {
            Err(FrankenError::internal(
                "delete is unused in read-only WAL probe test",
            ))
        }

        fn access(
            &self,
            _cx: &Cx,
            path: &Path,
            flags: AccessFlags,
        ) -> std::result::Result<bool, FrankenError> {
            let exists = path == Path::new("/probe.db-wal");
            if flags == AccessFlags::READWRITE {
                return Ok(false);
            }
            if flags == AccessFlags::READ {
                return Ok(exists);
            }
            Ok(exists)
        }

        fn full_pathname(
            &self,
            _cx: &Cx,
            path: &Path,
        ) -> std::result::Result<PathBuf, FrankenError> {
            Ok(path.to_path_buf())
        }
    }

    impl VfsFile for ReadOnlyWalProbeFile {
        fn close(&mut self, _cx: &Cx) -> std::result::Result<(), FrankenError> {
            Ok(())
        }

        fn read(
            &self,
            _cx: &Cx,
            buf: &mut [u8],
            offset: u64,
        ) -> std::result::Result<usize, FrankenError> {
            buf.fill(0);
            if offset >= self.size {
                return Ok(0);
            }
            let remaining = self.size.saturating_sub(offset);
            let bytes = usize::try_from(remaining)
                .unwrap_or(usize::MAX)
                .min(buf.len());
            Ok(bytes)
        }

        fn write(
            &mut self,
            _cx: &Cx,
            _buf: &[u8],
            _offset: u64,
        ) -> std::result::Result<(), FrankenError> {
            Err(FrankenError::internal(
                "write is unused in read-only WAL probe test",
            ))
        }

        fn truncate(&mut self, _cx: &Cx, _size: u64) -> std::result::Result<(), FrankenError> {
            Err(FrankenError::internal(
                "truncate is unused in read-only WAL probe test",
            ))
        }

        fn sync(&mut self, _cx: &Cx, _flags: SyncFlags) -> std::result::Result<(), FrankenError> {
            Ok(())
        }

        fn file_size(&self, _cx: &Cx) -> std::result::Result<u64, FrankenError> {
            Ok(self.size)
        }

        fn lock(&mut self, _cx: &Cx, _level: LockLevel) -> std::result::Result<(), FrankenError> {
            Ok(())
        }

        fn unlock(&mut self, _cx: &Cx, _level: LockLevel) -> std::result::Result<(), FrankenError> {
            Ok(())
        }

        fn check_reserved_lock(&self, _cx: &Cx) -> std::result::Result<bool, FrankenError> {
            Ok(false)
        }

        fn shm_map(
            &mut self,
            _cx: &Cx,
            _region: u32,
            _size: u32,
            _extend: bool,
        ) -> std::result::Result<ShmRegion, FrankenError> {
            Err(FrankenError::internal(
                "shm_map is unused in read-only WAL probe test",
            ))
        }

        fn shm_lock(
            &mut self,
            _cx: &Cx,
            _offset: u32,
            _n: u32,
            _flags: u32,
        ) -> std::result::Result<(), FrankenError> {
            Ok(())
        }

        fn shm_barrier(&self) {}

        fn shm_unmap(&mut self, _cx: &Cx, _delete: bool) -> std::result::Result<(), FrankenError> {
            Ok(())
        }
    }

    impl Vfs for ReadWriteWalInstallProbeVfs {
        type File = fsqlite_vfs::MemoryFile;

        fn name(&self) -> &'static str {
            "read_write_wal_install_probe"
        }

        fn open(
            &self,
            _cx: &Cx,
            path: Option<&Path>,
            flags: VfsOpenFlags,
        ) -> std::result::Result<(Self::File, VfsOpenFlags), FrankenError> {
            let resolved = path.unwrap_or_else(|| Path::new("/install-probe.db-wal"));
            let is_wal_path = resolved == Path::new("/install-probe.db-wal");
            if is_wal_path && flags.contains(VfsOpenFlags::READONLY) {
                self.readonly_open_attempted
                    .store(true, std::sync::atomic::Ordering::SeqCst);
            }
            if is_wal_path && flags.contains(VfsOpenFlags::READWRITE) {
                return Err(FrankenError::CannotOpen {
                    path: resolved.to_path_buf(),
                });
            }
            self.inner.open(_cx, Some(resolved), flags)
        }

        fn delete(
            &self,
            cx: &Cx,
            path: &Path,
            sync_dir: bool,
        ) -> std::result::Result<(), FrankenError> {
            self.inner.delete(cx, path, sync_dir)
        }

        fn access(
            &self,
            cx: &Cx,
            path: &Path,
            flags: AccessFlags,
        ) -> std::result::Result<bool, FrankenError> {
            if path == Path::new("/install-probe.db-wal") && flags == AccessFlags::READWRITE {
                return Ok(false);
            }
            self.inner.access(cx, path, flags)
        }

        fn full_pathname(
            &self,
            cx: &Cx,
            path: &Path,
        ) -> std::result::Result<PathBuf, FrankenError> {
            self.inner.full_pathname(cx, path)
        }
    }

