        // succeed without issue (no regression to serialized-only).
        conn.execute("INSERT INTO ratchet_auto VALUES (1, 42);")
            .unwrap();
        let rows = conn
            .query("SELECT val FROM ratchet_auto WHERE id = 1;")
            .unwrap();
