    // ── Parse cache regression tests (br-legjy.7.3) ────────────────────

    #[test]
    fn test_parse_cache_repeated_select_returns_same_results() {
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE pc (id INTEGER PRIMARY KEY, val TEXT);")
            .unwrap();
        conn.execute("INSERT INTO pc VALUES (1, 'a'), (2, 'b'), (3, 'c');")
            .unwrap();

        let sql = "SELECT val FROM pc WHERE id = ?1";
        let params = [SqliteValue::Integer(2)];

        // First call: populates cache.
        let rows1 = conn.query_with_params(sql, &params).unwrap();
        // Second call: should use cached parse.
        let rows2 = conn.query_with_params(sql, &params).unwrap();

        assert_eq!(rows1.len(), 1);
        assert_eq!(rows2.len(), 1);
        assert_eq!(rows1[0].values(), rows2[0].values());
        assert_eq!(rows1[0].values()[0], SqliteValue::Text("b".into()));
    }

    #[test]
    fn test_parse_cache_execute_uses_single_statement_fast_path() {
        let conn = Connection::open(":memory:").unwrap();
        let cached_sql = "THIS IS DEFINITELY NOT VALID SQL";
        let key = Connection::sql_hash(cached_sql);
        let statement = parse_single_statement("SELECT 1;").unwrap();
        let cookie = *conn.schema_cookie.borrow();
        *conn.parse_cache_cookie.borrow_mut() = cookie;
        conn.parse_cache.borrow_mut().put(
            key,
            std::sync::Arc::new(ParseCacheEntry {
                sql: cached_sql.to_owned(),
                statement: Arc::new(statement),
            }),
        );

        // If execute() reparses first, this call fails with a parse error.
        // The fast path should return from cache and execute successfully.
        let count = conn.execute(cached_sql).unwrap();
        assert_eq!(count, 1);
    }

    #[test]
    fn test_parse_cache_invalidated_by_ddl() {
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE pc2 (id INTEGER PRIMARY KEY, x TEXT);")
            .unwrap();
        conn.execute("INSERT INTO pc2 VALUES (1, 'before');")
            .unwrap();

        // Populate cache.
        let rows = conn.query("SELECT x FROM pc2 WHERE id = 1").unwrap();
        assert_eq!(rows[0].values()[0], SqliteValue::Text("before".into()));

        // DDL invalidates cache (schema cookie increment).
        conn.execute("ALTER TABLE pc2 ADD COLUMN y TEXT DEFAULT 'new';")
            .unwrap();

        // After DDL, re-parsed query must still work.
        let rows = conn.query("SELECT x FROM pc2 WHERE id = 1").unwrap();
        assert_eq!(rows[0].values()[0], SqliteValue::Text("before".into()));
    }

    #[test]
    fn test_table_execution_metadata_cache_invalidated_by_ddl() {
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE cache_meta (id INTEGER PRIMARY KEY, value TEXT);")
            .unwrap();

        let first = conn.table_execution_metadata();
        let second = conn.table_execution_metadata();
        assert!(std::sync::Arc::ptr_eq(&first, &second));
        assert_eq!(
            first
                .rowid_alias_col_by_root_page
                .values()
                .copied()
                .collect::<Vec<_>>(),
            vec![0]
        );

        conn.execute("CREATE INDEX idx_cache_meta_value ON cache_meta (value DESC);")
            .unwrap();

        let third = conn.table_execution_metadata();
        assert!(!std::sync::Arc::ptr_eq(&first, &third));
        assert_eq!(third.index_desc_flags_by_root_page.len(), 1);
        assert_eq!(
            third
                .index_desc_flags_by_root_page
                .values()
                .next()
                .expect("index metadata missing"),
            &vec![true]
        );
    }

    #[test]
    fn test_table_execution_metadata_cache_keeps_autoincrement_values_live() {
        let conn = Connection::open(":memory:").unwrap();
        conn.execute(
            "CREATE TABLE cache_auto (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                value TEXT
            );",
        )
        .unwrap();

        let cached = conn.table_execution_metadata();
        let cached_again = conn.table_execution_metadata();
        assert!(std::sync::Arc::ptr_eq(&cached, &cached_again));
        assert_eq!(
            conn.autoincrement_sequence_by_root_page()
                .values()
                .copied()
                .collect::<Vec<_>>(),
            vec![0]
        );

        conn.execute("INSERT INTO cache_auto (value) VALUES ('first');")
            .unwrap();

        let cached_after_dml = conn.table_execution_metadata();
        assert!(std::sync::Arc::ptr_eq(&cached, &cached_after_dml));
        assert_eq!(
            conn.autoincrement_sequence_by_root_page()
                .values()
                .copied()
                .collect::<Vec<_>>(),
            vec![1]
        );
    }

    #[test]
    fn test_parse_cache_execute_with_params_repeated_dml() {
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE pc3 (id INTEGER PRIMARY KEY, n INTEGER);")
            .unwrap();

        let sql = "INSERT INTO pc3 VALUES (?1, ?2)";
        // Insert using same SQL (cached parse).
        conn.execute_with_params(sql, &[SqliteValue::Integer(1), SqliteValue::Integer(10)])
            .unwrap();
        conn.execute_with_params(sql, &[SqliteValue::Integer(2), SqliteValue::Integer(20)])
            .unwrap();
        conn.execute_with_params(sql, &[SqliteValue::Integer(3), SqliteValue::Integer(30)])
            .unwrap();

        let rows = conn.query("SELECT n FROM pc3 ORDER BY id").unwrap();
        assert_eq!(rows.len(), 3);
        assert_eq!(rows[0].values()[0], SqliteValue::Integer(10));
        assert_eq!(rows[1].values()[0], SqliteValue::Integer(20));
        assert_eq!(rows[2].values()[0], SqliteValue::Integer(30));
    }

    // ── Prepared DML tests (GH-11) ────────────────────────────────────

    #[test]
    fn test_prepare_insert_with_params() {
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE prep_dml (id TEXT PRIMARY KEY, name TEXT);")
            .unwrap();

        let stmt = conn
            .prepare("INSERT INTO prep_dml (id, name) VALUES (?1, ?2)")
            .unwrap();
        assert!(stmt.is_dml());
        assert!(matches!(
            stmt.dml_dispatch.as_ref(),
            Some(PreparedDmlDispatch::Precompiled(PreparedPrecompiledDml {
                kind: PreparedDmlKind::Insert,
                ..
            }))
        ));

        conn.execute_prepared_with_params(
            &stmt,
            &[
                SqliteValue::Text("a".into()),
                SqliteValue::Text("Alice".into()),
            ],
        )
        .unwrap();
        conn.execute_prepared_with_params(
            &stmt,
            &[
                SqliteValue::Text("b".into()),
                SqliteValue::Text("Bob".into()),
            ],
        )
        .unwrap();

        let rows = conn.query("SELECT name FROM prep_dml ORDER BY id").unwrap();
        assert_eq!(rows.len(), 2);
        assert_eq!(rows[0].values()[0], SqliteValue::Text("Alice".into()));
        assert_eq!(rows[1].values()[0], SqliteValue::Text("Bob".into()));
    }

    #[test]
    fn test_prepared_insert_precomputes_post_write_action() {
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE prep_plain (id INTEGER PRIMARY KEY, name TEXT);")
            .unwrap();
        conn.execute("CREATE TABLE prep_ai (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT);")
            .unwrap();

        let plain_stmt = conn
            .prepare("INSERT INTO prep_plain (id, name) VALUES (?1, ?2)")
            .unwrap();
        let ai_stmt = conn
            .prepare("INSERT INTO prep_ai (name) VALUES (?1)")
            .unwrap();

        assert!(matches!(
            plain_stmt.dml_dispatch.as_ref(),
            Some(PreparedDmlDispatch::Precompiled(PreparedPrecompiledDml {
                kind: PreparedDmlKind::Insert,
                post_write_action: PreparedInsertPostWriteAction::None,
                ..
            }))
        ));
        assert!(matches!(
            ai_stmt.dml_dispatch.as_ref(),
            Some(PreparedDmlDispatch::Precompiled(PreparedPrecompiledDml {
                kind: PreparedDmlKind::Insert,
                post_write_action: PreparedInsertPostWriteAction::RefreshAutoincrementSequence,
                ..
            }))
        ));
    }

    #[test]
    fn test_prepare_update_with_params() {
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE prep_upd (id INTEGER PRIMARY KEY, val TEXT);")
            .unwrap();
        conn.execute("INSERT INTO prep_upd VALUES (1, 'old');")
            .unwrap();

        let stmt = conn
            .prepare("UPDATE prep_upd SET val = ?1 WHERE id = ?2")
            .unwrap();
        assert!(stmt.is_dml());
        assert!(matches!(
            stmt.dml_dispatch.as_ref(),
            Some(PreparedDmlDispatch::Deferred(_))
        ));
        assert!(
            stmt.prepared_update_delete_fast_path.is_some(),
            "simple UPDATE should cache fast-path metadata at prepare time"
        );
        assert!(
            stmt.db.is_some(),
            "simple UPDATE should compile to a reusable program"
        );
        assert!(
            stmt.dispatch_precompiled_program().is_some(),
            "simple UPDATE should reuse the prepared program at execution time"
        );

        let affected = conn
            .execute_prepared_with_params(
                &stmt,
                &[SqliteValue::Text("new".into()), SqliteValue::Integer(1)],
            )
            .unwrap();
        assert_eq!(affected, 1);

        let rows = conn.query("SELECT val FROM prep_upd WHERE id = 1").unwrap();
        assert_eq!(rows[0].values()[0], SqliteValue::Text("new".into()));
    }

