    // ── bd-1dp9.6.7.2.1: Prepared INSERT reuse tests ────────────────────

    #[test]
    fn test_prepared_insert_reuse_multiple_executions() {
        // Verify that a single prepared INSERT can be executed multiple times
        // with different parameters, reusing the pre-compiled VdbeProgram.
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE prep_reuse (id INTEGER PRIMARY KEY, name TEXT);")
            .unwrap();

        let stmt = conn
            .prepare("INSERT INTO prep_reuse (id, name) VALUES (?1, ?2)")
            .unwrap();

        // The stmt should have db set (pre-compiled, not placeholder).
        assert!(
            stmt.db.is_some(),
            "simple VALUES INSERT should be pre-compiled with db set"
        );
        assert!(matches!(
            stmt.dml_dispatch.as_ref(),
            Some(PreparedDmlDispatch::Precompiled(PreparedPrecompiledDml {
                kind: PreparedDmlKind::Insert,
                ..
            }))
        ));

        for i in 1..=5 {
            let affected = stmt
                .execute_with_params(&[
                    SqliteValue::Integer(i),
                    SqliteValue::Text(format!("name_{i}").into()),
                ])
                .unwrap();
            assert_eq!(affected, 1);
        }

        let rows = conn.query("SELECT COUNT(*) FROM prep_reuse").unwrap();
        assert_eq!(rows[0].values()[0], SqliteValue::Integer(5));

        let rows = conn
            .query("SELECT name FROM prep_reuse ORDER BY id")
            .unwrap();
        assert_eq!(rows[0].values()[0], SqliteValue::Text("name_1".into()));
        assert_eq!(rows[4].values()[0], SqliteValue::Text("name_5".into()));
    }

    #[test]
    fn test_prepared_table_select_prepare_reuses_compiled_program_until_schema_change() {
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE prep_sel_reuse (id INTEGER PRIMARY KEY, val TEXT);")
            .unwrap();
        conn.execute("INSERT INTO prep_sel_reuse VALUES (1, 'alpha'), (2, 'beta');")
            .unwrap();

        let sql = "SELECT val FROM prep_sel_reuse WHERE id = ?1";
        let stmt1 = conn.prepare(sql).unwrap();
        let stmt2 = conn.prepare(sql).unwrap();

        assert!(
            stmt1.db.is_some(),
            "table SELECT should compile to a real program"
        );
        assert!(
            stmt2.db.is_some(),
            "table SELECT should compile to a real program"
        );
        assert!(
            std::sync::Arc::ptr_eq(&stmt1.program, &stmt2.program),
            "repeated prepare() should reuse the cached compiled SELECT program"
        );

        let row = stmt2
            .query_row_with_params(&[SqliteValue::Integer(2)])
            .unwrap();
        assert_eq!(row.values()[0], SqliteValue::Text("beta".into()));

        conn.execute("CREATE TABLE prep_sel_reuse_bump (id INTEGER PRIMARY KEY);")
            .unwrap();
        let stmt3 = conn.prepare(sql).unwrap();
        assert!(
            !std::sync::Arc::ptr_eq(&stmt1.program, &stmt3.program),
            "schema change should invalidate the cached compiled SELECT program"
        );
    }

    #[test]
    fn test_prepare_reuses_prepared_template_without_second_parse_or_compile() {
        let _profile_guard = StatementReuseHotPathProfileGuard::new();
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE prep_template_cache (id INTEGER PRIMARY KEY, val TEXT);")
            .unwrap();

        let sql = "SELECT val FROM prep_template_cache WHERE id = ?1";
        let stmt1 = conn.prepare(sql).unwrap();
        let stmt2 = conn.prepare(sql).unwrap();
        let profile = hot_path_profile_snapshot();

        assert!(
            std::sync::Arc::ptr_eq(&stmt1.program, &stmt2.program),
            "prepared cache should reuse the same compiled program"
        );
        assert_eq!(
            profile.parser.prepared_cache_misses, 1,
            "first prepare should populate the prepared cache: {profile:?}"
        );
        assert_eq!(
            profile.parser.prepared_cache_hits, 1,
            "second prepare should hit the prepared cache: {profile:?}"
        );
        assert_eq!(
            profile.parser.rewrite_calls, 1,
            "prepared cache hit should skip a second rewrite pass: {profile:?}"
        );
        assert_eq!(
            profile.parser.compiled_cache_misses, 1,
            "only the first prepare should compile the statement: {profile:?}"
        );
        assert_eq!(
            profile.parser.compiled_cache_hits, 0,
            "prepared cache hit should bypass the compiled-program cache entirely: {profile:?}"
        );
    }

