    #[test]
    fn test_compiled_cache_invalidated_by_aggregate_and_window_registration() {
        struct Product;

        impl fsqlite_func::AggregateFunction for Product {
            type State = i64;

            fn initial_state(&self) -> Self::State {
                1
            }

            fn step(
                &self,
                state: &mut Self::State,
                args: &[SqliteValue],
            ) -> fsqlite_error::Result<()> {
                *state *= args[0].to_integer();
                Ok(())
            }

            fn finalize(&self, state: Self::State) -> fsqlite_error::Result<SqliteValue> {
                Ok(SqliteValue::Integer(state))
            }

            fn num_args(&self) -> i32 {
                1
            }

            fn name(&self) -> &str {
                "product"
            }
        }

        struct MovingSum;

        impl fsqlite_func::WindowFunction for MovingSum {
            type State = i64;

            fn initial_state(&self) -> Self::State {
                0
            }

            fn step(
                &self,
                state: &mut Self::State,
                args: &[SqliteValue],
            ) -> fsqlite_error::Result<()> {
                *state += args[0].to_integer();
                Ok(())
            }

            fn inverse(
                &self,
                state: &mut Self::State,
                args: &[SqliteValue],
            ) -> fsqlite_error::Result<()> {
                *state -= args[0].to_integer();
                Ok(())
            }

            fn value(&self, state: &Self::State) -> fsqlite_error::Result<SqliteValue> {
                Ok(SqliteValue::Integer(*state))
            }

            fn finalize(&self, state: Self::State) -> fsqlite_error::Result<SqliteValue> {
                Ok(SqliteValue::Integer(state))
            }

            fn num_args(&self) -> i32 {
                1
            }

            fn name(&self) -> &str {
                "moving_sum"
            }
        }

        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE cc_udf (v INTEGER);").unwrap();
        conn.execute("INSERT INTO cc_udf VALUES (2), (3);").unwrap();

        conn.query("SELECT SUM(v) FROM cc_udf;").unwrap();
        assert!(
            conn.compiled_cache_len() > 0,
            "aggregate query should populate compiled cache"
        );

        conn.register_aggregate_function(Product);
        assert_eq!(
            conn.compiled_cache_len(),
            0,
            "aggregate registration must clear compiled cache"
        );

        conn.query("SELECT SUM(v) FROM cc_udf;").unwrap();
        assert!(
            conn.compiled_cache_len() > 0,
            "compiled cache should repopulate after aggregate registration"
        );

        conn.register_window_function(MovingSum);
        assert_eq!(
            conn.compiled_cache_len(),
            0,
            "window registration must clear compiled cache"
        );
    }

    #[test]
    fn test_prepared_cache_hit_uses_current_scalar_function_registry() {
        use fsqlite_func::ScalarFunction;
        let _profile_guard = StatementReuseHotPathProfileGuard::new();

        struct Double;

        impl ScalarFunction for Double {
            fn invoke(&self, args: &[SqliteValue]) -> Result<SqliteValue> {
                Ok(SqliteValue::Integer(args[0].to_integer() * 2))
            }

            fn num_args(&self) -> i32 {
                1
            }

            fn name(&self) -> &str {
                "scale1"
            }
        }

        struct Triple;

        impl ScalarFunction for Triple {
            fn invoke(&self, args: &[SqliteValue]) -> Result<SqliteValue> {
                Ok(SqliteValue::Integer(args[0].to_integer() * 3))
            }

            fn num_args(&self) -> i32 {
                1
            }

            fn name(&self) -> &str {
                "scale1"
            }
        }

        let conn = Connection::open(":memory:").unwrap();
        conn.register_scalar_function(Double);

        let stmt1 = conn.prepare("SELECT scale1(?1);").unwrap();
        let row1 = stmt1
            .query_row_with_params(&[SqliteValue::Integer(2)])
            .unwrap();
        assert_eq!(row1.values()[0], SqliteValue::Integer(4));

        conn.register_scalar_function(Triple);

        let stmt2 = conn.prepare("SELECT scale1(?1);").unwrap();
        let row2 = stmt2
            .query_row_with_params(&[SqliteValue::Integer(2)])
            .unwrap();
        assert_eq!(row2.values()[0], SqliteValue::Integer(6));

        let profile = hot_path_profile_snapshot();
        assert_eq!(
            profile.parser.prepared_cache_hits, 1,
            "scalar re-registration should still allow a prepared-cache hit: {profile:?}"
        );
        assert_eq!(
            profile.parser.prepared_cache_misses, 1,
            "only the first prepare should miss the prepared cache: {profile:?}"
        );
    }

