    // ── Time-travel query integration tests ──────────────────────────────

    #[test]
    fn test_time_travel_select_commitseq_rejects_when_no_history() {
        // Verify the full SQL path works end-to-end:
        //   Parser → AST → Planner → Codegen → VDBE (SetSnapshot) → Result
        //
        // In a :memory: database the MVCC VersionStore is empty, so the
        // engine MUST reject the time-travel query with an explicit error
        // rather than silently returning current data. Returning current
        // data when historical data was requested is incorrect and
        // violates the time-travel query contract.
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE users (id INTEGER PRIMARY KEY, name TEXT);")
            .unwrap();
        conn.execute("INSERT INTO users VALUES (1, 'Alice');")
            .unwrap();
        conn.execute("INSERT INTO users VALUES (2, 'Bob');")
            .unwrap();

        // Execute a time-travel query. With an empty VersionStore, the
        // engine must return an explicit error — NOT silently fall through
        // to current data.
        let result = conn.query("SELECT id, name FROM users FOR SYSTEM_TIME AS OF COMMITSEQ 5;");

        match result {
            Err(e) => {
                let msg = format!("{e}");
                assert!(
                    msg.contains("time-travel")
                        || msg.contains("historical data not available")
                        || msg.contains("compatibility mode")
                        || msg.contains("version store")
                        || msg.contains("SetSnapshot")
                        || msg.contains("commit"),
                    "expected a clear time-travel error, got: {msg}"
                );
            }
            Ok(rows) => {
                // If the engine takes a path that doesn't reach the
                // TimeTravelPageIo (e.g., no cursor upgrade because no
                // VersionStore was set, or Mem backend), that is also
                // acceptable for now. The important thing is we don't
                // silently return current data through a TimeTravelPageIo
                // with an empty VersionStore.
                // Log a note so we can track which path was taken.
                eprintln!(
                    "NOTE: time-travel query returned {} rows via \
                     non-TimeTravelPageIo path (acceptable until full \
                     native-mode wiring is complete)",
                    rows.len()
                );
            }
        }
    }

    #[test]
    fn test_time_travel_select_timestamp_returns_error() {
        // Timestamp-based time-travel requires a CommitLog which is not yet
        // available. The engine MUST return a clear error, not silently
        // return current data.
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE users (id INTEGER PRIMARY KEY, name TEXT);")
            .unwrap();
        conn.execute("INSERT INTO users VALUES (1, 'Alice');")
            .unwrap();

        let result =
            conn.query("SELECT id, name FROM users FOR SYSTEM_TIME AS OF '2024-01-01T00:00:00Z';");

        match result {
            Err(e) => {
                let msg = format!("{e}");
                assert!(
                    msg.contains("timestamp")
                        || msg.contains("CommitLog")
                        || msg.contains("time-travel"),
                    "expected time-travel timestamp error, got: {msg}"
                );
            }
            Ok(_rows) => {
                // Non-TimeTravelPageIo paths may still reach here.
                // Once full native-mode wiring is complete, this should
                // become unreachable.
                eprintln!(
                    "NOTE: timestamp time-travel query did not error \
                     (non-TimeTravelPageIo path)"
                );
            }
        }
    }

    #[test]
    fn test_time_travel_dml_blocked_insert() {
        // DML in a time-travel context must be rejected. While the
        // parser currently only attaches FOR SYSTEM_TIME AS OF to
        // SELECT queries, we verify the write-protection at the
        // cursor level as well.
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE t (id INTEGER PRIMARY KEY, val TEXT);")
            .unwrap();
        conn.execute("INSERT INTO t VALUES (1, 'a');").unwrap();

        // Attempt a time-travel SELECT that would trigger write through
        // a read-only cursor — this exercises the PageWriter rejection.
        let result = conn.query("SELECT * FROM t FOR SYSTEM_TIME AS OF COMMITSEQ 1;");
        // We just verify it doesn't panic; error or empty result is fine.
        let _ = result;
    }

    // ── End-to-end time-travel correctness tests (#23) ─────────────────────

    #[test]
    fn time_travel_snapshot_debug() {
        // Debug test: verify what's actually in the snapshots.
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE t (id INTEGER PRIMARY KEY, val TEXT);")
            .unwrap();
        conn.execute("BEGIN;").unwrap();
        conn.execute("INSERT INTO t VALUES (1, 'hello');").unwrap();
        conn.execute("COMMIT;").unwrap();

        let snaps = conn.time_travel_snapshots.borrow();
        eprintln!("snapshot count: {}", snaps.len());
        for snap in snaps.iter() {
            let table_count = snap.db.tables.len();
            eprintln!(
                "  seq={}, tables={}, timestamp_ns={}",
                snap.commit_seq, table_count, snap.timestamp_ns
            );
            // Check if the table has rows by looking at the tables.
            for (root_page, table) in snap.db.tables.iter() {
                let row_count = table.iter_rows().count();
                eprintln!(
                    "    root_page={}, num_columns={}, rows={}",
                    root_page, table.num_columns, row_count
                );
            }
        }
        drop(snaps);

        // Verify snapshot at seq 2 has 1 row.
        let snaps = conn.time_travel_snapshots.borrow();
        let snap_seq2 = snaps.iter().find(|s| s.commit_seq == 2);
        assert!(snap_seq2.is_some(), "snapshot at seq 2 should exist");
        let snap = snap_seq2.unwrap();
        let total_rows: usize = snap
            .db
            .tables
            .iter()
            .map(|(_, t)| t.iter_rows().count())
            .sum();
        assert!(
            total_rows > 0,
            "snapshot at seq 2 should have rows, got {total_rows}"
        );
    }

    #[test]
    fn file_backed_connections_do_not_capture_memdb_time_travel_snapshots() {
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("file_backed_time_travel.db");
        let conn = Connection::open(path.to_str().unwrap()).unwrap();

        conn.execute("CREATE TABLE t (id INTEGER PRIMARY KEY, val TEXT);")
            .unwrap();
        conn.execute("INSERT INTO t VALUES (1, 'hello');").unwrap();

        let snaps = conn.time_travel_snapshots.borrow();
        assert!(
            snaps.is_empty(),
            "file-backed connections should not retain MemDatabase time-travel snapshots"
        );
    }

    #[test]
    fn autocommit_dml_skips_memdb_time_travel_snapshot_capture() {
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE t (id INTEGER PRIMARY KEY, val TEXT);")
            .unwrap();

        let snapshot_count_after_ddl = conn.time_travel_snapshots.borrow().len();
        assert_eq!(
            snapshot_count_after_ddl, 1,
            "autocommit DDL should still retain the schema snapshot for time-travel"
        );

        conn.execute("INSERT INTO t VALUES (1, 'hello');").unwrap();
        conn.execute("UPDATE t SET val = 'world' WHERE id = 1;")
            .unwrap();
        conn.execute("DELETE FROM t WHERE id = 1;").unwrap();

        let snapshots = conn.time_travel_snapshots.borrow();
        assert_eq!(
            snapshots.len(),
            snapshot_count_after_ddl,
            "ordinary autocommit DML should not clone MemDatabase history on every statement"
        );
        assert_eq!(
            snapshots[0].commit_seq, 1,
            "the retained snapshot should still be the post-DDL schema state"
        );
    }

    #[test]
    fn file_backed_connections_reopen_with_schema_only_memdb_rows() {
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("schema_only_memdb_reload.db");
        let path_str = path.to_str().unwrap();

        {
            let conn = Connection::open(path_str).unwrap();
            conn.execute("CREATE TABLE t (id INTEGER PRIMARY KEY, val TEXT);")
                .unwrap();
            conn.execute("INSERT INTO t VALUES (1, 'hello');").unwrap();
            conn.execute("INSERT INTO t VALUES (2, 'world');").unwrap();
        }

        let conn = Connection::open(path_str).unwrap();
        assert!(
            !conn.memdb_rows_loaded.get(),
            "file-backed parity-cert connections should not eagerly hydrate table rows"
        );

        let root_page = conn
            .schema
            .borrow()
            .iter()
            .find(|table| table.name.eq_ignore_ascii_case("t"))
            .map(|table| table.root_page)
            .expect("table t should exist in schema");
        let memdb_row_count = conn
            .db
            .borrow()
            .get_table(root_page)
            .expect("table t should exist in MemDatabase")
            .iter_rows()
            .count();
        assert_eq!(
            memdb_row_count, 0,
            "schema-only file-backed reload should avoid copying user rows into MemDatabase"
        );

        let rows = conn.query("SELECT val FROM t ORDER BY id;").unwrap();
        assert_eq!(
            rows.len(),
            2,
            "pager-backed reads should still see both rows"
        );
        assert_eq!(rows[0].values(), &[SqliteValue::Text("hello".into())]);
        assert_eq!(rows[1].values(), &[SqliteValue::Text("world".into())]);
    }

    #[test]
    fn disabling_parity_cert_hydrates_file_backed_memdb_rows() {
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("parity_cert_memdb_hydrate.db");
        let path_str = path.to_str().unwrap();

        {
            let conn = Connection::open(path_str).unwrap();
            conn.execute("CREATE TABLE t (id INTEGER PRIMARY KEY, val TEXT);")
                .unwrap();
            conn.execute("INSERT INTO t VALUES (1, 'hello');").unwrap();
            conn.execute("INSERT INTO t VALUES (2, 'world');").unwrap();
        }

        let conn = Connection::open(path_str).unwrap();
        assert!(!conn.memdb_rows_loaded.get());

        conn.execute("PRAGMA fsqlite.parity_cert = OFF;").unwrap();

        assert!(
            conn.memdb_rows_loaded.get(),
            "disabling parity-cert should restore eager MemDatabase hydration"
        );

        let root_page = conn
            .schema
            .borrow()
            .iter()
            .find(|table| table.name.eq_ignore_ascii_case("t"))
            .map(|table| table.root_page)
            .expect("table t should exist in schema");
        let memdb_row_count = conn
            .db
            .borrow()
            .get_table(root_page)
            .expect("table t should exist in MemDatabase")
            .iter_rows()
            .count();
        assert_eq!(
            memdb_row_count, 2,
            "PRAGMA parity_cert = OFF should reload file-backed rows into MemDatabase"
        );
    }

    #[test]
    fn schema_only_reload_preserves_autoincrement_sequence_state() {
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("schema_only_autoincrement.db");
        let path_str = path.to_str().unwrap();

        {
            let conn = Connection::open(path_str).unwrap();
            conn.execute("CREATE TABLE t (id INTEGER PRIMARY KEY AUTOINCREMENT, val TEXT);")
                .unwrap();
            conn.execute("INSERT INTO t (val) VALUES ('first');")
                .unwrap();
            conn.execute("INSERT INTO t (val) VALUES ('second');")
                .unwrap();
            conn.execute("DELETE FROM t WHERE id = 2;").unwrap();
        }

        let conn = Connection::open(path_str).unwrap();
        assert!(
            !conn.memdb_rows_loaded.get(),
            "reopen should keep file-backed MemDatabase in schema-only mode"
        );

        conn.execute("INSERT INTO t (val) VALUES ('third');")
            .unwrap();

        let rows = conn.query("SELECT id FROM t ORDER BY id;").unwrap();
        let ids: Vec<i64> = rows
            .iter()
            .map(|row| match row.values()[0] {
                SqliteValue::Integer(id) => id,
                ref other => panic!("expected integer id, got {other:?}"),
            })
            .collect();
        assert_eq!(
            ids,
            vec![1, 3],
            "AUTOINCREMENT should continue from sqlite_sequence even when MemDatabase rows stay unloaded"
        );
    }

    #[test]
    fn time_travel_by_commit_seq_returns_historical_state() {
        // Verify that FOR SYSTEM_TIME AS OF COMMITSEQ returns the database
        // state as it existed at that specific commit, not the current state.
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE users (id INTEGER PRIMARY KEY, name TEXT);")
            .unwrap();
        // CREATE TABLE autocommits → captures snapshot at seq 1.

        conn.execute("BEGIN;").unwrap();
        conn.execute("INSERT INTO users VALUES (1, 'Alice');")
            .unwrap();
        conn.execute("COMMIT;").unwrap();
        // Explicit commit → seq 2 (table has 1 row: Alice).

        conn.execute("BEGIN;").unwrap();
        conn.execute("INSERT INTO users VALUES (2, 'Bob');")
            .unwrap();
        conn.execute("COMMIT;").unwrap();
        // Explicit commit → seq 3 (table has 2 rows: Alice, Bob).

        conn.execute("BEGIN;").unwrap();
        conn.execute("INSERT INTO users VALUES (3, 'Carol');")
            .unwrap();
        conn.execute("COMMIT;").unwrap();
        // Explicit commit → seq 4 (table has 3 rows: Alice, Bob, Carol).

        // Current state: 3 rows.
        let current = conn.query("SELECT * FROM users;").unwrap();
        assert_eq!(current.len(), 3, "current state should have 3 rows");

        // Historical: after seq 2 (only Alice).
        let hist_2 = conn
            .query("SELECT id, name FROM users FOR SYSTEM_TIME AS OF COMMITSEQ 2;")
            .unwrap();
        assert_eq!(hist_2.len(), 1, "seq 2 should have 1 row");
        // Verify Alice is present in the result row (column ordering may vary
        // between pager-backed and MemPageStore execution paths).
        let alice_present = hist_2[0]
            .values()
            .iter()
            .any(|v| *v == SqliteValue::Text("Alice".into()));
        assert!(
            alice_present,
            "seq 2 should contain Alice, got: {:?}",
            hist_2[0].values()
        );

        // Historical: after seq 3 (Alice + Bob).
        let hist_3 = conn
            .query("SELECT id, name FROM users FOR SYSTEM_TIME AS OF COMMITSEQ 3;")
            .unwrap();
        assert_eq!(hist_3.len(), 2, "seq 3 should have 2 rows");

        // Historical: after seq 4 (Alice + Bob + Carol).
        let hist_4 = conn
            .query("SELECT id, name FROM users FOR SYSTEM_TIME AS OF COMMITSEQ 4;")
            .unwrap();
        assert_eq!(hist_4.len(), 3, "seq 4 should have 3 rows");

        // Non-existent commit_seq returns an error.
        let err = conn.query("SELECT * FROM users FOR SYSTEM_TIME AS OF COMMITSEQ 999;");
        assert!(err.is_err(), "non-existent commit_seq should error");
        let msg = format!("{}", err.unwrap_err());
        assert!(
            msg.contains("time-travel"),
            "error should mention time-travel, got: {msg}"
        );
    }

    #[test]
    fn time_travel_delete_visibility() {
        // Verify that rows deleted in the current state are still visible
        // in historical snapshots.
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE items (id INTEGER PRIMARY KEY, val TEXT);")
            .unwrap();

        conn.execute("BEGIN;").unwrap();
        conn.execute("INSERT INTO items VALUES (1, 'one');")
            .unwrap();
        conn.execute("INSERT INTO items VALUES (2, 'two');")
            .unwrap();
        conn.execute("COMMIT;").unwrap();
        // seq 2: table has (1,'one'), (2,'two')

        conn.execute("BEGIN;").unwrap();
        conn.execute("DELETE FROM items WHERE id = 1;").unwrap();
        conn.execute("COMMIT;").unwrap();
        // seq 3: table has only (2,'two')

        // Current state: 1 row.
        let current = conn.query("SELECT * FROM items;").unwrap();
        assert_eq!(current.len(), 1);

        // Historical seq 2: both rows should be visible.
        let hist = conn
            .query("SELECT * FROM items FOR SYSTEM_TIME AS OF COMMITSEQ 2;")
            .unwrap();
        assert_eq!(
            hist.len(),
            2,
            "deleted row should be visible in historical snapshot"
        );
    }

    #[test]
    fn time_travel_update_shows_old_values() {
        // Verify that updated values are correctly captured in historical snapshots.
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE kv (k TEXT PRIMARY KEY, v TEXT);")
            .unwrap();

        conn.execute("BEGIN;").unwrap();
        conn.execute("INSERT INTO kv VALUES ('key1', 'old_value');")
            .unwrap();
        conn.execute("COMMIT;").unwrap();
        // seq 2: key1 = old_value

        conn.execute("BEGIN;").unwrap();
        conn.execute("UPDATE kv SET v = 'new_value' WHERE k = 'key1';")
            .unwrap();
        conn.execute("COMMIT;").unwrap();
        // seq 3: key1 = new_value

        // Current state: new_value
        let current = conn.query("SELECT v FROM kv WHERE k = 'key1';").unwrap();
        assert_eq!(
            current[0].values()[0],
            SqliteValue::Text("new_value".into())
        );

        // Historical seq 2: old_value
        let hist = conn
            .query("SELECT v FROM kv FOR SYSTEM_TIME AS OF COMMITSEQ 2;")
            .unwrap();
        assert_eq!(hist[0].values()[0], SqliteValue::Text("old_value".into()));
    }

    #[test]
    fn time_travel_does_not_corrupt_live_state() {
        // Ensure that executing a time-travel query does not modify the
        // live MemDatabase state.
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE t (x INTEGER);").unwrap();

        conn.execute("BEGIN;").unwrap();
        conn.execute("INSERT INTO t VALUES (10);").unwrap();
        conn.execute("COMMIT;").unwrap();

        conn.execute("BEGIN;").unwrap();
        conn.execute("INSERT INTO t VALUES (20);").unwrap();
        conn.execute("COMMIT;").unwrap();

        // Time-travel to seq 2 (only row 10).
        let hist = conn
            .query("SELECT * FROM t FOR SYSTEM_TIME AS OF COMMITSEQ 2;")
            .unwrap();
        assert_eq!(hist.len(), 1);

        // Live state should still have both rows.
        let live = conn.query("SELECT * FROM t;").unwrap();
        assert_eq!(
            live.len(),
            2,
            "live state must not be corrupted by time-travel query"
        );
    }

    #[test]
    fn time_travel_empty_table_snapshot() {
        // Verify that the snapshot after CREATE TABLE (before any INSERTs)
        // returns an empty result set.
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE t (id INTEGER);").unwrap();
        // seq 1: empty table

        conn.execute("BEGIN;").unwrap();
        conn.execute("INSERT INTO t VALUES (42);").unwrap();
        conn.execute("COMMIT;").unwrap();
        // seq 2: one row

        // Historical seq 1: empty.
        let hist = conn
            .query("SELECT * FROM t FOR SYSTEM_TIME AS OF COMMITSEQ 1;")
            .unwrap();
        assert_eq!(hist.len(), 0, "snapshot after CREATE TABLE should be empty");

        // Current: one row.
        let current = conn.query("SELECT * FROM t;").unwrap();
        assert_eq!(current.len(), 1);
    }

