    /// Broad conformance probe: DML, subquery patterns, type coercion,
    /// complex expressions, and edge cases.
    #[test]
    fn test_conformance_broad_probe() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE t1 (a INTEGER PRIMARY KEY, b TEXT, c REAL, d BLOB);",
            "INSERT INTO t1 VALUES (1, 'hello', 1.5, X'CAFE');",
            "INSERT INTO t1 VALUES (2, 'world', 2.5, NULL);",
            "INSERT INTO t1 VALUES (3, NULL, NULL, X'BABE');",
            "INSERT INTO t1 VALUES (4, 'hello', 3.5, NULL);",
            "INSERT INTO t1 VALUES (5, '', 0.0, X'');",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // Type coercion in comparisons
            "SELECT a FROM t1 WHERE c = 1.5",
            "SELECT a FROM t1 WHERE c = '1.5'",
            "SELECT a FROM t1 WHERE b = b ORDER BY a",
            // NULL comparisons
            "SELECT a FROM t1 WHERE c IS NULL",
            "SELECT a FROM t1 WHERE c IS NOT NULL ORDER BY a",
            "SELECT a FROM t1 WHERE b IS NULL OR b = '' ORDER BY a",
            // BETWEEN with NULL boundaries
            "SELECT a FROM t1 WHERE c BETWEEN 1.0 AND 3.0 ORDER BY a",
            // LIKE
            "SELECT a FROM t1 WHERE b LIKE 'hel%' ORDER BY a",
            "SELECT a FROM t1 WHERE b LIKE '%llo' ORDER BY a",
            "SELECT a FROM t1 WHERE b LIKE '%' ORDER BY a",
            // GLOB
            "SELECT a FROM t1 WHERE b GLOB 'h*' ORDER BY a",
            // typeof
            "SELECT typeof(a), typeof(b), typeof(c), typeof(d) FROM t1 WHERE a = 1",
            "SELECT typeof(NULL), typeof(1), typeof(1.0), typeof(''), typeof(X'00')",
            // CAST
            "SELECT CAST(c AS INTEGER) FROM t1 WHERE a = 1",
            "SELECT CAST(a AS TEXT) FROM t1 WHERE a = 2",
            "SELECT CAST('123abc' AS INTEGER)",
            "SELECT CAST('' AS INTEGER)",
            // abs, random seed
            "SELECT abs(-42), abs(0), abs(42)",
            "SELECT abs(NULL)",
            // String functions
            "SELECT upper('hello'), lower('HELLO')",
            "SELECT substr('hello', 2, 3)",
            "SELECT substr('hello', -2)",
            "SELECT instr('hello world', 'world')",
            "SELECT replace('aabbcc', 'bb', 'XX')",
            // Arithmetic edge cases
            "SELECT 1/0",
            "SELECT 1.0/0.0",
            "SELECT 0/0",
            "SELECT 1 % 0",
            // Unary minus
            "SELECT -(-1), -(1.5), -NULL",
            // Concatenation
            "SELECT 'a' || 'b' || 'c'",
            "SELECT 'a' || NULL",
            "SELECT NULL || 'b'",
            // IIF
            "SELECT iif(1, 'yes', 'no'), iif(0, 'yes', 'no'), iif(NULL, 'yes', 'no')",
            // NULLIF
            "SELECT nullif(1, 1), nullif(1, 2), nullif(NULL, NULL)",
            // Multi-column IN list
            "SELECT a FROM t1 WHERE b IN ('hello', 'world') ORDER BY a",
            "SELECT a FROM t1 WHERE a IN (1, 3, 5) ORDER BY a",
            // NOT IN
            "SELECT a FROM t1 WHERE a NOT IN (1, 3) ORDER BY a",
            // Aggregate with WHERE
            "SELECT count(*), sum(c), avg(c) FROM t1 WHERE c IS NOT NULL",
            // Aggregate with empty result
            "SELECT count(*), sum(c), avg(c) FROM t1 WHERE a > 100",
            // GROUP BY with NULL values
            "SELECT b, count(*) FROM t1 GROUP BY b ORDER BY b",
            // ORDER BY with NULLs
            "SELECT b FROM t1 ORDER BY b",
            "SELECT c FROM t1 ORDER BY c DESC",
            // Subquery scalar
            "SELECT (SELECT max(c) FROM t1)",
            "SELECT a, (SELECT count(*) FROM t1 WHERE t1.b = t.b) AS cnt FROM t1 t ORDER BY a",
            // hex and zeroblob
            "SELECT hex(X'CAFE')",
            "SELECT hex(zeroblob(4))",
            "SELECT length(zeroblob(10))",
            // printf
            "SELECT printf('%d items', 42)",
            "SELECT printf('%.2f', 3.14159)",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!("{} broad probe mismatches found", mismatches.len());
        }
    }

    /// DML + CTE + complex subquery conformance probe.
    #[test]
    fn test_conformance_dml_cte_probe() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE inventory (id INTEGER PRIMARY KEY, item TEXT, qty INTEGER, price REAL);",
            "INSERT INTO inventory VALUES (1, 'widget', 100, 9.99);",
            "INSERT INTO inventory VALUES (2, 'gadget', 50, 19.99);",
            "INSERT INTO inventory VALUES (3, 'widget', 75, 9.99);",
            "INSERT INTO inventory VALUES (4, 'doohickey', 200, 4.99);",
            "INSERT INTO inventory VALUES (5, 'gadget', 30, 24.99);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // CTE basic
            "WITH totals AS (SELECT item, SUM(qty) AS total_qty FROM inventory GROUP BY item) SELECT item, total_qty FROM totals ORDER BY total_qty DESC",
            // CTE with aggregate + filter
            "WITH expensive AS (SELECT * FROM inventory WHERE price > 10) SELECT count(*), sum(qty) FROM expensive",
            // CTE with JOIN
            "WITH item_stats AS (SELECT item, SUM(qty) AS total, AVG(price) AS avg_price FROM inventory GROUP BY item) SELECT s.item, s.total FROM item_stats s WHERE s.total > 50 ORDER BY s.item",
            // Recursive CTE (simple counting)
            "WITH RECURSIVE cnt(x) AS (SELECT 1 UNION ALL SELECT x+1 FROM cnt WHERE x < 5) SELECT x FROM cnt",
            // Recursive CTE (fibonacci)
            "WITH RECURSIVE fib(a, b) AS (SELECT 0, 1 UNION ALL SELECT b, a+b FROM fib WHERE b < 100) SELECT a FROM fib",
            // Subquery in SELECT list
            "SELECT item, qty, (SELECT SUM(qty) FROM inventory i2 WHERE i2.item = inventory.item) AS total_item_qty FROM inventory ORDER BY id",
            // Subquery in WHERE with correlated aggregate
            "SELECT item, qty FROM inventory WHERE qty = (SELECT MAX(qty) FROM inventory i2 WHERE i2.item = inventory.item) ORDER BY id",
            // DISTINCT with aggregate
            "SELECT DISTINCT item FROM inventory ORDER BY item",
            "SELECT COUNT(DISTINCT item) FROM inventory",
            "SELECT item, COUNT(DISTINCT price) FROM inventory GROUP BY item ORDER BY item",
            // GROUP_CONCAT with ORDER
            "SELECT item, GROUP_CONCAT(CAST(qty AS TEXT), '+') FROM inventory GROUP BY item ORDER BY item",
            // TOTAL vs SUM
            "SELECT TOTAL(qty), SUM(qty) FROM inventory",
            "SELECT TOTAL(qty), SUM(qty) FROM inventory WHERE qty > 1000",
            // INSERT + SELECT back
            "INSERT INTO inventory VALUES (6, 'gizmo', 10, 49.99)",
            "SELECT count(*) FROM inventory",
            // UPDATE with expression
            "UPDATE inventory SET qty = qty * 2 WHERE item = 'gizmo'",
            "SELECT qty FROM inventory WHERE item = 'gizmo' AND id = 6",
            // DELETE with subquery condition
            "DELETE FROM inventory WHERE id = 6",
            "SELECT count(*) FROM inventory",
            // Complex WHERE with multiple conditions
            "SELECT id FROM inventory WHERE (qty > 50 AND price < 15) OR item = 'gadget' ORDER BY id",
            // CASE in ORDER BY
            "SELECT item, qty FROM inventory ORDER BY CASE item WHEN 'widget' THEN 1 WHEN 'gadget' THEN 2 ELSE 3 END, qty DESC",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!("{} DML/CTE probe mismatches found", mismatches.len());
        }
    }

    /// Conformance oracle for expression evaluation edge cases.
    #[test]
    fn test_conformance_oracle_expressions() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE t (id INTEGER PRIMARY KEY, a TEXT, b INTEGER, c REAL);",
            "INSERT INTO t VALUES (1, 'hello', 10, 1.5);",
            "INSERT INTO t VALUES (2, 'world', 20, 2.5);",
            "INSERT INTO t VALUES (3, NULL, NULL, NULL);",
            "INSERT INTO t VALUES (4, 'test', 0, 0.0);",
            "INSERT INTO t VALUES (5, 'HELLO', -5, -1.5);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // Scalar min/max with NULL (the bug we just fixed)
            "SELECT min(1,2,3), max(1,2,3)",
            "SELECT min(NULL, 1), max(NULL, 1)",
            "SELECT min('a','b','c'), max('a','b','c')",
            // ORDER BY alias with expressions
            "SELECT a, b * c AS product FROM t WHERE b IS NOT NULL ORDER BY product DESC",
            "SELECT a, length(a) AS alen FROM t WHERE a IS NOT NULL ORDER BY alen, a",
            // CASE in GROUP BY result column
            "SELECT CASE WHEN b > 0 THEN 'positive' WHEN b = 0 THEN 'zero' ELSE 'other' END AS sign, count(*) FROM t WHERE b IS NOT NULL GROUP BY sign ORDER BY sign",
            // IN with subquery containing GROUP BY
            "SELECT a FROM t WHERE a IN (SELECT a FROM t GROUP BY a HAVING count(*) = 1) ORDER BY a",
            // Nested COALESCE/NULLIF
            "SELECT COALESCE(NULLIF(a, 'hello'), 'default') FROM t ORDER BY id",
            // IIF with column expressions
            "SELECT IIF(b > 10, 'big', 'small') FROM t WHERE b IS NOT NULL ORDER BY id",
            // Compound SELECT with ORDER BY
            "SELECT 'x' AS v UNION SELECT 'y' UNION SELECT 'z' ORDER BY v",
            "SELECT 1 AS n UNION ALL SELECT 2 UNION ALL SELECT 1 ORDER BY n",
            // Aggregate over CASE
            "SELECT SUM(CASE WHEN b > 0 THEN b ELSE 0 END) FROM t",
            "SELECT COUNT(CASE WHEN a IS NOT NULL THEN 1 END) FROM t",
            // GROUP BY with multiple columns
            "SELECT CASE WHEN b > 0 THEN 'pos' ELSE 'other' END AS sign, count(*) FROM t GROUP BY 1 ORDER BY 1",
            // LIKE patterns
            "SELECT a FROM t WHERE a LIKE 'h%' ORDER BY a",
            "SELECT a FROM t WHERE a LIKE '%llo' ORDER BY a",
            "SELECT a FROM t WHERE a LIKE '_e%' ORDER BY a",
            // GLOB
            "SELECT a FROM t WHERE a GLOB '*ell*' ORDER BY a",
            // Arithmetic edge cases
            "SELECT 1/0, 0/0",
            "SELECT 9223372036854775807 + 1",
            // String concatenation
            "SELECT 'hello' || ' ' || 'world'",
            "SELECT NULL || 'test'",
            // REPLACE function
            "SELECT replace('hello world', 'world', 'there')",
            "SELECT replace('aaa', 'a', 'bb')",
            // INSTR
            "SELECT instr('hello world', 'world'), instr('hello', 'xyz')",
            // HEX/UNHEX
            "SELECT hex('abc'), hex(123)",
            // TYPEOF in expressions
            "SELECT typeof(1+1), typeof(1.0+1), typeof('a'||'b')",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} expression conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Probe compound SELECT, CTE, and edge-case patterns.
    #[test]
    fn test_conformance_compound_and_cte() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE t1 (id INTEGER PRIMARY KEY, val TEXT);",
            "INSERT INTO t1 VALUES (1, 'a'), (2, 'b'), (3, 'c');",
            "CREATE TABLE t2 (id INTEGER PRIMARY KEY, val TEXT);",
            "INSERT INTO t2 VALUES (2, 'b'), (3, 'c'), (4, 'd');",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // UNION
            "SELECT val FROM t1 UNION SELECT val FROM t2 ORDER BY 1",
            // UNION ALL
            "SELECT val FROM t1 UNION ALL SELECT val FROM t2 ORDER BY 1",
            // INTERSECT
            "SELECT val FROM t1 INTERSECT SELECT val FROM t2 ORDER BY 1",
            // EXCEPT
            "SELECT val FROM t1 EXCEPT SELECT val FROM t2",
            // CTE
            "WITH cte AS (SELECT id, val FROM t1 WHERE id > 1) SELECT * FROM cte ORDER BY id",
            // Recursive CTE
            "WITH RECURSIVE cnt(x) AS (VALUES(1) UNION ALL SELECT x+1 FROM cnt WHERE x < 5) SELECT x FROM cnt",
            // CTE with aggregate
            "WITH summary AS (SELECT val, COUNT(*) AS c FROM (SELECT val FROM t1 UNION ALL SELECT val FROM t2) GROUP BY val) SELECT val, c FROM summary ORDER BY val",
            // Nested UNION in CTE
            "WITH combined AS (SELECT val FROM t1 UNION SELECT val FROM t2) SELECT COUNT(*) FROM combined",
            // Multiple CTEs
            "WITH a AS (SELECT val FROM t1), b AS (SELECT val FROM t2) SELECT a.val FROM a WHERE a.val IN (SELECT val FROM b) ORDER BY a.val",
            // UNION with LIMIT
            "SELECT val FROM t1 UNION SELECT val FROM t2 ORDER BY 1 LIMIT 3",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!("{} compound/CTE mismatches found", mismatches.len());
        }
    }

    /// Correlated subquery, self-join alias scoping, and UPDATE/DELETE patterns.
    #[test]
    fn test_conformance_correlated_update_probe() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE emp (id INTEGER PRIMARY KEY, name TEXT, dept TEXT, salary REAL);",
            "INSERT INTO emp VALUES (1, 'Alice', 'eng', 100.0);",
            "INSERT INTO emp VALUES (2, 'Bob', 'eng', 120.0);",
            "INSERT INTO emp VALUES (3, 'Carol', 'sales', 90.0);",
            "INSERT INTO emp VALUES (4, 'Dave', 'sales', 80.0);",
            "INSERT INTO emp VALUES (5, 'Eve', 'eng', 110.0);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // Correlated scalar subquery: per-dept max salary
            "SELECT e.name, e.salary, (SELECT MAX(e2.salary) FROM emp e2 WHERE e2.dept = e.dept) AS dept_max FROM emp e ORDER BY e.id",
            // Correlated subquery in WHERE: employees earning above dept avg
            "SELECT e.name FROM emp e WHERE e.salary > (SELECT AVG(e2.salary) FROM emp e2 WHERE e2.dept = e.dept) ORDER BY e.name",
            // Correlated EXISTS
            "SELECT e.name FROM emp e WHERE EXISTS (SELECT 1 FROM emp e2 WHERE e2.dept = e.dept AND e2.salary > e.salary) ORDER BY e.name",
            // NOT EXISTS: highest earner per dept
            "SELECT e.name, e.dept FROM emp e WHERE NOT EXISTS (SELECT 1 FROM emp e2 WHERE e2.dept = e.dept AND e2.salary > e.salary) ORDER BY e.dept",
            // Correlated subquery: count colleagues
            "SELECT e.name, (SELECT COUNT(*) - 1 FROM emp e2 WHERE e2.dept = e.dept) AS colleagues FROM emp e ORDER BY e.id",
            // Correlated subquery in HAVING (via CTE workaround)
            "WITH dept_stats AS (SELECT dept, AVG(salary) AS avg_sal FROM emp GROUP BY dept) SELECT e.name, e.salary FROM emp e WHERE e.salary > (SELECT avg_sal FROM dept_stats WHERE dept = e.dept) ORDER BY e.name",
            // UPDATE with scalar subquery (non-correlated)
            "UPDATE emp SET salary = salary + 10 WHERE dept = 'sales'",
            "SELECT name, salary FROM emp WHERE dept = 'sales' ORDER BY name",
            // DELETE with correlated subquery
            "DELETE FROM emp WHERE salary < (SELECT AVG(salary) FROM emp)",
            "SELECT name, salary FROM emp ORDER BY name",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} correlated/update probe mismatches found",
                mismatches.len()
            );
        }
    }

    /// Probe LIMIT/OFFSET, aggregate expressions in JOINs,
    /// GROUP BY edge cases, and HAVING with expressions.
    #[test]
    fn test_conformance_limit_agg_join() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE orders (id INTEGER PRIMARY KEY, cust_id INTEGER, amount REAL, status TEXT);",
            "INSERT INTO orders VALUES (1, 1, 100.0, 'shipped');",
            "INSERT INTO orders VALUES (2, 1, 50.0, 'pending');",
            "INSERT INTO orders VALUES (3, 2, 200.0, 'shipped');",
            "INSERT INTO orders VALUES (4, 2, 75.0, 'shipped');",
            "INSERT INTO orders VALUES (5, 3, 300.0, 'pending');",
            "INSERT INTO orders VALUES (6, 3, 25.0, 'cancelled');",
            "CREATE TABLE customers (id INTEGER PRIMARY KEY, name TEXT, region TEXT);",
            "INSERT INTO customers VALUES (1, 'Alice', 'east');",
            "INSERT INTO customers VALUES (2, 'Bob', 'west');",
            "INSERT INTO customers VALUES (3, 'Carol', 'east');",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // LIMIT with literal
            "SELECT id FROM orders ORDER BY id LIMIT 3",
            // LIMIT with OFFSET
            "SELECT id FROM orders ORDER BY id LIMIT 2 OFFSET 2",
            // LIMIT 0
            "SELECT id FROM orders ORDER BY id LIMIT 0",
            // OFFSET without LIMIT (SQLite treats as LIMIT -1 OFFSET n)
            "SELECT id FROM orders ORDER BY id LIMIT -1 OFFSET 3",
            // Aggregate with JOIN
            "SELECT c.name, SUM(o.amount) AS total FROM customers c JOIN orders o ON c.id = o.cust_id GROUP BY c.name ORDER BY c.name",
            // COUNT with JOIN
            "SELECT c.name, COUNT(o.id) AS cnt FROM customers c JOIN orders o ON c.id = o.cust_id GROUP BY c.name ORDER BY c.name",
            // AVG with JOIN
            "SELECT c.name, AVG(o.amount) AS avg_amt FROM customers c JOIN orders o ON c.id = o.cust_id GROUP BY c.name ORDER BY c.name",
            // HAVING with expression
            "SELECT c.name, SUM(o.amount) AS total FROM customers c JOIN orders o ON c.id = o.cust_id GROUP BY c.name HAVING SUM(o.amount) > 150 ORDER BY c.name",
            // Aggregate over CASE in JOIN
            "SELECT c.region, SUM(CASE WHEN o.status = 'shipped' THEN o.amount ELSE 0 END) AS shipped_total FROM customers c JOIN orders o ON c.id = o.cust_id GROUP BY c.region ORDER BY c.region",
            // COUNT DISTINCT in JOIN
            "SELECT c.region, COUNT(DISTINCT o.status) AS status_count FROM customers c JOIN orders o ON c.id = o.cust_id GROUP BY c.region ORDER BY c.region",
            // GROUP BY with multiple aggregates
            "SELECT c.region, MIN(o.amount), MAX(o.amount), COUNT(*) FROM customers c JOIN orders o ON c.id = o.cust_id GROUP BY c.region ORDER BY c.region",
            // Subquery in FROM with LIMIT
            "SELECT * FROM (SELECT id, amount FROM orders ORDER BY amount DESC LIMIT 3) sub ORDER BY sub.id",
            // GROUP BY ordinal with HAVING
            "SELECT status, COUNT(*) AS cnt FROM orders GROUP BY 1 HAVING COUNT(*) > 1 ORDER BY 1",
            // COALESCE in aggregate
            "SELECT SUM(COALESCE(amount, 0)) FROM orders",
            // Nested aggregate: max of group sums (via subquery)
            "SELECT MAX(total) FROM (SELECT cust_id, SUM(amount) AS total FROM orders GROUP BY cust_id)",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} limit/agg/join conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Probe type coercion, CAST, expression edge cases, and
    /// multi-table patterns that exercise deeper code paths.
    #[test]
    fn test_conformance_types_and_multipath() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE items (id INTEGER PRIMARY KEY, name TEXT, price REAL, qty INTEGER);",
            "INSERT INTO items VALUES (1, 'apple', 1.50, 10);",
            "INSERT INTO items VALUES (2, 'banana', 0.75, 20);",
            "INSERT INTO items VALUES (3, 'cherry', 3.00, 0);",
            "INSERT INTO items VALUES (4, 'date', NULL, 5);",
            "INSERT INTO items VALUES (5, 'elderberry', 12.50, NULL);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // CAST expressions
            "SELECT CAST(price AS INTEGER) FROM items ORDER BY id",
            "SELECT CAST(qty AS REAL) FROM items ORDER BY id",
            "SELECT CAST(name AS BLOB) FROM items WHERE id = 1",
            "SELECT CAST(123 AS TEXT)",
            "SELECT CAST(NULL AS INTEGER), CAST(NULL AS TEXT), CAST(NULL AS REAL)",
            // ABS edge cases
            "SELECT abs(-1), abs(0), abs(1), abs(NULL)",
            "SELECT abs(-9223372036854775807)",
            // ROUND
            "SELECT round(2.5), round(3.5), round(-2.5)",
            "SELECT round(1.2345, 2), round(1.2345, 0)",
            // UNICODE / CHAR
            "SELECT unicode('A'), unicode('a'), unicode(' ')",
            "SELECT char(65), char(97), char(32)",
            // ZEROBLOB
            "SELECT typeof(zeroblob(4)), length(zeroblob(4))",
            // TOTAL (returns 0.0 for empty, unlike SUM which returns NULL)
            "SELECT total(price) FROM items",
            "SELECT total(price) FROM items WHERE id > 100",
            // SUM returns NULL for empty set
            "SELECT sum(price) FROM items WHERE id > 100",
            // GROUP_CONCAT
            "SELECT group_concat(name) FROM items WHERE name IS NOT NULL ORDER BY id",
            "SELECT group_concat(name, ' | ') FROM items WHERE name IS NOT NULL ORDER BY id",
            // SUBSTR edge cases
            "SELECT substr('hello', 1, 3), substr('hello', -2)",
            "SELECT substr('hello', 0, 3)",
            // LTRIM/RTRIM/TRIM
            "SELECT ltrim('  hello  '), rtrim('  hello  '), trim('  hello  ')",
            "SELECT ltrim('xxxhello', 'x'), rtrim('helloyyy', 'y')",
            // UPPER/LOWER
            "SELECT upper('hello'), lower('HELLO')",
            // Nested function calls
            "SELECT length(upper(trim('  hello  ')))",
            // BETWEEN
            "SELECT id FROM items WHERE price BETWEEN 1.0 AND 5.0 ORDER BY id",
            // NOT BETWEEN
            "SELECT id FROM items WHERE price NOT BETWEEN 1.0 AND 5.0 ORDER BY id",
            // IS / IS NOT
            "SELECT id FROM items WHERE price IS NULL ORDER BY id",
            "SELECT id FROM items WHERE price IS NOT NULL ORDER BY id",
            // Ternary comparison chain via CASE
            "SELECT id, CASE WHEN price > 10 THEN 'expensive' WHEN price > 1 THEN 'moderate' ELSE 'cheap' END AS tier FROM items WHERE price IS NOT NULL ORDER BY id",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} types/multipath conformance mismatches found",
                mismatches.len()
            );
        }
    }

    #[test]
    fn test_conformance_subquery_coalesce_iif() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE t1 (id INTEGER PRIMARY KEY, a INTEGER, b TEXT);",
            "INSERT INTO t1 VALUES (1, 10, 'x');",
            "INSERT INTO t1 VALUES (2, 20, 'y');",
            "INSERT INTO t1 VALUES (3, NULL, 'z');",
            "INSERT INTO t1 VALUES (4, 30, NULL);",
            "CREATE TABLE t2 (id INTEGER PRIMARY KEY, t1_id INTEGER, val REAL);",
            "INSERT INTO t2 VALUES (1, 1, 100.0);",
            "INSERT INTO t2 VALUES (2, 1, 200.0);",
            "INSERT INTO t2 VALUES (3, 2, 50.0);",
            "INSERT INTO t2 VALUES (4, 3, 75.0);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // COALESCE
            "SELECT coalesce(a, -1) FROM t1 ORDER BY id",
            "SELECT coalesce(NULL, NULL, 42)",
            "SELECT coalesce(b, 'missing') FROM t1 ORDER BY id",
            // NULLIF
            "SELECT nullif(10, 10), nullif(10, 20), nullif(NULL, 1)",
            "SELECT nullif(a, 10) FROM t1 ORDER BY id",
            // IIF
            "SELECT iif(1, 'yes', 'no'), iif(0, 'yes', 'no'), iif(NULL, 'yes', 'no')",
            "SELECT iif(a > 15, 'big', 'small') FROM t1 WHERE a IS NOT NULL ORDER BY id",
            // Scalar subquery in SELECT list
            "SELECT id, (SELECT count(*) FROM t2 WHERE t2.t1_id = t1.id) AS cnt FROM t1 ORDER BY id",
            // Scalar subquery in WHERE
            "SELECT id FROM t1 WHERE (SELECT sum(val) FROM t2 WHERE t2.t1_id = t1.id) > 100 ORDER BY id",
            // EXISTS subquery
            "SELECT id FROM t1 WHERE EXISTS (SELECT 1 FROM t2 WHERE t2.t1_id = t1.id) ORDER BY id",
            "SELECT id FROM t1 WHERE NOT EXISTS (SELECT 1 FROM t2 WHERE t2.t1_id = t1.id) ORDER BY id",
            // IN subquery
            "SELECT id FROM t1 WHERE id IN (SELECT t1_id FROM t2) ORDER BY id",
            "SELECT id FROM t1 WHERE id NOT IN (SELECT t1_id FROM t2 WHERE t1_id IS NOT NULL) ORDER BY id",
            // Arithmetic on aggregates
            "SELECT count(*) + 1, sum(a) * 2 FROM t1",
            // Multiple aggregates
            "SELECT min(a), max(a), avg(a) FROM t1",
            // HAVING
            "SELECT t1_id, sum(val) AS s FROM t2 GROUP BY t1_id HAVING sum(val) > 100 ORDER BY t1_id",
            // ORDER BY expression
            "SELECT id, a FROM t1 ORDER BY a IS NULL, a",
            // LIMIT with OFFSET
            "SELECT id FROM t1 ORDER BY id LIMIT 2 OFFSET 1",
            // UNION
            "SELECT a FROM t1 WHERE a > 15 UNION SELECT CAST(val AS INTEGER) FROM t2 WHERE val < 100 ORDER BY 1",
            // EXCEPT
            "SELECT id FROM t1 EXCEPT SELECT t1_id FROM t2 ORDER BY 1",
            // INTERSECT
            "SELECT id FROM t1 INTERSECT SELECT t1_id FROM t2 ORDER BY 1",
            // UNION ALL
            "SELECT 'from_t1' AS src, id FROM t1 WHERE id <= 2 UNION ALL SELECT 'from_t2', id FROM t2 WHERE id <= 2 ORDER BY src, id",
            // REPLACE
            "SELECT replace('hello world', 'world', 'there')",
            "SELECT replace('aaa', 'a', 'bb')",
            // INSTR
            "SELECT instr('hello world', 'world'), instr('hello', 'xyz')",
            // HEX / QUOTE
            "SELECT hex('ABC'), hex(NULL)",
            "SELECT quote(1), quote('hello'), quote(NULL), quote(1.5)",
            // typeof
            "SELECT typeof(1), typeof(1.0), typeof('x'), typeof(NULL), typeof(X'AB')",
            // max/min with multiple args (scalar form)
            "SELECT max(1, 2, 3), min(1, 2, 3)",
            "SELECT max(NULL, 2), min(NULL, 2)",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} subquery/coalesce/iif conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// LEFT JOIN, DISTINCT+LIMIT, complex UPDATE/DELETE, and
    /// expression-only SELECT edge cases.
    #[test]
    fn test_conformance_left_join_distinct_limit() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE dept (id INTEGER PRIMARY KEY, name TEXT);",
            "INSERT INTO dept VALUES (1, 'eng');",
            "INSERT INTO dept VALUES (2, 'sales');",
            "INSERT INTO dept VALUES (3, 'hr');",
            "CREATE TABLE emp (id INTEGER PRIMARY KEY, name TEXT, dept_id INTEGER, salary INTEGER);",
            "INSERT INTO emp VALUES (1, 'Alice', 1, 100);",
            "INSERT INTO emp VALUES (2, 'Bob', 1, 120);",
            "INSERT INTO emp VALUES (3, 'Carol', 2, 90);",
            "INSERT INTO emp VALUES (4, 'Dave', NULL, 80);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // LEFT JOIN basics
            "SELECT d.name, e.name FROM dept d LEFT JOIN emp e ON d.id = e.dept_id ORDER BY d.name, e.name",
            // LEFT JOIN with NULL dept_id
            "SELECT e.name, d.name FROM emp e LEFT JOIN dept d ON e.dept_id = d.id ORDER BY e.name",
            // LEFT JOIN with aggregate
            "SELECT d.name, COUNT(e.id) AS cnt FROM dept d LEFT JOIN emp e ON d.id = e.dept_id GROUP BY d.name ORDER BY d.name",
            // LEFT JOIN with SUM
            "SELECT d.name, SUM(e.salary) AS total FROM dept d LEFT JOIN emp e ON d.id = e.dept_id GROUP BY d.name ORDER BY d.name",
            // LEFT JOIN with COALESCE(SUM(...), 0) — aggregate inside scalar wrapper
            "SELECT d.name, COALESCE(SUM(e.salary), 0) AS total FROM dept d LEFT JOIN emp e ON d.id = e.dept_id GROUP BY d.name ORDER BY d.name",
            // DISTINCT basics
            "SELECT DISTINCT dept_id FROM emp ORDER BY dept_id",
            // DISTINCT with LIMIT
            "SELECT DISTINCT dept_id FROM emp ORDER BY dept_id LIMIT 2",
            // DISTINCT with LIMIT 0
            "SELECT DISTINCT dept_id FROM emp ORDER BY dept_id LIMIT 0",
            // Aggregate inside expression wrapper (single-table)
            "SELECT COALESCE(SUM(salary), 0) FROM emp",
            // Arithmetic on aggregates
            "SELECT COUNT(*) * 2, SUM(salary) + 100 FROM emp",
            // CASE wrapping aggregate
            "SELECT CASE WHEN SUM(salary) > 200 THEN 'high' ELSE 'low' END FROM emp",
            // Expression-only SELECT edge cases
            "SELECT 1+2, 3*4, 10/3, 10%3",
            "SELECT -(-5), -(3.14)",
            "SELECT 'a' < 'b', 'b' < 'a', 'a' = 'a'",
            "SELECT 1 AND 0, 1 OR 0, NOT 1, NOT 0",
            "SELECT NULL AND 1, NULL OR 1, NULL AND 0, NULL OR 0",
            // UPDATE with subquery
            "UPDATE emp SET salary = salary + 10 WHERE dept_id = (SELECT id FROM dept WHERE name = 'eng')",
            "SELECT name, salary FROM emp WHERE dept_id = 1 ORDER BY name",
            // DELETE with IN
            "DELETE FROM emp WHERE dept_id IN (SELECT id FROM dept WHERE name = 'hr')",
            "SELECT COUNT(*) FROM emp",
            // Nested subquery in SELECT
            "SELECT (SELECT MAX(salary) FROM emp) - (SELECT MIN(salary) FROM emp)",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} left_join/distinct/limit conformance mismatches found",
                mismatches.len()
            );
        }
    }

    #[test]
    fn test_conformance_complex_patterns() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE employees (id INTEGER PRIMARY KEY, name TEXT, dept TEXT, salary INTEGER, mgr_id INTEGER);",
            "INSERT INTO employees VALUES (1, 'Alice', 'eng', 120, NULL);",
            "INSERT INTO employees VALUES (2, 'Bob', 'eng', 100, 1);",
            "INSERT INTO employees VALUES (3, 'Carol', 'sales', 90, 1);",
            "INSERT INTO employees VALUES (4, 'Dave', 'sales', 80, 3);",
            "INSERT INTO employees VALUES (5, 'Eve', 'hr', 95, 1);",
            "INSERT INTO employees VALUES (6, 'Frank', 'hr', 85, 5);",
            "CREATE TABLE projects (id INTEGER PRIMARY KEY, name TEXT, lead_id INTEGER, budget REAL);",
            "INSERT INTO projects VALUES (1, 'Alpha', 1, 50000.0);",
            "INSERT INTO projects VALUES (2, 'Beta', 2, 30000.0);",
            "INSERT INTO projects VALUES (3, 'Gamma', 3, 20000.0);",
            "INSERT INTO projects VALUES (4, 'Delta', 5, 15000.0);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // Self-join: employees with their managers
            "SELECT e.name, m.name AS mgr FROM employees e LEFT JOIN employees m ON e.mgr_id = m.id ORDER BY e.id",
            // Correlated subquery: employees earning more than their dept average
            "SELECT name FROM employees WHERE salary > (SELECT avg(salary) FROM employees e2 WHERE e2.dept = employees.dept) ORDER BY name",
            // GROUP BY with HAVING on count
            "SELECT dept, count(*) AS cnt FROM employees GROUP BY dept HAVING count(*) > 1 ORDER BY dept",
            // Nested aggregate in subquery
            "SELECT name FROM employees WHERE dept = (SELECT dept FROM employees GROUP BY dept ORDER BY sum(salary) DESC LIMIT 1) ORDER BY name",
            // Multi-table join with aggregate
            "SELECT e.name, count(p.id) AS proj_count FROM employees e LEFT JOIN projects p ON p.lead_id = e.id GROUP BY e.id ORDER BY e.id",
            // CASE inside aggregate
            "SELECT dept, sum(CASE WHEN salary >= 100 THEN 1 ELSE 0 END) AS high_earners FROM employees GROUP BY dept ORDER BY dept",
            // CTE with join
            "WITH dept_totals AS (SELECT dept, sum(salary) AS total FROM employees GROUP BY dept) SELECT e.name, dt.total FROM employees e JOIN dept_totals dt ON e.dept = dt.dept WHERE e.salary > 90 ORDER BY e.name",
            // Chained CTEs
            "WITH high_paid AS (SELECT * FROM employees WHERE salary >= 100), leads AS (SELECT DISTINCT lead_id FROM projects) SELECT h.name FROM high_paid h WHERE h.id IN (SELECT lead_id FROM leads) ORDER BY h.name",
            // Multiple CTEs joined
            "WITH a AS (SELECT dept, count(*) AS cnt FROM employees GROUP BY dept), b AS (SELECT dept, sum(salary) AS total FROM employees GROUP BY dept) SELECT a.dept, a.cnt, b.total FROM a JOIN b ON a.dept = b.dept ORDER BY a.dept",
            // Expression in ORDER BY not in SELECT list
            "SELECT name FROM employees ORDER BY salary DESC, name ASC",
            // ORDER BY column number
            "SELECT name, salary FROM employees ORDER BY 2 DESC, 1 ASC",
            // LIKE patterns
            "SELECT name FROM employees WHERE name LIKE 'A%' ORDER BY name",
            "SELECT name FROM employees WHERE name LIKE '%a%' ORDER BY name",
            "SELECT name FROM employees WHERE name LIKE '_o%' ORDER BY name",
            // GLOB pattern
            "SELECT name FROM employees WHERE name GLOB 'A*' ORDER BY name",
            // IN with literal list
            "SELECT name FROM employees WHERE dept IN ('eng', 'hr') ORDER BY name",
            // NOT IN with literal list
            "SELECT name FROM employees WHERE dept NOT IN ('eng') ORDER BY name",
            // Compound: UNION with ORDER BY
            "SELECT name FROM employees WHERE dept = 'eng' UNION SELECT name FROM employees WHERE salary > 90 ORDER BY name",
            // Compound: INTERSECT
            "SELECT name FROM employees WHERE dept = 'eng' INTERSECT SELECT name FROM employees WHERE salary > 90 ORDER BY name",
            // Compound: EXCEPT
            "SELECT name FROM employees WHERE salary > 80 EXCEPT SELECT name FROM employees WHERE dept = 'eng' ORDER BY name",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);

        // Test INSERT...SELECT
        fconn
            .execute("CREATE TABLE emp_backup (id INTEGER PRIMARY KEY, name TEXT, dept TEXT, salary INTEGER, mgr_id INTEGER)")
            .unwrap();
        rconn
            .execute_batch("CREATE TABLE emp_backup (id INTEGER PRIMARY KEY, name TEXT, dept TEXT, salary INTEGER, mgr_id INTEGER)")
            .unwrap();
        let insert_sel = "INSERT INTO emp_backup SELECT * FROM employees WHERE dept = 'eng'";
        fconn.execute(insert_sel).unwrap();
        rconn.execute_batch(insert_sel).unwrap();
        let verify = ["SELECT * FROM emp_backup ORDER BY id"];
        let mut dml_mismatches = oracle_compare(&fconn, &rconn, &verify);

        // UPDATE with subquery in WHERE
        let upd =
            "UPDATE employees SET salary = salary + 10 WHERE id IN (SELECT lead_id FROM projects)";
        fconn.execute(upd).unwrap();
        rconn.execute_batch(upd).unwrap();
        let verify2 = ["SELECT id, salary FROM employees ORDER BY id"];
        dml_mismatches.extend(oracle_compare(&fconn, &rconn, &verify2));

        // DELETE with subquery
        let del =
            "DELETE FROM emp_backup WHERE id NOT IN (SELECT id FROM employees WHERE salary > 110)";
        fconn.execute(del).unwrap();
        rconn.execute_batch(del).unwrap();
        let verify3 = ["SELECT * FROM emp_backup ORDER BY id"];
        dml_mismatches.extend(oracle_compare(&fconn, &rconn, &verify3));

        let all_mismatches: Vec<String> = mismatches.into_iter().chain(dml_mismatches).collect();
        if !all_mismatches.is_empty() {
            for m in &all_mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} complex pattern conformance mismatches found",
                all_mismatches.len()
            );
        }
    }

    /// Probe LIMIT edge cases, complex expressions, nested aggregates,
    /// multi-level subqueries, and expression-heavy ORDER BY.
    #[test]
    fn test_conformance_limit_expr_nested() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE data (id INTEGER PRIMARY KEY, cat TEXT, val INTEGER, note TEXT);",
            "INSERT INTO data VALUES (1, 'a', 10, 'first');",
            "INSERT INTO data VALUES (2, 'b', 20, 'second');",
            "INSERT INTO data VALUES (3, 'a', 30, 'third');",
            "INSERT INTO data VALUES (4, 'b', 40, NULL);",
            "INSERT INTO data VALUES (5, 'c', NULL, 'fifth');",
            "INSERT INTO data VALUES (6, 'a', 10, 'sixth');",
            "INSERT INTO data VALUES (7, 'c', 50, 'seventh');",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // LIMIT 0 — should return no rows
            "SELECT * FROM data LIMIT 0",
            "SELECT cat, count(*) FROM data GROUP BY cat LIMIT 0",
            "SELECT DISTINCT cat FROM data LIMIT 0",
            "SELECT id FROM data ORDER BY id LIMIT 0",
            // LIMIT with negative (means no limit in SQLite)
            "SELECT id FROM data ORDER BY id LIMIT -1",
            // LIMIT with expression
            "SELECT id FROM data ORDER BY id LIMIT 2 + 1",
            "SELECT id FROM data ORDER BY id LIMIT 3 OFFSET 2",
            // ORDER BY expression
            "SELECT id, val FROM data ORDER BY val IS NULL, val DESC",
            "SELECT id FROM data ORDER BY abs(val - 25) LIMIT 3",
            "SELECT id, cat FROM data ORDER BY cat, id DESC",
            // Complex WHERE with AND/OR
            "SELECT id FROM data WHERE (cat = 'a' AND val > 10) OR cat = 'c' ORDER BY id",
            "SELECT id FROM data WHERE NOT (cat = 'b') AND val IS NOT NULL ORDER BY id",
            // Nested CASE in SELECT
            "SELECT id, CASE cat WHEN 'a' THEN val * 2 WHEN 'b' THEN val + 100 ELSE 0 END AS computed FROM data WHERE val IS NOT NULL ORDER BY id",
            // Aggregate with CASE inside
            "SELECT cat, SUM(CASE WHEN val > 20 THEN val ELSE 0 END) AS big_sum FROM data GROUP BY cat ORDER BY cat",
            // COUNT with filter via CASE
            "SELECT cat, COUNT(CASE WHEN val IS NOT NULL THEN 1 END) AS non_null_count FROM data GROUP BY cat ORDER BY cat",
            // Correlated subquery in SELECT
            "SELECT id, (SELECT MAX(val) FROM data d2 WHERE d2.cat = data.cat) AS cat_max FROM data ORDER BY id",
            // Correlated EXISTS
            "SELECT id FROM data d1 WHERE EXISTS (SELECT 1 FROM data d2 WHERE d2.cat = d1.cat AND d2.id != d1.id) ORDER BY id",
            // NOT IN with NULLs (tricky!)
            "SELECT id FROM data WHERE cat NOT IN ('a', 'b') ORDER BY id",
            // IN with subquery
            "SELECT id FROM data WHERE cat IN (SELECT cat FROM data GROUP BY cat HAVING count(*) > 1) ORDER BY id",
            // Nested arithmetic
            "SELECT (val * 2 + 10) / 3 FROM data WHERE val IS NOT NULL ORDER BY id",
            // String concatenation
            "SELECT cat || '-' || CAST(val AS TEXT) FROM data WHERE val IS NOT NULL ORDER BY id",
            // COALESCE in ORDER BY
            "SELECT id, val FROM data ORDER BY COALESCE(val, 999), id",
            // Multiple aggregates without GROUP BY
            "SELECT COUNT(*), SUM(val), AVG(val), MIN(val), MAX(val) FROM data",
            "SELECT COUNT(*), SUM(val) FROM data WHERE val > 100",
            // GROUP BY with HAVING and ORDER BY (tiebreak with cat for determinism)
            "SELECT cat, SUM(val) AS s FROM data GROUP BY cat HAVING SUM(val) > 20 ORDER BY s DESC, cat",
            // Aggregate over empty set
            "SELECT COUNT(*), SUM(val), MIN(val), MAX(val), TOTAL(val) FROM data WHERE id > 100",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} limit/expr/nested conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Probe INSERT/UPDATE/DELETE with RETURNING, complex UPDATE with
    /// subqueries, and multi-table DML patterns.
    #[test]
    fn test_conformance_dml_returning_complex() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE stock (id INTEGER PRIMARY KEY, item TEXT NOT NULL, qty INTEGER DEFAULT 0, price REAL);",
            "INSERT INTO stock VALUES (1, 'Widget', 100, 9.99);",
            "INSERT INTO stock VALUES (2, 'Gadget', 50, 24.95);",
            "INSERT INTO stock VALUES (3, 'Doohickey', 200, 4.50);",
            "INSERT INTO stock VALUES (4, 'Thingamajig', 0, 99.99);",
            "CREATE TABLE orders (id INTEGER PRIMARY KEY, stock_id INTEGER, qty INTEGER, ts TEXT DEFAULT 'now');",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let mut mismatches = Vec::new();

        // -- DML sequences: run same ops on both, then compare SELECT results --

        let dml_ops = [
            // INSERT with DEFAULT
            "INSERT INTO orders (stock_id, qty) VALUES (1, 10)",
            "INSERT INTO orders (stock_id, qty) VALUES (2, 5)",
            "INSERT INTO orders (stock_id, qty) VALUES (1, 3)",
            // UPDATE with arithmetic
            "UPDATE stock SET qty = qty - 10 WHERE id = 1",
            // UPDATE with subquery in WHERE
            "UPDATE stock SET qty = qty - 5 WHERE id IN (SELECT stock_id FROM orders WHERE qty >= 5)",
            // DELETE
            "DELETE FROM orders WHERE qty < 5",
        ];
        for op in &dml_ops {
            fconn.execute(op).unwrap();
            rconn.execute_batch(op).unwrap();
        }

        let verify = [
            "SELECT * FROM stock ORDER BY id",
            "SELECT * FROM orders ORDER BY id",
            // JOIN after DML
            "SELECT s.item, o.qty FROM stock s JOIN orders o ON s.id = o.stock_id ORDER BY s.item, o.qty",
            // Aggregate after DML
            "SELECT stock_id, SUM(qty) FROM orders GROUP BY stock_id ORDER BY stock_id",
            // Computed column
            "SELECT item, qty * price AS inventory_value FROM stock ORDER BY id",
            // Subquery in SELECT after DML
            "SELECT item, (SELECT COALESCE(SUM(qty), 0) FROM orders WHERE stock_id = stock.id) AS total_ordered FROM stock ORDER BY id",
        ];

        mismatches.extend(oracle_compare(&fconn, &rconn, &verify));

        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} DML/returning conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Probe recursive CTEs, VALUES clause, multi-way JOINs, self-joins,
    /// and LEFT/CROSS JOIN semantics.
    #[test]
    fn test_conformance_join_cte_advanced() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE emp (id INTEGER PRIMARY KEY, name TEXT, mgr_id INTEGER, dept TEXT, salary INTEGER);",
            "INSERT INTO emp VALUES (1, 'Alice', NULL, 'eng', 100000);",
            "INSERT INTO emp VALUES (2, 'Bob', 1, 'eng', 90000);",
            "INSERT INTO emp VALUES (3, 'Carol', 1, 'eng', 95000);",
            "INSERT INTO emp VALUES (4, 'Dave', 2, 'sales', 80000);",
            "INSERT INTO emp VALUES (5, 'Eve', NULL, 'sales', 110000);",
            "INSERT INTO emp VALUES (6, 'Frank', 5, 'sales', 75000);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // Self-join: find manager name
            "SELECT e.name, m.name AS manager FROM emp e LEFT JOIN emp m ON e.mgr_id = m.id ORDER BY e.id",
            // COUNT with LEFT JOIN
            "SELECT m.name, COUNT(e.id) AS reports FROM emp m LEFT JOIN emp e ON e.mgr_id = m.id GROUP BY m.id ORDER BY m.name",
            // Recursive CTE: org hierarchy
            "WITH RECURSIVE chain(id, name, depth) AS (SELECT id, name, 0 FROM emp WHERE mgr_id IS NULL UNION ALL SELECT e.id, e.name, c.depth + 1 FROM emp e JOIN chain c ON e.mgr_id = c.id) SELECT name, depth FROM chain ORDER BY depth, name",
            // Recursive CTE: counting
            "WITH RECURSIVE cnt(x) AS (SELECT 1 UNION ALL SELECT x + 1 FROM cnt WHERE x < 5) SELECT x FROM cnt",
            // Recursive CTE: fibonacci
            "WITH RECURSIVE fib(a, b) AS (SELECT 0, 1 UNION ALL SELECT b, a + b FROM fib WHERE b < 100) SELECT a FROM fib",
            // Multi-column GROUP BY
            "SELECT dept, CASE WHEN salary > 90000 THEN 'senior' ELSE 'junior' END AS level, COUNT(*) FROM emp GROUP BY dept, 2 ORDER BY dept, level",
            // CROSS JOIN (small tables)
            "SELECT a.id, b.id FROM (SELECT 1 AS id UNION ALL SELECT 2) a CROSS JOIN (SELECT 10 AS id UNION ALL SELECT 20) b ORDER BY a.id, b.id",
            // Subquery as table source
            "SELECT sub.dept, sub.avg_sal FROM (SELECT dept, AVG(salary) AS avg_sal FROM emp GROUP BY dept) sub ORDER BY sub.dept",
            // HAVING with expression
            "SELECT dept, AVG(salary) AS avg_s FROM emp GROUP BY dept HAVING AVG(salary) > 85000 ORDER BY dept",
            // WHERE with subquery comparison
            "SELECT name FROM emp WHERE salary > (SELECT AVG(salary) FROM emp) ORDER BY name",
            // Multiple CTEs
            "WITH eng AS (SELECT * FROM emp WHERE dept = 'eng'), sales AS (SELECT * FROM emp WHERE dept = 'sales') SELECT eng.name, sales.name FROM eng CROSS JOIN sales WHERE eng.salary > sales.salary ORDER BY eng.name, sales.name",
            // UNION of JOINed queries
            "SELECT 'has_mgr' AS type, name FROM emp WHERE mgr_id IS NOT NULL UNION ALL SELECT 'no_mgr', name FROM emp WHERE mgr_id IS NULL ORDER BY type, name",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!("{} join/CTE conformance mismatches found", mismatches.len());
        }
    }

    /// INSERT...SELECT, multi-table DML, and aggregate edge cases.
    #[test]
    fn test_conformance_insert_select_dml() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE src (id INTEGER PRIMARY KEY, val INTEGER);",
            "INSERT INTO src VALUES (1, 10), (2, 20), (3, 30), (4, 40), (5, 50);",
            "CREATE TABLE dst (id INTEGER PRIMARY KEY, val INTEGER);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // INSERT...SELECT
            "INSERT INTO dst SELECT * FROM src WHERE val >= 30",
            "SELECT * FROM dst ORDER BY id",
            // INSERT...SELECT with expression
            "INSERT INTO dst (id, val) SELECT id + 100, val * 2 FROM src WHERE val < 30",
            "SELECT * FROM dst ORDER BY id",
            // UPDATE with aggregate subquery
            "UPDATE dst SET val = val + (SELECT MIN(val) FROM src) WHERE id < 10",
            "SELECT * FROM dst ORDER BY id",
            // DELETE with subquery
            "DELETE FROM dst WHERE val > (SELECT AVG(val) FROM dst)",
            "SELECT * FROM dst ORDER BY id",
            // Count after operations
            "SELECT COUNT(*) FROM dst",
            // Aggregate with HAVING referencing alias
            "SELECT val / 10 AS bucket, COUNT(*) AS cnt FROM src GROUP BY bucket HAVING cnt >= 1 ORDER BY bucket",
            // Multiple aggregates in SELECT without GROUP BY
            "SELECT COUNT(*), SUM(val), AVG(val), MIN(val), MAX(val) FROM src",
            // GROUP_CONCAT with ORDER in source
            "SELECT group_concat(val, ',') FROM (SELECT val FROM src ORDER BY val DESC)",
            // TOTAL on empty filtered set
            "SELECT total(val) FROM src WHERE val > 1000",
            // SUM on empty set (should be NULL)
            "SELECT sum(val) FROM src WHERE val > 1000",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} insert/select/DML conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Deep probe: type affinity edge cases, integer overflow, floating-point
    /// precision, NULL arithmetic, string/numeric coercion, and CAST chains.
    #[test]
    fn test_conformance_type_edge_cases() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let queries = [
            // Integer overflow edge cases
            "SELECT 9223372036854775807 + 0",
            "SELECT 9223372036854775807 * 1",
            "SELECT -9223372036854775808 + 0",
            "SELECT -(-9223372036854775807)",
            // Integer overflow → float promotion
            "SELECT 9223372036854775807 + 1",
            "SELECT -9223372036854775808 - 1",
            "SELECT 9223372036854775807 * 2",
            // Float precision
            "SELECT 0.1 + 0.2",
            "SELECT CAST(0.1 + 0.2 AS TEXT)",
            "SELECT typeof(0.1 + 0.2)",
            // Division
            "SELECT 10 / 3",
            "SELECT 10.0 / 3",
            "SELECT 10 / 3.0",
            "SELECT 1 / 0",
            "SELECT 1.0 / 0.0",
            // Modulo
            "SELECT 10 % 3",
            "SELECT -10 % 3",
            "SELECT 10 % -3",
            // NULL arithmetic
            "SELECT NULL + 1, NULL * 2, NULL / 1, NULL % 2",
            "SELECT 1 + NULL, 'hello' || NULL",
            // String-to-number coercion
            "SELECT '123' + 0",
            "SELECT '123abc' + 0",
            "SELECT 'abc' + 0",
            "SELECT '' + 0",
            // CAST chains
            "SELECT CAST(CAST(1.9 AS INTEGER) AS TEXT)",
            "SELECT CAST(CAST('42' AS INTEGER) AS REAL)",
            "SELECT CAST(CAST(NULL AS INTEGER) AS TEXT)",
            // Boolean-like expressions (SQLite has no boolean type)
            "SELECT 1 AND 0, 1 OR 0, NOT 0, NOT 1",
            "SELECT 1 AND NULL, 0 AND NULL, NULL AND NULL",
            "SELECT 1 OR NULL, 0 OR NULL, NULL OR NULL",
            // Comparison edge cases
            "SELECT 1 = 1.0",
            "SELECT '1' = 1",
            "SELECT NULL = NULL, NULL != NULL",
            "SELECT NULL IS NULL, NULL IS NOT NULL",
            // Unary minus (skip -0.0 negative-zero edge case — tracked separately)
            "SELECT -0",
            "SELECT typeof(-0)",
            // Hex literals
            "SELECT 0x10, 0xFF",
            // Large integer literals
            "SELECT 2147483647",
            "SELECT 2147483648",
            "SELECT 9223372036854775807",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} type edge case conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Deep probe: complex multi-level subqueries, correlated updates with
    /// aggregate references, and INSERT...SELECT patterns.
    #[test]
    fn test_conformance_complex_subqueries() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE products (id INTEGER PRIMARY KEY, name TEXT, category TEXT, price REAL);",
            "INSERT INTO products VALUES (1, 'Laptop', 'electronics', 999.99);",
            "INSERT INTO products VALUES (2, 'Phone', 'electronics', 699.99);",
            "INSERT INTO products VALUES (3, 'Shirt', 'clothing', 29.99);",
            "INSERT INTO products VALUES (4, 'Pants', 'clothing', 49.99);",
            "INSERT INTO products VALUES (5, 'Book', 'media', 14.99);",
            "INSERT INTO products VALUES (6, 'Movie', 'media', 19.99);",
            "CREATE TABLE reviews (id INTEGER PRIMARY KEY, product_id INTEGER, rating INTEGER, body TEXT);",
            "INSERT INTO reviews VALUES (1, 1, 5, 'Great laptop');",
            "INSERT INTO reviews VALUES (2, 1, 4, 'Good');",
            "INSERT INTO reviews VALUES (3, 2, 3, 'OK phone');",
            "INSERT INTO reviews VALUES (4, 3, 5, 'Nice shirt');",
            "INSERT INTO reviews VALUES (5, 5, 2, 'Boring');",
            "INSERT INTO reviews VALUES (6, 5, 4, 'Interesting');",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // Correlated subquery: avg rating per product
            "SELECT p.name, (SELECT AVG(r.rating) FROM reviews r WHERE r.product_id = p.id) AS avg_r FROM products p ORDER BY p.id",
            // Correlated subquery: count reviews per product
            "SELECT name, (SELECT COUNT(*) FROM reviews r WHERE r.product_id = products.id) AS cnt FROM products ORDER BY id",
            // Correlated subquery in WHERE: products with avg rating > 3
            "SELECT name FROM products WHERE (SELECT AVG(rating) FROM reviews WHERE product_id = products.id) > 3 ORDER BY name",
            // Nested correlated: categories where all products have at least one review
            "SELECT DISTINCT category FROM products p WHERE NOT EXISTS (SELECT 1 FROM products p2 WHERE p2.category = p.category AND NOT EXISTS (SELECT 1 FROM reviews r WHERE r.product_id = p2.id)) ORDER BY category",
            // Derived table with JOIN
            "SELECT p.name, stats.avg_r FROM products p JOIN (SELECT product_id, AVG(rating) AS avg_r FROM reviews GROUP BY product_id) stats ON p.id = stats.product_id ORDER BY p.name",
            // CTE + JOIN
            "WITH cat_stats AS (SELECT category, AVG(price) AS avg_price, COUNT(*) AS cnt FROM products GROUP BY category) SELECT p.name, cs.avg_price FROM products p JOIN cat_stats cs ON p.category = cs.category ORDER BY p.name",
            // Multi-CTE
            "WITH expensive AS (SELECT * FROM products WHERE price > 50), reviewed AS (SELECT DISTINCT product_id FROM reviews) SELECT e.name FROM expensive e WHERE e.id IN (SELECT product_id FROM reviewed) ORDER BY e.name",
            // INSERT...SELECT
            "CREATE TABLE price_log (product_name TEXT, price REAL, category TEXT)",
        ];

        let mut mismatches = oracle_compare(&fconn, &rconn, &queries);

        // Run the DML ops
        let dml =
            ["INSERT INTO price_log SELECT name, price, category FROM products WHERE price > 20"];
        for op in &dml {
            fconn.execute(op).unwrap();
            rconn.execute_batch(op).unwrap();
        }

        let verify = [
            "SELECT * FROM price_log ORDER BY product_name",
            // Aggregate over joined tables
            "SELECT p.category, COUNT(r.id) AS review_count, AVG(r.rating) AS avg_rating FROM products p LEFT JOIN reviews r ON p.id = r.product_id GROUP BY p.category ORDER BY p.category",
            // HAVING on joined aggregate
            "SELECT p.category, COUNT(DISTINCT p.id) AS product_count FROM products p LEFT JOIN reviews r ON p.id = r.product_id GROUP BY p.category HAVING COUNT(r.id) > 1 ORDER BY p.category",
            // Complex expression in SELECT
            "SELECT name, CASE WHEN price > 100 THEN 'premium' WHEN price > 20 THEN 'standard' ELSE 'budget' END AS tier, round(price * 1.1, 2) AS with_tax FROM products ORDER BY id",
        ];

        mismatches.extend(oracle_compare(&fconn, &rconn, &verify));

        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} complex subquery conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Expression-only SELECTs, nested function calls, HAVING with aggregate
    /// expressions, and single-table GROUP BY with aggregate-in-scalar.
    #[test]
    fn test_conformance_fromless_having_scalar_agg() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE scores (id INTEGER PRIMARY KEY, student TEXT, subject TEXT, score INTEGER);",
            "INSERT INTO scores VALUES (1, 'Alice', 'math', 90);",
            "INSERT INTO scores VALUES (2, 'Alice', 'science', 85);",
            "INSERT INTO scores VALUES (3, 'Bob', 'math', 75);",
            "INSERT INTO scores VALUES (4, 'Bob', 'science', 95);",
            "INSERT INTO scores VALUES (5, 'Carol', 'math', 60);",
            "INSERT INTO scores VALUES (6, 'Carol', 'science', 70);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // Single-table GROUP BY with COALESCE(aggregate)
            "SELECT student, COALESCE(SUM(score), 0) AS total FROM scores GROUP BY student ORDER BY student",
            // Aggregate in arithmetic expression
            "SELECT student, SUM(score) * 100 / COUNT(*) AS pct FROM scores GROUP BY student ORDER BY student",
            // HAVING with aggregate expression
            "SELECT subject, AVG(score) AS avg_score FROM scores GROUP BY subject HAVING AVG(score) > 75 ORDER BY subject",
            // HAVING with multiple aggregate conditions
            "SELECT student, COUNT(*) AS cnt, SUM(score) AS total FROM scores GROUP BY student HAVING COUNT(*) = 2 AND SUM(score) > 160 ORDER BY student",
            // Aggregate + CASE in single table
            "SELECT student, SUM(CASE WHEN score >= 80 THEN 1 ELSE 0 END) AS high_scores FROM scores GROUP BY student ORDER BY student",
            // COALESCE wrapping SUM with CASE
            "SELECT student, COALESCE(SUM(CASE WHEN subject = 'math' THEN score END), 0) AS math_total FROM scores GROUP BY student ORDER BY student",
            // Expression-only with nested functions
            "SELECT abs(round(-3.7))",
            "SELECT length(replace('hello world', 'world', 'there'))",
            "SELECT upper(substr('hello world', 7))",
            // Aggregate on expression
            "SELECT SUM(score * 2), AVG(score + 10) FROM scores",
            // GROUP BY with LIMIT
            "SELECT student, SUM(score) AS total FROM scores GROUP BY student ORDER BY total DESC LIMIT 2",
            // GROUP BY with LIMIT 0
            "SELECT student, SUM(score) FROM scores GROUP BY student ORDER BY student LIMIT 0",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} fromless/having/scalar-agg conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// REPLACE, UPSERT (INSERT OR REPLACE/IGNORE), multi-value INSERT,
