    /// Multi-table JOIN patterns, self-join, CROSS JOIN, and complex
    /// WHERE conditions with subqueries and expressions.
    #[test]
    fn test_conformance_join_patterns() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE t1 (id INTEGER PRIMARY KEY, val TEXT, grp INTEGER);",
            "INSERT INTO t1 VALUES (1, 'a', 1);",
            "INSERT INTO t1 VALUES (2, 'b', 1);",
            "INSERT INTO t1 VALUES (3, 'c', 2);",
            "INSERT INTO t1 VALUES (4, 'd', 2);",
            "INSERT INTO t1 VALUES (5, 'e', 3);",
            "CREATE TABLE t2 (id INTEGER PRIMARY KEY, t1_id INTEGER, score INTEGER);",
            "INSERT INTO t2 VALUES (1, 1, 100);",
            "INSERT INTO t2 VALUES (2, 2, 200);",
            "INSERT INTO t2 VALUES (3, 3, 300);",
            "INSERT INTO t2 VALUES (4, 1, 150);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // Self-join
            "SELECT a.val, b.val FROM t1 a, t1 b WHERE a.grp = b.grp AND a.id < b.id ORDER BY a.val, b.val",
            // CROSS JOIN
            "SELECT t1.val, t2.score FROM t1 CROSS JOIN t2 WHERE t1.id = 1 ORDER BY t2.score",
            // Multiple JOINs
            "SELECT t1.val, t2.score FROM t1 JOIN t2 ON t1.id = t2.t1_id ORDER BY t1.val, t2.score",
            // LEFT JOIN with IS NULL (anti-join pattern)
            "SELECT t1.val FROM t1 LEFT JOIN t2 ON t1.id = t2.t1_id WHERE t2.id IS NULL ORDER BY t1.val",
            // Subquery in WHERE with multiple conditions
            "SELECT val FROM t1 WHERE grp = (SELECT grp FROM t1 WHERE val = 'a') AND id > 1 ORDER BY val",
            // EXISTS with correlated subquery
            "SELECT val FROM t1 WHERE EXISTS (SELECT 1 FROM t2 WHERE t2.t1_id = t1.id AND t2.score > 150) ORDER BY val",
            // NOT IN with subquery
            "SELECT val FROM t1 WHERE id NOT IN (SELECT t1_id FROM t2) ORDER BY val",
            // Aggregate with HAVING and ORDER BY alias
            "SELECT grp, SUM(LENGTH(val)) AS total_len FROM t1 GROUP BY grp HAVING total_len > 1 ORDER BY grp",
            // Subquery as derived table with alias
            "SELECT sub.max_score FROM (SELECT t1_id, MAX(score) AS max_score FROM t2 GROUP BY t1_id) sub ORDER BY sub.max_score DESC",
            // UNION of self-join results
            "SELECT val FROM t1 WHERE grp = 1 UNION SELECT val FROM t1 WHERE grp = 2 ORDER BY 1",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} join patterns conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Deep probe: NULL propagation through arithmetic and comparisons,
    /// mixed-type IN lists, BETWEEN edge cases, complex CASE WHEN.
    #[test]
    fn test_conformance_null_and_type_edge_cases() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE t (id INTEGER PRIMARY KEY, a INTEGER, b REAL, c TEXT, d BLOB);",
            "INSERT INTO t VALUES (1, 10, 1.5, 'hello', X'CAFE');",
            "INSERT INTO t VALUES (2, NULL, 2.5, NULL, NULL);",
            "INSERT INTO t VALUES (3, 0, 0.0, '', X'');",
            "INSERT INTO t VALUES (4, -5, -1.5, 'world', X'BABE');",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // NULL arithmetic propagation
            "SELECT NULL + 1, NULL * 2, NULL - 3, NULL / 4",
            "SELECT a + NULL, NULL + a FROM t ORDER BY id",
            // NULL comparison returns NULL (not true/false)
            "SELECT NULL = NULL, NULL != NULL, NULL < 1, NULL > 1",
            "SELECT NULL = 0, NULL != 0",
            // NULL in CASE WHEN
            "SELECT CASE NULL WHEN NULL THEN 'match' ELSE 'no' END",
            "SELECT CASE WHEN NULL THEN 'true' ELSE 'false' END",
            // IN with mixed types
            "SELECT 1 IN (1, 2, 3), 1 IN (1.0, 2, 3)",
            "SELECT 'a' IN ('a', 'b', 'c')",
            "SELECT NULL IN (1, 2, 3), 1 IN (1, NULL, 3)",
            // BETWEEN edge cases
            "SELECT 5 BETWEEN 1 AND 10, 0 BETWEEN 1 AND 10",
            "SELECT NULL BETWEEN 1 AND 10, 5 BETWEEN NULL AND 10, 5 BETWEEN 1 AND NULL",
            // NOT BETWEEN
            "SELECT 5 NOT BETWEEN 1 AND 10, 0 NOT BETWEEN 1 AND 10",
            // Boolean expressions
            "SELECT 1 AND 1, 1 AND 0, 0 AND 0",
            "SELECT 1 OR 0, 0 OR 0, 1 OR 1",
            "SELECT NOT 1, NOT 0, NOT NULL",
            // Truthiness
            "SELECT CASE WHEN 0 THEN 'yes' ELSE 'no' END",
            "SELECT CASE WHEN '' THEN 'yes' ELSE 'no' END",
            "SELECT CASE WHEN 0.0 THEN 'yes' ELSE 'no' END",
            // IFNULL / NULLIF
            "SELECT ifnull(NULL, 'default'), ifnull('value', 'default')",
            "SELECT nullif(1, 1), nullif(1, 2), nullif(NULL, 1)",
            // Type affinity in comparisons
            "SELECT '10' > 9, '10' > '9'",
            "SELECT typeof('10' + 0), typeof(10 || '')",
            // Concatenation with NULL
            "SELECT 'a' || NULL, NULL || 'b', NULL || NULL",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!("{} NULL/type edge case mismatches found", mismatches.len());
        }
    }

    /// VDBE codegen path: single-table queries with WHERE, ORDER BY, LIMIT,
    /// and index scans that go through compile_table_select.
    #[test]
    fn test_conformance_vdbe_codegen_path() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE users (id INTEGER PRIMARY KEY, name TEXT NOT NULL, age INTEGER, email TEXT);",
            "CREATE INDEX idx_users_age ON users(age);",
            "CREATE INDEX idx_users_name ON users(name);",
            "INSERT INTO users VALUES (1, 'Alice', 30, 'alice@example.com');",
            "INSERT INTO users VALUES (2, 'Bob', 25, 'bob@example.com');",
            "INSERT INTO users VALUES (3, 'Carol', 35, NULL);",
            "INSERT INTO users VALUES (4, 'Dave', 25, 'dave@example.com');",
            "INSERT INTO users VALUES (5, 'Eve', 40, 'eve@example.com');",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // Basic full-table scan
            "SELECT * FROM users ORDER BY id",
            // Simple WHERE
            "SELECT name FROM users WHERE age > 30 ORDER BY name",
            // WHERE with AND
            "SELECT name FROM users WHERE age >= 25 AND age <= 35 ORDER BY name",
            // WHERE with OR
            "SELECT name FROM users WHERE age = 25 OR age = 40 ORDER BY name",
            // WHERE with NOT
            "SELECT name FROM users WHERE NOT (age > 30) ORDER BY name",
            // WHERE IS NULL
            "SELECT name FROM users WHERE email IS NULL",
            // WHERE IS NOT NULL
            "SELECT name FROM users WHERE email IS NOT NULL ORDER BY name",
            // ORDER BY DESC
            "SELECT name, age FROM users ORDER BY age DESC, name ASC",
            // LIMIT
            "SELECT name FROM users ORDER BY id LIMIT 3",
            // LIMIT with OFFSET
            "SELECT name FROM users ORDER BY id LIMIT 2 OFFSET 2",
            // LIMIT 0
            "SELECT name FROM users ORDER BY id LIMIT 0",
            // LIMIT 1
            "SELECT name FROM users ORDER BY id LIMIT 1",
            // COUNT with WHERE
            "SELECT COUNT(*) FROM users WHERE age > 30",
            // Multiple columns with expressions
            "SELECT id, name, age * 2 AS double_age FROM users ORDER BY id",
            // WHERE with LIKE
            "SELECT name FROM users WHERE name LIKE 'A%' ORDER BY name",
            // WHERE with IN list
            "SELECT name FROM users WHERE age IN (25, 35) ORDER BY name",
            // DISTINCT
            "SELECT DISTINCT age FROM users ORDER BY age",
            // WHERE with BETWEEN
            "SELECT name FROM users WHERE age BETWEEN 25 AND 35 ORDER BY name",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} VDBE codegen conformance mismatches found",
                mismatches.len()
            );
        }
    }

    #[test]
    fn test_explain_query_plan_reports_planner_selected_detail() {
        let conn = Connection::open(":memory:").unwrap();
        conn.execute(
            "CREATE TABLE users (id INTEGER PRIMARY KEY, name TEXT NOT NULL, age INTEGER);",
        )
        .unwrap();
        conn.execute("CREATE INDEX idx_users_age ON users(age);")
            .unwrap();
        conn.execute("INSERT INTO users VALUES (1, 'Alice', 30);")
            .unwrap();
        conn.execute("INSERT INTO users VALUES (2, 'Bob', 25);")
            .unwrap();

        let rowid_rows = conn
            .query("EXPLAIN QUERY PLAN SELECT name FROM users WHERE rowid = 1")
            .unwrap();
        assert_eq!(
            rowid_rows[0].values[3],
            SqliteValue::Text("SEARCH users USING INTEGER PRIMARY KEY (rowid=?)".into()),
        );

        let index_rows = conn
            .query("EXPLAIN QUERY PLAN SELECT name FROM users WHERE age = 25")
            .unwrap();
        assert_eq!(
            index_rows[0].values[3],
            SqliteValue::Text("SEARCH users USING INDEX idx_users_age (age=?)".into()),
        );

        let covering_rows = conn
            .query("EXPLAIN QUERY PLAN SELECT age FROM users WHERE age = 25")
            .unwrap();
        assert_eq!(
            covering_rows[0].values[3],
            SqliteValue::Text("SEARCH users USING COVERING INDEX idx_users_age (age=?)".into()),
        );
    }

    #[test]
    fn test_single_row_fast_paths_honor_limit_and_offset() {
        let conn = Connection::open(":memory:").unwrap();
        conn.execute(
            "CREATE TABLE users (id INTEGER PRIMARY KEY, name TEXT NOT NULL, age INTEGER);",
        )
        .unwrap();
        conn.execute("CREATE INDEX idx_users_age ON users(age);")
            .unwrap();
        conn.execute("INSERT INTO users VALUES (1, 'Alice', 30);")
            .unwrap();
        conn.execute("INSERT INTO users VALUES (2, 'Bob', 25);")
            .unwrap();

        let rowid_limit_zero = conn
            .query("SELECT name FROM users WHERE rowid = 1 LIMIT 0")
            .unwrap();
        assert!(rowid_limit_zero.is_empty());

        let rowid_offset_skip = conn
            .query("SELECT name FROM users WHERE rowid = 1 LIMIT 1 OFFSET 1")
            .unwrap();
        assert!(rowid_offset_skip.is_empty());

        let index_limit_zero = conn
            .query("SELECT name FROM users WHERE age = 25 LIMIT 0")
            .unwrap();
        assert!(index_limit_zero.is_empty());

        let index_offset_skip = conn
            .query("SELECT name FROM users WHERE age = 25 LIMIT 1 OFFSET 1")
            .unwrap();
        assert!(index_offset_skip.is_empty());
    }

    #[test]
    fn test_conformance_multi_join_order_expr() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE authors (id INTEGER PRIMARY KEY, name TEXT);",
            "INSERT INTO authors VALUES (1, 'Alice');",
            "INSERT INTO authors VALUES (2, 'Bob');",
            "INSERT INTO authors VALUES (3, 'Carol');",
            "CREATE TABLE books (id INTEGER PRIMARY KEY, title TEXT, author_id INTEGER, year INTEGER);",
            "INSERT INTO books VALUES (1, 'Book A', 1, 2020);",
            "INSERT INTO books VALUES (2, 'Book B', 1, 2021);",
            "INSERT INTO books VALUES (3, 'Book C', 2, 2019);",
            "INSERT INTO books VALUES (4, 'Book D', 2, 2022);",
            "INSERT INTO books VALUES (5, 'Book E', 3, 2020);",
            "CREATE TABLE reviews (id INTEGER PRIMARY KEY, book_id INTEGER, rating INTEGER, reviewer TEXT);",
            "INSERT INTO reviews VALUES (1, 1, 5, 'Dan');",
            "INSERT INTO reviews VALUES (2, 1, 4, 'Eve');",
            "INSERT INTO reviews VALUES (3, 2, 3, 'Dan');",
            "INSERT INTO reviews VALUES (4, 3, 5, 'Eve');",
            "INSERT INTO reviews VALUES (5, 4, 2, 'Dan');",
            "INSERT INTO reviews VALUES (6, 5, 4, 'Dan');",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // Three-way JOIN
            "SELECT a.name, b.title, r.rating FROM authors a JOIN books b ON b.author_id = a.id JOIN reviews r ON r.book_id = b.id ORDER BY a.name, b.title",
            // Three-way JOIN with aggregate
            "SELECT a.name, count(r.id) AS review_count FROM authors a JOIN books b ON b.author_id = a.id JOIN reviews r ON r.book_id = b.id GROUP BY a.name ORDER BY a.name",
            // Three-way JOIN with aggregate + HAVING
            "SELECT a.name, avg(r.rating) AS avg_rating FROM authors a JOIN books b ON b.author_id = a.id JOIN reviews r ON r.book_id = b.id GROUP BY a.name HAVING avg(r.rating) >= 4.0 ORDER BY a.name",
            // LEFT JOIN preserving unmatched (secondary sort for stability)
            "SELECT b.title, r.rating FROM books b LEFT JOIN reviews r ON r.book_id = b.id ORDER BY b.title, r.rating",
            // ORDER BY expression not in SELECT (non-GROUP BY)
            "SELECT title FROM books ORDER BY year DESC, title ASC",
            // ORDER BY with CASE expression
            "SELECT title, year FROM books ORDER BY CASE WHEN year >= 2021 THEN 0 ELSE 1 END, title",
            // Multi-column DISTINCT
            "SELECT DISTINCT author_id, year FROM books ORDER BY author_id, year",
            // Single-table correlated subqueries (VDBE codegen path)
            "SELECT a.name, (SELECT count(*) FROM books b WHERE b.author_id = a.id) AS book_count FROM authors a ORDER BY a.name",
            // COALESCE with single-table subquery
            "SELECT a.name, COALESCE((SELECT max(b.year) FROM books b WHERE b.author_id = a.id), 0) AS latest FROM authors a ORDER BY a.name",
            // Correlated scalar subqueries with JOINs (connection-level fallback)
            "SELECT a.name, (SELECT avg(r.rating) FROM books b JOIN reviews r ON r.book_id = b.id WHERE b.author_id = a.id) AS avg_rating FROM authors a ORDER BY a.name",
            // COALESCE wrapping a correlated JOIN subquery
            "SELECT a.name, COALESCE((SELECT count(r.id) FROM books b JOIN reviews r ON r.book_id = b.id WHERE b.author_id = a.id), 0) AS review_count FROM authors a ORDER BY a.name",
            // Complex WHERE with AND/OR/NOT
            "SELECT title FROM books WHERE (year > 2019 AND author_id = 1) OR (year < 2021 AND author_id = 2) ORDER BY title",
            // NULL handling in ORDER BY
            "SELECT b.title, r.rating FROM books b LEFT JOIN reviews r ON r.book_id = b.id ORDER BY r.rating IS NULL, r.rating DESC, b.title",
            // GROUP BY with ORDER BY on aggregate not in SELECT
            "SELECT a.name FROM authors a JOIN books b ON b.author_id = a.id GROUP BY a.name ORDER BY count(b.id) DESC, a.name",
            // CASE with aggregate
            "SELECT a.name, CASE WHEN count(b.id) > 1 THEN 'prolific' ELSE 'modest' END AS output FROM authors a JOIN books b ON b.author_id = a.id GROUP BY a.name ORDER BY a.name",
            // Nested CASE
            "SELECT title, CASE WHEN year >= 2022 THEN 'new' WHEN year >= 2020 THEN 'recent' ELSE 'old' END AS era FROM books ORDER BY title",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} multi-join/order-expr conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Correlated scalar subqueries whose FROM clause contains JOINs.
    /// Validates the connection-level fallback that inline-evaluates such
    /// subqueries by substituting outer references and executing per-row.
    #[test]
    fn test_conformance_correlated_join_subqueries() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE departments (id INTEGER PRIMARY KEY, name TEXT);",
            "INSERT INTO departments VALUES (1, 'Engineering');",
            "INSERT INTO departments VALUES (2, 'Marketing');",
            "INSERT INTO departments VALUES (3, 'Sales');",
            "CREATE TABLE employees (id INTEGER PRIMARY KEY, name TEXT, dept_id INTEGER, salary INTEGER);",
            "INSERT INTO employees VALUES (1, 'Alice', 1, 120000);",
            "INSERT INTO employees VALUES (2, 'Bob', 1, 110000);",
            "INSERT INTO employees VALUES (3, 'Carol', 2, 95000);",
            "INSERT INTO employees VALUES (4, 'Dan', 2, 90000);",
            "INSERT INTO employees VALUES (5, 'Eve', 3, 85000);",
            "CREATE TABLE projects (id INTEGER PRIMARY KEY, name TEXT, lead_id INTEGER, dept_id INTEGER);",
            "INSERT INTO projects VALUES (1, 'Alpha', 1, 1);",
            "INSERT INTO projects VALUES (2, 'Beta', 2, 1);",
            "INSERT INTO projects VALUES (3, 'Gamma', 3, 2);",
            "CREATE TABLE tasks (id INTEGER PRIMARY KEY, project_id INTEGER, assignee_id INTEGER, status TEXT);",
            "INSERT INTO tasks VALUES (1, 1, 1, 'done');",
            "INSERT INTO tasks VALUES (2, 1, 2, 'done');",
            "INSERT INTO tasks VALUES (3, 2, 1, 'active');",
            "INSERT INTO tasks VALUES (4, 2, 2, 'done');",
            "INSERT INTO tasks VALUES (5, 3, 3, 'active');",
            "INSERT INTO tasks VALUES (6, 3, 4, 'done');",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // Basic correlated single-table subquery (baseline)
            "SELECT d.name, (SELECT avg(e.salary) FROM employees e WHERE e.dept_id = d.id) AS avg_sal FROM departments d ORDER BY d.name",
            // Correlated subquery with JOIN in FROM
            "SELECT d.name, (SELECT count(t.id) FROM projects p JOIN tasks t ON t.project_id = p.id WHERE p.dept_id = d.id) AS task_count FROM departments d ORDER BY d.name",
            // COALESCE wrapping correlated JOIN subquery
            "SELECT d.name, COALESCE((SELECT sum(e.salary) FROM employees e JOIN projects p ON p.lead_id = e.id WHERE p.dept_id = d.id), 0) AS lead_salary_sum FROM departments d ORDER BY d.name",
            // Multiple correlated subqueries in same SELECT
            "SELECT d.name, (SELECT count(*) FROM employees e WHERE e.dept_id = d.id) AS emp_count, (SELECT count(t.id) FROM projects p JOIN tasks t ON t.project_id = p.id WHERE p.dept_id = d.id) AS task_count FROM departments d ORDER BY d.name",
            // Correlated JOIN subquery with aggregate filter
            "SELECT d.name, (SELECT count(t.id) FROM projects p JOIN tasks t ON t.project_id = p.id WHERE p.dept_id = d.id AND t.status = 'done') AS done_tasks FROM departments d ORDER BY d.name",
            // Correlated JOIN subquery returning NULL for unmatched
            "SELECT d.name, (SELECT max(t.id) FROM projects p JOIN tasks t ON t.project_id = p.id WHERE p.dept_id = d.id AND t.status = 'cancelled') AS max_cancelled FROM departments d ORDER BY d.name",
            // Three-table correlated subquery
            "SELECT d.name, (SELECT count(DISTINCT t.assignee_id) FROM projects p JOIN tasks t ON t.project_id = p.id JOIN employees e ON e.id = t.assignee_id WHERE p.dept_id = d.id) AS unique_workers FROM departments d ORDER BY d.name",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} correlated join subquery conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Implicit aggregation (no GROUP BY), round edge cases, and mixed
    /// aggregate/scalar expressions in GROUP BY.
    #[test]
    fn test_conformance_implicit_agg_and_round() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE nums (id INTEGER PRIMARY KEY, val REAL, label TEXT);",
            "INSERT INTO nums VALUES (1, 1.5, 'a');",
            "INSERT INTO nums VALUES (2, 2.5, 'a');",
            "INSERT INTO nums VALUES (3, 3.5, 'b');",
            "INSERT INTO nums VALUES (4, 4.5, 'b');",
            "INSERT INTO nums VALUES (5, 5.5, 'c');",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // Implicit aggregation — no GROUP BY
            "SELECT count(*) FROM nums",
            "SELECT sum(val), avg(val) FROM nums",
            "SELECT min(val), max(val) FROM nums",
            // Implicit aggregation on empty result
            "SELECT count(*) FROM nums WHERE val > 100",
            "SELECT sum(val) FROM nums WHERE val > 100",
            "SELECT avg(val) FROM nums WHERE val > 100",
            // round edge cases
            "SELECT round(2.5)",
            "SELECT round(3.5)",
            "SELECT round(2.55, 1)",
            "SELECT round(2.45, 1)",
            "SELECT round(-2.5)",
            "SELECT round(-3.5)",
            "SELECT round(0.5)",
            "SELECT round(1.5)",
            "SELECT round(2.225, 2)",
            "SELECT round(2.235, 2)",
            "SELECT round(2.245, 2)",
            "SELECT round(2.255, 2)",
            // Mixed aggregate + scalar in GROUP BY result
            "SELECT label, count(*) AS cnt, round(avg(val), 1) AS avg_val FROM nums GROUP BY label ORDER BY label",
            "SELECT label, sum(val) * 2 AS double_sum FROM nums GROUP BY label ORDER BY label",
            "SELECT label, max(val) - min(val) AS range_val FROM nums GROUP BY label ORDER BY label",
            // Aggregate with HAVING
            "SELECT label, count(*) AS cnt FROM nums GROUP BY label HAVING count(*) >= 2 ORDER BY label",
            "SELECT label, avg(val) AS avg_val FROM nums GROUP BY label HAVING avg(val) > 3.0 ORDER BY label",
            // Implicit aggregation on joined empty result
            "SELECT count(*) FROM nums n1 JOIN nums n2 ON n1.id = n2.id WHERE n1.val > 100",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} implicit agg/round conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// EXISTS subqueries, IN subqueries, WHERE-clause subqueries, and
    /// complex expression patterns.
    #[test]
    fn test_conformance_subquery_expressions() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE t1 (id INTEGER PRIMARY KEY, val TEXT, grp INTEGER);",
            "INSERT INTO t1 VALUES (1, 'alpha', 1);",
            "INSERT INTO t1 VALUES (2, 'beta', 1);",
            "INSERT INTO t1 VALUES (3, 'gamma', 2);",
            "INSERT INTO t1 VALUES (4, 'delta', 2);",
            "INSERT INTO t1 VALUES (5, 'epsilon', 3);",
            "CREATE TABLE t2 (id INTEGER PRIMARY KEY, t1_id INTEGER, score INTEGER);",
            "INSERT INTO t2 VALUES (1, 1, 90);",
            "INSERT INTO t2 VALUES (2, 2, 85);",
            "INSERT INTO t2 VALUES (3, 3, 95);",
            "INSERT INTO t2 VALUES (4, 5, 70);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // EXISTS subquery
            "SELECT val FROM t1 WHERE EXISTS (SELECT 1 FROM t2 WHERE t2.t1_id = t1.id) ORDER BY val",
            // NOT EXISTS
            "SELECT val FROM t1 WHERE NOT EXISTS (SELECT 1 FROM t2 WHERE t2.t1_id = t1.id) ORDER BY val",
            // IN subquery
            "SELECT val FROM t1 WHERE id IN (SELECT t1_id FROM t2) ORDER BY val",
            // NOT IN subquery
            "SELECT val FROM t1 WHERE id NOT IN (SELECT t1_id FROM t2) ORDER BY val",
            // Scalar subquery in WHERE
            "SELECT val FROM t1 WHERE (SELECT max(score) FROM t2 WHERE t2.t1_id = t1.id) > 80 ORDER BY val",
            // Scalar subquery comparison
            "SELECT val FROM t1 WHERE grp = (SELECT grp FROM t1 WHERE val = 'alpha') ORDER BY val",
            // CASE with subquery
            "SELECT val, CASE WHEN (SELECT count(*) FROM t2 WHERE t2.t1_id = t1.id) > 0 THEN 'has_score' ELSE 'no_score' END AS status FROM t1 ORDER BY val",
            // Aggregate over expression
            "SELECT grp, count(*) AS cnt, group_concat(val, ', ') AS vals FROM t1 GROUP BY grp ORDER BY grp",
            // COALESCE with subquery
            "SELECT val, COALESCE((SELECT score FROM t2 WHERE t2.t1_id = t1.id), -1) AS score FROM t1 ORDER BY val",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} subquery expression conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// LIMIT/OFFSET edge cases across different query paths, UNION/INTERSECT/EXCEPT,
    /// and type coercion in comparisons.
    #[test]
    fn test_conformance_limit_union_coercion() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE items (id INTEGER PRIMARY KEY, name TEXT, price REAL, qty INTEGER);",
            "INSERT INTO items VALUES (1, 'A', 10.5, 100);",
            "INSERT INTO items VALUES (2, 'B', 20.0, 50);",
            "INSERT INTO items VALUES (3, 'C', 15.75, 75);",
            "INSERT INTO items VALUES (4, 'D', 5.25, 200);",
            "INSERT INTO items VALUES (5, 'E', 30.0, 25);",
            "INSERT INTO items VALUES (6, 'F', 12.0, 150);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // LIMIT only
            "SELECT name FROM items ORDER BY id LIMIT 3",
            // LIMIT + OFFSET
            "SELECT name FROM items ORDER BY id LIMIT 3 OFFSET 2",
            // LIMIT 0
            "SELECT name FROM items ORDER BY id LIMIT 0",
            // LIMIT larger than result set
            "SELECT name FROM items ORDER BY id LIMIT 100",
            // OFFSET larger than result set
            "SELECT name FROM items ORDER BY id LIMIT 10 OFFSET 100",
            // LIMIT on GROUP BY
            "SELECT qty, count(*) AS cnt FROM items GROUP BY qty ORDER BY qty LIMIT 3",
            // UNION
            "SELECT name FROM items WHERE price > 20 UNION SELECT name FROM items WHERE qty < 50 ORDER BY name",
            // UNION ALL
            "SELECT name FROM items WHERE price > 15 UNION ALL SELECT name FROM items WHERE qty > 100 ORDER BY name",
            // INTERSECT
            "SELECT name FROM items WHERE price > 10 INTERSECT SELECT name FROM items WHERE qty >= 50 ORDER BY name",
            // EXCEPT
            "SELECT name FROM items WHERE price > 10 EXCEPT SELECT name FROM items WHERE qty > 100 ORDER BY name",
            // Type coercion: integer vs text comparison
            "SELECT name FROM items WHERE id = '3'",
            // Type coercion: integer vs float
            "SELECT name FROM items WHERE id = 3.0",
            // ORDER BY expression
            "SELECT name, price * qty AS total FROM items ORDER BY price * qty DESC LIMIT 3",
            // Compound SELECT with LIMIT
            "SELECT name FROM items WHERE price > 20 UNION ALL SELECT name FROM items WHERE qty < 30 ORDER BY name LIMIT 2",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} limit/union/coercion conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Single-table SELECT edge cases: GROUP BY with expressions, ORDER BY
    /// on computed columns, WHERE with BETWEEN/IN/LIKE, and DISTINCT.
    #[test]
    fn test_conformance_single_table_select_edge_cases() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE products (id INTEGER PRIMARY KEY, name TEXT, category TEXT, price REAL, stock INTEGER, active INTEGER DEFAULT 1);",
            "INSERT INTO products VALUES (1, 'Widget A', 'tools', 19.99, 50, 1);",
            "INSERT INTO products VALUES (2, 'Widget B', 'tools', 29.99, 30, 1);",
            "INSERT INTO products VALUES (3, 'Gadget X', 'electronics', 99.99, 10, 1);",
            "INSERT INTO products VALUES (4, 'Gadget Y', 'electronics', 149.99, 5, 0);",
            "INSERT INTO products VALUES (5, 'Part Z', 'hardware', 4.99, 200, 1);",
            "INSERT INTO products VALUES (6, 'Part W', 'hardware', 2.99, 500, 1);",
            "INSERT INTO products VALUES (7, 'Cable', 'electronics', 9.99, 100, 1);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // BETWEEN
            "SELECT name FROM products WHERE price BETWEEN 10 AND 100 ORDER BY name",
            // NOT BETWEEN
            "SELECT name FROM products WHERE price NOT BETWEEN 10 AND 100 ORDER BY name",
            // IN list
            "SELECT name FROM products WHERE category IN ('tools', 'hardware') ORDER BY name",
            // NOT IN list
            "SELECT name FROM products WHERE category NOT IN ('tools', 'hardware') ORDER BY name",
            // LIKE
            "SELECT name FROM products WHERE name LIKE 'Widget%' ORDER BY name",
            "SELECT name FROM products WHERE name LIKE '%get%' ORDER BY name",
            "SELECT name FROM products WHERE name LIKE 'Part _' ORDER BY name",
            // GLOB
            "SELECT name FROM products WHERE name GLOB 'Widget*' ORDER BY name",
            // DISTINCT
            "SELECT DISTINCT category FROM products ORDER BY category",
            // GROUP BY with expression
            "SELECT CASE WHEN price > 50 THEN 'expensive' ELSE 'cheap' END AS tier, count(*) AS cnt FROM products GROUP BY CASE WHEN price > 50 THEN 'expensive' ELSE 'cheap' END ORDER BY tier",
            // ORDER BY computed column (not in SELECT)
            "SELECT name FROM products ORDER BY price * stock DESC LIMIT 3",
            // Multiple conditions with AND/OR
            "SELECT name FROM products WHERE (category = 'tools' OR category = 'hardware') AND active = 1 AND stock > 30 ORDER BY name",
            // IS NULL / IS NOT NULL
            "SELECT count(*) FROM products WHERE name IS NOT NULL",
            // Aggregate with WHERE filter
            "SELECT category, sum(price * stock) AS inventory_value FROM products WHERE active = 1 GROUP BY category ORDER BY category",
            // GROUP BY with HAVING on computed expression
            "SELECT category, count(*) AS cnt FROM products GROUP BY category HAVING count(*) > 1 ORDER BY category",
            // DISTINCT with ORDER BY
            "SELECT DISTINCT category FROM products ORDER BY category DESC",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} single-table SELECT edge case mismatches found",
                mismatches.len()
            );
        }
    }

    /// Patterns commonly generated by ORMs: column aliasing, nested functions,
    /// mixed aggregate/scalar in SELECT, and multi-table GROUP BY with HAVING.
    #[test]
    fn test_conformance_orm_patterns() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE users (id INTEGER PRIMARY KEY, name TEXT, email TEXT, created_at TEXT);",
            "INSERT INTO users VALUES (1, 'Alice', 'alice@test.com', '2024-01-01');",
            "INSERT INTO users VALUES (2, 'Bob', 'bob@test.com', '2024-02-15');",
            "INSERT INTO users VALUES (3, 'Carol', 'carol@test.com', '2024-03-20');",
            "CREATE TABLE orders (id INTEGER PRIMARY KEY, user_id INTEGER, amount REAL, status TEXT, created_at TEXT);",
            "INSERT INTO orders VALUES (1, 1, 100.0, 'completed', '2024-01-15');",
            "INSERT INTO orders VALUES (2, 1, 50.0, 'completed', '2024-02-01');",
            "INSERT INTO orders VALUES (3, 2, 200.0, 'pending', '2024-02-20');",
            "INSERT INTO orders VALUES (4, 2, 75.0, 'completed', '2024-03-01');",
            "INSERT INTO orders VALUES (5, 3, 150.0, 'completed', '2024-03-25');",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // Aliased column in ORDER BY
            "SELECT u.name AS user_name, count(o.id) AS order_count FROM users u JOIN orders o ON o.user_id = u.id GROUP BY u.name ORDER BY order_count DESC, u.name",
            // Sum with HAVING
            "SELECT u.name, sum(o.amount) AS total FROM users u JOIN orders o ON o.user_id = u.id GROUP BY u.name HAVING sum(o.amount) > 100 ORDER BY u.name",
            // LEFT JOIN with aggregate (NULL handling)
            "SELECT u.name, COALESCE(sum(o.amount), 0) AS total FROM users u LEFT JOIN orders o ON o.user_id = u.id AND o.status = 'completed' GROUP BY u.name ORDER BY u.name",
            // Nested function in aggregate context
            "SELECT u.name, count(CASE WHEN o.status = 'completed' THEN 1 END) AS completed_count FROM users u JOIN orders o ON o.user_id = u.id GROUP BY u.name ORDER BY u.name",
            // Subquery in FROM (derived table)
            "SELECT sq.name, sq.total FROM (SELECT u.name, sum(o.amount) AS total FROM users u JOIN orders o ON o.user_id = u.id GROUP BY u.name) sq ORDER BY sq.total DESC",
            // CASE in GROUP BY result
            "SELECT CASE WHEN count(o.id) > 1 THEN 'frequent' ELSE 'occasional' END AS buyer_type, count(*) AS cnt FROM users u JOIN orders o ON o.user_id = u.id GROUP BY u.id ORDER BY buyer_type",
            // Multiple aggregates
            "SELECT u.name, min(o.amount) AS min_order, max(o.amount) AS max_order, count(o.id) AS num_orders FROM users u JOIN orders o ON o.user_id = u.id GROUP BY u.name ORDER BY u.name",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} ORM pattern conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// INSERT...SELECT, UPDATE with subqueries, DELETE with subqueries,
    /// and multi-statement DML conformance.
    #[test]
    fn test_conformance_dml_subqueries() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE src (id INTEGER PRIMARY KEY, val TEXT, score INTEGER);",
            "INSERT INTO src VALUES (1, 'alpha', 10);",
            "INSERT INTO src VALUES (2, 'beta', 20);",
            "INSERT INTO src VALUES (3, 'gamma', 30);",
            "CREATE TABLE dst (id INTEGER PRIMARY KEY, val TEXT, score INTEGER);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        // INSERT...SELECT
        let dml = ["INSERT INTO dst SELECT * FROM src WHERE score >= 20"];
        for s in &dml {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // Verify INSERT...SELECT result
            "SELECT * FROM dst ORDER BY id",
            // Scalar subquery in WHERE
            "SELECT val FROM src WHERE score > (SELECT min(score) FROM src) ORDER BY val",
            // IN subquery
            "SELECT val FROM src WHERE id IN (SELECT id FROM dst) ORDER BY val",
            // NOT IN subquery
            "SELECT val FROM src WHERE id NOT IN (SELECT id FROM dst) ORDER BY val",
            // EXISTS subquery
            "SELECT val FROM src WHERE EXISTS (SELECT 1 FROM dst WHERE dst.id = src.id) ORDER BY val",
            // NOT EXISTS subquery
            "SELECT val FROM src WHERE NOT EXISTS (SELECT 1 FROM dst WHERE dst.id = src.id) ORDER BY val",
            // Scalar subquery in SELECT list
            "SELECT val, (SELECT count(*) FROM dst WHERE dst.score <= src.score) AS rank_approx FROM src ORDER BY val",
            // Correlated subquery with aggregate in WHERE
            "SELECT val FROM src WHERE score = (SELECT max(score) FROM src s2 WHERE s2.id <= src.id) ORDER BY val",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} DML subquery conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Nested subqueries, multi-level correlated, and complex WHERE expressions.
    #[test]
    fn test_conformance_nested_subqueries_and_complex_where() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE departments (id INTEGER PRIMARY KEY, name TEXT);",
            "INSERT INTO departments VALUES (1, 'Engineering');",
            "INSERT INTO departments VALUES (2, 'Marketing');",
            "INSERT INTO departments VALUES (3, 'Sales');",
            "CREATE TABLE employees (id INTEGER PRIMARY KEY, name TEXT, dept_id INTEGER, salary REAL);",
            "INSERT INTO employees VALUES (1, 'Alice', 1, 95000);",
            "INSERT INTO employees VALUES (2, 'Bob', 1, 85000);",
            "INSERT INTO employees VALUES (3, 'Carol', 2, 75000);",
            "INSERT INTO employees VALUES (4, 'Dave', 2, 65000);",
            "INSERT INTO employees VALUES (5, 'Eve', 3, 55000);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // Subquery returning max salary per dept, filter employees above dept avg
            "SELECT e.name FROM employees e WHERE e.salary > (SELECT avg(e2.salary) FROM employees e2 WHERE e2.dept_id = e.dept_id) ORDER BY e.name",
            // Department names with more than 1 employee
            "SELECT d.name FROM departments d WHERE (SELECT count(*) FROM employees e WHERE e.dept_id = d.id) > 1 ORDER BY d.name",
            // Nested subquery: departments where max salary > overall avg
            "SELECT d.name FROM departments d WHERE (SELECT max(e.salary) FROM employees e WHERE e.dept_id = d.id) > (SELECT avg(salary) FROM employees) ORDER BY d.name",
            // Complex WHERE with AND/OR and subqueries
            "SELECT e.name FROM employees e WHERE (e.salary > 70000 OR e.dept_id = 3) AND e.dept_id IN (SELECT id FROM departments WHERE name != 'Marketing') ORDER BY e.name",
            // BETWEEN with subquery bounds
            "SELECT e.name FROM employees e WHERE e.salary BETWEEN (SELECT min(salary) FROM employees) + 10000 AND (SELECT max(salary) FROM employees) - 10000 ORDER BY e.name",
            // Aggregate with HAVING referencing correlated subquery
            "SELECT d.name, count(*) as cnt FROM departments d JOIN employees e ON e.dept_id = d.id GROUP BY d.name HAVING count(*) = (SELECT max(c) FROM (SELECT count(*) as c FROM employees GROUP BY dept_id)) ORDER BY d.name",
            // CASE with subquery
            "SELECT e.name, CASE WHEN e.salary > (SELECT avg(salary) FROM employees) THEN 'above' ELSE 'below' END AS salary_rank FROM employees e ORDER BY e.name",
            // Derived table with JOIN
            "SELECT d.name, sub.avg_sal FROM departments d JOIN (SELECT dept_id, avg(salary) AS avg_sal FROM employees GROUP BY dept_id) sub ON sub.dept_id = d.id ORDER BY d.name",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} nested subquery conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// NULL handling edge cases: IS NULL, IS NOT NULL, COALESCE chains,
    /// NULL in aggregates, NULL in DISTINCT, NULL comparisons.
    #[test]
    fn test_conformance_null_handling() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE t (id INTEGER PRIMARY KEY, a TEXT, b INTEGER, c REAL);",
            "INSERT INTO t VALUES (1, 'x', 10, 1.5);",
            "INSERT INTO t VALUES (2, NULL, 20, NULL);",
            "INSERT INTO t VALUES (3, 'y', NULL, 3.5);",
            "INSERT INTO t VALUES (4, NULL, NULL, NULL);",
            "INSERT INTO t VALUES (5, 'x', 10, 1.5);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // IS NULL / IS NOT NULL
            "SELECT id FROM t WHERE a IS NULL ORDER BY id",
            "SELECT id FROM t WHERE b IS NOT NULL ORDER BY id",
            // COALESCE chains
            "SELECT id, COALESCE(a, 'none') FROM t ORDER BY id",
            "SELECT id, COALESCE(a, CAST(b AS TEXT), 'empty') FROM t ORDER BY id",
            // NULL in aggregates
            "SELECT count(*), count(a), count(b), count(c) FROM t",
            "SELECT sum(b), avg(b), min(b), max(b) FROM t",
            "SELECT group_concat(a, ',') FROM t",
            // DISTINCT with NULLs
            "SELECT DISTINCT a FROM t ORDER BY a",
            "SELECT DISTINCT b FROM t ORDER BY b",
            // NULL comparison behavior
            "SELECT id FROM t WHERE a = NULL ORDER BY id",
            "SELECT id FROM t WHERE a != NULL ORDER BY id",
            "SELECT id FROM t WHERE NOT (a IS NULL) ORDER BY id",
            // NULL in CASE
            "SELECT id, CASE WHEN a IS NULL THEN 'null' WHEN a = 'x' THEN 'ex' ELSE 'other' END FROM t ORDER BY id",
            // NULL in IN list
            "SELECT id FROM t WHERE a IN ('x', NULL) ORDER BY id",
            "SELECT id FROM t WHERE a NOT IN ('x', NULL) ORDER BY id",
            // NULL arithmetic
            "SELECT id, b + 1, b * 2, b - c FROM t ORDER BY id",
            // IFNULL and NULLIF
            "SELECT id, ifnull(a, 'default'), nullif(a, 'x') FROM t ORDER BY id",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} NULL handling conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Type coercion edge cases: mixed-type comparisons, affinity rules,
    /// CAST behavior, and numeric string handling.
    #[test]
    fn test_conformance_type_coercion_edge_cases() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE mixed (id INTEGER PRIMARY KEY, val);",
            "INSERT INTO mixed VALUES (1, 42);",
            "INSERT INTO mixed VALUES (2, '42');",
            "INSERT INTO mixed VALUES (3, 42.0);",
            "INSERT INTO mixed VALUES (4, '42.0');",
            "INSERT INTO mixed VALUES (5, 'abc');",
            "INSERT INTO mixed VALUES (6, NULL);",
            "INSERT INTO mixed VALUES (7, x'CAFE');",
            "INSERT INTO mixed VALUES (8, 0);",
            "INSERT INTO mixed VALUES (9, '');",
            "INSERT INTO mixed VALUES (10, 0.0);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // typeof on each
            "SELECT id, typeof(val) FROM mixed ORDER BY id",
            // Equality comparisons across types
            "SELECT id FROM mixed WHERE val = 42 ORDER BY id",
            "SELECT id FROM mixed WHERE val = '42' ORDER BY id",
            "SELECT id FROM mixed WHERE val = 42.0 ORDER BY id",
            // Ordering across types (SQLite sort order: NULL < INT/REAL < TEXT < BLOB)
            "SELECT id, val FROM mixed ORDER BY val, id",
            // CAST behavior (exclude BLOB row 7: CAST(x'CAFE' AS TEXT) produces non-UTF-8 that rusqlite cannot retrieve)
            "SELECT id, CAST(val AS INTEGER) FROM mixed WHERE id != 7 ORDER BY id",
            "SELECT id, CAST(val AS REAL) FROM mixed WHERE id != 7 ORDER BY id",
            "SELECT id, CAST(val AS TEXT) FROM mixed WHERE id != 7 ORDER BY id",
            // Arithmetic with text that looks numeric
            "SELECT val + 0 FROM mixed WHERE typeof(val) = 'text' ORDER BY id",
            // Comparison with zero
            "SELECT id FROM mixed WHERE val = 0 ORDER BY id",
            "SELECT id FROM mixed WHERE val > 0 ORDER BY id",
            // Boolean-like comparisons
            "SELECT id FROM mixed WHERE val ORDER BY id",
            // total() vs sum() with NULLs
            "SELECT sum(val), total(val) FROM mixed",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} type coercion conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Complex GROUP BY: expressions in GROUP BY, HAVING with complex
    /// predicates, aggregate of aggregate-like expressions, and edge cases.
    #[test]
    fn test_conformance_complex_group_by() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE sales (id INTEGER PRIMARY KEY, product TEXT, category TEXT, amount REAL, qty INTEGER, sale_date TEXT);",
            "INSERT INTO sales VALUES (1, 'Widget A', 'gadgets', 19.99, 5, '2024-01-15');",
            "INSERT INTO sales VALUES (2, 'Widget B', 'gadgets', 29.99, 3, '2024-01-20');",
            "INSERT INTO sales VALUES (3, 'Gizmo X', 'tools', 49.99, 2, '2024-02-10');",
            "INSERT INTO sales VALUES (4, 'Gizmo Y', 'tools', 39.99, 4, '2024-02-15');",
            "INSERT INTO sales VALUES (5, 'Widget A', 'gadgets', 19.99, 1, '2024-03-01');",
            "INSERT INTO sales VALUES (6, 'Doohickey', 'misc', 9.99, 10, '2024-03-05');",
            "INSERT INTO sales VALUES (7, 'Widget B', 'gadgets', 29.99, 2, '2024-03-10');",
            "INSERT INTO sales VALUES (8, 'Gizmo X', 'tools', 49.99, 1, '2024-03-15');",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // GROUP BY expression (upper)
            "SELECT upper(category), count(*) FROM sales GROUP BY upper(category) ORDER BY upper(category)",
            // GROUP BY with computed column
            "SELECT category, sum(amount * qty) AS revenue FROM sales GROUP BY category ORDER BY revenue DESC",
            // HAVING with multiple conditions
            "SELECT category, count(*) AS cnt, sum(amount) AS total FROM sales GROUP BY category HAVING count(*) > 1 AND sum(amount) > 50 ORDER BY category",
            // GROUP BY multiple columns
            "SELECT category, product, sum(qty) AS total_qty FROM sales GROUP BY category, product ORDER BY category, product",
            // Aggregate with DISTINCT
            "SELECT count(DISTINCT product) FROM sales",
            "SELECT count(DISTINCT category) FROM sales",
            // GROUP BY with CASE expression
            "SELECT CASE WHEN amount < 20 THEN 'cheap' WHEN amount < 40 THEN 'mid' ELSE 'premium' END AS tier, count(*), sum(qty) FROM sales GROUP BY CASE WHEN amount < 20 THEN 'cheap' WHEN amount < 40 THEN 'mid' ELSE 'premium' END ORDER BY tier",
            // GROUP BY with COALESCE
            "SELECT COALESCE(category, 'unknown'), sum(amount) FROM sales GROUP BY COALESCE(category, 'unknown') ORDER BY 1",
            // Aggregate of expression
            "SELECT category, avg(amount * qty) AS avg_revenue, min(amount * qty) AS min_rev FROM sales GROUP BY category ORDER BY category",
            // GROUP BY with subquery in HAVING
            "SELECT category, sum(amount) AS total FROM sales GROUP BY category HAVING sum(amount) > (SELECT avg(amount) * 2 FROM sales) ORDER BY category",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} complex GROUP BY conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// UPDATE and DELETE with complex WHERE clauses, JOINs, and subqueries.
    #[test]
    fn test_conformance_update_delete_complex() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE items (id INTEGER PRIMARY KEY, name TEXT, price REAL, active INTEGER);",
            "INSERT INTO items VALUES (1, 'apple', 1.50, 1);",
            "INSERT INTO items VALUES (2, 'banana', 0.75, 1);",
            "INSERT INTO items VALUES (3, 'cherry', 3.00, 0);",
            "INSERT INTO items VALUES (4, 'date', 5.00, 1);",
            "INSERT INTO items VALUES (5, 'elderberry', 8.00, 0);",
            "CREATE TABLE price_changes (item_id INTEGER, new_price REAL);",
            "INSERT INTO price_changes VALUES (1, 2.00);",
            "INSERT INTO price_changes VALUES (3, 2.50);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        // UPDATE with subquery in SET
        let dml1 = "UPDATE items SET price = (SELECT new_price FROM price_changes WHERE item_id = items.id) WHERE id IN (SELECT item_id FROM price_changes)";
        fconn.execute(dml1).unwrap();
        rconn.execute_batch(dml1).unwrap();

        let q1 = ["SELECT id, name, price FROM items ORDER BY id"];
        let m1 = oracle_compare(&fconn, &rconn, &q1);

        // DELETE with subquery in WHERE
        let dml2 = "DELETE FROM items WHERE active = 0";
        fconn.execute(dml2).unwrap();
        rconn.execute_batch(dml2).unwrap();

        let q2 = ["SELECT id, name, price, active FROM items ORDER BY id"];
        let m2 = oracle_compare(&fconn, &rconn, &q2);

        // UPDATE with expression
        let dml3 = "UPDATE items SET price = price * 1.1 WHERE price < 3.0";
        fconn.execute(dml3).unwrap();
        rconn.execute_batch(dml3).unwrap();

        let q3 = ["SELECT id, name, round(price, 2) FROM items ORDER BY id"];
        let m3 = oracle_compare(&fconn, &rconn, &q3);

        let mut all_mismatches = Vec::new();
        all_mismatches.extend(m1);
        all_mismatches.extend(m2);
        all_mismatches.extend(m3);

        if !all_mismatches.is_empty() {
            for m in &all_mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} UPDATE/DELETE conformance mismatches found",
                all_mismatches.len()
            );
        }
    }

    /// Multi-table JOINs: 3-way, self-join, cross join, and complex ON conditions.
    #[test]
    fn test_conformance_multi_table_joins() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE authors (id INTEGER PRIMARY KEY, name TEXT);",
            "INSERT INTO authors VALUES (1, 'Asimov');",
            "INSERT INTO authors VALUES (2, 'Clarke');",
            "INSERT INTO authors VALUES (3, 'Heinlein');",
            "CREATE TABLE books (id INTEGER PRIMARY KEY, title TEXT, author_id INTEGER, genre TEXT);",
            "INSERT INTO books VALUES (1, 'Foundation', 1, 'scifi');",
            "INSERT INTO books VALUES (2, 'Rendezvous', 2, 'scifi');",
            "INSERT INTO books VALUES (3, 'Stranger', 3, 'scifi');",
            "INSERT INTO books VALUES (4, 'I Robot', 1, 'scifi');",
            "INSERT INTO books VALUES (5, 'Childhood', 2, 'scifi');",
            "CREATE TABLE reviews (id INTEGER PRIMARY KEY, book_id INTEGER, rating INTEGER);",
            "INSERT INTO reviews VALUES (1, 1, 5);",
            "INSERT INTO reviews VALUES (2, 1, 4);",
            "INSERT INTO reviews VALUES (3, 2, 3);",
            "INSERT INTO reviews VALUES (4, 3, 5);",
            "INSERT INTO reviews VALUES (5, 4, 4);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // 3-way INNER JOIN
            "SELECT a.name, b.title, r.rating FROM authors a JOIN books b ON b.author_id = a.id JOIN reviews r ON r.book_id = b.id ORDER BY a.name, b.title, r.rating",
            // LEFT JOIN chain: authors with avg rating (some books have no reviews)
            "SELECT a.name, count(r.id) AS review_count, COALESCE(avg(r.rating), 0) AS avg_rating FROM authors a LEFT JOIN books b ON b.author_id = a.id LEFT JOIN reviews r ON r.book_id = b.id GROUP BY a.name ORDER BY a.name",
            // Self-join: find books by same author
            "SELECT b1.title, b2.title FROM books b1 JOIN books b2 ON b1.author_id = b2.author_id AND b1.id < b2.id ORDER BY b1.title, b2.title",
            // CROSS JOIN (small)
            "SELECT a1.name, a2.name FROM authors a1, authors a2 WHERE a1.id < a2.id ORDER BY a1.name, a2.name",
            // Complex ON with OR
            "SELECT a.name, b.title FROM authors a JOIN books b ON b.author_id = a.id AND (b.title LIKE 'F%' OR b.title LIKE 'I%') ORDER BY a.name, b.title",
            // JOIN with aggregate and GROUP BY
            "SELECT a.name, count(DISTINCT b.id) AS book_count, count(r.id) AS total_reviews FROM authors a LEFT JOIN books b ON b.author_id = a.id LEFT JOIN reviews r ON r.book_id = b.id GROUP BY a.id, a.name ORDER BY a.name",
            // Subquery in FROM with JOIN
            "SELECT sub.name, sub.book_count FROM (SELECT a.name, count(b.id) AS book_count FROM authors a JOIN books b ON b.author_id = a.id GROUP BY a.name) sub WHERE sub.book_count > 1 ORDER BY sub.name",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} multi-table JOIN conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Expression evaluation edge cases: operator precedence, nested CASE,
    /// CAST chains, string concatenation, and arithmetic overflow.
    #[test]
    fn test_conformance_expression_eval_edge_cases() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let queries = [
            // Operator precedence
            "SELECT 2 + 3 * 4",
            "SELECT (2 + 3) * 4",
            "SELECT 10 - 3 - 2",
            "SELECT 10 / 3",
            "SELECT 10 % 3",
            "SELECT 10.0 / 3",
            // Unary minus
            "SELECT -(-5)",
            "SELECT -(3 + 4)",
            // String concatenation
            "SELECT 'hello' || ' ' || 'world'",
            "SELECT 'num: ' || 42",
            "SELECT NULL || 'text'",
            "SELECT 'text' || NULL",
            // Nested CASE
            "SELECT CASE WHEN 1 > 2 THEN 'a' WHEN 2 > 3 THEN 'b' ELSE CASE WHEN 3 > 2 THEN 'c' ELSE 'd' END END",
            // CASE with no ELSE (should return NULL)
            "SELECT CASE WHEN 1 > 2 THEN 'yes' END",
            // Simple CASE (value-form)
            "SELECT CASE 2 WHEN 1 THEN 'one' WHEN 2 THEN 'two' WHEN 3 THEN 'three' END",
            // CAST chains
            "SELECT CAST(CAST('123.456' AS REAL) AS INTEGER)",
            "SELECT CAST(CAST(42 AS TEXT) AS REAL)",
            // Boolean expressions
            "SELECT 1 AND 0",
            "SELECT 1 OR 0",
            "SELECT NOT 1",
            "SELECT NOT 0",
            "SELECT 1 AND NULL",
            "SELECT 0 AND NULL",
            "SELECT 1 OR NULL",
            "SELECT 0 OR NULL",
            // Large integer arithmetic
            "SELECT 9223372036854775807",
            "SELECT -9223372036854775808",
            "SELECT 9223372036854775807 + 1",
            // LIKE patterns
            "SELECT 'hello' LIKE 'h%'",
            "SELECT 'hello' LIKE '%llo'",
            "SELECT 'hello' LIKE '%ell%'",
            "SELECT 'hello' LIKE 'h_llo'",
            "SELECT 'hello' LIKE 'HELLO'",
            // GLOB patterns
            "SELECT 'hello' GLOB 'h*'",
            "SELECT 'hello' GLOB 'H*'",
            "SELECT 'hello' GLOB 'h?llo'",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} expression eval conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Compound SELECTs: UNION, UNION ALL, INTERSECT, EXCEPT with
    /// ORDER BY, LIMIT, and complex operands.
    #[test]
    fn test_conformance_compound_select_ordering() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE t1 (id INTEGER PRIMARY KEY, val TEXT);",
            "INSERT INTO t1 VALUES (1, 'a');",
            "INSERT INTO t1 VALUES (2, 'b');",
            "INSERT INTO t1 VALUES (3, 'c');",
            "INSERT INTO t1 VALUES (4, 'b');",
            "CREATE TABLE t2 (id INTEGER PRIMARY KEY, val TEXT);",
            "INSERT INTO t2 VALUES (10, 'b');",
            "INSERT INTO t2 VALUES (20, 'c');",
            "INSERT INTO t2 VALUES (30, 'd');",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // UNION with ORDER BY
            "SELECT val FROM t1 UNION SELECT val FROM t2 ORDER BY val",
            // UNION ALL with ORDER BY
            "SELECT val FROM t1 UNION ALL SELECT val FROM t2 ORDER BY val",
            // INTERSECT
            "SELECT val FROM t1 INTERSECT SELECT val FROM t2 ORDER BY val",
            // EXCEPT
            "SELECT val FROM t1 EXCEPT SELECT val FROM t2 ORDER BY val",
            // UNION with LIMIT
            "SELECT val FROM t1 UNION SELECT val FROM t2 ORDER BY val LIMIT 3",
            // UNION ALL with LIMIT + OFFSET
            "SELECT val FROM t1 UNION ALL SELECT val FROM t2 ORDER BY val LIMIT 3 OFFSET 2",
            // Compound with expressions
            "SELECT id, val FROM t1 WHERE id <= 2 UNION SELECT id, val FROM t2 WHERE id <= 20 ORDER BY id",
            // Triple compound
            "SELECT val FROM t1 UNION SELECT val FROM t2 UNION SELECT 'e' ORDER BY val",
            // UNION of expressions
            "SELECT 1 AS x UNION SELECT 2 UNION SELECT 3 ORDER BY x",
            // UNION ALL preserving duplicates
            "SELECT val FROM t1 UNION ALL SELECT val FROM t2 ORDER BY val, 1",
            // EXCEPT with aggregate subquery
            "SELECT val FROM t1 EXCEPT SELECT val FROM t1 WHERE id > 2 ORDER BY val",
            // INTERSECT with condition
            "SELECT val FROM t1 WHERE val >= 'b' INTERSECT SELECT val FROM t2 WHERE val <= 'c' ORDER BY val",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} compound SELECT conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// UPSERT (INSERT OR REPLACE/IGNORE), ON CONFLICT, and conflict handling.
    #[test]
    fn test_conformance_upsert_conflict() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE kv (key TEXT PRIMARY KEY, value TEXT, counter INTEGER DEFAULT 0);",
            "INSERT INTO kv VALUES ('a', 'alpha', 1);",
            "INSERT INTO kv VALUES ('b', 'beta', 2);",
            "INSERT INTO kv VALUES ('c', 'gamma', 3);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        // INSERT OR REPLACE
        let dml1 = "INSERT OR REPLACE INTO kv VALUES ('a', 'ALPHA', 10)";
        fconn.execute(dml1).unwrap();
        rconn.execute_batch(dml1).unwrap();

        let q1 = ["SELECT key, value, counter FROM kv ORDER BY key"];
        let m1 = oracle_compare(&fconn, &rconn, &q1);

        // INSERT OR IGNORE
        let dml2 = "INSERT OR IGNORE INTO kv VALUES ('b', 'BETA', 20)";
        fconn.execute(dml2).unwrap();
        rconn.execute_batch(dml2).unwrap();

        // New key
        let dml3 = "INSERT OR IGNORE INTO kv VALUES ('d', 'delta', 4)";
        fconn.execute(dml3).unwrap();
        rconn.execute_batch(dml3).unwrap();

        let q2 = ["SELECT key, value, counter FROM kv ORDER BY key"];
        let m2 = oracle_compare(&fconn, &rconn, &q2);

        // INSERT...ON CONFLICT DO UPDATE (UPSERT)
        let dml4 = "INSERT INTO kv (key, value, counter) VALUES ('c', 'GAMMA', 30) ON CONFLICT(key) DO UPDATE SET value = excluded.value, counter = counter + excluded.counter";
        fconn.execute(dml4).unwrap();
        rconn.execute_batch(dml4).unwrap();

        let q3 = ["SELECT key, value, counter FROM kv ORDER BY key"];
        let m3 = oracle_compare(&fconn, &rconn, &q3);

        // INSERT...ON CONFLICT DO NOTHING
        let dml5 = "INSERT INTO kv (key, value, counter) VALUES ('a', 'ignored', 0) ON CONFLICT DO NOTHING";
        fconn.execute(dml5).unwrap();
        rconn.execute_batch(dml5).unwrap();

        let q4 = ["SELECT key, value, counter FROM kv ORDER BY key"];
        let m4 = oracle_compare(&fconn, &rconn, &q4);

        let mut all = Vec::new();
        all.extend(m1);
        all.extend(m2);
        all.extend(m3);
        all.extend(m4);

        if !all.is_empty() {
            for m in &all {
                eprintln!("{m}\n");
            }
            panic!("{} UPSERT conformance mismatches found", all.len());
        }
    }

