    /// Probe UPDATE/DELETE with complex patterns: correlated subqueries,
    /// computed expressions, and multi-step DML sequences.
    #[test]
    fn test_conformance_dml_advanced() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE inventory (id INTEGER PRIMARY KEY, item TEXT NOT NULL, qty INTEGER DEFAULT 0, price REAL, category TEXT);",
            "INSERT INTO inventory VALUES (1, 'Widget', 100, 9.99, 'hardware');",
            "INSERT INTO inventory VALUES (2, 'Gadget', 50, 24.95, 'electronics');",
            "INSERT INTO inventory VALUES (3, 'Bolt', 1000, 0.10, 'hardware');",
            "INSERT INTO inventory VALUES (4, 'Chip', 200, 5.50, 'electronics');",
            "INSERT INTO inventory VALUES (5, 'Gear', 75, 15.00, 'hardware');",
            "CREATE TABLE sales (id INTEGER PRIMARY KEY, inv_id INTEGER, sold INTEGER, ts TEXT);",
            "INSERT INTO sales VALUES (1, 1, 10, '2024-01-15');",
            "INSERT INTO sales VALUES (2, 2, 5, '2024-01-16');",
            "INSERT INTO sales VALUES (3, 1, 20, '2024-02-01');",
            "INSERT INTO sales VALUES (4, 3, 100, '2024-02-10');",
            "INSERT INTO sales VALUES (5, 4, 50, '2024-02-15');",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let mut mismatches = Vec::new();

        // Pre-DML queries
        let pre = [
            "SELECT item, qty * price AS stock_value FROM inventory ORDER BY id",
            "SELECT i.item, SUM(s.sold) AS total_sold FROM inventory i LEFT JOIN sales s ON s.inv_id = i.id GROUP BY i.item ORDER BY i.item",
        ];
        mismatches.extend(oracle_compare(&fconn, &rconn, &pre));

        // Complex DML
        let dml = [
            "UPDATE inventory SET price = round(price * 1.1, 2) WHERE category = 'hardware'",
            "UPDATE inventory SET qty = qty - COALESCE((SELECT SUM(sold) FROM sales WHERE inv_id = inventory.id), 0)",
            "DELETE FROM sales WHERE sold < (SELECT AVG(sold) FROM sales)",
            "INSERT INTO sales (inv_id, sold, ts) VALUES (5, 25, '2024-03-01')",
        ];
        for op in &dml {
            fconn.execute(op).unwrap();
            rconn.execute_batch(op).unwrap();
        }

        // Post-DML verification
        let post = [
            "SELECT * FROM inventory ORDER BY id",
            "SELECT * FROM sales ORDER BY id",
            "SELECT category, SUM(qty) AS total_qty, round(AVG(price), 2) AS avg_price FROM inventory GROUP BY category ORDER BY category",
            "SELECT i.item, s.sold FROM inventory i JOIN sales s ON s.inv_id = i.id ORDER BY i.item, s.sold",
            "SELECT item, qty, price, round(qty * price, 2) AS total_value FROM inventory ORDER BY total_value DESC",
        ];
        mismatches.extend(oracle_compare(&fconn, &rconn, &post));

        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} DML advanced conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Probe expression edge cases: nested CASE, BETWEEN with expressions,
    /// complex IN lists, LIKE/GLOB patterns, and arithmetic chains.
    #[test]
    fn test_conformance_expression_depth() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let queries = [
            // Nested CASE
            "SELECT CASE WHEN 1 THEN CASE WHEN 0 THEN 'a' ELSE 'b' END ELSE 'c' END",
            "SELECT CASE WHEN NULL THEN 'a' WHEN 1 THEN 'b' END",
            "SELECT CASE 3 WHEN 1 THEN 'one' WHEN 2 THEN 'two' WHEN 3 THEN 'three' END",
            // BETWEEN with expressions
            "SELECT 5 BETWEEN 1+2 AND 3*3",
            "SELECT 'c' BETWEEN 'a' AND 'e'",
            "SELECT NULL BETWEEN 1 AND 10",
            // IN with expressions
            "SELECT 3 IN (1, 2, 3)",
            "SELECT 4 IN (1, 2, 3)",
            "SELECT NULL IN (1, 2, 3)",
            "SELECT 1 IN (1, NULL, 3)",
            "SELECT 2 IN (1, NULL, 3)",
            // NOT IN with NULL (three-valued logic)
            "SELECT 2 NOT IN (1, NULL, 3)",
            "SELECT NULL NOT IN (1, 2)",
            // Complex arithmetic chains
            "SELECT 2 + 3 * 4",
            "SELECT (2 + 3) * 4",
            "SELECT 10 - 3 - 2",
            "SELECT 100 / 10 / 2",
            "SELECT 17 % 5 + 2",
            // Bitwise operations
            "SELECT 5 & 3, 5 | 3, ~5",
            "SELECT 0xFF & 0x0F",
            "SELECT 1 << 4, 32 >> 2",
            // String comparison
            "SELECT 'abc' < 'abd'",
            "SELECT 'abc' = 'ABC'",
            "SELECT '' < 'a'",
            // Concatenation edge cases
            "SELECT 'a' || 'b' || 'c'",
            "SELECT 1 || 2 || 3",
            "SELECT NULL || 'hello'",
            // LIKE edge cases
            "SELECT 'hello' LIKE 'HELLO'",
            "SELECT 'hello' LIKE 'h_llo'",
            "SELECT 'hello' LIKE '%ell%'",
            "SELECT 'hello' LIKE 'hello%'",
            "SELECT 'hello' LIKE '%'",
            "SELECT '' LIKE '%'",
            "SELECT NULL LIKE '%'",
            // GLOB (case-sensitive)
            "SELECT 'Hello' GLOB 'Hello'",
            "SELECT 'Hello' GLOB 'hello'",
            "SELECT 'Hello' GLOB 'H*'",
            "SELECT 'Hello' GLOB '?ello'",
            // Mixed type comparisons
            "SELECT 1 < 2.0",
            "SELECT 1 = 1.0",
            "SELECT '9' > '10'",
            "SELECT 9 > 10",
            // Ternary conditional via IIF nesting
            "SELECT iif(1 > 2, 'a', iif(3 > 2, 'b', 'c'))",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} expression depth conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Probe compound SELECT (UNION/INTERSECT/EXCEPT) with complex operands,
    /// nested CTEs, and recursive patterns.
    #[test]
    fn test_conformance_compound_advanced() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE colors (id INTEGER PRIMARY KEY, name TEXT, hex TEXT);",
            "INSERT INTO colors VALUES (1, 'red', '#FF0000');",
            "INSERT INTO colors VALUES (2, 'green', '#00FF00');",
            "INSERT INTO colors VALUES (3, 'blue', '#0000FF');",
            "INSERT INTO colors VALUES (4, 'white', '#FFFFFF');",
            "INSERT INTO colors VALUES (5, 'black', '#000000');",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // UNION with ORDER BY and LIMIT
            "SELECT name FROM colors WHERE id <= 3 UNION SELECT name FROM colors WHERE id >= 3 ORDER BY name",
            // UNION ALL preserves duplicates
            "SELECT name FROM colors WHERE id <= 3 UNION ALL SELECT name FROM colors WHERE id >= 3 ORDER BY name",
            // INTERSECT
            "SELECT name FROM colors WHERE id <= 3 INTERSECT SELECT name FROM colors WHERE id >= 3 ORDER BY name",
            // EXCEPT
            "SELECT name FROM colors WHERE id <= 4 EXCEPT SELECT name FROM colors WHERE id >= 3 ORDER BY name",
            // Nested UNION
            "SELECT 1 AS n UNION SELECT 2 UNION SELECT 3 ORDER BY n",
            // Compound with aggregates
            "SELECT 'max' AS stat, MAX(id) AS val FROM colors UNION ALL SELECT 'min', MIN(id) FROM colors UNION ALL SELECT 'count', COUNT(*) FROM colors ORDER BY stat",
            // Compound with LIMIT
            "SELECT name FROM colors ORDER BY name LIMIT 2 OFFSET 0",
            "SELECT name FROM colors ORDER BY name LIMIT 10 OFFSET 3",
            // CTE used in UNION
            "WITH warm AS (SELECT name FROM colors WHERE name IN ('red')) SELECT name FROM warm UNION SELECT name FROM colors WHERE name = 'blue' ORDER BY name",
            // Recursive CTE: generate_series equivalent
            "WITH RECURSIVE seq(n) AS (SELECT 1 UNION ALL SELECT n + 1 FROM seq WHERE n < 10) SELECT n FROM seq",
            // Recursive CTE with string building
            "WITH RECURSIVE parts(s, n) AS (SELECT 'a', 1 UNION ALL SELECT s || 'a', n + 1 FROM parts WHERE n < 5) SELECT s FROM parts ORDER BY n",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} compound advanced conformance mismatches found",
                mismatches.len()
            );
        }
    }

    #[test]
    fn test_conformance_aggregate_edge_cases() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE sales (id INTEGER PRIMARY KEY, product TEXT, amount REAL, region TEXT, qty INTEGER);",
            "INSERT INTO sales VALUES (1, 'A', 10.5, 'north', 3);",
            "INSERT INTO sales VALUES (2, 'B', 20.0, 'south', 1);",
            "INSERT INTO sales VALUES (3, 'A', 15.5, 'south', 2);",
            "INSERT INTO sales VALUES (4, 'C', 5.0, 'north', 10);",
            "INSERT INTO sales VALUES (5, 'B', 8.0, 'north', 4);",
            "INSERT INTO sales VALUES (6, 'A', 12.0, 'south', NULL);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // COUNT(*) vs COUNT(column) — NULL handling
            "SELECT product, count(*), count(qty) FROM sales GROUP BY product ORDER BY product",
            // SUM with NULL values
            "SELECT product, sum(qty) FROM sales GROUP BY product ORDER BY product",
            // AVG with NULL values (should exclude NULLs)
            "SELECT product, avg(qty) FROM sales GROUP BY product ORDER BY product",
            // TOTAL (always returns float, 0.0 for empty)
            "SELECT product, total(amount) FROM sales GROUP BY product ORDER BY product",
            // GROUP_CONCAT
            "SELECT region, group_concat(product) FROM sales GROUP BY region ORDER BY region",
            "SELECT region, group_concat(product, '; ') FROM sales GROUP BY region ORDER BY region",
            // GROUP_CONCAT with ORDER BY on non-SELECT column
            "SELECT product FROM sales GROUP BY product ORDER BY sum(amount) DESC",
            // Multiple aggregates with arithmetic
            "SELECT product, sum(amount) * count(*) AS weighted FROM sales GROUP BY product ORDER BY product",
            // HAVING with complex expression
            "SELECT region, sum(amount) AS total FROM sales GROUP BY region HAVING sum(amount) > 30 ORDER BY region",
            // Aggregate over arithmetic expression
            "SELECT product, sum(amount * qty) AS revenue FROM sales WHERE qty IS NOT NULL GROUP BY product ORDER BY product",
            // MIN/MAX with text
            "SELECT min(product), max(product) FROM sales",
            // COUNT DISTINCT
            "SELECT count(DISTINCT product), count(DISTINCT region) FROM sales",
            // Nested expression in GROUP BY
            "SELECT CASE WHEN amount > 10 THEN 'high' ELSE 'low' END AS tier, count(*) FROM sales GROUP BY CASE WHEN amount > 10 THEN 'high' ELSE 'low' END ORDER BY tier",
            // Empty group aggregate
            "SELECT count(*), sum(amount), avg(amount), min(amount), max(amount) FROM sales WHERE id > 100",
            // Aggregate with COALESCE
            "SELECT product, sum(COALESCE(qty, 0)) AS total_qty FROM sales GROUP BY product ORDER BY product",
            // GROUP BY with LIMIT
            "SELECT product, sum(amount) AS total FROM sales GROUP BY product ORDER BY total DESC LIMIT 2",
            // GROUP BY with OFFSET
            "SELECT product, sum(amount) AS total FROM sales GROUP BY product ORDER BY total DESC LIMIT 2 OFFSET 1",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} aggregate edge case conformance mismatches found",
                mismatches.len()
            );
        }
    }

    #[test]
    fn test_conformance_window_functions() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE emp (id INTEGER PRIMARY KEY, name TEXT, dept TEXT, salary INTEGER);",
            "INSERT INTO emp VALUES (1, 'Alice', 'eng', 120);",
            "INSERT INTO emp VALUES (2, 'Bob', 'eng', 100);",
            "INSERT INTO emp VALUES (3, 'Carol', 'sales', 90);",
            "INSERT INTO emp VALUES (4, 'Dave', 'sales', 80);",
            "INSERT INTO emp VALUES (5, 'Eve', 'hr', 110);",
            "INSERT INTO emp VALUES (6, 'Frank', 'hr', 95);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // ROW_NUMBER
            "SELECT name, dept, row_number() OVER (ORDER BY salary DESC) AS rn FROM emp ORDER BY rn",
            // ROW_NUMBER with PARTITION BY
            "SELECT name, dept, row_number() OVER (PARTITION BY dept ORDER BY salary DESC) AS rn FROM emp ORDER BY dept, rn",
            // RANK
            "SELECT name, salary, rank() OVER (ORDER BY salary DESC) AS rnk FROM emp ORDER BY rnk, name",
            // DENSE_RANK
            "SELECT name, salary, dense_rank() OVER (ORDER BY salary DESC) AS drnk FROM emp ORDER BY drnk, name",
            // SUM window
            "SELECT name, salary, sum(salary) OVER (ORDER BY id) AS running_total FROM emp ORDER BY id",
            // COUNT window
            "SELECT name, dept, count(*) OVER (PARTITION BY dept) AS dept_size FROM emp ORDER BY id",
            // AVG window
            "SELECT name, salary, avg(salary) OVER (PARTITION BY dept) AS dept_avg FROM emp ORDER BY id",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} window function conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Probe CREATE TABLE AS SELECT, INSERT OR REPLACE, INSERT OR IGNORE,
    /// and schema-modifying DDL followed by queries.
    #[test]
    fn test_conformance_ddl_and_upsert_patterns() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE source (id INTEGER PRIMARY KEY, name TEXT, score INTEGER);",
            "INSERT INTO source VALUES (1, 'Alice', 95);",
            "INSERT INTO source VALUES (2, 'Bob', 80);",
            "INSERT INTO source VALUES (3, 'Carol', 90);",
            "INSERT INTO source VALUES (4, 'Dave', 85);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let mut mismatches = Vec::new();

        // CREATE TABLE AS SELECT
        let ctas = ["CREATE TABLE top_scorers AS SELECT * FROM source WHERE score >= 90"];
        for op in &ctas {
            fconn.execute(op).unwrap();
            rconn.execute_batch(op).unwrap();
        }

        let verify1 = [
            "SELECT * FROM top_scorers ORDER BY id",
            "SELECT COUNT(*) FROM top_scorers",
        ];
        mismatches.extend(oracle_compare(&fconn, &rconn, &verify1));

        // INSERT OR IGNORE + INSERT OR REPLACE
        let upsert_setup = [
            "CREATE TABLE kv (key TEXT PRIMARY KEY, val INTEGER);",
            "INSERT INTO kv VALUES ('a', 1);",
            "INSERT INTO kv VALUES ('b', 2);",
            "INSERT OR IGNORE INTO kv VALUES ('a', 99);",
            "INSERT OR REPLACE INTO kv VALUES ('b', 20);",
            "INSERT OR IGNORE INTO kv VALUES ('c', 3);",
        ];
        for op in &upsert_setup {
            fconn.execute(op).unwrap();
            rconn.execute_batch(op).unwrap();
        }

        let verify2 = [
            "SELECT * FROM kv ORDER BY key",
            // Multiple tables after DDL
            "SELECT s.name, k.val FROM source s JOIN kv k ON lower(substr(s.name, 1, 1)) = k.key ORDER BY s.name",
        ];
        mismatches.extend(oracle_compare(&fconn, &rconn, &verify2));

        // ALTER TABLE ADD COLUMN
        let alter = [
            "ALTER TABLE source ADD COLUMN grade TEXT DEFAULT 'ungraded'",
            "UPDATE source SET grade = 'A' WHERE score >= 90",
            "UPDATE source SET grade = 'B' WHERE score < 90",
        ];
        for op in &alter {
            fconn.execute(op).unwrap();
            rconn.execute_batch(op).unwrap();
        }

        let verify3 = [
            "SELECT * FROM source ORDER BY id",
            "SELECT grade, COUNT(*) FROM source GROUP BY grade ORDER BY grade",
        ];
        mismatches.extend(oracle_compare(&fconn, &rconn, &verify3));

        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} DDL/upsert conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Probe GROUP BY with complex expressions, multi-column aggregates,
    /// and aggregate functions on computed expressions.
    #[test]
    fn test_conformance_group_by_complex() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE events (id INTEGER PRIMARY KEY, ts TEXT, type TEXT, amount REAL);",
            "INSERT INTO events VALUES (1, '2024-01-15', 'sale', 100.0);",
            "INSERT INTO events VALUES (2, '2024-01-15', 'refund', -50.0);",
            "INSERT INTO events VALUES (3, '2024-01-16', 'sale', 200.0);",
            "INSERT INTO events VALUES (4, '2024-01-16', 'sale', 150.0);",
            "INSERT INTO events VALUES (5, '2024-02-01', 'sale', 300.0);",
            "INSERT INTO events VALUES (6, '2024-02-01', 'refund', -75.0);",
            "INSERT INTO events VALUES (7, '2024-02-15', 'sale', 50.0);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // GROUP BY substr expression (month extraction)
            "SELECT substr(ts, 1, 7) AS month, SUM(amount) FROM events GROUP BY substr(ts, 1, 7) ORDER BY month",
            // GROUP BY with CASE expression
            "SELECT CASE WHEN amount > 0 THEN 'positive' ELSE 'negative' END AS sign, COUNT(*) FROM events GROUP BY 1 ORDER BY sign",
            // GROUP BY with HAVING on different aggregate
            "SELECT type, COUNT(*) AS cnt, SUM(amount) AS total FROM events GROUP BY type HAVING SUM(amount) > 0 ORDER BY type",
            // Multiple aggregates
            "SELECT type, MIN(amount), MAX(amount), AVG(amount), COUNT(*) FROM events GROUP BY type ORDER BY type",
            // GROUP BY with computed expression in SELECT
            "SELECT substr(ts, 1, 7) AS month, COUNT(*) AS events, SUM(CASE WHEN amount > 0 THEN amount ELSE 0 END) AS revenue, SUM(CASE WHEN amount < 0 THEN amount ELSE 0 END) AS refunds FROM events GROUP BY 1 ORDER BY month",
            // GROUP_CONCAT
            "SELECT type, group_concat(CAST(id AS TEXT), ',') FROM events GROUP BY type ORDER BY type",
            // Aggregate with WHERE filter
            "SELECT COUNT(*) FROM events WHERE amount > 0",
            "SELECT SUM(amount) FROM events WHERE type = 'sale'",
            // DISTINCT aggregate
            "SELECT COUNT(DISTINCT type) FROM events",
            "SELECT COUNT(DISTINCT substr(ts, 1, 7)) FROM events",
            // Empty group aggregate
            "SELECT type, SUM(amount) FROM events WHERE id > 100 GROUP BY type ORDER BY type",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} GROUP BY complex conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Probe indexed queries, WHERE clause optimization, and multi-index
    /// lookups that exercise the planner and VDBE index scan paths.
    #[test]
    fn test_conformance_index_and_where() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE users (id INTEGER PRIMARY KEY, name TEXT, email TEXT, age INTEGER, active INTEGER DEFAULT 1);",
            "INSERT INTO users VALUES (1, 'Alice', 'alice@example.com', 30, 1);",
            "INSERT INTO users VALUES (2, 'Bob', 'bob@example.com', 25, 0);",
            "INSERT INTO users VALUES (3, 'Carol', 'carol@example.com', 35, 1);",
            "INSERT INTO users VALUES (4, 'Dave', 'dave@example.com', 28, 1);",
            "INSERT INTO users VALUES (5, 'Eve', 'eve@example.com', 40, 0);",
            "INSERT INTO users VALUES (6, 'Frank', 'frank@example.com', 22, 1);",
            "CREATE INDEX idx_age ON users(age);",
            "CREATE INDEX idx_name ON users(name);",
            "CREATE INDEX idx_active_age ON users(active, age);",
            "CREATE UNIQUE INDEX idx_email ON users(email);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // PK lookup
            "SELECT name FROM users WHERE id = 3",
            // Index range scan
            "SELECT name FROM users WHERE age >= 30 ORDER BY name",
            "SELECT name FROM users WHERE age BETWEEN 25 AND 35 ORDER BY name",
            // UNIQUE index lookup
            "SELECT name FROM users WHERE email = 'carol@example.com'",
            // Composite index
            "SELECT name FROM users WHERE active = 1 AND age > 25 ORDER BY name",
            // OR condition (may or may not use index)
            "SELECT name FROM users WHERE age < 25 OR age > 35 ORDER BY name",
            // NOT
            "SELECT name FROM users WHERE NOT active ORDER BY name",
            // IS NULL / IS NOT NULL
            "SELECT COUNT(*) FROM users WHERE email IS NOT NULL",
            // LIKE with index
            "SELECT name FROM users WHERE name LIKE 'A%' ORDER BY name",
            "SELECT name FROM users WHERE name LIKE '%e' ORDER BY name",
            // IN with index
            "SELECT name FROM users WHERE id IN (1, 3, 5) ORDER BY name",
            "SELECT name FROM users WHERE age IN (25, 30, 40) ORDER BY name",
            // ORDER BY with index
            "SELECT name FROM users ORDER BY age",
            "SELECT name FROM users ORDER BY age DESC",
            // LIMIT with index scan
            "SELECT name FROM users ORDER BY age LIMIT 3",
            "SELECT name FROM users ORDER BY age DESC LIMIT 2",
            // Complex WHERE with AND/OR precedence
            "SELECT name FROM users WHERE (active = 1 AND age > 30) OR (active = 0 AND age < 30) ORDER BY name",
            // Negative test: no matching rows
            "SELECT name FROM users WHERE age > 100",
            "SELECT COUNT(*) FROM users WHERE age > 100",
            // DELETE with indexed WHERE
            "DELETE FROM users WHERE id = 6",
        ];

        let mut mismatches = oracle_compare(&fconn, &rconn, &queries);

        // Run DELETE on both
        fconn.execute("DELETE FROM users WHERE id = 6").ok();
        rconn.execute_batch("DELETE FROM users WHERE id = 6").ok();

        let verify = [
            "SELECT COUNT(*) FROM users",
            "SELECT name FROM users ORDER BY name",
            // Verify index still works after delete
            "SELECT name FROM users WHERE age > 30 ORDER BY name",
        ];
        mismatches.extend(oracle_compare(&fconn, &rconn, &verify));

        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} index/WHERE conformance mismatches found",
                mismatches.len()
            );
        }
    }

    /// Probe edge cases in NULL handling: three-valued logic, NULL in
    /// aggregates, NULL in CASE, NULL in COALESCE chains, NULL ordering.
    #[test]
    fn test_conformance_null_semantics_deep() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let setup = [
            "CREATE TABLE nulls (id INTEGER PRIMARY KEY, a INTEGER, b TEXT, c REAL);",
            "INSERT INTO nulls VALUES (1, 10, 'x', 1.5);",
            "INSERT INTO nulls VALUES (2, NULL, 'y', 2.5);",
            "INSERT INTO nulls VALUES (3, 30, NULL, 3.5);",
            "INSERT INTO nulls VALUES (4, NULL, NULL, NULL);",
            "INSERT INTO nulls VALUES (5, 50, 'z', NULL);",
        ];
        for s in &setup {
            fconn.execute(s).unwrap();
            rconn.execute_batch(s).unwrap();
        }

        let queries = [
            // NULL in comparisons
            "SELECT id FROM nulls WHERE a IS NULL ORDER BY id",
            "SELECT id FROM nulls WHERE a IS NOT NULL ORDER BY id",
            "SELECT id FROM nulls WHERE a = NULL ORDER BY id",
            "SELECT id FROM nulls WHERE a != NULL ORDER BY id",
            "SELECT id FROM nulls WHERE a > 20 ORDER BY id",
            "SELECT id FROM nulls WHERE NOT (a > 20) ORDER BY id",
            // NULL in CASE
            "SELECT id, CASE WHEN a IS NULL THEN 'null' WHEN a > 20 THEN 'big' ELSE 'small' END FROM nulls ORDER BY id",
            "SELECT id, CASE a WHEN 10 THEN 'ten' WHEN 30 THEN 'thirty' ELSE 'other' END FROM nulls ORDER BY id",
            // COALESCE chains with NULL
            "SELECT id, COALESCE(a, -1) FROM nulls ORDER BY id",
            "SELECT id, COALESCE(b, CAST(a AS TEXT), 'none') FROM nulls ORDER BY id",
            "SELECT COALESCE(NULL, NULL, NULL, 42)",
            // NULL in aggregates
            "SELECT COUNT(*), COUNT(a), COUNT(b), COUNT(c) FROM nulls",
            "SELECT SUM(a), SUM(c), AVG(a), AVG(c) FROM nulls",
            "SELECT MIN(a), MAX(a), MIN(b), MAX(b) FROM nulls",
            "SELECT TOTAL(a), TOTAL(c) FROM nulls",
            // NULL in GROUP BY
            "SELECT a, COUNT(*) FROM nulls GROUP BY a ORDER BY a IS NULL, a",
            "SELECT b, COUNT(*) FROM nulls GROUP BY b ORDER BY b IS NULL, b",
            // NULL in DISTINCT
            "SELECT DISTINCT a FROM nulls ORDER BY a IS NULL, a",
            // NULL in ORDER BY (NULLs should come first in ASC)
            "SELECT id, a FROM nulls ORDER BY a, id",
            "SELECT id, a FROM nulls ORDER BY a DESC, id",
            // NULLIF
            "SELECT NULLIF(a, 10) FROM nulls WHERE id = 1",
            "SELECT NULLIF(a, 10) FROM nulls WHERE id = 2",
            // IIF with NULL
            "SELECT IIF(a IS NULL, 'yes', 'no') FROM nulls ORDER BY id",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} NULL semantics conformance mismatches found",
                mismatches.len()
            );
        }
    }

