    /// Probe expression evaluation: nested, edge-case arithmetic, boolean.
    #[test]
    fn test_conformance_expression_evaluation() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let queries = [
            // Operator precedence
            "SELECT 2 + 3 * 4",
            "SELECT (2 + 3) * 4",
            "SELECT 10 / 3",
            "SELECT 10 % 3",
            "SELECT -10 % 3",
            // Integer overflow
            "SELECT 9223372036854775807 + 1",
            "SELECT -9223372036854775808 - 1",
            // Float precision
            "SELECT 0.1 + 0.2",
            "SELECT typeof(0.1 + 0.2)",
            // Boolean expressions
            "SELECT 1 AND 0",
            "SELECT 1 OR 0",
            "SELECT NOT 0",
            "SELECT NOT 1",
            "SELECT NOT NULL",
            "SELECT 1 AND NULL",
            "SELECT 0 AND NULL",
            "SELECT 1 OR NULL",
            "SELECT 0 OR NULL",
            // String concatenation
            "SELECT 'hello' || ' ' || 'world'",
            "SELECT 'abc' || NULL",
            "SELECT NULL || 'def'",
            // Comparison operators
            "SELECT 1 = 1, 1 != 1, 1 < 2, 1 > 2, 1 <= 1, 1 >= 2",
            // GLOB
            "SELECT 'hello' GLOB 'h*'",
            "SELECT 'Hello' GLOB 'h*'",
            // Unary minus on various types
            "SELECT -42, -3.14, -(-5)",
            // Bitwise operations
            "SELECT 5 & 3, 5 | 3, ~5",
            "SELECT 7 << 2, 64 >> 3",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!(
                "{} expression evaluation mismatches found",
                mismatches.len()
            );
        }
    }

